	public interface IRaygunClient
	{
		IObservable<RaygunMessageEventArgs> OnRaygunError { get; }

		string FullAppVersion { get; }

		void Initialize(string clientId);

		void UpdateUserInfo(string username, string fullName, string email);

		void SendInBackground(Exception exception, IList<string> tags, IDictionary customData);
	}
	public class RaygunMessageEventArgs
	{
		public IList<string> Tags { get; set; } = new List<string>();

		public IDictionary UserCustomData { get; set; } = new Dictionary<string, object>();

		public DateTime OccurredOn { get; set; } = DateTime.Now;

		public string ClassName { get; set; } = string.Empty;

		public string Message { get; set; } = string.Empty;

		public IList<string> StackTrace { get; set; } = new List<string>();
	}
	public class RaygunCrashReporter : BaseCrashReporter
	{
		private readonly IRaygunClient raygun;

		private IDisposable onRaygunErrorSub;

		public RaygunCrashReporter(IRaygunClient raygun, IIfitApiService ifitApiService, ILogFileService logFileService, IFileService fileService, ICoreAnalytics analytics, string branchId, string version, bool isDebugMode)
			: base(ifitApiService, logFileService, fileService, analytics, branchId, version, isDebugMode)
		{
			this.raygun = raygun;
			Initialize();
		}

		protected override void Initialize()
		{
			if (!isDebugMode)
			{
				raygun.Initialize(ifitApiService.Environment.RaygunId);
				onRaygunErrorSub?.Dispose();
				onRaygunErrorSub = raygun.OnRaygunError.SubscribeOn(Scheduler.CurrentThread).ObserveOn(Scheduler.CurrentThread).Subscribe(OnNewError);
				base.Initialize();
			}
		}

		private void OnNewError(RaygunMessageEventArgs args)
		{
			if (args == null)
			{
				iFit.Logger.Log.Trace("CrashReporter", "New error not being handled");
				return;
			}
			PrepareErrorReport(args.Tags, args.UserCustomData).Wait();
			if (!args.Tags.Contains("Manual"))
			{
				WriteCrashInfoToLogs(args);
			}
		}

		private void WriteCrashInfoToLogs(RaygunMessageEventArgs args)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.AppendLine("CRASH INFO:");
			stringBuilder.AppendLine("Occured on: " + args.OccurredOn.ToString("O", CultureInfo.InvariantCulture));
			stringBuilder.AppendLine("Class: " + args.ClassName);
			stringBuilder.AppendLine("Message: " + args.Message);
			if (args.StackTrace != null)
			{
				foreach (string item in args.StackTrace)
				{
					stringBuilder.AppendLine(item);
				}
			}
			stringBuilder.AppendLine("\n\n");
			iFit.Logger.Log.Trace("CrashReporter", stringBuilder.ToString());
		}

		protected override void SendInBackground(Exception exception, IList<string> tags, IDictionary customData)
		{
			raygun.SendInBackground(exception, tags, customData);
		}

		protected override void OnUserChanged(User user)
		{
			raygun.UpdateUserInfo(user.Username, user.FullName, user.Email);
		}

		public override void Dispose()
		{
			base.Dispose();
			onRaygunErrorSub?.Dispose();
		}
	}
