		{
		}
	}
	[Target("Raygun")]
	public class RaygunTarget : TargetWithLayout
	{
		private const string ManualTag = "Manual";

		private readonly IRaygunClient raygunClient;

		internal RaygunTarget(IRaygunClient client, string layout)
		{
			raygunClient = client;
			Layout = layout;
		}

		protected override void Write(LogEventInfo logEvent)
		{
			Exception ex = ExtractException(logEvent);
			List<string> tags = ExtractTags(logEvent, ex);
			Dictionary<string, object> dictionary = ExtractProperties(logEvent);
			string value = Layout.Render(logEvent);
			dictionary["RenderedLogMessage"] = value;
			dictionary["LogMessageTemplate"] = logEvent.Message;
			if (ex == null)
			{
				ex = new RaygunException(logEvent.Message);
			}
			if (Mvx.TryResolve<ICrashReporter>(out var service))
			{
				service.ReportError(logEvent.Message, ex, dictionary);
			}
			else
			{
				raygunClient.SendInBackground(ex, tags, dictionary);
			}
		}

		private static Exception ExtractException(LogEventInfo logEvent)
		{
			if (logEvent.Exception != null)
			{
				return logEvent.Exception;
			}
			if (logEvent.Parameters != null && logEvent.Parameters.Length != 0)
			{
				return logEvent.Parameters[0] as Exception;
			}
			return null;
		}

		private static Dictionary<string, object> ExtractProperties(LogEventInfo logEvent)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			if (logEvent.Properties.Count > 0)
			{
				foreach (KeyValuePair<object, object> property in logEvent.Properties)
				{
					string text = property.Key.ToString();
					if (!string.IsNullOrEmpty(text) && !(text == "Tags") && !(text == "tags"))
					{
						object value = property.Value;
						if (value == null || Convert.GetTypeCode(value) != TypeCode.Object)
						{
							dictionary[text] = value;
						}
						else
						{
							dictionary[text] = value.ToString();
						}
					}
				}
			}
			return dictionary;
		}

		private List<string> ExtractTags(LogEventInfo logEvent, Exception exception)
		{
			List<string> list = new List<string>();
			if (exception != null && exception.Data != null)
			{
				if (exception.Data.Contains("Tags"))
				{
					object tagsData = exception.Data["Tags"];
					list.AddRange(ParseTagsData(tagsData));
				}
				if (exception.Data.Contains("tags"))
				{
					object tagsData2 = exception.Data["tags"];
					list.AddRange(ParseTagsData(tagsData2));
				}
			}
			if (logEvent.Properties.Count > 0)
			{
				if (logEvent.Properties.ContainsKey("Tags"))
				{
					object tagsData3 = logEvent.Properties["Tags"];
					list.AddRange(ParseTagsData(tagsData3));
				}
				if (logEvent.Properties.ContainsKey("tags"))
				{
					object tagsData4 = logEvent.Properties["tags"];
					list.AddRange(ParseTagsData(tagsData4));
				}
			}
			list.Add("Manual");
			return list;
		}

		private static IEnumerable<string> ParseTagsData(object tagsData)
		{
			IEnumerable<string> enumerable = tagsData as IEnumerable<string>;
			string text = tagsData as string;
			if (enumerable != null)
			{
				return enumerable;
			}
			if (text != null)
			{
				return SplitValues(text);
			}
			return Enumerable.Empty<string>();
		}

		private static string[] SplitValues(string input)
		{
			if (!string.IsNullOrWhiteSpace(input))
			{
				return input.Split(new char[1] { ',' }, StringSplitOptions.RemoveEmptyEntries);
			}
			return new string[0];
		}
	}
	public static class RaygunTargetFactory
	{
		public const string DefaultRaygunLogLayout = "${time} [${level}:${var:tag:default=None}] ${message} ${exception:format=ToString,StackTrace}${newline}";

		public static RaygunTarget Create(IRaygunClient client, string logLayout = "${time} [${level}:${var:tag:default=None}] ${message} ${exception:format=ToString,StackTrace}${newline}")
		{
			return new RaygunTarget(client, logLayout);
		}
	}
