	public abstract class BaseCrashReporter : ICrashReporter, IDisposable
	{
		public const string CrashCacheDirName = "crashes";

		private static readonly JsonSerializerSettings jsonDeserializerSettings = new JsonSerializerSettings
		{
			ConstructorHandling = ConstructorHandling.AllowNonPublicDefaultConstructor,
			MetadataPropertyHandling = MetadataPropertyHandling.Ignore
		};

		private const int FeatureFlagCheckTimeoutSeconds = 30;

		protected const string Tag = "CrashReporter";

		public const string ManualTag = "Manual";

		public const string MobileTag = "Mobile";

		public const string CrashTag = "Crash";

		public const string MessageKey = "message";

		public const string BranchKey = "branch";

		public const string S3LogsKey = "s3-logs";

		public const string CurrentViewModelNameKey = "viewmodel";

		public const string UploadLogsS3FeatureDisabledDescription = "The s3 log uploads have been disabled for this raygun report. If you would like to enable them please contact an engineering lead to re-enable it";

		protected readonly IIfitApiService ifitApiService;

		protected readonly ILogFileService logFileService;

		protected readonly IFileService fileService;

		private readonly ICoreAnalytics analytics;

		protected IFeatureFlagManager featureFlagManager;

		protected readonly string branchId;

		protected readonly string currentVersion;

		protected readonly bool isDebugMode;

		private readonly string crashDirPath;

		private IDisposable whenCurrentUserIdChangedSub;

		protected BaseCrashReporter(IIfitApiService ifitApiService, ILogFileService logFileService, IFileService fileService, ICoreAnalytics analytics, string branchId, string version, bool isDebugMode)
		{
			this.ifitApiService = ifitApiService;
			this.logFileService = logFileService;
			this.fileService = fileService;
			this.analytics = analytics;
			this.branchId = branchId;
			currentVersion = version;
			this.isDebugMode = isDebugMode;
			crashDirPath = Path.Combine(logFileService.Config.LogDirPath, "crashes");
		}

		protected virtual void Initialize()
		{
			whenCurrentUserIdChangedSub = ifitApiService.WhenCurrentUserIdChanged.SubscribeAsync((string _) => OnUserChanged());
			Task.Run((Func<Task>)OnUserChanged);
		}

		private async Task OnUserChanged()
		{
			_ = 1;
			try
			{
				User user = ((!ifitApiService.HasLoggedInUser) ? null : (await User.GetMe(ifitApiService, populate: false)));
				User user2 = user;
				if (user2 != null)
				{
					OnUserChanged(user2);
				}
				await UploadPersistedErrors();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("CrashReporter", "BaseCrashReporter - OnUserChanged - Exception", exception);
			}
		}

		public Task ReportError(string message, Exception exception, IDictionary<string, object> customData, bool includeLogFiles = true)
		{
			return ReportError(null, message, exception, includeLogFiles, isManualLog: true, customData);
		}

		public Task ReportError(IList<string> tags, string message, Exception exception, bool includeLogFiles, bool isManualLog)
		{
			return ReportError(tags, message, exception, includeLogFiles, isManualLog, null);
		}

		private async Task ReportError(IList<string> tags, string message, Exception exception, bool includeLogFiles, bool isManualLog, IDictionary<string, object> customData)
		{
			try
			{
				if (string.IsNullOrWhiteSpace(message))
				{
					return;
				}
				if (isDebugMode)
				{
					iFit.Logger.Log.Trace("CrashReporter", "Not reporting \"" + message + "\" because we're in Debug");
					return;
				}
				tags = tags ?? new List<string>();
				string item = (isManualLog ? "Manual" : "Crash");
				if (!tags.Contains(item))
				{
					tags.Add(item);
				}
				if (!tags.Contains("DoNotReport"))
				{
					await SendReport(tags, message, exception, includeLogFiles, customData);
				}
				analytics.ReportRaygunUpload(exception, tags);
				iFit.Logger.Log.Trace("CrashReporter", "Reported error \"" + message + "\" successfully");
			}
			catch (Exception ex)
			{
				UploadFailedRaygunReport(exception, ex, tags, customData);
				iFit.Logger.Log.Error("CrashReporter", "Failed to report error: " + message, ex);
			}
		}

		private async Task SendReport(IList<string> tags, string message, Exception exception, bool includeLogFiles, IDictionary<string, object> customData)
		{
			Dictionary<string, object> dataToUpload = new Dictionary<string, object> { ["message"] = message };
			if (branchId.IsNotNullOrWhiteSpace())
			{
				dataToUpload.Add("branch", branchId);
			}
			customData?.ForEach(delegate(KeyValuePair<string, object> x)
			{
				if (!dataToUpload.ContainsKey(x.Key))
				{
					dataToUpload[x.Key] = x.Value;
				}
			});
			if (includeLogFiles)
			{
				await PrepareErrorReport(tags, dataToUpload);
			}
			SendInBackground(exception, tags, dataToUpload);
		}

		public async Task PersistError(string tag, string message, Exception exception)
		{
			await CrashReporterUtil.Instance.PersistError(crashDirPath, tag, currentVersion, message, exception).ConfigureAwait(continueOnCapturedContext: false);
		}

		private async Task UploadPersistedErrors()
		{
			_ = 2;
			try
			{
				await CrashReporterUtil.Instance.PersistenceLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				await FileSystem.Current.LocalStorage.CreateFolderAsync(crashDirPath, CreationCollisionOption.OpenIfExists).ConfigureAwait(continueOnCapturedContext: false);
				List<IFileInfo> files = fileService.GetFiles(crashDirPath, includeDirectories: false);
				iFit.Logger.Log.Error("CrashReporter", $"Found {files.Count} persisted errors");
				List<Task> list = new List<Task>();
				foreach (IFileInfo item in files)
				{
					if (!item.IsDirectory)
					{
						list.Add(ParseAndUploadCrash(item));
					}
				}
				await Task.WhenAll(list.ToArray());
			}
			finally
			{
				CrashReporterUtil.Instance.PersistenceLock.Release();
			}
		}

		private async Task ParseAndUploadCrash(IFileInfo crash)
		{
			_ = 2;
			try
			{
				IFile file = await crash.GetFileAsync().ConfigureAwait(continueOnCapturedContext: false);
				try
				{
					await ReportErrorFromFile(file, crash.Name);
				}
				catch (Exception ex)
				{
					iFit.Logger.Log.Error("CrashReporter", "Failed to report error " + crash.Name, ex);
					UploadFailedRaygunReport(new RaygunReportGenerateFailedException("Failed to possibly generate raygun report for stored report. See ReasonForFailedUpload in custom data for cause of failure "), ex, new List<string>(), new Dictionary<string, object>());
				}
				await file.DeleteAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex2)
			{
				iFit.Logger.Log.Error("CrashReporter", "Failed to read or delete error report for " + crash.Name, ex2);
				UploadFailedRaygunReport(new RaygunReportGenerateFailedException("Failed to possibly generate raygun report for stored report. See ReasonForFailedUpload in custom data for cause of failure "), ex2, new List<string>(), new Dictionary<string, object>());
			}
		}

		private async Task ReportErrorFromFile(IFile file, string crashName)
		{
			string text = await file.ReadAllTextAsync().ConfigureAwait(continueOnCapturedContext: false);
			CrashReport report = JsonConvert.DeserializeObject<CrashReport>(text, jsonDeserializerSettings);
			if (report == null)
			{
				if (string.IsNullOrWhiteSpace(text))
				{
					iFit.Logger.Log.Error("CrashReporter", "Deleting crash report for file " + crashName + " since it's null or whitespace");
				}
				else
				{
					iFit.Logger.Log.Error("CrashReporter", "Failed to parse report with contents: " + text);
				}
				await ReportError("An unknown problem prevented us from persisting crash information, but a crash did occur. (" + crashName.Split('-').First() + ")", new CrashPersistenceException(), null);
				return;
			}
			if (report.Version == null)
			{
				iFit.Logger.Log.Debug("CrashReporter", "Ignoring old crash report with no version number");
				return;
			}
			if (!report.Version.Equals(currentVersion))
			{
				iFit.Logger.Log.Debug("CrashReporter", "Ignoring crash report from version " + report.Version + " because we are now on version " + currentVersion);
				return;
			}
			bool flag = report.ExceptionType == typeof(iFitAnrError);
			bool flag2 = flag;
			if (flag2)
			{
				flag2 = !(await ShouldUploadAnr(report).ConfigureAwait(continueOnCapturedContext: false));
			}
			if (!flag2)
			{
				Dictionary<string, object> customData = new Dictionary<string, object> { ["viewmodel"] = report.CurrentViewModelName };
				await ReportError(new List<string> { report.Tag }, report.Message, report.Exception, includeLogFiles: true, isManualLog: false, customData).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task<bool> ShouldUploadAnr(CrashReport report)
		{
			bool flag = featureFlagManager == null;
			bool flag2 = flag;
			if (flag2)
			{
				flag2 = !(await FeatureFlagManagerInitialized());
			}
			if (flag2)
			{
				return false;
			}
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.ANRLoggingFeature))
			{
				return false;
			}
			iFitAnrError iFitAnrError2 = new iFitAnrError("iFitAnrError: " + report.Exception.Message + " - " + report.CurrentViewModelName, null);
			if (report.Exception.Data.Count > 0)
			{
				foreach (DictionaryEntry datum in report.Exception.Data)
				{
					iFitAnrError2.Data.Add($"{datum.Key}", $"{datum.Value}");
				}
			}
			iFitAnrError2.SetStackTrace(report.Exception.StackTrace);
			report.Exception = iFitAnrError2;
			return true;
		}

		private async Task<bool> ShouldUploadToS3(IDictionary customData)
		{
			if (!customData.Contains("Manual"))
			{
				return true;
			}
			bool flag = featureFlagManager == null;
			bool flag2 = flag;
			if (flag2)
			{
				flag2 = !(await FeatureFlagManagerInitialized());
			}
			if (flag2)
			{
				return true;
			}
			return featureFlagManager.IsFeatureEnabled(FeatureFlags.ManualReportS3LoggingEnabled);
		}

		private async Task<bool> FeatureFlagManagerInitialized()
		{
			Stopwatch timer = new Stopwatch();
			timer.Start();
			while (featureFlagManager == null && timer.Elapsed < TimeSpan.FromSeconds(30.0))
			{
				await Task.Delay(TimeSpan.FromSeconds(1.0)).ConfigureAwait(continueOnCapturedContext: false);
				Mvx.TryResolve<IFeatureFlagManager>(out featureFlagManager);
			}
			timer.Stop();
			if (featureFlagManager == null || timer.Elapsed >= TimeSpan.FromSeconds(30.0))
			{
				iFit.Logger.Log.Trace("CrashReporter", "Bool flag syncing timed out.");
				return false;
			}
			if ((await (featureFlagManager?.UserSynced.FirstAsync((LaunchDarklySyncState result) => result.Status != LaunchDarklySyncStatus.InProgress))).Status == LaunchDarklySyncStatus.Synced)
			{
				return true;
			}
			iFit.Logger.Log.Trace("CrashReporter", "User Not Synced.");
			return false;
		}

		protected virtual async Task PrepareErrorReport(IList<string> tags, IDictionary customData)
		{
			if (!customData.Contains("s3-logs"))
			{
				List<string> list = ((!(await ShouldUploadToS3(customData))) ? new List<string> { "The s3 log uploads have been disabled for this raygun report. If you would like to enable them please contact an engineering lead to re-enable it" } : (await UploadLogs()));
				List<string> list2 = list;
				if (list2 != null)
				{
					customData["s3-logs"] = list2;
				}
			}
			if (!tags.Contains("Mobile"))
			{
				tags.Insert(0, "Mobile");
			}
			if (!tags.Contains(ifitApiService.Environment.Name))
			{
				tags.Add(ifitApiService.Environment.Name);
			}
		}

		private async Task<List<string>> UploadLogs()
		{
			try
			{
				List<IFileInfo> logFiles = (from x in logFileService.GetLogs()
					where x.Name.Contains("_logs")
					orderby x.CreationTimeUtc descending
					select x).Take(1).ToList();
				List<LogFileUploadResult> logFiles2 = logFileService.PrepareFilesForS3(logFiles);
				return (await logFileService.UploadLogsToS3(logFiles2)).Select((LogFileUploadResult x) => x.LogUrl).ToList();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("CrashReporter", "Failed to upload log files", exception);
				return null;
			}
		}

		private Dictionary<string, object> PrepareFailedRaygunReportException(Exception ex)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			if (ex.InnerException != null)
			{
				dictionary["InnerException"] = PrepareFailedRaygunReportException(ex.InnerException);
			}
			else
			{
				dictionary["ClassName"] = ex.GetType().ToString();
				dictionary["Message"] = ex.Message;
				dictionary["StackTrace"] = ex.StackTrace;
			}
			return dictionary;
		}

		private void UploadFailedRaygunReport(Exception failedException, Exception reasonForFailedException, IList<string> tags, IDictionary<string, object> customData)
		{
			analytics.ReportFailedRaygunReport(failedException, tags, reasonForFailedException);
			Dictionary<string, object> dataToUpload = new Dictionary<string, object>();
			Dictionary<string, object> previousData = new Dictionary<string, object>();
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			customData?.ForEach(delegate(KeyValuePair<string, object> x)
			{
				if (!dataToUpload.ContainsKey(x.Key))
				{
					previousData[x.Key] = x.Value;
				}
			});
			dataToUpload["FailedReportData"] = previousData;
			if (reasonForFailedException.InnerException != null)
			{
				dictionary["ReasonForFailedReportInnerException"] = PrepareFailedRaygunReportException(reasonForFailedException.InnerException);
			}
			else
			{
				dictionary["ReasonForFailedReportClassName"] = reasonForFailedException.GetType().ToString();
				dictionary["ReasonForFailedReportMessage"] = reasonForFailedException.Message;
				dictionary["ReasonForFailedReportStackTrace"] = reasonForFailedException.StackTrace;
			}
			if (failedException is RaygunReportGenerateFailedException)
			{
				dataToUpload["FailedReport"] = dictionary;
				SendInBackground(failedException, tags, dataToUpload);
				return;
			}
			RaygunFailedException exception = new RaygunFailedException("We failed to report a crash to Raygun. See custom data for reason and failed exception.");
			if (failedException.InnerException != null)
			{
				dictionary["FailedReportInnerException"] = PrepareFailedRaygunReportException(failedException.InnerException);
			}
			else
			{
				dictionary["FailedReportClassName"] = failedException?.GetType().ToString();
				dictionary["FailedReportMessage"] = failedException?.Message;
				dictionary["FailedReportStackTrace"] = failedException?.StackTrace;
			}
			dataToUpload["FailedReport"] = dictionary;
			SendInBackground(exception, tags, dataToUpload);
		}

		public virtual void Dispose()
		{
			whenCurrentUserIdChangedSub?.Dispose();
		}

		protected abstract void OnUserChanged(User user);

		protected abstract void SendInBackground(Exception exception, IList<string> tags, IDictionary customData);
	}
	[JsonConverter(typeof(CrashReportSerializer))]
	public class CrashReport
	{
		public string Message { get; set; }

		public string Tag { get; set; }

		public string Version { get; set; }

		public Type ExceptionType { get; set; }

		public string CurrentViewModelName { get; set; }

		public Exception Exception { get; set; }
	}
	public static class CrashReportExtensions
	{
		private static readonly JsonSerializerSettings jsonSettings = new JsonSerializerSettings
		{
			PreserveReferencesHandling = PreserveReferencesHandling.Objects,
			ReferenceLoopHandling = ReferenceLoopHandling.Ignore
		};

		public static string ToJson(this CrashReport report)
		{
			try
			{
				return JsonConvert.SerializeObject(report, jsonSettings);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("CrashReporter", "Error serializing crash report", exception);
			}
			return null;
		}
	}
	public class CrashReportSerializer : JsonConverter
	{
		private const string innerExceptionKey = "InnerException";

		private const string classNameKey = "ClassName";

		private const string remoteStackTraceStringKey = "RemoteStackTraceString";

		private const string remoteStackIndexKey = "RemoteStackIndex";

		private const string stackTraceStringKey = "StackTraceString";

		private const string helpUrlKey = "HelpURL";

		private const string exceptionMethodKey = "ExceptionMethod";

		private const string stackTraceKey = "StackTrace";

		private const string targetSiteKey = "TargetSite";

		private const string signatureKey = "Signature";

		private const string helpLinkKey = "HelpLink";

		public override bool CanWrite => false;

		public override bool CanRead => true;

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			JObject jObject = JObject.Load(reader);
			CrashReport crashReport = (existingValue as CrashReport) ?? new CrashReport();
			crashReport.Message = crashReport.Message ?? ((string?)jObject["Message"]);
			crashReport.Tag = crashReport.Tag ?? ((string?)jObject["Tag"]);
			crashReport.Version = crashReport.Version ?? ((string?)jObject["Version"]);
			crashReport.ExceptionType = crashReport.ExceptionType ?? jObject["ExceptionType"].ToObject<Type>();
			crashReport.CurrentViewModelName = (string?)jObject["CurrentViewModelName"];
			Dictionary<string, object> dictionary = jObject["Exception"].ToObject<Dictionary<string, object>>(serializer);
			bool flag = CheckMissingData(dictionary, crashReport.ExceptionType);
			if (flag)
			{
				PopulateMissingData(dictionary);
			}
			string text = JsonConvert.SerializeObject(dictionary);
			try
			{
				Type type = (flag ? typeof(Exception) : crashReport.ExceptionType);
				object obj = JsonConvert.DeserializeObject(text, type);
				if (obj is Exception exception)
				{
					crashReport.Exception = exception;
				}
			}
			catch (Exception ex)
			{
				crashReport.Message = ex.Message + $"\nFailed with original JSON:{jObject}\nCleaned JSON:{text}";
				crashReport.ExceptionType = ex.GetType();
				crashReport.Exception = ex;
			}
			return crashReport;
		}

		private Dictionary<string, object> PopulateMissingData(Dictionary<string, object> mapping)
		{
			if (!mapping.TryGetValue("ClassName", out var value))
			{
				mapping.TryGetValue("TargetSite", out var value2);
				if (value2 != null)
				{
					(value2 as JObject).ToObject<Dictionary<string, object>>().TryGetValue("ClassName", out var value3);
					mapping["ClassName"] = value3;
				}
				else
				{
					mapping["ClassName"] = typeof(Exception).FullName;
				}
			}
			if (!mapping.TryGetValue("RemoteStackTraceString", out value))
			{
				mapping["RemoteStackTraceString"] = string.Empty;
			}
			if (!mapping.TryGetValue("RemoteStackIndex", out value))
			{
				mapping["RemoteStackIndex"] = 0;
			}
			if (!mapping.TryGetValue("StackTraceString", out value))
			{
				mapping.TryGetValue("StackTrace", out var value4);
				mapping["StackTraceString"] = value4;
			}
			if (!mapping.TryGetValue("HelpURL", out value))
			{
				mapping.TryGetValue("HelpLink", out var value5);
				mapping["HelpURL"] = value5;
			}
			if (!mapping.TryGetValue("ExceptionMethod", out value))
			{
				mapping.TryGetValue("TargetSite", out var value6);
				if (value6 != null)
				{
					(value6 as JObject).ToObject<Dictionary<string, object>>().TryGetValue("Signature", out var value7);
					mapping["ExceptionMethod"] = value7;
				}
				else
				{
					mapping["ExceptionMethod"] = string.Empty;
				}
			}
			if (mapping.TryGetValue("InnerException", out var value8) && !string.IsNullOrWhiteSpace(value8?.ToString()))
			{
				Dictionary<string, object> mapping2 = JsonConvert.DeserializeObject<Dictionary<string, object>>(value8.ToString());
				mapping["InnerException"] = PopulateMissingData(mapping2);
			}
			return mapping;
		}

		private bool CheckMissingData(Dictionary<string, object> mapping, Type exceptionType)
		{
			object value;
			bool flag = mapping.TryGetValue("InnerException", out value) && !string.IsNullOrWhiteSpace(value?.ToString());
			string value2 = JsonConvert.SerializeObject(mapping);
			try
			{
				Exception ex = JsonConvert.DeserializeObject(value2, exceptionType) as Exception;
				if (flag && ex?.InnerException == null)
				{
					return true;
				}
				object value3;
				bool flag2 = mapping.TryGetValue("StackTrace", out value3) && !string.IsNullOrWhiteSpace(value3?.ToString());
				if (string.IsNullOrEmpty(ex?.StackTrace) || (flag2 && !value3.Equals(ex?.StackTrace)))
				{
					return true;
				}
			}
			catch (Exception)
			{
				return true;
			}
			return false;
		}

		public override bool CanConvert(Type objectType)
		{
			return true;
		}
	}
	internal static class ObservableExtensions
	{
		private const string Tag = "Observable";

		private static void EmptyAction(object obj = null)
		{
		}

		internal static IDisposable SubscribeAsync<T>(this IObservable<T> observable, Func<T, Task> onNext, Action<Exception> onError, Action onCompleted)
		{
			return observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe(EmptyAction, onError, onCompleted);
		}

		internal static IDisposable SubscribeAsync<T>(this IObservable<T> observable, Func<T, Task> onNext, Action<Exception> onError)
		{
			return observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe(EmptyAction, onError);
		}

		internal static IDisposable SubscribeAsync<T>(this IObservable<T> observable, Func<T, Task> onNext, Action onCompleted)
		{
			return observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe(EmptyAction, onCompleted);
		}

		internal static IDisposable SubscribeAsync<T>(this IObservable<T> observable, Func<T, Task> onNext)
		{
			return observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe();
		}

		internal static IDisposable SubscribeAsyncWithErrorLogging<T>(this IObservable<T> observable, Func<T, Task> onNext)
		{
			return observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe(EmptyAction, delegate(Exception ex)
			{
				iFit.Logger.Log.Error("Observable", $"{ex}");
			});
		}

		internal static IDisposable SubscribeAsyncWithErrorLogging<T>(this IObservable<T> obs, Func<T, Task> onNext, Action onCompleted)
		{
			return obs.SubscribeAsync(onNext, delegate(Exception ex)
			{
				iFit.Logger.Log.Error("Observable", $"{ex}");
			}, onCompleted);
		}

		internal static void SubscribeAsyncWithErrorLogging<T>(this IObservable<T> observable, Func<T, Task> onNext, CancellationToken token)
		{
			observable.Select((Func<T, Task>)async delegate(T x)
			{
				await onNext(x);
			}).Subscribe(EmptyAction, delegate(Exception ex)
			{
				iFit.Logger.Log.Error("Observable", $"{ex}");
			}, token);
		}
	}
