namespace iFit.CrashReporter.Util
{
	public interface ICrashReporterUtil
	{
		SemaphoreSlim PersistenceLock { get; }

		Task PersistError(string crashDirectoryPath, string tag, string version, string message, Exception exception);

		Task PersistenceLockReleased();

		string CurrentViewModelName();
	}
	public class CrashReporterUtil : ICrashReporterUtil
	{
		private static ICrashReporterUtil _instance;

		private const string Tag = "CrashReporter";

		public static ICrashReporterUtil Instance
		{
			get
			{
				if (Mvx.TryResolve<ICrashReporterUtil>(out var service))
				{
					return service;
				}
				if (_instance == null)
				{
					_instance = new CrashReporterUtil();
				}
				return _instance;
			}
		}

		public SemaphoreSlim PersistenceLock { get; } = new SemaphoreSlim(1);

		private CrashReporterUtil()
		{
		}

		public async Task PersistError(string crashDirectoryPath, string tag, string version, string message, Exception exception)
		{
			if (Mvx.TryResolve<IShireRecoveryStateManager>(out var service))
			{
				service.PrepareToShutdown();
			}
			try
			{
				string currentViewModelName = CurrentViewModelName();
				iFit.Logger.Log.Trace("CrashReporter", $"Waiting for lock to persist error: {message} | {exception.GetType()}");
				await PersistenceLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				iFit.Logger.Log.Trace("CrashReporter", $"Persisting error: {message} | {exception.GetType()}");
				await FileSystem.Current.LocalStorage.CreateFolderAsync(crashDirectoryPath, CreationCollisionOption.OpenIfExists).ConfigureAwait(continueOnCapturedContext: false);
				iFit.Logger.Log.Trace("CrashReporter", "Successfully opened directory for storing crashes at location: " + crashDirectoryPath);
				string fileGuid = $"{exception.GetType()}-{Guid.NewGuid()}";
				IFile file = await FileSystem.Current.LocalStorage.CreateFileAsync(Path.Combine(crashDirectoryPath, fileGuid + ".json"), CreationCollisionOption.GenerateUniqueName).ConfigureAwait(continueOnCapturedContext: false);
				iFit.Logger.Log.Trace("CrashReporter", "Successfully created crash report file named " + fileGuid + ".json");
				if (exception?.InnerException != null)
				{
					iFit.Logger.Log.Trace("CrashReporter", "Adding details of InnerExceptions");
					message = string.Concat(message, Environment.NewLine, "Exception Types from outer to inner: ", Environment.NewLine, string.Concat(from ex in GetInnerExceptions(exception)
						select ex.GetType()?.ToString() + " > "));
				}
				else
				{
					iFit.Logger.Log.Trace("CrashReporter", "No inner exception found--not adding details for those.");
				}
				iFit.Logger.Log.Trace("CrashReporter", "Generating crash report with currentViewModelName: " + currentViewModelName);
				CrashReport crashReport = new CrashReport
				{
					Message = message,
					Tag = tag,
					Version = version,
					ExceptionType = exception.GetType(),
					Exception = exception,
					CurrentViewModelName = currentViewModelName
				};
				iFit.Logger.Log.Trace("CrashReporter", "Converting crash report to json");
				string text = crashReport.ToJson();
				if (string.IsNullOrWhiteSpace(text))
				{
					iFit.Logger.Log.Trace("CrashReporter", "Error while serializing. Will report a CrashSerializationException instead.");
					crashReport.Exception = new CrashSerializationException($"Exception of type {crashReport.ExceptionType} could not be serialized");
					text = crashReport.ToJson();
				}
				else
				{
					iFit.Logger.Log.Trace("CrashReporter", "Successfully converted crash report to json--beginning to write data to " + fileGuid + ".json");
				}
				await file.WriteAllTextAsync(text).ConfigureAwait(continueOnCapturedContext: false);
				iFit.Logger.Log.Trace("CrashReporter", "Finished writing crash data json to file.");
			}
			catch (Exception exception2)
			{
				iFit.Logger.Log.Error("CrashReporter", "Unable to write to file", exception2);
			}
			finally
			{
				PersistenceLock.Release();
				iFit.Logger.Log.Trace("CrashReporter", "Finished persisting error report.  Releasing lock.");
			}
		}

		private IEnumerable<Exception> GetInnerExceptions(Exception ex)
		{
			Exception innerException = ex;
			do
			{
				yield return innerException;
				innerException = innerException.InnerException;
			}
			while (innerException != null);
		}

		public Task PersistenceLockReleased()
		{
			return PersistenceLock.WaitAsync();
		}

		public string CurrentViewModelName()
		{
			try
			{
				if (Mvx.TryResolve<IDialogPresenter>(out var service))
				{
					return service?.CurrentMainViewModel?.GetType().Name ?? string.Empty;
				}
			}
			catch (Exception)
			{
				iFit.Logger.Log.Error("CrashReporter", "CrashReporterUtil caught an exception trying to get CurrentViewModelName");
			}
			return string.Empty;
		}
	}
}
namespace iFit.Api
{
	public class AuthenticatedHttpClientHandler : NativeMessageHandler
	{
		public const string jsonMime = "application/json";

		private const string Bearer = "Bearer";

		private const string Basic = "Basic";

		private const string Both = "Both";

		private readonly IIfitApiService ifitApi;

		protected virtual IConnectivity Connectivity => CrossConnectivity.Current;

		public AuthenticatedHttpClientHandler(IIfitApiService ifitApi)
		{
			this.ifitApi = ifitApi;
			if (ifitApi.GetToken() == null)
			{
				throw new ArgumentNullException("GetToken");
			}
			if (ifitApi.GzipPostData)
			{
				base.AutomaticDecompression = DecompressionMethods.GZip | DecompressionMethods.Deflate;
			}
		}

		protected override async Task<HttpResponseMessage> SendAsync(HttpRequestMessage request, CancellationToken cancellationToken)
		{
			if (request == null)
			{
				iFit.Logger.Log.Error("Api", "Error in AuthenticatedHttpClientHandler, request is null");
				return null;
			}
			if (!Connectivity.IsConnected)
			{
				throw new ConnectivityException(Connectivity.GetType().Name + " reports no internet connection available.", new NoInternetConnectionException());
			}
			HttpRequestHeaders headers = request.Headers;
			headers.Authorization = await ResolveAuthentication(request.Headers.Authorization).ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				if (Mvx.TryResolve<IUserAgent>(out var service))
				{
					request.Headers.Add(service.Name, service.Value);
				}
				else
				{
					request.Headers.Add(UserAgent.Key, UserAgent.Shire);
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Api", "Could not set User-Agent header in AuthenticatedHttpClientHandler", exception);
			}
			string stringRequest = string.Empty;
			if (request.Content != null)
			{
				stringRequest = await request.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false);
			}
			if (string.IsNullOrWhiteSpace(stringRequest))
			{
				stringRequest = "<blank>";
			}
			bool flag = request != null && request.Content?.Headers?.ContentEncoding?.Contains("gzip") == true;
			if (ifitApi.GzipPostData && !flag && request?.Content?.Headers?.ContentType?.MediaType == "application/json" && (request.Method == HttpMethod.Post || request.Method == HttpMethod.Put))
			{
				string text = await request.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (text.Length > 0)
				{
					byte[] array = iFit.Api.Util.Gzip.Compress(text);
					ByteArrayContent byteArrayContent = new ByteArrayContent(array, 0, array.Length);
					byteArrayContent.Headers.Add("Content-Encoding", "gzip");
					byteArrayContent.Headers.Add("Content-Type", "application/json");
					byteArrayContent.Headers.Add("Content-Transfer-Encoding", "binary");
					request.Content = byteArrayContent;
				}
			}
			HttpResponseMessage response;
			try
			{
				response = await ((HttpClientHandler)this).SendAsync(request, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (HttpRequestException ex)
			{
				throw new ConnectivityException(ex.Message, ex);
			}
			catch (OperationCanceledException ex2)
			{
				throw new ConnectivityException(ex2.Message, ex2);
			}
			if (response == null)
			{
				iFit.Logger.Log.Error("Api", "Error in AuthenticatedHttpClientHandler, response was null. " + request.Method.ToString().ToUpper() + " Request Uri: " + (request.RequestUri?.ToString() ?? "<null>") + ", Request Content: " + stringRequest);
			}
			else
			{
				ifitApi.HandleResponse(response);
				try
				{
					if (!response.IsSuccessStatusCode)
					{
						int retryCount = RetryCount(request);
						if ((response.StatusCode == HttpStatusCode.Unauthorized || response.StatusCode == HttpStatusCode.Forbidden) && retryCount < 3)
						{
							await ThrowGlobalErrorIfUnauthorizedRefreshTokenRequest(stringRequest, request, response);
							await ifitApi.RefreshToken();
							request.Headers.Add("x-retry-count", (retryCount + 1).ToString());
							return await SendAsync(request, cancellationToken);
						}
						string text2 = string.Empty;
						if (response.Content != null)
						{
							text2 = await response.Content.ReadAsStringAsync().ConfigureAwait(continueOnCapturedContext: false);
						}
						if (string.IsNullOrWhiteSpace(text2))
						{
							text2 = "<blank>";
						}
						iFit.Logger.Log.Error("Api", $"{request.Method.ToString().ToUpper()} request failed with error code {(int)response.StatusCode} ({response.StatusCode}). " + "Request Uri: " + (request?.RequestUri?.ToString() ?? "<null>") + ", Request Content: '" + stringRequest + "', Response: '" + text2 + "'");
					}
				}
				catch (Exception arg)
				{
					iFit.Logger.Log.Error("Api", $"Issue determining whether or not an API request returned an error: {arg}");
				}
			}
			return response;
		}

		private static bool IsRefreshTokenRequest(string requestString, HttpRequestMessage request)
		{
			if (string.IsNullOrWhiteSpace(requestString) || request == null)
			{
				return false;
			}
			if (request.RequestUri.AbsolutePath.EndsWith("/cockatoo/v2/login/refresh"))
			{
				return true;
			}
			if (!request.RequestUri.AbsolutePath.EndsWith("/oauth/token"))
			{
				return false;
			}
			try
			{
				Dictionary<string, string> dictionary = JsonConvert.DeserializeObject<Dictionary<string, string>>(requestString);
				return dictionary.ContainsKey("grant_type") && dictionary["grant_type"] == "refresh_token";
			}
			catch
			{
			}
			return false;
		}

		private async Task ThrowGlobalErrorIfUnauthorizedRefreshTokenRequest(string requestString, HttpRequestMessage request, HttpResponseMessage response)
		{
			if (!IsRefreshTokenRequest(requestString, request))
			{
				return;
			}
			UnauthorizedAccessException exception = new UnauthorizedAccessException($"Error {response.StatusCode} when trying to refresh token - calling ClearCurrentUser and initiating global error");
			ifitApi.ClearCurrentUser();
			IAppFinishedStartup appFinishedStartup = Mvx.Resolve<IAppFinishedStartup>();
			await appFinishedStartup.WaitForStartUpToComplete();
			IGlobalErrorService globalErrorService = Mvx.Resolve<IGlobalErrorService>();
			globalErrorService.ReportGlobalError(exception, showDialog: false, AppStrings.global_error_authentication_error, forceLogout: true);
			throw exception;
		}

		private int RetryCount(HttpRequestMessage request)
		{
			if (request.Headers.TryGetValues("x-retry-count", out var values))
			{
				return values.Select((string x) => int.TryParse(x, out var result) ? result : 0).Max();
			}
			return 0;
		}

		private async Task<AuthenticationHeaderValue> ResolveAuthentication(AuthenticationHeaderValue auth)
		{
			string scheme;
			string parameter;
			switch (auth?.Scheme)
			{
			case "Bearer":
				scheme = auth.Scheme;
				parameter = await ifitApi.GetToken().ConfigureAwait(continueOnCapturedContext: false);
				break;
			case "Basic":
				scheme = auth.Scheme;
				parameter = ifitApi.BasicAuth;
				break;
			case "Both":
				if (ifitApi.HasLoggedInUser)
				{
					scheme = "Bearer";
					parameter = await ifitApi.GetToken().ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					scheme = "Basic";
					parameter = ifitApi.BasicAuth;
				}
				break;
			default:
				return null;
			}
			auth = new AuthenticationHeaderValue(scheme, parameter);
			return auth;
		}
	}
