		private User GetSpoofedUser()
		{
			if (_currentlyAuthenticatedUser == null)
			{
				return null;
			}
			User user = _currentlyAuthenticatedUser.DeepClone();
			IIfitApiInjectionService ifitApiInjectionService = injectionService;
			if (ifitApiInjectionService != null && ifitApiInjectionService.GetSpoofedSubscriptionType.HasValue)
			{
				user.SubscriptionType = injectionService.GetSpoofedSubscriptionType.GetValueOrDefault();
				user.Premium = user.SubscriptionType == User.SubscriptionTypes.Premium || user.SubscriptionType == User.SubscriptionTypes.CoachPlus;
			}
			IIfitApiInjectionService ifitApiInjectionService2 = injectionService;
			if (ifitApiInjectionService2 != null && ifitApiInjectionService2.ShouldSpoofIsPlanetFitnessUser)
			{
				user.IsPlanetFitnessUser = true;
			}
			return user;
		}

		public IfitApiService(IBlobCacheService cacheService, IIfitEnvironment environment, IAuthenticatedHttpClientHandlerFactory authHandlerFactory, bool gzipPostData = true, IIfitApiInjectionService injectionService = null)
		{
			Cache = cacheService.LocalMachine;
			SecureCache = cacheService.Secure;
			GzipPostData = gzipPostData;
			this.authHandlerFactory = authHandlerFactory;
			this.injectionService = injectionService;
			SwitchEnvironment(environment);
		}

		public T GetGatewayService<T>() where T : class, IGenericIFitGatewayApi
		{
			gatewayServices.TryGetValue(typeof(T), out var value);
			if (value == null)
			{
				throw new Exception($"Service of type {typeof(T)} not found");
			}
			return value as T;
		}

		public T GetDevGatewayService<T>() where T : class, IGenericIFitGatewayApi
		{
			if (Environment.EnvironmentType != iFit.Api.Environments.Environments.Test)
			{
				return null;
			}
			devGatewayServices.TryGetValue(typeof(T), out var value);
			if (value == null)
			{
				throw new Exception($"Service of type {typeof(T)} not found");
			}
			return value as T;
		}

		public async Task<User> RefreshCurrentlyAuthenticatedUser()
		{
			if (CurrentlyAuthenticatedUser == null)
			{
				return null;
			}
			_currentlyAuthenticatedUser = await User.GetMe(this, populate: false, force: true);
			return _currentlyAuthenticatedUser;
		}

		protected virtual AuthenticatedHttpClientHandler CreateAuthHandler()
		{
			return authHandlerFactory.Create(this);
		}

		public void SwitchEnvironment(IIfitEnvironment environment)
		{
			clientId = environment.ClientId;
			clientSecret = environment.ClientSecret;
			BasicAuth = Base64Encode(clientId + ":" + clientSecret);
			AuthenticatedHttpClientHandler handler = CreateAuthHandler();
			string uriString = environment.Endpoint;
			if (_useDebugEndpoint)
			{
				uriString = environment.DebugEndpoint;
			}
			RefitSettings settings = new RefitSettings
			{
				ContentSerializer = new NewtonsoftJsonContentSerializer(JsonSerializerSettings)
			};
			userInitiatedClient = new HttpClient(handler)
			{
				BaseAddress = new Uri(uriString)
			};
			if (_useDebugEndpoint)
			{
				userInitiatedClient.DefaultRequestHeaders.Add("X-Moesif-Application-Id", environment.MoesifApplicationId);
			}
			gatewayApiClient = new HttpClient(handler)
			{
				BaseAddress = new Uri(environment.BaseGatewayAPIUrl)
			};
			gatewayApi = RestService.For<IIFitGatewayApi>(gatewayApiClient);
			smsApiClient = new HttpClient(handler)
			{
				BaseAddress = new Uri(environment.BaseSmsAPIUrl)
			};
			smsApi = RestService.For<IIFitSmsGatewayApi>(smsApiClient);
			userInitiated = RestService.For<IIfitApi>(userInitiatedClient, settings);
			gatewayServices.Clear();
			foreach (IFitGatewayApiSetup gatewayServiceSetup in gatewayServiceSetups)
			{
				gatewayServices.Add(gatewayServiceSetup.ServiceType, gatewayServiceSetup.GenerateRestService(gatewayApiClient) as IGenericIFitGatewayApi);
			}
			devEnvironment = null;
			devGatewayApiClient = null;
			devGatewayServices.Clear();
			if (environment.EnvironmentType == iFit.Api.Environments.Environments.Test)
			{
				devEnvironment = new IfitDevEnvironment(new string[1] { environment.ClientId }, new string[1] { environment.ClientSecret });
				devGatewayApiClient = new HttpClient(handler)
				{
					BaseAddress = new Uri(devEnvironment.BaseGatewayAPIUrl)
				};
				foreach (IFitGatewayApiSetup devGatewayServiceSetup in devGatewayServiceSetups)
				{
					devGatewayServices.Add(devGatewayServiceSetup.ServiceType, devGatewayServiceSetup.GenerateRestService(devGatewayApiClient) as IGenericIFitGatewayApi);
				}
			}
			junoApiClient = new HttpClient(handler)
			{
				BaseAddress = new Uri(environment.BaseJunoAPIUrl)
			};
			junoApi = RestService.For<IIFitJunoApi>(junoApiClient);
			_environment = environment;
			_whenApiEnvironmentChanged.OnNext(_environment);
		}

		public async Task InitCache()
		{
			await ssCache.WaitAsync();
			try
			{
				if (!cacheInitialized)
				{
					await ConvertAuthenticatedUsersIfNecessary();
					try
					{
						string id = await SecureCache.GetObject<string>("currently-authenticated-user-id");
						CurrentlyAuthenticatedUser = await SecureCache.GetObject<User>(User.UserKeyForId(id));
					}
					catch (KeyNotFoundException)
					{
						iFit.Logger.Log.Trace("Api", "currently-authenticated-user-id was not found in the cache in InitCache");
					}
					await GetAuthenticatedUsers();
					cacheInitialized = true;
				}
			}
			catch (Exception ex2)
			{
				iFit.Logger.Log.Trace("Api", "Error initializing cache: " + ex2.ToString());
				throw;
			}
			finally
			{
				ssCache.Release();
			}
		}

		public async Task ResetEnvironment()
		{
			iFit.Logger.Log.Trace("Api", $"Resetting environment, # of authed users: {AuthenticatedUsers?.Count}");
			List<User> authenticatedUsers = AuthenticatedUsers;
			if (authenticatedUsers != null && authenticatedUsers.Count > 0)
			{
				await Logout(logoutAllUsers: true);
			}
			await Cache.InvalidateAll().ToTask().ConfigureAwait(continueOnCapturedContext: false);
			iFit.Logger.Log.Trace("Api", "ResetEnvironment has successfully cleared Cache");
			await SecureCache.InvalidateAll().ToTask().ConfigureAwait(continueOnCapturedContext: false);
			iFit.Logger.Log.Trace("Api", "ResetEnvironment has successfully cleared SecureCache");
		}

		public static string Base64Encode(string plainText)
		{
			byte[] bytes = Encoding.UTF8.GetBytes(plainText);
			return Convert.ToBase64String(bytes);
		}

		public async Task<LoginResult> Login(string username, string password, bool forceLogin)
		{
			if (!forceLogin)
			{
				List<User> source = await GetAuthenticatedUsers();
				if (source.Any((User x) => (x != null && x.Username?.Equals(username, StringComparison.OrdinalIgnoreCase) == true) || (x != null && x.Email?.Equals(username, StringComparison.OrdinalIgnoreCase) == true)))
				{
					if (CurrentlyAuthenticatedUser == null)
					{
						CurrentlyAuthenticatedUser = source.FirstOrDefault((User x) => (x != null && x.Username?.Equals(username, StringComparison.OrdinalIgnoreCase) == true) || (x != null && x.Email?.Equals(username, StringComparison.OrdinalIgnoreCase) == true));
						await GetToken();
					}
					return LoginResult.AlreadyLoggedIn;
				}
			}
			try
			{
				AuthTokenRequest authTokenRequest = new AuthTokenRequest
				{
					ClientId = clientId,
					ClientSecret = clientSecret,
					Password = password,
					Username = username
				};
				Token = await authTokenRequest.PasswordFlow(this);
				return await LoginAfterTokenUpdate(LoginProvider.ifit);
			}
			catch (ApiException ex) when (ex.StatusCode == HttpStatusCode.Forbidden)
			{
				return LoginResult.InvalidPassword;
			}
			catch (Exception ex2)
			{
				iFit.Logger.Log.Error("Api", "Failure to Authenticate", ex2.GetBaseException());
				return LoginResult.UnknownFailure;
			}
		}

		public async Task<LoginResult> Login(string username, string password)
		{
			return await Login(username, password, forceLogin: false).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task<LoginResult> LoginViaProvider(string accessToken, LoginProvider provider)
		{
			List<User> source = await GetAuthenticatedUsers();
			if (source.Any((User x) => x.Facebook == accessToken || x.Google == accessToken))
			{
				if (CurrentlyAuthenticatedUser == null)
				{
					CurrentlyAuthenticatedUser = source.FirstOrDefault((User x) => x.Facebook == accessToken || x.Google == accessToken);
					await GetToken();
				}
				return LoginResult.AlreadyLoggedIn;
			}
			try
			{
				ThirdPartyAuthTokenRequest authTokenRequest = new ThirdPartyAuthTokenRequest
				{
					ClientId = clientId,
					ClientSecret = clientSecret,
					Provider = provider.ToString(),
					ProviderToken = accessToken
				};
				Token = await Service.AuthProviderFlow(authTokenRequest);
				return await LoginAfterTokenUpdate(provider);
			}
			catch (ApiException ex)
			{
				if (ex.StatusCode == HttpStatusCode.Forbidden)
				{
					try
					{
						AuthenticateViaProviderError authenticateViaProviderError = JsonConvert.DeserializeObject<AuthenticateViaProviderError>(ex.Content);
						if (provider != LoginProvider.ifit && "Provider user is not an iFIT user.".Equals(authenticateViaProviderError.Message))
						{
							return LoginResult.NeedsThirdPartyAssociation;
						}
					}
					catch (Exception ex2)
					{
						iFit.Logger.Log.Error("Api", "Failed deserializing non-iFIT user", ex2.GetBaseException());
					}
				}
				return LoginResult.UnknownFailure;
			}
			catch (Exception ex3)
			{
				iFit.Logger.Log.Error("Api", "Failed AuthenticateViaProvider", ex3.GetBaseException());
				return LoginResult.UnknownFailure;
			}
		}

		public async Task<LoginResult> LoginWithIfitToken(AuthToken token)
		{
			Token = token;
			return await LoginAfterTokenUpdate(LoginProvider.ifit);
		}

		private async Task<LoginResult> LoginAfterTokenUpdate(LoginProvider provider)
		{
			try
			{
				if (!Token.IsValidToken())
				{
					return LoginResult.InvalidToken;
				}
				await AddAuthenticatedUserToCache(Token);
			}
			catch (ApiException ex)
			{
				iFit.Logger.Log.Error("Api", $"Failed to login with {provider} due to AuthenticateAfterTokenUpdate", ex.GetBaseException());
				return LoginResult.UnknownFailure;
			}
			catch (SubscriptionTypeNotSupportedException)
			{
				return LoginResult.SubscriptionTypeNotSupported;
			}
			catch (FormatException ex3)
			{
				iFit.Logger.Log.Error("Api", "Failed to login due to " + ex3.Message, ex3);
				return LoginResult.UnknownFailure;
			}
			return LoginResult.Success;
		}

		public async Task<string> GetToken()
		{
			_ = 5;
			try
			{
				await ssToken.WaitAsync();
				if (Token?.AccessToken == null)
				{
					if (CurrentlyAuthenticatedUser == null)
					{
						string id = await SecureCache.GetObject<string>("currently-authenticated-user-id");
						CurrentlyAuthenticatedUser = await SecureCache.GetObject<User>(User.UserKeyForId(id));
					}
					Token = await SecureCache.GetObject<AuthToken>(userAuthTokenKey);
					if (Token == null)
					{
						iFit.Logger.Log.Error("Api", "Token returned from the SecureCache was null, returning null.");
						return null;
					}
					if (Token.AccessToken == null)
					{
						iFit.Logger.Log.Error("Api", "Token.AccessToken returned from the SecureCache was null, returning null.");
						return null;
					}
				}
				if (Token.AlmostExpired)
				{
					Token = await GetRefreshedToken();
					await SecureCache.InsertObject(userAuthTokenKey, Token);
				}
				return Token.AccessToken;
			}
			catch (NullReferenceException exception)
			{
				iFit.Logger.Log.Error("Api", "IfitApiService: GetToken Null Exception", exception);
				return null;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "IfitApiService: GetToken Exception", ex.GetBaseException());
				return null;
			}
			finally
			{
				ssToken.Release();
			}
		}

		public virtual async Task<string> RefreshToken()
		{
			_ = 2;
			string accessToken;
			try
			{
				await ssToken.WaitAsync();
				Token = await GetRefreshedToken();
				await SecureCache.InsertObject(userAuthTokenKey, Token);
				accessToken = Token.AccessToken;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "IfitApiService: RefreshToken Exception", ex.GetBaseException());
				return null;
			}
			finally
			{
				ssToken.Release();
			}
			_whenAccessTokenRefreshed.OnNext(accessToken);
			return accessToken;
		}

		private bool IsJwt(string token)
		{
			Regex regex = new Regex("^[^. ]+\\.[^.]+\\.[^.]+$");
			return regex.IsMatch(token);
		}

		protected async Task<AuthToken> GetRefreshedToken()
		{
			RefreshTokenRequest refreshTokenRequest = new RefreshTokenRequest
			{
				ClientId = clientId,
				ClientSecret = clientSecret,
				RefreshToken = Token.RefreshToken
			};
			if (IsJwt(Token.AccessToken))
			{
				return (await GatewayService.RefreshAuth0Token(refreshTokenRequest))?.ToAuthToken();
			}
			return await Service.RefreshOAuthToken(refreshTokenRequest);
		}

		public async Task Logout(bool logoutAllUsers = false)
		{
			_whenLoggingOut.OnNext(Unit.Default);
			if (logoutAllUsers)
			{
				iFit.Logger.Log.Trace("Api", "Logging out all users");
				await SecureCache.Invalidate("authenticated-user-ids");
				iFit.Logger.Log.Trace("Api", "SecureCache has removed AuthenticatedUserIdsKey from the cache");
				await SecureCache.InvalidateAllObjects<AuthToken>();
				iFit.Logger.Log.Trace("Api", "SecureCache has removed AuthToken from the cache");
				AuthenticatedUsers = null;
			}
			else
			{
				await RemoveAuthenticatedUserFromCache(CurrentlyAuthenticatedUser);
				iFit.Logger.Log.Trace("Api", "Logged out current user");
			}
			await SecureCache.Invalidate("currently-authenticated-user-id");
			CurrentlyAuthenticatedUser = null;
			Token = null;
		}

		public async Task Logout(string userNameOrEmail)
		{
			if (UserMatchesUserNameOrEmail(CurrentlyAuthenticatedUser))
			{
				await Logout();
				return;
			}
			User user = AuthenticatedUsers?.FirstOrDefault(UserMatchesUserNameOrEmail);
			if (user != null)
			{
				iFit.Logger.Log.Trace("Api", "Logging out user: " + user.Id);
				await RemoveAuthenticatedUserFromCache(user);
				_whenCurrentUserIdChanged.OnNext(_currentlyAuthenticatedUser?.Id);
			}
			else
			{
				iFit.Logger.Log.Trace("Api", "Logging out user: none");
			}
			bool UserMatchesUserNameOrEmail(User user2)
			{
				if (user2 != null)
				{
					if (!userNameOrEmail.Equals(user2.Username))
					{
						return userNameOrEmail.Equals(user2.Email);
					}
					return true;
				}
				return false;
			}
		}

		public void ClearCurrentUser()
		{
			CurrentlyAuthenticatedUser = null;
			Token = null;
			User.ClearCurrentCachedUser();
		}

		public async Task SwitchUser(string userId)
		{
			iFit.Logger.Log.Trace("User", "Attempting to switch to user with id [" + userId + "]");
			List<User> list = await GetAuthenticatedUsers();
			iFit.Logger.Log.Trace("User", "Got " + list.Count + " authenticated users.");
			User newUser = list.LastOrDefault((User x) => x.Id == userId);
			if (newUser == null)
			{
				iFit.Logger.Log.Trace("User", "Failed to find authenticated user while switching [id: " + userId + "]");
				throw new Exception("no authenticated user for that ID");
			}
			iFit.Logger.Log.Trace("User", "The user with id [" + userId + "] is authenticated.");
			Token = await SecureCache.GetObject<AuthToken>(newUser.Id + "-auth-token");
			CurrentlyAuthenticatedUser = newUser;
			iFit.Logger.Log.Trace("User", "Got AuthToken and set CurrentlyAuthenticatedUser to user with id [" + userId + "].");
			if (!(await VerifyUserAndToken()))
			{
				iFit.Logger.Log.Trace("User", "The user cache got corrupted so we are invalidating the cache and sending the user back to the login screen.");
				CurrentlyAuthenticatedUser = null;
				Token = null;
				await SecureCache.InvalidateAll();
				return;
			}
			if (Token.IsExpired)
			{
				iFit.Logger.Log.Trace("User", "AuthToken for user with id [" + userId + "] is expired.");
				Token = await GetRefreshedToken();
				iFit.Logger.Log.Trace("User", "Got refreshed AuthToken for user with id [" + userId + "].");
				await SecureCache.InsertObject(newUser.Id + "-auth-token", Token);
				iFit.Logger.Log.Trace("User", "Inserted AuthToken for user with id [" + userId + "].");
			}
			await SecureCache.InsertObject("currently-authenticated-user-id", CurrentlyAuthenticatedUser.Id);
			iFit.Logger.Log.Trace("User", "Successfully switched to user with id [" + userId + "]");
		}

		private async Task<bool> VerifyUserAndToken()
		{
			User user = await User.FetchMe(this);
			if (CurrentlyAuthenticatedUser.Id == user.Id)
			{
				return true;
			}
			return false;
		}

		public async Task<List<User>> GetAuthenticatedUsers()
		{
			if (AuthenticatedUsers == null)
			{
				AuthenticatedUsers = new List<User>();
				List<string> authenticatedUserIds = await GetAuthenticatedUserIds();
				List<string> userIdsToRemove = new List<string>();
				foreach (string userId in authenticatedUserIds)
				{
					try
					{
						User user = await SecureCache.GetObject<User>(User.UserKeyForId(userId));
						if (user != null)
						{
							AuthenticatedUsers.Add(user);
						}
					}
					catch (KeyNotFoundException exception)
					{
						iFit.Logger.Log.Trace("User", "Could not find a user for id [" + userId + "]");
						userIdsToRemove.Add(userId);
						if (Mvx.TryResolve<ICoreAnalytics>(out var service))
						{
							service.HandledKeyNotFoundForUserError(userId, exception);
						}
					}
				}
				if (userIdsToRemove.Count > 0)
				{
					List<string> value = authenticatedUserIds.Except(userIdsToRemove).ToList();
					await SecureCache.InsertObject("authenticated-user-ids", value);
				}
			}
			return AuthenticatedUsers;
		}

		public async Task InvalidateUserMemoryCache()
		{
			AuthenticatedUsers = null;
			await GetAuthenticatedUsers();
			_currentlyAuthenticatedUser = await SecureCache.GetObject<User>(User.UserKeyForId(CurrentlyAuthenticatedUserId));
		}

