		public void SetNextResponse(HttpStatusCode? httpStatusCode)
		{
			nextResponseStatusCode = httpStatusCode;
		}

		public void HandleResponse(HttpResponseMessage response)
		{
			if (response != null && nextResponseStatusCode.HasValue)
			{
				response.StatusCode = nextResponseStatusCode.Value;
				nextResponseStatusCode = null;
			}
		}

		private async Task AddAuthenticatedUserToCache(AuthToken token)
		{
			await GetAuthenticatedUsers();
			List<string> userIds = await GetAuthenticatedUserIds();
			User me = await User.FetchMe(this);
			iFit.Logger.Log.Trace("User", "Attempting to add user to authenticated users list [id: " + me.Id + "]");
			if (me.SubscriptionType == User.SubscriptionTypes.PremiumNonEquipment)
			{
				Token = null;
				iFit.Logger.Log.Trace("User", $"Can not add {User.SubscriptionTypes.PremiumNonEquipment} users to auth list [id: {me.Id}]");
				throw new SubscriptionTypeNotSupportedException("PremiumNonEquipment users are not supported");
			}
			CurrentlyAuthenticatedUser = me;
			if (!userIds.Contains(me.Id))
			{
				userIds.Add(me.Id);
				AuthenticatedUsers.Add(me);
			}
			await SecureCache.InsertObject(userAuthTokenKey, token);
			await SecureCache.InsertObject(User.UserKeyForId(CurrentlyAuthenticatedUser.Id), CurrentlyAuthenticatedUser);
			await SecureCache.InsertObject("currently-authenticated-user-id", CurrentlyAuthenticatedUser.Id);
			await SecureCache.InsertObject("authenticated-user-ids", userIds);
			iFit.Logger.Log.Trace("User", "Finished adding user to authenticated users list [id: " + me.Id + "]");
		}

		private async Task RemoveAuthenticatedUserFromCache(User user)
		{
			try
			{
				await cacheRemovalSemaphore.WaitAsync();
				iFit.Logger.Log.Trace("User", "Attempting to remove user from authenticated users list [id: " + user.Id + "]");
				List<string> value = (await GetAuthenticatedUserIds()).Where((string x) => x != user.Id).ToList();
				await SecureCache.InsertObject("authenticated-user-ids", value);
				await SecureCache.Invalidate(User.UserKeyForId(user.Id));
				User.ClearCurrentCachedUser();
				int num = AuthenticatedUsers.FindIndex((User x) => x.Id == user.Id);
				if (num >= 0 && num < AuthenticatedUsers.Count)
				{
					AuthenticatedUsers.RemoveAt(num);
				}
				await SecureCache.InvalidateObject<AuthToken>(user.Id + "-auth-token");
			}
			catch (KeyNotFoundException ex)
			{
				iFit.Logger.Log.Error("Api", "Error Removing Cached User:" + user.Id + " - " + ex.Message, ex);
			}
			finally
			{
				iFit.Logger.Log.Trace("User", "Finished attempting to remove user from auth list [id: " + user.Id + "]");
				cacheRemovalSemaphore.Release();
			}
		}

		private async Task<List<string>> GetAuthenticatedUserIds()
		{
			List<string> list;
			try
			{
				list = await SecureCache.GetObject<List<string>>("authenticated-user-ids");
				iFit.Logger.Log.Trace("User", $"Found {list.Count} users on authenticated user list.");
			}
			catch (KeyNotFoundException)
			{
				iFit.Logger.Log.Trace("User", "No authenticated user list found in cache.  Initializing a new list.");
				list = new List<string>();
			}
			return list;
		}

		private async Task ConvertAuthenticatedUsersIfNecessary()
		{
			IEnumerable<string> source = await SecureCache.GetAllKeys().FirstAsync();
			iFit.Logger.Log.Trace("Api", $"SecureCache has {source.Count()} keys");
			iFit.Logger.Log.Trace("Api", string.Format("SecureCache contains AuthenticatedUserIdsKey: {0}", source.Contains("authenticated-user-ids")));
			iFit.Logger.Log.Trace("Api", string.Format("SecureCache does not contain AuthenticatedUsersKey: {0}", !source.Contains("authenticated-users")));
			iFit.Logger.Log.Trace("Api", string.Format("SecureCache contains CurrentlyAuthenticatedUserIdKey: {0}", source.Contains("currently-authenticated-user-id")));
			iFit.Logger.Log.Trace("Api", string.Format("SecureCache does not contain CurrentlyAuthenticatedUserKey: {0}", !source.Contains("currently-authenticated-user")));
			if (source.Contains("authenticated-user-ids") || !source.Contains("authenticated-users") || source.Contains("currently-authenticated-user-id") || !source.Contains("currently-authenticated-user"))
			{
				return;
			}
			List<string> authenticatedUserIds = new List<string>();
			foreach (User user in await SecureCache.GetObject<List<User>>("authenticated-users"))
			{
				await SecureCache.InsertObject(User.UserKeyForId(user.Id), user);
				authenticatedUserIds.Add(user.Id);
			}
			await SecureCache.InsertObject("authenticated-user-ids", authenticatedUserIds);
			await SecureCache.Invalidate("authenticated-users");
			User currentlyAuthenticatedUser = await SecureCache.GetObject<User>("currently-authenticated-user");
			await SecureCache.InsertObject(User.UserKeyForId(currentlyAuthenticatedUser.Id), currentlyAuthenticatedUser);
			await SecureCache.InsertObject("currently-authenticated-user-id", currentlyAuthenticatedUser.Id);
			await SecureCache.Invalidate("currently-authenticated-user");
		}

		public async Task<bool> DeleteAccount()
		{
			try
			{
				string id = CurrentlyAuthenticatedUser.Id;
				await Service.DeleteAccount(id).ConfigureAwait(continueOnCapturedContext: false);
				return true;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "Failed DeleteAccount", ex.GetBaseException());
			}
			return false;
		}

		public async Task PrepareForBounce()
		{
			await ssCache.WaitAsync();
			try
			{
				IEnumerable<string> enumerable = await SecureCache.GetAllKeys().FirstAsync();
				string[] source = (enumerable as string[]) ?? enumerable.ToArray();
				iFit.Logger.Log.Trace("Api", "Preparing for bounce by disposing caches");
				iFit.Logger.Log.Trace("Api", $"SecureCache has {source.Count()}");
				iFit.Logger.Log.Trace("Api", string.Format("SecureCache contains AuthenticatedUserIdsKey: {0}", Enumerable.Contains(source, "authenticated-user-ids")));
				iFit.Logger.Log.Trace("Api", string.Format("SecureCache contains CurrentlyAuthenticatedUserIdKey: {0}", Enumerable.Contains(source, "currently-authenticated-user-id")));
				SecureCache.DisposeIfDisposable();
				Cache.DisposeIfDisposable();
				SecureCache.Shutdown.Wait();
				Cache.Shutdown.Wait();
				iFit.Logger.Log.Trace("Api", "Preparing for bounce caches disposed");
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Trace("Api", "Preparing for bounce failed", exception);
			}
			finally
			{
				ssCache.Release();
			}
		}
	}
