namespace iFit.Api.Util
{
	public interface IBlobCacheService
	{
		IBlobCache Secure { get; set; }

		IBlobCache LocalMachine { get; }

		void Wipe();

		Task Flush(object value, string valueName, string originClassName, string userSpecificId = "", bool temp = false);

		Task<T> GetFromCache<T>(string valueName, string originClassName, string userSpecificId = "", bool temp = false, T defaultValue = default(T));
	}
	public class BlobCacheService : IBlobCacheService, IDisposable
	{
		private const string Tag = "BlobCacheService";

		public IBlobCache Secure { get; set; }

		public IBlobCache LocalMachine { get; private set; }

		public BlobCacheService(IBlobCache secure, IBlobCache localMachine)
		{
			Secure = secure;
			LocalMachine = localMachine;
		}

		public void Dispose()
		{
			Secure?.Dispose();
			LocalMachine?.Dispose();
			Secure = null;
			LocalMachine = null;
		}

		public void Wipe()
		{
			iFit.Logger.Log.Trace("BlobCacheService", "Attempting to wipe Secure cache");
			CacheUtil.WipeEntireCache(Secure);
			iFit.Logger.Log.Trace("BlobCacheService", "Attempting to wipe LocalMachine cache");
			CacheUtil.WipeEntireCache(LocalMachine);
		}

		public string CreateKey(string originClassName, string valueName, string userSpecificId)
		{
			string text = "";
			if (userSpecificId.IsEmpty())
			{
				return originClassName + "." + valueName;
			}
			return originClassName + "." + valueName + "." + userSpecificId;
		}

		public async Task Flush(object value, string valueName, string originClassName, string userSpecificId = "", bool temp = false)
		{
			string key = CreateKey(originClassName, valueName, userSpecificId);
			try
			{
				if (temp)
				{
					await LocalMachine.InsertObject(key, value);
				}
				else
				{
					await Secure.InsertObject(key, value);
				}
			}
			catch (SQLiteException ex)
			{
				iFit.Logger.Log.Error("BlobCacheService", $"Caught a SQLiteException in Flush. Result: {ex.Result}, Message: {ex.Message}");
				IFatalityService fatalityService = Mvx.Resolve<IFatalityService>();
				fatalityService.ReportFatalEvent(ex, AppStrings.database_malformed_error);
			}
		}

		public async Task<T> GetFromCache<T>(string valueName, string originClassName, string userSpecificId = "", bool temp = false, T defaultValue = default(T))
		{
			string key = CreateKey(originClassName, valueName, userSpecificId);
			try
			{
				if (temp)
				{
					return await LocalMachine.GetObject<T>(key);
				}
				return await Secure.GetObject<T>(key);
			}
			catch (KeyNotFoundException ex)
			{
				iFit.Logger.Log.Error("BlobCacheService", "Caught a KeyNotFoundException in GetFromCache. " + ex.Message);
			}
			return defaultValue;
		}
	}
	public static class CacheUtil
	{
		private const string Tag = "Cache";

		private static readonly object cacheWipeLock = new object();

		private static readonly SemaphoreSlim ss = new SemaphoreSlim(1);

		public static void WipeEntireCache(IBlobCache cache, bool handleExceptions = true)
		{
			if (cache == null)
			{
				return;
			}
			lock (cacheWipeLock)
			{
				try
				{
					cache.InvalidateAll().Wait();
					cache.Flush().Wait();
					cache.Vacuum().Wait();
					iFit.Logger.Log.Trace("Cache", "Cache has successfully been cleared");
				}
				catch (Exception ex)
				{
					if (!handleExceptions)
					{
						throw;
					}
					iFit.Logger.Log.Error("Cache", "Exception thrown when attempting to invalidate, flush, and vacuum cache in WipeEntireCache", ex.GetBaseException());
				}
			}
		}

		public static async Task WipeEntireCacheAsync(IBlobCache cache, bool handleExceptions = true)
		{
			if (cache == null)
			{
				return;
			}
			await ss.WaitAsync();
			try
			{
				await cache.InvalidateAll();
				await cache.Flush();
				await cache.Vacuum();
				iFit.Logger.Log.Trace("Cache", "Cache has successfully been cleared");
			}
			catch (Exception ex)
			{
				if (!handleExceptions)
				{
					throw;
				}
				iFit.Logger.Log.Error("Cache", "Exception thrown when attempting to invalidate, flush, and vacuum cache in WipeEntireCacheAsync", ex.GetBaseException());
			}
			finally
			{
				ss.Release();
			}
		}
	}
	internal static class Gzip
	{
		internal static byte[] Compress(string content)
		{
			using MemoryStream memoryStream = new MemoryStream();
			using (GZipStream destination = new GZipStream(memoryStream, CompressionMode.Compress))
			{
				using MemoryStream memoryStream2 = new MemoryStream(Encoding.UTF8.GetBytes(content));
				memoryStream2.CopyTo(destination);
			}
			return memoryStream.ToArray();
		}

		internal static string Decompress(byte[] content)
		{
			using MemoryStream stream = new MemoryStream(content);
			using GZipStream gZipStream = new GZipStream(stream, CompressionMode.Decompress);
			using MemoryStream memoryStream = new MemoryStream();
			gZipStream.CopyTo(memoryStream);
			byte[] array = memoryStream.ToArray();
			return Encoding.UTF8.GetString(array, 0, array.Length);
		}
	}
	internal class UnixTimeConverter : DateTimeConverterBase
	{
		protected static readonly DateTime _epoch = new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			if (value == null || (DateTime)value < _epoch)
			{
				writer.WriteValue(0);
			}
			else
			{
				writer.WriteValue(Math.Round(((DateTime)value - _epoch).TotalMilliseconds).ToString());
			}
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			if (reader.Value == null)
			{
				return null;
			}
			if (reader.Value is long num && num <= 0)
			{
				return _epoch;
			}
			long num2 = ((reader.Value is long num3) ? num3 : Convert.ToInt64((string)reader.Value));
			return _epoch.AddMilliseconds(num2);
		}
	}
	internal class UnixTimeConverterLong : UnixTimeConverter
	{
		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			if (value == null || (DateTime)value < UnixTimeConverter._epoch)
			{
				writer.WriteValue(0);
				return;
			}
			double value2 = Math.Round(((DateTime)value - UnixTimeConverter._epoch).TotalMilliseconds);
			writer.WriteValue(value2);
		}
	}
