	internal class WorkoutContextConverter : StringEnumConverter
	{
		private const string OnDemandStr = "ondemand";

		private const string ScheduledLiveStr = "scheduledLive";

		private const string ScheduledPreStr = "scheduledPre";

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			switch ((Workout.WorkoutContext)value)
			{
			case Workout.WorkoutContext.ScheduledLive:
				writer.WriteValue("scheduledLive");
				break;
			case Workout.WorkoutContext.ScheduledPre:
				writer.WriteValue("scheduledPre");
				break;
			default:
				writer.WriteValue("ondemand");
				break;
			}
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			string text = reader.Value as string;
			if (text == "scheduledLive")
			{
				return Workout.WorkoutContext.ScheduledLive;
			}
			if (text == "scheduledPre")
			{
				return Workout.WorkoutContext.ScheduledPre;
			}
			return Workout.WorkoutContext.OnDemand;
		}
	}
