namespace iFit.Api.Gateway.DataObjects
{
	public static class StreetView
	{
		public static async Task<byte[]> Get(IIFitGatewayApiService api, int width, int height, double lat, double lng, double heading, CancellationToken token = default(CancellationToken))
		{
			token.ThrowIfCancellationRequested();
			return await (await api.Service.StreetView(lat.ToString(CultureInfo.InvariantCulture), lng.ToString(CultureInfo.InvariantCulture), heading.ToString(CultureInfo.InvariantCulture), width, height, redirect: false, token)).Content.ReadAsByteArrayAsync();
		}
	}
