			string text = "--";
			string text2 = "--";
			if (BpmRange.CountSafe() > 2)
			{
				text = BpmRange[0].ToString();
				text2 = BpmRange[1].ToString();
			}
			return $"WidgetState: {WidgetState} BpmRange: {text}-{text2} HasAchievedCurrentZone: {HasAchievedCurrentZone} TriggerPause: {TriggerPause} Scale: {Scale}";
		}
	}
