		public async Task<ActivityLog> Create(IIfitApiService api)
		{
			ActivityLog result = await WebDataObject.DefaultPolicy.ExecuteAsync(() => (!string.IsNullOrEmpty(UserId)) ? api.Service.CreateActivityLog(this) : api.Service.CreateActivityLogAnonymous(this));
			if (result != null)
			{
				await api.SecureCache.InsertObject(result.Id, result, DateTimeOffset.Now.AddDays(90.0));
			}
			else
			{
				iFit.Logger.Log.Fatal("Api", "CreateActivityLog returned a null ActivityLog without throwing an exception, which should never happen. Workout id: " + WorkoutId + ", Wolf Generated Id: " + WolfGeneratedId + ", User Id: " + UserId);
			}
			return result;
		}

		public async Task<ActivityLog> CreatePrivate(IIfitApiService api)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.CreatePrivateActivityLog(this));
		}

		public static async Task Delete(IIfitApiService api, string id)
		{
			await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				await api.Service.DeleteActivityLog(id);
			});
		}

		public static async Task<ActivityLog> Get(IIfitApiService api, string id, bool force = false)
		{
			if (force)
			{
				await api.SecureCache.InvalidateObject<ActivityLog>(id);
			}
			return await api.SecureCache.GetOrFetchObject(id, fetch, DateTimeOffset.Now.AddDays(90.0));
			async Task<ActivityLog> fetch()
			{
				return await FetchActivityLog(api, id);
			}
		}

		protected static async Task<ActivityLog> FetchActivityLog(IIfitApiService api, string id)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetActivityLog(id));
		}

		public static async Task<List<ActivityLog>> Search(IIfitApiService api, Query query = null, int page = 1, int perPage = 30)
		{
			string type = ((query?.Type == null) ? null : string.Join(",", query.Type));
			long? before = ((query == null || !query.Before.HasValue) ? ((long?)null) : WebDataObject.DateTimeToUnix(query.Before.Value));
			long? after = ((query == null || !query.After.HasValue) ? ((long?)null) : WebDataObject.DateTimeToUnix(query.After.Value));
			return await api.Service.SearchActivityLogs(before, after, type, query?.WorkoutId, query?.ListWorkoutId, page.ToString(), perPage.ToString(), query?.Trim, query?.FilterRedundant ?? false);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!isDisposed)
			{
				if (disposing)
				{
					Stats?.Dispose();
					Stats = null;
				}
				isDisposed = true;
			}
		}

		public virtual void Dispose()
		{
			Dispose(disposing: true);
		}
	}
