	}
	public class RefreshTokenRequest
	{
		public string ClientId { get; set; }

		public string ClientSecret { get; set; }

		public string GrantType { get; set; } = "refresh_token";

		public string RefreshToken { get; set; }
	}
	public class AuthToken
	{
		public string AccessToken { get; set; }

		public string RefreshToken { get; set; }

		public string TokenType { get; set; }

		public int ExpiresIn { get; set; }

		public DateTime CreatedAt { get; set; } = DateTime.Now;

		[JsonIgnore]
		public DateTime ExpiresAt => CreatedAt.AddSeconds(ExpiresIn);

		[JsonIgnore]
		public bool IsExpired => CheckIfExpired(DateTime.Now);

		[JsonIgnore]
		public bool AlmostExpired => CheckIfExpired(DateTime.Now + TimeSpan.FromHours(1.0));

		protected bool CheckIfExpired(DateTime currentTime)
		{
			return (ExpiresAt - currentTime).TotalSeconds <= 0.0;
		}

		public bool IsValidToken()
		{
			if (string.IsNullOrWhiteSpace(AccessToken))
			{
				return false;
			}
			if (IsExpired)
			{
				return false;
			}
			return true;
		}
	}
	public class Auth0Token
	{
		[JsonProperty(PropertyName = "access_token")]
		public string AccessToken { get; set; }

		[JsonProperty(PropertyName = "refresh_token")]
		public string RefreshToken { get; set; }

		[JsonProperty(PropertyName = "token_type")]
		public string TokenType { get; set; }

		[JsonProperty(PropertyName = "expires_in")]
		public int ExpiresIn { get; set; }

		public DateTime CreatedAt { get; set; } = DateTime.Now;

		public AuthToken ToAuthToken()
		{
			return new AuthToken
			{
				AccessToken = AccessToken,
				RefreshToken = RefreshToken,
				TokenType = TokenType,
				ExpiresIn = ExpiresIn,
				CreatedAt = CreatedAt
			};
		}
	}
