			}
			TaskCompletionSource<ObservableCollection<Challenge>> tcs = new TaskCompletionSource<ObservableCollection<Challenge>>();
			ObservableCollection<Challenge> result = null;
			api.Cache.GetAndFetchLatest(key, fetch, (DateTimeOffset x) => true, DateTimeOffset.Now.AddDays(14.0)).Subscribe(delegate(List<Challenge> x)
			{
				if (result == null)
				{
