		{
			[JsonConverter(typeof(StringEnumConverter))]
			public Genders? Gender { get; set; }

			[JsonConverter(typeof(StringEnumConverter))]
			public Groups? Group { get; set; }

			[JsonConverter(typeof(StringEnumConverter))]
			public EquipmentStyle? Equipment { get; set; }

