		public static async Task<List<ChallengeStandings>> Get(IIfitApiService api, string id, Query query = null, bool force = false)
		{
			string key = api.CurrentlyAuthenticatedUserId + "-challengstandings-" + id;
			if (force)
			{
				await api.Cache.InvalidateObject<List<ChallengeStandings>>(key);
			}
			TaskCompletionSource<List<ChallengeStandings>> tcs = new TaskCompletionSource<List<ChallengeStandings>>();
			List<ChallengeStandings> result = null;
			api.Cache.GetAndFetchLatest(key, fetch, (DateTimeOffset x) => true, DateTimeOffset.Now.AddDays(1.0)).Subscribe(delegate(List<ChallengeStandings> x)
			{
				if (result == null)
				{
					result = x;
					tcs.SetResult(result);
				}
				else
				{
					result.Clear();
					result.AddRange(x);
				}
			});
			return await tcs.Task;
			async Task<List<ChallengeStandings>> fetch()
			{
				return await FetchStandings(api, id, query);
			}
		}

		public static async Task<List<ChallengeStandings>> FetchStandings(IIfitApiService api, string id, Query query)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				IIfitApi service = api.Service;
				string id2 = id;
				Query query2 = query;
				string gender = ((query2 != null) ? query2.Gender.GetAttribute<EnumMemberAttribute>().Value : null);
				Query query3 = query;
				string obj = ((query3 != null) ? query3.Group.GetAttribute<EnumMemberAttribute>().Value : null);
				Query query4 = query;
				return await service.GetChallengeStandings(id2, gender, obj, (query4 != null) ? query4.Equipment.GetAttribute<EnumMemberAttribute>().Value : null, query?.MinAge, query?.MaxAge);
			});
		}
	}
