		public static async Task<List<T>> Get<T>(IIfitApiService api, Model model = Model.Workouts, int page = 1, int per_page = 99, string notType = "", bool force = false) where T : WebDataObject
		{
			string cacheKey = CacheKey(api, model);
			if (model == Model.Workouts)
			{
				if (force)
				{
					await api.Cache.InvalidateObject<List<T>>(cacheKey);
				}
				return (page != 1 || per_page != 99) ? (await FetchFavoriteWorkouts<T>(api, page, per_page, notType)) : (await GetOrFetchFavoriteWorkouts<T>(api, cacheKey, page, per_page, notType));
			}
			throw new ArgumentException("no matching favorite model " + model);
		}

