			try
			{
				await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
				{
					await api.Service.DeleteFavorite(relatedModel.GetAttribute<EnumMemberAttribute>().Value, relatedId);
				});
			}
			catch (Exception)
			{
				return false;
			}
			return true;
		}

		private static async Task InvalidateFavorites(IIfitApiService api, Model relatedModel)
		{
			string key = CacheKey(api, relatedModel);
			if (relatedModel == Model.Workouts)
			{
				await api.Cache.InvalidateObject<List<Workout>>(key);
				return;
			}
			throw new ArgumentException("no matching favorite model " + relatedModel);
		}

		private static string CacheKey(IIfitApiService api, Model favoriteModel)
		{
			string text = api?.CurrentlyAuthenticatedUserId ?? "nouser";
