			UserNewsProfile
		}

		public class Query
		{
			[JsonConverter(typeof(iFit.Api.Util.UnixTimeConverter))]
			public DateTime Before { get; set; }

			[JsonConverter(typeof(iFit.Api.Util.UnixTimeConverter))]
			public DateTime After { get; set; }

			public FeedType[] Filter { get; set; }

			public bool? ExludeWearableData { get; set; }
		}

		public string Id { get; set; }

		public string User { get; set; }

		public string RelatedModel { get; set; }

