		public static async Task<ObservableCollection<Feed>> Get(IIfitApiService api, FeedGroup type, Query query = null, string id = null, bool force = false)
		{
			string key = api.CurrentlyAuthenticatedUserId + type.GetAttribute<EnumMemberAttribute>().Value;
			if (force)
			{
				await api.SecureCache.InvalidateObject<List<Feed>>(key);
			}
			TaskCompletionSource<ObservableCollection<Feed>> tcs = new TaskCompletionSource<ObservableCollection<Feed>>();
			ObservableCollection<Feed> result = null;
			IObservable<List<Feed>> andFetchLatest = api.SecureCache.GetAndFetchLatest(key, fetch, (DateTimeOffset x) => true, DateTimeOffset.Now.AddDays(1.0));
			andFetchLatest.Subscribe(delegate(List<Feed> x)
			{
				if (result == null)
				{
					result = new ObservableCollection<Feed>(x);
					tcs.SetResult(result);
				}
				else
				{
					MergeLists.Merge(result, x, (Feed k) => k.Id);
				}
			});
			return await tcs.Task;
			async Task<List<Feed>> fetch()
			{
				return await FetchFeeds(api, type, id, query);
			}
		}

		public static async Task<List<Feed>> FetchFeeds(IIfitApiService api, FeedGroup type, string id, Query query)
		{
			Query query2 = query;
			int num;
			if (query2 == null)
			{
				num = 1;
			}
			else
			{
				_ = query2.Before;
				num = 0;
			}
			long? _before = ((num != 0) ? ((long?)null) : WebDataObject.DateTimeToUnix((query?.Before).Value));
			Query query3 = query;
			int num2;
			if (query3 == null)
			{
				num2 = 1;
			}
			else
			{
				_ = query3.After;
				num2 = 0;
			}
			long? _after = ((num2 != 0) ? ((long?)null) : WebDataObject.DateTimeToUnix((query?.After).Value));
			string _filter = ((query?.Filter == null) ? null : string.Join(",", query.Filter.Select((FeedType f) => f.GetAttribute<EnumMemberAttribute>().Value)));
			return type switch
			{
				FeedGroup.Community => await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetCommunityFeed(_before, _after, _filter, query?.ExludeWearableData)), 
				FeedGroup.Profile => await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetProfileFeed(_before, _after, _filter, query?.ExludeWearableData)), 
				_ => await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetNewsProfileFeed(id, _before, _after, _filter, query?.ExludeWearableData)), 
			};
		}
	}
