	public class HowlNotifications
	{
		public class TriggerMessage
		{
			[JsonIgnore]
			private int next;

			public string TriggerName { get; set; }

			public string TriggerType { get; set; }

			public string ActionMessage { get; set; }

			public List<string> Messages { get; set; }

			public string NextMessage()
			{
				return Messages[next++ % Messages.Count];
			}

			public void LanguageTokenizing(string token, string value)
			{
				for (int i = 0; i < Messages.Count; i++)
				{
					Messages[i] = Messages[i].Replace(token, value);
				}
			}
		}

		public List<TriggerMessage> TriggerBasedNotifications { get; set; }
	}
