	public class LatLng : GeoCoordinate
	{
		private string _id;

		public string Id => _id ?? (_id = Guid.NewGuid().ToString());

		public double Lat
		{
			get
			{
				return base.Latitude;
			}
			set
			{
				base.Latitude = value;
			}
		}

		public double Lng
		{
			get
			{
				return base.Longitude;
			}
			set
			{
				base.Longitude = value;
			}
		}

		public bool SnappedToRoad { get; set; }

		public LatLng()
		{
		}

		public LatLng(double latitude, double longitude, bool snappedToRoad = false)
			: base(latitude, longitude)
		{
			SnappedToRoad = snappedToRoad;
		}

		public LatLng Copy()
		{
			if (base.IsUnknown)
			{
				return new LatLng();
			}
			return new LatLng(Lat, Lng);
		}

		public void ExplicitlySetId(string id)
		{
			_id = id;
		}

		public override string ToString()
		{
			return string.Format(CultureInfo.InvariantCulture, "{0},{1}", base.Latitude, base.Longitude);
		}

		public bool Equals(LatLng p)
		{
			return Id.Equals(p?.Id);
		}

		public static bool operator ==(LatLng p1, LatLng p2)
		{
			if ((object)p1 == p2)
			{
				return true;
			}
			if ((object)p1 == null || (object)p2 == null)
			{
				return false;
			}
			return p1.Equals(p2);
		}

		public static bool operator !=(LatLng p1, LatLng p2)
		{
			return !(p1 == p2);
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			return Id.Equals((obj as LatLng)?.Id);
		}

		public override int GetHashCode()
		{
			return Id.GetHashCode();
		}
	}
	public class LatLngAtDistance
	{
		public LatLng LatLng { get; set; }

		public double Meters { get; set; }

		public LatLngAtDistance(double meters, LatLng latlng)
		{
			LatLng = latlng;
			Meters = meters;
		}

		public List<LatLngAtDistance> GetPointsBetween(LatLngAtDistance end, double minMetersBetween)
		{
			List<LatLngAtDistance> list = new List<LatLngAtDistance>();
			double num = LatLng.GetDistanceTo(end.LatLng) / minMetersBetween;
			if (num < 1.0)
			{
				list.Add(end);
				return list;
			}
			double num2 = (end.LatLng.Lat - LatLng.Lat) / num;
			double num3 = (end.LatLng.Lng - LatLng.Lng) / num;
			LatLngAtDistance latLngAtDistance = this;
			for (double num4 = 1.0; num4 <= num; num4 += 1.0)
			{
				LatLng latLng = new LatLng(LatLng.Lat + num4 * num2, LatLng.Lng + num4 * num3);
				double meters = latLngAtDistance.Meters + latLngAtDistance.LatLng.GetDistanceTo(latLng);
				LatLngAtDistance latLngAtDistance2 = new LatLngAtDistance(meters, latLng);
				latLngAtDistance = latLngAtDistance2;
				list.Add(latLngAtDistance2);
			}
			return list;
		}

		public double GetDistanceTo(LatLngAtDistance end)
		{
			return LatLng.GetDistanceTo(end.LatLng);
		}
	}
