			Workout,
			[EnumMember(Value = "generic")]
			Generic
		}

		public class Query
		{
			public string[] Ids { get; set; }

			public bool? Viewed { get; set; } = false;

			[JsonConverter(typeof(StringEnumConverter))]
			public Types? Type { get; set; }
		}

		public string Id { get; set; }

		public string Description { get; set; }

		public bool Viewed { get; set; }

		[JsonConverter(typeof(StringEnumConverter))]
		public Types Type { get; set; }

		[JsonConverter(typeof(iFit.Api.Util.UnixTimeConverter))]
		public DateTime Created { get; set; }

		public static async Task<Notification> Get(IIfitApiService api, string id)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetNotification(id));
		}

		public static async Task<ObservableCollection<Notification>> MyNotifications(IIfitApiService api, Query query = null, bool force = false)
		{
			string key = api.CurrentlyAuthenticatedUserId + "-notifications";
			if (force)
			{
				await api.Cache.InvalidateObject<List<Notification>>(key);
			}
			TaskCompletionSource<ObservableCollection<Notification>> tcs = new TaskCompletionSource<ObservableCollection<Notification>>();
			ObservableCollection<Notification> result = null;
			api.Cache.GetAndFetchLatest(key, fetch, (DateTimeOffset x) => true, DateTimeOffset.Now.AddDays(1.0)).Subscribe(delegate(List<Notification> x)
			{
				if (result == null)
				{
					result = new ObservableCollection<Notification>(x);
					tcs.SetResult(result);
				}
				else
				{
					MergeLists.Merge(result, x, (Notification k) => k.Id);
				}
			});
			return await tcs.Task;
			async Task<List<Notification>> fetch()
			{
				return await FetchNotifications(api, query);
			}
		}

		public static async Task<List<Notification>> FetchNotifications(IIfitApiService api, Query query)
		{
			string _ids = ((query?.Ids == null) ? null : string.Join(",", query.Ids));
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				IIfitApi service = api.Service;
				string ids = _ids;
				Query query2 = query;
				return await service.GetNotifications(ids, (query2 != null) ? query2.Type.GetAttribute<EnumMemberAttribute>().Value : null, query?.Viewed);
			});
		}

		public async Task<Notification> Update(IIfitApiService api, bool viewed = true)
		{
			Viewed = viewed;
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.UpdateNotification(Id, this));
		}

		public static async Task<bool> Delete(IIfitApiService api, string id)
		{
			try
			{
				await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
				{
					await api.Service.DeleteNotification(id);
				});
			}
			catch (Exception)
			{
				return false;
			}
			return true;
		}
	}
