	public class PromoCode : WebDataObject
	{
		public string Code { get; set; }

		public string Title { get; set; }

		public string Description { get; set; }

		public int PercentDiscount { get; set; }

		public string[] Items { get; set; }

		public bool BypassBilling { get; set; }

		[JsonConverter(typeof(iFit.Api.Util.NullableUnixTimeConverter))]
		public DateTime? StartDate { get; set; }

		[JsonConverter(typeof(iFit.Api.Util.NullableUnixTimeConverter))]
		public DateTime? EndDate { get; set; }

		[JsonIgnore]
		public bool IsValid
		{
			get
			{
				if ((!StartDate.HasValue || DateTime.UtcNow >= StartDate.Value) && (!EndDate.HasValue || DateTime.UtcNow <= EndDate.Value))
				{
					string[] items = Items;
					if (items == null)
					{
						return false;
					}
					return items.Length >= 1;
				}
				return false;
			}
		}

		public static async Task<PromoCode> GetPromoCode(IIfitApiService api, string code, bool force = false)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.RetrievePromoCode(code));
		}
	}
