			HttpClient httpClient = new HttpClient();
			try
			{
				HttpResponseMessage httpResponseMessage = await httpClient.GetAsync(ImageUrl);
				string text = httpResponseMessage?.RequestMessage?.RequestUri?.ToString();
				iFit.Logger.Log.Info("Images", "User Avatar ImageUrl: " + ImageUrl);
				if (text != null && (text.Contains("71c982465d-male.jpg") || text.Contains("865ed62ecb-female.jpg")))
				{
					return null;
				}
				using MemoryStream ms = new MemoryStream(await httpResponseMessage.Content.ReadAsByteArrayAsync());
				return await BitmapLoader.Current.Load(ms, null, null);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "Error loading user image url: " + ex.Message);
				return null;
			}
		}

		public async Task<User> Create(IIfitApiService api)
		{
			if (Id != null)
			{
				throw new Exception("user already exists");
			}
			if (Email == null || Username == null || Password == null)
			{
				throw new Exception("create is missing a required field");
			}
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.CreateUser(this));
		}

		public virtual async Task<User> CreateWithUsernameConflictResolution(IIfitApiService api)
		{
			if (Id != null)
			{
				throw new Exception("user already exists");
			}
			if (Email == null || Username == null || Password == null)
			{
				throw new Exception("create is missing a required field");
			}
			Random random = new Random();
			string usernameFormat = Username + "{0:000}";
			int attempts = 0;
			int num = 4 - Username.Length;
			if (num > 0)
			{
				Username = Username.LengthenByXChars(num);
			}
			while (await ExistsWithUsername(api, Username))
			{
				Username = string.Format(usernameFormat, random.Next(0, 999));
				int num2 = attempts + 1;
				attempts = num2;
				if (num2 >= 5)
				{
					throw new Exception("user already exists");
				}
			}
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.CreateUser(this));
		}

