		public static async Task<User> GetMe(IIfitApiService api, bool populate = true, bool force = false)
		{
			if (force || DateTime.UtcNow.Subtract(LastTimeGetMeInvalidated).TotalMinutes > (double)MaximumGetMeValidationMinutes)
			{
				User freshUser = await fetch();
				if (freshUser != null)
				{
					await api.SecureCache.InsertObject(UserKeyForId(freshUser.Id), freshUser);
					if (populate)
					{
						await getConfig(api, freshUser, force);
					}
					LastTimeGetMeInvalidated = DateTime.UtcNow;
					meCached = freshUser;
				}
			}
			if (meCached == null)
			{
				meCached = await api.SecureCache.GetOrFetchObject(UserKeyForId(api.CurrentlyAuthenticatedUserId), fetch);
				if (meCached == null)
				{
					return null;
				}
				if (populate)
				{
					await getConfig(api, meCached, force);
				}
			}
			return meCached;
			Task<User> fetch()
			{
				return FetchMe(api);
			}
			static Task getConfig(IIfitApiService api2, User user, bool force2)
			{
				Task<UserSettings> settings = user.GetSettings(api2, force2);
				Task<UserPreferences> preferences = user.GetPreferences(api2, force2);
				return Task.WhenAll(settings, preferences);
			}
		}

