				if (ex.StatusCode != HttpStatusCode.NotFound)
				{
					iFit.Logger.Log.Error("Api", $"User.GetPrimary - id: {id} returned status {ex.StatusCode}");
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Api", "Problem when calling User.GetPrimary with id " + id, exception);
			}
			return false;
		}

