		public async Task LinkFacebookAccount(IIfitApiService api, string token = null)
		{
			if (Id == null)
			{
				throw new FacebookLinkingException("Link to facebook is only for existing saved users with an id.");
			}
			if (!string.Equals(Id, api.CurrentlyAuthenticatedUserId))
			{
				throw new FacebookLinkingException("Can only link the currently authenticated user from facebook");
			}
			string fbToken = token ?? Facebook;
			if (string.IsNullOrWhiteSpace(fbToken))
			{
				throw new FacebookLinkingException("Can not connect to facebook without the token. Pass it in or set the Facebook field of the user object");
			}
			try
			{
				await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
				{
					await api.Service.LinkFacebookAccount(fbToken);
				});
			}
			catch (ApiException ex)
			{
				if (ex.StatusCode == HttpStatusCode.BadRequest)
				{
					throw new FacebookLinkingException("Invalid facebook token provided to the web API");
				}
				throw;
			}
		}

		public async Task UnlinkFacebookAccount(IIfitApiService api)
		{
			if (Id == null)
			{
				throw new FacebookLinkingException("Unlink from facebook is only for existing saved objects with an id.");
			}
			if (!string.Equals(Id, api.CurrentlyAuthenticatedUserId))
			{
				throw new FacebookLinkingException("Can only unlink the currently authenticated user from facebook");
			}
			await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				await api.Service.UnlinkFacebookAccount();
			});
		}

