	public class UserHeartRateSettings : WebDataObject
	{
		public List<ZoneData> HeartRateZones;

		private List<ZoneData> heartRateZonesCache;

		private List<UserHeartRateZone> zonesFromApiCache;

		private readonly SemaphoreSlim hrZonesSemaphore = new SemaphoreSlim(1, 1);

		[JsonIgnore]
		private List<UserHeartRateZone> _zones = new List<UserHeartRateZone>();

		public int RestingHeartRate { get; set; }

		public int MaxHeartRate { get; set; }

		public int HeartRateReserve { get; set; }

		[JsonIgnore]
		public List<UserHeartRateZone> Zones
		{
			get
			{
				hrZonesSemaphore.Wait();
				try
				{
					if (heartRateZonesCache.IsNullOrEmpty() || !HeartRateZones.SequenceEqual(heartRateZonesCache))
					{
						zonesFromApiCache = HeartRateZones?.Where((ZoneData x) => x != null && x.Count >= 2).Select((ZoneData x, int index) => new UserHeartRateZone(index + 1, x[0], (index == 4) ? x[1] : (x[1] - 1))).ToList();
						heartRateZonesCache = HeartRateZones;
					}
					return zonesFromApiCache.IsNullOrEmpty() ? _zones : zonesFromApiCache;
				}
				finally
				{
					hrZonesSemaphore.Release();
				}
			}
			set
			{
				_zones = value;
			}
		}

		public void UpdateWith(UserHeartRateSettings settings)
		{
			hrZonesSemaphore.Wait();
			try
			{
				if (settings != null)
				{
					RestingHeartRate = settings.RestingHeartRate;
					MaxHeartRate = settings.MaxHeartRate;
					HeartRateReserve = settings.HeartRateReserve;
					HeartRateZones = settings.HeartRateZones;
				}
				else
				{
					RestingHeartRate = 0;
					MaxHeartRate = 0;
					HeartRateReserve = 0;
					HeartRateZones = new List<ZoneData>();
				}
			}
			finally
			{
				hrZonesSemaphore.Release();
			}
		}

		public double BpmToInterpolatedZone(double bpm)
		{
			if (Zones.Count == 0)
			{
				return 0.0;
			}
			UserHeartRateZone userHeartRateZone = Zones.First();
			if (bpm < (double)userHeartRateZone.MinBpm)
			{
				return 0.0;
			}
			foreach (UserHeartRateZone zone in Zones)
			{
				if (bpm <= (double)zone.MaxBpm)
				{
					return (double)zone.ZoneNumber + (bpm - (double)zone.MinBpm) / (double)(zone.MaxBpm - zone.MinBpm);
				}
			}
			return Zones.Last().ZoneNumber;
		}
	}
	public class ZoneData : List<int>
	{
	}
	public class UserHeartRateZone
	{
		public int ZoneNumber { get; private set; }

		public int MinBpm { get; private set; }

		public int MaxBpm { get; private set; }

		public int MinPercentage { get; private set; }

		public int MaxPercentage { get; private set; }

		public UserHeartRateZone(int zoneNumber, int minBpm, int maxBpm)
		{
			ZoneNumber = zoneNumber;
			MinBpm = minBpm;
			MaxBpm = maxBpm;
			DetermineZonePercentages();
		}

		private void DetermineZonePercentages()
		{
			switch (ZoneNumber)
			{
			case 1:
				MinPercentage = 50;
				MaxPercentage = 60;
				break;
			case 2:
				MinPercentage = 60;
				MaxPercentage = 70;
				break;
			case 3:
				MinPercentage = 70;
				MaxPercentage = 80;
				break;
			case 4:
				MinPercentage = 80;
				MaxPercentage = 90;
				break;
			case 5:
				MinPercentage = 90;
				MaxPercentage = 100;
				break;
			default:
				MinPercentage = 0;
				MaxPercentage = 50;
				break;
			}
		}
	}
