	public class WebDataObject
	{
		protected static DateTime Epoch = new DateTime(1970, 1, 1, 0, 0, 0);

		public static readonly AsyncRetryPolicy DefaultPolicy = Policy.Handle<WebException>().Or((ConnectivityException x) => !(x.InnerException is NoInternetConnectionException)).WaitAndRetryAsync(3, (int retryAttempt) => TimeSpan.FromSeconds(Math.Pow(2.0, retryAttempt)));

		public static long? DateTimeToUnix(DateTime dateTime)
		{
			return (long)dateTime.Subtract(Epoch).TotalMilliseconds;
		}

		protected async Task CheckPendingCreateConnectivity<T>(IBlobCache cache, string userId, bool ifDisconnectedTryAgainLater) where T : WebDataObject, IPendingCreate
		{
			if (ifDisconnectedTryAgainLater && !CrossConnectivity.Current.IsConnected)
			{
				(this as T).RequestingUserId = userId;
				PendingCreateItem<T> pendingCreateItem = new PendingCreateItem<T>
				{
					PendingItem = (T)this,
					Key = "pending" + DateTime.Now.ToString("O")
				};
				await cache.InsertObject(pendingCreateItem.Key, pendingCreateItem, DateTimeOffset.Now.AddDays(30.0));
				throw new ConnectivityException("not connected, will try to upload later");
			}
		}
	}
