		public class Path : IDeepCloneable<Path>, IDeepCloneable, IDisposable
		{
			public const double MinimumDistance = 3.0;

			protected List<LatLngAtDistance> _latLngsAtDistances { get; set; }

			[JsonIgnore]
			public List<LatLngAtDistance> LatLngsAtDistances
			{
				get
				{
					if (_latLngsAtDistances == null)
					{
						UpdateDistanceLatLng();
					}
					return _latLngsAtDistances;
				}
			}

			public string Type { get; set; }

			public List<List<double>> Coordinates { get; set; }

			public List<LatLng> LatLngs => Coordinates?.Where((List<double> x) => x != null && x.Count >= 2)?.Select((List<double> x) => new LatLng(x[1], x[0]))?.ToList();

			public LatLng LatLngAtMeter(double meters)
			{
				meters = Math.Max(meters, 0.0);
				if (_latLngsAtDistances == null)
				{
					UpdateDistanceLatLng();
				}
				return _latLngsAtDistances.Last((LatLngAtDistance x) => x.Meters <= meters).LatLng;
			}

			public void UpdateDistanceLatLng()
			{
				List<LatLng> latLngs = LatLngs;
				_latLngsAtDistances = new List<LatLngAtDistance>();
				if (latLngs.CountSafe() >= 1)
				{
					_latLngsAtDistances.Add(new LatLngAtDistance(0.0, latLngs[0]));
					for (int i = 1; i < latLngs.Count; i++)
					{
						LatLngAtDistance latLngAtDistance = _latLngsAtDistances.Last();
						double meters = latLngAtDistance.Meters + latLngAtDistance.LatLng.GetDistanceTo(latLngs[i]);
						LatLngAtDistance end = new LatLngAtDistance(meters, latLngs[i]);
						_latLngsAtDistances.AddRange(latLngAtDistance.GetPointsBetween(end, 3.0));
					}
				}
			}

			public void Dispose()
			{
				_latLngsAtDistances?.Clear();
				_latLngsAtDistances = null;
				Coordinates?.Clear();
				Coordinates = null;
			}

			public Path DeepClone()
			{
				return new Path
				{
					Coordinates = Coordinates?.Select((List<double> x) => x.ToList()).ToList(),
					Type = Type
				};
			}

			object IDeepCloneable.DeepClone()
			{
				return DeepClone();
			}
		}

