		public class Control : TimestampedValue, IDeepCloneable<Control>, IDeepCloneable
		{
			public enum ControlType
			{
				[EnumMember(Value = "incline")]
				Incline,
				[EnumMember(Value = "mps")]
				Mps,
				[EnumMember(Value = "resistance")]
				Resistance,
				[EnumMember(Value = "gear")]
				Gear,
				[EnumMember(Value = "rpm")]
				Rpm,
				[EnumMember(Value = "watts")]
				Watts,
				[EnumMember(Value = "calories")]
				Calories,
				[EnumMember(Value = "zone")]
				Zone,
				[EnumMember(Value = "relativeResistance")]
				RelativeResistance,
				[EnumMember(Value = "spm")]
				SPM,
				[EnumMember(Value = "estimated_bpm")]
				EstimatedBPM
			}

			private const double DefaultStandardMps = 0.44704;

			private const double DefaultMetricMps = 0.555556;

			public bool OverriddenByUser { get; set; }

			public bool HasBeenSent { get; set; }

			public bool SentToResetOverrideByUser { get; set; }

			[JsonConverter(typeof(StringEnumConverter))]
			public ControlType Type { get; set; }

			public bool IsDefaultStartSpeed()
			{
				if (!base.Value.AlmostEqual(0.555556))
				{
					return base.Value.AlmostEqual(0.44704);
				}
				return true;
			}

			public bool IsAlmostDefaultValue(int decimalPlaces)
			{
				switch (Type)
				{
				case ControlType.Mps:
					if (!base.Value.AlmostEqual(0.555556, decimalPlaces))
					{
						return base.Value.AlmostEqual(0.44704, decimalPlaces);
					}
					return true;
				case ControlType.Gear:
					return base.Value.AlmostEqual(1.0, decimalPlaces);
				case ControlType.Incline:
					return base.Value.AlmostEqual(0.0, decimalPlaces);
				case ControlType.Resistance:
				case ControlType.RelativeResistance:
					return base.Value.AlmostEqual(1.0, decimalPlaces);
				default:
					return base.Value.AlmostEqual(0.0, decimalPlaces);
				}
			}

			public override string ToString()
			{
				return $"[Control: At={base.At}, Value={base.Value}, Type={Type}, Overridden={OverriddenByUser}, HasBeenSet={HasBeenSent}]";
			}

			public new Control DeepClone()
			{
				return new Control
				{
					At = base.At,
					Value = base.Value,
					OverriddenByUser = OverriddenByUser,
					HasBeenSent = HasBeenSent,
					SentToResetOverrideByUser = SentToResetOverrideByUser,
					Type = Type
				};
			}

			object IDeepCloneable.DeepClone()
			{
				return DeepClone();
			}
		}

