		public static Workout ManualWorkout(bool isMetric, double? incline = null, double? runningTime = null)
		{
			double targetValue = runningTime.GetValueOrDefault() + 10800.0;
			Workout workout = new Workout
			{
				Target = TargetType.Seconds,
				TargetValue = targetValue,
				Title = ManualWorkoutTitle,
				Controls = new List<Control>(),
				WorkoutFilters = new List<string> { WorkoutFilter.IsManual.ToString() }
			};
			if (incline.HasValue)
			{
				workout.Controls.Add(new Control
				{
					Type = Control.ControlType.Incline,
					At = 0.0,
					Value = (incline ?? 0.0)
				});
			}
			return workout;
		}

		public static WorkoutType WorkoutTypeFromEquipmentType(string equipmentType)
		{
			switch (equipmentType.ToLowerInvariant())
			{
			case "bike":
			case "stationary bike":
			case "studio bike":
			case "tdf bike":
				return WorkoutType.Cycle;
			case "rower":
				return WorkoutType.Row;
			case "strength":
			case "fusion":
				return WorkoutType.Strength;
			default:
				return WorkoutType.Run;
			}
		}

		[OnDeserialized]
		private void OnDeserializedMethod(StreamingContext context)
		{
			if (ScaledControls == null)
			{
				ScaledControls = new Dictionary<int, List<Control>>();
			}
			if (!ScaledControls.ContainsKey(0))
			{
				ScaledControls.Add(0, Controls);
			}
			ValidateAndCorrectScaledControls();
		}

