				Type = Type,
				Created = Created,
				Target = Target,
				ScaledControls = ScaledControls?.ToDictionary((KeyValuePair<int, List<Control>> entry) => entry.Key, (KeyValuePair<int, List<Control>> entry) => entry.Value.DeepClone()),
				HeartRateZones = HeartRateZones?.DeepClone(),
				StartingControlLevel = StartingControlLevel,
				LibraryFilters = LibraryFilters?.Select((LibraryFilter x) => x?.DeepClone())?.ToList(),
				WorkoutFilters = WorkoutFilters,
				WorkoutNotificationFilters = WorkoutNotificationFilters?.ToList()
			};
		}

		object IDeepCloneable.DeepClone()
		{
			return DeepClone();
		}

		public bool IsMissingScaledControls()
		{
			if (ScaledControls == null || ScaledControls.Count == 0)
			{
				return true;
			}
			if (ScaledControls.Count == 1 && ScaledControls.First().Key == 0)
			{
				return true;
			}
			foreach (KeyValuePair<int, List<Control>> scaledControl in ScaledControls)
			{
				if (scaledControl.Key != 0 && (scaledControl.Value == null || scaledControl.Value.Count == 0))
				{
					return true;
				}
			}
			return false;
		}

		public void ValidateAndCorrectScaledControls()
		{
			if (IsMissingScaledControls())
			{
				return;
			}
			int num = ScaledControls.Keys.Min();
			int num2 = ScaledControls.Keys.Max();
			for (int i = num + 1; i < num2 - 1; i++)
			{
				if (!ScaledControls.ContainsKey(i))
				{
					iFit.Logger.Log.Warn("Api", $"Workout Id: {Id} missing ALL controls for level: {i}. Using previous level to fill the gap.");
					ScaledControls.Add(i, ScaledControls[i - 1]);
				}
			}
		}

		public ScaledWorkoutDetails GetScaledWorkoutDetails()
		{
			if (IsMissingScaledControls())
			{
				return null;
			}
			return new ScaledWorkoutDetails(ScaledControls, StartingControlLevel);
		}

