		public static async Task<List<Workout>> GetWorkouts(IIfitApiService api, List<string> workoutIds, int? softwareNumber = null, bool trim = false, bool doEnableScaling = false)
		{
			string userId = (api.HasLoggedInUser ? api.CurrentlyAuthenticatedUserId : "");
			string trimFields = null;
			if (trim)
			{
				trimFields = "controls,scaledControls,heartRateZones";
			}
			Dictionary<string, Workout> distinctWorkoutsDict = new Dictionary<string, Workout>((int)((double)workoutIds.Count * 1.5));
			foreach (string id in workoutIds.Distinct())
			{
				try
				{
					distinctWorkoutsDict.Add(id, await api.Cache.GetObject<Workout>(CacheKey(id, userId, softwareNumber, trim, doEnableScaling)));
				}
				catch (KeyNotFoundException)
				{
					distinctWorkoutsDict.Add(id, null);
				}
			}
			List<string> list = (from x in distinctWorkoutsDict
				where x.Value == null
				select x.Key).ToList();
			if (list.Count > 0)
			{
				List<Workout> list2 = await FetchWorkouts(api, list, trimFields, softwareNumber, doEnableScaling);
				foreach (Workout item in list2)
				{
					distinctWorkoutsDict[item.Id] = item;
				}
				if (list2.Count > 0)
				{
					Dictionary<string, Workout> keyValuePairs = list2.ToDictionary((Workout x) => CacheKey(x.Id, userId, softwareNumber, trim, doEnableScaling));
					await api.Cache.InsertObjects(keyValuePairs, DateTimeOffset.Now.AddDays(1.0));
				}
			}
			List<Workout> list3 = new List<Workout>(workoutIds.Count);
			foreach (string workoutId in workoutIds)
			{
				Workout workout = distinctWorkoutsDict[workoutId];
				if (workout != null)
				{
					list3.Add(distinctWorkoutsDict[workoutId]);
				}
			}
			return list3;
		}

		private static async Task<List<Workout>> FetchWorkouts(IIfitApiService api, List<string> notFound, string trimFields, int? softwareNumber = null, bool doEnableScaling = false)
		{
			if (notFound == null)
			{
				return null;
			}
			List<Task<List<Workout>>> list = new List<Task<List<Workout>>>();
			int num = 0;
			while (num < notFound.Count)
			{
				List<string> list2 = notFound.Skip(num).Take(14).ToList();
				if (list2 != null)
				{
					num += list2.Count;
					list.Add(FetchWorkoutsWithTrainer(api, list2, softwareNumber, trimFields, doEnableScaling));
				}
			}
			return (await Task.WhenAll(list)).SelectMany((List<Workout> x) => x).ToList();
		}

		private static async Task<List<Workout>> FetchWorkoutsWithTrainer(IIfitApiService api, IEnumerable<string> workoutIds, int? softwareNumber = null, string trimFields = null, bool doEnableScaling = false)
		{
			if (workoutIds == null)
			{
				return null;
			}
			string ids = string.Join(",", workoutIds);
			List<Workout> workouts = await api.GetGatewayService<IIFitLycanApi>().LoadWorkouts(ids, softwareNumber, trimFields, doEnableScaling);
			try
			{
				List<string> source = (from x in workouts
					select x.Metadata?.TrainerId into x
					where !string.IsNullOrWhiteSpace(x)
					select x).Distinct().ToList();
				List<Task<Trainer>> tasks = source.Select((string x) => Trainer.Get(api, x)).ToList();
				Dictionary<string, Trainer> trainers = (await Task.WhenAll(tasks)).Select((Trainer x) => x).ToDictionary((Trainer x) => x.Id);
				foreach (Workout item in workouts.Where((Workout x) => !string.IsNullOrWhiteSpace(x.Metadata?.TrainerId) && trainers.ContainsKey(x.Metadata.TrainerId)))
				{
					item.Metadata.Trainer = trainers[item.Metadata.TrainerId];
				}
			}
			catch (Exception)
			{
			}
			return workouts;
		}

		public static async Task<List<Workout>> Search(IIfitApiService api, Query query = null, bool doEnableScaling = false)
		{
			string _ids = ((query?.Ids == null) ? null : string.Join(",", query.Ids));
			string _types = ((query?.Types == null) ? null : string.Join(",", query.Types));
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				IIFitLycanApi gatewayService = api.GetGatewayService<IIFitLycanApi>();
				string ids = _ids;
				string type = _types;
				string owner_id = query?.OwnerId;
				Query query2 = query;
				return await gatewayService.SearchWorkouts(ids, type, owner_id, (query2 != null) ? query2.Target.GetAttribute<EnumMemberAttribute>().Value : null, query?.hasGeo, query?.TargetValue, doEnableScaling);
			});
		}

