		public List<Control> GetScaledWorkoutControls(int scale)
		{
			if (scale < MinWorkoutScale || scale > MaxWorkoutScale)
			{
				return null;
			}
			return ScaledControls[scale];
		}

		public void RoundInclineControls(double roundTo = 0.5)
		{
			RoundWorkoutControlsTo(roundTo, Control.ControlType.Incline);
		}

		public void RoundWorkoutControlsTo(double roundTo, Control.ControlType type)
		{
			if ((Controls?.Count).GetValueOrDefault() < 1)
			{
				return;
			}
			if (roundTo <= 5E-324)
			{
				throw new ArgumentOutOfRangeException("roundTo", "RoundTo value cannot be zero or negative.");
			}
			double num = 1.0 / roundTo;
			if (Controls == null)
			{
				return;
			}
			foreach (Control control in Controls)
			{
				if (control != null && control.Type == type)
				{
					control.Value = Math.Round(num * control.Value) / num;
				}
			}
		}

		public void LogWorkoutControls(string message)
		{
			iFit.Logger.Log.Debug("Workout", "#" + message + " Start logging controls for workout: Title: " + Title + " | Id: " + Id);
			Controls.DoForEach(delegate(Control x)
			{
				iFit.Logger.Log.Debug("Workout", $"* Type: {x.Type} | At: {x.At} | Value: {x.Value} | BeenSent{x.HasBeenSent} | Overridden: {x.OverriddenByUser} | ResetOverride: {x.SentToResetOverrideByUser}");
			});
			iFit.Logger.Log.Debug("Workout", "#" + message + " End logging controls for workout: Title: " + Title + " | Id: " + Id);
		}
	}
	public class WorkoutGroup : WebDataObject
	{
		public string Id { get; set; }

		public string Name { get; set; }

		public List<string> WorkoutIds { get; set; }

		public List<Workout> WorkoutsOrderedByDifficulty { get; set; }

		private static string CacheKey(string workoutGroupId, string trainerIds)
		{
			return "workout-group-" + workoutGroupId + "-" + trainerIds;
		}

		public static async Task<List<WorkoutGroup>> GetAll(IIfitApiService api)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetAllWorkoutGroups());
		}

		public static async Task<WorkoutGroup> Get(IIfitApiService api, string id, bool force = false)
		{
			if (id == null)
			{
				return null;
			}
			string key = CacheKey(id, "");
			if (force)
			{
				await api.Cache.Invalidate(key);
			}
			Func<Task<WorkoutGroup>> fetchFunc = async () => await FetchWorkoutGroup(api, id);
			WorkoutGroup workoutGroup = await api.Cache.GetOrFetchObject(key, fetchFunc, DateTimeOffset.Now.AddDays(90.0));
			WorkoutGroup workoutGroup2 = workoutGroup;
			workoutGroup2.WorkoutsOrderedByDifficulty = (await Workout.GetWorkouts(api, workoutGroup.WorkoutIds)).OrderBy((Workout x) => x.Difficulty.Score).ToList();
			SetGroupRating(workoutGroup);
			return workoutGroup;
		}

		public static async Task<List<WorkoutGroup>> Get(IIfitApiService api, IList<string> ids, bool force = false)
		{
			if (ids == null)
			{
				return null;
			}
			Dictionary<string, int[]> groupIndexData = (from x in ids.Select((string x, int i) => new
				{
					Index = i,
					Val = x
				})
				group x by x.Val).ToDictionary(x => x.Key, x => x.Select(y => y.Index).ToArray());
			if (groupIndexData?.Keys == null)
			{
				return null;
			}
			Dictionary<string, WorkoutGroup> workoutGroups = await RetrieveWorkoutGroups(api, force, groupIndexData.Keys);
			if (workoutGroups == null)
			{
				return null;
			}
			List<IGrouping<string, Workout>> list = (await RetrieveWorkoutsForGroups(api, workoutGroups)).GroupBy((Workout x) => x.WorkoutGroupId, (Workout x) => x, StringComparer.CurrentCultureIgnoreCase).ToList();
			List<WorkoutGroup> list2 = new List<WorkoutGroup>(Enumerable.Repeat<WorkoutGroup>(null, ids.Count));
			foreach (IGrouping<string, Workout> item in list)
			{
				string key = item.Key;
				WorkoutGroup workoutGroup = workoutGroups[key];
				workoutGroup.WorkoutsOrderedByDifficulty = item.OrderBy((Workout x) => x.Difficulty.Score).ToList();
				int[] array = groupIndexData[key];
				int[] array2 = array;
				foreach (int index in array2)
				{
					list2[index] = workoutGroup;
				}
			}
			SetMultipleGroupsRatings(list2);
			return list2;
		}

		private static async Task<Dictionary<string, WorkoutGroup>> RetrieveWorkoutGroups(IIfitApiService api, bool force, IEnumerable<string> distinctGroupIds)
		{
			if (distinctGroupIds == null)
			{
				return null;
			}
			List<Task<WorkoutGroup>> groupGets = new List<Task<WorkoutGroup>>();
			foreach (string id in distinctGroupIds)
			{
				string cacheKey = CacheKey(id, "");
				if (force)
				{
					await api.Cache.Invalidate(cacheKey);
				}
				Func<Task<WorkoutGroup>> fetchFunc = async () => await FetchWorkoutGroup(api, id);
				groupGets.Add(api.Cache.GetOrFetchObject(cacheKey, fetchFunc, DateTimeOffset.Now.AddDays(90.0)).ToTask());
			}
			await Task.WhenAll(groupGets);
			Dictionary<string, WorkoutGroup> workoutGroups = new Dictionary<string, WorkoutGroup>(StringComparer.CurrentCultureIgnoreCase);
			foreach (Task<WorkoutGroup> item in groupGets)
			{
				WorkoutGroup workoutGroup = await item;
				if (!workoutGroups.ContainsKey(workoutGroup.Id))
				{
					workoutGroups.Add(workoutGroup.Id, workoutGroup);
				}
			}
			return workoutGroups;
		}

		private static async Task<List<Workout>> RetrieveWorkoutsForGroups(IIfitApiService api, Dictionary<string, WorkoutGroup> workoutGroups)
		{
			if (workoutGroups == null)
			{
				return null;
			}
			List<string> list = workoutGroups.SelectMany((KeyValuePair<string, WorkoutGroup> x) => x.Value.WorkoutIds).ToList();
			int num = 0;
			List<Task<List<Workout>>> list2 = new List<Task<List<Workout>>>();
			while (num < list.Count)
			{
				List<string> list3 = list.Skip(num).Take(14).ToList();
				num += list3.Count;
				list2.Add(Workout.GetWorkouts(api, list3));
			}
			return (await Task.WhenAll(list2)).SelectMany((List<Workout> x) => x).ToList();
		}

		public static async Task<List<WorkoutGroup>> GetForTrainer(IIfitApiService api, string trainerId, bool force = false)
		{
			if (trainerId == null)
			{
				return null;
			}
			string key = CacheKey("", trainerId);
			if (force)
			{
				await api.Cache.Invalidate(key);
			}
			Func<Task<List<WorkoutGroup>>> fetchFunc = async () => await FetchWorkoutGroupForTrainer(api, trainerId);
			List<WorkoutGroup> workoutGroups = await api.Cache.GetOrFetchObject(key, fetchFunc, DateTimeOffset.Now.AddDays(90.0));
			if (workoutGroups != null && workoutGroups.Count > 0)
			{
				Dictionary<string, WorkoutGroup> groupHash = workoutGroups.ToDictionary((WorkoutGroup x) => x.Id);
				List<string> workoutIds = workoutGroups.SelectMany((WorkoutGroup x) => x.WorkoutIds).ToList();
				IEnumerable<IGrouping<string, Workout>> enumerable = from x in await Workout.GetWorkouts(api, workoutIds)
					group x by x.WorkoutGroupId;
				foreach (IGrouping<string, Workout> item in enumerable)
				{
					if (groupHash.TryGetValue(item.Key, out var value))
					{
						value.WorkoutsOrderedByDifficulty = item.OrderBy((Workout x) => x.Difficulty.Score).ToList();
					}
				}
			}
			SetMultipleGroupsRatings(workoutGroups);
			return workoutGroups;
		}

		private static async Task<List<WorkoutGroup>> FetchWorkoutGroupForTrainer(IIfitApiService api, string trainerId)
		{
			if (trainerId == null)
			{
				return null;
			}
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetWorkoutGroups(trainerId));
		}

		protected static async Task<WorkoutGroup> FetchWorkoutGroup(IIfitApiService api, string id)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetWorkoutGroup(id));
		}

		private static void SetMultipleGroupsRatings(List<WorkoutGroup> workoutGroups)
		{
			workoutGroups?.ForEach(SetGroupRating);
		}

		private static void SetGroupRating(WorkoutGroup workoutGroup)
		{
			if (workoutGroup?.WorkoutsOrderedByDifficulty != null)
			{
				Workout.WorkoutRating groupRating = workoutGroup.WorkoutsOrderedByDifficulty.First().Ratings;
				workoutGroup.WorkoutsOrderedByDifficulty.ForEach(delegate(Workout x)
				{
					x.Ratings = groupRating;
				});
			}
		}
	}
