				properties.Add(wodCoach.Advanced);
			}
			if ((difficulty == FitnessLevel.Moderate || difficulty == FitnessLevel.All) && wodCoach.Moderate != null)
			{
				list.Add(Workout.Get(api, wodCoach.Moderate?.WorkoutId, softwareNumber, force));
				properties.Add(wodCoach.Moderate);
			}
			if ((difficulty == FitnessLevel.Default || difficulty == FitnessLevel.All) && wodCoach.Default != null)
			{
				list.Add(Workout.Get(api, wodCoach.Default?.WorkoutId, softwareNumber, force));
				properties.Add(wodCoach.Default);
			}
			Workout[] result = await Task.WhenAll(list);
			properties.ToObservable().Subscribe(delegate(WorkoutOfTheDay x)
			{
				x.Workout = result.FirstOrDefault((Workout w) => w.Id == x.WorkoutId);
				if (roundWorkoutInclineControls)
				{
					x.Workout?.RoundInclineControls();
				}
			});
			return wodCoach;
			async Task<WorkoutOfTheDayCoachPlus> Fetch()
			{
				return await FetchWorkoutOfTheDayCoachPlus(api, type, softwareNumber);
			}
		}

		protected static async Task<WorkoutOfTheDayCoachPlus> FetchWorkoutOfTheDayCoachPlus(IIfitApiService api, WorkoutOfTheDay.WotdType type, int softwareNumber)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.Service.GetWorkoutOfTheDayCoachPlus(type.GetAttribute<EnumMemberAttribute>().Value, softwareNumber));
		}
	}
