		{
			string key = api.CurrentlyAuthenticatedUserId + "-myworkoutstandings-" + id;
			if (force)
			{
				await api.Cache.InvalidateObject<List<WorkoutStanding>>(key);
			}
			TaskCompletionSource<ObservableCollection<WorkoutStanding>> tcs = new TaskCompletionSource<ObservableCollection<WorkoutStanding>>();
			ObservableCollection<WorkoutStanding> result = null;
			api.Cache.GetAndFetchLatest(key, fetch, (DateTimeOffset x) => true, DateTimeOffset.Now.AddDays(1.0)).Subscribe(delegate(List<WorkoutStanding> x)
			{
				if (result == null)
				{
					result = new ObservableCollection<WorkoutStanding>(x);
					tcs.SetResult(result);
				}
				else
				{
					MergeLists.Merge(result, x, (WorkoutStanding k) => k.UserId);
				}
			});
			return await tcs.Task;
			async Task<List<WorkoutStanding>> fetch()
			{
				return await FetchWorkoutStandings(api, id, query);
			}
		}

		public static async Task<List<WorkoutStanding>> FetchWorkoutStandings(IIfitApiService api, string id, Query query)
		{
			return await WebDataObject.DefaultPolicy.ExecuteAsync(async delegate
			{
				IIfitApi service = api.Service;
				string id2 = id;
				Query query2 = query;
				string gender = ((query2 != null) ? query2.Gender.GetAttribute<EnumMemberAttribute>().Value : null);
				Query query3 = query;
				string obj = ((query3 != null) ? query3.Group.GetAttribute<EnumMemberAttribute>().Value : null);
				Query query4 = query;
				return await service.GetWorkoutStandings(id2, gender, obj, (query4 != null) ? query4.Equipment.GetAttribute<EnumMemberAttribute>().Value : null, query?.MinAge, query?.MaxAge);
			});
		}
	}
