	public class CumulativeWattHours
	{
		public double WattHours { get; private set; }

		public double Distance { get; private set; }

		public double Time { get; private set; }

		public CumulativeWattHours(double wattHrs, double distance, double time)
		{
			WattHours = wattHrs;
			Distance = distance;
			Time = time;
		}

		public CumulativeWattHours()
		{
		}

		public void Update(double wattHours, IConsoleBasicInfo latestBasicInfo)
		{
			if (latestBasicInfo != null && !WattHours.AlmostEqual(wattHours))
			{
				WattHours = wattHours;
				Time = latestBasicInfo.RunningTime;
				Distance = latestBasicInfo.DistanceMeters;
			}
		}
	}
	public static class CompetitionCalculations
	{
		public const double DefaultLycanLevel = 0.4;

		public const double DefaultWeight = 85.0;

		public const double DefaultAge = 45.0;

		public const double OffEquipmentVO2 = 0.10303;

		public static double CalculateWatts(double kg, double mps, double grade)
		{
			double num = CalculateV02(mps, grade);
			return (num + 0.11666) * 60.0 * kg / 10.8;
		}

		public static double CalculateTreadmillOffEquipmentWatts(double kg, double mps, double grade, double multiplier)
		{
			double num = CalculateV02(mps, grade) * multiplier;
			return (num + 0.11666) * 60.0 * kg / 10.8;
		}

		public static double CalculateAerobicOffEquipmentWatts(double kg, double multiplier)
		{
			double num = 0.10303 * multiplier;
			return (num + 0.11666) * 60.0 * kg / 10.8;
		}

		private static double CalculateV02(double mps, double grade)
		{
			double val = ((!(mps < 1.8)) ? (0.2 * mps + 0.9 * mps * grade + 0.05833333) : (0.1 * mps + 1.8 * mps * grade + 0.05833));
			return Math.Max(val, 0.0533333);
		}

		public static double CalculateWattHours(User user, IConsoleBasicInfo latestBasicInfo, IConsoleInfo consoleInfo, CumulativeWattHours cwh = null)
		{
			if (latestBasicInfo == null || consoleInfo == null)
			{
				return 0.0;
			}
			int runningTime = latestBasicInfo.RunningTime;
			if (runningTime <= 0)
			{
				return 0.0;
			}
			double num = (double)runningTime - (cwh?.Time ?? 0.0);
			double num2 = latestBasicInfo.DistanceMeters - (cwh?.Distance ?? 0.0);
			if (num <= 0.0 || num2 <= 0.0)
			{
				return cwh?.WattHours ?? 0.0;
			}
			double kg = user?.Weight ?? 85.0;
			double mps = num2 / num;
			double grade = latestBasicInfo.Grade / 100.0;
			double num3 = CalculateWatts(kg, mps, grade) * num / 3600.0;
			return num3 + (cwh?.WattHours ?? 0.0);
		}

		public static bool ShouldCalculateWatts(IConsoleBasicInfo latestBasicInfo, IConsoleInfo consoleInfo)
		{
			if (latestBasicInfo.AvgWatts > 0.0)
			{
				return false;
			}
			ConsoleType machineType = consoleInfo.MachineType;
			if ((uint)machineType <= 1u)
			{
				return true;
			}
			return false;
		}
	}
	public class BoolToIntConverter : MvxValueConverter<bool, int>
	{
		private readonly int onTrue;

		private readonly int onFalse;

		public BoolToIntConverter(int onTrue, int onFalse)
		{
			this.onTrue = onTrue;
			this.onFalse = onFalse;
		}

		protected override int Convert(bool val, Type targetType, object parameter, CultureInfo culture)
		{
			if (!val)
			{
				return onFalse;
			}
			return onTrue;
		}

		protected override bool ConvertBack(int val, Type targetType, object parameter, CultureInfo culture)
		{
			return val == onTrue;
		}
	}
	public class IntToBoolConverter : MvxValueConverter<int, bool>
	{
		private readonly int target;

		public IntToBoolConverter(int target)
		{
			this.target = target;
		}

		protected override bool Convert(int val, Type targetType, object parameter, CultureInfo culture)
		{
			return val == target;
		}

		protected override int ConvertBack(bool val, Type targetType, object parameter, CultureInfo culture)
		{
			if (!val)
			{
				return 0;
			}
			return target;
		}
	}
