		private static IDictionary<string, string> AddOrReplaceBoolKey(IDictionary<string, string> dict, string whichKey, bool enabled)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>(dict);
			if (dictionary.ContainsKey(whichKey))
			{
				dictionary[whichKey] = (enabled ? "true" : "false");
			}
			else
			{
				dictionary.Add(whichKey, enabled ? "true" : "false");
			}
			return dictionary;
		}
	}
	public static class BuiltInUtil
	{
		private const string RemoveInvalidVersionCharactersExpression = " ?\\(.*?\\)|([^0-9.])";

		private const string EnsureNETVersionCompatibleExpression = "^(?:[^\\d]*?)(?<VERSION>(\\d+\\.){0,3}\\d+)";

		private const string IgnoreVersion = "9.9.9.9999";

		public static bool CheckVersionStrings(string currentVersion, string remoteVersion)
		{
			try
			{
				if (currentVersion == "9.9.9.9999" || remoteVersion == "9.9.9.9999")
				{
					iFit.Logger.Log.Info("UpdateCheck", "Ignoreing update for app: CurrentVersion: " + currentVersion + " RemoteVersion: " + remoteVersion);
					return false;
				}
				string version = CleanVersionString(currentVersion);
				string version2 = CleanVersionString(remoteVersion);
				Version version3 = new Version(version);
				Version version4 = new Version(version2);
				return version3 < version4;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("UpdateCheck", "Could not compare versions: " + ex.Message, ex);
				return false;
			}
		}

		private static string CleanVersionString(string version)
		{
			Regex regex = new Regex(" ?\\(.*?\\)|([^0-9.])");
			string input = regex.Replace(version, string.Empty);
			regex = new Regex("^(?:[^\\d]*?)(?<VERSION>(\\d+\\.){0,3}\\d+)");
			return regex.Match(input).Groups["VERSION"].ToString();
		}

		public static bool IsValidSoftwareNumber(IFolder updateFolder, List<int> softwareNumbers, int softwareNumber)
		{
			if (PerformSoftwareNumberCheckOnUpdateFolder(updateFolder, softwareNumber))
			{
				return IsValidSoftwareNumberInList(softwareNumbers, softwareNumber);
			}
			return false;
		}

		public static bool IsValidSoftwareNumberInList(List<int> softwareNumbers, int softwareNumber)
		{
			iFit.Logger.Log.Info("UpdateCheck", $"Checking if SoftwareNumbers contains {softwareNumber}");
			return softwareNumbers?.Contains(softwareNumber) ?? true;
		}

		private static bool PerformSoftwareNumberCheckOnUpdateFolder(IFolder updateFolder, int softwareNumber)
		{
			iFit.Logger.Log.Info("UpdateCheck", $"Checking if update folder name contains {softwareNumber}");
			try
			{
				string text = updateFolder.Name.Substring(updateFolder.Name.LastIndexOf('_') + 1);
				iFit.Logger.Log.Info("UpdateCheck", "Software number from update folder: " + text);
				return softwareNumber == Convert.ToInt32(text);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("UpdateCheck", "Error finding software number from update folder: " + ex.Message);
				return false;
			}
		}
	}
	public class FixedSizedQueue<T> : Queue<T>
	{
		private readonly object syncObject = new object();

		public int Size { get; private set; }

		public FixedSizedQueue(int size)
		{
			Size = size;
		}

		public new void Enqueue(T obj)
		{
			base.Enqueue(obj);
			lock (syncObject)
			{
				while (base.Count > Size)
				{
					Dequeue();
				}
			}
		}
	}
	public class HexColorConverter : JsonConverter
	{
		public override bool CanConvert(Type objectType)
		{
