		protected readonly Subject<int> _whenSignalStrengthChanged = new Subject<int>();

		protected readonly ReplaySubject<WifiEnabledState> _whenEnabledChanged = new ReplaySubject<WifiEnabledState>(1);

		protected readonly Subject<WifiNetworkState> _whenNetworkStateChanged = new Subject<WifiNetworkState>();

		protected readonly ReplaySubject<WifiNetworkInfo> _whenNetworkChanged = new ReplaySubject<WifiNetworkInfo>(1);

		public virtual bool IsWifiEnabled { get; protected set; }

		public int CurrentSignalStrength { get; protected set; }

		public int SpeedTestTimeout { get; set; } = 25000;

