		public BaseWifiService(IConnectivity connectivity, IIfitApiService ifitApi)
		{
			this.connectivity = connectivity;
			this.ifitApi = ifitApi;
		}

		public async Task CheckInternetSpeed(Action action)
		{
			if (!IsInternetSpeedTestRunning)
			{
				IsInternetSpeedTestRunning = true;
				if (!(await IsConnectionFast()))
				{
					action();
				}
			}
		}

		private async Task<bool> IsConnectionFast()
		{
			Stopwatch stopwatch = new Stopwatch();
			try
			{
				using HttpClient httpClient = new HttpClient();
				stopwatch.Start();
				Task<byte[]> byteArrayAsync = httpClient.GetByteArrayAsync(new Uri(ifitApi.Environment.SpeedTestEndpoint));
				if (!byteArrayAsync.Wait(TimeSpan.FromMilliseconds(SpeedTestTimeout)))
				{
					return false;
				}
				stopwatch.Stop();
			}
			catch
			{
				return true;
			}
			long elapsedMilliseconds = stopwatch.ElapsedMilliseconds;
			float num = 12814.136f;
			float num2 = (float)elapsedMilliseconds / 1000f;
			float num3 = num / num2;
			iFit.Logger.Log.Trace("Wifi", "Internet speed is " + num3);
			return num3 >= 512f;
		}

		public async Task<bool> PingSucceeds()
		{
			HttpClient httpClient = new HttpClient(new NativeMessageHandler());
			httpClient.DefaultRequestHeaders.ConnectionClose = true;
			httpClient.Timeout = TimeSpan.FromSeconds(10.0);
			try
			{
				iFit.Logger.Log.Trace("Wifi", "Pinging ifit.com to see if we have internet");
				await httpClient.GetAsync("https://www.ifit.com/favicon.ico");
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Wifi", "No or slow internet present", exception);
				return false;
			}
			iFit.Logger.Log.Trace("Wifi", "Internet detected.");
			return true;
		}

		public async Task<bool> IsConnectionPoor()
		{
			bool flag = await PingSucceeds();
			return IsWifiEnabled && ActiveNetworkInfo != null && flag;
		}

		public async Task<bool> IsConnectionPoorOrLost()
		{
			bool flag = !IsWifiEnabled || ActiveNetworkInfo == null;
			bool flag2 = flag;
			if (!flag2)
			{
				flag2 = !(await PingSucceeds());
			}
			return flag2;
		}

		public bool InNetworkStateWithoutConnectivity()
		{
			List<WifiNetworkState> source = new List<WifiNetworkState>
			{
				WifiNetworkState.Blocked,
				WifiNetworkState.Disconnected,
				WifiNetworkState.Disconnecting,
				WifiNetworkState.AuthenticationFailed,
				WifiNetworkState.Suspended,
				WifiNetworkState.Failed
			};
			return source.Any((WifiNetworkState x) => x == NetworkState);
		}

		public async Task<bool> EnsureConnection(int ensureConnectionTimeout = 15)
		{
			if (connectivity.IsConnected)
			{
				return true;
			}
			if (WhenNetworkStateChanged == null)
			{
				return false;
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			WhenNetworkStateChanged.Where((WifiNetworkState x) => x == WifiNetworkState.Connected)?.Take(1)?.Timeout(TimeSpan.FromSeconds(ensureConnectionTimeout))?.Subscribe((Action<WifiNetworkState>)delegate
			{
				tcs.TrySetResult(result: true);
			}, (Action<Exception>)delegate
			{
				tcs.TrySetResult(result: false);
			});
			return await tcs.Task;
		}

		public abstract void Dispose();
	}
