	public class WifiNetworkInfo
	{
		public enum SecurityType
		{
			WpaWpa2,
			WpaEnt,
			Wep,
			None,
			Unsupported
		}

		public enum AuthType
		{
			Pass,
			IdentityPass,
			None,
			Unsupported
		}

		public enum RssiLevel
		{
			NA,
			None,
			One,
			Two,
			Three,
			Four
		}

		public bool IsHidden { get; set; } = true;

		public string Ssid { get; set; } = "";

		public string Password { get; set; }

		public string EnterpiseIdentity { get; set; }

		public int Rssi { get; set; } = -1;

		public SecurityType Security { get; set; } = SecurityType.None;

		public AuthType Auth => GetAuthType();

		public string DisplayName => Ssid.Replace("\"", "");

		public int ConnectionStrength
		{
			get
			{
				if (Rssi != -1)
				{
					return 2 * (Rssi + 100);
				}
				return 0;
			}
		}

		public RssiLevel WifiRssiLevel => DetermineLevelStrength();

		public WifiNetworkInfo()
		{
		}

		public WifiNetworkInfo(bool hidden, string ssid, SecurityType sec, int rssi, string password = null)
		{
			IsHidden = hidden;
			Ssid = ssid;
			Security = sec;
			Rssi = rssi;
			Password = password;
		}

		public override string ToString()
		{
			return $"[WifiNetworkInfo: SSID={Ssid}, IsHidden={IsHidden}, Identity={EnterpiseIdentity}, Rssi={Rssi}, ConnectionStrength={ConnectionStrength}, RssiLevel={WifiRssiLevel}]";
		}

		private RssiLevel DetermineLevelStrength()
		{
			if (Rssi == -2)
			{
				return RssiLevel.NA;
			}
			if (Rssi == -1)
			{
				return RssiLevel.None;
			}
			if (Rssi < -80)
			{
				return RssiLevel.One;
			}
			if (Rssi < -70)
			{
				return RssiLevel.Two;
			}
			if (Rssi < -55)
			{
				return RssiLevel.Three;
			}
			return RssiLevel.Four;
		}

		private AuthType GetAuthType()
		{
			if (Security == SecurityType.WpaWpa2 || Security == SecurityType.Wep)
			{
				return AuthType.Pass;
			}
			if (Security == SecurityType.WpaEnt)
			{
				return AuthType.IdentityPass;
			}
			if (Security == SecurityType.None)
			{
				return AuthType.None;
			}
			return AuthType.Unsupported;
		}

		public bool Equals(WifiNetworkInfo p)
		{
			return DisplayName.Equals(p?.DisplayName);
		}

		public static bool operator ==(WifiNetworkInfo p1, WifiNetworkInfo p2)
		{
			if ((object)p1 == p2)
			{
				return true;
			}
			if ((object)p1 == null || (object)p2 == null)
			{
				return false;
			}
			return p1.Equals(p2);
		}

		public static bool operator !=(WifiNetworkInfo p1, WifiNetworkInfo p2)
		{
			return !(p1 == p2);
		}

		public override bool Equals(object obj)
		{
			if (obj == null)
			{
				return false;
			}
			return DisplayName.Equals((obj as WifiNetworkInfo)?.DisplayName);
		}

		public override int GetHashCode()
		{
			return DisplayName.GetHashCode();
		}
	}
}
