	public static class JsonObfuscator
	{
		public const string CouldNotObfuscate = "We had trouble obfuscating some JavaScript, for security reasons were showing this instead of the real JavaScript.";

		public const string HideThis = "sensitive information hidden";

		public static readonly string[] SensitiveKeys = new string[5] { "clientId", "clientSecret", "bearerToken", "token", "refreshToken" };

		public static string PrepareJsonForLogging(string json, string preKeyIndicator = "\"", string keyValueSeparator = "\" : \"", string valuePattern = ".+?", string postValueIndicator = "\"")
		{
			try
			{
				return SensitiveKeys.Aggregate(json, (string current, string sensitiveKey) => Regex.Replace(current, preKeyIndicator + sensitiveKey + keyValueSeparator + valuePattern + postValueIndicator, preKeyIndicator + sensitiveKey + keyValueSeparator + "sensitive information hidden" + postValueIndicator));
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("WebView", "JsonObfuscator.PrepareJsonForLogging", exception);
			}
			return "We had trouble obfuscating some JavaScript, for security reasons were showing this instead of the real JavaScript.";
		}
	}
