namespace Shire.Core.ViewModelResolvers
{
	public interface IViewModelOverride
	{
		MvxViewModelRequest OverrideRequest(MvxViewModelRequest request);
	}
	[AttributeUsage(AttributeTargets.Class)]
	public class ViewModelOverrideAttribute : Attribute
	{
		public Type ViewModelType { get; }

		public ViewModelOverrideAttribute(Type viewModelType)
		{
			ViewModelType = viewModelType;
		}
	}
	public class ViewModelOverrideResolver : BaseViewModelPresentationFilter
	{
		private readonly IViewModelOverrideResolverCache cache;

		public ViewModelOverrideResolver(IViewModelOverrideResolverCache cache)
		{
			this.cache = cache;
		}

		public override MvxViewModelRequest OnShowing(MvxViewModelRequest request)
		{
			Type overriderType = GetOverriderType(request.ViewModelType);
			if (overriderType != null && Mvx.Resolve(overriderType) is IViewModelOverride viewModelOverride)
			{
				return viewModelOverride.OverrideRequest(request);
			}
			return request;
		}

		private Type GetOverriderType(Type requestedViewModel)
		{
			return cache.RetrieveViewModelOverrideResolverForType(requestedViewModel);
		}
	}
	public interface IViewModelOverrideResolverCache
	{
		void RegisterViewModelOverrideResolvers(IEnumerable<Type> types);

		Type RetrieveViewModelOverrideResolverForType(Type type);
	}
	public class ViewModelOverrideResolverCache : IViewModelOverrideResolverCache
	{
		private bool isInitialized;

		private Dictionary<Type, Type> overriderTypeMappings;

		public void RegisterViewModelOverrideResolvers(IEnumerable<Type> types)
		{
			overriderTypeMappings = types.ToDictionary(GetViewModelType, (Type x) => x);
			isInitialized = true;
			static Type GetViewModelType(Type type)
			{
				object[] customAttributes = type.GetCustomAttributes(typeof(ViewModelOverrideAttribute), inherit: true);
				if (customAttributes == null || !customAttributes.Any())
				{
					throw new InvalidOperationException($"Type {type} is a view model overrider but does not have a ViewModelOverrideAttribute");
				}
				return (customAttributes[0] as ViewModelOverrideAttribute)?.ViewModelType;
			}
		}

		public Type RetrieveViewModelOverrideResolverForType(Type type)
		{
			if (!isInitialized)
			{
				throw new InvalidOperationException("ViewModelOverrideResolverCache.RetrieveViewModelOverrideResolverForType was not called and the class is not initialized correctly");
			}
			if (overriderTypeMappings.TryGetValue(type, out var value))
			{
				return value;
			}
			return null;
		}
	}
}
