			if (console is INonconnectedFitnessConsole nonconnectedFitnessConsole)
			{
				return GetMockTypeStringFromMockType(nonconnectedFitnessConsole.MockType);
			}
			if (console.IsHybridMachine())
			{
				return AppStrings.hybrid_trainer;
			}
			if (console.ConsoleInfo.MachineType == ConsoleType.SpinBike)
			{
				return AppStrings.studio_bike;
			}
			return GetMachineTypeStringFromConsoleType(console.ConsoleInfo.MachineType);
		}

