	public static class ListExtensions
	{
		public static void ClearWithDisposal<T>(this IList<T> list, Action<T> disposal) where T : class
		{
			if (list != null)
			{
				for (int i = 0; i < list.Count; i++)
				{
					disposal(list[i]);
					list[i] = null;
				}
				list.Clear();
			}
		}

		public static int FindMaximumByHeartRateMethod(this IList<int> list, int valueTolerance = 1, int minimumSamples = 3)
		{
			if (list.Count == 0)
			{
				throw new ArgumentException("FindMaximumByHeartRateMethod input list must have at least one element");
			}
			int num = 2 * minimumSamples - 1;
			int num2 = minimumSamples - 1;
			if (list.Count <= num)
			{
				return list.Max();
			}
			int num3 = 0;
			List<int> list2 = new List<int>();
			int num4 = 0;
			for (int i = num2; i < list.Count - num2; i++)
			{
				num4 = list[i];
				for (int j = i - num2; j <= i + num2; j++)
				{
					int num5 = Math.Abs(list[j] - num4);
					if (num5 <= valueTolerance)
					{
						list2.Add(list[j]);
					}
				}
				if (list2.Count > minimumSamples)
				{
					int val = list2.Max();
					num3 = Math.Max(val, num3);
				}
				list2.Clear();
			}
			if (num3 == 0)
			{
				num3 = list.Max();
				iFit.Logger.Log.Trace("Workout", $"Unable to find a maximum by Heart Rate Method. Using simple maximum {num3}");
			}
			return num3;
		}

		public static void TryDisposeAll<TData>(this IEnumerable<TData> list, Action<Exception, TData> onDisposeError = null) where TData : IDisposable
		{
			list?.DoForEach(delegate(TData x)
			{
				try
				{
					x?.Dispose();
				}
				catch (Exception arg)
				{
					onDisposeError?.Invoke(arg, x);
				}
			});
		}
	}
	public static class WorkoutExtensions
	{
		private const string IfitMusicUrl = "https://ifit-music.s3-cdn.ifit.com/{0}";

		private const string LegacyTrackFileIdPattern = "^https?\\:\\/\\/(ifit-music\\.)?s3\\.amazonaws\\.com\\/(ifit-music\\/)?(([a-z0-9]+)\\.([a-z0-9]{2,10}))$";

		public static Workout.WorkoutCategory Category(this Workout workout)
		{
			if (workout.IsVideoWorkout())
			{
				return Workout.WorkoutCategory.Video;
			}
			if (workout.IsGoogleMap)
			{
				return Workout.WorkoutCategory.Map;
			}
			return Workout.WorkoutCategory.Manual;
		}

		public static bool IsManual(this Workout workout)
		{
			if (workout != null)
			{
				return IsManualWorkout(workout.Target, workout.Id, workout.IsLiveWorkout, workout.IsVideoWorkout(), workout.IsGoogleMap);
			}
			return false;
		}

		public static bool IsManualWorkout(Workout.TargetType target, string workoutId, bool isLiveWorkout = false, bool isVideoWorkout = false, bool isMapWorkout = false)
		{
			if (!isLiveWorkout && !isMapWorkout && !isVideoWorkout && target == Workout.TargetType.Seconds)
			{
				return string.IsNullOrWhiteSpace(workoutId);
			}
			return false;
		}

		public static bool IsTimeDistanceWorkout(this Workout workout)
		{
			if (workout != null && !workout.IsVideoWorkout() && !workout.IsGoogleMap)
			{
				return !workout.IsManual();
			}
			return false;
		}

		public static bool IsVideoWorkout(this Workout workout)
		{
			if (workout == null)
			{
				return false;
			}
			if (!workout.HasFilter(Workout.WorkoutFilter.IsVideo) && !workout.IsLiveWorkout)
			{
				if (workout.VideoId != null)
				{
					return workout.Metadata != null;
				}
				return false;
			}
			return true;
		}

		public static bool IsUserWebCreatedWorkout(this Workout workout)
		{
			if (workout?.Controls == null)
			{
				return false;
			}
			if (!workout.IsManual() && !workout.IsVideoWorkout())
			{
				return !workout.IsGoogleMap;
			}
			return false;
		}

		public static bool HasAudioMetadata(this Workout workout)
		{
			return !string.IsNullOrWhiteSpace(workout?.GetWorkoutMetadataAudioUrl());
		}

		public static double CurrentAt(this Workout workout, IFitnessConsole console)
		{
			if (workout == null || console == null)
			{
				return 0.0;
			}
			return workout.Target switch
			{
				Workout.TargetType.Meters => console.LatestBasicInfo.DistanceMeters, 
				Workout.TargetType.Seconds => console.LatestBasicInfo.TimeSeconds, 
				_ => throw new NotSupportedException(), 
			};
		}

		public static List<Workout.Control> BoundedControls(this Workout workout, double maxMps, double maxIncline, double minIncline, double maxResistance, int minGear, int maxGear, double? constantMps = null, double? constantResistance = null, int? constantGear = null)
		{
			if (workout == null)
			{
				return null;
			}
			return GetBoundedControls(workout.Controls, workout.TargetValue, maxMps, maxIncline, minIncline, maxResistance, minGear, maxGear, constantMps, constantResistance, constantGear);
		}

		public static List<Workout.Control> GetBoundedControls(List<Workout.Control> workoutControls, double workoutTargetValue, double maxMps, double maxIncline, double minIncline, double maxResistance, int minGear, int maxGear, double? constantMps = null, double? constantResistance = null, int? constantGear = null)
		{
			List<Workout.Control> controls = workoutControls.DeepClone()?.ExcludingNulls().ToList();
			if (controls == null)
			{
				return null;
			}
			(from x in workoutControls.DistinctBy((Workout.Control x) => x.Type)
				select x.Type).ForEach(delegate(Workout.Control.ControlType x)
			{
				if (!controls.Any((Workout.Control k) => k.At.AlmostEqual(0.0, 5) && k.Type == x))
				{
					controls.Add(new Workout.Control
					{
						At = 0.0,
						Value = (controls?.FirstOrDefault((Workout.Control k) => k.Type == x)?.Value).GetValueOrDefault(),
						Type = x
					});
				}
				if (!controls.Any((Workout.Control k) => k.At.AlmostEqual(workoutTargetValue, 5) && k.Type == x))
				{
					controls.Add(new Workout.Control
					{
						At = workoutTargetValue,
						Value = (controls?.LastOrDefault((Workout.Control k) => k.Type == x)?.Value).GetValueOrDefault(),
						Type = x
					});
				}
			});
			controls = controls.OrderBy((Workout.Control x) => x.At).ToList();
			controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps).ForEach(delegate(Workout.Control x)
			{
				x.Value = constantMps.GetValueOrDefault(Math.Min(x.Value, maxMps));
			});
			controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline).ForEach(delegate(Workout.Control x)
			{
				x.Value = Math.Min(x.Value, maxIncline);
				x.Value = Math.Max(x.Value, minIncline);
			});
			controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Resistance).ForEach(delegate(Workout.Control x)
			{
				x.Value = constantResistance.GetValueOrDefault(Math.Min(x.Value, maxResistance));
			});
			controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Gear).ForEach(delegate(Workout.Control x)
			{
				x.Value = constantGear.GetValueOrDefault((int)Math.Round(x.Value).Clamp(minGear, maxGear));
			});
			return controls;
		}

		public static bool MustUseEstimatedPace(this Workout workout)
		{
			if (workout == null)
			{
				return false;
			}
			return !workout.HasControlsFor(Workout.Control.ControlType.Mps);
		}

		public static bool HasControlsFor(this Workout workout, Workout.Control.ControlType type)
		{
			bool? obj;
			if (workout == null)
			{
				obj = null;
			}
			else
			{
				List<Workout.Control> controls = workout.Controls;
				obj = ((controls != null) ? new bool?(controls.HasControlsFor(type, workout.TargetValue)) : ((bool?)null));
			}
			bool? flag = obj;
			return flag == true;
		}

		private static bool HasControlsFor(this IEnumerable<Workout.Control> controls, Workout.Control.ControlType type, double targetValue)
		{
			if (controls.CountSafe() < 1)
			{
				return false;
			}
			return controls.Any((Workout.Control c) => c != null && c.Type == type && (c.At > 5E-324 || !c.IsAlmostDefaultValue(3)) && c.At < targetValue - 1.0);
		}

		public static bool HasControlsFor(this IEnumerable<Workout.Control> controls, Workout.Control.ControlType type)
		{
			if (controls.CountSafe() < 1)
			{
				return false;
			}
			return controls.Any((Workout.Control c) => c != null && c.Type == type && (c.At > 5E-324 || !c.IsAlmostDefaultValue(3)));
		}

		public static List<Workout.Control> ConvertInclineControlsToResistance(this IEnumerable<Workout.Control> workoutControls, double consoleMinResistance, double consoleMaxResistance, bool roundResistanceValues = true)
		{
			return (from c in workoutControls?.Where((Workout.Control c) => c != null)
				select new Workout.Control
				{
					At = c.At,
					HasBeenSent = c.HasBeenSent,
					OverriddenByUser = c.OverriddenByUser,
					Type = ((c.Type == Workout.Control.ControlType.Incline) ? Workout.Control.ControlType.Resistance : c.Type),
					Value = ((c.Type == Workout.Control.ControlType.Incline) ? InclineResistanceUtil.InclineToResistance(c.Value / 100.0, consoleMinResistance, consoleMaxResistance, roundResistanceValues) : c.Value)
				}).ToList();
		}

		public static List<Workout.Control> ConvertResistanceControlsToIncline(this IEnumerable<Workout.Control> workoutControls, double consoleMaxResistance, double consoleMinGrade, double consoleMaxGrade)
		{
			return (from c in workoutControls?.Where((Workout.Control c) => c != null)
				select new Workout.Control
				{
					At = c.At,
					HasBeenSent = c.HasBeenSent,
					OverriddenByUser = c.OverriddenByUser,
					Type = ((c.Type != Workout.Control.ControlType.Resistance) ? c.Type : Workout.Control.ControlType.Incline),
					Value = ((c.Type == Workout.Control.ControlType.Resistance) ? (InclineResistanceUtil.ResistanceToIncline(c.Value, consoleMaxResistance, consoleMinGrade / 100.0, consoleMaxGrade / 100.0) * 100.0) : c.Value)
				}).ToList();
		}

		public static void ConvertInclineWorkoutToResistanceIfNecessary(this Workout workout, IFitnessConsole console)
		{
			if (workout == null)
			{
				return;
			}
			workout.Controls = workout.Controls.ConvertInclineControlsToResistanceIfNecessary(console, workout.TargetValue, workout.IsManual());
			if (workout.IsMissingScaledControls())
			{
				return;
			}
			foreach (int item in workout.ScaledControls.Keys.ToList())
			{
				workout.ScaledControls[item] = workout.ScaledControls[item].ConvertInclineControlsToResistanceIfNecessary(console, workout.TargetValue, workout.IsManual());
			}
		}

		public static List<Workout.Control> ConvertInclineControlsToResistanceIfNecessary(this List<Workout.Control> controls, IFitnessConsole console, double targetValue, bool isManual)
		{
			if (controls.CountSafe() < 1 || console?.ConsoleInfo == null)
			{
				return controls;
			}
			bool flag = !console.ConsoleInfo.CanSetIncline && console.ConsoleInfo.CanSetResistance && !controls.HasControlsFor(Workout.Control.ControlType.Resistance) && controls.HasControlsFor(Workout.Control.ControlType.Incline);
			bool flag2 = console.ConsoleInfo.MachineType == ConsoleType.Elliptical && controls.HasControlsFor(Workout.Control.ControlType.Incline, targetValue) && !controls.HasControlsFor(Workout.Control.ControlType.Resistance, targetValue) && !controls.HasControlsFor(Workout.Control.ControlType.RelativeResistance, targetValue) && console.ConsoleInfo.CanSetIncline && console.ConsoleInfo.CanSetResistance;
			if (flag)
			{
				if (isManual && console.ConsoleInfo.MachineType.IsHiit())
				{
					controls.Where((Workout.Control c) => c.Type == Workout.Control.ControlType.Incline).DoForEach(delegate(Workout.Control c)
					{
						c.Type = Workout.Control.ControlType.Resistance;
						c.Value = 1.0;
					});
					return controls;
				}
				return controls.Where((Workout.Control c) => c.Type != Workout.Control.ControlType.Resistance).ConvertInclineControlsToResistance(console.ConsoleInfo.MinResistanceLevel, console.ConsoleInfo.MaxResistanceLevel);
			}
			if (flag2)
			{
				List<Workout.Control> collection = controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline).ConvertInclineControlsToResistance(console.ConsoleInfo.MinResistanceLevel, console.ConsoleInfo.MaxResistanceLevel);
				controls.AddRange(collection);
			}
			return controls;
		}

		public static List<Workout.Control> ConvertRelativeResistanceControlsToResistance(this Workout workout, IConsoleInfo consoleInfo = null)
		{
			return workout.Controls.ConvertRelativeResistanceToResistance(consoleInfo);
		}

		public static List<Workout.Control> ConvertRelativeResistanceToResistance(this IEnumerable<Workout.Control> controls, IConsoleInfo consoleInfo)
		{
			double minResistance = consoleInfo?.MinResistanceLevel ?? 1.0;
			double maxResistance = ((!((consoleInfo?.MaxResistanceLevel).GetValueOrDefault() > 0.0)) ? 26.0 : (consoleInfo?.MaxResistanceLevel ?? 26.0));
			return (from z in ((from c in (from x in controls?.Where((Workout.Control c) => c != null)
						orderby x.At
						select x).ThenBy((Workout.Control y) => y.Type.ToString())
					select new Workout.Control
					{
						At = c.At,
						HasBeenSent = c.HasBeenSent,
						OverriddenByUser = c.OverriddenByUser,
						Type = ((c.Type == Workout.Control.ControlType.RelativeResistance) ? Workout.Control.ControlType.Resistance : c.Type),
						Value = ((c.Type == Workout.Control.ControlType.RelativeResistance) ? ResistanceRelativeResistanceUtil.RelativeResistanceToResistance(c.Value, minResistance, maxResistance, round: true) : c.Value)
					}).ToList())?.GroupBy((Workout.Control x) => new { x.At, x.Type })
				orderby z.Key.At
				select z.First()).ToList();
		}

		public static List<Workout.Control> ConvertResistanceControlsToRelativeResistance(this IEnumerable<Workout.Control> workoutControls, IConsoleInfo consoleInfo = null)
		{
			double minResistance = consoleInfo?.MinResistanceLevel ?? 1.0;
			double maxResistance = ((!((consoleInfo?.MaxResistanceLevel).GetValueOrDefault() > 0.0)) ? 26.0 : (consoleInfo?.MaxResistanceLevel ?? 26.0));
			return (from c in workoutControls?.Where((Workout.Control c) => c != null)
				select new Workout.Control
				{
					At = c.At,
					HasBeenSent = c.HasBeenSent,
					OverriddenByUser = c.OverriddenByUser,
					Type = ((c.Type == Workout.Control.ControlType.Resistance) ? Workout.Control.ControlType.RelativeResistance : c.Type),
					Value = ((c.Type == Workout.Control.ControlType.Resistance) ? ResistanceRelativeResistanceUtil.ResistanceToRelativeResistance(c.Value, minResistance, maxResistance) : c.Value)
				}).ToList();
		}

		public static void ConvertWorkoutControlsForConsole(this Workout workout, IFitnessConsole console)
		{
			IConsoleInfo consoleInfo = console.ConsoleInfo;
			if (consoleInfo.MachineType.IsBeltBasedMachine())
			{
				return;
			}
			bool flag = workout.HasControlsFor(Workout.Control.ControlType.RelativeResistance);
			bool flag2 = workout.HasControlsFor(Workout.Control.ControlType.Resistance);
			bool flag3 = workout.HasControlsFor(Workout.Control.ControlType.Incline);
			if (!flag)
			{
				if (!flag2 && !flag3)
				{
					iFit.Logger.Log.Trace("Workout", "Workout doesn't have any Resistance, RelativeResistance, or Incline controls.  Not converting.");
					return;
				}
				bool canSetIncline = console.ConsoleInfo.CanSetIncline;
				if (!flag2 && flag3 && !canSetIncline)
				{
					workout.Controls = workout.Controls.ConvertInclineControlsToResistance(1.0, 26.0, roundResistanceValues: false);
					if (!workout.IsMissingScaledControls())
					{
						foreach (int item in workout.ScaledControls.Keys.ToList())
						{
							workout.ScaledControls[item] = workout.ScaledControls[item].ConvertInclineControlsToResistance(1.0, 26.0, roundResistanceValues: false);
						}
					}
				}
				if (workout.HasControlsFor(Workout.Control.ControlType.Resistance))
				{
					workout.Controls = workout.Controls.ConvertResistanceControlsToRelativeResistance(consoleInfo);
					if (!workout.IsMissingScaledControls())
					{
						foreach (int item2 in workout.ScaledControls.Keys.ToList())
						{
							workout.ScaledControls[item2] = workout.ScaledControls[item2].ConvertResistanceControlsToRelativeResistance(consoleInfo);
						}
					}
				}
			}
			if (!workout.HasControlsFor(Workout.Control.ControlType.RelativeResistance))
			{
				iFit.Logger.Log.Trace("Workout", "Attempted to convert workout controls to RelativeResistance, but did not succeed. Not converting.");
				return;
			}
			Workout.Control.ControlType targetType = console.GetTargetControlType();
			if (!workout.Controls.Any((Workout.Control x) => x.Type == targetType))
			{
				workout.ConvertWorkoutControlsFromRelativeResistanceToTarget(console, targetType);
			}
		}

		public static void ConvertWorkoutControlsFromRelativeResistanceToTarget(this Workout workout, IFitnessConsole console, Workout.Control.ControlType targetType)
		{
			(double, double) consoleMaxMinFromTargetType = console.ConsoleInfo.GetConsoleMaxMinFromTargetType(targetType);
			double min = consoleMaxMinFromTargetType.Item1;
			double max = consoleMaxMinFromTargetType.Item2;
			workout.Controls = toTarget(workout.Controls);
			if (workout.IsMissingScaledControls())
			{
				return;
			}
			foreach (int item in workout.ScaledControls.Keys.ToList())
			{
				workout.ScaledControls[item] = toTarget(workout.ScaledControls[item]);
			}
			List<Workout.Control> toTarget(IEnumerable<Workout.Control> workoutControls)
			{
				return workoutControls.Where((Workout.Control c) => c != null)?.Select((Workout.Control c) => new Workout.Control
				{
					At = c.At,
					HasBeenSent = c.HasBeenSent,
					OverriddenByUser = c.OverriddenByUser,
					SentToResetOverrideByUser = c.SentToResetOverrideByUser,
					Type = ((c.Type == Workout.Control.ControlType.RelativeResistance) ? targetType : c.Type),
					Value = ((c.Type == Workout.Control.ControlType.RelativeResistance) ? ResistanceRelativeResistanceUtil.RelativeResistanceToResistance(c.Value, min, max, round: true) : c.Value)
				}).ToList();
			}
		}

		public static (double min, double max) GetConsoleMaxMinFromTargetType(this IConsoleInfo info, Workout.Control.ControlType targetType)
		{
			switch (targetType)
			{
			case Workout.Control.ControlType.Gear:
			{
				(int, int) tuple = (info.CanSetGear ? (info.MinGear, info.MaxGear) : (1, 26));
				return (min: tuple.Item1, max: tuple.Item2);
			}
			case Workout.Control.ControlType.Resistance:
				if (!info.CanSetResistance)
				{
					return (min: 1.0, max: 26.0);
				}
				return (min: info.MinResistanceLevel, max: info.MaxResistanceLevel);
			case Workout.Control.ControlType.Incline:
				if (!info.CanSetIncline)
				{
					return (min: -5.0, max: 20.0);
				}
				return (min: info.MinIncline, max: info.MaxIncline);
			default:
				return (min: -1.0, max: -1.0);
			}
		}

		public static Workout.Control.ControlType GetTargetControlType(this IFitnessConsole console)
		{
			if (console.ConsoleInfo.MachineType.IsAerobicMachine())
			{
				if (console.ConsoleInfo.CanSetGear)
				{
					return Workout.Control.ControlType.Gear;
				}
				if (console.ConsoleInfo.CanSetResistance)
				{
					return Workout.Control.ControlType.Resistance;
				}
			}
			return Workout.Control.ControlType.Incline;
		}

		public static double? ConstantMapWorkoutPaceMps(this Workout workout, bool isMetric, ConsoleType type)
		{
			double? result = null;
			if (type.IsAerobicMachine() || workout?.IsGoogleMap == true || (workout != null && !workout.Controls.Any((Workout.Control c) => c.Type == Workout.Control.ControlType.Mps)))
			{
				result = UnitUtil.EnsureMps(isMetric ? SpeedUnit.Kph : SpeedUnit.Mph, type.EstimateWorkoutSpeed(isMetric));
			}
			return result;
		}

		public static string GetWorkoutMetadataAudioUrl(this Workout workout)
		{
			if (workout == null || workout.Metadata?.Audio == null)
			{
				return null;
			}
			if (workout.Metadata.Audio.Trim().Length < 1)
			{
				return string.Empty;
			}
			string text = workout.Metadata.Audio.Trim();
			string format = "https://ifit-music.s3-cdn.ifit.com/{0}";
			Regex regex = new Regex("^https?\\:\\/\\/(ifit-music\\.)?s3\\.amazonaws\\.com\\/(ifit-music\\/)?(([a-z0-9]+)\\.([a-z0-9]{2,10}))$", RegexOptions.IgnoreCase);
			GroupCollection groupCollection = regex.Match(text)?.Groups;
			if ((groupCollection?.Count ?? 0) >= 4 && !string.IsNullOrWhiteSpace(groupCollection[3]?.Value))
			{
				string value = groupCollection[3].Value;
				text = string.Format(format, value);
			}
			return text;
		}

		public static bool ShouldUseEquipmentlessConsole(this Workout workout)
		{
			return workout.IsStrengthWorkout();
		}

		public static double GetEstimatedHeartRateAtTimeForStrengthWorkout(this Workout workout, double seconds)
		{
			if (workout == null || workout.Type != Workout.WorkoutType.Strength)
			{
				return 0.0;
			}
			double num = workout.Metadata?.AverageHeartRate ?? 125.0;
			return workout.GetWorkoutSegmentAtTime(seconds)?.EstimatedBpm ?? num;
		}

		public static bool DoesContainCategory(this Workout workout, string category)
		{
			if (workout == null)
			{
				throw new ArgumentNullException("workout");
			}
			if (string.IsNullOrWhiteSpace(category))
			{
				return false;
			}
			return workout.LibraryFilters?.Any((Workout.LibraryFilter filter) => filter != null && filter.Categories?.Any((Workout.LibraryFilterCategory x) => x != null && x.Name?.Equals(category, StringComparison.OrdinalIgnoreCase) == true) == true) ?? false;
		}

		public static bool DoesContainAtLeastOneCategoryFromList(this Workout workout, IEnumerable<string> applicableCategories)
		{
			if (workout == null)
			{
				throw new ArgumentNullException("workout");
			}
			return applicableCategories?.Any((string category) => workout.DoesContainCategory(category)) ?? false;
		}

		public static WorkoutOfTheDay.WotdType GetWotdType(this ConsoleType consoleType)
		{
			switch (consoleType)
			{
			case ConsoleType.Rower:
				return WorkoutOfTheDay.WotdType.Rower;
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return WorkoutOfTheDay.WotdType.Cycle;
			default:
				return WorkoutOfTheDay.WotdType.Run;
			}
		}

		public static bool IsTimeWithinAnyVideoMusicRange(this WorkoutVideo workoutVideo, double seconds)
		{
			if (workoutVideo == null)
			{
				return false;
			}
			return workoutVideo.VideoMusicRegions?.Any((WorkoutVideo.Timestamp ts) => ts.IsValid && seconds >= (double)ts.Start && seconds < (double)ts.End) == true;
		}

		public static List<WorkoutVideo.Timestamp> CollapseValidVideoMusicRegions(this List<WorkoutVideo.Timestamp> original)
		{
			if (original == null)
			{
				return null;
			}
			List<WorkoutVideo.Timestamp> list = (from x in original
				where x.IsValid
				orderby x.Start
				select x).ToList();
			if (list.Count < 1)
			{
				return new List<WorkoutVideo.Timestamp>(0);
			}
			if (list.Count == 1)
			{
				return new List<WorkoutVideo.Timestamp>(1) { list.First() };
			}
			Stack<WorkoutVideo.Timestamp> stack = new Stack<WorkoutVideo.Timestamp>(list.Count);
			Queue<WorkoutVideo.Timestamp> queue = new Queue<WorkoutVideo.Timestamp>(list);
			stack.Push(queue.Dequeue());
			while (queue.Count > 0)
			{
				WorkoutVideo.Timestamp[] array = CollapseTimestampPairIfNecessary(stack.Pop(), queue.Dequeue());
				stack.Push(array[0]);
				if (array.Length > 1)
				{
					stack.Push(array[1]);
				}
			}
			List<WorkoutVideo.Timestamp> list2 = stack.ToList();
			list2.Reverse();
			return list2;
		}

		private static WorkoutVideo.Timestamp[] CollapseTimestampPairIfNecessary(WorkoutVideo.Timestamp ts1, WorkoutVideo.Timestamp ts2)
		{
			WorkoutVideo.Timestamp timestamp = ((ts1.Start <= ts2.Start) ? ts1 : ts2);
			WorkoutVideo.Timestamp timestamp2 = ((timestamp == ts1) ? ts2 : ts1);
			if (timestamp2.Start <= timestamp.End)
			{
				int start = timestamp.Start;
				int end = Math.Max(timestamp.End, timestamp2.End);
				return new WorkoutVideo.Timestamp[1]
				{
					new WorkoutVideo.Timestamp(start, end)
				};
			}
			return new WorkoutVideo.Timestamp[2] { timestamp, timestamp2 };
		}

		public static bool HasStrengthMirrorWorkoutFilter(this Workout workout)
		{
			if (workout == null)
			{
				return false;
			}
			if (!workout.HasFilter(Workout.WorkoutFilter.IsVault))
			{
				return workout.HasFilter(Workout.WorkoutFilter.IsVue);
			}
			return true;
		}

		public static bool IsMind(this Workout workout)
		{
			return workout?.LibraryFilters?.FirstOrDefault((Workout.LibraryFilter f) => f?.Categories?.FirstOrDefault((Workout.LibraryFilterCategory c) => c?.Name?.ToLower() == "mind") != null) != null;
		}

		public static List<Workout.Control> OnlyControlsOrderedByAt(this Workout workout, Workout.Control.ControlType type)
		{
			return (from y in workout.Controls
				where y.Type == type
				orderby y.At
				select y).ToList();
		}

		public static int CountType(this Workout workout, Workout.Control.ControlType type)
		{
			return workout.Controls.Count((Workout.Control x) => x.Type == type);
		}
	}
