	public class BootloaderStatusCode
	{
		private static readonly Dictionary<byte, BootloaderStatusCode> StatusCodes = new Dictionary<byte, BootloaderStatusCode>();

		public static readonly BootloaderStatusCode CyretSuccess = new BootloaderStatusCode(0, "The command was successfully received and executed");

		public static readonly BootloaderStatusCode ErrVerify = new BootloaderStatusCode(2, "The verification of flash failed");

		public static readonly BootloaderStatusCode ErrLength = new BootloaderStatusCode(3, "The amount of data available is outside the expected range");

		public static readonly BootloaderStatusCode ErrData = new BootloaderStatusCode(4, "The data is not of the proper form");

		public static readonly BootloaderStatusCode ErrCommand = new BootloaderStatusCode(5, "The command is not recognized");

		public static readonly BootloaderStatusCode ErrDevice = new BootloaderStatusCode(6, "The expected device does not match the detected device.");

		public static readonly BootloaderStatusCode ErrVersion = new BootloaderStatusCode(7, "The bootloader version detected is not supported.");

		public static readonly BootloaderStatusCode ErrChecksum = new BootloaderStatusCode(8, "Packet checksum does not match the expected value");

		public static readonly BootloaderStatusCode ErrArray = new BootloaderStatusCode(9, "Flash array is not valid");

		public static readonly BootloaderStatusCode ErrRow = new BootloaderStatusCode(10, "The flash row is not valid");

		public static readonly BootloaderStatusCode ErrApp = new BootloaderStatusCode(12, "The application is not valid and cannot be set as active");

		public static readonly BootloaderStatusCode ErrActive = new BootloaderStatusCode(13, "The application is currently marked as active");

		public static readonly BootloaderStatusCode ErrUnknown = new BootloaderStatusCode(15, "An unknown error occurred");

		public static readonly BootloaderStatusCode CommandChecksum = new BootloaderStatusCode(49, "Verify the checksum for the bootloadable project");

		public static readonly BootloaderStatusCode CommandReportSize = new BootloaderStatusCode(50, "Reports the programmable portions of flash");

		public static readonly BootloaderStatusCode CommandAppStatus = new BootloaderStatusCode(51, "Gets the status info about the provided app status");

		public static readonly BootloaderStatusCode CommandErase = new BootloaderStatusCode(52, "Erase the specified flash row");

		public static readonly BootloaderStatusCode CommandSync = new BootloaderStatusCode(53, "Sync the bootloader and host application");

		public static readonly BootloaderStatusCode CommandAppActive = new BootloaderStatusCode(54, "Sets the active application");

		public static readonly BootloaderStatusCode CommandData = new BootloaderStatusCode(55, "Queue up a block of data for programming");

		public static readonly BootloaderStatusCode CommandENTER = new BootloaderStatusCode(56, "Enter the bootloader");

		public static readonly BootloaderStatusCode CommandProgram = new BootloaderStatusCode(57, "Program the specified row");

		public static readonly BootloaderStatusCode CommandGetRowChecksum = new BootloaderStatusCode(58, "Compute flash row checksum for verification");

		public static readonly BootloaderStatusCode CommandExit = new BootloaderStatusCode(59, "Exits the bootloader and resets the chip");

		public static readonly BootloaderStatusCode CommandGetMetadata = new BootloaderStatusCode(60, "Reports the detadata for a selected application");

		public static readonly BootloaderStatusCode CommandVerifyFlashRow = new BootloaderStatusCode(69, "Verifies data in buffer with specified row in flash");

		public static readonly BootloaderStatusCode NoStatusCode = new BootloaderStatusCode(79, "No status");

		public readonly byte Id;

		public readonly string Description;

		private BootloaderStatusCode(byte id, string description)
		{
			Id = id;
			Description = description;
			StatusCodes[id] = this;
		}

		public static BootloaderStatusCode GetBootloaderStatusCode(byte id)
		{
			if (!StatusCodes.ContainsKey(id))
			{
				return NoStatusCode;
			}
			return StatusCodes[id];
		}
	}
	public class ByteUtil
	{
		public enum Endianess
		{
			Big,
			Little
		}

		public static byte[] HexStringToByteArray(string hexString)
		{
			return (from x in Enumerable.Range(0, hexString.Length)
				where x % 2 == 0
				select Convert.ToByte(hexString.Substring(x, 2), 16)).ToArray();
		}

		public static int ToInt(byte[] bytes, Endianess endianess)
		{
			if (endianess == Endianess.Little)
			{
				return (bytes[1] << 8) + bytes[0];
			}
			return (bytes[0] << 8) + bytes[1];
		}

		public static byte[] Checksum(byte[] bytes)
		{
			return ShortToBytes((short)(~SumBytes(bytes) + 1));
		}

		public static byte ChecksumByte(byte[] bytes)
		{
			return (byte)(~SumBytes(bytes) + 1);
		}

		public static int SumBytes(byte[] bytes)
		{
			return bytes.Sum((byte x) => x & 0xFF);
		}

		public static byte[] ShortToBytes(short number)
		{
			return new byte[2]
			{
				(byte)(number & 0xFF),
				(byte)((number >> 8) & 0xFF)
			};
		}
	}
	public class FileHeader
	{
		public byte[] SiliconId { get; private set; }

		public byte SiliconRev { get; private set; }

		public byte CheckSum { get; private set; }

		public FileHeader(string hex)
		{
			byte[] array = ByteUtil.HexStringToByteArray(hex);
			SiliconId = array.Take(4).ToArray();
			SiliconRev = array[4];
			CheckSum = array[5];
		}
	}
	public class Packet
	{
		public const byte DefaultStartOfPacket = 1;

		public const byte DefaultEndOfPacket = 23;

		public byte StartOfPacket { get; private set; }

		public byte EndOfPacket { get; private set; }

		public BootloaderStatusCode StatusCode { get; private set; }

		public byte[] DataLength { get; private set; }

		public byte[] Data { get; private set; }

		public byte[] CheckSum { get; private set; }

		public Packet(BootloaderStatusCode code, byte[] data)
		{
			StartOfPacket = 1;
			EndOfPacket = 23;
			StatusCode = code;
			DataLength = ByteUtil.ShortToBytes((short)data.Length);
			Data = data;
			CheckSum = CalculateChecksum();
		}

		public Packet(byte[] bytes)
		{
			StartOfPacket = bytes[0];
			StatusCode = BootloaderStatusCode.GetBootloaderStatusCode(bytes[1]);
			DataLength = bytes.Skip(2).Take(2).ToArray();
			int num = ByteUtil.ToInt(DataLength, ByteUtil.Endianess.Little);
			Data = ((num == 0) ? new byte[0] : bytes.Skip(4).Take(num).ToArray());
			CheckSum = bytes.Skip(num + 4).Take(2).ToArray();
			EndOfPacket = bytes[num + 6];
		}

		public Packet(BootloaderStatusCode code, Row row)
		{
			StartOfPacket = 1;
			EndOfPacket = 23;
			StatusCode = code;
			DataLength = row.DataLengthBytes;
			Data = row.Data;
			CheckSum = CalculateChecksum();
		}

		public byte[] CalculateChecksum()
		{
			return ByteUtil.Checksum(new byte[2] { StartOfPacket, StatusCode.Id }.Concat(DataLength).Concat(Data).ToArray());
		}

		public byte[] ToBytes()
		{
			return new byte[2] { StartOfPacket, StatusCode.Id }.Concat(DataLength).Concat(Data).Concat(CheckSum)
				.Concat(new byte[1] { EndOfPacket })
				.ToArray();
		}

		public bool IsValid()
		{
			if (StartOfPacket == 1 && EndOfPacket == 23 && Data.Length == ByteUtil.ToInt(DataLength, ByteUtil.Endianess.Little))
			{
				return ByteUtil.ToInt(CalculateChecksum(), ByteUtil.Endianess.Little) == ByteUtil.ToInt(CheckSum, ByteUtil.Endianess.Little);
			}
			return false;
		}

		public bool IsSuccess()
		{
			return StatusCode == BootloaderStatusCode.CyretSuccess;
		}
	}
	public static class PacketFactory
	{
		public static Packet CreateEnterBootloaderPacket()
		{
			return CreatePacketWithNoData(BootloaderStatusCode.CommandENTER);
		}

		public static Packet CreateSyncBootloaderPacket()
		{
			return CreatePacketWithNoData(BootloaderStatusCode.CommandSync);
		}

		public static Packet CreateExitBootloaderPacket()
		{
			return CreatePacketWithNoData(BootloaderStatusCode.CommandExit);
		}

		public static Packet CreateGetFlashSizePacket()
		{
			return new Packet(BootloaderStatusCode.CommandReportSize, new byte[1]);
		}

		public static Packet CreateProgramRowPacket(byte arrayId, byte[] rowId, byte[] data)
		{
			return new Packet(BootloaderStatusCode.CommandProgram, CreateDataForArrayIdAndRow(arrayId, rowId).Concat(data).ToArray());
		}

		public static Packet CreateEraseRowPacket(byte arrayId, byte[] rowId)
		{
			return new Packet(BootloaderStatusCode.CommandErase, CreateDataForArrayIdAndRow(arrayId, rowId));
		}

		public static Packet CreateSendDataPacket(byte[] data)
		{
			return new Packet(BootloaderStatusCode.CommandData, data);
		}

		public static Packet CreateVerifyRowPacket(byte arrayId, byte[] rowId)
		{
			return new Packet(BootloaderStatusCode.CommandGetRowChecksum, CreateDataForArrayIdAndRow(arrayId, rowId));
		}

		private static byte[] CreateDataForArrayIdAndRow(byte arrayId, byte[] rowId)
		{
			return new byte[1] { arrayId }.Concat(rowId).ToArray();
		}

		private static Packet CreatePacketWithNoData(BootloaderStatusCode code)
		{
			return new Packet(code, new byte[0]);
		}
	}
	public class Row
	{
		private const int ChunkSize = 53;

		public byte ArrayId { get; private set; }

		public byte[] RowNumber { get; private set; }

		public byte[] DataLengthBytes { get; private set; }

		public byte[] Data { get; private set; }

		public byte CheckSum { get; private set; }

		public int DataLength => ByteUtil.ToInt(DataLengthBytes, ByteUtil.Endianess.Big);

		public Row(string row)
		{
			ParseRow(row);
		}

		private void ParseRow(string row)
		{
			byte[] array = ByteUtil.HexStringToByteArray(row.Replace(":", ""));
			ArrayId = array[0];
			RowNumber = new byte[2]
			{
				array[2],
				array[1]
			};
			CheckSum = array[^1];
			DataLengthBytes = new byte[2]
			{
				array[3],
				array[4]
			};
			Data = array.Skip(5).Take(DataLength).ToArray();
		}

		public List<Packet> ConvertDataIntoPackets()
		{
			List<Packet> list = new List<Packet>();
			List<IEnumerable<byte>> list2 = Data.Partition(53).ToList();
			for (int i = 0; i < list2.Count - 1; i++)
			{
				list.Add(PacketFactory.CreateSendDataPacket(list2[i].ToArray()));
			}
			list.Add(PacketFactory.CreateProgramRowPacket(ArrayId, RowNumber, list2[list2.Count - 1].ToArray()));
			return list;
		}
	}
}
