	public abstract class ShireBaseViewModel : MvxViewModel, IVisible, IDisposable
	{
		protected bool isDisposed;

		private bool _visible;

		public virtual object ArbitraryData { get; set; }

		public IMvxCommand CloseViewModel => new MvxCommand(DoClose);

		public Type ParentType { get; set; }

		public Guid ViewModelIdentifier { get; private set; } = Guid.NewGuid();

		public WeakReference<IMvxView> View { get; set; }

		public virtual bool IsVisible
		{
			get
			{
				return _visible;
			}
			set
			{
				if (_visible == value || isDisposed)
				{
					return;
				}
				_visible = value;
				if (_visible)
				{
					OnViewShown().ContinueWith(delegate(Task t)
					{
						if (t.IsCompleted)
						{
							OnAfterViewShown();
						}
					});
				}
				else
				{
					OnViewHidden();
				}
			}
		}

		protected int viewShownCount { get; set; }

		public virtual void InitWithArbitraryData()
		{
		}

		public virtual void Dispose()
		{
			iFit.Logger.Log.Trace("MvxTrace", string.Format("{0}: {1} called ({2})", GetType().Name, "Dispose", ViewModelIdentifier));
			isDisposed = true;
			OnViewHidden();
		}

		protected virtual void DoClose()
		{
			DoClose(new MvxClosePresentationHint(this));
		}

		protected virtual void DoClose(MvxPresentationHint presentationHint)
		{
			iFit.Logger.Log.Trace("MvxTrace", string.Format("{0}: {1} called ({2})", GetType().Name, "DoClose", ViewModelIdentifier));
			ChangePresentation(presentationHint);
		}

		public virtual async Task OnViewShown()
		{
			iFit.Logger.Log.Trace("MvxTrace", string.Format("{0}: {1} called ({2})", GetType().Name, "OnViewShown", ViewModelIdentifier));
			viewShownCount++;
			await Task.FromResult(0);
		}

		public virtual void OnAfterViewShown()
		{
			iFit.Logger.Log.Trace("MvxTrace", string.Format("{0}: {1} called ({2})", GetType().Name, "OnAfterViewShown", ViewModelIdentifier));
		}

		protected virtual void OnViewHidden()
		{
			iFit.Logger.Log.Trace("MvxTrace", string.Format("{0}: {1} called ({2})", GetType().Name, "OnViewHidden", ViewModelIdentifier));
		}

		public virtual void ShowUpdateProgressDialog()
		{
		}

		public void RegisterChangedCallback(INotifyChange property, string propertyName)
		{
			if (property != null)
			{
				property.Changed += delegate
				{
					RaisePropertyChanged(propertyName);
				};
			}
		}

		public void RegisterCollectionChangedCallback(INotifyCollectionChanged property, string propertyName)
		{
			property.CollectionChanged += delegate
			{
				RaisePropertyChanged(propertyName);
			};
		}
	}
