	public class ViewLookupBase
	{
		protected const string ViewSuffix = "View";

		protected const string ViewModelSuffix = "ViewModel";

		public bool ShouldRegisterItem(PlatformAttribute attr, bool isTablet)
		{
			return attr.FormFactor == PlatformAttribute.FormFactorType.Tablet == isTablet;
		}

		protected string GetStrippedName(Type type)
		{
			string result = type.Name;
			if (TrimEndString(type.Name, "View", ref result))
			{
				return result;
			}
			TrimEndString(type.Name, "ViewModel", ref result);
			return result;
		}

		private bool TrimEndString(string original, string end, ref string result)
		{
			if (original.Substring(original.Length - end.Length, end.Length).Equals(end))
			{
				result = original.Substring(0, original.Length - end.Length);
				return true;
			}
			return false;
		}
	}
