namespace Shire.Core.InAppNotifications.Helpers
{
	public interface IBaseNotificationHelper : IDisposable
	{
		NotificationData Get(string guid = null);

		bool Dismiss(string guid = null);

		void DismissAll();

		void Post(NotificationData notification);

		void Pause(TimeSpan pausedFor);

		bool AnyRunning();
	}
	public abstract class BaseNotificationHelper : IBaseNotificationHelper, IDisposable
	{
		protected Subject<(NotificationChangeType type, NotificationData data)> notificationNotify;

		protected NotificationData activeNotification;

		protected readonly object objLock = new object();

		protected bool IsDisposed { get; private set; }

		protected BaseNotificationHelper(Subject<(NotificationChangeType type, NotificationData data)> notificationNotify)
		{
			this.notificationNotify = notificationNotify;
		}

		public NotificationData Get(string guid = null)
		{
			if (IsDisposed)
			{
				return null;
			}
			NotificationData notificationData = activeNotification;
			if (notificationData != null && (guid == null || notificationData.Id.Equals(guid)) && !notificationData.Dismissed)
			{
				return notificationData;
			}
			return null;
		}

		public bool Dismiss(string guid = null)
		{
			if (IsDisposed)
			{
				return false;
			}
			bool result = false;
			NotificationData notificationData = Get(guid);
			if (notificationData != null)
			{
				result = DismissNotification(notificationData);
			}
			return result;
		}

		public virtual void DismissAll()
		{
			if (!IsDisposed)
			{
				NotificationData notificationData = Get();
				if (notificationData != null)
				{
					DismissNotification(notificationData);
				}
			}
		}

		public virtual void Post(NotificationData notification)
		{
			if (!IsDisposed)
			{
				iFit.Logger.Log.Trace(InAppNotificationService.Tag, $"Posting notification {notification}");
			}
		}

		public abstract void Pause(TimeSpan pausedFor);

		public abstract bool AnyRunning();

		protected virtual void OnDismissed()
		{
		}

		protected void SetNotificationToActive(NotificationData notification)
		{
			if (!IsDisposed)
			{
				NotificationData notificationData;
				lock (objLock)
				{
					notificationData = activeNotification;
					activeNotification = notification;
				}
				if (notificationData != null)
				{
					DismissNotification(notificationData);
				}
				SetupNotificationAdd(notification);
			}
		}

		protected void SetupNotificationAdd(NotificationData notification)
		{
			if (notification.Duration > TimeSpan.Zero)
			{
				Task.Run(async delegate
				{
					await Task.Delay(notification.Duration);
					DismissNotification(notification);
				});
			}
			notificationNotify.OnNext((NotificationChangeType.Add, notification));
		}

		private bool DismissNotification(NotificationData notification)
		{
			bool flag;
			lock (objLock)
			{
				flag = !notification.Dismissed;
				notification.Dismissed = true;
			}
			if (flag)
			{
				iFit.Logger.Log.Trace(InAppNotificationService.Tag, $"Dismissing notification {notification}");
				notificationNotify.OnNext((NotificationChangeType.Remove, notification));
				OnDismissed();
			}
			return flag;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!IsDisposed)
			{
				if (disposing)
				{
					notificationNotify = null;
					activeNotification = null;
				}
				IsDisposed = true;
			}
		}
	}
	public class DismissOldOnPost : BaseNotificationHelper
	{
		public DismissOldOnPost(Subject<(NotificationChangeType type, NotificationData data)> notificationNotify)
			: base(notificationNotify)
		{
		}

		public override void Post(NotificationData notification)
		{
			base.Post(notification);
			SetNotificationToActive(notification);
		}

		public override void Pause(TimeSpan pausedFor)
		{
			throw new NotImplementedException();
		}

		public override bool AnyRunning()
		{
			if (activeNotification != null)
			{
				return !activeNotification.Dismissed;
			}
			return false;
		}
	}
	public class QueueNewOnPost(Subject<(NotificationChangeType type, NotificationData data)> notificationNotify) : BaseNotificationHelper(notificationNotify)
	{
		private readonly Queue<NotificationData> queue = new Queue<NotificationData>();

		private Task pausingTask;

		private DateTime pausedTill = new DateTime(0L);

		public override bool AnyRunning()
		{
			int num = 0;
			lock (objLock)
			{
				num = queue.Count;
			}
			if (activeNotification == null || activeNotification.Dismissed)
			{
				return num > 0;
			}
			return true;
		}

		public override void Pause(TimeSpan pausedFor)
		{
			if (!base.IsDisposed)
			{
				pausedTill = DateTime.Now + pausedFor;
			}
		}

		public override void Post(NotificationData notification)
		{
			if (base.IsDisposed)
			{
				return;
			}
			base.Post(notification);
			if (IsDuplicateMessage(notification))
			{
				iFit.Logger.Log.Trace(InAppNotificationService.Tag, $"Duplicate notification {notification}");
				return;
			}
			lock (objLock)
			{
				queue.Enqueue(notification);
			}
			PostNextQueueNotification();
		}

		public override void DismissAll()
		{
			if (!base.IsDisposed)
			{
				ClearQueue();
				base.DismissAll();
			}
		}

		private void ClearQueue()
		{
			lock (objLock)
			{
				queue.Clear();
			}
		}

		private void PostNextQueueNotification()
		{
			if (base.IsDisposed || PauseNotificationsIfNeeded())
			{
				return;
			}
			NotificationData notificationData = null;
			lock (objLock)
			{
				if ((activeNotification == null || activeNotification.Dismissed) && queue.Count > 0)
				{
					notificationData = (activeNotification = queue.Dequeue());
				}
			}
			if (notificationData != null)
			{
				SetupNotificationAdd(notificationData);
			}
		}

		protected override void OnDismissed()
		{
			PostNextQueueNotification();
		}

		private bool PauseNotificationsIfNeeded()
		{
			bool result = false;
			TimeSpan pauseTime = pausedTill - DateTime.Now;
			if (pauseTime.TotalMilliseconds > 0.0)
			{
				result = true;
				if (ShouldCreatePauseTimer())
				{
					pausingTask = Task.Run(async delegate
					{
						await Task.Delay(pauseTime + TimeSpan.FromMilliseconds(10.0));
						pausingTask = null;
						if (!PauseNotificationsIfNeeded())
						{
							PostNextQueueNotification();
						}
					});
				}
			}
			return result;
		}

		private bool ShouldCreatePauseTimer()
		{
			bool result = false;
			lock (objLock)
			{
				if (pausingTask == null)
				{
					result = true;
					pausingTask = Task.FromResult(1);
				}
			}
			return result;
		}

		private bool IsDuplicateMessage(NotificationData notification)
		{
			NotificationData notificationData = activeNotification;
			if (notificationData != null && !notificationData.Dismissed)
			{
				NotificationData notificationData2 = activeNotification;
				if (notificationData2 != null && notificationData2.IsDuplicateMessage(notification))
				{
					return true;
				}
			}
			bool flag = false;
			lock (objLock)
			{
				return queue.Any((NotificationData x) => x.IsDuplicateMessage(notification));
			}
		}

		protected override void Dispose(bool disposing)
		{
			if (base.IsDisposed)
			{
				return;
			}
			if (disposing)
			{
				ClearQueue();
				Task task = pausingTask;
				if (task != null && task.IsCompleted)
				{
					pausingTask.Dispose();
				}
				pausingTask = null;
			}
			base.Dispose(disposing);
		}
	}
}
namespace Shire.Core.Util
{
	public interface IMainThreadSchedulerService
	{
		IScheduler Scheduler { get; }
	}
	public class AsyncReaderWriterLock : IDisposable
	{
		private readonly SemaphoreSlim readSemaphore = new SemaphoreSlim(1, 1);

		private readonly SemaphoreSlim writeSemaphore = new SemaphoreSlim(1, 1);

		protected int readerCount;

		public async Task AcquireWriterLock(CancellationToken token = default(CancellationToken))
		{
			await writeSemaphore.WaitAsync(token).ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				await readSemaphore.WaitAsync(token).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch
			{
				writeSemaphore.Release();
				throw;
			}
		}

		public void ReleaseWriterLock()
		{
			readSemaphore.Release();
			writeSemaphore.Release();
		}

		public async Task AcquireReaderLock(CancellationToken token = default(CancellationToken))
		{
			await writeSemaphore.WaitAsync(token).ConfigureAwait(continueOnCapturedContext: false);
			if (Interlocked.Increment(ref readerCount) == 1)
			{
				try
				{
					await readSemaphore.WaitAsync(token).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch
				{
					Interlocked.Decrement(ref readerCount);
					writeSemaphore.Release();
					throw;
				}
			}
			writeSemaphore.Release();
		}

		public void ReleaseReaderLock()
		{
			if (Interlocked.Decrement(ref readerCount) == 0)
			{
				readSemaphore.Release();
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposing)
			{
				writeSemaphore.Dispose();
				readSemaphore.Dispose();
			}
		}
	}
	public class AverageTimer
	{
		private const string Tag = "Benchmark";

		private readonly string label;

		private readonly int logFrequency;

		private readonly SemaphoreSlim ss = new SemaphoreSlim(1, 1);

		private DateTime? startTime;

		public Average Average { get; private set; }

		public AverageTimer(string label, int logFrequency)
		{
			this.label = label;
			this.logFrequency = logFrequency;
			Average = new Average();
		}

		public async Task StartAsync()
		{
			await ss.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			startTime = DateTime.UtcNow;
			ss.Release();
		}

		public void Start()
		{
			ss.Wait();
			startTime = DateTime.UtcNow;
			ss.Release();
		}

		public async Task AbortAsync()
		{
			await ss.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			startTime = null;
			ss.Release();
		}

		public async Task EndAsync(string addition = null)
		{
			if (!startTime.HasValue)
			{
				return;
			}
			await ss.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				EndTimer(addition);
			}
			finally
			{
				ss.Release();
			}
		}

		public void End(string addition = null)
		{
			if (!startTime.HasValue)
			{
				return;
			}
			ss.Wait();
			try
			{
				EndTimer(addition);
			}
			finally
			{
				ss.Release();
			}
		}

		private void EndTimer(string addition)
		{
			DateTime utcNow = DateTime.UtcNow;
			double totalMilliseconds = (utcNow - startTime.Value).TotalMilliseconds;
			Average.AddSample(totalMilliseconds);
			if (Average.NumberOfSamplings % logFrequency == 0)
			{
				Log(addition);
			}
			startTime = null;
		}

		public void Log(string addition = null)
		{
			iFit.Logger.Log.Trace("Benchmark", $"AverageTimer \"{label}\": {Average.CurrentAverage:0.00} millis over {Average.NumberOfSamplings} samples. {addition}");
		}
	}
