	public static class CalorieMultiplierCalculator
	{
		public const double OffEquipmentValue = 0.10303;

		public static double CalculateOffEquipmentAerobicCaloriesDelta(int lastTime, int currentTime, double massKg, List<Workout.VideoWorkoutMetadata.CalorieMultiplierEvent> events)
		{
			double num = 0.0;
			for (int i = lastTime + 1; i <= currentTime; i++)
			{
				num += CalculateOffEquipmentAerobicCalories(i, massKg, 1.0, events);
			}
			return num;
		}

		public static double CalculateOffEquipmentAerobicCalories(int currentTime, double massKg, double seconds, List<Workout.VideoWorkoutMetadata.CalorieMultiplierEvent> events)
		{
			double result = 0.0;
			Workout.VideoWorkoutMetadata.CalorieMultiplierEvent calorieEventForTime = GetCalorieEventForTime(events, currentTime);
			if (calorieEventForTime != null)
			{
				result = CalculateAerobicCalories(0.10303 * calorieEventForTime.Multiplier, massKg, seconds);
			}
			return result;
		}

		public static Workout.VideoWorkoutMetadata.CalorieMultiplierEvent GetCalorieEventForTime(List<Workout.VideoWorkoutMetadata.CalorieMultiplierEvent> calorieMultiplierEvents, int time)
		{
			return calorieMultiplierEvents?.FirstOrDefault((Workout.VideoWorkoutMetadata.CalorieMultiplierEvent x) => time > x.Start && time <= x.End);
		}

		public static double CalculateAerobicCalories(double vo2, double kg, double seconds = 1.0)
		{
			return CalorieFormulas.OxygenConsumedToCalories(vo2, kg, seconds);
		}

		public static double CalculateOffEquipmentBeltMachineCalories(int currentTime, double newRawCalories, double previousRawCalories, double previousDecoratedCalories, List<Workout.VideoWorkoutMetadata.CalorieMultiplierEvent> events, double kph)
		{
			Workout.VideoWorkoutMetadata.CalorieMultiplierEvent calorieEventForTime = GetCalorieEventForTime(events, currentTime);
			double num = newRawCalories - previousRawCalories;
			if (calorieEventForTime != null && UnitUtil.EnsureMph(SpeedUnit.Kph, kph, 1).AlmostEqual(1.0, 1))
			{
				return previousDecoratedCalories + num * calorieEventForTime.Multiplier;
			}
			return previousDecoratedCalories + num;
		}
	}
