		LiveWorkoutControlValues GetWorkoutControlValues(string controlString);
	}
	public class CaptionParser : ICaptionParser
	{
		private const int NumOfControls = 9;

		private const int CurrentTimeSecondsIndex = 0;

		private const int SpeedMphIndex = 1;

		private const int InclinePercentIndex = 2;

		private const int ResistanceIndex = 3;

		private const int TargetRpmIndex = 4;

		private const int TargetWattsIndex = 5;

		private const int TargetHrZoneIndex = 6;

		private const int TargetHrIndex = 7;

		private const int WorkoutStateIndex = 8;

		public LiveWorkoutControlValues GetWorkoutControlValues(string controlString)
		{
			if (string.IsNullOrWhiteSpace(controlString))
			{
				throw new ArgumentException("Malformed control string: null or empty, controlString=" + controlString);
			}
			string text = controlString.Trim();
			if (text.Contains("\n"))
			{
				throw new ArgumentException("Malformed control string: contains newlines, controlString=" + controlString);
			}
			LiveWorkoutControlValues liveWorkoutControlValues = new LiveWorkoutControlValues();
			string[] array = controlString.Split(',');
			if (array.Length != 9)
			{
				throw new ArgumentException($"Malformed control string: not enough or too many fields, expected: {9} but got {array.Length}, controlString={controlString}");
			}
			float[] array2 = ConvertToNumericVals(array);
			liveWorkoutControlValues.CurrentSeconds = array2[0];
			liveWorkoutControlValues.SpeedMph = array2[1];
			liveWorkoutControlValues.Incline = array2[2];
			liveWorkoutControlValues.Resistance = array2[3];
			liveWorkoutControlValues.TargetRPM = array2[4];
			liveWorkoutControlValues.TargetWatts = array2[5];
			liveWorkoutControlValues.TargetHRZone = array2[6];
			liveWorkoutControlValues.TargetHR = array2[7];
			int num = (int)array2[8];
			if (num < 0 || num > 2)
			{
				throw new ArgumentException($"Caption LiveWorkoutState field contained an out-of-bounds value: {num}");
			}
			liveWorkoutControlValues.WorkoutState = (LiveWorkoutState)num;
			return liveWorkoutControlValues;
		}

		private static float[] ConvertToNumericVals(string[] controlStrs)
		{
			float[] array = new float[9];
			for (int i = 0; i < array.Length; i++)
			{
				if (float.TryParse(controlStrs[i], NumberStyles.Float, CultureInfo.InvariantCulture, out var result))
				{
					array[i] = result;
					continue;
				}
				throw new ArgumentException($"\"{array[i]}\" is not a valid numeric value.");
			}
			return array;
		}
	}
	public class ChartDataCollection : ImprovedObservableCollection<Tuple<double, double>>
	{
		public void RemoveAllAndAddList(List<Tuple<double, double>> addList)
		{
			try
			{
				CheckReentrancy();
				using (BlockReentrancy())
				{
					List<Tuple<double, double>> oldItems = this.ToList();
					base.Items.Clear();
					foreach (Tuple<double, double> add in addList)
					{
						base.Items.Add(add);
					}
					OnCollectionChanged(new NotifyCollectionChangedEventArgs(NotifyCollectionChangedAction.Replace, addList, oldItems));
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Charting", "Failed to remove all data and add list in ChartDataCollection", exception);
			}
		}

		public void RemoveDataBeforeKey(double key)
		{
			if (base.Items.Count <= 0)
			{
				return;
			}
			try
			{
				CheckReentrancy();
				using (BlockReentrancy())
				{
					Tuple<double, double> tuple = base.Items.LastOrDefault((Tuple<double, double> x) => x.Item1 <= key);
					if (tuple == null)
					{
						return;
					}
					Tuple<double, double> item = new Tuple<double, double>(key, tuple.Item2);
					List<Tuple<double, double>> list = this.Where((Tuple<double, double> x) => x.Item1 <= key).ToList();
					foreach (Tuple<double, double> item2 in list)
					{
						base.Items.Remove(item2);
					}
					base.Items.Insert(0, item);
					OnCollectionChanged(new NotifyCollectionChangedEventArgs(NotifyCollectionChangedAction.Replace, new List<Tuple<double, double>> { item }, list));
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Charting", "Failed to remove data in ChartDataCollection", exception);
			}
		}
	}
	public static class ColorUtils
	{
		public static SplatColor MakeRandomColor(bool opaque = true, bool cache = true, Random rng = null)
		{
			if (rng == null)
			{
				rng = new Random();
			}
			if (cache)
			{
				byte[] array = new byte[opaque ? 3 : 4];
				rng.NextBytes(array);
				string text = BitConverter.ToString(array).Replace("-", string.Empty);
				if (text.Length == 6)
				{
					text += "FF";
				}
				return HexColorCache.Get(text);
			}
			return SplatColor.FromArgb(opaque ? 255 : rng.Next(256), rng.Next(256), rng.Next(256), rng.Next(256));
		}
	}
