	public class ExecutionTimer
	{
		private const string Tag = "Benchmark";

		private readonly string groupName;

		private readonly StringBuilder sb = new StringBuilder();

		private readonly object lockObject = new object();

		private long lastMillis;

		public Stopwatch Stopwatch { get; } = new Stopwatch();

		public ExecutionTimer(string groupName, bool start = true)
		{
			lock (lockObject)
			{
				this.groupName = groupName;
				sb.Append(groupName + " - ");
				if (start)
				{
					Stopwatch.Start();
				}
			}
		}

		public void ResetAndStart()
		{
			lock (lockObject)
			{
				lastMillis = 0L;
				sb.Clear();
				sb.Append(groupName + " - ");
				Stopwatch.Restart();
			}
		}

		public void Mark(string itemName)
		{
			long num = Stopwatch.ElapsedMilliseconds - lastMillis;
			lock (lockObject)
			{
				sb.Append($"{itemName}: {num} ");
				lastMillis = Stopwatch.ElapsedMilliseconds;
			}
		}

		public void Finish()
		{
			Stopwatch.Stop();
			lock (lockObject)
			{
				sb.Append($"Total: {Stopwatch.ElapsedMilliseconds}");
				iFit.Logger.Log.Trace("Benchmark", sb.ToString());
			}
		}
	}
