	public class FileDownloader : IFileDownloader
	{
		private class Downloader : IDisposable
		{
			private readonly IFileToDownload file;

			private DateTime LastSuccessfulRead;

			private readonly byte[] buffer = new byte[8192];

			private readonly TimeSpan MaxWaitForResume = TimeSpan.FromMinutes(1.0);

			private readonly Subject<byte[]> downloadedBytes = new Subject<byte[]>();

			public IObservable<byte[]> DownloadedBytes => downloadedBytes;

			public Downloader(IFileToDownload file)
			{
				this.file = file;
			}

			public async Task Download()
			{
				LastSuccessfulRead = DateTime.Now;
				using HttpClient client = new HttpClient(new HttpClientHandler());
				if (file.Size.HasValue && file.Size > 0)
				{
					while (DateTime.Now - LastSuccessfulRead < MaxWaitForResume)
					{
						try
						{
							if (file.Progress > 0)
							{
								client.DefaultRequestHeaders.Range = new RangeHeaderValue(file.Progress, file.Size - 1);
							}
							await DownloadUsingClient(client);
							return;
						}
						catch (Exception)
						{
							await Task.Delay(TimeSpan.FromSeconds(1.0));
						}
					}
					throw new TimeoutException();
				}
				await DownloadUsingClient(client);
			}

			private async Task DownloadUsingClient(HttpClient client)
			{
				_ = 2;
				try
				{
					using HttpResponseMessage response = await client.GetAsync(file.Url, HttpCompletionOption.ResponseHeadersRead);
					response.EnsureSuccessStatusCode();
					using Stream contentStream = await response.Content.ReadAsStreamAsync();
					_ = 2;
					while (true)
					{
						try
						{
							using (CancellationTokenSource cancellationTokenSource = new CancellationTokenSource(5000))
							{
								int num = await contentStream.ReadAsync(buffer, 0, buffer.Length, cancellationTokenSource.Token);
								LastSuccessfulRead = DateTime.Now;
								if (num <= 0)
								{
									downloadedBytes.OnCompleted();
									break;
								}
								file.Progress += num;
								downloadedBytes.OnNext(buffer.Take(num).ToArray());
							}
							continue;
						}
						catch (TimeoutException)
						{
							client.CancelPendingRequests();
							throw;
						}
					}
				}
				catch (ObjectDisposedException ex2)
				{
					iFit.Logger.Log.Error("DeviceAdmin", "Something was already disposed in FileDownloader - " + ex2.Message + " - " + ex2.StackTrace);
				}
			}

			public void Dispose()
			{
				downloadedBytes?.Dispose();
			}
		}

		public class FileToDownload : IFileToDownload
		{
			public string Name { get; set; }

			public string Url { get; set; }

			public Uri Uri { get; set; }

			public long? Size { get; set; }

			public long Progress { get; set; }

			public IFile DestinationFile { get; set; }

			public FileToDownload(string url)
			{
				Url = url;
				Uri = new Uri(url);
				Size = 0L;
				Name = Path.GetFileName(Uri.LocalPath);
			}
		}

		public class DownloadUpdate : IDownloadUpdate
		{
			public int TotalPercentComplete => (int)Math.Round((double)TotalFilesProgress / (double)TotalFilesSize * 100.0);

			public int FilesDownloaded { get; set; }

			public long TotalFilesSize { get; set; }

			public long TotalFilesProgress { get; set; }

			public string DisplayString { get; set; }

			public List<IFileToDownload> Files { get; } = new List<IFileToDownload>();
		}

		private readonly Subject<IDownloadUpdate> whenProgress = new Subject<IDownloadUpdate>();

		private readonly IFolder targetDir;

		private readonly IFolder TempDownloadDirectory = FileSystem.Current.LocalStorage;

		private readonly DownloadUpdate update = new DownloadUpdate();

		public IObservable<IDownloadUpdate> WhenProgress => whenProgress;

		public FileDownloader(IFolder targetDir)
		{
			this.targetDir = targetDir;
		}

		public async Task<IDownloadUpdate> DownloadFiles(List<string> urls)
		{
			await Task.Run(async delegate
			{
				await SetupDownloads(urls);
				foreach (IFileToDownload file in update.Files)
				{
					await DownloadFile(file);
				}
			});
			return update;
		}

		private async Task SetupDownloads(List<string> urls)
		{
			update.TotalFilesSize = 0L;
			urls.DoForEach(delegate(string x)
			{
				update.Files.Add(new FileToDownload(x));
			});
			foreach (IFileToDownload file in update.Files)
			{
				await GetSize(file);
				if (file.Size.HasValue)
				{
					update.TotalFilesSize += file.Size.Value;
				}
			}
			whenProgress.OnNext(update);
		}

		private async Task GetSize(IFileToDownload file)
		{
			using HttpClient httpClient = new HttpClient();
			HttpResponseMessage httpInitialResponse = await httpClient.GetAsync(file.Url, HttpCompletionOption.ResponseHeadersRead);
			if (!httpInitialResponse.IsSuccessStatusCode)
			{
				throw new ConnectivityException($"HTTP response {(int)httpInitialResponse.StatusCode} ({httpInitialResponse.ReasonPhrase}), failed to get size of file {file.Url}");
			}
			using (await httpInitialResponse.Content.ReadAsStreamAsync())
			{
				file.Size = httpInitialResponse.Content.Headers.ContentLength;
			}
		}

		private async Task DownloadFile(IFileToDownload file)
		{
			file.DestinationFile = await TempDownloadDirectory.CreateFileAsync(file.Name + ".tmp", CreationCollisionOption.ReplaceExisting);
			FileStream fileStream = await file.DestinationFile.OpenAsync(FileAccess.ReadWrite);
			try
			{
				using Downloader downloader = new Downloader(file);
				downloader.DownloadedBytes.Subscribe(delegate(byte[] bytes)
				{
					fileStream?.Write(bytes, 0, bytes.Length);
					update.TotalFilesProgress += bytes.Length;
					whenProgress.OnNext(update);
				});
				await downloader.Download();
			}
			finally
			{
				if (fileStream != null)
				{
					((IDisposable)fileStream).Dispose();
				}
			}
			DownloadUpdate downloadUpdate = update;
			int filesDownloaded = downloadUpdate.FilesDownloaded + 1;
			downloadUpdate.FilesDownloaded = filesDownloaded;
			whenProgress.OnNext(update);
			await file.DestinationFile.MoveAsync(targetDir.Path + "/" + file.Name);
		}
	}
	public static class FileSizeFormatter
	{
		private const long bytesInKb = 1024L;

		private const long bytesInMb = 1048576L;

		private const long bytesInGb = 1073741824L;

		public static string FormatDownloadProgress(long bytesReceived, long bytesTotal)
		{
			string text = FormatToSize(bytesReceived);
			string text2 = FormatToSize(bytesTotal);
			return text + " of " + text2;
		}

		public static string FormatToSize(double bytes)
		{
			if (bytes < 1048576.0)
			{
				return Math.Round(bytes / 1024.0, 1) + "KB";
			}
			if (bytes < 1073741824.0)
			{
				return Math.Round(bytes / 1048576.0, 1) + "MB";
			}
			return Math.Round(bytes / 1073741824.0, 1) + "GB";
		}

		public static string FormatToSize(long bytes)
		{
			return FormatToSize((double)bytes);
		}
	}
	public static class Gzip
	{
		public static byte[] Compress(string content)
		{
			using MemoryStream memoryStream = new MemoryStream();
			using (GZipStream destination = new GZipStream(memoryStream, CompressionMode.Compress))
			{
				using MemoryStream memoryStream2 = new MemoryStream(Encoding.UTF8.GetBytes(content));
				memoryStream2.CopyTo(destination);
			}
			return memoryStream.ToArray();
		}

		public static string Decompress(byte[] content)
		{
			using MemoryStream stream = new MemoryStream(content);
			using GZipStream gZipStream = new GZipStream(stream, CompressionMode.Decompress);
			using MemoryStream memoryStream = new MemoryStream();
			gZipStream.CopyTo(memoryStream);
			byte[] array = memoryStream.ToArray();
			return Encoding.UTF8.GetString(array, 0, array.Length);
		}
	}
	public static class HexColorCache
	{
		private static readonly Dictionary<string, SplatColor> Cache = new Dictionary<string, SplatColor>();

		public static int CacheSize => Cache.Count;

		public static void ClearCache()
		{
			Cache.Clear();
		}

		public static SplatColor Get(string hexString)
		{
			hexString = NormalizeHexString(hexString);
			if (Cache.ContainsKey(hexString))
			{
				return Cache[hexString];
			}
			SplatColor splatColor = GenerateFromHex(hexString);
			Cache.Add(hexString, splatColor);
			return splatColor;
		}

		private static SplatColor GenerateFromHex(string hexString)
		{
			if (string.IsNullOrWhiteSpace(hexString))
			{
				throw new ArgumentNullException("hexString");
			}
			byte red = Convert.ToByte(hexString.Substring(0, 2), 16);
			byte green = Convert.ToByte(hexString.Substring(2, 2), 16);
			byte blue = Convert.ToByte(hexString.Substring(4, 2), 16);
			byte alpha = Convert.ToByte(hexString.Substring(6, 2), 16);
			return SplatColor.FromArgb(alpha, red, green, blue);
		}

		private static string NormalizeHexString(string hexString)
		{
			if (string.IsNullOrWhiteSpace(hexString))
			{
				throw new ArgumentNullException("hexString");
			}
			string text = hexString.Trim().ToUpper();
			if (text[0] == '#')
			{
				text = text.Substring(1, text.Length - 1);
			}
			if (text.Length == 2)
			{
				text = string.Format("{0}{0}{0}", text);
			}
			if (text.Length == 6)
			{
				text += "FF";
			}
			if (!Regex.IsMatch(text, "^([0123456789ABCDEF]{8})$"))
			{
				throw new HexColorParsingException("Invalid color hex string.");
			}
			return text;
		}
	}
	public class HexColorParsingException : Exception
	{
		public HexColorParsingException()
		{
		}

		public HexColorParsingException(string message)
			: base(message)
		{
		}
	}
	public static class HumanNameConverter
	{
		public static string ConvertFirstLastNameToFullName(string firstName, string lastName)
		{
			string fullName = (firstName ?? string.Empty).Trim() + " " + (lastName ?? string.Empty).Trim();
			Tuple<string, string> tuple = ConvertFullNameToFirstLastName(fullName);
			return (tuple.Item1 + " " + tuple.Item2).Trim();
		}

		public static Tuple<string, string> ConvertFullNameToFirstLastName(string fullName)
		{
			string[] array = Regex.Replace(fullName.Trim(), "\\s+", " ").Split(' ');
			string item = ((array.Length >= 1) ? array[0] : string.Empty);
			string item2 = ((array.Length >= 2) ? string.Join(string.Empty, array.Skip(1)) : string.Empty);
			return new Tuple<string, string>(item, item2);
		}

		public static bool IsValidHumanName(string fullName)
		{
			if (!string.IsNullOrWhiteSpace(fullName))
			{
				NameValidator nameValidator = NameValidators.DefaultNameValidator;
				if (Mvx.TryResolve<ICulture>(out var service))
				{
					nameValidator = service.GetNameValidator();
				}
				Regex regex = nameValidator.Validator;
				int firstNameMaxLength = nameValidator.FirstNameMaxLength;
				int lastNameLength = nameValidator.LastNameLength;
				if (Regex.Split(fullName, " ").Count((string name) => !regex.IsMatch(name.Trim())) > 0)
				{
					return false;
				}
				Tuple<string, string> tuple = ConvertFullNameToFirstLastName(fullName);
				if (tuple.Item1.Length <= firstNameMaxLength && tuple.Item2.Length <= lastNameLength)
				{
					return true;
				}
			}
			return false;
		}

		public static bool IsValidFirstLast(string firstName, string lastName)
		{
			if (!string.IsNullOrWhiteSpace(firstName) && !string.IsNullOrWhiteSpace(lastName))
			{
				return IsValidHumanName(ConvertFirstLastNameToFullName(firstName, lastName));
			}
			return false;
		}
	}
