	public static class ImageDownloader
	{
		public static async Task<byte[]> DownloadImage(string uri, DateTimeOffset? expiration = null, IBlobCache cache = null, HttpClient client = null)
		{
			if (!Uri.TryCreate(uri, UriKind.Absolute, out var imageUri))
			{
				throw new ArgumentException("Invalid Uri.", "uri");
			}
			if (cache == null)
			{
				IBlobCacheService blobCacheService = Mvx.Resolve<IBlobCacheService>();
				cache = blobCacheService.LocalMachine;
			}
			if (client == null)
			{
				client = Mvx.Resolve<IIfitApiService>().Client;
			}
			DateTimeOffset value = ((!expiration.HasValue) ? DateTimeOffset.Now.AddDays(7.0) : expiration.Value);
			return await cache.GetOrFetchObject(imageUri.AbsoluteUri, fetch, value);
			async Task<byte[]> fetch()
			{
				return await Fetch(client, imageUri.AbsoluteUri);
			}
		}

		private static async Task<byte[]> Fetch(HttpClient client, string url)
		{
			return await client.GetByteArrayAsync(url);
		}
	}
	public static class ImageUtil
	{
		public static async Task<byte[]> DownloadImageFromUrl(IBlobCache cache, string imgUrl, bool force = false, CancellationToken token = default(CancellationToken))
		{
			if (force)
			{
				await cache.InvalidateObject<byte[]>(imgUrl);
			}
			return await cache.GetOrFetchObject(imgUrl, fetch, DateTimeOffset.Now.AddDays(14.0));
			async Task<byte[]> fetch()
			{
				return await FetchImg(imgUrl, token);
			}
		}

		private static async Task<byte[]> FetchImg(string imgUrl, CancellationToken token)
		{
			using HttpClient client = new HttpClient();
			token.ThrowIfCancellationRequested();
			return await client.GetByteArrayAsync(imgUrl);
		}

		public static bool IsResizable(string url)
		{
			return url.Contains("img.ifit.com/workouts/");
		}

		public static string GetResizedUrl(string url, int width, int height)
		{
			if (!IsResizable(url))
			{
				return url;
			}
			string arg = url.Substring(url.IndexOf("workouts/"));
			return $"https://img.ifit.com/{width}x{height}/{arg}";
		}
	}
	public class JsonBuilder
	{
		private IList<Tuple<string, object>> elements = new List<Tuple<string, object>>();

		public void AddString(string key, string value)
		{
			AddElement(key, "\"" + value + "\"");
		}

		public void AddInt(string key, int value)
		{
			AddElement(key, value);
		}

		public void AddDouble(string key, double value)
		{
			AddElement(key, value);
		}

		public void AddBool(string key, bool value)
		{
			AddElement(key, value.ToString().ToLower());
		}

		private void AddElement(string key, object value)
		{
			elements.Add(new Tuple<string, object>(key, value));
		}

		public void RemoveElement(string key)
		{
			Tuple<string, object> tuple = elements.FirstOrDefault((Tuple<string, object> x) => x.Item1 == key);
			if (tuple != null)
			{
				elements.Remove(tuple);
			}
		}

		public override string ToString()
		{
			IEnumerable<string> values = elements.Select((Tuple<string, object> pair) => string.Format(CultureInfo.InvariantCulture, "\"{0}\":{1}", pair.Item1, pair.Item2));
			return "{" + string.Join(",", values) + "}";
		}
	}
	public static class JsonDownloadUtil
	{
		private static readonly JsonSerializer defaultSerializer = new JsonSerializer
		{
			ContractResolver = new Shire.Core.Api.SnakeCasePropertyNamesContractResolver(),
			NullValueHandling = NullValueHandling.Ignore
		};

		public static async Task<TResult> DownloadAndParseJson<TResult>(string url, JsonSerializer serializer = null, CancellationToken token = default(CancellationToken))
		{
			return await Task.Run(delegate
			{
				if (string.IsNullOrWhiteSpace(url))
				{
					throw new ArgumentNullException("url");
				}
				using HttpClient httpClient = new HttpClient(new NativeMessageHandler());
				using Stream stream = httpClient.GetStreamAsync(url).Result;
				using StreamReader reader = new StreamReader(stream);
				using JsonReader reader2 = new JsonTextReader(reader);
				token.ThrowIfCancellationRequested();
				serializer = serializer ?? defaultSerializer;
				return serializer.Deserialize<TResult>(reader2);
			}, token);
		}
	}
