	[JsonConverter(typeof(MetricStatListSerializer))]
	public class MetricStatList
	{
		private double _maxTimestamp;

		private double _maxValue;

		protected internal LinkedList<StatDataPoint> stats = new LinkedList<StatDataPoint>();

		private LinkedListNode<StatDataPoint> trailingNode;

		protected double valueSum;

		protected double valueTimeProductSum;

		protected bool removeZerosFromAverages;

		protected int nonZeroCount;

		protected double nonZeroTotalTime;

		private readonly SemaphoreSlim threadSafe = new SemaphoreSlim(1);

		public int Count => stats?.Count ?? 0;

		public StatDataPoint First
		{
			get
			{
				if (stats == null || stats.Count == 0)
				{
					return new StatDataPoint(0.0, 0.0);
				}
				return stats.First.Value;
			}
		}

		public StatDataPoint Last
		{
			get
			{
				if (stats == null || stats.Count == 0)
				{
					return new StatDataPoint(0.0, 0.0);
				}
				return stats.Last.Value;
			}
		}

		public double MaxTimestamp => _maxTimestamp;

		public double MaxValue => _maxValue;

		public MetricStatList(bool removeZeros = false)
		{
			removeZerosFromAverages = removeZeros;
		}

		public void RecordStat(double timestamp, double value)
		{
			if (removeZerosFromAverages && !value.AlmostEqual(0.0))
			{
				nonZeroCount++;
			}
			threadSafe.Wait();
			try
			{
				valueSum += value;
				UpdateMaximumValues(timestamp, value);
				if (stats.Count == 0)
				{
					stats.AddFirst(new StatDataPoint(timestamp, value));
					return;
				}
				StatDataPoint value2 = stats.Last.Value;
				if (timestamp >= value2.Timestamp)
				{
					double num = timestamp - value2.Timestamp;
					valueTimeProductSum += num * value2.Value;
					stats.AddLast(new StatDataPoint(timestamp, value));
					if (removeZerosFromAverages && !value2.Value.AlmostEqual(0.0))
					{
						nonZeroTotalTime += num;
					}
					return;
				}
				if (stats.Count == 1)
				{
					stats.AddFirst(new StatDataPoint(timestamp, value));
					double num = value2.Timestamp - timestamp;
					valueTimeProductSum += num * value;
					if (removeZerosFromAverages && !value.AlmostEqual(0.0))
					{
						nonZeroTotalTime += num;
					}
					return;
				}
				LinkedListNode<StatDataPoint> linkedListNode = stats.Last;
				while (linkedListNode.Previous != null && linkedListNode.Value.Timestamp >= timestamp)
				{
					LinkedListNode<StatDataPoint> linkedListNode2 = linkedListNode;
					linkedListNode = linkedListNode.Previous;
					double num = linkedListNode2.Value.Timestamp - linkedListNode.Value.Timestamp;
					valueTimeProductSum -= num * linkedListNode.Value.Value;
					if (removeZerosFromAverages && !linkedListNode.Value.Value.AlmostEqual(0.0))
					{
						nonZeroTotalTime -= num;
					}
				}
				if (linkedListNode.Value.Timestamp > timestamp)
				{
					stats.AddBefore(linkedListNode, new StatDataPoint(timestamp, value));
					linkedListNode = linkedListNode.Previous;
				}
				else
				{
					stats.AddAfter(linkedListNode, new StatDataPoint(timestamp, value));
				}
				while (linkedListNode != null)
				{
					LinkedListNode<StatDataPoint> next = linkedListNode.Next;
					if (next == null)
					{
						break;
					}
					double num = next.Value.Timestamp - linkedListNode.Value.Timestamp;
					valueTimeProductSum += num * linkedListNode.Value.Value;
					if (removeZerosFromAverages && !linkedListNode.Value.Value.AlmostEqual(0.0))
					{
						nonZeroTotalTime += num;
					}
					linkedListNode = linkedListNode.Next;
				}
			}
			finally
			{
				threadSafe.Release();
			}
		}

		public async Task PrependStat(double timestamp, double value)
		{
			if (removeZerosFromAverages && !value.AlmostEqual(0.0))
			{
				nonZeroCount++;
			}
			await threadSafe.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				valueSum += value;
				if (stats.Count >= 1)
				{
					StatDataPoint value2 = stats.First.Value;
					double num = value2.Timestamp - timestamp;
					valueTimeProductSum += num * value;
				}
				stats.AddFirst(new StatDataPoint(timestamp, value));
			}
			finally
			{
				threadSafe.Release();
			}
		}

		public void Clear()
		{
			stats.Clear();
			valueSum = 0.0;
			valueTimeProductSum = 0.0;
			nonZeroCount = 0;
			nonZeroTotalTime = 0.0;
			_maxValue = 0.0;
			_maxTimestamp = 0.0;
		}

		public async Task CloneToStatList(MetricStatList target)
		{
			await threadSafe.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				target.valueSum = valueSum;
				target.valueTimeProductSum = valueTimeProductSum;
				target.stats = new LinkedList<StatDataPoint>(stats);
				target.removeZerosFromAverages = removeZerosFromAverages;
				target.nonZeroCount = nonZeroCount;
				target.nonZeroTotalTime = nonZeroTotalTime;
				target._maxValue = _maxValue;
				target._maxTimestamp = _maxTimestamp;
			}
			finally
			{
				threadSafe.Release();
			}
		}

		public async Task<double> GetAverage(AverageType type, double smoothingInterval = 0.0, double currentRunningTime = 0.0)
		{
			await threadSafe.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				switch (type)
				{
				case AverageType.Standard:
					return GetStandardAverage();
				case AverageType.Weighted:
					return GetWeightedAverage(currentRunningTime);
				case AverageType.Interpolated:
					return 0.0;
				}
			}
			finally
			{
				threadSafe.Release();
			}
			return 0.0;
		}

		public async Task<StatDataPoint> LastStatAtTimeStamp(double timestamp)
		{
			await threadSafe.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				if (trailingNode == null)
				{
					trailingNode = stats.First;
				}
				while (trailingNode?.Next != null && trailingNode.Next.Value.Timestamp <= timestamp)
				{
					trailingNode = trailingNode.Next;
				}
				iFit.Logger.Log.Debug("Charting", $"Requested stat at timestamp {timestamp}, returning {trailingNode?.Value}");
				return trailingNode?.Value;
			}
			finally
			{
				threadSafe.Release();
			}
		}

		private double GetStandardAverage()
		{
			return valueSum / (double)AveragesCount();
		}

		private double GetWeightedAverage(double currentRunningTime = 0.0)
		{
			switch (AveragesCount())
			{
			case 0:
				return 0.0;
			case 1:
				return stats.First.Value.Value;
			default:
			{
				double num = 0.0;
				double num2 = valueTimeProductSum;
				StatDataPoint value = stats.First.Value;
				StatDataPoint value2 = stats.Last.Value;
				if (currentRunningTime > value2.Timestamp)
				{
					num = ((!removeZerosFromAverages || value2.Value.AlmostEqual(0.0)) ? (currentRunningTime - value.Timestamp) : (nonZeroTotalTime + currentRunningTime - value2.Timestamp));
					num2 += (currentRunningTime - value2.Timestamp) * value2.Value;
				}
				else
				{
					num = (removeZerosFromAverages ? nonZeroTotalTime : (value2.Timestamp - value.Timestamp));
				}
				if (!num.AlmostEqual(0.0))
				{
					return num2 / num;
				}
				return 0.0;
			}
			}
		}

		private double GetInterpolatedAverage(double timeInterval = 0.0)
		{
			return GetSmoothedAverage(timeInterval, interpolate: true);
		}

		private double GetSmoothedAverage(double timeInterval = 0.0, bool interpolate = false)
		{
			switch (stats.Count)
			{
			case 0:
				return 0.0;
			case 1:
				return stats.First.Value.Value;
			default:
			{
				LinearSpline linearSpline = null;
				if (interpolate)
				{
					List<double> list = stats.Select((StatDataPoint x) => x.Timestamp).ToList();
					List<double> list2 = stats.Select((StatDataPoint x) => x.Value).ToList();
					linearSpline = LinearSpline.InterpolateSorted(list.ToArray(), list2.ToArray());
				}
				LinkedListNode<StatDataPoint> first = stats.First;
				LinkedListNode<StatDataPoint> last = stats.Last;
				LinkedListNode<StatDataPoint> linkedListNode = first;
				double num = first.Value.Timestamp;
				double num2 = 0.0;
				int num3 = 0;
				while (true)
				{
					LinkedListNode<StatDataPoint> next = linkedListNode.Next;
					if (next != null && next.Value.Timestamp < num)
					{
						linkedListNode = next;
						continue;
					}
					num2 = ((!interpolate) ? (num2 + linkedListNode.Value.Value) : (num2 + linearSpline.Interpolate(linkedListNode.Value.Timestamp)));
					num3++;
					linkedListNode = next;
					num += timeInterval;
					if (linkedListNode == null)
					{
						break;
					}
				}
				return num2 / (double)num3;
			}
			}
		}

		public async Task<List<StatDataPoint>> GetStatList()
		{
			await threadSafe.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				List<StatDataPoint> list = new List<StatDataPoint>(stats.Count);
				foreach (StatDataPoint stat in stats)
				{
					list.Add(stat);
				}
				return list;
			}
			finally
			{
				threadSafe.Release();
			}
		}

		public IEnumerator<StatDataPoint> GetEnumerator()
		{
			return stats.GetEnumerator();
		}

		private void UpdateMaximumValues(double timestamp, double value)
		{
			if (timestamp > _maxTimestamp)
			{
				_maxTimestamp = timestamp;
			}
			if (value > _maxValue)
			{
				_maxValue = value;
			}
		}

		private int AveragesCount()
		{
			if (!removeZerosFromAverages)
			{
				return Count;
			}
			return nonZeroCount;
		}
	}
	public static class MetricStatListExtensions
	{
		public static bool IsNullOrEmpty(this MetricStatList metricStatList)
		{
			if (metricStatList == null || metricStatList.Count == 0)
			{
				return true;
			}
			return false;
		}
	}
	public class MetricStatListSerializer : JsonConverter
	{
		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			MetricStatList metricStatList = value as MetricStatList;
			writer.WriteStartObject();
			writer.WritePropertyName("$stats");
			writer.WriteStartArray();
			if (metricStatList != null)
			{
				foreach (StatDataPoint stat in metricStatList.stats)
				{
					writer.WriteStartObject();
					writer.WritePropertyName("$Timestamp");
					serializer.Serialize(writer, stat.Timestamp);
					writer.WritePropertyName("$Value");
					serializer.Serialize(writer, stat.Value);
					writer.WriteEndObject();
				}
			}
			writer.WriteEndArray();
			writer.WriteEndObject();
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			JObject jObject = JObject.Load(reader);
			MetricStatList metricStatList = new MetricStatList();
			JArray jArray = jObject["$stats"].Value<JArray>();
			foreach (JToken item in jArray)
			{
				metricStatList.RecordStat(item["$Timestamp"].Value<double>(), item["$Value"].Value<double>());
			}
			return metricStatList;
		}

		public override bool CanConvert(Type objectType)
		{
			return typeof(MetricStatList).IsAssignableFrom(objectType);
		}
	}
