			Task item = MpsChanges.CloneToStatList(stats.MpsChanges);
			Task item2 = KphChanges.CloneToStatList(stats.KphChanges);
			Task item3 = ActualKphChanges.CloneToStatList(stats.ActualKphChanges);
			Task item4 = GradeChanges.CloneToStatList(stats.GradeChanges);
			Task item5 = DistanceChanges.CloneToStatList(stats.DistanceChanges);
			Task item6 = TimeSeconds.CloneToStatList(stats.TimeSeconds);
			Task item7 = CalorieChanges.CloneToStatList(stats.CalorieChanges);
			Task item8 = WattChanges.CloneToStatList(stats.WattChanges);
			Task item9 = ResistanceChanges.CloneToStatList(stats.ResistanceChanges);
			Task item10 = GearChanges.CloneToStatList(stats.GearChanges);
			Task item11 = RpmChanges.CloneToStatList(stats.RpmChanges);
			Task item12 = VerticalMetersGainChanges.CloneToStatList(stats.VerticalMetersGainChanges);
			Task item13 = VerticalMetersNetChanges.CloneToStatList(stats.VerticalMetersNetChanges);
			Task item14 = PulseChanges.CloneToStatList(stats.PulseChanges);
			Task item15 = StrokeChanges.CloneToStatList(stats.StrokeChanges);
			Task item16 = StrokePerMinChanges.CloneToStatList(stats.StrokePerMinChanges);
			Task item17 = FiveHundredSplitChanges.CloneToStatList(stats.FiveHundredSplitChanges);
			Task item18 = FiveHundredSplitDecimalChanges.CloneToStatList(stats.FiveHundredSplitDecimalChanges);
			Task item19 = AvgFiveHundredSplitChanges.CloneToStatList(stats.AvgFiveHundredSplitChanges);
			Task item20 = XScore.CloneToStatList(stats.XScore);
			List<Task> tasks = new List<Task>
			{
				item, item2, item3, item4, item5, item6, item7, item8, item9, item10,
				item11, item12, item13, item14, item15, item16, item17, item18, item19, item20
			};
			await Task.WhenAll(tasks).ConfigureAwait(continueOnCapturedContext: false);
			return stats;
		}

