		public double GetAverageMps()
		{
			int count = DistanceChanges.Count;
			if (count < 2)
			{
				return 0.0;
			}
			StatDataPoint value = DistanceChanges.stats.Last.Value;
			if (value.Value.AlmostEqual(0.0))
			{
				value = DistanceChanges.stats.Last.Previous.Value;
			}
			double value2 = value.Value;
			double timestamp = value.Timestamp;
			return Math.Max(value2 / timestamp, 0.0);
		}

		public async Task<int> GetMaxHeartRate()
		{
			return (await PulseChanges.GetStatList()).Select((StatDataPoint x) => (int)x.Value).ToList().FindMaximumByHeartRateMethod();
		}

