		}

		public static async Task<double> GetAverage(AverageType type, MetricStatList source, double timeInterval = 1.0, double currentRunningTime = 0.0)
		{
			return type switch
			{
				AverageType.Interpolated => await source.GetAverage(AverageType.Interpolated, timeInterval, currentRunningTime), 
				AverageType.Standard => await source.GetAverage(AverageType.Standard), 
				_ => await source.GetAverage(AverageType.Weighted, 0.0, currentRunningTime), 
			};
		}
	}
	public static class MetricStatsToActivityLog
	{
		public static readonly string PulseString = "pulse";

		public static readonly string CaloriesString = "calories";

		public static readonly string ElevationString = "verticalNet";

		public static readonly string InclineString = "grade";

		public static readonly string DistanceString = "distance";

		public static readonly string SpeedString = "mps";

		public static readonly string ResistanceString = "resistance";

		public static readonly string RPMString = "rpm";

		public static readonly string WattsString = "watts";

		public static readonly string RepsString = "stroke";

		public static readonly string SPMString = "spm";

		public static readonly string SplitsString = "splits";

		public static readonly string XScoreString = "xscore";

		public static async Task<ActivityLog> FromConsole(MetricStats stats, IConsoleInfo console, string userId, int softwareNumber, string workoutId = null, string programId = null, string challengeId = null)
		{
			bool flag = stats?.StatLists.Any((MetricStatList s) => s.Count > 0) ?? false;
			ActivityLog log = new ActivityLog
			{
				Duration = (flag ? ((long)(stats.StatLists.Where((MetricStatList x) => x.Count > 0).Max((MetricStatList x) => x.MaxTimestamp) * 1000.0)) : 1)
			};
			log.End = DateTime.UtcNow;
			log.Start = log.End - TimeSpan.FromMilliseconds(log.Duration);
			log.Type = LogType(console);
			log.SoftwareNumber = softwareNumber;
			log.UserId = userId;
			log.WorkoutId = workoutId;
			log.ProgramId = programId;
			log.ChallengeId = challengeId;
			log.MachineId = console?.BrainboardSerialNumber;
			ActivityLog activityLog = log;
			activityLog.Stats = await CreateStatGroup(stats, log.Duration, console).ConfigureAwait(continueOnCapturedContext: false);
			return log;
		}

		private static async Task<ActivityLog.StatGroup> CreateStatGroup(MetricStats stats, long duration, IConsoleInfo console)
		{
			if (stats == null)
			{
				return new ActivityLog.StatGroup();
			}
			Task<List<ActivityLog.StatGroup.Stat>> BpmTask = DataPointToStats(stats.PulseChanges, duration, PulseString);
			Task<List<ActivityLog.StatGroup.Stat>> CaloriesTask = DataPointToStats(stats.CalorieChanges, duration, CaloriesString, sequential: true, needsToStartWithZero: true);
			Task<List<ActivityLog.StatGroup.Stat>> ElevationTask = DataPointToStats(stats.VerticalMetersNetChanges, duration, ElevationString, sequential: false, needsToStartWithZero: true);
			Task<List<ActivityLog.StatGroup.Stat>> InclineTask = DataPointToStats(stats.GradeChanges, duration, InclineString);
			Task<List<ActivityLog.StatGroup.Stat>> MetersTask = DataPointToStats(stats.DistanceChanges, duration, DistanceString, sequential: true, needsToStartWithZero: true);
			Task<List<ActivityLog.StatGroup.Stat>> MpsTask = DataPointToStats(stats.MpsChanges, duration, SpeedString);
			Task<List<ActivityLog.StatGroup.Stat>> ResistanceTask = ResistanceDataPointToStats(stats, duration, console);
			Task<List<ActivityLog.StatGroup.Stat>> RpmTask = DataPointToStats(stats.RpmChanges, duration, RPMString);
			Task<List<ActivityLog.StatGroup.Stat>> WattsTask = DataPointToStats(stats.WattChanges, duration, WattsString);
			Task<List<ActivityLog.StatGroup.Stat>> RepsTask = DataPointToStats(stats.StrokeChanges, duration, RepsString);
			Task<List<ActivityLog.StatGroup.Stat>> SpmTask = DataPointToStats(stats.StrokePerMinChanges, duration, SPMString);
			Task<List<ActivityLog.StatGroup.Stat>> FiveHundredSplitTask = DataPointToStats(stats.FiveHundredSplitChanges, duration, SplitsString);
			Task<List<ActivityLog.StatGroup.Stat>> AverageFiveHundredSplitTask = DataPointToStats(stats.AvgFiveHundredSplitChanges, duration, SplitsString);
			Task<List<ActivityLog.StatGroup.Stat>> XScoreTask = DataPointToStats(stats.XScore, duration, XScoreString, sequential: true, needsToStartWithZero: true);
			List<Task<List<ActivityLog.StatGroup.Stat>>> tasks = new List<Task<List<ActivityLog.StatGroup.Stat>>>
			{
				BpmTask, CaloriesTask, ElevationTask, InclineTask, MetersTask, MpsTask, ResistanceTask, RpmTask, WattsTask, RepsTask,
				SpmTask, FiveHundredSplitTask, AverageFiveHundredSplitTask, XScoreTask
			};
			await Task.WhenAll(tasks).ConfigureAwait(continueOnCapturedContext: false);
			return new ActivityLog.StatGroup
			{
				Bpm = ((BpmTask.Status == TaskStatus.RanToCompletion) ? BpmTask.Result : null),
				Calories = ((CaloriesTask.Status == TaskStatus.RanToCompletion) ? CaloriesTask.Result : null),
				Elevation = ((ElevationTask.Status == TaskStatus.RanToCompletion) ? ElevationTask.Result : null),
				Incline = ((InclineTask.Status == TaskStatus.RanToCompletion) ? InclineTask.Result : null),
				Meters = ((MetersTask.Status == TaskStatus.RanToCompletion) ? MetersTask.Result : null),
				Mps = ((MpsTask.Status == TaskStatus.RanToCompletion) ? MpsTask.Result : null),
				Resistance = ((ResistanceTask.Status == TaskStatus.RanToCompletion) ? ResistanceTask.Result : null),
				Rpm = ((RpmTask.Status == TaskStatus.RanToCompletion) ? RpmTask.Result : null),
				Watts = ((WattsTask.Status == TaskStatus.RanToCompletion) ? WattsTask.Result : null),
				Reps = ((RepsTask.Status == TaskStatus.RanToCompletion) ? RepsTask.Result : null),
				Spm = ((SpmTask.Status == TaskStatus.RanToCompletion) ? SpmTask.Result : null),
				FiveHundredSplit = ((FiveHundredSplitTask.Status == TaskStatus.RanToCompletion) ? FiveHundredSplitTask.Result : null),
				AverageFiveHundredSplit = ((AverageFiveHundredSplitTask.Status == TaskStatus.RanToCompletion) ? AverageFiveHundredSplitTask.Result : null),
				XScore = ((XScoreTask.Status == TaskStatus.RanToCompletion) ? XScoreTask.Result : null)
			};
		}

		private static async Task<List<ActivityLog.StatGroup.Stat>> ResistanceDataPointToStats(MetricStats stats, long duration, IConsoleInfo console)
		{
			MetricStatList statList = stats.ResistanceChanges;
			if (console != null && console.MachineType == ConsoleType.SpinBike)
			{
				statList = stats.GearChanges;
			}
			return await DataPointToStats(statList, duration, ResistanceString);
		}

		private static async Task<List<ActivityLog.StatGroup.Stat>> DataPointToStats(MetricStatList statList, long duration, string statName, bool sequential = false, bool needsToStartWithZero = false)
		{
			iFit.Logger.Log.Trace("STATS", $"TYPE - {statName}\t\tDURATION - {duration}");
			List<StatDataPoint> list = await statList.GetStatList().ConfigureAwait(continueOnCapturedContext: false);
			if (list == null || list.Count < 2)
			{
				if (list != null && list.Count == 1 && !list.First().Value.AlmostEqual(0.0))
				{
					iFit.Logger.Log.Trace("Workout", "Short Source of Type - " + statName + " - from console workout");
					return new List<ActivityLog.StatGroup.Stat>
					{
						new ActivityLog.StatGroup.Stat(0L, list.First().Value),
						new ActivityLog.StatGroup.Stat(duration, list.First().Value)
					};
				}
				return null;
			}
			iFit.Logger.Log.Trace("STATS", $"Last Stat Time - {list.Last().Timestamp}\t\tLastStat Value - {list.Last().Value}");
			List<ActivityLog.StatGroup.Stat> list2;
			try
			{
				list2 = (from x in (from x in list
						select new ActivityLog.StatGroup.Stat((long)(x.Timestamp * 1000.0), Math.Round(x.Value, 3)) into x
						where x.Offset <= duration
						orderby x.Value descending
						select x).DistinctBy((ActivityLog.StatGroup.Stat x) => x.Offset)
					orderby x.Value
					orderby x.Offset
					select x).ToList();
			}
			catch (InvalidOperationException exception)
			{
				iFit.Logger.Log.Error("Workout", "Exception processing post-workout stat " + statName, exception);
				throw;
			}
			if (list2.First().Offset != 0L)
			{
				list2.Insert(0, new ActivityLog.StatGroup.Stat(0L, 0.0));
			}
			else if (needsToStartWithZero)
			{
				list2.First().Value = 0.0;
			}
			if (list2.Count == 1)
			{
				list2.Add(new ActivityLog.StatGroup.Stat(duration, list2.Last().Value));
			}
			if (sequential)
			{
				try
				{
					list2 = list2.DistinctBy((ActivityLog.StatGroup.Stat x) => x.Value).ToList();
				}
				catch (InvalidOperationException exception2)
				{
					iFit.Logger.Log.Error("Workout", "Exception processing post-workout stat " + statName, exception2);
					throw;
				}
				list2.Last().Offset = duration;
			}
			else if (list2.Last().Offset < duration)
			{
				list2.Add(new ActivityLog.StatGroup.Stat(duration, list2.Last().Value));
			}
			return list2;
		}

		private static string LogType(IConsoleInfo console)
		{
			if (console == null)
			{
				return Workout.WorkoutType.Run.GetEnumMemberAttributeValue();
			}
			switch (console.MachineType)
			{
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return Workout.WorkoutType.Cycle.GetEnumMemberAttributeValue();
			case ConsoleType.Rower:
				return Workout.WorkoutType.Row.GetEnumMemberAttributeValue();
			case ConsoleType.Equipmentless:
			case ConsoleType.Mirror:
				return Workout.WorkoutType.Strength.GetEnumMemberAttributeValue();
			default:
				return Workout.WorkoutType.Run.GetEnumMemberAttributeValue();
			}
		}
	}
