				{ "image/x-quicktime", ".qti" },
				{ "message/rfc822", ".eml" },
				{ "text/html", ".html" },
				{ "text/plain", ".txt" },
				{ "text/scriptlet", ".wsc" },
				{ "text/xml", ".xml" },
				{ "video/3gpp", ".3gp" },
				{ "video/3gpp2", ".3gp2" },
				{ "video/mp4", ".mp4" },
				{ "video/mpeg", ".mpg" },
				{ "video/quicktime", ".mov" },
				{ "video/vnd.dlna.mpeg-tts", ".m2t" },
				{ "video/x-dv", ".dv" },
				{ "video/x-la-asf", ".lsf" },
				{ "video/x-ms-asf", ".asf" },
				{ "x-world/x-vrml", ".xof" }
			};
			List<KeyValuePair<string, string>> list = dictionary.ToList();
			foreach (KeyValuePair<string, string> item in list)
			{
				if (!dictionary.ContainsKey(item.Value))
				{
					dictionary.Add(item.Value, item.Key);
				}
			}
			return dictionary;
		}

		public static string GetMimeType(string extension)
		{
			if (extension == null)
			{
				throw new ArgumentNullException("extension");
			}
			if (!extension.StartsWith(".", StringComparison.Ordinal))
			{
				extension = "." + extension;
			}
			if (!mappings.Value.TryGetValue(extension, out var value))
			{
				return "application/octet-stream";
			}
			return value;
		}

		public static string GetExtension(string mimeType)
		{
			if (mimeType == null)
			{
				throw new ArgumentNullException("mimeType");
			}
			if (mimeType.StartsWith(".", StringComparison.Ordinal))
			{
				throw new ArgumentException("Requested mime type is not valid: " + mimeType);
			}
			if (mappings.Value.TryGetValue(mimeType, out var value))
			{
				return value;
			}
			throw new ArgumentException("Requested mime type is not registered: " + mimeType);
		}
	}
	public class NonGenericSubject
	{
