	public static class NullableExtensions
	{
		public static bool TryGetValue<T>(this T? value, out T result) where T : struct
		{
			if (value.HasValue)
			{
				result = value.Value;
				return true;
			}
			result = default(T);
			return false;
		}

		public static bool TryGetValue<T>(this T value, out T result) where T : class
		{
			if (value != null)
			{
				result = value;
				return true;
			}
			result = null;
			return false;
		}
	}
	public static class RowerEstimator
	{
		public static double CalculateEstimatedStrokeCount(double spm, double seconds)
		{
			return spm * seconds / 60.0;
		}

		public static double CalculateEstimatedDistance(double estimatedStrokeCount, double height)
		{
			return estimatedStrokeCount * 8.0 * height / 1.75;
		}

		public static double CalculateEstimatedDistance(double spm, double seconds, double height)
		{
			return CalculateEstimatedDistance(CalculateEstimatedStrokeCount(spm, seconds), height);
		}
	}
	public class StatDataPoint
	{
		[JsonProperty]
		private double _timestamp;

		[JsonProperty]
		private double _value;

		private const double EPSILON = 0.01;

		public double Timestamp => _timestamp;

		public double Value => _value;

		public StatDataPoint()
		{
		}

		public StatDataPoint(double timestamp, double value)
		{
			_timestamp = timestamp;
			_value = value;
		}

		public override bool Equals(object obj)
		{
			StatDataPoint statDataPoint = (StatDataPoint)obj;
			if (statDataPoint == null)
			{
				return false;
			}
			if (_timestamp.AlmostEqual(statDataPoint.Timestamp, 0.01))
			{
				return _value.AlmostEqual(statDataPoint.Value, 0.01);
			}
			return false;
		}

		public override int GetHashCode()
		{
			int num = (int)Math.Round(_timestamp);
			int num2 = (int)Math.Round(_value);
			return num >> 16 + num2;
		}

		public Tuple<double, double> ToTuple()
		{
			return new Tuple<double, double>(_timestamp, _value);
		}

		public override string ToString()
		{
			return $"[StatDataPoint => Timestamp={Timestamp} Value={Value}]";
		}
	}
	public static class TaskContinueWithException
	{
		private const string Tag = "FatalUnhandledThreadException";

		public static string FlattenException(Exception exception)
		{
			StringBuilder stringBuilder = new StringBuilder();
			while (exception != null)
			{
				stringBuilder.AppendLine(exception.Message);
				stringBuilder.AppendLine(exception.StackTrace);
				exception = exception.InnerException;
			}
			return stringBuilder.ToString();
		}

		public static void LogThreadException(Exception ex)
		{
			iFit.Logger.Log.Error("FatalUnhandledThreadException", FlattenException(ex));
		}

		public static void LogEx(Task t)
		{
			t.Exception.Handle(delegate(Exception ex)
			{
				LogThreadException(ex);
				return false;
			});
		}
	}
	public class ValidPresenterRequestHelper
	{
		private const int DefaultThresholdMillis = 500;

		private readonly TimeSpan threshold;

		private readonly Assembly viewModelAssembly;

		public Type LastShownType { get; private set; }

		public DateTime LastShownTime { get; private set; }

		public ValidPresenterRequestHelper(Assembly viewModelAssembly, TimeSpan? timeSpan = null)
		{
			this.viewModelAssembly = viewModelAssembly;
			threshold = timeSpan ?? TimeSpan.FromMilliseconds(500.0);
		}

		public virtual bool WasRecentlyShown(MvxViewModelRequest request)
		{
			return WasRecentlyShown(GetHighLevelViewModelType(request));
		}

		public virtual bool WasRecentlyShown(Type viewModelType)
		{
			if (LastShownType != viewModelType)
			{
				return false;
			}
			return DateTime.UtcNow - LastShownTime < threshold;
		}

		public virtual void UpdateLastShown(MvxViewModelRequest request)
		{
			UpdateLastShown(GetHighLevelViewModelType(request));
		}

		public virtual void UpdateLastShown(Type viewModelType)
		{
			LastShownType = viewModelType;
			LastShownTime = DateTime.UtcNow;
		}

		protected virtual Type GetHighLevelViewModelType(MvxViewModelRequest request)
		{
			string value = string.Empty;
			if (request?.PresentationValues?.TryGetValue("dialogViewModel", out value) == true)
			{
				return viewModelAssembly.GetType(value);
			}
			if (request?.PresentationValues?.TryGetValue("childViewModel", out value) == true)
			{
				return viewModelAssembly.GetType(value);
			}
			return request?.ViewModelType;
		}
	}
	public interface IWorkoutEstimationCache
	{
		Task AddEstimate(int version, string workoutId, int consoleIdentifier, double userKgs, WorkoutEstimator.Stats stats);

		Task<WorkoutEstimator.Stats> GetEstimate(int version, string workoutId, int consoleIdentifier, double userKgs);

		Task ClearDiskCache(bool vacuum = false);

		Task Clear(bool vacuum = false);

		Task Cleanup();
	}
	public class WorkoutEstimationCache : IWorkoutEstimationCache
	{
		private static DateTime LastCleanup = DateTime.UtcNow.AddDays(-2.0);

		private static Random RandomHours = new Random();

		private readonly IBlobCache diskCache;

		private static TimeSpan DiskCacheExpirationTime => TimeSpan.FromHours(RandomHours.Next(144, 192));

		public WorkoutEstimationCache(IBlobCache diskCache)
		{
			this.diskCache = diskCache;
		}

		public async Task AddEstimate(int version, string workoutId, int consoleIdentifier, double userKgs, WorkoutEstimator.Stats stats)
		{
			if (StatsAreJunk(stats))
			{
				return;
			}
			string key = GenerateCacheKey(version, workoutId, consoleIdentifier, userKgs);
			try
			{
				if (diskCache != null)
				{
					await diskCache.InvalidateObject<WorkoutEstimator.Stats>(key);
					await diskCache.InsertObject(key, stats, DiskCacheExpirationTime);
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Workout", "Could not add workout estimation to disk cache", exception);
			}
		}

		public async Task<WorkoutEstimator.Stats> GetEstimate(int version, string workoutId, int consoleIdentifier, double userKgs)
		{
			WorkoutEstimator.Stats stats = null;
			string key = GenerateCacheKey(version, workoutId, consoleIdentifier, userKgs);
			try
			{
				if (diskCache != null)
				{
					stats = await diskCache.GetObject<WorkoutEstimator.Stats>(key);
				}
			}
			catch
			{
			}
			if (StatsAreJunk(stats))
			{
				return null;
			}
			return stats;
		}

		public async Task ClearDiskCache(bool vacuum = false)
		{
			if (diskCache != null)
			{
				await diskCache.InvalidateAllSafe("WorkoutEstimationCache: ClearDiskCache");
				if (vacuum)
				{
					await diskCache.VacuumSafe("WorkoutEstimationCache: ClearDiskCache:");
				}
			}
		}

		public async Task Clear(bool vacuum = false)
		{
			await ClearDiskCache(vacuum);
		}

		public async Task Cleanup()
		{
			if (!(DateTime.UtcNow - LastCleanup < TimeSpan.FromDays(1.0)))
			{
				if (diskCache != null)
				{
					await diskCache.VacuumSafe("WorkoutEstimationCache: Cleanup:");
				}
				LastCleanup = DateTime.UtcNow;
			}
		}

		private bool StatsAreJunk(WorkoutEstimator.Stats stats)
		{
			if (stats != null)
			{
				if (stats.Calories.Equals(0.0) && stats.Meters.Equals(0.0))
				{
					return stats.Seconds.Equals(0.0);
				}
				return false;
			}
			return true;
		}

		protected virtual string GenerateCacheKey(int version, string workoutId, int consoleIdentifier, double userKgs)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("WorkoutEstimation:");
			stringBuilder.Append(version);
			stringBuilder.Append(';');
			stringBuilder.Append(workoutId);
			stringBuilder.Append(';');
			stringBuilder.Append(consoleIdentifier);
			stringBuilder.Append(';');
			stringBuilder.AppendFormat("{0:0.00000}", userKgs);
			return stringBuilder.ToString();
		}
	}
	public interface IWorkoutEstimator
	{
		IFitnessConsole Console { get; }

		Task<WorkoutEstimator.Stats> Estimate(Workout workout, double? constantMps = null, bool useCache = true);

		Task<WorkoutEstimator.Stats> EstimateWorkout(List<Workout.Control> workoutControls, Workout.WorkoutType workoutType, Workout.TargetType workoutTarget, double workoutTargetValue, double? workoutAverageHeartRate, bool shouldUseEquipmentlessConsole, bool isStrengthWorkout, string workoutId = null, double? constantMps = null, bool useCache = true);

		void UpdateUserKgs(double userKgs);
	}
	public class WorkoutEstimator : IWorkoutEstimator
	{
		public class Stats
		{
			private const double UninitializedConstantMps = -1.0;

			public double Seconds { get; set; }

			public double Calories { get; set; }

			public double Meters { get; set; }

			public double ElevationMetersGained { get; set; }

			public double ElevationMetersLost { get; set; }

			public double? ConstantMps { get; set; } = -1.0;

			public List<Tuple<double, double>> PredictedElevationProfile { get; set; } = new List<Tuple<double, double>>();

			[JsonIgnore]
			public double ElevationMetersNet => ElevationMetersGained + ElevationMetersLost;

			public void AddChanges(double elevationMetersChange, double calorieChange, double distanceChange, double secondsChange, double mps)
			{
				if (elevationMetersChange <= 0.0)
				{
					ElevationMetersLost += elevationMetersChange;
				}
				else
				{
					ElevationMetersGained += elevationMetersChange;
				}
				Calories += calorieChange;
				Meters += distanceChange;
				Seconds += secondsChange;
				if (ConstantMps.HasValue && (calorieChange > 0.0 || distanceChange > 0.0 || secondsChange > 0.0))
				{
					if (Math.Abs(ConstantMps.Value - -1.0) < 5E-324)
					{
						ConstantMps = mps;
					}
					else if (Math.Abs(ConstantMps.Value - mps) > 5E-324)
					{
						ConstantMps = null;
					}
				}
			}

			public void AddRowerChange(double height, double resistance, double spm, double seconds, double meters)
			{
				Seconds += seconds;
				Calories += CalorieFormulas.Rower(height, seconds, spm, resistance);
				Meters += ((spm == 0.0) ? meters : RowerEstimator.CalculateEstimatedDistance(spm, seconds, height));
			}

			public void AddElevationProfile(Workout.TargetType targetType)
			{
				double num = 0.0;
				switch (targetType)
				{
				default:
					return;
				case Workout.TargetType.Meters:
					num = Meters;
					break;
				case Workout.TargetType.Calories:
					num = Calories;
					break;
				case Workout.TargetType.Seconds:
					num = Seconds;
					break;
				}
				PredictedElevationProfile.Add(new Tuple<double, double>(num, ElevationMetersNet));
			}
		}

		private readonly ConsoleType type;

		private readonly double userHeightMeters;

		private readonly double maxMps;

		private readonly double maxIncline;

		private readonly double minIncline;

		private readonly double maxResistance;

		private readonly double maxWeightKg;

		private readonly int minGear;

		private readonly int maxGear;

		private readonly bool provideElevationProfile;

		private readonly IWorkoutEstimationCache cache;

		private double userKgs;

		private double userAge;

		private bool userMale;

		public const int Version = 4;

		private AerobicWatts.Table? aerobicWattsTable;

		private int ConsolePartNumber => (Console?.ConsoleInfo?.PartNumber).GetValueOrDefault();

		private int ConsoleIdentifier => ConsolePartNumber;

		private bool CacheAvailable
		{
			get
			{
				if (cache != null)
				{
					return ConsoleIdentifier > 0;
				}
				return false;
			}
		}

		private bool CanSetIncline => Console?.ConsoleInfo?.CanSetIncline ?? (maxIncline > minIncline);

		private double ControlsMaxIncline
		{
			get
			{
				if (!CanSetIncline && type.IsAerobicMachine())
				{
					return 1.7976931348623157E+308;
				}
				return maxIncline;
			}
		}

		private double ControlsMinIncline
		{
			get
			{
				if (!CanSetIncline && type.IsAerobicMachine())
				{
					return -1.7976931348623157E+308;
				}
				return minIncline;
			}
		}

		public IFitnessConsole Console { get; private set; }

		protected WorkoutEstimator(ConsoleType type = ConsoleType.Treadmill, double userKgs = 83.91, double userAge = 35.0, bool userMale = true, double userHeightMeters = 1.778, double maxMps = 5.36447, double maxIncline = 20.0, double minIncline = -5.0, double maxResistance = 26.0, int minGear = 1, int maxGear = 26, double maxWeightKg = 136.078, bool provideElevationProfile = false, IWorkoutEstimationCache cache = null, IFitnessConsole console = null)
		{
			this.type = type;
			this.userKgs = userKgs.Clamp(1.0, maxWeightKg);
			this.userAge = userAge;
			this.userMale = userMale;
			this.userHeightMeters = userHeightMeters;
			this.maxMps = maxMps;
			this.maxIncline = maxIncline;
			this.minIncline = minIncline;
			this.maxResistance = maxResistance;
			this.minGear = minGear;
			this.maxGear = maxGear;
			this.provideElevationProfile = provideElevationProfile;
			Console = console;
			if (cache == null)
			{
				if (Mvx.TryResolve<IWorkoutEstimationCache>(out var service))
				{
					this.cache = service;
				}
				else
				{
					iFit.Logger.Log.Error("Workout", "Could not resolve IWorkoutEstimationCache");
				}
			}
			else
			{
				this.cache = cache;
			}
		}

		public static IWorkoutEstimator Factory(IFitnessConsole console, double? userWeight, double? userHeightMeters, double? userAge, bool? userMale, bool provideElevationProfile = false, bool isMetric = false, IWorkoutEstimationCache cache = null)
		{
			ConsoleType consoleType = console?.ConsoleInfo?.MachineType ?? ConsoleType.Treadmill;
			double num = userWeight ?? 83.91;
			double num2 = userHeightMeters ?? 1.778;
			double num3 = (isMetric ? 5.55555 : 5.36447);
			if (console?.ConsoleInfo != null)
			{
				IConsoleInfo consoleInfo = console.ConsoleInfo;
				double num4 = UnitUtil.EnsureMps(SpeedUnit.Kph, consoleInfo.MaxKph);
				double maxWeight = consoleInfo.MaxWeight;
				return new WorkoutEstimator(consoleType, num, userAge ?? 35.0, userMale ?? true, num2, num4, consoleInfo.MaxIncline, consoleInfo.MinIncline, consoleInfo.MaxResistanceLevel, consoleInfo.MinGear, consoleInfo.MaxGear, maxWeight, provideElevationProfile, cache, console);
			}
			return new WorkoutEstimator(consoleType, num, 35.0, userMale: true, 1.778, num3, 20.0, -5.0, 26.0, 1, 26, 136.078, provideElevationProfile, cache, console);
		}

		public static double PreviousOrDefaultControl(List<Workout.Control> controls, double at, Workout.Control.ControlType controlType)
		{
			return (controls.LastOrDefault((Workout.Control x) => x.At < at && x.Type == controlType)?.Value).GetValueOrDefault();
		}

		public async Task<Stats> Estimate(Workout workout, double? constantMps = null, bool useCache = true)
		{
			return await EstimateWorkout(workout.Controls, workout.Type, workout.Target, workout.TargetValue, workout.Metadata?.AverageHeartRate, workout.ShouldUseEquipmentlessConsole(), workout.IsStrengthWorkout(), workout.Id, constantMps, useCache);
		}

		public async Task<Stats> EstimateWorkout(List<Workout.Control> workoutControls, Workout.WorkoutType workoutType, Workout.TargetType workoutTarget, double workoutTargetValue, double? workoutAverageHeartRate, bool shouldUseEquipmentlessConsole, bool isStrengthWorkout, string workoutId = null, double? constantMps = null, bool useCache = true)
		{
			bool workoutHasId = !string.IsNullOrWhiteSpace(workoutId);
			if (useCache && CacheAvailable && workoutHasId)
			{
				Stats stats = await cache.GetEstimate(4, workoutId, ConsoleIdentifier, userKgs).ConfigureAwait(continueOnCapturedContext: false);
				if (stats != null)
				{
					return stats;
				}
			}
			SetAerobicWattsTableIfNeeded(constantMps);
			List<Workout.Control> controls = WorkoutExtensions.GetBoundedControls(workoutControls, workoutTargetValue, maxMps, ControlsMaxIncline, ControlsMinIncline, maxResistance, minGear, maxGear, constantMps);
			if (controls == null)
			{
				return null;
			}
			HandleAerobicConversionsIfNeeded(ref controls, workoutTargetValue, WorkoutExtensions.IsManualWorkout(workoutTarget, workoutId));
			IList<WorkoutSegment> segments = WorkoutSegmentationUtil.SegmentWorkout(controls, workoutTarget, constantMps.GetValueOrDefault(), workoutTargetValue, workoutAverageHeartRate, shouldUseEquipmentlessConsole);
			Stats stats2 = EstimateSegments(workoutType, segments, workoutTarget, isStrengthWorkout);
			if (useCache && CacheAvailable && workoutHasId)
			{
				await cache.AddEstimate(4, workoutId, ConsoleIdentifier, userKgs, stats2).ConfigureAwait(continueOnCapturedContext: false);
			}
			return stats2;
		}

		public void UpdateUserKgs(double userKgs)
		{
			this.userKgs = userKgs;
		}

		private void SetAerobicWattsTableIfNeeded(double? constantMps)
		{
			if (!type.IsAerobicMachine() || !constantMps.HasValue)
			{
				return;
			}
			aerobicWattsTable = null;
			if (AerobicWatts.Tables.TryGetValue(ConsolePartNumber, out var value))
			{
				double num = UnitUtil.EnsureMph(SpeedUnit.Mps, constantMps.Value);
				if (Math.Abs(num - value.SpeedMph) < 0.1)
				{
					aerobicWattsTable = value;
				}
				else
				{
					iFit.Logger.Log.Trace("Workout", $"Estimating workout at {constantMps} mph but AerobicWatts table is for {value.SpeedMph} mph, will estimate without lookup.");
				}
			}
		}

		private void HandleAerobicConversionsIfNeeded(ref List<Workout.Control> controls, double targetValue, bool isManual)
		{
			if (type.IsAerobicMachine() && (type.IsRower() || aerobicWattsTable.HasValue))
			{
				controls = controls.ConvertInclineControlsToResistanceIfNecessary(Console, targetValue, isManual).ConvertResistanceControlsToRelativeResistance(Console?.ConsoleInfo);
			}
			else
			{
				controls = controls.ConvertRelativeResistanceToResistance(Console?.ConsoleInfo).ConvertResistanceControlsToIncline(maxResistance, 1.7976931348623157E+308, -1.7976931348623157E+308);
			}
		}

		private Stats EstimateSegments(Workout.WorkoutType workoutType, IList<WorkoutSegment> segments, Workout.TargetType target, bool isStrengthWorkout)
		{
			if (isStrengthWorkout)
			{
				return EstimateStrengthWorkoutSegments(segments);
			}
			ConsoleType consoleType = type;
			if (consoleType.IsRower())
			{
				if (workoutType.IsRowWorkout())
				{
					return EstimateRowerSegments(segments);
				}
				consoleType = ConsoleType.Treadmill;
			}
			Stats stats = new Stats();
			foreach (WorkoutSegment segment in segments)
			{
				double calorieChange = segment.EstimateCalories(consoleType, userKgs, userHeightMeters, userAge, userMale, aerobicWattsTable);
				double elevationMetersChange = (CanSetIncline ? segment.ElevationChange : 0.0);
				stats.AddChanges(elevationMetersChange, calorieChange, segment.Meters, segment.Seconds, segment.Mps);
				if (provideElevationProfile)
				{
					stats.AddElevationProfile(target);
				}
			}
			return stats;
		}

		private Stats EstimateStrengthWorkoutSegments(IList<WorkoutSegment> segments)
		{
			Stats stats = new Stats();
			segments.ForEach(delegate(WorkoutSegment segment)
			{
				double calorieChange = segment.EstimateCaloriesByEstimatedHeartRate(userKgs, userAge, userMale);
				stats.AddChanges(0.0, calorieChange, 0.0, segment.Seconds, 0.0);
			});
			return stats;
		}

		private Stats EstimateRowerSegments(IList<WorkoutSegment> segments)
		{
			Stats stats = new Stats();
			segments.ForEach(delegate(WorkoutSegment segment)
			{
				stats.AddRowerChange(userHeightMeters, segment.RelativeResistance, segment.Spm, segment.Seconds, segment.Meters);
			});
			return stats;
		}
	}
}
namespace Shire.Core.Util.WorkoutSegmentation
{
	public static class WorkoutSegmentationUtil
	{
		private const double MetersPerStroke = 9.0;

		private const double SecondsPerMinute = 60.0;

		public static IList<WorkoutSegment> SegmentWorkout(IList<Workout.Control> controls, Workout.TargetType targetType, double initialMps, double targetValue, double? avgHeartRate = null, bool isEquipmentless = false)
		{
			WorkoutSegment.Builder builder = null;
			builder = targetType switch
			{
				Workout.TargetType.Meters => WorkoutSegment.FromMeters, 
				Workout.TargetType.Seconds => WorkoutSegment.FromSeconds, 
				_ => throw new ArgumentException($"Unsupported workout target type ({targetType}).", "targetType"), 
			};
			IEnumerable<Workout.Control> enumerable = controls?.Where((Workout.Control c) => c != null);
			if (enumerable == null)
			{
				throw new ArgumentException("Workout has null Controls list.", "targetType");
			}
			Workout.Control[] array = enumerable.ToArray();
			List<WorkoutSegment> list = new List<WorkoutSegment>();
			double mps = initialMps;
			double incline = 0.0;
			double relativeResistance = 0.0;
			double num = 0.0;
			double spm = 0.0;
			double estimatedBpm = avgHeartRate ?? 125.0;
			for (int num2 = 0; num2 < array.Length; num2++)
			{
				Workout.Control control = array[num2];
				double num3 = control.At.Clamp(0.0, 1.7976931348623157E+308);
				if (num3 > num)
				{
					double atValueDifference = num3 - num;
					WorkoutSegment item = builder(incline, relativeResistance, mps, atValueDifference, spm, estimatedBpm);
					list.Add(item);
					num = num3;
				}
				switch (control.Type)
				{
				case Workout.Control.ControlType.Incline:
					incline = control.Value;
					break;
				case Workout.Control.ControlType.RelativeResistance:
					relativeResistance = control.Value;
					break;
				case Workout.Control.ControlType.Mps:
					mps = control.Value;
					break;
				case Workout.Control.ControlType.SPM:
					mps = control.Value * 9.0 / 60.0;
					spm = control.Value;
					break;
				case Workout.Control.ControlType.EstimatedBPM:
					estimatedBpm = control.Value;
					break;
				case Workout.Control.ControlType.Resistance:
					if (!isEquipmentless)
					{
						throw new ArgumentOutOfRangeException("controls", $"Control {num2} is Resistance, remember to convert to RelativeResistance.");
					}
					break;
				}
			}
			if (targetValue > 0.0 && (targetValue > num || list.Count < 1))
			{
				WorkoutSegment item2 = builder(incline, relativeResistance, mps, targetValue - num, spm, estimatedBpm);
				list.Add(item2);
				num = targetValue;
			}
			return list;
		}

		public static IList<WorkoutSegment> SegmentWorkout(this Workout workout)
		{
			if (workout == null)
			{
				throw new ArgumentNullException("workout");
			}
			return SegmentWorkout(workout.Controls, workout.Target, 0.0, workout.TargetValue, workout.Metadata?.AverageHeartRate, workout.ShouldUseEquipmentlessConsole());
		}

		public static WorkoutSegment GetWorkoutSegmentAtTime(this Workout workout, double seconds)
		{
			if (seconds < 0.0 || workout == null)
			{
				return null;
			}
			IList<WorkoutSegment> list = workout.SegmentWorkout();
			if (list.CountSafe() < 1)
			{
				return null;
			}
			double num = 0.0;
			for (int i = 0; i < list.Count(); i++)
			{
				WorkoutSegment workoutSegment = list.ElementAtOrDefault(i);
				if (workoutSegment != null)
				{
					double num2 = num + workoutSegment.Seconds;
					if (seconds >= num && seconds < num2)
					{
						return workoutSegment;
					}
					if (i >= list.Count() - 1 && seconds.Equals(num2))
					{
						return workoutSegment;
					}
					num = num2;
				}
			}
			return null;
		}
	}
}
namespace Shire.Core.Util.Units
{
	public static class MpsRpmUtil
	{
		public const double MpsConversionRatio = 2.237;

		public const double BikeRatioMultiplier = 5.0;

		public const double EllipticalRatioMultiplier = 8.0;

		public const double MetersPerStroke = 8.0;

		public static double MpsToRpm(IConsoleInfo consoleInfo, double mps, double resistance = 0.0)
		{
			ConsoleType? consoleType = consoleInfo?.MachineType;
			bool flag = consoleInfo?.CanSetIncline ?? false;
			switch (consoleType)
			{
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return MpsToRpmForBike(mps);
			case ConsoleType.Elliptical:
			case ConsoleType.VerticalElliptical:
				return MpsToRpmForElliptical(mps);
			default:
				return 0.0;
			}
		}

		public static double RpmToMps(IConsoleInfo consoleInfo, double rpm, double resistance = 0.0)
		{
			switch (consoleInfo?.MachineType)
			{
			case ConsoleType.Bike:
			case ConsoleType.SpinBike:
				return RpmToMpsForBike(rpm);
			case ConsoleType.Elliptical:
			case ConsoleType.VerticalElliptical:
				return RpmToMpsForElliptical(rpm);
			default:
				return 0.0;
			}
		}

		public static double MpsToRpmForBike(double mps)
		{
			return mps * 2.237 * 5.0;
		}

		public static double RpmToMpsForBike(double rpm)
		{
			return rpm / 11.185;
		}

		public static double MpsToRpmForInclineBike(double mps, double resistance)
		{
			double num = mps * 2.237;
			return 1000000.0 * (34.0 - resistance) / 4275507.6 * num;
		}

		public static double RpmForMpsForInclineBike(double rpm, double resistance)
		{
			double num = 4275507.6 * rpm / (1000000.0 * (34.0 - resistance));
			return num / 2.237;
		}

		public static double MpsToRpmForElliptical(double mps)
		{
			return mps * 2.237 * 8.0;
		}

		public static double RpmToMpsForElliptical(double rpm)
		{
			return rpm / 17.896;
		}

		public static double MpsToRpmForInclineElliptical(double mps, double resistance)
		{
			double num = mps * 2.237;
			return 1000000.0 * (34.0 - resistance) / 4275507.6 * num / 0.625;
		}

		public static double RpmToMpsForInclineElliptical(double rpm, double resistance)
		{
			double num = 4275507.6 * rpm / (1000000.0 * (34.0 - resistance)) * 0.625;
			return num / 2.237;
		}
	}
}
