	public enum ShareResult
	{
		Success,
		Cancelled,
		Failed,
		Undefined
	}
	public interface IShareProvider
	{
		Task<ShareResult> Share(string message, string uri);
	}
	public enum SocialShareProvider
	{
		Facebook,
		Twitter
	}
	public interface ISocialShareUtil
	{
		Task<ShareResult> Share(SocialShareProvider type, string message, string uri);
	}
	public abstract class SocialShareUtil : ISocialShareUtil
	{
		protected readonly Dictionary<SocialShareProvider, IShareProvider> shareMapping;

		protected readonly IFacebookShareProvider facebookShare;

		protected readonly ITwitterShareProvider twitterShare;

		protected SocialShareUtil(IFacebookShareProvider facebookShare, ITwitterShareProvider twitterShare)
		{
			this.twitterShare = twitterShare;
			this.facebookShare = facebookShare;
			shareMapping = new Dictionary<SocialShareProvider, IShareProvider>
			{
				{
					SocialShareProvider.Facebook,
					facebookShare
				},
				{
					SocialShareProvider.Twitter,
					twitterShare
				}
			};
		}

		public async Task<ShareResult> Share(SocialShareProvider type, string message, string uri)
		{
			if (!shareMapping.ContainsKey(type))
			{
				throw new InvalidOperationException("Share type " + type.ToString() + " does not have a mapping");
			}
			return await shareMapping[type].Share(message, uri);
		}
	}
