namespace Shire.Core.Util.Extensions
{
	public static class AkavacheExtensions
	{
		private const string Tag = "Cache";

		private static readonly SemaphoreSlim GetFetchLock = new SemaphoreSlim(1, 1);

		private static string Message(string message)
		{
			if (!string.IsNullOrEmpty(message))
			{
				return " in " + message;
			}
			return string.Empty;
		}

		public static async Task VacuumSafe(this IBlobCache cache, string caller = null)
		{
			try
			{
				await cache.Vacuum();
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Cache", "Failed to vacuum cache" + Message(caller), ex.GetBaseException());
			}
		}

		public static async Task FlushSafe(this IBlobCache cache, string caller = null)
		{
			try
			{
				await cache.Flush();
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Cache", "Failed to flush cache" + Message(caller), ex.GetBaseException());
			}
		}

		public static async Task InvalidateAllSafe(this IBlobCache cache, string caller = null)
		{
			try
			{
				iFit.Logger.Log.Trace("Cache", "Inavlidating all items in cache, caller: " + caller);
				await cache.InvalidateAll();
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Cache", "Failed to invalidate all items in cache" + Message(caller), ex.GetBaseException());
			}
		}

		public static async Task<TObj> GetThenFetchIfNecessary<TObj>(this IBlobCache cache, string key, Func<Task<TObj>> fetchFunc, DateTimeOffset? expiration = null) where TObj : class
		{
			TObj result = null;
			if (cache == null)
			{
				throw new ArgumentNullException("cache");
			}
			await GetFetchLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				try
				{
					result = await cache.GetObject<TObj>(key);
				}
				catch (KeyNotFoundException)
				{
				}
				if (result == null)
				{
					result = await fetchFunc().ConfigureAwait(continueOnCapturedContext: false);
					if (result != null)
					{
						await cache.InsertObject(key, result, expiration);
					}
				}
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Trace("Api", $"Exception thrown Akavache GetThenFetchIfNecessary: {arg}");
			}
			finally
			{
				GetFetchLock.Release();
			}
			return result;
		}
	}
	public static class ByteExtensions
	{
		public static bool WildcardSequenceEquals(this byte[] bytes, byte?[] sequence)
		{
			if (bytes == null || sequence == null || bytes.Length != sequence.Length)
			{
				return false;
			}
			for (long num = 0L; num < bytes.Length; num++)
			{
				byte b = bytes[num];
				byte? b2 = sequence[num];
				if (b2.HasValue && b != b2.Value)
				{
					return false;
				}
			}
			return true;
		}
	}
	public static class DateTimeExtensions
	{
		public static int CalculateAge(this DateTime? birthdayParam, DateTime? overrideCurrent = null)
		{
			if (!birthdayParam.HasValue)
			{
				return 0;
			}
			DateTime value = birthdayParam.Value;
			DateTime dateTime = overrideCurrent ?? DateTime.Now;
			if (value > dateTime)
			{
				return 0;
			}
			if (dateTime.Month > value.Month)
			{
				return dateTime.Year - value.Year;
			}
			if (dateTime.Month == value.Month && dateTime.Day >= value.Day)
			{
				return dateTime.Year - value.Year;
			}
			return dateTime.Year - value.Year - 1;
		}
	}
	public static class DictionaryExtensions
	{
		public static IDictionary<TKey, TValue> MergeDictionaries<TKey, TValue>(this IDictionary<TKey, TValue> existingDict, IDictionary<TKey, TValue> dictionary, MergeMode mergeMode = MergeMode.MergeReplacingExisting)
		{
			if (existingDict == null && dictionary == null)
			{
				return null;
			}
			if (existingDict == dictionary)
			{
				return new Dictionary<TKey, TValue>(existingDict);
			}
			if (existingDict.CountSafe() < 1 && dictionary.CountSafe() < 1)
			{
				return new Dictionary<TKey, TValue>();
			}
			if (dictionary.CountSafe() < 1)
			{
				return new Dictionary<TKey, TValue>(existingDict);
			}
			if (existingDict.CountSafe() < 1)
			{
				return new Dictionary<TKey, TValue>(dictionary);
			}
			Dictionary<TKey, TValue> result = new Dictionary<TKey, TValue>(existingDict.Count + dictionary.Count);
			existingDict.DoForEach(delegate(KeyValuePair<TKey, TValue> x)
			{
				result.Add(x.Key, x.Value);
			});
			dictionary.DoForEach(delegate(KeyValuePair<TKey, TValue> x)
			{
				if (result.ContainsKey(x.Key))
				{
					if (mergeMode == MergeMode.MergeReplacingExisting)
					{
						result[x.Key] = x.Value;
					}
				}
				else
				{
					result.Add(x.Key, x.Value);
				}
			});
			return result;
		}
	}
	public enum MergeMode
	{
		MergeKeepingExisting,
		MergeReplacingExisting
	}
	public static class DisposableExtensions
	{
		public static TDisposable DisposeWith<TDisposable>(this TDisposable disposable, CompositeDisposable disposables) where TDisposable : class, IDisposable
		{
			disposables.Add(disposable);
			return disposable;
		}
	}
	public static class EnumExtensions
	{
		public static bool HasAnyFlag(this Enum value, Enum flags)
		{
			if (value != null)
			{
				return (Convert.ToInt32(value) & Convert.ToInt32(flags)) != 0;
			}
			return false;
		}

		public static string ToEnumMemberAttrValue(this Enum enums)
		{
			EnumMemberAttribute enumMemberAttribute = enums.GetType().GetRuntimeField(enums.ToString())?.GetCustomAttributes(inherit: false).OfType<EnumMemberAttribute>().FirstOrDefault();
			if (enumMemberAttribute == null)
			{
				return enums.ToString();
			}
			return enumMemberAttribute.Value;
		}
	}
	public static class ExceptionExtensions
	{
		public interface INativeExceptionUtil
		{
			bool NativeRelatesTo<TException>(Exception ex) where TException : Exception;
		}

		public static bool RelatesTo<TException>(this Exception ex) where TException : Exception
		{
			if (ex is TException)
			{
				return true;
			}
			for (Exception ex2 = ex?.InnerException; ex2 != null; ex2 = ex2?.InnerException)
			{
				if (ex2 is TException)
				{
					return true;
				}
			}
			if (Mvx.TryResolve<INativeExceptionUtil>(out var service))
			{
				return service.NativeRelatesTo<TException>(ex);
			}
			return false;
		}

		public static bool AnyMessageContains(this Exception ex, string text, StringComparison stringComparison = StringComparison.OrdinalIgnoreCase)
		{
			if (text == null)
			{
				return false;
			}
			for (Exception ex2 = ex; ex2 != null; ex2 = ex2.InnerException)
			{
				string message = ex2.Message;
				if (message != null && message.Contains(text, stringComparison))
				{
					return true;
				}
			}
			return false;
		}
	}
	public static class FieldBindingExtensions
	{
		public static IObservable<T> ToObservable<T>(this INC<T> nc)
		{
			return from x in Observable.FromEventPattern(delegate(EventHandler h)
				{
					nc.Changed += h;
				}, delegate(EventHandler h)
				{
					nc.Changed -= h;
				})
				select nc.Value;
		}

		public static IObservable<IList<T>> ToObservable<T>(this INCList<T> ncList)
		{
			return from x in Observable.FromEventPattern(delegate(EventHandler h)
				{
					ncList.Changed += h;
				}, delegate(EventHandler h)
				{
					ncList.Changed -= h;
				})
				select ncList.Value;
		}

		public static IObservable<T> ToObservable<T>(this INotifyPropertyChanged propChangedClass, string propertyName)
		{
			return from x in Observable.FromEventPattern<PropertyChangedEventHandler, PropertyChangedEventArgs>(delegate(PropertyChangedEventHandler h)
				{
					propChangedClass.PropertyChanged += h;
				}, delegate(PropertyChangedEventHandler h)
				{
					propChangedClass.PropertyChanged -= h;
				})
				select x.EventArgs.PropertyName into x
				where x.Equals(propertyName)
				select (T)propChangedClass.GetType().GetRuntimeProperty(x).GetValue(propChangedClass);
		}
	}
	public static class GeocodeExtensions
	{
		public static string ToWorkoutTitle(this Geocode.GeocodeResults results)
		{
			Geocode.AddressComponent addressComponent = results.AddressComponents.FirstOrDefault((Geocode.AddressComponent x) => x.Types.Contains("locality"));
			Geocode.AddressComponent addressComponent2 = results.AddressComponents.FirstOrDefault((Geocode.AddressComponent x) => x.Types.Contains("administrative_area_level_1"));
			Geocode.AddressComponent addressComponent3 = results.AddressComponents.FirstOrDefault((Geocode.AddressComponent x) => x.Types.Contains("country"));
