	public static class HttpExtensions
	{
		public static bool IsConsideredErrorStatus(this HttpStatusCode statusCode)
		{
			return statusCode >= HttpStatusCode.BadRequest;
		}

		public static Uri AppendOrReplaceQueryVars(this Uri uri, IDictionary<string, string> queryVars, MergeMode mergeMode = MergeMode.MergeReplacingExisting, bool shouldUrlEncodeParams = true, string fragment = null, FragmentAppendMode fragmentAppendMode = FragmentAppendMode.AfterQueryString, bool shouldUrlEncodeFragment = false)
		{
			if (uri == null || queryVars.CountSafe() < 1)
			{
				return uri;
			}
			IDictionary<string, string> dict = uri.DecodeQueryParameters().MergeDictionaries(queryVars, mergeMode);
			string value = uri.BaseUrl();
			string text = ((shouldUrlEncodeFragment && !string.IsNullOrEmpty(fragment)) ? WebUtility.UrlEncode(fragment) : fragment);
			if (text == null && !string.IsNullOrWhiteSpace(uri.Fragment))
			{
				text = uri.GetUrlFragment();
			}
			string text2 = dict.BuildQueryStringFromVars(shouldUrlEncodeParams);
			StringBuilder stringBuilder = new StringBuilder(value);
			if (fragmentAppendMode == FragmentAppendMode.BeforeQueryString)
			{
				stringBuilder.Append("#" + (text ?? string.Empty));
				if (!string.IsNullOrEmpty(text2))
				{
					stringBuilder.Append("?" + text2);
				}
			}
			else
			{
				if (!string.IsNullOrEmpty(text2))
				{
					stringBuilder.Append("?" + text2);
				}
				if (!string.IsNullOrEmpty(text))
				{
					stringBuilder.Append("#" + text);
				}
			}
			return new Uri(stringBuilder.ToString());
		}

		public static string BuildQueryStringFromVars(this IDictionary<string, string> dict, bool shouldUrlEncode = true)
		{
			if (dict.CountSafe() < 1)
			{
				return string.Empty;
			}
			IEnumerable<string> values = (from x in dict
				where !string.IsNullOrEmpty(x.Key)
				orderby x.Key
				select x).Select(delegate(KeyValuePair<string, string> x)
			{
				if (string.IsNullOrEmpty(x.Value))
				{
					if (!shouldUrlEncode)
					{
						return x.Key;
					}
					return WebUtility.UrlEncode(x.Key);
				}
				return (!shouldUrlEncode) ? (x.Key + "=" + x.Value) : (WebUtility.UrlEncode(x.Key) + "=" + WebUtility.UrlEncode(x.Value));
			});
			return string.Join("&", values);
		}

		public static IDictionary<string, string> DecodeQueryParameters(this Uri uri)
		{
			if (uri == null)
			{
				return null;
			}
			string text = uri.Query;
			if (string.IsNullOrWhiteSpace(text) && uri.Fragment.Length > 0 && uri.Fragment.Contains("?"))
			{
				text = uri.Fragment.Substring(uri.Fragment.IndexOf('?') + 1);
			}
			if (string.IsNullOrWhiteSpace(text))
			{
				return new Dictionary<string, string>();
			}
			return (from parameter in text.TrimStart('?').Split(new char[2] { '&', ';' }, StringSplitOptions.RemoveEmptyEntries)
				select parameter.Split(new char[1] { '=' }, StringSplitOptions.RemoveEmptyEntries) into parts
				group (parts.Length <= 2) ? ((parts.Length <= 1) ? string.Empty : parts[1]) : string.Join("=", parts, 1, parts.Length - 1) by parts[0]).ToDictionary((IGrouping<string, string> grouping) => grouping.Key, (IGrouping<string, string> grouping) => string.Join(",", grouping));
		}

		public static string GetUrlFragment(this Uri uri)
		{
			if (uri == null)
			{
				return null;
			}
			string text = (uri.Fragment.Contains("?") ? uri.Fragment.Substring(0, uri.Fragment.IndexOf('?')) : uri.Fragment);
			return text.Replace("#", "");
		}

		public static string BaseUrl(this Uri uri)
		{
			return uri.Scheme + "://" + uri.Host + uri.AbsolutePath;
		}

		public static Uri CreateUrlSafe(this string urlString)
		{
			if (string.IsNullOrWhiteSpace(urlString))
			{
				return null;
			}
			try
			{
				return new Uri(urlString);
			}
			catch (UriFormatException exception)
			{
				iFit.Logger.Log.Fatal("WebView", "Malformed URL: " + urlString, exception);
				return null;
			}
		}

		public static string WebViewStoreKey(this Uri uri)
		{
			string urlFragment = uri.GetUrlFragment();
			if (!string.IsNullOrEmpty(urlFragment))
			{
				return uri.BaseUrl() + "#" + urlFragment;
			}
			return uri.BaseUrl() ?? "";
		}

		public static string WebviewHolderFactoryStoreKey(this Uri uri)
		{
			string urlFragment = uri.GetUrlFragment();
			if (!string.IsNullOrEmpty(urlFragment))
			{
				return uri.BaseUrl() + "#" + urlFragment;
			}
			return uri.BaseUrl() ?? "";
		}

		public static Uri GetUrlWithFragment(this Uri uri, string fragment)
		{
			if (uri == null)
			{
				return null;
			}
			UriBuilder uriBuilder = new UriBuilder(uri)
			{
				Fragment = (string.IsNullOrEmpty(fragment) ? string.Empty : "#") + (fragment?.Replace("#", "").Trim() ?? string.Empty)
			};
			return uriBuilder.Uri;
		}
	}
