	public static class IDeviceExtensions
	{
		public static void SortDevices(this ImprovedObservableCollection<IBleDevice> devices)
		{
			IBleDevice[] collection = devices.Where((IBleDevice d) => d.State == DeviceState.Connected).Take(1).ToArray();
			IBleDevice[] collection2 = devices.Where((IBleDevice d) => d.State == DeviceState.Connecting).Take(1).ToArray();
			IBleDevice[] collection3 = (from d in devices
				where !d.IsMock && d.State != DeviceState.Connected && d.State != DeviceState.Connecting
				orderby d.Rssi descending
				select d).ToArray();
			IBleDevice[] collection4 = (from d in devices
				where d.IsMock && d.State != DeviceState.Connected && d.State != DeviceState.Connecting
				orderby d.Name.ToLowerInvariant()
				select d).ToArray();
			List<IBleDevice> list = new List<IBleDevice>();
			list.AddRange(collection);
			list.AddRange(collection2);
			list.AddRange(collection3);
			list.AddRange(collection4);
			if (!devices.SequenceEqual(list))
			{
				devices.Clear();
				devices.AddRange(list);
			}
			list.Clear();
			list = null;
		}
	}
	public static class INCExtensions
	{
		public static void SafeUpdateValue<T>(this INC<T> nc, T newValue)
		{
			T value = nc.Value;
			if (((value != null) ? new bool?(value.Equals(newValue)) : ((bool?)null)) != true)
			{
				nc.Value = newValue;
			}
		}
	}
	public static class JsonCloner
	{
		public static T CloneJson<T>(this T source)
		{
			if (source == null)
			{
				return default(T);
			}
			JsonSerializer jsonSerializer = new JsonSerializer
			{
				ObjectCreationHandling = ObjectCreationHandling.Replace
			};
			using MemoryStream memoryStream = new MemoryStream();
			StreamWriter streamWriter = new StreamWriter(memoryStream);
			JsonTextWriter jsonWriter = new JsonTextWriter(streamWriter);
			jsonSerializer.Serialize(jsonWriter, source);
			streamWriter.Flush();
			memoryStream.Position = 0L;
			StreamReader reader = new StreamReader(memoryStream);
			JsonTextReader reader2 = new JsonTextReader(reader);
			return jsonSerializer.Deserialize<T>(reader2);
		}
	}
	public static class LatLngAtDistanceExtension
	{
		public static List<iFit.Api.Google.LatLngAtDistance> GetPointsBetween(this iFit.Api.Google.LatLngAtDistance start, iFit.Api.Google.LatLngAtDistance end, double minMetersBetween)
		{
			List<iFit.Api.Google.LatLngAtDistance> list = new List<iFit.Api.Google.LatLngAtDistance>();
			double num = start.LatLng.GetDistanceTo(end.LatLng) / minMetersBetween;
			if (num < 1.0)
			{
				list.Add(end);
				return list;
			}
			double num2 = (end.LatLng.Lat - start.LatLng.Lat) / num;
			double num3 = (end.LatLng.Lng - start.LatLng.Lng) / num;
			iFit.Api.Google.LatLngAtDistance latLngAtDistance = start;
			for (double num4 = 1.0; num4 <= num; num4 += 1.0)
			{
				iFit.Api.Google.LatLng latLng = new iFit.Api.Google.LatLng(start.LatLng.Lat + num4 * num2, start.LatLng.Lng + num4 * num3);
				double meters = latLngAtDistance.Meters + latLngAtDistance.LatLng.GetDistanceTo(latLng);
				iFit.Api.Google.LatLngAtDistance latLngAtDistance2 = new iFit.Api.Google.LatLngAtDistance(meters, latLng);
				latLngAtDistance = latLngAtDistance2;
				list.Add(latLngAtDistance2);
			}
			return list;
		}

		public static double GetDistanceTo(this iFit.Api.Google.LatLngAtDistance start, iFit.Api.Google.LatLngAtDistance end)
		{
			return start.LatLng.GetDistanceTo(end.LatLng);
		}
	}
	public static class LatLngExtensions
	{
		public static bool IsAtLeastXMetersAway(this iFit.Api.Google.LatLng start, iFit.Api.Google.LatLng next, double minMeters)
		{
			if (start == null || next == null)
			{
				return false;
			}
			if (start.IsUnknown || next.IsUnknown)
			{
				return true;
			}
			if (start.GetDistanceTo(next) < minMeters)
			{
				return false;
			}
			return true;
		}

		public static async Task<double> CalculateElevationGain(this List<iFit.Api.Google.LatLng> coordinates, IGoogleApiService googleApi)
		{
			List<Elevations.ElevationResults> results = (await Elevations.GetFromPoints(googleApi, coordinates)).Results;
			double num = 0.0;
			for (int i = 0; i < results.Count - 1; i++)
			{
				Elevations.ElevationResults elevationResults = results[i];
				Elevations.ElevationResults elevationResults2 = results[i + 1];
				double num2 = elevationResults2.Elevation - elevationResults.Elevation;
				if (num2 > 0.0)
				{
					num += num2;
				}
			}
			return num;
		}

		public static double GetHeadingDegrees(this iFit.Api.Google.LatLng start, iFit.Api.Google.LatLng end)
		{
			return start.GetHeadingDegrees(end.Lat, end.Lng);
		}

		public static double GetHeadingDegrees(this iFit.Api.Google.LatLng start, double endLat, double endLng)
		{
			double x = endLat - start.Lat;
			double y = endLng - start.Lng;
			double num;
			for (num = Math.Atan2(y, x) * 180.0 / Math.PI; num < 0.0; num += 360.0)
			{
			}
			while (num > 360.0)
			{
				num -= 360.0;
			}
			return num;
		}
	}
