	public static class ObjectExtensions
	{
		public static IDisposable SubscribeToEvent<TSource>(this TSource source, EventHandler handler, Action<TSource, EventHandler> addHandler, Action<TSource, EventHandler> removeHandler) where TSource : class
		{
			source.ThrowIfNull("source");
			handler.ThrowIfNull("handler");
			addHandler.ThrowIfNull("addHandler");
			removeHandler.ThrowIfNull("removeHandler");
			return Observable.FromEventPattern(delegate(EventHandler arg)
			{
				addHandler(source, arg);
			}, delegate(EventHandler arg)
			{
				removeHandler(source, arg);
			}).Subscribe(delegate(EventPattern<object> data)
			{
				handler(data.Sender, (EventArgs)data.EventArgs);
			});
		}

		public static IDisposable SubscribeToEvent<TSource, TEventArgs>(this TSource source, EventHandler<TEventArgs> handler, Action<TSource, EventHandler<TEventArgs>> addHandler, Action<TSource, EventHandler<TEventArgs>> removeHandler) where TSource : class
		{
			source.ThrowIfNull("source");
			handler.ThrowIfNull("handler");
			addHandler.ThrowIfNull("addHandler");
			removeHandler.ThrowIfNull("removeHandler");
			return Observable.FromEventPattern(delegate(EventHandler<TEventArgs> arg)
			{
				addHandler(source, arg);
			}, delegate(EventHandler<TEventArgs> arg)
			{
				removeHandler(source, arg);
			}).Subscribe(delegate(EventPattern<TEventArgs> data)
			{
				handler(data.Sender, data.EventArgs);
			});
		}

		public static T ThrowIfNull<T>(this T obj, string parameterName) where T : class
		{
			if (obj == null)
			{
				throw new ArgumentNullException(parameterName ?? "unknown_parameter");
			}
			return obj;
		}
	}
