	public interface IEventService
	{
		void InitFeatureGatingSubscription(IFeatureFlagManager featureFlagManager, ICoreAnalytics coreAnalytics);

		Task<TimedEvent> CreateAsync(string key, Dictionary<string, object> properties = null);

		Task LogAsync(string key);

		Task LogAsync(TimedEvent timedEvent);

		Task<TimedEvent> FetchEvent(string key);

		void AddWorkoutProperties(TimedEvent timedEvent, Workout workout);
	}
	public class EventService : IEventService
	{
		private static readonly Lazy<IEventService> _lazyInstance = new Lazy<IEventService>(() => new EventService());

		private List<TimedEvent> events = new List<TimedEvent>();

		private SemaphoreSlim listSemaphore = new SemaphoreSlim(1);

		private ICoreAnalytics coreAnalytics;

		private IFeatureFlagManager featureFlagManager;

		public static IEventService Instance
		{
			get
			{
				if (Mvx.TryResolve<IEventService>(out var service))
				{
					return service;
				}
				return _lazyInstance.Value;
			}
		}

		private EventService()
		{
		}

		public void InitFeatureGatingSubscription(IFeatureFlagManager featureFlagManager, ICoreAnalytics coreAnalytics)
		{
			this.featureFlagManager = featureFlagManager;
			this.coreAnalytics = coreAnalytics;
		}

		public async Task<TimedEvent> CreateAsync(string key, Dictionary<string, object> properties = null)
		{
			if (!FeatureEnabled())
			{
				return null;
			}
			TimedEvent timedEvent = new TimedEvent(key, properties);
			await AddEventToList(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
			return timedEvent;
		}

		public async Task LogAsync(string key)
		{
			TimedEvent timedEvent = await FetchEvent(key).ConfigureAwait(continueOnCapturedContext: false);
			if (timedEvent != null)
			{
				await LogAsync(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task LogAsync(TimedEvent timedEvent)
		{
			if (FeatureEnabled() && timedEvent != null)
			{
				await timedEvent.EndEvent().ConfigureAwait(continueOnCapturedContext: false);
				await SendEvent(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		public async Task<TimedEvent> FetchEvent(string key)
		{
			if (!FeatureEnabled())
			{
				return null;
			}
			try
			{
				await listSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				return events.FirstOrDefault((TimedEvent x) => x.Key == key);
			}
			finally
			{
				listSemaphore.Release();
			}
		}

		public void AddWorkoutProperties(TimedEvent timedEvent, Workout workout)
		{
			if (timedEvent != null && workout != null && FeatureEnabled() && coreAnalytics != null)
			{
				timedEvent.AddProperties(coreAnalytics.WorkoutProperties(workout));
			}
		}

		private async Task SendEvent(TimedEvent timedEvent)
		{
			if (timedEvent == null)
			{
				return;
			}
			if (coreAnalytics == null)
			{
				RetrySend(timedEvent);
			}
			else if (FeatureEnabled())
			{
				try
				{
					await coreAnalytics.PostEvent(timedEvent.Key, timedEvent.Properties).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (ArgumentException ex)
				{
					iFit.Logger.Log.Trace("Api", "TimedEvent: Failed adding properties to event: " + ex.Message, ex);
					await TrackEvent(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Api", "TimedEvent: Failed to send event to analytics", exception);
				}
				await ClearEventFromList(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task TrackEvent(TimedEvent timedEvent)
		{
			if (timedEvent == null)
			{
				return;
			}
			try
			{
				await coreAnalytics.Track(timedEvent.Key, timedEvent.Properties).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Api", "TimedEvent: Failed to send event to analytics", exception);
			}
		}

		private void RetrySend(TimedEvent timedEvent)
		{
			if (timedEvent != null)
			{
				Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(Observable.Timer(TimeSpan.FromSeconds(30.0)).Take(1), async delegate
				{
					await SendEvent(timedEvent).ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		private bool FeatureEnabled()
		{
			return featureFlagManager?.IsFeatureEnabled(FeatureFlags.LoadTimeAnalytics) ?? true;
		}

		private async Task AddEventToList(TimedEvent timedEvent)
		{
			if (!FeatureEnabled() || timedEvent == null)
			{
				return;
			}
			try
			{
				await listSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				events.RemoveAll((TimedEvent x) => x.Key == timedEvent.Key);
				events.Add(timedEvent);
			}
			finally
			{
				listSemaphore.Release();
			}
		}

		private async Task ClearEventFromList(TimedEvent timedEvent)
		{
			if (timedEvent == null)
			{
				return;
			}
			try
			{
				await listSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				events.RemoveAll((TimedEvent x) => x.Key == timedEvent.Key);
			}
			finally
			{
				listSemaphore.Release();
			}
		}
	}
	public interface IWorkoutPathoutService
	{
		bool IsWorkoutRunning { get; }

		Task StartAsync(Workout workout);

		Task FinishAsync(string reason, Dictionary<string, object> properties = null);

		Task TrackFromRecovery(string reason, Dictionary<string, object> properties = null);
	}
	public class TimedEvent
	{
		private const string StartKey = "startTime";

		private const string EndKey = "endTime";

		private const string DurationKey = "durationSeconds";

		private SemaphoreSlim eventSemaphore = new SemaphoreSlim(1);

		public Dictionary<string, object> Properties { get; private set; } = new Dictionary<string, object>();

		public DateTime Start { get; private set; }

		public DateTime End { get; private set; }

		public TimeSpan Duration => End.Subtract(Start);

		public string Key { get; private set; }

		internal TimedEvent(string key, Dictionary<string, object> properties)
		{
			Key = key;
			if (properties != null)
			{
				Properties = properties;
			}
			Start = DateTime.UtcNow;
		}

		internal async Task EndEvent()
		{
			await eventSemaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			End = DateTime.UtcNow;
			AddClassProperties();
			eventSemaphore.Release();
		}

		private void AddClassProperties()
		{
			if (!Properties.ContainsKey("startTime"))
			{
				Properties["startTime"] = Start;
			}
			if (!Properties.ContainsKey("endTime"))
			{
				Properties["endTime"] = End;
			}
			if (!Properties.ContainsKey("durationSeconds"))
			{
				Properties["durationSeconds"] = (int)Math.Round(Duration.TotalSeconds);
			}
		}
	}
	public class WorkoutPathoutService : IWorkoutPathoutService
	{
		public static class Reason
		{
			public const string Key = "pathoutReason";

			public const string Completed = "completed";

			public const string SignalCrash = "signalCrash";

			public const string Shutdown = "shutdown";

			public const string RecoveryParseFailed = "recoveryParseFailed";

			public const string Unknown = "unknown";

			public const string UserEndedEarly = "userEndedEarly";

			public const string UserEndedBeforeThresholds = "userEndedBeforeThresholds";

			public const string PauseScreenTimeout = "pauseScreenTimeout";

			public const string PauseScreenTimeoutInBackground = "pauseScreenTimeoutInBackground";

			public const string StoppedGettingControls = "stoppedGettingControls";

			public const string BleUserLeave = "userLeaveBLEDisconnect";

			public const string BleTimeout = "timeoutBLEDisconnect";

			public const string BleRadioDisabledException = "bleRadioDisabledException";

			public const string FailedToStart = "failedToStart";
		}

		private class WorkoutPathoutUnknownReasonException : Exception
		{
		}

		private const string EventWorkoutPathout = "EventWorkoutPathout";

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ICoreAnalytics coreAnalytics;

		private readonly ICrashReporter crashReporter;

		private readonly string multipleEventsExceptionMessage = "Can't have more than one event started for WorkoutPathoutService.";

		private readonly string eventIsNotStartedExceptionMessage = "Can't finish an event. It isn't started yet.";

		private readonly SemaphoreSlim semaphore = new SemaphoreSlim(1);

		private TimedEvent pathoutEvent;

		private bool FeatureEnabled => featureFlagManager?.IsFeatureEnabled(FeatureFlags.WorkoutPathoutAnalytics) ?? false;

		public bool IsWorkoutRunning => pathoutEvent != null;

		public WorkoutPathoutService(IFeatureFlagManager featureFlagManager, ICoreAnalytics coreAnalytics, ICrashReporter crashReporter)
		{
			this.featureFlagManager = featureFlagManager;
			this.coreAnalytics = coreAnalytics;
			this.crashReporter = crashReporter;
		}

		public async Task StartAsync(Workout workout)
		{
			if (!FeatureEnabled)
			{
				return;
			}
			try
			{
				await semaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (pathoutEvent != null)
				{
					iFit.Logger.Log.Warn("WorkoutPathoutService", multipleEventsExceptionMessage);
					return;
				}
				pathoutEvent = new TimedEvent("EventWorkoutPathout", null);
				AddWorkoutProperties(pathoutEvent, workout);
			}
			finally
			{
				semaphore.Release();
			}
		}

		public async Task FinishAsync(string reason, Dictionary<string, object> properties = null)
		{
			if (!FeatureEnabled)
			{
				pathoutEvent = null;
				return;
			}
			try
			{
				await semaphore.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
				if (pathoutEvent == null)
				{
					iFit.Logger.Log.Warn("WorkoutPathoutService", eventIsNotStartedExceptionMessage);
					return;
				}
				pathoutEvent.Properties["pathoutReason"] = reason;
				pathoutEvent.AddProperties(properties);
				Dictionary<string, object> analyticsData = pathoutEvent.Properties;
				pathoutEvent = null;
				await coreAnalytics.TrackWithGoogleAnalytics("EventWorkoutPathout", analyticsData, throwIfInvalid: false).ConfigureAwait(continueOnCapturedContext: false);
				if (coreAnalytics.IsSegmentEnabled)
				{
					await coreAnalytics.PostEvent("EventWorkoutPathout", analyticsData).ConfigureAwait(continueOnCapturedContext: false);
				}
				if (reason == "unknown")
				{
					throw new WorkoutPathoutUnknownReasonException();
				}
			}
			catch (WorkoutPathoutUnknownReasonException exception)
			{
				await crashReporter.ReportError("WorkoutPathoutService : Reason: " + reason, exception, properties);
			}
			catch (Exception exception2)
			{
				iFit.Logger.Log.Warn("Api", "TimedEvent: Failed to send event to analytics", exception2);
			}
			finally
			{
				semaphore.Release();
			}
		}

		public async Task TrackFromRecovery(string reason, Dictionary<string, object> properties = null)
		{
			if (!FeatureEnabled)
			{
				return;
			}
			try
			{
				if (properties == null)
				{
					properties = new Dictionary<string, object> { { "pathoutReason", reason } };
				}
				else
				{
					properties.TryAdd("pathoutReason", reason);
				}
				await coreAnalytics.TrackWithGoogleAnalytics("EventWorkoutPathout", properties, throwIfInvalid: false);
				if (coreAnalytics.IsSegmentEnabled)
				{
					await coreAnalytics.Track("EventWorkoutPathout", properties).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Warn("Api", "TimedEvent: Failed to send event to analytics", exception);
			}
		}

		private void AddWorkoutProperties(TimedEvent timedEvent, Workout workout)
		{
			if (timedEvent != null && workout != null && FeatureEnabled && coreAnalytics != null)
			{
				timedEvent.AddProperties(coreAnalytics.WorkoutProperties(workout));
			}
		}
	}
}
namespace Shire.Core.Util.EffortScore
{
	public interface IEffortScoreCalculator
	{
		bool EffortScoreEnabled { get; }

		double CalculateForCurrentTime(double calories);

		double CalculateForCurrentTime(double calories, double lycanLevel);

		bool ShouldCalculateEffortScore(ConsoleState consoleState);
	}
	public class EffortScoreCalculator : IEffortScoreCalculator
	{
		public const double DefaultLycanLevel = 0.4;

		public const double DefaultWeight = 85.0;

		public const double DefaultAge = 45.0;

		protected readonly IFitnessConsole console;

		protected readonly bool isManualWorkout;

		protected readonly bool leaderboardDataUploadEnabled;

		protected readonly User user;

		public bool EffortScoreEnabled
		{
			get
			{
				if (leaderboardDataUploadEnabled)
				{
					return !isManualWorkout;
				}
				return false;
			}
		}

		public bool ShouldCalculateEffortScore(ConsoleState consoleState)
		{
			if (EffortScoreEnabled)
			{
				return consoleState == ConsoleState.Workout;
			}
			return false;
		}

		public EffortScoreCalculator(User user, IFitnessConsole console, bool leaderboardDataUploadEnabled, bool isManualWorkout = false)
		{
			this.console = console;
			this.isManualWorkout = isManualWorkout;
			this.leaderboardDataUploadEnabled = leaderboardDataUploadEnabled;
			this.user = user;
		}

		public double CalculateForCurrentTime(double calories, double lycanLevel)
		{
			double num = ((double?)user?.Age) ?? 45.0;
			double num2 = user?.Weight ?? 85.0;
			double num3 = ((double?)console?.LatestBasicInfo?.RunningTime) ?? 0.0;
			double num4 = calories * 1000.0 / num3 / 5.0 / num2;
			double num5 = (num4 + 0.11666) * 60.0 * num2 / 10.8;
			double num6 = num5 * num3 / 3600.0 / num2;
			double num7 = num6 / lycanLevel * 50.0 + num3 * num / 1000.0;
			if (!double.IsNaN(num7))
			{
				return num7;
			}
			return 0.0;
		}

		public double CalculateForCurrentTime(double calories)
		{
			return CalculateForCurrentTime(calories, 0.4);
		}
	}
}
namespace Shire.Core.Util.DataSampling
{
	public static class DataSamplingExtensions
	{
		private static List<Tuple<TypeX, TypeY>> SampleDataAbstractly<TypeX, TypeY>(this IEnumerable<Tuple<TypeX, TypeY>> rawData, double toleranceRatioX, double toleranceRatioY, Func<TypeX, double, double> funcAdditionDoubleX, Func<TypeY, TypeY, double> funcSubtractionY, Func<IEnumerable<TypeX>, double> rangeFuncX, Func<IEnumerable<TypeY>, double> rangeFuncY) where TypeX : IComparable where TypeY : IComparable
		{
			List<Tuple<TypeX, TypeY>> list = (from p in rawData
				where p != null
				select new Tuple<TypeX, TypeY>(p.Item1, p.Item2)).ToList();
			if (toleranceRatioX <= 0.0 && toleranceRatioY <= 0.0)
			{
				return list;
			}
			if (toleranceRatioX >= 1.0)
			{
				throw new ArgumentOutOfRangeException("toleranceRatioX", "X axis tolerance ratio must be less than 1.");
			}
			if (toleranceRatioY >= 1.0)
			{
				throw new ArgumentOutOfRangeException("toleranceRatioY", "Y axis tolerance ratio must be less than 1.");
			}
			if ((rawData?.Count()).GetValueOrDefault() < 3)
			{
				return list;
			}
			if (list.Count < 3)
			{
				return list;
			}
			if (toleranceRatioX > 0.0)
			{
				double num = rangeFuncX(list.Select((Tuple<TypeX, TypeY> p) => p.Item1));
				double arg = num * toleranceRatioX;
				TypeX arg2 = list[0].Item1;
				for (int num2 = 1; num2 < list.Count - 1; num2++)
				{
					TypeX item = list[num2].Item1;
					if (item.CompareTo(funcAdditionDoubleX(arg2, arg)) < 0)
					{
						list[num2] = null;
					}
					else
					{
						arg2 = item;
					}
				}
				list.RemoveAll((Tuple<TypeX, TypeY> p) => p == null);
			}
			if (toleranceRatioY > 0.0)
			{
				double num3 = rangeFuncY(list.Select((Tuple<TypeX, TypeY> p) => p.Item2));
				double value = num3 * toleranceRatioY;
				for (int num4 = 1; num4 < list.Count; num4++)
				{
					Tuple<TypeX, TypeY> tuple = list[num4 - 1];
					Tuple<TypeX, TypeY> tuple2 = list[num4];
					if (Math.Abs(funcSubtractionY(tuple2.Item2, tuple.Item2)).CompareTo(value) < 0)
					{
						list[num4] = new Tuple<TypeX, TypeY>(tuple2.Item1, tuple.Item2);
					}
				}
			}
			return list;
		}

		public static List<Tuple<double, double>> SampleData(this IEnumerable<Tuple<double, double>> rawData, double toleranceRatioX, double toleranceRatioY)
		{
			return rawData.SampleDataAbstractly(toleranceRatioX, toleranceRatioY, (double d1, double d2) => d1 + d2, (double d1, double d2) => d1 - d2, (IEnumerable<double> points) => Math.Abs(points.Max() - points.Min()), (IEnumerable<double> points) => Math.Abs(points.Max() - points.Min()));
		}

		public static List<Tuple<float, float>> SampleData(this IEnumerable<Tuple<float, float>> rawData, double toleranceRatioX, double toleranceRatioY)
		{
			return rawData.SampleDataAbstractly(toleranceRatioX, toleranceRatioY, (float d1, double d2) => (double)d1 + d2, (float d1, float d2) => d1 - d2, (IEnumerable<float> points) => Math.Abs(points.Max() - points.Min()), (IEnumerable<float> points) => Math.Abs(points.Max() - points.Min()));
		}

		public static List<Tuple<int, int>> SampleData(this IEnumerable<Tuple<int, int>> rawData, double toleranceRatioX, double toleranceRatioY)
		{
			return rawData.SampleDataAbstractly(toleranceRatioX, toleranceRatioY, (int d1, double d2) => (double)d1 + d2, (int d1, int d2) => d1 - d2, (IEnumerable<int> points) => Math.Abs(points.Max() - points.Min()), (IEnumerable<int> points) => Math.Abs(points.Max() - points.Min()));
		}

		public static List<Tuple<long, long>> SampleData(this IEnumerable<Tuple<long, long>> rawData, double toleranceRatioX, double toleranceRatioY)
		{
			return rawData.SampleDataAbstractly(toleranceRatioX, toleranceRatioY, (long d1, double d2) => (double)d1 + d2, (long d1, long d2) => d1 - d2, (IEnumerable<long> points) => Math.Abs(points.Max() - points.Min()), (IEnumerable<long> points) => Math.Abs(points.Max() - points.Min()));
		}

