		{
			return rawData.SampleDataAbstractly(toleranceRatioX, toleranceRatioY, (double d1, double d2) => d1 + d2, (int d1, int d2) => d1 - d2, (IEnumerable<double> points) => Math.Abs(points.Max() - points.Min()), (IEnumerable<int> points) => Math.Abs(points.Max() - points.Min()));
		}

