namespace Shire.Core.Util.CreditCard
{
	internal class BrandInfo
	{
		public List<Rule> Rules { get; set; }

		public string BrandName { get; set; }

		public bool SkipLuhn { get; set; }

		public BrandInfo()
		{
			Rules = new List<Rule>();
			BrandName = "Unknown";
			SkipLuhn = false;
		}
	}
	public class CreditCardDetector
	{
		public string CardNumber { get; private set; }

		public CardIssuer Brand { get; private set; }

		public string BrandName { get; private set; }

		public string IssuerCategory => MajorIndustryIdentifier.Categories[Convert.ToInt32(CardNumber[0].ToString())];

		public CreditCardDetector(string cardNumber)
		{
			if (!ValidationHelper.IsAValidNumber(cardNumber))
			{
				throw new ArgumentException("Invalid number. Just numbers and white spaces are accepted on the string.");
			}
			CardNumber = cardNumber.RemoveWhiteSpace();
			LoadCard();
		}

		private void LoadCard()
		{
			foreach (KeyValuePair<CardIssuer, BrandInfo> brandsDatum in CreditCardData.BrandsData)
			{
				BrandInfo value = brandsDatum.Value;
				foreach (Rule rule in value.Rules)
				{
					if (rule.Lengths.Any((int c) => c == CardNumber.Length) && rule.Prefixes.Any(CardNumber.StartsWith))
					{
						Brand = brandsDatum.Key;
						BrandName = value.BrandName;
						return;
					}
				}
			}
			Brand = CardIssuer.Unknown;
			BrandName = CardIssuer.Unknown.ToString();
		}

		public bool IsValid()
		{
			if (!CreditCardData.BrandsData[Brand].SkipLuhn)
			{
				return Luhn.CheckLuhn(CardNumber);
			}
			return true;
		}

		public bool IsValid(params CardIssuer[] issuers)
		{
			return issuers.Any((CardIssuer issuer) => issuer == Brand && IsValid());
		}
	}
	public static class CreditCardFactory
	{
		private static readonly Random RandomNumber = new Random();

		public static string RandomCardNumber(CardIssuer brand)
		{
			StringBuilder stringBuilder = new StringBuilder();
			Rule rule = CreditCardData.BrandsData[brand].Rules.First();
			if (brand != CardIssuer.Unknown)
			{
				stringBuilder.Append(rule.Prefixes[RandomNumber.Next(0, rule.Prefixes.Count)]);
			}
			int length = stringBuilder.Length;
			for (int i = 0; i < rule.Lengths.First() - 1 - length; i++)
			{
				stringBuilder.Append(RandomNumber.Next(0, 10));
			}
			stringBuilder.Append(Luhn.CreateCheckDigit(stringBuilder.ToString()));
			return stringBuilder.ToString();
		}
	}
