	public static class Luhn
	{
		private static readonly Func<char, int> CharToInt = (char c) => c - 48;

		private static readonly Func<int, bool> IsEven = (int i) => i % 2 == 0;

		private static readonly Func<int, int> DoubleDigit = (int i) => (i * 2).ToString().ToCharArray().Select(CharToInt)
			.Sum();

		public static bool CheckLuhn(string creditCardNumber)
		{
			if (!ValidationHelper.IsAValidNumber(creditCardNumber))
			{
				throw new ArgumentException("Invalid number. Just numbers and white spaces are accepted on the string.");
			}
			int num = creditCardNumber.RemoveWhiteSpace().ToCharArray().Select(CharToInt)
				.Reverse()
				.Select((int digit, int index) => (!IsEven(index + 1)) ? digit : DoubleDigit(digit))
				.Sum();
			return num % 10 == 0;
		}

		public static string CreateCheckDigit(string number)
		{
			if (!ValidationHelper.IsAValidNumber(number))
			{
				throw new ArgumentException("Invalid number. Just numbers and white spaces are accepted on the string.");
			}
			int num = Enumerable.Reverse(number.RemoveWhiteSpace().ToCharArray()).Select(CharToInt).Select((int digit, int index) => (!IsEven(index)) ? digit : DoubleDigit(digit))
				.Sum();
			return (num * 9).ToString().ToCharArray().Last()
				.ToString();
		}
	}
