namespace Shire.Core.PresentationFilters
{
	public interface IPresentationFilter
	{
		MvxViewModelRequest OnShowing(MvxViewModelRequest request);

		void OnClosing(ShireBaseViewModel viewModel);
	}
	public abstract class BaseViewModelPresentationFilter : IPresentationFilter
	{
		public virtual void OnClosing(ShireBaseViewModel viewModel)
		{
		}

		public virtual MvxViewModelRequest OnShowing(MvxViewModelRequest request)
		{
			return request;
		}
	}
	public interface IPresentationFilterCache
	{
		void RegisterPresentationFilters(IEnumerable<Type> types);

		IEnumerable<IPresentationFilter> RetrieveFiltersForType(Type type);
	}
	public class PresentationFilterCache : IPresentationFilterCache
	{
		private readonly List<Type> globalFilterCache = new List<Type>();

		private readonly Dictionary<Type, List<Type>> filterCache = new Dictionary<Type, List<Type>>();

		public void RegisterPresentationFilters(IEnumerable<Type> types)
		{
			Type[] array = types.Where((Type x) => ImplementsPresentationFilter(x) && IsValidClass(x)).ToArray();
			Type[] array2 = array;
			foreach (Type type in array2)
			{
				TypeInfo typeInfo = type.GetTypeInfo();
				ViewModelPresentationFilterAttribute[] array3 = typeInfo.GetCustomAttributes(typeof(ViewModelPresentationFilterAttribute), inherit: true).Cast<ViewModelPresentationFilterAttribute>().ToArray();
				if (array3.Length != 0)
				{
					foreach (Type item in array3.SelectMany((ViewModelPresentationFilterAttribute x) => x.ViewModelTypes))
					{
						if (!filterCache.ContainsKey(item))
						{
							filterCache.Add(item, new List<Type>());
						}
						filterCache[item].Add(type);
					}
				}
				else
				{
					globalFilterCache.Add(type);
				}
				Mvx.RegisterType(type, type);
			}
			static bool ImplementsPresentationFilter(Type c)
			{
				return typeof(BaseViewModelPresentationFilter).IsAssignableFrom(c);
			}
			static bool IsValidClass(Type type2)
			{
				TypeInfo typeInfo2 = type2.GetTypeInfo();
				bool isClass = typeInfo2.IsClass;
				bool flag = !typeInfo2.IsAbstract;
				return isClass && flag;
			}
		}

		public IEnumerable<IPresentationFilter> RetrieveFiltersForType(Type type)
		{
			IEnumerable<Type> enumerable = globalFilterCache.AsEnumerable();
			if (filterCache.ContainsKey(type))
			{
				enumerable = enumerable.Concat(filterCache[type]);
			}
			foreach (Type item in enumerable)
			{
				if (Mvx.Resolve(item) is IPresentationFilter presentationFilter)
				{
					yield return presentationFilter;
				}
			}
		}
	}
	public interface IPresentationFilterResolver
	{
		MvxViewModelRequest OnShowing(MvxViewModelRequest request);

		void OnClosing(ShireBaseViewModel whichViewModel);
	}
	public class PresentationFilterResolver : IPresentationFilterResolver
	{
		private readonly IPresentationFilterCache cache;

		public PresentationFilterResolver(IPresentationFilterCache cache)
		{
			this.cache = cache;
		}

		public MvxViewModelRequest OnShowing(MvxViewModelRequest request)
		{
			IEnumerable<IPresentationFilter> enumerable = cache.RetrieveFiltersForType(request.ViewModelType);
			foreach (IPresentationFilter item in enumerable)
			{
				Type viewModelType = request.ViewModelType;
				request = item.OnShowing(request);
				if (viewModelType != request.ViewModelType)
				{
					request = OnShowing(request);
					break;
				}
			}
			return request;
		}

		public void OnClosing(ShireBaseViewModel whichViewModel)
		{
			if (whichViewModel == null)
			{
				return;
			}
			IEnumerable<IPresentationFilter> enumerable = cache.RetrieveFiltersForType(whichViewModel.GetType());
			foreach (IPresentationFilter item in enumerable)
			{
				item.OnClosing(whichViewModel);
			}
		}
	}
	[AttributeUsage(AttributeTargets.Class)]
	public class ViewModelPresentationFilterAttribute : Attribute
	{
		public Type[] ViewModelTypes { get; }

		public ViewModelPresentationFilterAttribute(params Type[] viewModelTypes)
		{
			ViewModelTypes = viewModelTypes;
		}
	}
