				}
				return false;
			}
		}

		public bool HasEverSuccessfullyConnected { get; protected set; }

		public abstract bool IsConnected { get; }

		protected bool VerboseOutput => featureFlagManager.IsFeatureEnabled(FeatureFlags.LogMQTTVerbose);

		private int PayloadLoggingInterval => featureFlagManager.GetInt(FeatureFlags.LogMQTTPayloadInterval, 10);

