	public class AudioServiceUnhandledError
	{
		public const string ParsingErrorType = "PARSING_ERROR";

		public const int NoCode = -1;

		public const int ParsingErrorCode = -2;

		public const int NoStatus = -1;

		public Exception Exception { get; }

		public string Type { get; set; }

		public int Code { get; set; }

		public string Message { get; set; }

		public int Status { get; set; }

		public bool IsKnownError { get; set; }

		public static AudioServiceUnhandledError FromAndroidException(Exception ex)
		{
			AudioServiceUnhandledError audioServiceUnhandledError = new AudioServiceUnhandledError(ex);
			string text = ex.ToString();
			try
			{
				int num = text.IndexOf("java.lang.Exception: {", StringComparison.InvariantCulture);
				if (num > 0)
				{
					num += "java.lang.Exception: {".Length + 1;
					text = text.Substring(num);
					string value = Regex.Match(text, "type: \"[^\"]*\"").Value;
					int num2 = value.IndexOf("\"", StringComparison.InvariantCulture) + 1;
					audioServiceUnhandledError.Type = value.Substring(num2, value.Length - 1 - num2);
					string s = Regex.Match(text, "code: \\d+").Value.Substring("code: ".Length);
					audioServiceUnhandledError.Code = int.Parse(s);
					string value2 = Regex.Match(text, "message: \"[^\"]*\"").Value;
					int num3 = value2.IndexOf("\"", StringComparison.InvariantCulture) + 1;
					audioServiceUnhandledError.Message = value2.Substring(num3, value2.Length - 1 - num3);
					string s2 = Regex.Match(text, "status: \\d+").Value.Substring("status: ".Length);
					audioServiceUnhandledError.Status = int.Parse(s2);
				}
				else
				{
					string value3 = Regex.Match(text, "java.lang.Exception: .*").Value;
					string message = (audioServiceUnhandledError.Type = value3.Substring("java.lang.Exception: ".Length));
					audioServiceUnhandledError.Code = -1;
					audioServiceUnhandledError.Message = message;
					audioServiceUnhandledError.Status = -1;
				}
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Audio", "Error parsing data from FeedException for string " + text);
				audioServiceUnhandledError.Type = "PARSING_ERROR";
				audioServiceUnhandledError.Code = -2;
				audioServiceUnhandledError.Message = $"Couldn't parse data from FeedException. Parsing exception: {arg}";
				audioServiceUnhandledError.Status = -1;
			}
			return audioServiceUnhandledError;
		}

		public AudioServiceUnhandledError(Exception exception)
		{
			Exception = exception;
		}
	}
