		public static bool IsMetadataEqual(AudioTrack audioTrack1, AudioTrack audioTrack2)
		{
			if (audioTrack1 == null || audioTrack2 == null)
			{
				return false;
			}
			if (audioTrack1 == audioTrack2)
			{
				return true;
			}
			if (audioTrack1.Title == audioTrack2.Title && audioTrack1.Artist == audioTrack2.Artist)
			{
				return audioTrack1.Album == audioTrack2.Album;
			}
			return false;
		}
	}
