	public abstract class FeedFmService : IAudioService, IDisposable
	{
		protected const float DefaultCrossfadeTimeSeconds = 1f;

		private const int MaxDmcaExceptions = 3;

		private ConsoleState currentConsoleState;

		protected BehaviorSubject<MusicState> playerStateChanged = new BehaviorSubject<MusicState>(MusicState.Uninitialized);

		protected Subject<string> playerAvailable = new Subject<string>();

		protected Subject<AudioPlayerStation> stationChanged = new Subject<AudioPlayerStation>();

		protected Subject<AudioTrack> playStarted = new Subject<AudioTrack>();

		protected Subject<bool> skipCompleted = new Subject<bool>();

		protected Subject<bool> skipRequested = new Subject<bool>();

		protected Subject<bool> instantPlaybackReady = new Subject<bool>();

		protected Subject<bool> stationOutOfMusic = new Subject<bool>();

		protected Subject<bool> cachePrepared = new Subject<bool>();

		protected Subject<AudioServiceUnhandledError> unhandledErrorOccurred = new Subject<AudioServiceUnhandledError>();

		protected BehaviorSubject<bool> skipStatusChanged = new BehaviorSubject<bool>(value: false);

		protected Subject<string> clientIdCreated = new Subject<string>();

		protected Subject<(AudioTrack track, float elapsedTime, float duration)> playerProgressUpdated = new Subject<(AudioTrack, float, float)>();

		private IDisposable whenConsoleStateChanged;

		protected IIfitApiService ifitApiService;

		protected readonly IFeedFmAvailabilityService feedFmAvailabilityService;

		protected readonly ICurrentConsoleService currentConsoleService;

		protected readonly IWifiService wifiService;

		public abstract string ClientId { get; }

		public MusicState ActiveState
		{
			get
			{
				if (!wifiService.IsWifiEnabled || wifiService.InNetworkStateWithoutConnectivity())
				{
					return MusicState.Unavailable;
				}
				try
				{
					return playerStateChanged.Value;
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Audio", "Getting ActiveState threw an exception. Returning Unavailable.", exception);
					return MusicState.Unavailable;
				}
			}
			protected set
			{
				playerStateChanged.OnNext(value);
			}
		}

		protected bool ShouldMutePlayerRatherThanPause
		{
			get
			{
				AudioPlayerStation activeStation = ActiveStation;
				if (activeStation != null && activeStation.FirstPlay && IsWorkoutContextScheduled)
				{
					return currentConsoleState.IsRunningState();
				}
				return false;
			}
		}

		public abstract AudioPlayerStation ActiveStation { get; }

		public abstract AudioTrack ActiveTrack { get; }

		public int MaxBitrate { get; }

		public int NumDmcaExceptions { get; private set; }

		public abstract bool CanSkip { get; }

		public abstract List<AudioTrack> PlayHistory { get; }

		public abstract List<AudioPlayerStation> Stations { get; }

		public bool IsPlaying => WhenPlayerStateChanged.FirstAsync((MusicState x) => x == MusicState.Playing) != null;

		public bool IsDisposed { get; private set; }

		protected bool IsWorkoutContextScheduled { get; private set; }

		protected ILockScreenMediaSettings LockScreenMediaSettings { get; }

		public BehaviorSubject<PauseMusicType> PauseTypeChanged { get; set; } = new BehaviorSubject<PauseMusicType>(PauseMusicType.None);

		public IObservable<MusicState> WhenPlayerStateChanged => playerStateChanged;

		public IObservable<PauseMusicType> WhenPauseStateChanged => PauseTypeChanged;

		public IObservable<string> WhenPlayerAvailable => playerAvailable;

		public IObservable<AudioPlayerStation> WhenStationChanged => stationChanged;

		public IObservable<AudioTrack> WhenPlayStarted => playStarted;

		public IObservable<bool> WhenSkipCompleted => skipCompleted;

		public IObservable<bool> WhenSkipRequested => skipRequested;

		public IObservable<bool> WhenInstantPlaybackReady => instantPlaybackReady;

		public IObservable<bool> WhenStationOutOfMusic => stationOutOfMusic;

		public IObservable<AudioServiceUnhandledError> WhenUnhandledErrorOccurred => unhandledErrorOccurred;

		public IObservable<bool> WhenCanSkipStatusChanged => skipStatusChanged;

		public IObservable<string> WhenClientIdCreated => clientIdCreated;

		public IObservable<bool> WhenCachePrepared => cachePrepared;

		public IObservable<(AudioTrack track, float elapsedTime, float duration)> WhenPlayerProgressUpdated => playerProgressUpdated;

		protected FeedFmService(IIfitApiService ifitApiService, ILockScreenMediaSettings lockScreenMediaSettings, IFeedFmAvailabilityService feedFmAvailabilityService, ICurrentConsoleService currentConsoleService, IWifiService wifiService)
		{
			this.ifitApiService = ifitApiService;
			this.feedFmAvailabilityService = feedFmAvailabilityService;
			this.currentConsoleService = currentConsoleService;
			this.wifiService = wifiService;
			LockScreenMediaSettings = lockScreenMediaSettings;
		}

		public abstract void Play();

		public bool ChangeToStationWithId(string id)
		{
			return ChangeToStationWithId(id, 0f);
		}

		public abstract bool ChangeToStationWithId(string id, float startAt);

		public abstract void Stop();

		public abstract void Pause(PauseMusicType pauseMusicType = PauseMusicType.PausedManually);

		public abstract void SetVolume(float volume);

		public abstract void Seek();

		public abstract void Skip();

		public abstract void Like();

		public abstract void Dislike();

		public abstract void Unlike();

		public abstract void UpdateSession();

		public async Task<bool> QueueStationWithId(string stationId, CancellationToken cancellationToken = default(CancellationToken))
		{
			return await QueueStationWithId(stationId, 0f, cancellationToken).ConfigureAwait(continueOnCapturedContext: false);
		}

		public abstract Task<bool> QueueStationWithId(string stationId, float startAt, CancellationToken cancellationToken = default(CancellationToken));

		public virtual void Init(string clientId = null)
		{
			WhenUnhandledErrorOccurred.Where((AudioServiceUnhandledError error) => error.Exception.Message != null && error.Exception.Message.Contains("dmca", StringComparison.OrdinalIgnoreCase)).SubscribeWithErrorLogging(delegate
			{
				HandleDmcaRestriction();
			});
			whenConsoleStateChanged = currentConsoleService.ActiveConsole.WhenStateChanged.SubscribeWithErrorLogging(delegate(StateChange x)
			{
				currentConsoleState = ((x.Current == ConsoleState.Paused) ? x.Old : x.Current);
			});
			currentConsoleState = (currentConsoleService?.ActiveConsole?.LatestBasicInfo?.CurrentState).GetValueOrDefault();
		}

		public void LiveWorkoutStarting()
		{
			ActiveState = MusicState.Loading;
		}

		private void HandleDmcaRestriction()
		{
			if (CanSkip && NumDmcaExceptions < 3)
			{
				NumDmcaExceptions++;
				iFit.Logger.Log.Error("Audio", $"DMCA exception count: {NumDmcaExceptions}, skipping track.");
				Skip();
			}
			else
			{
				NumDmcaExceptions = 0;
				iFit.Logger.Log.Error("Audio", "Max number of DMCA exceptions reached, stopping player.");
				Stop();
			}
		}

