		Task HandleAudioServiceActiveState();
	}
	public class MusicStateService : IMusicStateService, IDisposable
	{
		private MusicState lastState = MusicState.Uninitialized;

		private IAudioService feedFm;

		private IDisposable feedFmServiceStateChanged;

		private IDisposable feedFmServicePauseStateChanged;

		private const int RetryCount = 5;

		private const int RetryDelayMillis = 200;

		public Func<Task> OnPlayingAsync { get; set; }

		public Func<Task> OnPausedAsync { get; set; }

		public Func<Task> OnStoppedAsync { get; set; }

		public Func<Task> OnReadyAsync { get; set; }

		public Func<Task> OnLoadingAsync { get; set; }

		public async Task Init(IAudioService audioService)
		{
			feedFm = audioService;
			feedFmServiceStateChanged?.Dispose();
			MusicStateService musicStateService = this;
			IAudioService audioService2 = feedFm;
			object obj;
			if (audioService2 == null)
			{
				obj = null;
			}
			else
			{
				IObservable<MusicState> whenPlayerStateChanged = audioService2.WhenPlayerStateChanged;
				obj = ((whenPlayerStateChanged != null) ? iFit.CrashReporter.ObservableExtensions.SubscribeAsyncWithErrorLogging(whenPlayerStateChanged, HandleAudioServiceStateChanges) : null);
			}
			musicStateService.feedFmServiceStateChanged = (IDisposable)obj;
			feedFmServicePauseStateChanged?.Dispose();
			MusicStateService musicStateService2 = this;
			IAudioService audioService3 = feedFm;
			object obj2;
			if (audioService3 == null)
			{
				obj2 = null;
			}
			else
			{
				IObservable<PauseMusicType> whenPauseStateChanged = audioService3.WhenPauseStateChanged;
				obj2 = ((whenPauseStateChanged != null) ? iFit.CrashReporter.ObservableExtensions.SubscribeAsyncWithErrorLogging(whenPauseStateChanged, HandlePauseStateChanges) : null);
			}
			musicStateService2.feedFmServicePauseStateChanged = (IDisposable)obj2;
		}

		public async Task HandleAudioServiceActiveState()
		{
			PolicyResult<MusicState> policyResult = Policy.Handle<Exception>().WaitAndRetry(5, (int _) => TimeSpan.FromMilliseconds(200.0)).ExecuteAndCapture((Func<MusicState>)RetrieveFeedFmState);
			MusicState state = ((policyResult.Outcome == OutcomeType.Successful) ? policyResult.Result : MusicState.Uninitialized);
			await HandleAudioServiceStateChanges(state);
		}

		private MusicState RetrieveFeedFmState()
		{
			return feedFm.ActiveState;
		}

		private async Task HandlePauseStateChanges(PauseMusicType pauseMusicType)
		{
			MusicState musicState = lastState;
			if ((uint)(musicState - 5) <= 3u || musicState == MusicState.Ready)
			{
				await OnPausedAsync();
			}
		}

		private async Task HandleAudioServiceStateChanges(MusicState state)
		{
			lastState = state;
			switch (state)
			{
			case MusicState.Stopped:
				await OnStoppedAsync();
				break;
			case MusicState.PausedManually:
			case MusicState.PausedForMusicRegion:
			case MusicState.PausedByHeadphoneRemoval:
			case MusicState.PausedDisabled:
				await OnPausedAsync();
				break;
			case MusicState.Playing:
				await OnPlayingAsync();
				break;
			case MusicState.Ready:
				await OnReadyAsync();
				break;
			case MusicState.Loading:
			case MusicState.Stalled:
			case MusicState.Waiting:
				await OnLoadingAsync();
				break;
			case MusicState.Available:
			case MusicState.Unavailable:
			case MusicState.Uninitialized:
			case MusicState.Off:
				await OnStoppedAsync();
				break;
			case MusicState.AvailableOfflineOnly:
			case MusicState.Complete:
			case MusicState.Idle:
			case MusicState.RequestingSkip:
				break;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}

		protected void Dispose(bool disposing)
		{
			if (disposing)
			{
				feedFmServiceStateChanged?.Dispose();
				feedFmServiceStateChanged = null;
				feedFmServicePauseStateChanged?.Dispose();
				feedFmServicePauseStateChanged = null;
			}
		}
	}
