		protected async Task CreateOrUpdateStartMarker(iFit.Api.Google.LatLng location)
		{
			if (StartPointMarker != null)
			{
				StartPointMarker.Location = location;
			}
			else if (StartMarkerIconBytes != null)
			{
				StartPointMarker = await AddMarker(location, StartMarkerIconBytes, StartMarkerIsVisible, StartIconXAnchor, StartIconYAnchor);
			}
			else
			{
				StartPointMarker = await AddMarker(location);
			}
		}

		protected async Task CreateOrUpdateEndMarker(iFit.Api.Google.LatLng location)
		{
			if (EndPointMarker != null)
			{
				EndPointMarker.Location = location;
				if (IsStartMarker(location.Lat, location.Lng))
				{
					StartPointMarker.IsVisible = false;
				}
				else if (!StartPointMarker.IsVisible && StartMarkerIsVisible)
				{
					StartPointMarker.IsVisible = true;
				}
			}
			else if (EndMarkerIconBytes != null)
			{
				EndPointMarker = await AddMarker(location, EndMarkerIconBytes, EndMarkerIsVisible, EndIconXAnchor, EndIconYAnchor);
			}
			else
			{
				EndPointMarker = await AddMarker(location);
			}
		}

		protected async Task<List<iFit.Api.Google.LatLng>> AddInSnappedToRoadSegments(List<iFit.Api.Google.LatLng> route)
		{
			if (route.Count < 1)
			{
				return route;
			}
			List<iFit.Api.Google.LatLng> resultList = new List<iFit.Api.Google.LatLng>();
			iFit.Api.Google.LatLng previousPoint = route[0];
			foreach (iFit.Api.Google.LatLng point in route)
			{
				if (point.SnappedToRoad)
				{
					List<iFit.Api.Google.LatLng> list = await GetRouteFromTwoPoints(previousPoint, point);
					if (list.Count == 0)
					{
						continue;
					}
					resultList.AddRange(list);
				}
				else
				{
					resultList.Add(point);
				}
				previousPoint = point;
			}
			return resultList;
		}

		protected async Task<List<iFit.Api.Google.LatLng>> GetRouteFromTwoPoints(iFit.Api.Google.LatLng start, iFit.Api.Google.LatLng end)
		{
			List<iFit.Api.Google.LatLng> directionRoute = new List<iFit.Api.Google.LatLng>();
			if (PointDistance(start, end) < 1.0)
			{
				iFit.Logger.Log.Trace("DrawMap", "Distance between points is less than 1 meter, ignoring add...");
				return directionRoute;
			}
			try
			{
				directionRoute.AddRange(Directions.GetRouteFromDirections(await Directions.Get(api, start.ToString(), end.ToString())));
				if (directionRoute.Count >= 2)
				{
					if (directionRoute.Last().Equals(end))
					{
						directionRoute.Remove(directionRoute.Last());
					}
					directionRoute.Add(end);
				}
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Trace("DrawMap", "Exception thrown getting directions", ex.GetBaseException());
			}
			return directionRoute;
		}

		private double PointDistance(iFit.Api.Google.LatLng start, iFit.Api.Google.LatLng end)
		{
			IList<iFit.Api.Google.LatLng> points = new List<iFit.Api.Google.LatLng> { start, end };
			return Polyline.PolylineMeters(points);
		}

		public void CenterMapFromRoute()
		{
			RouteBounds.UpdateBounds(RoutePoints);
			UpdateMapCenter(RouteBounds.CenterPoint);
		}

		public bool IsStartMarker(double latitude, double longitude)
		{
			iFit.Api.Google.LatLng location = StartPointMarker.Location;
			if (location.Lat.AlmostEqual(latitude, 1E-06))
			{
				return location.Lng.AlmostEqual(longitude, 1E-06);
			}
			return false;
		}

		public async Task<IMarker> AddMarker(iFit.Api.Google.LatLng location, string iconUrl = null, bool isVisible = true, float xAnchor = 0.5f, float yAnchor = 1f)
		{
