			}
			return await AddMarker(location, iconBytes, isVisible, xAnchor, yAnchor);
		}

		public async Task<IMarker> AddMarker(iFit.Api.Google.LatLng location, byte[] iconBytes, bool isVisible = true, float xAnchor = 0.5f, float yAnchor = 1f)
		{
			iFit.Api.Google.LatLng point = location.Copy();
			IMarker marker = AddMarkerNative(point, iconBytes, isVisible);
			if (marker?.Id != null)
			{
				if (Markers.ContainsKey(marker.Id))
				{
					Markers[marker.Id] = marker;
				}
				await marker.SetIcon(iconBytes, xAnchor, yAnchor);
			}
			return marker;
		}

		public void RemoveMarker(IMarker marker)
		{
			if (marker != null && marker.Id != null && Markers.ContainsKey(marker.Id))
			{
				Markers.Remove(marker.Id);
			}
			marker?.RemoveMarkerNative();
		}

