		private void CheckMaxDistanceForNewRoute(IList<iFit.Api.Google.LatLng> route)
		{
			double num = Polyline.PolylineMeters(route);
			if (num > 201168.0)
			{
				updatingRoute = false;
				throw new MaxWorkoutDistanceExceededException();
			}
		}

		public async Task<bool> AddRoutePoint(iFit.Api.Google.LatLng point)
		{
			if (updatingRoute)
			{
				return true;
			}
			updatingRoute = true;
			try
			{
				point.SnappedToRoad = RoadSnapOn;
				if (point.SnappedToRoad && RoutePoints.Count > 0)
				{
					List<iFit.Api.Google.LatLng> list = await GetRouteFromTwoPoints(RoutePoints.LastOrDefault(), point);
					if (list.Count == 0)
					{
						return false;
					}
					List<iFit.Api.Google.LatLng> list2 = list.DistinctBy((iFit.Api.Google.LatLng c) => c.Lat).DistinctBy((iFit.Api.Google.LatLng b) => b.Lng).ToList();
					list = list2;
					CheckMaxDistanceForNewRoute(RoutePoints.Concat(list).ToList());
					RoutePoints.AddRange(list);
					ManuallyAddedPoints.Add(point);
					AddManyRoutePoints(list);
				}
				else
				{
					CheckMaxDistanceForNewRoute(RoutePoints.Concat(new iFit.Api.Google.LatLng[1] { point }).ToList());
					RoutePoints.Add(point);
					ManuallyAddedPoints.Add(point);
					AddNoSnapRoutePoint(point);
				}
				List<Task> list3 = new List<Task>();
				if (RoutePoints.Count > 0)
				{
					Task item = CreateOrUpdateStartMarker(RoutePoints.First());
					list3.Add(item);
				}
				if (RoutePoints.Count > 1)
				{
					Task item2 = CreateOrUpdateEndMarker(RoutePoints.Last());
					list3.Add(item2);
				}
				await Task.WhenAll(list3);
			}
			catch (Exception ex) when (!(ex is MaxWorkoutDistanceExceededException))
			{
				iFit.Logger.Log.Trace("DrawMap", "Exception adding route point", ex.GetBaseException());
				return false;
			}
			finally
			{
				updatingRoute = false;
			}
			return true;
		}

		public async Task SetRoute(List<iFit.Api.Google.LatLng> route)
		{
			List<iFit.Api.Google.LatLng> range = await AddInSnappedToRoadSegments(route);
			RoutePoints.Clear();
			RoutePoints.AddRange(range);
			ManuallyAddedPoints.Clear();
			if (RoutePoints.Count > 0)
			{
				await CreateOrUpdateStartMarker(RoutePoints.First());
			}
			if (RoutePoints.Count > 1)
			{
				await CreateOrUpdateEndMarker(RoutePoints.Last());
			}
			SetRouteNative(RoutePoints);
		}

		public virtual void RemoveLastRoutePoint()
		{
			if (updatingRoute)
			{
				return;
			}
			updatingRoute = true;
			if (ManuallyAddedPoints.Count < 1)
			{
				return;
			}
			iFit.Api.Google.LatLng item = ManuallyAddedPoints.Last();
			ManuallyAddedPoints.Remove(item);
			if (ManuallyAddedPoints.Count < 2)
			{
				RoutePoints.Clear();
				RoutePoints.AddRange(ManuallyAddedPoints);
			}
			else
			{
				List<iFit.Api.Google.LatLng> list = RoutePoints.ToList();
				int num = list.LastIndexOf(ManuallyAddedPoints.Last());
				if (num > -1)
				{
					list.RemoveRange(num + 1, list.Count - num - 1);
					RoutePoints.ReplaceItems(list);
				}
			}
			if (RoutePoints.Count < 1)
			{
				if (StartPointMarker != null)
				{
					StartPointMarker.RemoveMarkerNative();
					StartPointMarker = null;
				}
				if (EndPointMarker != null)
				{
					EndPointMarker.RemoveMarkerNative();
					EndPointMarker = null;
				}
			}
			else if (RoutePoints.Count == 1)
			{
				if (StartPointMarker != null)
				{
					StartPointMarker.IsVisible = StartMarkerIsVisible;
				}
				if (EndPointMarker != null)
				{
					EndPointMarker.RemoveMarkerNative();
					EndPointMarker = null;
				}
			}
			else
			{
				if (EndPointMarker != null)
				{
					EndPointMarker.IsVisible = EndMarkerIsVisible;
					EndPointMarker.Location = RoutePoints.Last();
				}
				if (StartPointMarker != null)
				{
					if (EndPointMarker != null && StartPointMarker.Location.Lat.AlmostEqual(EndPointMarker.Location.Lat, 1E-06) && StartPointMarker.Location.Lng.AlmostEqual(EndPointMarker.Location.Lng, 1E-06))
					{
						StartPointMarker.IsVisible = false;
					}
					else
					{
						StartPointMarker.IsVisible = StartMarkerIsVisible;
					}
				}
			}
			SetRouteNative(RoutePoints);
			updatingRoute = false;
		}

		public virtual async Task CloseRouteLoop()
		{
			if (RoutePoints.Count >= 2 && RoutePoints.First().IsAtLeastXMetersAway(RoutePoints.Last(), 1.5))
			{
				iFit.Api.Google.LatLng latLng = RoutePoints.First().Copy();
				latLng.SnappedToRoad = RoadSnapOn;
				await AddRoutePoint(latLng);
			}
		}

		public virtual void ClearRoute()
		{
			RoutePoints.RemoveRange(0, RoutePoints.Count);
			ClearRouteNative();
			StartPointMarker?.RemoveMarkerNative();
			EndPointMarker?.RemoveMarkerNative();
			StartPointMarker = null;
			EndPointMarker = null;
		}

		public virtual async Task OutAndBack()
		{
			if (RoutePoints.Count < 2 || !RoutePoints.First().IsAtLeastXMetersAway(RoutePoints.Last(), 1.5))
			{
				return;
			}
			await Task.Run(delegate
			{
				List<iFit.Api.Google.LatLng> list = (from x in RoutePoints.Reverse()
					select x.Copy()).Skip(1).ToList();
				CheckMaxDistanceForNewRoute(RoutePoints.Concat(list).ToList());
				iFit.Api.Google.LatLng latLng = list.Last();
				latLng.SnappedToRoad = RoadSnapOn;
				RoutePoints.AddRange(list);
				ManuallyAddedPoints.Add(latLng);
				SetRouteNative(RoutePoints);
				EndPointMarker.Location = latLng;
			});
		}

