{
	[Serializable]
	public sealed class LaunchDarklyException : Exception
	{
		public LaunchDarklyException(string message)
			: base(message)
		{
		}
	}
	public static class LaunchDarklyConstants
	{
		public const string EquipmentTypeAttributeName = "equipmentType";

		public const string AppVersionAttributeName = "appVersion";

		public const string SoftwareNumberName = "softwareNumber";

		public const string IsTabletName = "IsTablet";

		public const string IsClubName = "IsClub";

		public const string IsEmbeddedName = "IsEmbedded";

		public const string DeviceName = "deviceName";

		public const string DeviceOperatingSystem = "operatingSystem";

		public const string OsIncrementalVersion = "osIncrementalVersion";

		public const string UUID = "uuid";
	}
	public enum LaunchDarklySyncStatus
	{
		InProgress,
		Synced,
		Broken
	}
	public class LaunchDarklySyncState
	{
		public readonly LaunchDarklySyncStatus Status;

		public readonly Exception Error;

		public LaunchDarklySyncState(LaunchDarklySyncStatus status, Exception error = null)
		{
			Status = status;
			Error = error;
		}
	}
	public abstract class BaseLaunchDarklyClient : IDisposable
	{
		protected readonly BehaviorSubject<LaunchDarklySyncState> userSynced = new BehaviorSubject<LaunchDarklySyncState>(new LaunchDarklySyncState(LaunchDarklySyncStatus.InProgress));

		private const int RequiredFlagsCheckIntervalMs = 1000;

		private const int MaxAttempts = 10;

		public readonly BehaviorSubject<bool> LaunchDarklyConnectionChanged = new BehaviorSubject<bool>(value: false);

		protected readonly ICoreAnalytics analytics;

		protected readonly IIfitApiService ifitApiService;

		protected readonly IAppVersionService appVersionService;

		protected readonly IDeviceInformation deviceInfo;

		protected readonly IHardwareInfo hardwareInfo;

		protected readonly ICurrentConsoleService currentConsoleService;

		protected bool isDisposed;

		protected readonly string anonymousUserId;

		protected readonly Environments ldPrimaryEnvironment;

		protected string ldCurrentUserId;

		protected string ldDefaultKeyName;

		private string environmentKeyName = string.Empty;

		protected readonly IDictionary<string, string> secondaryMobileKeys;

		protected static readonly IDictionary<string, string> MobileKeys = (from Environments x in Enum.GetValues(typeof(Environments))
			where x.GetAttribute<LaunchDarklyEnvironmentAttribute>() != null
			select x).ToDictionary((Environments env) => Enum.GetName(typeof(Environments), env), (Environments env) => env.LaunchDarklyMobileKey());

		private static readonly TimeSpan AttributesTimeout = TimeSpan.FromSeconds(5.0);

		public IObservable<LaunchDarklySyncState> UserSynced => userSynced;

		protected BaseLaunchDarklyClient(ICoreAnalytics analytics, IIfitApiService ifitApiService, IAppVersionService appVersionService, IDeviceInformation deviceInfo, IHardwareInfo hardwareInfo, ICurrentConsoleService currentConsoleService, string anonymousUserId = null)
		{
			this.analytics = analytics;
			this.ifitApiService = ifitApiService;
			this.appVersionService = appVersionService;
			this.deviceInfo = deviceInfo;
			this.hardwareInfo = hardwareInfo;
			this.currentConsoleService = currentConsoleService;
			this.anonymousUserId = anonymousUserId;
			ldDefaultKeyName = "default";
			ldPrimaryEnvironment = ifitApiService.Environment.EnvironmentType;
			ldCurrentUserId = ifitApiService.CurrentlyAuthenticatedUserId;
			environmentKeyName = GetMobileKeyName();
			string primaryEnvironmentKey = ldPrimaryEnvironment.LaunchDarklyMobileKey();
			secondaryMobileKeys = MobileKeys.Where((KeyValuePair<string, string> x) => x.Value != primaryEnvironmentKey).ToDictionary((KeyValuePair<string, string> x) => x.Key, (KeyValuePair<string, string> x) => x.Value);
		}

		public abstract bool GetBool(string key, bool defaultValue);

		public abstract double GetDouble(string key, double defaultValue);

		public abstract int GetInt(string key, int defaultValue);

		public abstract string GetString(string key, string defaultValue);

		public abstract bool AreFlagsAvailable();

		public abstract Task UpdateUser();

		protected abstract void UpdateClientForMobileKey(string keyName);

		public abstract bool IsOnline();

		public abstract void SetOnline();

		public abstract void SetOffline();

		public abstract void Flush();

		public virtual void SwitchEnvironment()
		{
			Environments environmentType = ifitApiService.Environment.EnvironmentType;
			try
			{
				environmentType.LaunchDarklyMobileKey();
			}
			catch (ArgumentOutOfRangeException ex)
			{
				iFit.Logger.Log.Error("FeatureFlags", ex.Message, ex);
				return;
			}
			string mobileKeyName = GetMobileKeyName();
			if (environmentKeyName == mobileKeyName)
			{
				iFit.Logger.Log.Info("FeatureFlags", "NOT Updating LaunchDarkly environment to " + mobileKeyName + " as we're already set to use " + environmentKeyName);
				return;
			}
			environmentKeyName = mobileKeyName;
			iFit.Logger.Log.Info("FeatureFlags", $"Setting LaunchDarkly environment to {environmentType} using key name {mobileKeyName}");
			try
			{
				UpdateClientForMobileKey(mobileKeyName);
			}
			catch (Exception ex2)
			{
				iFit.Logger.Log.Error("FeatureFlags", $"Error updating LaunchDarkly to environment {environmentType}: {ex2.Message}", ex2);
			}
		}

		public T GetJsonObject<T>(string key, T defaultValue)
		{
			try
			{
				string value = GetString(key, null);
				if (!string.IsNullOrWhiteSpace(value))
				{
					return JsonConvert.DeserializeObject<T>(value);
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("FeatureFlags", "Caught exception while attempting to get flag " + key + " from LD", exception);
				analytics.HandledFeatureFlagError(key, exception);
			}
			return defaultValue;
		}

		protected string GetMobileKeyName()
		{
			Environments environmentType = ifitApiService.Environment.EnvironmentType;
			if (environmentType != ldPrimaryEnvironment)
			{
				return Enum.GetName(typeof(Environments), environmentType);
			}
			return ldDefaultKeyName;
		}

		protected async Task WaitForRequiredFlags()
		{
			int attempts = 0;
			while (attempts++ < 10)
			{
				if (AreFlagsAvailable())
				{
					userSynced.OnNext(new LaunchDarklySyncState(LaunchDarklySyncStatus.Synced));
					iFit.Logger.Log.Debug("FeatureFlags", "Flags are supposedly ready. Dashboard Webview URL: " + GetString("wolf-dashboard-webview-3", "BUT THAT WAS A LIE!"));
					return;
				}
				iFit.Logger.Log.Debug("FeatureFlags", "Flags aren't ready yet. Waiting...");
				await Task.Delay(1000).ConfigureAwait(continueOnCapturedContext: false);
			}
			userSynced.OnNext(new LaunchDarklySyncState(LaunchDarklySyncStatus.Broken, new TimeoutException("Timed out waiting for feature flag sync")));
		}

		protected virtual void Dispose(bool disposing)
		{
			isDisposed = true;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
			GC.SuppressFinalize(this);
		}
	}
}
