	public class AppLifecycleService : IAppLifecycleService
	{
		public enum AppState
		{
			Background,
			Foreground
		}

		private IFeatureFlagManager featureFlagManager;

		private DateTime _appLastResumed;

		private DateTime _appLastPaused;

		public DateTime AppLastResumed => _appLastResumed;

		public DateTime AppLastPaused => _appLastPaused;

		public bool IsAppInBackground => AppLastResumed < AppLastPaused;

		public event EventHandler<AppStateEventArgs> AppStateChanged;

		public AppLifecycleService()
		{
			_appLastResumed = (_appLastPaused = DateTime.Now);
		}

		public void AppPaused()
		{
			_appLastPaused = DateTime.Now;
			this.AppStateChanged?.Invoke(this, new AppStateEventArgs(AppState.Background));
		}

		public void AppResumed()
		{
			_appLastResumed = DateTime.Now;
			this.AppStateChanged?.Invoke(this, new AppStateEventArgs(AppState.Foreground));
		}
	}
	public abstract class AppLinkingServiceBase : IAppLinking
	{
		protected class AppLinkInfo
		{
			public Func<Dictionary<string, string>, Type, string, bool> Handler { get; set; }
		}

		protected class AppLinkExecutionInfo : AppLinkInfo
		{
			public string Path { get; set; }

			public Dictionary<string, string> Args { get; set; }

			public AppLinkExecutionInfo(AppLinkInfo baseInfo)
			{
				base.Handler = baseInfo.Handler;
			}
		}

		private TaskCompletionSource<string> urlInitialized;

		private TaskCompletionSource<bool> applicationReadyForLink;

		private readonly TaskCompletionSource<bool> branchInitialized = new TaskCompletionSource<bool>();

		private ICoreAnalytics analytics;

		private const string Tag = "AppLinking";

		private string AppScheme;

		private Func<string, bool> AppStateValidationHandler;

		protected Dictionary<string, AppLinkInfo> handlers = new Dictionary<string, AppLinkInfo>();

		public string ExternalUriString { get; protected set; }

		private ICoreAnalytics Analytics
		{
			get
			{
				if (analytics != null)
				{
					return analytics;
				}
				if (!Mvx.TryResolve<ICoreAnalytics>(out var service))
				{
					return null;
				}
				analytics = service;
				return service;
			}
		}

		protected AppLinkingServiceBase()
		{
			Reset();
		}

		protected void Reset()
		{
			urlInitialized?.TrySetCanceled();
			urlInitialized = new TaskCompletionSource<string>();
			applicationReadyForLink?.TrySetCanceled();
			applicationReadyForLink = new TaskCompletionSource<bool>();
		}

		public virtual void ResetExternalLinkReadyState()
		{
			Reset();
		}

		public void MarkApplicationReadyForLink()
		{
			applicationReadyForLink.TrySetResult(result: true);
		}

		public void MarkBranchInitialized()
		{
			branchInitialized.TrySetResult(result: true);
		}

		public void Init(string OurAppScheme, Func<string, bool> AppWillAllowViewModelNavigation)
		{
			AppScheme = OurAppScheme;
			AppStateValidationHandler = AppWillAllowViewModelNavigation;
		}

		public void InitializeLink(string url)
		{
			if (!string.IsNullOrEmpty(ExternalUriString) && string.IsNullOrEmpty(url))
			{
				iFit.Logger.Log.Info("AppLinking", "InitializeLink canceled. ExternalUriString is not empty, but url is empty");
				return;
			}
			ExternalUriString = url;
			urlInitialized.TrySetResult(ExternalUriString);
		}

		public async Task<string> WaitForInitializationComplete()
		{
			return await urlInitialized.Task;
		}

		public async Task WaitForApplicationReadyForLink()
		{
			await applicationReadyForLink.Task;
		}

		public async Task WaitForBranchInitialized()
		{
			await branchInitialized.Task;
		}

		private string StandardizePath(string url)
		{
			return url.Trim().TrimEnd('/');
		}

		private AppLinkExecutionInfo GetExecutionForUrl(string url)
		{
			Uri uri = new Uri(url);
			string text = StandardizePath(uri.AbsolutePath);
			string text2 = null;
			Dictionary<string, string> dictionary = new Dictionary<string, string>(uri.DecodeQueryParameters());
			foreach (string key2 in handlers.Keys)
			{
				Regex regex = new Regex(key2);
				string[] groupNames = regex.GetGroupNames();
				if (regex.IsMatch(text))
				{
					Match match = regex.Match(text);
					for (int i = 1; i < match.Groups.Count; i++)
					{
						string key = groupNames[i];
						string value = match.Groups[i].Value;
						dictionary[key] = value;
					}
					text2 = key2;
					break;
				}
			}
			if (text2 != null)
			{
				return new AppLinkExecutionInfo(handlers[text2])
				{
					Path = text,
					Args = dictionary
				};
			}
			throw new ArgumentException("The link path '" + url + "' could not be matched to a handler");
		}

		public virtual bool HandleExternalLinkRequest(string appLinkUrl, Type currentViewModel = null)
		{
			if (string.IsNullOrEmpty(ExternalUriString) && !string.IsNullOrEmpty(appLinkUrl))
			{
				InitializeLink(appLinkUrl);
			}
			try
			{
				AppLinkExecutionInfo executionForUrl = GetExecutionForUrl(appLinkUrl);
				if (executionForUrl.Handler(executionForUrl.Args, currentViewModel, appLinkUrl))
				{
					Analytics?.OnDeepLinkNavigated(appLinkUrl);
					ExternalUriString = string.Empty;
					return true;
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Navigation", "Error in HandleExternalLinkRequest", exception);
			}
			Analytics?.OnDeepLinkNavigationFailed(appLinkUrl);
			return false;
		}

		protected abstract bool ShouldOpenFallback(string destUrl);

		public virtual bool OpenLinkUrl(string destUrlString, string fallbackUrlString = null)
		{
			if (!AppStateValidationHandler(destUrlString))
			{
				iFit.Logger.Log.Error("AppLinking", "Could not navigate on open link URL");
				return false;
			}
			Uri uri = null;
			try
			{
				uri = new Uri(destUrlString);
			}
			catch (Exception)
			{
				iFit.Logger.Log.Error("AppLinking", "Invalid URL passed to AppLinkingServiceBase.OpenLinkUrl()");
				return false;
			}
			if (AppScheme.StartsWith(uri.Scheme.ToLowerInvariant()))
			{
				return HandleExternalLinkRequest(destUrlString);
			}
			bool flag = ShouldOpenFallback(destUrlString);
			if (flag && string.IsNullOrEmpty(fallbackUrlString))
			{
				return false;
			}
			IMvxWebBrowserTask mvxWebBrowserTask = Mvx.Resolve<IMvxWebBrowserTask>();
			mvxWebBrowserTask.ShowWebPage(flag ? fallbackUrlString : destUrlString);
			return true;
		}

		public void RegisterDeepLinkHandler(string pattern, Func<Dictionary<string, string>, Type, string, bool> handler)
		{
			AppLinkInfo value = new AppLinkInfo
			{
				Handler = handler
			};
			handlers[StandardizePath(pattern)] = value;
		}
	}
	public class BleDeviceSupplementaryData
	{
