	}
	public abstract class BleDeviceSupplementaryDataServiceBase : IBleDeviceSupplementaryDataService
	{
		private bool isDownloading;

		protected static Dictionary<string, BleDeviceSupplementaryData> Dictionary { get; private set; }

		protected abstract Uri RemoteJsonDictionaryUri { get; }

		protected BleDeviceSupplementaryDataServiceBase()
		{
			if (Dictionary == null && !isDownloading)
			{
				Task.Run((Func<Task>)DownloadDictionary);
			}
		}

		public BleDeviceSupplementaryData SupplementaryDataForDevice(string hardwareTypeKey)
		{
			if (Dictionary == null)
			{
				return null;
			}
			if (!Dictionary.ContainsKey(hardwareTypeKey))
			{
				return null;
			}
			return Dictionary[hardwareTypeKey];
		}

		private async Task DownloadDictionary()
		{
			isDownloading = true;
			try
			{
				Dictionary = await JsonDownloadUtil.DownloadAndParseJson<Dictionary<string, BleDeviceSupplementaryData>>(RemoteJsonDictionaryUri.ToString());
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Ble", "Unable to download supplementary data dictionary for BLE devices: {0}", exception);
			}
			finally
			{
				isDownloading = false;
			}
		}
	}
	public abstract class ChartDataProvider : IDisposable
	{
		protected readonly IFitnessConsole console;

		protected MetricStatList source;

		protected readonly FitnessValue KeyMetric;

		private ICombinedAudioVideoPlayer _combinedAudioVideoPlayer;

		protected ICombinedAudioVideoPlayer CombinedAudioVideoPlayer
		{
			get
			{
				if (_combinedAudioVideoPlayer == null && Mvx.TryResolve<IVideoService>(out var service))
				{
					_combinedAudioVideoPlayer = service.PreBufferedVideoPlayer;
				}
				return _combinedAudioVideoPlayer;
			}
		}

		protected bool IsVideo { get; }

		public abstract ChartDataCollection ProviderData { get; protected set; }

		public ChartMetricConfiguration.MetricType MetricType { get; set; }

		protected ChartDataProvider(IFitnessConsole console, Workout workout, MetricStatList source, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey = FitnessValue.CurrentTime)
		{
			IsVideo = workout.IsVideoWorkout();
			MetricType = chartType;
			if (metricKey == FitnessValue.CurrentDistance || (uint)(metricKey - 16) <= 1u)
			{
				KeyMetric = metricKey;
				this.console = console;
				this.source = source;
				StatDataPoint statDataPoint = source?.First;
				ProviderData.Add(new Tuple<double, double>(statDataPoint?.Timestamp ?? 0.0, statDataPoint?.Value ?? 0.0));
				return;
			}
			throw new ArgumentException("Unsupported key metric type");
		}

		public virtual void Dispose()
		{
			source?.Clear();
			source = null;
		}

		protected virtual double GetLatestKeyForType(FitnessValue keyType)
		{
			if (IsVideo && CombinedAudioVideoPlayer != null)
			{
				return (int)CombinedAudioVideoPlayer.LastVideoPositionSeconds;
			}
			return keyType switch
			{
				FitnessValue.CurrentTime => console.LatestBasicInfo.TimeSeconds, 
				FitnessValue.CurrentDistance => console.LatestBasicInfo.DistanceMeters, 
				FitnessValue.CurrentCalories => console.LatestBasicInfo.Calories, 
				_ => throw new ArgumentException("Unsupported key metric"), 
			};
		}
	}
	public interface ICompetitionService
	{
		string WolfGeneratedId { get; }

		IObservable<int> SendNextMoment { get; }

		bool IsUsingNativeCompetitionService { get; }

		Task StartCompetitionAsync(IFitnessConsole console, Workout workout, IWorkoutRunner workoutRunner, string wolfGeneratedId, bool recovered);

		void EndCompetition(bool workoutFinished);

		void AddMomentWithInfo(int moment, IList<IControlDecorator> decorators);

