	public class CompetitionService : ICompetitionService
	{
		public class ReloaderProperties
		{
			public IFitnessConsole Console { get; set; }

			public Workout Workout { get; set; }

			public string WolfGeneratedId { get; set; }

			public bool Recovered { get; set; }

			public ReloaderProperties(IFitnessConsole console, Workout workout, string wolfGeneratedId, bool recovered)
			{
				Console = console;
				Workout = workout;
				WolfGeneratedId = wolfGeneratedId;
				Recovered = recovered;
			}
		}

		private const string Tag = "CompetitionService";

		private string lastWolfGeneratedId;

		private readonly Subject<int> _sendNextMoment = new Subject<int>();

		private IDictionary<string, string> ActiveTokenInfo;

		private const string IotWebSocketServer = "wss://az2wp4gg6an1j-ats.iot.us-east-1.amazonaws.com/mqtt";

		private const string TokenKey = "token";

		private const string SignatureKey = "signature";

		private IIfitApiService ifitApi;

		private IConnectivity connectivityService;

		private IFeatureFlagManager featureFlagManager;

		private ICoreAnalytics analytics;

		private ConsoleStateStats consoleStateStats;

		private ReloaderProperties reloaderProperties;

		private IWorkoutRunner workoutRunner;

		private readonly INativeCompetitionService nativeCompetitionService;

		protected readonly ICurrentConsoleService currentConsoleService;

		public string WolfGeneratedId { get; set; }

		public IObservable<int> SendNextMoment => _sendNextMoment;

		public bool IsUsingNativeCompetitionService => NativeCompetitionActive;

		protected bool NativeCompetitionActive { get; set; }

		protected CompetitionLog ActiveCompetition { get; private set; }

		public CompetitionService(IIfitApiService ifitApi, IConnectivity connectivityService, IFeatureFlagManager featureFlagManager, ICoreAnalytics analytics, INativeCompetitionService nativeCompetitionService, ICurrentConsoleService currentConsoleService)
		{
			this.ifitApi = ifitApi;
			this.connectivityService = connectivityService;
			this.featureFlagManager = featureFlagManager;
			this.analytics = analytics;
			this.nativeCompetitionService = nativeCompetitionService;
			this.currentConsoleService = currentConsoleService;
		}

		public async Task StartCompetitionAsync(IFitnessConsole console, Workout workout, IWorkoutRunner workoutRunner, string wolfGeneratedId, bool recovered)
		{
			reloaderProperties = null;
			connectivityService.ConnectivityChanged -= InitialConnectionChanged;
			this.workoutRunner = workoutRunner;
			if (currentConsoleService?.IsBuiltinClub ?? false)
			{
				iFit.Logger.Log.Trace("CompetitionService", "NOT starting competition: IsBuiltinClub doesn't support competitions");
				return;
			}
			bool valueOrDefault = ifitApi?.CurrentlyAuthenticatedUser?.Premium == true;
			if (featureFlagManager.ShouldUseNativeCompetitionService(workoutRunner.RunContext.Context) && valueOrDefault)
			{
				iFit.Logger.Log.Trace("CompetitionService", $"Starting native competition for {workoutRunner.RunContext.Context}");
				NativeCompetitionActive = true;
				await nativeCompetitionService.StartCompetitionAsync(workout);
			}
			if (!featureFlagManager.IsLeaderboardDataUploadEnabledForWorkout(workoutRunner.RunContext.Context))
			{
				iFit.Logger.Log.Trace("CompetitionService", $"NOT starting competition: feature flag disabled for {workoutRunner.RunContext.Context}");
				return;
			}
			if (console is INonconnectedFitnessConsole)
			{
				iFit.Logger.Log.Trace("CompetitionService", "NOT starting competition: nonConnectedConsole doesn't support competitions");
				return;
			}
			if (!ifitApi.HasLoggedInUser)
			{
				iFit.Logger.Log.Error("CompetitionService", "ERROR starting competition: no logged in user");
				return;
			}
			if (ActiveCompetition != null)
			{
				iFit.Logger.Log.Trace("CompetitionService", "NOT starting competition: competition already started");
				return;
			}
			try
			{
				ActiveTokenInfo = await ifitApi.GatewayService.GetIotToken().ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("CompetitionService", "ERROR starting competition: getting IoT token failed: " + ex.Message);
			}
			if (!connectivityService.IsConnected)
			{
				iFit.Logger.Log.Trace("CompetitionService", "ERROR No connection, waiting for connection before restarting competition service");
				reloaderProperties = new ReloaderProperties(console, workout, wolfGeneratedId, recovered);
				connectivityService.ConnectivityChanged += InitialConnectionChanged;
				return;
			}
			if (ActiveTokenInfo == null || !ActiveTokenInfo.ContainsKey("token") || !ActiveTokenInfo.ContainsKey("signature"))
			{
				iFit.Logger.Log.Error("CompetitionService", "ERROR starting competition: some token info is missing");
				return;
			}
			if (consoleStateStats == null)
			{
				iFit.Logger.Log.Error("CompetitionService", "ERROR starting competition: console state stats is null");
				return;
			}
			WolfGeneratedId = wolfGeneratedId;
			CompetitionActivity recoveredLog = null;
			if (recovered && WolfGeneratedId != null)
			{
				iFit.Logger.Log.Trace("CompetitionService", "Grabbing competition data for " + WolfGeneratedId);
				List<string> fields = new List<string> { "watts", "rpm", "meters" };
				recoveredLog = await CompetitionActivity.Get(ifitApi, WolfGeneratedId, fields).ConfigureAwait(continueOnCapturedContext: false);
			}
			iFit.Logger.Log.Trace("CompetitionService", (recovered ? "Recovering" : "Starting") + " competition with " + WolfGeneratedId);
			await InitializeCompetitionAsync(new CompetitionLog(ifitApi.CurrentlyAuthenticatedUser, console, featureFlagManager, workout, workoutRunner, WolfGeneratedId, recoveredLog, consoleStateStats)).ConfigureAwait(continueOnCapturedContext: false);
			connectivityService.ConnectivityChanged -= ConnectivityServiceConnectivityChanged;
			connectivityService.ConnectivityChanged += ConnectivityServiceConnectivityChanged;
		}

		private void InitialConnectionChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (reloaderProperties == null)
			{
				connectivityService.ConnectivityChanged -= InitialConnectionChanged;
				iFit.Logger.Log.Error("CompetitionService", "Tried to retrying StartCompetition but there were no reloader properties, aborting");
			}
			else if (e.IsConnected)
			{
				iFit.Logger.Log.Trace("CompetitionService", "Retrying StartCompetition with " + reloaderProperties.WolfGeneratedId);
				Task.Run(async delegate
				{
					await StartCompetitionAsync(reloaderProperties.Console, reloaderProperties.Workout, workoutRunner, reloaderProperties.WolfGeneratedId, reloaderProperties.Recovered).ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		private void ConnectivityServiceConnectivityChanged(object sender, ConnectivityChangedEventArgs e)
		{
			if (e.IsConnected)
			{
				iFit.Logger.Log.Trace("CompetitionService", "ConnectivityChanged, restarting competition");
				Task.Run(async delegate
				{
					await RestartCompetitionAsync().ConfigureAwait(continueOnCapturedContext: false);
				});
			}
		}

		private async Task InitializeCompetitionAsync(CompetitionLog competition)
		{
			string currentlyAuthenticatedUserId = ifitApi.CurrentlyAuthenticatedUserId;
			string text = ifitApi.Environment.Name.ToLower();
			if (text.Equals("prod"))
			{
				text = "production";
			}
			MqttClientConfigs mqttClientConfigs = new MqttClientConfigs();
			mqttClientConfigs.WebSocketServer = "wss://az2wp4gg6an1j-ats.iot.us-east-1.amazonaws.com/mqtt";
			mqttClientConfigs.Topic = "omnius/" + text + "/" + currentlyAuthenticatedUserId + "/ingest";
			mqttClientConfigs.ClientId = "omnius-" + text + "-" + currentlyAuthenticatedUserId;
			mqttClientConfigs.CustomHeaders = new Dictionary<string, string>
			{
				["x-amz-customauthorizer-name"] = "omnius-" + text,
				["x-amz-customauthorizer-token"] = ActiveTokenInfo["token"],
				["x-amz-customauthorizer-signature"] = ActiveTokenInfo["signature"]
			};
			MqttClientConfigs configs = mqttClientConfigs;
			ActiveCompetition = competition;
			await competition.InitializeAndConnectAsync(configs).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task RestartCompetitionAsync()
		{
			if (ActiveCompetition != null)
			{
				await InitializeCompetitionAsync(ActiveCompetition).ConfigureAwait(continueOnCapturedContext: false);
				SendNextMoment.Next();
			}
			else
			{
				iFit.Logger.Log.Error("CompetitionService", "ERROR restarting competition: no competition exists");
			}
		}

		public void EndCompetition(bool workoutComplete)
		{
			iFit.Logger.Log.Trace("CompetitionService", $"Ending competition - workout complete - {workoutComplete}");
			if (NativeCompetitionActive)
			{
				NativeCompetitionActive = false;
				nativeCompetitionService?.EndCompetition(workoutComplete);
			}
			ActiveCompetition?.Finish(workoutComplete, analytics);
			ActiveCompetition = null;
			ActiveTokenInfo = null;
			lastWolfGeneratedId = WolfGeneratedId;
			WolfGeneratedId = null;
			consoleStateStats = null;
			reloaderProperties = null;
			Dispose();
		}

		private void Dispose()
		{
			connectivityService.ConnectivityChanged -= InitialConnectionChanged;
			connectivityService.ConnectivityChanged -= ConnectivityServiceConnectivityChanged;
		}

		public void AddMomentWithInfo(int moment, IList<IControlDecorator> decorators)
		{
			Task.Run(async delegate
			{
				if (ActiveCompetition != null)
				{
					await ActiveCompetition.AddSecondWithInfo(decorators).ConfigureAwait(continueOnCapturedContext: false);
					_sendNextMoment.OnNext(moment);
				}
			});
		}

		public async Task DeleteCurrentCompetitionData()
		{
			if (workoutRunner?.RunContext == null)
			{
				iFit.Logger.Log.Error("Workout", "DeleteCurrentCompetitionData called while WorkoutRunner was null.");
				return;
			}
			if (!featureFlagManager.IsLeaderboardDataUploadEnabledForWorkout(workoutRunner.RunContext.Context))
			{
				iFit.Logger.Log.Trace("Workout", "Not clearing competition data for workout since data upload is disabled.");
				return;
			}
			string activityLogToDelete = WolfGeneratedId ?? lastWolfGeneratedId;
			if (activityLogToDelete == null)
			{
				iFit.Logger.Log.Trace("Workout", "Not clearing competition data for workout since no WolfGeneratedId");
			}
			else if (await CompetitionActivity.Delete(ifitApi, activityLogToDelete))
			{
				iFit.Logger.Log.Trace("Workout", "Data cleared from omnius for " + activityLogToDelete);
			}
			else
			{
				iFit.Logger.Log.Error("Workout", "Failed to clear omnius for " + activityLogToDelete);
			}
		}

		public void SetConsoleStateStats(ConsoleStateStats consoleStateStats)
		{
			this.consoleStateStats = consoleStateStats;
		}

		public int GetRank()
		{
			if (nativeCompetitionService?.Participants == null || !nativeCompetitionService.Participants.Any())
			{
				iFit.Logger.Log.Trace("CompetitionService", "Participants list is null or empty");
				return -1;
			}
			return nativeCompetitionService.Participants.FirstOrDefault((CompetitionParticipant participant) => participant != null && participant.Type == ParticipantType.You)?.Rank ?? (-1);
		}

		public bool CompetitionsFeatureEnabled(IWorkoutRunner runner)
		{
			IIfitApiService ifitApiService = ifitApi;
			if (ifitApiService == null || ifitApiService.CurrentlyAuthenticatedUser?.Premium != true)
			{
				iFit.Logger.Log.Trace("CompetitionService", "Feature Disabled: Competitions only on for premium users");
				return false;
			}
			ICurrentConsoleService obj = currentConsoleService;
			if (obj != null && obj.IsBuiltinClub)
			{
				iFit.Logger.Log.Trace("CompetitionService", "Feature Disabled: Competitions are not on for Club Units");
				return false;
			}
			if (featureFlagManager.ShouldUseNativeCompetitionService(runner.RunContext.Context))
			{
				iFit.Logger.Log.Trace("CompetitionService", "Feature Enabled: Native competition is enabled");
				return true;
			}
			if (featureFlagManager.IsLeaderboardDataUploadEnabledForWorkout(runner.RunContext.Context))
			{
				iFit.Logger.Log.Trace("CompetitionService", "Feature Enabled: Competitions leaderboard data upload is enabled");
				return true;
			}
			iFit.Logger.Log.Trace("CompetitionService", "Feature Disabled: Competitions leaderboard data upload is disabled");
			return false;
		}
	}
	public class ConsoleStateStats : IDisposable
	{
		private const int StateChangeTimeResetSeconds = 20;

		private Subject<(double metricValue, double timestamp, FitnessValue type)> consoleStateStatsChangedSub;

		private IFitnessConsole console;

		private IDisposable metricChangedSub;

		private bool initialized;

		private bool hasForcedRecordKphStat;

		private IEffortScoreCalculator effortScoreCalculator;

		private bool disposed;

		public MetricStats WarmUpStats { get; set; } = new MetricStats();

		public MetricStats RunningStats { get; set; } = new MetricStats();

		public MetricStats CoolDownStats { get; set; } = new MetricStats();

		public IObservable<(double metricValue, double timestamp, FitnessValue type)> ConsoleStateStatsChanged => consoleStateStatsChangedSub;

		public ConsoleStateStats()
		{
		}

		public ConsoleStateStats(IFitnessConsole console, ConsoleStateStatsFacade consoleStateStatsFacade, IEffortScoreCalculator effortScoreCalculator = null)
		{
			Init(console, consoleStateStatsFacade, effortScoreCalculator);
		}

		public void Init(IFitnessConsole console, ConsoleStateStatsFacade consoleStateStatsFacade, IEffortScoreCalculator effortScoreCalculator = null)
		{
			this.console = console;
			this.effortScoreCalculator = effortScoreCalculator;
			metricChangedSub?.Dispose();
			metricChangedSub = null;
			if (Mvx.TryResolve<IFeatureFlagManager>(out var service) && service != null && service.IsFeatureEnabled(FeatureFlags.WolfImprovedRecoveryManager))
			{
				consoleStateStatsChangedSub = new Subject<(double, double, FitnessValue)>();
			}
			metricChangedSub = consoleStateStatsFacade.ObserveChanges().SubscribeWithErrorLogging(MetricChanged);
		}

		private (ConsoleState State, int Time) CreateChangeTuple(StateChange stateChange, FitnessValueChange<int> timeChange)
		{
			return (State: stateChange.Current, Time: timeChange.Current);
		}

		public void Reset()
		{
			WarmUpStats.Reset();
			RunningStats.Reset();
			CoolDownStats.Reset();
		}

		public async Task<ConsoleStateStats> Clone()
		{
			ConsoleStateStats stats = new ConsoleStateStats();
			ConsoleStateStats consoleStateStats = stats;
			consoleStateStats.WarmUpStats = await WarmUpStats.Clone().ConfigureAwait(continueOnCapturedContext: false);
			consoleStateStats = stats;
			consoleStateStats.RunningStats = await RunningStats.Clone().ConfigureAwait(continueOnCapturedContext: false);
			consoleStateStats = stats;
			consoleStateStats.CoolDownStats = await CoolDownStats.Clone().ConfigureAwait(continueOnCapturedContext: false);
			return stats;
		}

		private void MetricChanged(FitnessValueChange<ConsoleStateValues> change)
		{
			if (console?.LatestBasicInfo == null || !console.LatestBasicInfo.IsInState(ConsoleState.WarmUp, ConsoleState.Workout, ConsoleState.PauseOverride, ConsoleState.CoolDown))
			{
				return;
			}
			int valueOrDefault = (console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault();
			IFitnessConsole fitnessConsole = console;
			if (fitnessConsole != null && fitnessConsole.LatestBasicInfo?.TimeTrendMatchesState == false)
			{
				iFit.Logger.Log.Trace("Workout", $"Not recording {change.Type} value of {change.Current} at time {valueOrDefault} because the console info is not trustworthy.");
				return;
			}
			if (!initialized)
			{
				IFitnessConsole fitnessConsole2 = console;
				if (fitnessConsole2 != null && fitnessConsole2.LatestBasicInfo?.CurrentState == ConsoleState.Workout && change.Type == FitnessValue.CurrentTime)
				{
					iFit.Logger.Log.Trace("Workout", $"ConsoleStateStats is entering the Running state, time is {valueOrDefault}");
					EnterRunningState();
					return;
				}
			}
			switch (console.LatestBasicInfo.CurrentState)
			{
			case ConsoleState.WarmUp:
				AddMetric(WarmUpStats, change);
				break;
			case ConsoleState.Workout:
			case ConsoleState.PauseOverride:
				if (initialized)
				{
					AddMetric(RunningStats, change);
					ForceRecordCurrentKphIfNeeded();
				}
				else
				{
					AddMetric(WarmUpStats, change);
				}
				break;
			case ConsoleState.CoolDown:
				AddMetric(CoolDownStats, change);
				break;
			}
		}

		private void ForceRecordCurrentKphIfNeeded()
		{
			try
			{
				FitnessValue fitnessValue = (((!(console?.ConsoleInfo?.MachineType.IsBeltBasedMachine())) ?? false) ? FitnessValue.ActualKph : FitnessValue.Kph);
				MetricStatList metricStatList = ((fitnessValue != FitnessValue.Kph) ? RunningStats?.ActualKphChanges : RunningStats?.KphChanges);
				if (hasForcedRecordKphStat)
				{
					return;
				}
				IFitnessConsole fitnessConsole = console;
				if (fitnessConsole != null && fitnessConsole.LatestBasicInfo?.TimeTrendMatchesState == true && metricStatList != null && metricStatList.Count < 2 && metricStatList.Count > 0)
				{
					hasForcedRecordKphStat = true;
					double num = ((fitnessValue == FitnessValue.Kph) ? console.LatestBasicInfo.Kph : console.LatestBasicInfo.ActualKph);
					double value = metricStatList.Last.Value;
					if (!num.AlmostEqual(value))
					{
						iFit.Logger.Log.Trace("Workout", $"Console is now trusted but last recorded Kph stat of {value} != current {num}, " + "forcing recording current Kph stat to ensure we have captured changes from when the console was untrusted");
						RecordCurrentMetric(metricStatList, num, RunningStats, fitnessValue);
						RecordCurrentMetric(RunningStats.MpsChanges, UnitUtil.EnsureMps(SpeedUnit.Kph, num), RunningStats, fitnessValue);
					}
				}
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Workout", "Force record kph stat failed", ex);
				iFit.Logger.Log.Error("Workout", ex.StackTrace + $"\nRunningStats.KphChanges.Count: {RunningStats?.KphChanges?.Count}, " + $"RunningStats.KphChanges.Last: {RunningStats?.KphChanges?.Last?.Value}, " + $"console.LatestBasicInfo.Kph: {console?.LatestBasicInfo?.Kph}");
			}
		}

		private void InsertInitialChange(MetricStatList metricChangeList)
		{
			if (metricChangeList != null)
			{
				StatDataPoint first = metricChangeList.First;
				if (metricChangeList.Count < 1 || (first != null && first.Timestamp > 0.0))
				{
					metricChangeList.PrependStat(0.0, 0.0);
				}
				else if (first != null && first.Value > 0.0)
				{
					metricChangeList.PrependStat(0.0, 0.0);
				}
			}
		}

		private void EnterRunningState()
		{
			if (RunningStats == null)
			{
				RunningStats = new MetricStats();
			}
			ConsoleState consoleState = console?.LatestBasicInfo?.CurrentState ?? ConsoleState.Unknown;
			if (consoleState == ConsoleState.Workout || consoleState == ConsoleState.PauseOverride)
			{
				InsertInitialChange(RunningStats.DistanceChanges);
				InsertInitialChange(RunningStats.CalorieChanges);
				InsertInitialChange(RunningStats.PulseChanges);
			}
			if (console?.ConsoleInfo?.MachineType.IsBeltBasedMachine() == true)
			{
				InitializeMetric(RunningStats.KphChanges, (console?.LatestBasicInfo?.Kph).GetValueOrDefault(), FitnessValue.Kph);
				InitializeMetric(RunningStats.MpsChanges, UnitUtil.EnsureMps(SpeedUnit.Kph, (console?.LatestBasicInfo?.Kph).GetValueOrDefault()), FitnessValue.Kph);
			}
			else
			{
				InitializeMetric(RunningStats.ActualKphChanges, (console?.LatestBasicInfo?.Kph).GetValueOrDefault(), FitnessValue.ActualKph);
				InitializeMetric(RunningStats.MpsChanges, UnitUtil.EnsureMps(SpeedUnit.Kph, (console?.LatestBasicInfo?.Kph).GetValueOrDefault()), FitnessValue.ActualKph);
				InitializeMetric(RunningStats.RpmChanges, (console?.LatestBasicInfo?.Rpm).GetValueOrDefault(), FitnessValue.Rpm);
			}
			InitializeMetric(RunningStats.GradeChanges, (console?.LatestBasicInfo?.Grade).GetValueOrDefault(), FitnessValue.Grade);
			InitializeMetric(RunningStats.VerticalMetersNetChanges, (console?.LatestBasicInfo?.VerticalMetersNet).GetValueOrDefault(), FitnessValue.VerticalMeterNet);
			if (console?.ConsoleInfo?.CanSetResistance == true)
			{
				InitializeMetric(RunningStats.ResistanceChanges, console?.LatestBasicInfo?.Resistance ?? 1.0, FitnessValue.Resistance);
			}
			if ((console?.ConsoleInfo?.MaxGear ?? 1) > 1)
			{
				InitializeMetric(RunningStats.GearChanges, console?.LatestBasicInfo?.Gear?.CurrentGear ?? 1, FitnessValue.Gear);
			}
			if (console?.ConsoleInfo?.SupportsPulse == true)
			{
				InitializeMetric(RunningStats.PulseChanges, (console?.LatestBasicInfo?.CurrentPulse?.UserPulse).GetValueOrDefault(), FitnessValue.Pulse);
			}
			if (console?.ConsoleInfo?.MachineType.IsRower() == true)
			{
				InitializeMetric(RunningStats.StrokeChanges, (console?.LatestBasicInfo?.Strokes).GetValueOrDefault(), FitnessValue.Strokes);
				InitializeMetric(RunningStats.StrokePerMinChanges, (console?.LatestBasicInfo?.StrokesPerMin).GetValueOrDefault(), FitnessValue.StrokesPerMin);
				InitializeMetric(RunningStats.FiveHundredSplitChanges, (console?.LatestBasicInfo?.FiveHundredSplit).GetValueOrDefault(), FitnessValue.FiveHundredSplit);
				MetricStatList fiveHundredSplitDecimalChanges = RunningStats.FiveHundredSplitDecimalChanges;
				IFitnessConsole fitnessConsole = console;
				InitializeMetric(fiveHundredSplitDecimalChanges, ((fitnessConsole == null) ? ((int?)null) : (fitnessConsole.LatestBasicInfo?.FiveHundredSplit / 60)).GetValueOrDefault(), FitnessValue.FiveHundredSplitDecimal);
				InitializeMetric(RunningStats.AvgFiveHundredSplitChanges, (console?.LatestBasicInfo?.AvgFiveHundredSplit).GetValueOrDefault(), FitnessValue.AvgFiveHundredSplit);
			}
			InitializeXScore(consoleState);
			initialized = true;
		}

		private void AddMetric(MetricStats targetStats, FitnessValueChange<ConsoleStateValues> change)
		{
			if (targetStats == null || change == null)
			{
				return;
			}
			ConsoleStateValues current = change.Current;
			switch (change.Type)
			{
			case FitnessValue.Kph:
			{
				if (current.Kph.TryGetValue(out double result8))
				{
					RecordCurrentMetric(targetStats.KphChanges, result8, targetStats, change.Type);
					if (console?.ConsoleInfo?.MachineType.IsBeltBasedMachine() == true)
					{
						RecordCurrentMetric(targetStats.MpsChanges, UnitUtil.EnsureMps(SpeedUnit.Kph, result8), targetStats, change.Type);
					}
				}
				break;
			}
			case FitnessValue.ActualKph:
			{
				if (current.ActualKph.TryGetValue(out double result13))
				{
					RecordCurrentMetric(targetStats.ActualKphChanges, result13, targetStats, change.Type);
					IFitnessConsole fitnessConsole = console;
					bool? obj;
					if (fitnessConsole == null)
					{
						obj = null;
					}
					else
					{
						IConsoleInfo consoleInfo = fitnessConsole.ConsoleInfo;
						obj = ((consoleInfo != null) ? new bool?(!consoleInfo.MachineType.IsBeltBasedMachine()) : ((bool?)null));
					}
					bool? flag = obj;
					if (flag == true)
					{
						RecordCurrentMetric(targetStats.MpsChanges, UnitUtil.EnsureMps(SpeedUnit.Kph, result13), targetStats, change.Type);
					}
				}
				break;
			}
			case FitnessValue.Grade:
			{
				if (current.Grade.TryGetValue(out double result18))
				{
					RecordCurrentMetric(targetStats.GradeChanges, result18, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.CurrentDistance:
			{
				if (current.CurrentDistanceMeters.TryGetValue(out double result12))
				{
					RecordCurrentMetric(targetStats.DistanceChanges, result12, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.CurrentTime:
			{
				if (current.CurrentTimeSeconds.TryGetValue(out int result4))
				{
					RecordCurrentMetric(targetStats.TimeSeconds, result4, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.CurrentCalories:
			{
				if (current.Calories.TryGetValue(out double result16))
				{
					RecordCurrentMetric(targetStats.CalorieChanges, result16, targetStats, change.Type);
					RecordXScore(targetStats.XScore, result16, targetStats, FitnessValue.EffortScore);
				}
				break;
			}
			case FitnessValue.Watts:
			{
				if (current.Watts.TryGetValue(out int result14))
				{
					RecordCurrentMetric(targetStats.WattChanges, result14, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.Resistance:
			{
				if (current.Resistance.TryGetValue(out double result10))
				{
					RecordCurrentMetric(targetStats.ResistanceChanges, result10, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.Gear:
			{
				if (current.Gear.TryGetValue(out var result6))
				{
					RecordCurrentMetric(targetStats.GearChanges, result6.CurrentGear, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.Rpm:
			{
				if (current.Rpm.TryGetValue(out int result2))
				{
					RecordCurrentMetric(targetStats.RpmChanges, result2, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.VerticalMeterGain:
			{
				if (current.VerticalMetersGain.TryGetValue(out double result17))
				{
					RecordCurrentMetric(targetStats.VerticalMetersGainChanges, result17, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.VerticalMeterNet:
			{
				if (current.VerticalMetersNet.TryGetValue(out double result15))
				{
					RecordCurrentMetric(targetStats.VerticalMetersNetChanges, result15, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.Pulse:
			{
				if (current.Pulse.TryGetValue(out var result11) && (!targetStats.PulseChanges.Last.Value.AlmostEqual(0.0) || result11.UserPulse != 0))
				{
					RecordCurrentMetric(targetStats.PulseChanges, result11.UserPulse, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.Strokes:
			{
				if (current.Strokes.TryGetValue(out int result9))
				{
					RecordCurrentMetric(targetStats.StrokeChanges, result9, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.StrokesPerMin:
			{
				if (current.StrokesPerMin.TryGetValue(out int result7))
				{
					RecordCurrentMetric(targetStats.StrokePerMinChanges, result7, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.FiveHundredSplit:
			{
				if (current.FiveHundredSplit.TryGetValue(out int result5))
				{
					RecordCurrentMetric(targetStats.FiveHundredSplitChanges, result5, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.FiveHundredSplitDecimal:
			{
				if (current.FiveHundredSplitDecimal.TryGetValue(out int result3))
				{
					RecordCurrentMetric(targetStats.FiveHundredSplitDecimalChanges, result3, targetStats, change.Type);
				}
				break;
			}
			case FitnessValue.AvgFiveHundredSplit:
			{
				if (current.AvgFiveHundredSplit.TryGetValue(out int result))
				{
					RecordCurrentMetric(targetStats.AvgFiveHundredSplitChanges, result, targetStats, change.Type);
				}
				break;
			}
			}
		}

		private bool ShouldCalculateXScore(ConsoleState currentState)
		{
			return effortScoreCalculator?.ShouldCalculateEffortScore(currentState) ?? false;
		}

		private void InitializeXScore(ConsoleState currentState)
		{
			if (ShouldCalculateXScore(currentState))
			{
				if ((console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault() > 0)
				{
					double metricValue = effortScoreCalculator.CalculateForCurrentTime((console?.LatestBasicInfo?.Calories).GetValueOrDefault());
					InitializeMetric(RunningStats.XScore, metricValue, FitnessValue.EffortScore);
				}
				else
				{
					InitializeMetric(RunningStats.XScore, 0.0, FitnessValue.EffortScore);
				}
			}
		}

		private void RecordXScore(MetricStatList xScoreStats, double calories, MetricStats stats, FitnessValue metricType)
		{
			if (ShouldCalculateXScore(console?.LatestBasicInfo?.CurrentState ?? ConsoleState.Unknown) && xScoreStats.Count != 0)
			{
				double num = effortScoreCalculator.CalculateForCurrentTime(calories);
				if (!double.IsNaN(num))
				{
					RecordCurrentMetric(xScoreStats, num, stats, metricType);
				}
			}
		}

		private void RecordCurrentMetric(MetricStatList targetList, double metricValue, MetricStats stats, FitnessValue metricType)
		{
			int num = (console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault();
			IFitnessConsole fitnessConsole = console;
			if (fitnessConsole == null || fitnessConsole.LatestBasicInfo?.CurrentState != ConsoleState.WarmUp)
			{
				IFitnessConsole fitnessConsole2 = console;
				if (fitnessConsole2 == null || fitnessConsole2.LatestBasicInfo?.CurrentState != ConsoleState.CoolDown)
				{
					goto IL_011a;
				}
			}
			int num2 = ((console.LatestBasicInfo.CurrentState == ConsoleState.WarmUp) ? console.ConsoleInfo.WarmUpTimeoutSeconds : console.ConsoleInfo.CoolDownTimeoutSeconds);
			if (targetList.Count < 2)
			{
				num = ((Math.Abs(num2 - num) > 20) ? num2 : num);
			}
			num = num2 - num;
			goto IL_011a;
			IL_011a:
			if (num < 0)
			{
				iFit.Logger.Log.Error("Workout", $"Value {metricValue} was about to be recorded at timestamp {num}. Ignoring instead.");
				return;
			}
			if ((double)num > stats.MaxDuration)
			{
				stats.MaxDuration = num;
			}
			AddMetricToList(targetList, metricValue, num, metricType);
		}

		private void InitializeMetric(MetricStatList metricList, double metricValue, FitnessValue metricType)
		{
			AddMetricToList(metricList, metricValue, 0.0, metricType);
		}

		private void AddMetricToList(MetricStatList metricList, double metricValue, double timeStamp, FitnessValue metricType)
		{
			consoleStateStatsChangedSub?.OnNext((metricValue, timeStamp, metricType));
			metricList.RecordStat(timeStamp, metricValue);
		}

		public void RecoverMetricToList(FitnessValue type, double metricValue, double timeStamp)
		{
			switch (type)
			{
			case FitnessValue.Kph:
				RunningStats.KphChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.ActualKph:
				RunningStats.ActualKphChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Grade:
				RunningStats.GradeChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.CurrentDistance:
				RunningStats.DistanceChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.CurrentTime:
				RunningStats.TimeSeconds.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.CurrentCalories:
				RunningStats.CalorieChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Watts:
				RunningStats.WattChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Resistance:
				RunningStats.ResistanceChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Gear:
				RunningStats.GearChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Rpm:
				RunningStats.RpmChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.VerticalMeterGain:
				RunningStats.VerticalMetersGainChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.VerticalMeterNet:
				RunningStats.VerticalMetersNetChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Pulse:
				RunningStats.PulseChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.Strokes:
				RunningStats.StrokeChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.StrokesPerMin:
				RunningStats.StrokePerMinChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.FiveHundredSplit:
				RunningStats.FiveHundredSplitChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.FiveHundredSplitDecimal:
				RunningStats.FiveHundredSplitDecimalChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.AvgFiveHundredSplit:
				RunningStats.AvgFiveHundredSplitChanges.RecordStat(timeStamp, metricValue);
				break;
			case FitnessValue.EffortScore:
				RunningStats.XScore.RecordStat(timeStamp, metricValue);
				break;
			default:
				iFit.Logger.Log.Trace("Workout", $"Not recovering unknown type:{type} {metricValue} at {timeStamp}");
				break;
			}
		}

		protected virtual void Dispose(bool disposing)
		{
			if (!disposed)
			{
				if (disposing)
				{
					metricChangedSub?.Dispose();
					metricChangedSub = null;
					consoleStateStatsChangedSub?.Dispose();
					consoleStateStatsChangedSub = null;
					WarmUpStats?.Dispose();
					RunningStats?.Dispose();
					CoolDownStats?.Dispose();
					WarmUpStats = null;
					RunningStats = null;
					CoolDownStats = null;
				}
				disposed = true;
			}
		}

		public void Dispose()
		{
			Dispose(disposing: true);
		}
	}
	public interface IDataFetcher
	{
		ConsoleWorkouts ConsoleWorkouts { get; }

		IObservable<ConsoleWorkouts> WhenConsoleWorkoutsLoaded { get; }

		Task FetchConsoleWorkouts(int softwareNumber);
	}
	public class DataFetcher : IDataFetcher
	{
		private readonly IIfitApiService IfitApi;

		private readonly Subject<ConsoleWorkouts> _whenConsoleWorkoutsLoaded = new Subject<ConsoleWorkouts>();

		public ConsoleWorkouts ConsoleWorkouts { get; private set; }

		public IObservable<ConsoleWorkouts> WhenConsoleWorkoutsLoaded => _whenConsoleWorkoutsLoaded;

		public DataFetcher(IIfitApiService ifitApi)
		{
			IfitApi = ifitApi;
		}

		public async Task FetchConsoleWorkouts(int softwareNumber)
		{
			if (SoftwareNumbers.NonConnectedSoftwareNumbers.Contains(softwareNumber))
			{
				iFit.Logger.Log.Trace("Api", $"Not fetching console workouts for {softwareNumber}");
				_whenConsoleWorkoutsLoaded.OnNext(ConsoleWorkouts);
				return;
			}
			try
			{
				ConsoleWorkouts = await ConsoleWorkouts.Get(IfitApi, softwareNumber);
				_whenConsoleWorkoutsLoaded.OnNext(ConsoleWorkouts);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "Exception when fetching console workouts " + ex.Message);
			}
		}
	}
	public interface IDateTimeChangeCheckService
	{
	}
	public class DateTimeChangeCheckService : IDateTimeChangeCheckService
	{
		private const int MaxSecondsTimeChange = 60;

		private DateTime lastDateTime;

		private readonly IDisposable tickSub;

		public DateTimeChangeCheckService()
		{
			tickSub = Observable.Interval(TimeSpan.FromSeconds(1.0)).SubscribeWithErrorLogging(delegate
			{
				CheckTimeChange();
			});
		}

		private void CheckTimeChange()
		{
			DateTime now = DateTime.Now;
			DateTime dateTime = lastDateTime;
			if (Math.Abs(now.Subtract(dateTime).TotalSeconds) > 60.0)
			{
				string text = ((now < dateTime) ? "behind" : "ahead of");
				iFit.Logger.Log.Trace("Settings", "DateTime was changed, current time is " + (now - dateTime).Duration().ToString("d\\:hh\\:mm\\:ss") + " " + text + " previous time");
			}
			lastDateTime = now;
		}
	}
	public abstract class FeatureFlagManager : IFeatureFlagManager
	{
		private readonly AsyncReaderWriterLock flagLock = new AsyncReaderWriterLock();

		private readonly IDictionary<string, string> tempStringFlags = new Dictionary<string, string>();

		private readonly IDictionary<string, bool> tempBoolFlags = new Dictionary<string, bool>();

		private readonly IDictionary<string, int> tempIntFlags = new Dictionary<string, int>();

		protected BaseLaunchDarklyClient launchDarklyClient;

		private const string DefaultStringValue = "";

		private readonly AsyncRetryPolicy updateUserPolicy = Policy.Handle<LaunchDarklyException>().Or<TimeoutException>().WaitAndRetryAsync(1, (int retryAttempt) => TimeSpan.FromSeconds(2.0));

		private IObservable<bool> WhenLaunchDarklyConnectionChanged => launchDarklyClient.LaunchDarklyConnectionChanged;

		public IObservable<LaunchDarklySyncState> UserSynced => launchDarklyClient.UserSynced;

		protected FeatureFlagManager(IIfitApiService ifitApiService, ICurrentConsoleService currentConsoleService)
		{
			FeatureFlags.InitFeatureFlags();
			currentConsoleService.WhenConsoleChanged.SubscribeWithErrorLogging(delegate(IFitnessConsole arg)
			{
				if (arg != null)
				{
					Task.Run((Func<Task>)UpdateLaunchDarklyUser);
				}
			});
			ifitApiService.WhenCurrentUserIdChanged.DistinctUntilChanged().SubscribeWithErrorLogging(delegate
			{
				Task.Run((Func<Task>)UpdateLaunchDarklyUser);
			});
			ifitApiService.WhenApiEnvironmentChanged.SubscribeWithErrorLogging(delegate
			{
				Task.Run(delegate
				{
					flagLock.AcquireWriterLock().Wait();
					try
					{
						launchDarklyClient.SwitchEnvironment();
					}
					finally
					{
						flagLock.ReleaseWriterLock();
					}
				});
			});
		}

		public void InitializeLaunchDarklyClient(BaseLaunchDarklyClient client)
		{
			launchDarklyClient = client;
		}

		public bool IsFeatureEnabled(FeatureFlag flag, bool defaultValue = false)
		{
			flagLock.AcquireReaderLock().Wait();
			try
			{
				IDictionary<string, bool> dictionary = tempBoolFlags;
				if (dictionary != null && dictionary.ContainsKey(flag.Key))
				{
					return tempBoolFlags[flag.Key];
				}
				return launchDarklyClient.GetBool(flag.Key, defaultValue);
			}
			finally
			{
				flagLock.ReleaseReaderLock();
			}
		}

		public string GetString(FeatureFlag flag)
		{
			return GetString(flag.Key);
		}

		public string GetString(string key)
		{
			flagLock.AcquireReaderLock().Wait();
			try
			{
				IDictionary<string, string> dictionary = tempStringFlags;
				if (dictionary != null && dictionary.ContainsKey(key))
				{
					return tempStringFlags[key];
				}
				return launchDarklyClient.GetString(key, "");
			}
			finally
			{
				flagLock.ReleaseReaderLock();
			}
		}

		public T GetObject<T>(FeatureFlag flag)
		{
			flagLock.AcquireReaderLock().Wait();
			try
			{
				return launchDarklyClient.GetJsonObject(flag.Key, default(T));
			}
			finally
			{
				flagLock.ReleaseReaderLock();
			}
		}

		public int GetInt(FeatureFlag flag, int fallback = 0)
		{
			return GetInt(flag.Key, fallback);
		}

		public int GetInt(string key, int fallback = 0)
		{
			flagLock.AcquireReaderLock().Wait();
			try
			{
				IDictionary<string, int> dictionary = tempIntFlags;
				if (dictionary != null && dictionary.ContainsKey(key))
				{
					return tempIntFlags[key];
				}
				return launchDarklyClient.GetInt(key, fallback);
			}
			finally
			{
				flagLock.ReleaseReaderLock();
			}
		}

		public bool GetBool(FeatureFlag flag, bool fallback = false)
		{
			return GetBool(flag.Key, fallback);
		}

		public bool GetBool(string key, bool fallback = false)
		{
			flagLock.AcquireReaderLock().Wait();
			try
			{
				IDictionary<string, bool> dictionary = tempBoolFlags;
				if (dictionary != null && dictionary.ContainsKey(key))
				{
					return tempBoolFlags[key];
				}
				return launchDarklyClient.GetBool(key, fallback);
			}
			finally
			{
				flagLock.ReleaseReaderLock();
			}
		}

		public virtual void SetBoolFlagTemporarily(FeatureFlag flag, bool newValue)
		{
			flagLock.AcquireWriterLock().Wait();
			try
			{
				if (tempBoolFlags.ContainsKey(flag.Key))
				{
					tempBoolFlags[flag.Key] = newValue;
				}
				else
				{
					tempBoolFlags.Add(flag.Key, newValue);
				}
			}
			finally
			{
				flagLock.ReleaseWriterLock();
			}
		}

		public void SetStringFlagTemporarily(FeatureFlag flag, string newValue)
		{
			flagLock.AcquireWriterLock().Wait();
			try
			{
				if (tempStringFlags.ContainsKey(flag.Key))
				{
					tempStringFlags[flag.Key] = newValue;
				}
				else
				{
					tempStringFlags.Add(flag.Key, newValue);
				}
			}
			finally
			{
				flagLock.ReleaseWriterLock();
			}
		}

		public void SetIntFlagTemporarily(FeatureFlag flag, int newValue)
		{
			flagLock.AcquireWriterLock().Wait();
			try
			{
				if (tempIntFlags.ContainsKey(flag.Key))
				{
					tempIntFlags[flag.Key] = newValue;
				}
				else
				{
					tempIntFlags.Add(flag.Key, newValue);
				}
			}
			finally
			{
				flagLock.ReleaseWriterLock();
			}
		}

		public void RemoveTemporaryFlag(FeatureFlag flag)
		{
			flagLock.AcquireWriterLock().Wait();
			switch (flag.Type)
			{
			case FeatureFlagType.Bool:
				tempBoolFlags.Remove(flag.Key);
				break;
			case FeatureFlagType.String:
			case FeatureFlagType.WebviewUrl:
				tempStringFlags.Remove(flag.Key);
				break;
			case FeatureFlagType.Int:
				tempIntFlags.Remove(flag.Key);
				break;
			}
			flagLock.ReleaseWriterLock();
		}

		protected async Task UpdateLaunchDarklyUser()
		{
			await flagLock.AcquireWriterLock();
			try
			{
				if (!(await EnsureLaunchDarklyConnected().ConfigureAwait(continueOnCapturedContext: false)))
				{
					return;
				}
				await updateUserPolicy.ExecuteAsync(async delegate
				{
					await launchDarklyClient.UpdateUser();
					await launchDarklyClient.UserSynced.FirstAsync((LaunchDarklySyncState result) => result.Status != LaunchDarklySyncStatus.InProgress);
				});
			}
			finally
			{
				flagLock.ReleaseWriterLock();
			}
		}

		protected async Task<bool> EnsureLaunchDarklyConnected()
		{
			if (launchDarklyClient == null)
			{
				return false;
			}
			if (launchDarklyClient.IsOnline())
			{
				return true;
			}
			await WhenLaunchDarklyConnectionChanged.Timeout(TimeSpan.FromMilliseconds(250.0)).FirstAsync((bool result) => result).Catch(Observable.Return(launchDarklyClient.IsOnline()));
			return launchDarklyClient.IsOnline();
		}

		public void SetOnline()
		{
			launchDarklyClient.SetOnline();
		}

		public void SetOffline()
		{
			launchDarklyClient.SetOffline();
		}

		public string GetWebviewAnalyticsString(FeatureFlag flag)
		{
			switch (flag.Type)
			{
			case FeatureFlagType.Bool:
				return IsFeatureEnabled(flag).ToString();
			case FeatureFlagType.Int:
				return GetInt(flag).ToString();
			case FeatureFlagType.String:
				return GetString(flag);
			case FeatureFlagType.WebviewUrl:
			{
				string result = "?";
				try
				{
					Uri uri = new Uri(GetString(flag));
					result = uri.Segments[1].Replace("/", "");
				}
				catch (Exception)
				{
					iFit.Logger.Log.Trace("FeatureFlags", "Unexpected Webview URL format for flag: " + GetString(flag));
				}
				return result;
			}
			default:
				return "Feature flag type unknown.";
			}
		}

		public string GetWebviewDataString(FeatureFlag flag)
		{
			switch (flag.Type)
			{
			case FeatureFlagType.Bool:
				return IsFeatureEnabled(flag).ToString().ToLower();
			case FeatureFlagType.Int:
				return GetInt(flag).ToString();
			case FeatureFlagType.String:
			case FeatureFlagType.WebviewUrl:
				return GetString(flag);
			default:
				throw new ArgumentException("Unknown flag type. Value can't be determined");
			}
		}

		public string GetWebviewDataString(string flag, FeatureFlagType type)
		{
			switch (type)
			{
			case FeatureFlagType.Bool:
				return GetBool(flag).ToString().ToLower();
			case FeatureFlagType.Int:
				return GetInt(flag).ToString();
			case FeatureFlagType.String:
			case FeatureFlagType.WebviewUrl:
				return GetString(flag);
			default:
				throw new ArgumentException("Unknown flag type. Value can't be determined");
			}
		}

		public void ClearTemporaryFlags()
		{
			tempStringFlags.Clear();
			tempIntFlags.Clear();
			tempBoolFlags.Clear();
		}
	}
	public enum FeatureFlagType
	{
		Bool,
		String,
		Int,
		WebviewUrl
	}
	public class FeatureFlag
	{
		public readonly string Key;

		public readonly FeatureFlagType Type;

		public readonly bool IsInLaunchDarkly;

		public FeatureFlag(string key, FeatureFlagType type, bool isInLaunchDarkly = true)
		{
			Key = key;
			Type = type;
			IsInLaunchDarkly = isInLaunchDarkly;
		}
	}
