	public class FitProCommTimeoutMonitoringService : IFitProCommTimeoutMonitoringService
	{
		private const int TimeoutAnalyticsDisabledThreshold = 0;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly ICoreAnalytics coreAnalytics;

		public int TimeoutCount { get; private set; }

		public FitProCommTimeoutMonitoringService(IFeatureFlagManager featureFlagManager, ICoreAnalytics coreAnalytics)
		{
			TimeoutCount = 0;
			this.featureFlagManager = featureFlagManager;
			this.coreAnalytics = coreAnalytics;
		}

		public void TimeoutOccurred()
		{
			TimeoutCount++;
			int num = featureFlagManager?.GetInt(FeatureFlags.ExcessiveFitProCommTimeoutThreshold) ?? 0;
			if (num > 0 && TimeoutCount == num)
			{
				iFit.Logger.Log.Trace("FitProCommTimeoutMonitoringService", $"FitPro StartPeriodicData timeouts have hit threshold {num}, sending analytics event.");
				coreAnalytics?.ExcessiveFitProCommTimeouts(num);
			}
		}
	}
	public class GlobalError
	{
		public string Message { get; set; }

		public bool ForceLogout { get; set; }

		public bool ShowDialog { get; set; }

		public GlobalError(string message)
		{
			Message = message;
		}
	}
	public interface IGlobalErrorService
	{
		IObservable<GlobalError> WhenGlobalErrorHappened { get; }

		void ReportGlobalError(Exception exception, bool showDialog = false, string displayMessage = null, bool forceLogout = false);
	}
	public class GlobalErrorService : IGlobalErrorService
	{
		private const string Tag = "GlobalErrorService";

		private readonly Subject<GlobalError> whenGlobalErrorHappened = new Subject<GlobalError>();

		public IObservable<GlobalError> WhenGlobalErrorHappened => whenGlobalErrorHappened;

		public void ReportGlobalError(Exception exception, bool showDialog = false, string displayMessage = null, bool forceLogout = false)
		{
			GlobalError globalError = new GlobalError(displayMessage ?? exception?.Message ?? AppStrings.global_error_default_message);
			iFit.Logger.Log.Error("GlobalErrorService", $"Global Error: {globalError.Message} (ForceLogout = {forceLogout})");
			globalError.ForceLogout = forceLogout;
			whenGlobalErrorHappened.OnNext(globalError);
		}
	}
	public class HistoricalStatChartDataProvider : ChartDataProvider
	{
		public enum MaxTailingRangeType
		{
			Key,
			Value
		}

		[Flags]
		public enum DataType
		{
			None = 0,
			Raw = 1,
			Normalized = 2,
			Bounded = 4,
			Binned = 8,
			NoBounded = 3,
			NoRaw = 6,
			NoNormalized = 5,
			All = 0xF
		}

		private const double EPSILON = 0.01;

		private const int numberOfSubBins = 3;

		private ActionBlock<bool> metricChangedBlock;

		private readonly DataType desiredType;

		private readonly MaxTailingRangeType tailingType;

		private readonly double? maxTrailingValue;

		private Tuple<double, double> leftBound;

		private Tuple<double, double> rightBound;

		protected readonly IDisposable metricStateSub;

		private double lastKey;

		private Tuple<double, double> previousData;

		private List<Tuple<double, double>> dataBins;

		protected bool preserveDataPoint;

		public override ChartDataCollection ProviderData { get; protected set; } = new ChartDataCollection();

		public ChartDataCollection BoundedData { get; protected set; } = new ChartDataCollection();

		public ChartDataCollection BinnedData { get; protected set; } = new ChartDataCollection();

		public bool IsDataBinned { get; private set; }

		public HistoricalStatChartDataProvider(IFitnessConsole console, Workout workout, FitnessValue metric, MetricStatList source, DataType desiredData, ChartMetricConfiguration.MetricType chartType, MaxTailingRangeType tailingType = MaxTailingRangeType.Key, double? maxTrailingValue = null, FitnessValue metricKey = FitnessValue.CurrentTime, List<Tuple<double, double>> dataBins = null)
			: base(console, workout, source, chartType, metricKey)
		{
			this.tailingType = tailingType;
			this.maxTrailingValue = maxTrailingValue;
			if (dataBins != null)
			{
				this.dataBins = dataBins.OrderBy((Tuple<double, double> t) => t.Item1).ToList();
			}
			desiredType = desiredData;
			IsDataBinned = (desiredData & DataType.Binned) == DataType.Binned && dataBins != null && dataBins.Count > 0;
			if (IsDataBinned)
			{
				ChartDataCollection providerData = ProviderData;
				if (providerData != null && providerData.Count > 0)
				{
					BinnedData.Add(ProviderData.FirstOrDefault());
				}
			}
			metricChangedBlock = new ActionBlock<bool>((Action<bool>)OnMetricChanged);
			lastKey = -1.0;
			metricStateSub = CreateMetricSub(FitnessValue.CurrentTime, shouldBlock: true);
		}

		private IDisposable CreateMetricSub(FitnessValue metricType, bool shouldBlock)
		{
			return console?.FacadeRepository.ObserveMetricChanges(metricType).Where(delegate(FitnessValueChange<double> x)
			{
				if (x != null)
				{
					IFitnessConsole fitnessConsole = console;
					if (fitnessConsole == null)
					{
						return false;
					}
					return fitnessConsole.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
				}
				return false;
			}).Subscribe(delegate
			{
				metricChangedBlock.Post(shouldBlock);
			});
		}

		public override void Dispose()
		{
			metricChangedBlock?.Complete();
			metricChangedBlock = null;
			metricStateSub?.Dispose();
			ProviderData?.Clear();
			BoundedData?.Clear();
			ProviderData = null;
			BoundedData = null;
		}

		private async void OnMetricChanged(bool isKeyMetric)
		{
			if (IsDataBinned)
			{
				UpdateBinnedData();
			}
			if ((desiredType & DataType.Raw) == DataType.Raw)
			{
				UpdateRawData();
			}
			if ((desiredType & DataType.Bounded) == DataType.Bounded)
			{
				await UpdateBoundedData();
			}
		}

		private void UpdateBinnedData()
		{
			if (source != null)
			{
				MetricStatList metricStatList = source;
				if (metricStatList == null || metricStatList.Count >= 1)
				{
					double newDataValue = BinDataValue(source.Last.Value, dataBins, 3);
					AddDataPointIfNeeded(newDataValue, BinnedData);
				}
			}
		}

		protected virtual void UpdateRawData()
		{
			if (source != null)
			{
				MetricStatList metricStatList = source;
				if (metricStatList == null || metricStatList.Count >= 1)
				{
					AddDataPointIfNeeded(source.Last.Value, ProviderData);
				}
			}
		}

		private void AddDataPointIfNeeded(double newDataValue, ChartDataCollection dataCollection)
		{
			double latestKeyForType = GetLatestKeyForType(KeyMetric);
			if (latestKeyForType < lastKey || latestKeyForType.AlmostEqual(lastKey, 1))
			{
				return;
			}
			lastKey = latestKeyForType;
			Tuple<double, double> tuple = new Tuple<double, double>(latestKeyForType, newDataValue);
			Tuple<double, double> tuple2 = previousData;
			if (tuple2 != null && tuple2.Item2.AlmostEqual(tuple.Item2, 2))
			{
				if (preserveDataPoint)
				{
					preserveDataPoint = false;
					dataCollection?.Add(tuple);
				}
				else if (dataCollection != null && dataCollection.Count > 0)
				{
					dataCollection[dataCollection.Count - 1] = tuple;
				}
			}
			else
			{
				dataCollection?.Add(tuple);
				preserveDataPoint = true;
			}
			previousData = tuple;
		}

		private async Task UpdateBoundedData()
		{
			if (BoundedData == null)
			{
				return;
			}
			try
			{
				if (leftBound != null && BoundedData.Contains(leftBound))
				{
					BoundedData.Remove(leftBound);
				}
				if (rightBound != null && BoundedData.Contains(rightBound))
				{
					BoundedData.Remove(rightBound);
				}
				Func<StatDataPoint, bool> func = ((!maxTrailingValue.HasValue) ? ((Func<StatDataPoint, bool>)((StatDataPoint x) => true)) : ((tailingType != MaxTailingRangeType.Key) ? ((Func<StatDataPoint, bool>)((StatDataPoint x) => source.Last.Value - x.Value <= maxTrailingValue)) : ((Func<StatDataPoint, bool>)((StatDataPoint x) => (double)console.LatestBasicInfo.TimeSeconds - x.Timestamp <= maxTrailingValue))));
				foreach (StatDataPoint item2 in source)
				{
					if (func(item2) && !ContainsEquivalent(BoundedData, item2))
					{
						BoundedData.Add(item2.ToTuple());
					}
				}
				Trim(BoundedData);
				double latestKey = GetLatestKeyForType(KeyMetric);
				if (maxTrailingValue.HasValue && tailingType == MaxTailingRangeType.Key)
				{
					double index = Math.Max(0.0, latestKey - maxTrailingValue.Value);
					double item = (await source.LastStatAtTimeStamp(index))?.Value ?? 0.0;
					if (BoundedData.Count == 0 || Math.Abs(BoundedData.First().Item1 - index) > 0.01)
					{
						leftBound = new Tuple<double, double>(index, item);
						BoundedData.Insert(0, leftBound);
					}
				}
				if (BoundedData.Count > 0)
				{
					rightBound = new Tuple<double, double>(latestKey, BoundedData.ExcludingNulls().Last().Item2);
					if (Math.Abs(BoundedData.Last().Item1 - rightBound.Item1) > 0.01)
					{
						BoundedData.Add(rightBound);
					}
				}
			}
			catch (Exception ex)
			{
				Shire.Core.Util.TaskContinueWithException.LogThreadException(ex);
			}
		}

		protected void Trim(IList<Tuple<double, double>> collection)
		{
			if (!maxTrailingValue.HasValue || collection.Count == 0)
			{
				return;
			}
			Func<Tuple<double, double>, double> itemValue;
			if (tailingType == MaxTailingRangeType.Key)
			{
				itemValue = (Tuple<double, double> x) => (double)console.LatestBasicInfo.TimeSeconds - x.Item1;
			}
			else
			{
				itemValue = (Tuple<double, double> x) => collection.Last().Item2 - x.Item2;
			}
			List<Tuple<double, double>> list = collection.Where((Tuple<double, double> x) => itemValue(x) > maxTrailingValue).ToList();
			foreach (Tuple<double, double> item in list)
			{
				collection.Remove(item);
			}
		}

		protected bool ContainsEquivalent(ICollection<Tuple<double, double>> collection, StatDataPoint point)
		{
			foreach (Tuple<double, double> item in collection)
			{
				if (item.Item1.AlmostEqual(point.Timestamp, 0.01) && item.Item2.AlmostEqual(point.Value, 0.01))
				{
					return true;
				}
			}
			return false;
		}

		protected double BinDataValue(double dataValue, List<Tuple<double, double>> bins, int subBinCount)
		{
			if (bins == null || bins.Count == 0 || subBinCount < 1)
			{
				return dataValue;
			}
			IEnumerable<Tuple<double, double>> enumerable = bins.Where((Tuple<double, double> tuple2) => dataValue >= tuple2.Item1 && dataValue < tuple2.Item2);
			if (enumerable.CountSafe() == 0)
			{
				return dataValue;
			}
			Tuple<double, double> tuple = enumerable.First();
			if (subBinCount == 1)
			{
				return (tuple.Item2 - tuple.Item1) / 2.0;
			}
			List<Tuple<double, double, double>> list = new List<Tuple<double, double, double>>();
			double num = (tuple.Item2 - tuple.Item1) / (double)subBinCount;
			double num2 = 1.7976931348623157E+308;
			double result = dataValue;
			for (int num3 = 0; num3 < subBinCount; num3++)
			{
				double num4 = tuple.Item1 + (double)num3 * num;
				double b = num4 + num;
				double num5 = num4 + num / 2.0;
				double num6 = tuple.Item1 + (double)num3 * num + num / 2.0;
				if (!dataValue.AlmostEqual(b))
				{
					double num7 = Math.Abs(num5 - dataValue);
					if (num7 < num2)
					{
						num2 = num7;
						result = num5;
					}
				}
			}
			return result;
		}
	}
