		public HRTrainingService(IFeatureFlagManager flagManager, IIfitApiService ifitApiService, IWorkoutFeatureService workoutFeatureService, IInAppNotificationService inAppNotificationService, IVideoService videoService, IActivePulseService activePulseService, IFitnessConsoleManager fitnessConsoleManager)
		{
			this.flagManager = flagManager;
			this.ifitApiService = ifitApiService;
			this.workoutFeatureService = workoutFeatureService;
			this.inAppNotificationService = inAppNotificationService;
			this.videoService = videoService;
			this.activePulseService = activePulseService;
			this.fitnessConsoleManager = fitnessConsoleManager;
			trailingHRQueue = new FixedSizedQueue<WorkoutScaleValueChangeData>(5);
			trailingRpmQueue = new FixedSizedQueue<WorkoutScaleValueChangeData>(11);
			workoutFeatureService.WhenScalingModeChanged.Subscribe(OnScalingModeChanged);
			OnScalingModeChanged(workoutFeatureService.ScalingMode);
			workoutFeatureService.UserChangedMetric.Subscribe(OnUserChangeMetric);
		}

		public void Stop()
		{
			workout = null;
			StopPulse();
			inAppNotificationsSub?.Dispose();
			inAppNotificationsSub = null;
			metricSub?.Dispose();
			metricSub = null;
			timeMetricSub?.Dispose();
			timeMetricSub = null;
			workoutPausedSub?.Dispose();
			workoutPausedSub = null;
			workoutResumedSub?.Dispose();
			workoutResumedSub = null;
			_whenHRZoneDataChanged.OnNext(null);
			trailingHRQueue?.Clear();
			trailingRpmQueue?.Clear();
		}

		public void Start(IFitnessConsole console, Workout workout, IReadOnlyList<Workout.TimestampedValue> hrTargetZones, string activityGuid)
		{
			if (workoutFeatureService.IsActivePulseAvailableInWorkout())
			{
				this.workout = workout;
				this.hrTargetZones = hrTargetZones;
				this.activityGuid = activityGuid;
				activePulseModel = flagManager.GetString(FeatureFlags.ActivePulseModel);
				paused = false;
				currentAt = 0;
				lastUserActionAtValue = 0;
				lastPauseAtValue = 0;
				startupChecksPerformed = false;
				firstSuccessfulPulse = false;
				DetermineControlType(console);
				InitUserHRSettings();
				metricSub?.Dispose();
				FitnessValue[] types = new FitnessValue[3]
				{
					FitnessValue.Pulse,
					FitnessValue.StrokesPerMin,
					FitnessValue.Rpm
				};
				metricSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(fitnessConsoleManager.ObserveValues(types).Where((Func<AnyFitnessValueChange, bool>)delegate
				{
					IFitnessConsole fitnessConsole = console;
					return fitnessConsole != null && fitnessConsole.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
				}), FitnessValueChangedAsync);
				workoutPausedSub = console.WhenStateChanged.Where((StateChange st) => st.Current == ConsoleState.Paused).SubscribeWithErrorLogging(delegate
				{
					Pause();
				});
				workoutResumedSub = console.WhenStateChanged.Where((StateChange st) => st.Current == ConsoleState.Resume || st.Current == ConsoleState.Workout).SubscribeWithErrorLogging(delegate
				{
					Resume();
				});
				if (inAppNotificationService != null)
				{
					inAppNotificationsSub?.Dispose();
					inAppNotificationsSub = inAppNotificationService.NotificationChanges.Subscribe(InAppNotification);
				}
				if (workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
				{
					StartPulse();
				}
			}
		}

		private void OnScalingModeChanged(ScalingMode ScalingMode)
		{
			if (workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
			{
				ControlAdapter?.LockWorkoutScale(controlType);
				_whenSuggestedLevelChanged.OnNext(WorkoutLevelUpdate.CreateWithNoChange());
				StartPulse();
			}
			else
			{
				_whenSuggestedLevelChanged.OnNext(WorkoutLevelUpdate.CreateWithActivePulseDisabled());
				StopPulse();
			}
		}

		private void OnUserChangeMetric(FitnessValue metricType)
		{
			lastUserActionAtValue = currentAt;
		}

		private void StartPulse()
		{
			iFit.Logger.Log.Trace("HRTrainingService", "Starting Pulse");
			if (workout == null)
			{
				return;
			}
			if (IsHRTestWorkoutId(workout.Id))
			{
				iFit.Logger.Log.Trace("HRTrainingService", "NOT sending data to pulse: this workout is the heart rate test, ID: " + workout.Id);
				return;
			}
			intervalSec = flagManager.GetInt(FeatureFlags.EvaluateWorkoutZoneInterval, 5);
			int size = flagManager.GetInt(FeatureFlags.EvaluateWorkoutZoneQueueSize, 5);
			trailingHRQueue = new FixedSizedQueue<WorkoutScaleValueChangeData>(size);
			trailingRpmQueue = new FixedSizedQueue<WorkoutScaleValueChangeData>(11);
			pulseLogLevel = flagManager.GetString(FeatureFlags.PulseLogLevel) ?? "error";
			sendDataToPulse = true;
			timeMetricSub?.Dispose();
			timeMetricSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(videoService.PreBufferedVideoPlayer.WhenVideoPositionSecondsChanged, async delegate(double at)
			{
				await SecondsMetricChangedAsync((int)at);
			});
			if (!startupChecksPerformed)
			{
				startupChecksPerformed = true;
				Task.Run(async delegate
				{
					await Task.Delay(3000);
					CheckForAndPostStartupNotifications();
				}).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private void CheckForAndPostStartupNotifications()
		{
			if (workout != null)
			{
				if (!workout.IsPulseOptimized)
				{
					inAppNotificationService?.Post(new CoachingMessageNotificationData(HowlActivePulseType.WorkoutNotOptimized));
				}
				if ((double)currentAt < CountdownPeriod.TotalSeconds)
				{
					inAppNotificationService?.Post(new CoachingMessageNotificationData(HowlActivePulseType.ActivePulseWarmup));
				}
			}
		}

		private void StopPulse()
		{
			sendDataToPulse = false;
		}

		private async Task FitnessValueChangedAsync(AnyFitnessValueChange change)
		{
			switch (change.Type)
			{
			case FitnessValue.Pulse:
				currentBpm = Convert.ToInt32(change.Current);
				await UpdateHRZoneData();
				break;
			case FitnessValue.Rpm:
			case FitnessValue.StrokesPerMin:
				currentRpm = Convert.ToInt32(change.Current);
				break;
			}
		}

		private async Task SecondsMetricChangedAsync(int at)
		{
			if (at > currentAt)
			{
				currentAt = at;
				if (trailingHRQueue.Any((WorkoutScaleValueChangeData x) => x.at == at))
				{
					trailingHRQueue.First((WorkoutScaleValueChangeData x) => x.at == at).value = currentBpm;
				}
				else
				{
					trailingHRQueue.Enqueue(new WorkoutScaleValueChangeData
					{
						at = currentAt,
						value = currentBpm
					});
				}
				if (trailingRpmQueue.Any((WorkoutScaleValueChangeData x) => x.at == at))
				{
					trailingRpmQueue.First((WorkoutScaleValueChangeData x) => x.at == at).value = currentRpm;
				}
				else
				{
					trailingRpmQueue.Enqueue(new WorkoutScaleValueChangeData
					{
						at = currentAt,
						value = currentRpm
					});
				}
				if (at % intervalSec == 0)
				{
					iFit.Logger.Log.Trace("HRTrainingService", "SecondsMetricChangedAsync: Preparing Pulse data for workout scale check.");
					await PulseHeartRateData();
				}
				int num = ((int?)hrTargetZones?.LastOrDefault((Workout.TimestampedValue x) => x.At <= (double)currentAt)?.Value) ?? 1;
				if (num != currTargetZoneNum)
				{
					currTargetZoneNum = num;
					iFit.Logger.Log.Trace("HRTrainingService", "Updating HR zone data");
					await UpdateHRZoneData();
				}
			}
			else if (at < currentAt)
			{
				iFit.Logger.Log.Warn("HRTrainingService", string.Format("{0} at={1} is < currentAt{2}. Not updating HR queue or sending HR data.", "SecondsMetricChangedAsync", at, currentAt));
			}
		}

		protected async Task InitUserHRSettings()
		{
			try
			{
				userHRSettings = await (await User.GetMe(ifitApiService)).GetHeartRateSettings(ifitApiService, force: true);
				userHRSettings?.Zones?.Sort((UserHeartRateZone x, UserHeartRateZone y) => x.MinBpm.CompareTo(y.MinBpm));
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("HRTrainingService", "ERROR getting user HR settings: " + ex.Message, ex);
			}
			await UpdateHRZoneData();
		}

		private async Task UpdateHRZoneData()
		{
			if (userHRSettings != null)
			{
				List<UserHeartRateZone> zones = userHRSettings.Zones;
				if (zones != null && zones.Count == 5 && userHRSettings.HeartRateReserve != 0 && userHRSettings.RestingHeartRate != 0)
				{
					goto IL_00ba;
				}
			}
			userHRSettings = await CalculateDefaultHRSettings();
			goto IL_00ba;
			IL_00ba:
			UserHeartRateZone userHeartRateZone = userHRSettings?.Zones?.FirstOrDefault((UserHeartRateZone x) => x.ZoneNumber == currTargetZoneNum);
			bool currentBpmMatchesTargetZone = currentBpm >= userHeartRateZone?.MinBpm && currentBpm <= userHeartRateZone?.MaxBpm;
			int zoneForCurrentBpm = GetZoneForCurrentBpm();
			HRZoneUpdate value = new HRZoneUpdate
			{
				CurrentAt = TimeSpan.FromSeconds(currentAt),
				CurrentBpm = currentBpm,
				CurrentBpmZoneNum = zoneForCurrentBpm,
				CurrentBpmMatchesTargetZone = currentBpmMatchesTargetZone,
				HasAchievedCurrentZone = hasAchievedCurrentZone,
				TargetZone = userHeartRateZone,
				RestingHR = (userHRSettings?.RestingHeartRate ?? 65),
				HRReserve = (userHRSettings?.HeartRateReserve ?? 120),
				CurrScale = CurrentWorkoutScale(),
				ScaleState = scaleState,
				BpmRange = new List<int> { BpmRangeMin, BpmRangeMax },
				SuppressNotificationOnUpdate = suppressNotificationOnUpdate
			};
			_whenHRZoneDataChanged?.OnNext(value);
		}

		protected int GetZoneForCurrentBpm()
		{
			if (currentBpm == 0 || currentBpm < userHRSettings.Zones.First().MinBpm || currentBpm > userHRSettings.Zones.Last().MaxBpm)
			{
				return 0;
			}
			foreach (UserHeartRateZone zone in userHRSettings.Zones)
			{
				if (currentBpm <= zone.MaxBpm)
				{
					return zone.ZoneNumber;
				}
			}
			return (userHRSettings?.Zones?.Last().ZoneNumber).GetValueOrDefault();
		}

		private void DetermineControlType(IFitnessConsole console)
		{
			List<Workout.Control.ControlType> source = workout.Controls.Select((Workout.Control x) => x.Type).ToList();
			if (console.ConsoleInfo.CanSetKph && source.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Mps))
			{
				controlType = Workout.Control.ControlType.Mps;
			}
			if (console.ConsoleInfo.CanSetGear && source.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Gear))
			{
				controlType = Workout.Control.ControlType.Gear;
			}
			if (console.ConsoleInfo.CanSetResistance && !console.ConsoleInfo.CanSetGear)
			{
				if (source.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Resistance))
				{
					controlType = Workout.Control.ControlType.Resistance;
				}
				else if (source.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.RelativeResistance))
				{
					controlType = Workout.Control.ControlType.RelativeResistance;
				}
			}
			if (console.ConsoleInfo.CanSetIncline && source.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Incline))
			{
				controlType = Workout.Control.ControlType.Incline;
			}
		}

		private int CurrentWorkoutScale()
		{
			return ControlAdapter?.ScaleForControlType(controlType) ?? 0;
		}

		public async Task<UserHeartRateSettings> CalculateDefaultHRSettings()
		{
			int num = 185;
			int hrReserve = num - 65;
			User currentlyAuthenticatedUser = ifitApiService.CurrentlyAuthenticatedUser;
			if (currentlyAuthenticatedUser != null)
			{
				num = ((currentlyAuthenticatedUser.Age > 0 && currentlyAuthenticatedUser.Age < 220) ? (220 - currentlyAuthenticatedUser.Age) : 185);
				hrReserve = num - 65;
			}
			List<UserHeartRateZone> list = new List<UserHeartRateZone>();
			int num2 = 1;
			for (double num3 = 0.5; num3 < 1.0; num3 = Math.Round((num3 + 0.1) * 100.0) / 100.0)
			{
				(int, int) zoneLimits = GetZoneLimits(hrReserve, num3);
				list.Add(new UserHeartRateZone(num2, zoneLimits.Item1, zoneLimits.Item2));
				num2++;
			}
			return new UserHeartRateSettings
			{
				Zones = list,
				MaxHeartRate = num,
				RestingHeartRate = 65
			};
		}

		private (int minBpm, int maxBpm) GetZoneLimits(int hrReserve, double percent)
		{
			return (minBpm: (int)Math.Round((double)hrReserve * percent + 65.0), maxBpm: (int)Math.Round((double)hrReserve * (percent + 0.1) + 65.0));
		}

		private async Task PulseHeartRateData()
		{
			_ = 1;
			try
			{
				if (ControlAdapter == null)
				{
					iFit.Logger.Log.Warn("HRTrainingService", "WARNING: HRTrainingService.ControlAdapter has not been set and we can't send correct workout scale to pulse!!");
				}
				bool flag = workoutFeatureService.ScalingMode != ScalingMode.ActivePulse;
				if (paused || flag)
				{
					if (flag)
					{
						iFit.Logger.Log.Trace("HRTrainingService", string.Format("Blocking Pulse request - we're in a non-scaling mode. {0}: {1}", "ScalingMode", workoutFeatureService.ScalingMode));
					}
					return;
				}
				string userId = ifitApiService.CurrentlyAuthenticatedUserId;
				WorkoutScaleRequest workoutScaleRequest = new WorkoutScaleRequest
				{
					userId = userId,
					workoutId = workout.Id,
					activityLogId = activityGuid,
					atValue = currentAt,
					heartRateValues = trailingHRQueue.ToList(),
					rpmValues = trailingRpmQueue.ToList(),
					currentScaleLevel = CurrentWorkoutScale(),
					lastPauseAtValue = lastPauseAtValue,
					lastUserActionAtValue = lastUserActionAtValue,
					maxScaleLevel = (ControlAdapter?.MaxScaleLevelAllowed ?? 0),
					isMockedWorkout = IsUsingMockDevice,
					softwareNumber = SoftwareNumber,
					consoleType = ConsoleType,
					activePulseModel = activePulseModel
				};
				SetWorkoutSubsetDataIfNeedBe(workoutScaleRequest);
				iFit.Logger.Log.Trace("HRTrainingService", "Requesting a workout scale check from activePulseService");
				WorkoutScaleResponse workoutScaleResponse = await activePulseService.WorkoutScaleCheck(workoutScaleRequest, pulseLogLevel).ConfigureAwait(continueOnCapturedContext: false);
				firstSuccessfulPulse = true;
				iFit.Logger.Log.Trace("HRTrainingService", $"Pulse requesting a scale change of: {workoutScaleResponse}");
				iFit.Logger.Log.Trace("HRTrainingService", $"userId={userId}, currentScaleLevel={workoutScaleRequest.currentScaleLevel}, lastUserActionAtValue={workoutScaleRequest.lastUserActionAtValue}, maxScaleLevel={workoutScaleRequest.maxScaleLevel}, widgetState={workoutScaleResponse.WidgetState}, currentAt={currentAt}, activePulseModel={activePulseModel}");
				if (workoutScaleResponse.TriggerPause)
				{
					sideRailResponseSave = workoutScaleResponse;
					workoutFeatureService.TurnMode(ScalingMode.ActivePulse, on: false);
					_whenSideRailsDetected.OnNext(workoutScaleResponse.TriggerPause);
				}
				else
				{
					await ProcessScaleCheckResponse(workoutScaleResponse);
				}
			}
			catch (Exception ex)
			{
				if (workout != null && workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
				{
					_whenSuggestedLevelChanged.OnNext(WorkoutLevelUpdate.CreateWithError());
				}
				iFit.Logger.Log.Error("HRTrainingService", "ERROR sending Heart Rate data: " + ex.Message, ex);
			}
		}

		private void SetWorkoutSubsetDataIfNeedBe(WorkoutScaleRequest request)
		{
			if (!firstSuccessfulPulse)
			{
				iFit.Logger.Log.Trace("HRTrainingService", "SetWorkoutSubsetDataIfNeedBe: Setting workout subset data for the workout scale request.");
				request.scaleRequestWorkout = new WorkoutSubset
				{
					HeartRateZones = workout.HeartRateZones,
					Controls = workout.Controls,
					ScaledControls = workout.ScaledControls,
					Metadata = workout.Metadata,
					TargetValue = workout.TargetValue,
					StartingLevel = workout.GetScaledWorkoutDetails()?.StartingLevel
				};
			}
		}

		private async Task ProcessScaleCheckResponse(WorkoutScaleResponse scaleCheckResponse, bool suppressNotifications = false)
		{
			bool flag = false;
			if (scaleCheckResponse.BpmRange.CountSafe() >= 2)
			{
				if (BpmRangeMin != scaleCheckResponse.BpmRange[0])
				{
					BpmRangeMin = scaleCheckResponse.BpmRange[0];
					flag = true;
				}
				int num = scaleCheckResponse.BpmRange[1] - 1;
				int num2 = num;
				UserHeartRateSettings userHeartRateSettings = userHRSettings;
				if (num2 == ((userHeartRateSettings == null) ? ((int?)null) : (userHeartRateSettings.Zones?.Last().MaxBpm - 1)))
				{
					num = userHRSettings.Zones.Last().MaxBpm;
				}
				if (BpmRangeMax != num)
				{
					BpmRangeMax = num;
					flag = true;
				}
			}
			if (scaleCheckResponse.WidgetState != scaleState)
			{
				scaleState = scaleCheckResponse.WidgetState;
				flag = true;
			}
			if (scaleCheckResponse.HasAchievedCurrentZone != hasAchievedCurrentZone)
			{
				hasAchievedCurrentZone = scaleCheckResponse.HasAchievedCurrentZone;
				flag = true;
			}
			WorkoutLevelUpdate response = WorkoutLevelUpdate.CreateWithResponse(scaleCheckResponse);
			if (flag)
			{
				suppressNotificationOnUpdate = ControlAdapter.SuppressScaleNotification(response.DeltaScale);
				await UpdateHRZoneData().ConfigureAwait(continueOnCapturedContext: false);
			}
			if (workoutFeatureService.IsScalingModeEnabled(ScalingMode.ActivePulse))
			{
				iFit.Logger.Log.Trace("HRTrainingService", "Pulse creating response");
				_whenSuggestedLevelChanged.OnNext(response);
				ScaleChange(response, suppressNotifications);
			}
		}

		private void ScaleChange(WorkoutLevelUpdate response, bool suppressNotifications = false)
		{
			if (response.Change == WorkoutLevelChange.ScaleChange && response.DeltaScale != 0)
			{
				ControlAdapter.ChangeWorkoutScaleBy(response.DeltaScale, suppressNotifications);
			}
		}

		protected void Pause()
		{
			paused = true;
			lastPauseAtValue = currentAt;
		}

		protected void Resume()
		{
			UserActionHappened();
			paused = false;
		}

		public string RetrieveHRTestWorkoutId(ConsoleType consoleType)
		{
			if (consoleType.IsRower())
			{
				return "5c47afeba108190030ff2f73";
			}
			if (consoleType.IsBike())
			{
				return "5bf5b051faa602002862a96d";
			}
			if (consoleType.IsElliptical())
			{
				return "5c5ca054b1d655002e6e1552";
			}
			return "5bc655bec6cebe002da3f1b4";
		}

		public static bool IsHRTestWorkoutId(string workoutId)
		{
			return MaxHrTestWorkIds.Any((string x) => x.Equals(workoutId));
		}

		public double BpmToInterpolatedZone(double bpm)
		{
			return userHRSettings?.BpmToInterpolatedZone(bpm) ?? 0.0;
		}

		private void InAppNotification((NotificationChangeType type, NotificationData data) obj)
		{
			if (obj.type == NotificationChangeType.Remove && obj.data is CoachingMessageNotificationData && obj.data.ActionHappened)
			{
				CoachingMessageNotificationData coachingMessageNotificationData = obj.data as CoachingMessageNotificationData;
				if (coachingMessageNotificationData.IsMessage(HowlActivePulseType.WorkoutNotOptimized))
				{
					workoutFeatureService.TurnMode(ScalingMode.ActivePulse, on: false);
				}
			}
		}

		public void SiderailContinue()
		{
			workoutFeatureService.TurnMode(ScalingMode.ActivePulse, on: true);
			WorkoutScaleResponse workoutScaleResponse = sideRailResponseSave;
			sideRailResponseSave = null;
			if (workoutScaleResponse != null)
			{
				ProcessScaleCheckResponse(workoutScaleResponse, suppressNotifications: true);
			}
		}

		public void UserActionHappened()
		{
			lastUserActionAtValue = currentAt;
		}
	}
