	public interface IIfitJoinService
	{
		Task<Tuple<User, LoginResult>> CreateAndLoginUser(User user);
	}
	public class IfitJoinService : IIfitJoinService
	{
		private readonly IIfitApiService ifitApi;

		private readonly IIfitUserExistenceService ifitUserExistence;

		private readonly IConnectivity connectivity;

		public IfitJoinService(IIfitApiService ifitApi, IConnectivity connectivity, IIfitUserExistenceService ifitUserExistence)
		{
			this.ifitApi = ifitApi;
			this.connectivity = connectivity;
			this.ifitUserExistence = ifitUserExistence;
		}

		public async Task<Tuple<User, LoginResult>> CreateAndLoginUser(User user)
		{
			LoginResult loginResult = await UserCanBeCreated(user);
			if (loginResult != LoginResult.Success)
			{
				return new Tuple<User, LoginResult>(user, loginResult);
			}
			string password = user.Password;
			LoginResult result = LoginResult.UnknownFailure;
			try
			{
				user = await user.CreateWithUsernameConflictResolution(ifitApi);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", $"Error creating user from JoinLoginService.CreateAndLoginUser: {ex.GetBaseException()}");
				return new Tuple<User, LoginResult>(user, LoginResult.UnableToCreateUser);
			}
			try
			{
				result = ((!string.IsNullOrEmpty(user.Facebook)) ? (await ifitApi.LoginViaProvider(user.Facebook, LoginProvider.facebook)) : (string.IsNullOrEmpty(user.Google) ? (await ifitApi.Login(user.Username, password)) : (await ifitApi.LoginViaProvider(user.Google, LoginProvider.google))));
			}
			catch (Exception ex2)
			{
				iFit.Logger.Log.Error("Api", $"Error logging in JoinLoginService.CreateAndLoginUser: {ex2.GetBaseException()}");
			}
			return new Tuple<User, LoginResult>(user, result);
		}

		private async Task<LoginResult> UserCanBeCreated(User user)
		{
			if (!connectivity.IsConnected)
			{
				return LoginResult.NoInternetConnection;
			}
			try
			{
				if (await ifitUserExistence.EmailInUse(user.Email))
				{
					return LoginResult.EmailInUse;
				}
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", $"Error checking email availability from JoinLoginService.CreateAndLoginUser: {ex.GetBaseException()}");
				return LoginResult.UnknownFailure;
			}
			return LoginResult.Success;
		}
	}
	public interface IIfitUserExistenceService
	{
		Task<bool> EmailInUse(string email);

		Task<bool> UsernameInUse(string email);

		Task<bool> EmailOrUsernameInUse(string email);

		bool CheckEmailFormat(string email);

		bool CheckUsernameFormat(string username);

		Task<LoginResult> CheckEmailUsernameAvailability(string usernameOrEmail);
	}
	public class IfitUserExistenceService : IIfitUserExistenceService
	{
		private readonly IIfitApiService ifitApi;

		private readonly IConnectivity connectivity;

		public IfitUserExistenceService(IIfitApiService ifitApi, IConnectivity connectivity)
		{
			this.ifitApi = ifitApi;
			this.connectivity = connectivity;
		}

		public async Task<bool> EmailInUse(string email)
		{
			AbleToCheckValidity(email);
			return await User.ExistsWithEmail(ifitApi, email);
		}

		public async Task<bool> UsernameInUse(string username)
		{
			AbleToCheckValidity(username);
			return await User.ExistsWithUsername(ifitApi, username);
		}

		public async Task<bool> EmailOrUsernameInUse(string emailOrUsername)
		{
			if (emailOrUsername.IsValidEmail())
			{
				return await EmailInUse(emailOrUsername);
			}
			return await UsernameInUse(emailOrUsername);
		}

		public bool CheckEmailFormat(string email)
		{
			return email.IsValidEmail();
		}

		public bool CheckUsernameFormat(string username)
		{
			return username.IsValidUsername();
		}

		public async Task<LoginResult> CheckEmailUsernameAvailability(string usernameOrEmail)
		{
			LoginResult validity = LoginResult.UnknownFailure;
			try
			{
				validity = (usernameOrEmail.IsValidEmail() ? ((!(await EmailInUse(usernameOrEmail))) ? LoginResult.EmailAvailable : LoginResult.EmailInUse) : ((!usernameOrEmail.IsValidUsername()) ? LoginResult.InvalidUsername : ((!(await UsernameInUse(usernameOrEmail))) ? LoginResult.UsernameAvailable : LoginResult.UsernameInUse)));
			}
			catch (ArgumentNullException)
			{
				validity = LoginResult.InvalidUsername;
			}
			catch (WebException)
			{
				validity = LoginResult.NoInternetConnection;
			}
			catch (Exception ex3)
			{
				iFit.Logger.Log.Error("Api", $"Error validating email/user name - {ex3.GetBaseException()}");
			}
			return validity;
		}

		private void AbleToCheckValidity(string emailOrUsername)
		{
			if (string.IsNullOrWhiteSpace(emailOrUsername))
			{
				iFit.Logger.Log.Trace("Api", "null emailOrUsername: " + emailOrUsername);
				throw new ArgumentNullException("emailOrUsername");
			}
			if (!connectivity.IsConnected)
			{
				iFit.Logger.Log.Trace("Api", $"not connected: {connectivity.IsConnected}");
				throw new WebException("No internet connectivity");
			}
		}
	}
