	public interface IJavascriptBridge : IDisposable
	{
		string LogTag { get; set; }

		Action<JavascriptBridgeCallLog> CallJavascript { get; set; }

		List<DelayedMethodCall> NativeMessagesReceivedBeforeViewModelShown { get; }

		void Call(string methodName, IDictionary<string, string> parameters);

		void Call(string methodName);

		void Call(JavascriptBridgeCallLog javascriptCallLog);

		void Expose(string methodName, Action<IDictionary<string, string>> methodBody);

		void Expose(string methodName, Action methodBody);

		void Expose<T>(string methodName, Action<T> methodBody) where T : class, new();

		void ExposeTask(string methodName, Func<IDictionary<string, string>, Task> methodBody);

		void HandleMessage(string message);
	}
	public class DelayedMethodCall
	{
		public string MethodName { get; }

		public IDictionary<string, object> Arguments { get; }

		public DelayedMethodCall(string methodName, IDictionary<string, object> arguments)
		{
			MethodName = methodName;
			Arguments = arguments;
		}
	}
	public class JavascriptBridge : IJavascriptBridge, IDisposable
	{
		public static string MethodToSetConfigs = "MethodToSetConfigs";

		protected readonly Dictionary<string, Action> methodsWithoutArguments = new Dictionary<string, Action>();

		protected readonly Dictionary<string, Action<IDictionary<string, string>>> methodsWithSimpleArguments = new Dictionary<string, Action<IDictionary<string, string>>>();

		protected readonly Dictionary<string, Action<object>> methodsWithComplexArguments = new Dictionary<string, Action<object>>();

		private readonly Dictionary<string, Type> complexArgumentTypes = new Dictionary<string, Type>();

		public const string KeyMethodName = "methodName";

		public string LogTag { get; set; }

		public Action<JavascriptBridgeCallLog> CallJavascript { get; set; }

		public List<DelayedMethodCall> NativeMessagesReceivedBeforeViewModelShown { get; private set; } = new List<DelayedMethodCall>();

		public void Call(string methodName)
		{
			Call(methodName, new Dictionary<string, string>());
		}

		public void Call(string methodName, IDictionary<string, string> parameters)
		{
			Call(new JavascriptBridgeCallLog(methodName, parameters));
		}

		public void Call(JavascriptBridgeCallLog javascriptCallLog)
		{
			CallJavascript?.Invoke(javascriptCallLog);
		}

		public void Expose(string methodName, Action<IDictionary<string, string>> methodBody)
		{
			methodsWithSimpleArguments[methodName] = methodBody;
		}

		public void Expose<T>(string methodName, Action<T> methodBody) where T : class, new()
		{
			methodsWithComplexArguments[methodName] = delegate(object o)
			{
				methodBody((T)o);
			};
			complexArgumentTypes[methodName] = typeof(T);
		}

		public void ExposeTask(string methodName, Func<IDictionary<string, string>, Task> methodBody)
		{
			Expose(methodName, delegate(IDictionary<string, string> obj)
			{
				methodBody(obj);
			});
		}

		public void Expose(string methodName, Action methodBody)
		{
			methodsWithoutArguments[methodName] = methodBody;
		}

		public void HandleMessage(string message)
		{
			IDictionary<string, object> dictionary;
			string text;
			try
			{
				dictionary = JsonConvert.DeserializeObject<Dictionary<string, object>>(message);
				text = (string)dictionary["methodName"];
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error(LogTag, "ERROR Parsing message from javascript: " + message + ".\nEnsure it's a valid JSON string with a 'methodName' value.");
				iFit.Logger.Log.Error(LogTag, $"{arg}");
				return;
			}
			dictionary.Remove("methodName");
			if (methodsWithSimpleArguments.ContainsKey(text))
			{
				Dictionary<string, string> dictionary2 = new Dictionary<string, string>();
				foreach (KeyValuePair<string, object> item2 in dictionary)
				{
					dictionary2[item2.Key] = item2.Value?.ToString();
				}
				methodsWithSimpleArguments[text](dictionary2);
			}
			else if (methodsWithoutArguments.ContainsKey(text))
			{
				methodsWithoutArguments[text]();
			}
			else if (methodsWithComplexArguments.ContainsKey(text))
			{
				Type type = complexArgumentTypes[text];
				object obj = JsonConvert.DeserializeObject(message, type);
				methodsWithComplexArguments[text](obj);
			}
			else
			{
				DelayedMethodCall item = new DelayedMethodCall(text, dictionary);
				NativeMessagesReceivedBeforeViewModelShown.Add(item);
				iFit.Logger.Log.Error(LogTag, "JavascriptBridge received unknown message with methodName: " + text);
			}
		}

		public void Dispose()
		{
			CallJavascript = null;
			methodsWithoutArguments?.Clear();
			methodsWithSimpleArguments?.Clear();
			methodsWithComplexArguments?.Clear();
			complexArgumentTypes?.Clear();
			NativeMessagesReceivedBeforeViewModelShown?.Clear();
		}
	}
	public class JavascriptBridgeCallLog
	{
		public string MethodName { get; }

		public IDictionary<string, string> JavascriptDict { get; }

		public string Javascript { get; }

		public string LogMessage { get; set; }

		public JavascriptBridgeCallLog(string methodName, IDictionary<string, string> javascriptDict, string javascript, string logMessage)
		{
			MethodName = methodName;
			JavascriptDict = javascriptDict;
			Javascript = javascript;
			LogMessage = logMessage;
		}

		public JavascriptBridgeCallLog(string methodName, IDictionary<string, string> parameters, string logMessage = null)
		{
			MethodName = methodName;
			JavascriptDict = parameters;
			Javascript = GenerateJavascriptString(parameters);
			LogMessage = logMessage ?? Javascript;
		}

		public JavascriptBridgeCallLog(JavascriptBridgeCallLog javascriptCallLog)
		{
			MethodName = javascriptCallLog.MethodName;
			JavascriptDict = javascriptCallLog.JavascriptDict;
			Javascript = javascriptCallLog.Javascript;
			LogMessage = javascriptCallLog.LogMessage;
		}

		private string GenerateJavascriptString(IDictionary<string, string> parameters = null)
		{
			StringBuilder stringBuilder = new StringBuilder();
			stringBuilder.Append("callJavaScript(");
			stringBuilder.Append("'{");
			stringBuilder.Append("\"methodName\" : \"" + MethodName + "\"");
			if (parameters != null)
			{
				foreach (string key in parameters.Keys)
				{
					string text = parameters[key];
					if (!string.IsNullOrEmpty(text))
					{
						text = text.Replace("'", "\\'");
						text = text.Replace("\"", "\\\\\"");
					}
					stringBuilder.Append(", ");
					stringBuilder.Append("\"" + key + "\" : \"" + text + "\"");
				}
			}
			stringBuilder.Append("}'");
			stringBuilder.Append(")");
			return stringBuilder.ToString();
		}

		public void ReplaceLogKeyValue(IDictionary<string, string> newParameters)
		{
			iFit.Logger.Log.Trace("WebView", "Replacing key/values in log.");
			try
			{
				if (JavascriptDict == null || newParameters == null)
				{
					throw new ArgumentNullException($"this.JavascriptDict: {JavascriptDict}, newParameters: {newParameters}");
				}
				foreach (string item in newParameters.Keys.Where((string key) => JavascriptDict.ContainsKey(key)))
				{
					JavascriptDict[item] = newParameters[item];
				}
				LogMessage = GenerateJavascriptString(JavascriptDict);
			}
			catch (NullReferenceException)
			{
				iFit.Logger.Log.Debug("WebView", "Null reference caught when replacing key values in log.");
			}
			catch (ArgumentNullException)
			{
				iFit.Logger.Log.Debug("WebView", "Javascript could not be converted to Dictionary<string, string>");
			}
		}

		public void RemoveLogKeyValue(ICollection<string> removedKeys)
		{
			iFit.Logger.Log.Trace("WebView", "Removing unwanted values from log.");
			Dictionary<string, string> newParameters = removedKeys.ToDictionary((string key) => key, (string key) => "Removed");
			ReplaceLogKeyValue(newParameters);
		}

		public void RemoveLogKeyValue(IDictionary<string, string> removedParameters)
		{
			RemoveLogKeyValue(removedParameters.Keys);
		}

		public void RemoveLogKeyValue(string removedKey)
		{
			RemoveLogKeyValue(new List<string> { removedKey });
		}

		public void ShortenLog(int maxSize = 500)
		{
			LogMessage = ShortenLog(LogMessage, maxSize);
		}

		private static string ShortenLog(string log, int maxSize = 500)
		{
			iFit.Logger.Log.Trace("WebView", "Trimming log string.");
			if (log.Length <= maxSize)
			{
				return log;
			}
			return log.Remove(maxSize) + "...";
		}

		public void AddLogAndShortenKeyValues(IDictionary<string, string> logDict, int maxSize = 500, IList<string> whiteList = null)
		{
			Dictionary<string, string> dictionary = new Dictionary<string, string>();
			foreach (string key in logDict.Keys)
			{
				string text = logDict[key];
				if (whiteList == null || !whiteList.Contains(key))
				{
					text = ShortenLog(text, maxSize);
				}
				dictionary.Add(key, text);
			}
			LogMessage = GenerateJavascriptString(dictionary);
		}
	}
	public class LiveWorkoutChartDataProvider : HistoricalStatChartDataProvider
	{
		private const int UpdateThreashold = 750;

		private readonly ICaptionParser captionParser;

		private int lastTimeStampFromCaptions;

		private DateTime lastCaptionUpdate;

		public LiveWorkoutChartDataProvider(IFitnessConsole console, Workout workout, FitnessValue metric, MetricStatList source, DataType desiredData, ChartMetricConfiguration.MetricType chartType, ICaptionParser captionParser, MaxTailingRangeType tailingType = MaxTailingRangeType.Key, double? maxTrailingValue = null, FitnessValue metricKey = FitnessValue.CurrentTime)
			: base(console, workout, metric, source, desiredData, chartType)
		{
			this.captionParser = captionParser;
			lastCaptionUpdate = new DateTime(0L);
			if (base.CombinedAudioVideoPlayer != null)
			{
				base.CombinedAudioVideoPlayer.OnNewCaptionString -= HandleNewCaptionString;
				base.CombinedAudioVideoPlayer.OnNewCaptionString += HandleNewCaptionString;
			}
			preserveDataPoint = false;
			metricStateSub?.Dispose();
		}

		public override void Dispose()
		{
			if (base.CombinedAudioVideoPlayer != null)
			{
				base.CombinedAudioVideoPlayer.OnNewCaptionString -= HandleNewCaptionString;
			}
			base.Dispose();
		}

		protected override double GetLatestKeyForType(FitnessValue keyType)
		{
			return lastTimeStampFromCaptions;
		}

		private void HandleNewCaptionString(object sender, string caption)
		{
			DateTime utcNow = DateTime.UtcNow;
			if (!string.IsNullOrEmpty(caption) && !(utcNow.Subtract(lastCaptionUpdate).TotalMilliseconds < 750.0))
			{
				string[] array = caption.Split(new string[1] { "\n" }, StringSplitOptions.RemoveEmptyEntries);
				LiveWorkoutControlValues liveWorkoutControlValues;
				try
				{
					liveWorkoutControlValues = captionParser?.GetWorkoutControlValues(array.Last());
				}
				catch (ArgumentException ex)
				{
					iFit.Logger.Log.Error("Workout", "Error handling new caption string for chart update: " + ex.Message);
					return;
				}
				if (liveWorkoutControlValues != null && liveWorkoutControlValues.WorkoutState == LiveWorkoutState.InWorkout)
				{
					lastTimeStampFromCaptions = (int)liveWorkoutControlValues.CurrentSeconds;
					UpdateRawData();
					lastCaptionUpdate = utcNow;
				}
			}
		}
	}
