			ShippingCity = null;
			ShippingCountry = null;
			ShippingState = null;
			ActivationCode = null;
		}
	}
	public interface IPendingConnectivityCreate : IDisposable
	{
		Task ConnectivityChanged(bool connected);
	}
	public class PendingConnectivityCreate : IPendingConnectivityCreate, IDisposable
	{
		private readonly IIfitApiService api;

		private IDisposable connectivityChanged;

		public IObservable<bool> WhenConnectivityChanged => from x in Observable.FromEventPattern<ConnectivityChangedEventHandler, ConnectivityChangedEventArgs>(delegate(ConnectivityChangedEventHandler h)
			{
				CrossConnectivity.Current.ConnectivityChanged += h;
			}, delegate(ConnectivityChangedEventHandler h)
			{
				CrossConnectivity.Current.ConnectivityChanged -= h;
			})
			select x.EventArgs.IsConnected;

		public PendingConnectivityCreate(IIfitApiService api)
		{
			this.api = api;
			Sindarin.Core.Util.ObservableExtensions.SubscribeAsync(Observable.Timer(TimeSpan.FromMinutes(5.0)).Take(1), (long _) => InitialFiveMinuteCheck());
		}

		private async Task InitialFiveMinuteCheck()
		{
			connectivityChanged = Sindarin.Core.Util.ObservableExtensions.SubscribeAsync(WhenConnectivityChanged, ConnectivityChanged);
			if (CrossConnectivity.Current.IsConnected)
			{
				await ConnectivityChanged(connected: true);
			}
		}

		public void Dispose()
		{
			connectivityChanged?.Dispose();
		}

		public async Task ConnectivityChanged(bool connected)
		{
			if (connected)
			{
				await RetryPendingItems<UserLog>();
			}
		}

		protected async Task RetryPendingItems<T>() where T : IPendingCreate
		{
			_ = 4;
			try
			{
				IEnumerable<PendingCreateItem<T>> pendingItems = await api.Cache.GetAllObjects<PendingCreateItem<T>>();
				pendingItems.OrderBy((PendingCreateItem<T> x) => x.PendingItem.RequestingUserId);
				List<User> authenticatedUsers = await api.GetAuthenticatedUsers();
				foreach (PendingCreateItem<T> item in pendingItems)
				{
					try
					{
						if (authenticatedUsers.Any((User x) => x.Id.Equals(item.PendingItem.RequestingUserId)))
						{
							if (!api.CurrentlyAuthenticatedUserId.Equals(item.PendingItem.RequestingUserId))
							{
								await api.SwitchUser(item.PendingItem.RequestingUserId);
							}
							T pendingItem = item.PendingItem;
							IIfitApiService ifitApiService = api;
							await pendingItem.RetryCreate(ifitApiService);
							await api.Cache.InvalidateObject<PendingCreateItem<T>>(item.Key);
						}
					}
					catch (Exception)
					{
					}
				}
			}
			catch (KeyNotFoundException)
			{
			}
		}
	}
	public abstract class PredictedChartDataProviderBase : ChartDataProvider
	{
		protected IScalingControlAdapter _controlAdapter;

		private readonly IDisposable metricStateSub;

		private IDisposable scaleSub;

		private IDisposable userMaxMpsSub;

		protected readonly Workout workout;

		private int scaleLevel;

		public override ChartDataCollection ProviderData { get; protected set; } = new ChartDataCollection();

		public IScalingControlAdapter ControlAdapter
		{
			get
			{
				return _controlAdapter;
			}
			set
			{
				_controlAdapter = value;
				if (value != null)
				{
					scaleSub?.Dispose();
					scaleSub = null;
					scaleSub = CreateScaleSub();
					userMaxMpsSub?.Dispose();
					userMaxMpsSub = null;
					userMaxMpsSub = CreateUserMaxMpsSub();
				}
			}
		}

		protected Workout.Control.ControlType? ControlType { get; set; }

		protected PredictedChartDataProviderBase(IFitnessConsole console, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey, FitnessValue? dataPointMetric = null)
			: base(console, workout, null, chartType, metricKey)
		{
			this.workout = workout;
			if (!workout.IsMissingScaledControls())
			{
				scaleLevel = workout.StartingControlLevel;
			}
			metricStateSub = CreateMetricSub(FitnessValue.CurrentTime);
		}

		public abstract Task InitAsync();

		protected virtual List<Workout.Control> GetControlsList()
		{
			List<Workout.Control> result = workout.Controls;
			if (ControlType.HasValue && !workout.IsMissingScaledControls())
			{
				scaleLevel = ControlAdapter?.ScaleForControlType(ControlType.Value) ?? scaleLevel;
				result = workout.GetScaledWorkoutControls(scaleLevel);
			}
			return result;
		}

		private IDisposable CreateMetricSub(FitnessValue metricType)
		{
			return (from x in console.FacadeRepository.ObserveMetricChanges(metricType)
				where console.LatestBasicInfo.CurrentState == ConsoleState.Workout
				select x).Subscribe(delegate
			{
				UpdateData();
			});
		}

		private IDisposable CreateScaleSub()
		{
			if (ControlType.HasValue)
			{
				return ControlAdapter.ScaleChangedForControlType.Where((Workout.Control.ControlType x) => x == ControlType.Value).Subscribe(delegate
				{
					UpdateDueToScaleChange();
				});
			}
			return null;
		}

		private IDisposable CreateUserMaxMpsSub()
		{
			if (ControlType.HasValue)
			{
				return ControlAdapter.UserMaxMpsChanged.Subscribe(delegate
				{
					UpdateDueToScaleChange();
				});
			}
			return null;
		}

		private void UpdateDueToScaleChange()
		{
			List<Tuple<double, double>> scalingRawData = GetScalingRawData();
			if (scalingRawData != null && scalingRawData.Count > 0)
			{
				ProviderData.RemoveAllAndAddList(scalingRawData);
				UpdateData();
			}
		}

		protected virtual List<Tuple<double, double>> GetScalingRawData()
		{
			return new List<Tuple<double, double>>();
		}

		protected virtual void UpdateData()
		{
			double latestKeyForType = GetLatestKeyForType(KeyMetric);
			ProviderData.RemoveDataBeforeKey(latestKeyForType);
		}

		public override void Dispose()
		{
			base.Dispose();
			metricStateSub?.Dispose();
			scaleSub?.Dispose();
			userMaxMpsSub?.Dispose();
			ProviderData?.Clear();
			ProviderData = null;
		}
	}
	public class PredictedInclineChartDataProvider : PredictedChartDataProviderBase
	{
		private readonly double inclineMax;

		private readonly double inclineMin;

		public PredictedInclineChartDataProvider(IFitnessConsole console, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey)
			: base(console, workout, chartType, metricKey, FitnessValue.Grade)
		{
			inclineMin = console.ConsoleInfo.MinIncline;
			inclineMax = console.ConsoleInfo.MaxIncline;
			base.ControlType = Workout.Control.ControlType.Incline;
		}

		public override Task InitAsync()
		{
			List<Tuple<double, double>> scalingRawData = GetScalingRawData();
			if (scalingRawData.Count > 0)
			{
				ProviderData.AddRange(scalingRawData);
			}
			return Task.FromResult(0);
		}

		protected override List<Tuple<double, double>> GetScalingRawData()
		{
			List<Tuple<double, double>> list = new List<Tuple<double, double>>();
			List<Workout.Control> controlsList = GetControlsList();
			List<Workout.Control> list2 = controlsList.Where((Workout.Control x) => x.Type == base.ControlType).ToList();
			if (list2 != null && list2.Count > 0)
			{
				list.Add(new Tuple<double, double>(0.0, list2.First().Value));
				foreach (Workout.Control item3 in list2)
				{
					double item = Math.Min(Math.Max(inclineMin, item3.Value), inclineMax);
					list.Add(new Tuple<double, double>(item3.At, item));
				}
				double item2 = Math.Ceiling(workout.TargetValue);
				list.Add(new Tuple<double, double>(item2, list2.Last().Value));
			}
			return list;
		}
	}
