		public PredictedVerticalNetChartDataProvider(IFitnessConsole console, List<Tuple<double, double>> source, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey = FitnessValue.CurrentTime)
			: base(console, workout, chartType, metricKey, FitnessValue.VerticalMeterNet)
