	public interface IRemainingWorkoutEstimates : IDisposable
	{
		IObservable<WorkoutEstimator.Stats> WhenRemainingStatsChanged { get; }

		WorkoutEstimator.Stats LatestRemainingStats { get; }

		void UpdateUserKgs(double userWeightKgs);
	}
	public class RemainingWorkoutEstimates : IRemainingWorkoutEstimates, IDisposable
	{
		private readonly Subject<WorkoutEstimator.Stats> _whenRemainingStatsChanged = new Subject<WorkoutEstimator.Stats>();

		protected readonly IFitnessConsole console;

		protected readonly Workout mainWorkout;

		protected readonly Workout warmup;

		protected readonly Workout cooldown;

		protected Workout targetWorkout;

		private readonly IWorkoutEstimator estimator;

		private readonly IDisposable stateSub;

		private IDisposable metricSub;

		public IObservable<WorkoutEstimator.Stats> WhenRemainingStatsChanged => _whenRemainingStatsChanged;

		public WorkoutEstimator.Stats LatestRemainingStats { get; private set; }

		public RemainingWorkoutEstimates(IFitnessConsole console, double userWeightKgs, double userHeightMeters, double userAge, bool userMale, Workout mainWorkout, Workout warmup = null, Workout cooldown = null)
		{
			this.console = console;
			this.mainWorkout = mainWorkout;
			this.warmup = warmup;
			this.cooldown = cooldown;
			estimator = WorkoutEstimator.Factory(console, userWeightKgs, userHeightMeters, userAge, userMale);
			StateChanged(console.LatestBasicInfo.CurrentState);
			stateSub = console.WhenStateChanged.Subscribe(delegate(StateChange x)
			{
				StateChanged(x.Current);
			});
		}

		public void Dispose()
		{
			stateSub?.Dispose();
			metricSub?.Dispose();
		}

		public void UpdateUserKgs(double userWeightKgs)
		{
			estimator.UpdateUserKgs(userWeightKgs);
		}

		private void StateChanged(ConsoleState state)
		{
			metricSub?.Dispose();
			switch (state)
			{
			case ConsoleState.WarmUp:
				targetWorkout = warmup;
				break;
			case ConsoleState.Workout:
			case ConsoleState.PauseOverride:
				targetWorkout = mainWorkout;
				break;
			case ConsoleState.CoolDown:
				targetWorkout = cooldown;
				break;
			default:
				return;
			}
			SetupWorkoutSub();
		}

		private void SetupWorkoutSub()
		{
			if (targetWorkout == null)
			{
				LatestRemainingStats = null;
				_whenRemainingStatsChanged.OnNext(null);
				return;
			}
			ICurrentTimeFacade currentTimeFacade = Mvx.Resolve<ICurrentTimeFacade>();
			metricSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(currentTimeFacade.ObserveCurrentTimeChanges(), (FitnessValueChange<int> _) => Estimate());
			Task.Run((Func<Task>)Estimate);
		}

		protected virtual async Task Estimate()
		{
			if (targetWorkout.IsManual())
			{
				return;
			}
			double currentAt = GetCurrentAt(targetWorkout, console);
			string id = targetWorkout.Id;
			List<Workout.Control> list = targetWorkout.Controls.DeepClone();
			Workout.TargetType target = targetWorkout.Target;
			double targetValue = targetWorkout.TargetValue;
			Workout.WorkoutType type = targetWorkout.Type;
			double? workoutAverageHeartRate = targetWorkout.Metadata?.AverageHeartRate;
			bool shouldUseEquipmentlessConsole = targetWorkout.ShouldUseEquipmentlessConsole();
			bool isStrengthWorkout = targetWorkout.IsStrengthWorkout();
			double value = ((console.ConsoleInfo.MachineType.IsBeltBasedMachine() || 14 == 0) ? console.LatestBasicInfo.Kph : console.LatestBasicInfo.ActualKph);
			BaselineControl(Workout.Control.ControlType.Incline, console.LatestBasicInfo.Grade, list, currentAt);
			BaselineControl(Workout.Control.ControlType.Mps, UnitUtil.EnsureMps(SpeedUnit.Kph, value), list, currentAt, 0.01);
			BaselineControl(Workout.Control.ControlType.Resistance, console.LatestBasicInfo.Resistance, list, currentAt);
			BaselineControl(Workout.Control.ControlType.Gear, console.LatestBasicInfo.Gear?.CurrentGear ?? 0, list, currentAt);
			double targetRemaining = GetTargetRemaining(targetValue, currentAt);
			IEnumerable<Workout.Control> source = from x in list
				where x.At < currentAt
				group x by x.Type into x
				select x.MaxBy((Workout.Control y) => y.At).FirstOrDefault();
			Workout.Control[] array = source.ToArray();
			list.RemoveAll((Workout.Control x) => x.At < currentAt);
			list.ForEach(delegate(Workout.Control x)
			{
				x.At -= currentAt;
			});
			if (array != null)
			{
				Workout.Control[] array2 = array;
				foreach (Workout.Control control in array2)
				{
					if (list.Count((Workout.Control x) => Math.Abs(x.At) < 0.001 && x.Type == control?.Type) == 0)
					{
						control.At = 0.0;
						list.Insert(0, control);
					}
				}
			}
			if (!list.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps))
			{
				double value2 = UnitUtil.EnsureMps(SpeedUnit.Kph, value);
				Workout.Control item = new Workout.Control
				{
					At = 0.0,
					Type = Workout.Control.ControlType.Mps,
					Value = value2
				};
				list.Insert(0, item);
			}
			LatestRemainingStats = await estimator.EstimateWorkout(list, type, target, targetRemaining, workoutAverageHeartRate, shouldUseEquipmentlessConsole, isStrengthWorkout, id, null, useCache: false).ConfigureAwait(continueOnCapturedContext: false);
			_whenRemainingStatsChanged.OnNext(LatestRemainingStats);
		}

		protected virtual double GetCurrentAt(Workout workout, IFitnessConsole fitProConsole)
		{
			return workout.CurrentAt(fitProConsole);
		}

		protected virtual double GetTargetRemaining(double targetValue, double currentAt)
		{
			return targetValue - currentAt;
		}

		private void BaselineControl(Workout.Control.ControlType controlType, double currentControlValue, List<Workout.Control> controls, double currentAt, double comparison = 0.001)
		{
			double num = WorkoutEstimator.PreviousOrDefaultControl(controls, currentAt, controlType);
			double num2 = Math.Abs(num * comparison);
			if (!(Math.Abs(num - currentControlValue) <= num2))
			{
				controls.Where((Workout.Control x) => x.Type == controlType).ForEach(delegate(Workout.Control x)
				{
					x.Value = currentControlValue;
				});
			}
		}
	}
	public class ScalingModeStateMachine
	{
		private readonly Subject<bool> whenSmartAdjustModeChanged;

		private readonly Subject<bool> whenActivePulseModeChanged;

		private bool apAvailable;

		private bool saAvailable;

		private bool apSettingTurnedOn;

		private ScalingMode _current;

		private bool _heartRateMonitorConnected;

		private readonly Subject<ScalingMode> whenModeChanges = new Subject<ScalingMode>();

		public ScalingMode Saved { get; private set; }

		public ScalingMode Current
		{
			get
			{
				return _current;
			}
			protected set
			{
				if (_current != value)
				{
					_current = value;
					whenModeChanges.OnNext(_current);
					Acr.Logging.Log.Info("ScalingControl", $"ScalingMode changed to={_current}");
				}
			}
		}

		public bool HeartRateMonitorConnected
		{
			get
			{
				return _heartRateMonitorConnected;
			}
			set
			{
				if (value != _heartRateMonitorConnected)
				{
					_heartRateMonitorConnected = value;
					if (apSettingTurnedOn && (Current == ScalingMode.SmartAdjust || Current == ScalingMode.ActivePulse))
					{
						TurnMode(ScalingMode.ActivePulse, value);
					}
				}
			}
		}

		public IObservable<ScalingMode> WhenModeChanged => whenModeChanges;

		public ScalingModeStateMachine(Subject<bool> whenActivePulseModeChanged, Subject<bool> whenSmartAdjustModeChanged)
		{
			this.whenActivePulseModeChanged = whenActivePulseModeChanged;
			this.whenSmartAdjustModeChanged = whenSmartAdjustModeChanged;
		}

		public void WorkoutStarting(bool apAvailable, bool saAvailable, bool apSettingTurnedOn, bool smartAdjustEnabled, bool recoveryWorkout, bool videoWorkout)
		{
			this.apAvailable = apAvailable;
			this.saAvailable = saAvailable;
			this.apSettingTurnedOn = apSettingTurnedOn;
			Saved = (smartAdjustEnabled ? ScalingMode.SmartAdjust : ScalingMode.Legacy);
			if (recoveryWorkout && !videoWorkout)
			{
				_current = ScalingMode.Manual;
			}
			else if (!smartAdjustEnabled)
			{
				_current = ScalingMode.Legacy;
			}
			else
			{
				_current = ScalingMode.SmartAdjust;
			}
		}

		public bool IsModeEnabled(ScalingMode mode)
		{
			if (mode != Current)
			{
				if (mode == ScalingMode.SmartAdjust)
				{
					return Current == ScalingMode.ActivePulse;
				}
				return false;
			}
			return true;
		}

		public void TurnMode(ScalingMode mode, bool on)
		{
			if (on)
			{
				TurnModeOn(mode);
			}
			else
			{
				TurnModeOff(mode);
			}
		}

		private void TurnModeOn(ScalingMode mode)
		{
			if (Current == mode)
			{
				return;
			}
			switch (mode)
			{
			case ScalingMode.Manual:
				Saved = Current;
				Current = ScalingMode.Manual;
				break;
			case ScalingMode.Legacy:
				Current = ScalingMode.Legacy;
				break;
			case ScalingMode.ActivePulse:
				apSettingTurnedOn = true;
				whenActivePulseModeChanged.OnNext(value: true);
				if (HeartRateMonitorConnected && apAvailable)
				{
					Current = ScalingMode.ActivePulse;
				}
				else if (saAvailable && Current != ScalingMode.SmartAdjust)
				{
					Current = ScalingMode.SmartAdjust;
				}
				break;
			case ScalingMode.SmartAdjust:
				whenSmartAdjustModeChanged.OnNext(value: true);
				if (saAvailable && Current != ScalingMode.ActivePulse)
				{
					Current = ScalingMode.SmartAdjust;
				}
				break;
			default:
				throw new ArgumentOutOfRangeException("mode", mode, null);
			}
		}

		private void TurnModeOff(ScalingMode mode)
		{
			if (CanTurnModeOff(mode))
			{
				switch (mode)
				{
				case ScalingMode.Manual:
					Current = Saved;
					break;
				case ScalingMode.Legacy:
					Saved = ScalingMode.Legacy;
					Current = ScalingMode.Manual;
					break;
				case ScalingMode.ActivePulse:
					apSettingTurnedOn = false;
					whenActivePulseModeChanged.OnNext(value: false);
					Current = ScalingMode.SmartAdjust;
					break;
				case ScalingMode.SmartAdjust:
					whenSmartAdjustModeChanged.OnNext(value: false);
					Current = ScalingMode.Legacy;
					break;
				default:
					throw new ArgumentOutOfRangeException("mode", mode, null);
				}
			}
		}

		private bool CanTurnModeOff(ScalingMode mode)
		{
			if (mode != Current)
			{
				if (mode == ScalingMode.SmartAdjust)
				{
					return Current == ScalingMode.ActivePulse;
				}
				return false;
			}
			return true;
		}
	}
	public interface ISchedulerService : IDisposable
	{
		IObservable<DateTime> WhenDayChanged { get; }

		DateTime StartTime { get; }
	}
	public class SchedulerService : ISchedulerService, IDisposable
	{
		private readonly Subject<DateTime> whenDayChanged = new Subject<DateTime>();

		private IDisposable timerSub;

		public IObservable<DateTime> WhenDayChanged => whenDayChanged;

		public DateTime StartTime { get; protected set; }

		public SchedulerService()
			: this(null, null)
		{
		}

		private SchedulerService(TimeSpan? dueTime = null, TimeSpan? period = null)
		{
			StartTime = DateTime.Now;
			dueTime = dueTime ?? (DateTime.Today.AddDays(1.0) - DateTime.Now + TimeSpan.FromHours(1.5));
			period = period ?? TimeSpan.FromHours(24.0);
			timerSub = Observable.Timer(dueTime.Value, period.Value).Subscribe(delegate
			{
				whenDayChanged.OnNext(DateTime.Now);
			});
		}

		public static SchedulerService CreateWithMockTimespans(TimeSpan dueTime, TimeSpan period)
		{
			return new SchedulerService(dueTime, period);
		}

		public void Dispose()
		{
			whenDayChanged?.Dispose();
			timerSub?.Dispose();
			timerSub = null;
		}
	}
	public class WorkoutCompatibilityService
	{
		private readonly Dictionary<Tuple<ConsoleType, Workout.WorkoutType>, bool> compatibilityMatrix = new Dictionary<Tuple<ConsoleType, Workout.WorkoutType>, bool>();

		public WorkoutCompatibilityService()
		{
			InitializeCompatibilityMatrix();
		}

		private void SetCompatibility(ConsoleType consoleType, Workout.WorkoutType workoutType, bool compatible)
		{
			Tuple<ConsoleType, Workout.WorkoutType> key = new Tuple<ConsoleType, Workout.WorkoutType>(consoleType, workoutType);
			compatibilityMatrix[key] = compatible;
		}

		public bool GetCompatibility(ConsoleType consoleType, Workout.WorkoutType workoutType)
		{
			Tuple<ConsoleType, Workout.WorkoutType> key = new Tuple<ConsoleType, Workout.WorkoutType>(consoleType, workoutType);
			if (compatibilityMatrix.ContainsKey(key))
			{
				return compatibilityMatrix[key];
			}
			return false;
		}

		public bool GetCompatibility(IFitnessConsole console, Workout workout)
		{
			return GetCompatibility(console.ConsoleInfo.MachineType, workout.Type);
		}

		private void InitializeCompatibilityMatrix()
		{
			SetCompatibility(ConsoleType.Treadmill, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.InclineTrainer, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.Elliptical, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.VerticalElliptical, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.FreeStrider, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.Strider, Workout.WorkoutType.Run, compatible: true);
			SetCompatibility(ConsoleType.SpinBike, Workout.WorkoutType.Cycle, compatible: true);
			SetCompatibility(ConsoleType.Bike, Workout.WorkoutType.Cycle, compatible: true);
			SetCompatibility(ConsoleType.Rower, Workout.WorkoutType.Row, compatible: true);
			SetCompatibility(ConsoleType.Rower, Workout.WorkoutType.Rowing, compatible: true);
			SetCompatibility(ConsoleType.Equipmentless, Workout.WorkoutType.Strength, compatible: true);
			SetCompatibility(ConsoleType.Mirror, Workout.WorkoutType.Strength, compatible: true);
		}
	}
	public static class WorkoutCompatibilityExtensions
	{
		public static bool CanDoWorkout(this IFitnessConsole console, Workout workout, bool isStrengthMirror = false)
		{
			if (workout.IsVideoWorkout() || isStrengthMirror)
			{
				return console.CanDoWorkoutFilter(workout, isStrengthMirror);
			}
			return true;
		}

		public static bool CanDoWorkoutFilter(this IFitnessConsole console, Workout workout, bool isStrengthMirror)
		{
			if (isStrengthMirror == workout.HasStrengthMirrorWorkoutFilter())
			{
				return console.CanDoWorkoutType(workout);
			}
			return false;
		}

		public static bool CanDoWorkoutType(this IFitnessConsole console, Workout workout)
		{
			if (workout.Type == Workout.WorkoutType.Strength)
			{
				return true;
			}
			if (console?.ConsoleInfo == null)
			{
				iFit.Logger.Log.Trace("Workout", $"Cannot do workout type {workout.Type} because console or consoleInfo is null.");
				return false;
			}
			return console.CanDoWorkoutType(workout.Type, console.ConsoleInfo.MachineType);
		}

		public static bool CanDoWorkoutType(this IFitnessConsole console, Workout.WorkoutType workoutType, ConsoleType lastKnowConsoleType)
		{
			if (workoutType == Workout.WorkoutType.Strength)
			{
				return true;
			}
			WorkoutCompatibilityService workoutCompatibilityService = new WorkoutCompatibilityService();
			if (console is NonconnectedStrengthFitnessConsole && workoutType == Workout.WorkoutType.Strength)
			{
				return true;
			}
			if (console.IsHybridMachine())
			{
				bool flag = workoutCompatibilityService.GetCompatibility(ConsoleType.Treadmill, workoutType) || workoutCompatibilityService.GetCompatibility(ConsoleType.Bike, workoutType);
				if (!flag)
				{
					iFit.Logger.Log.Trace("Workout", $"Hybrid machine cannot do workout type {workoutType}.");
				}
				return flag;
			}
			bool compatibility = workoutCompatibilityService.GetCompatibility(lastKnowConsoleType, workoutType);
			if (!compatibility)
			{
				iFit.Logger.Log.Trace("Workout", $"{lastKnowConsoleType} cannot do workout type {workoutType}.");
			}
			return compatibility;
		}
	}
