	public interface IWorkoutFeatureService
	{
		bool HeartRateMonitorConnected { get; set; }

		ScalingMode ScalingMode { get; }

		IObservable<ScalingMode> WhenScalingModeChanged { get; }

		IObservable<bool> WhenSmartAdjustModeChanged { get; }

