		bool IsSmartAdjustAvailable(ConsoleType? consoleType, bool checkUser = true);

		bool IsScalingAvailable(Workout workout, Workout.WorkoutContext context, ConsoleType? consoleType);

		bool IsActivePulseAvailableInWorkout();

		bool IsSmartAdjustAvailableInWorkout();

		void WorkoutStarting(Workout workout, Workout.WorkoutContext context, ConsoleType consoleType, bool activePulseEnabled, bool smartAdjustEnabled, bool recoveryWorkout = false, bool isVideoWorkout = false);

		bool ShouldUseLycanStartingLevel(Workout workout);

