	public class WorkoutFeatureService : IWorkoutFeatureService
	{
		private static readonly string className = "WorkoutFeatureService";

		private readonly IIfitApiService ifitApiService;

		private readonly IFeatureFlagManager flagManager;

		private readonly IDeviceInformation deviceInfo;

		private readonly ScalingModeStateMachine scalingModeMachine;

		private Workout currentWorkout;

		private Workout.WorkoutContext currentContext;

		private ConsoleType currentConsoleType;

		private Subject<bool> _whenSmartAdjustModeChanged = new Subject<bool>();

		private Subject<bool> _whenActivePulseModeChanged = new Subject<bool>();

		private bool _showDebugPulseChangeLevelView;

		protected Subject<bool> _whenShowDebugPulseChangeLevelView = new Subject<bool>();

		private bool IsTablet => deviceInfo.IsTablet;

		private bool PremiumUser => ifitApiService?.CurrentlyAuthenticatedUser?.Premium == true;

		public IObservable<bool> WhenSmartAdjustModeChanged => _whenSmartAdjustModeChanged;

		public IObservable<bool> WhenActivePulseModeChanged => _whenActivePulseModeChanged;

		public bool HeartRateMonitorConnected
		{
			get
			{
				return scalingModeMachine.HeartRateMonitorConnected;
			}
			set
			{
				scalingModeMachine.HeartRateMonitorConnected = value;
			}
		}

		public ScalingMode SavedScalingMode => scalingModeMachine.Saved;

		public IObservable<ScalingMode> WhenScalingModeChanged => scalingModeMachine.WhenModeChanged;

		public ScalingMode ScalingMode => scalingModeMachine.Current;

		public Subject<FitnessValue> UserChangedMetric { get; } = new Subject<FitnessValue>();

		public bool ShowDebugPulseChangeLevelView
		{
			get
			{
				return _showDebugPulseChangeLevelView;
			}
			set
			{
				if (value != _showDebugPulseChangeLevelView)
				{
					_showDebugPulseChangeLevelView = value;
					_whenShowDebugPulseChangeLevelView.OnNext(value);
				}
			}
		}

		public IObservable<bool> WhenShowDebugPulseChangeLevelView => _whenShowDebugPulseChangeLevelView;

		public WorkoutFeatureService(IFeatureFlagManager flagManager, IDeviceInformation deviceInfo, IIfitApiService ifitApiService)
		{
			this.flagManager = flagManager;
			this.deviceInfo = deviceInfo;
			this.ifitApiService = ifitApiService;
			scalingModeMachine = new ScalingModeStateMachine(_whenActivePulseModeChanged, _whenSmartAdjustModeChanged);
		}

		public void WorkoutStarting(Workout workout, Workout.WorkoutContext context, ConsoleType consoleType, bool activePulseEnabled, bool smartAdjustEnabled = true, bool recoveryWorkout = false, bool isVideoWorkout = false)
		{
			currentWorkout = workout;
			currentContext = context;
			currentConsoleType = consoleType;
			scalingModeMachine.WorkoutStarting(IsActivePulseAvailableInWorkout(), IsSmartAdjustAvailableInWorkout(), activePulseEnabled, smartAdjustEnabled, recoveryWorkout, isVideoWorkout);
		}

		public bool IsScalingAvailable(Workout workout, Workout.WorkoutContext context, ConsoleType? consoleType)
		{
			if (!IsSmartAdjustAvailable(workout, context, consoleType))
			{
				return IsActivePulseAvailable(workout, context, consoleType);
			}
			return true;
		}

		public bool IsSmartAdjustAvailable(ConsoleType? consoleType, bool checkUser = true)
		{
			if (IsConsoleTypeAllowed(consoleType, FeatureFlags.SmartAdjustDevices))
			{
				return IsUserPremiumCheck(checkUser);
			}
			return false;
		}

		public bool IsActivePulseAvailable(ConsoleType? consoleType, bool checkUser = true)
		{
			if (IsSmartAdjustAvailable(consoleType, checkUser) && IsConsoleTypeAllowed(consoleType, FeatureFlags.ActivePulseDevices))
			{
				return IsUserPremiumCheck(checkUser);
			}
			return false;
		}

		public bool IsActivePulseAvailableInWorkout()
		{
			return IsActivePulseAvailable(currentWorkout, currentContext, currentConsoleType);
		}

		public bool IsSmartAdjustAvailableInWorkout()
		{
			return IsSmartAdjustAvailable(currentWorkout, currentContext, currentConsoleType);
		}

		public bool IsScalingModeEnabled(ScalingMode mode)
		{
			return scalingModeMachine.IsModeEnabled(mode);
		}

		public void TurnMode(ScalingMode mode, bool on)
		{
			scalingModeMachine.TurnMode(mode, on);
		}

		private bool IsUserPremiumCheck(bool checkUser = true)
		{
			if (checkUser)
			{
				return PremiumUser;
			}
			return true;
		}

		private bool IsSmartAdjustAvailable(Workout workout, Workout.WorkoutContext context, ConsoleType? consoleType)
		{
			bool flag = workout != null && IsTablet && IsUserPremiumCheck() && !IsNonScalingWorkout(workout, context) && IsConsoleTypeAllowed(consoleType, FeatureFlags.SmartAdjustDevices) && workout.IsVideoWorkout();
			iFit.Logger.Log.Info("Workout", $"{className}:IsSmartAdjustAvailable: {flag}  {this}");
			return flag;
		}

		private bool IsActivePulseAvailable(Workout workout, Workout.WorkoutContext context, ConsoleType? consoleType)
		{
			bool flag = workout != null && IsTablet && IsUserPremiumCheck() && !IsNonScalingWorkout(workout, context) && workout.IsVideoWorkout() && IsConsoleTypeAllowed(consoleType, FeatureFlags.SmartAdjustDevices) && IsConsoleTypeAllowed(consoleType, FeatureFlags.ActivePulseDevices);
			iFit.Logger.Log.Info("Workout", $"{className}:IsActivePulseAvailable: consoleType={consoleType.ToString().ToLower()} result={flag}  {this}");
			return flag;
		}

		public bool ShouldUseLycanStartingLevel(Workout workout)
		{
			bool flag = workout.IsVideoWorkout();
			iFit.Logger.Log.Info("Workout", $"{className}:ShouldUseLycanStartingLevel: {flag}  {this}");
			return flag;
		}

		protected bool IsNonScalingWorkout(Workout workout, Workout.WorkoutContext context)
		{
			if (!HRTrainingService.IsHRTestWorkoutId(workout.Id) && !workout.IsGoogleMap && !workout.IsManual() && !workout.IsStrengthWorkout() && context != Workout.WorkoutContext.ScheduledLive)
			{
				return context == Workout.WorkoutContext.ScheduledPre;
			}
			return true;
		}

		public override string ToString()
		{
			return $"[WorkoutFeatureService ScalingMode={ScalingMode}]";
		}

		public bool IsConsoleTypeAllowed(ConsoleType? consoleType, FeatureFlag featureFlag)
		{
			string text = flagManager.GetString(featureFlag)?.ToLower();
			if (!consoleType.HasValue || string.IsNullOrWhiteSpace(text))
			{
				return false;
			}
			HashSet<string> hashSet = new HashSet<string>();
			string[] array = text.Split(',');
			string[] array2 = array;
			foreach (string text2 in array2)
			{
				hashSet.Add(text2.Trim());
			}
			return hashSet.Contains(consoleType.ToString().ToLower());
		}
	}
}
