	public static class NRF51BinConverter
	{
		private static byte Ascii2Char(byte ascii)
		{
			if (ascii >= 65)
			{
				return (byte)(ascii - 55);
			}
			if (ascii >= 48)
			{
				return (byte)(ascii - 48);
			}
			return 255;
		}

		private static byte ReadByte(byte[] hex, int pointer)
		{
			byte b = Ascii2Char(hex[pointer]);
			byte b2 = Ascii2Char(hex[pointer + 1]);
			return (byte)((b << 4) | b2);
		}

		private static ushort ReadAddress(byte[] hex, int pointer)
		{
			byte b = ReadByte(hex, pointer);
			byte b2 = ReadByte(hex, pointer + 2);
			return (ushort)((b << 8) | b2);
		}

		private static int CalculateBinLength(byte[] hex)
		{
			if (hex == null || hex.Length == 0)
			{
				return 0;
			}
			int num = 0;
			int num2 = hex.Length;
			int num3 = 0;
			uint num4 = 0u;
			do
			{
				byte b = hex[num3];
				num3++;
				if (b != 58)
				{
					return 0;
				}
				byte b2 = ReadByte(hex, num3);
				num3 += 2;
				ushort num5 = ReadAddress(hex, num3);
				num3 += 4;
				byte b3 = ReadByte(hex, num3);
				num3 += 2;
				switch (b3)
				{
				case 4:
				{
					uint num6 = ReadAddress(hex, num3);
					if (num > 0 && num6 != (num4 >> 16) + 1)
					{
						return num;
					}
					num4 = num6 << 16;
					break;
				}
				case 2:
				{
					uint num7 = (uint)(ReadAddress(hex, num3) << 4);
					if (num > 0 && num7 >> 16 != (num4 >> 16) + 1)
					{
						return num;
					}
					num4 = num7;
					break;
				}
				case 0:
					if (num4 + num5 >= 4096)
					{
						num += b2;
					}
					break;
				}
				num3 += b2 << 1;
				num3 += 2;
				if (hex[num3] == 13)
				{
					num3++;
				}
				if (hex[num3] == 10)
				{
					num3++;
				}
			}
			while (num3 < num2);
			return num;
		}

		public static byte[] HexToBin(byte[] hex)
		{
			int num = CalculateBinLength(hex);
			int num2 = hex.Length;
			int num3 = 0;
			int num4 = 0;
			uint num5 = 0u;
			byte[] array = new byte[num];
			int num6 = 0;
			do
			{
				byte b = hex[num3];
				num3++;
				if (b != 58)
				{
					return null;
				}
				byte b2 = ReadByte(hex, num3);
				num3 += 2;
				ushort num7 = ReadAddress(hex, num3);
				num3 += 4;
				byte b3 = ReadByte(hex, num3);
				num3 += 2;
				switch (b3)
				{
				case 4:
				{
					uint num9 = ReadAddress(hex, num3);
					num3 += 4;
					if (num4 > 0 && num9 != (num5 >> 16) + 1)
					{
						return TruncateArray(array, num4);
					}
					num5 = num9 << 16;
					break;
				}
				case 2:
				{
					uint num8 = (uint)(ReadAddress(hex, num3) << 4);
					num3 += 4;
					if (num4 > 0 && num8 >> 16 != (num5 >> 16) + 1)
					{
						return TruncateArray(array, num4);
					}
					num5 = num8;
					break;
				}
				case 0:
					if (num5 + num7 >= 4096)
					{
						for (int i = 0; i < b2; i++)
						{
							array[num6] = ReadByte(hex, num3);
							num6++;
							num3 += 2;
							num4++;
						}
					}
					else
					{
						num3 += b2 << 1;
					}
					break;
				default:
					num3 += b2 << 1;
					break;
				}
				num3 += 2;
				if (hex[num3] == 13)
				{
					num3++;
				}
				if (hex[num3] == 10)
				{
					num3++;
				}
			}
			while (num3 < num2);
			return TruncateArray(array, num4);
		}

		private static byte[] TruncateArray(byte[] sourceArr, int length)
		{
			if (sourceArr.Length == length)
			{
				return sourceArr;
			}
			byte[] array = new byte[length];
			Array.Copy(sourceArr, array, length);
			return array;
		}
	}
	public interface ISaveUpdateFilesService
	{
		IFolder SaveFolder { get; }

		Task SavePairKeySoftwareNumber(string pairKey, int softwareNumber);

		Task SaveUpdateDetails(IFirmware firmware, string pairKey = null);

		Task SaveFile(string fileName, IFile file);

		Task<IVersion> GetCurrentUpdateVersion();

		Task<string> GetCurrentUpdatePairKey();

		Task<IFirmware> GetCurrentUpdateFirmware();

		Task<IFile> GetFileFromFolder(string path);

		Task<List<Tuple<string, int>>> GetSetOfPreviouslyConnectedMachines();

		Task CleanUpSavedFiles();

		Task CleanUpCurrentUpdateFiles();

		Task DeleteFileFromFolder(string fileName);
	}
	public class SaveUpdateFilesService : ISaveUpdateFilesService
	{
		public const string SaveFolderName = ".wolfUpdating";

		private const string VersionFileName = "version.txt";

		private const string PairKeySoftwareNumberFileName = "pairKeysSoftwareNumber.txt";

		private const string PairKeyFileName = "currentUpdatePairKey.txt";

		public const string BleFirmwareFileName = "application.hex";

		public const string BleMetadataFileName = "application.dat";

		public const string UsbFirmwareFileName = "usbFirmwareFile.cyacd";

		private readonly TaskCompletionSource<bool> folderTcs;

		private readonly SemaphoreSlim pairKeySS = new SemaphoreSlim(1, 1);

		private readonly SemaphoreSlim versionSS = new SemaphoreSlim(1, 1);

		public IFolder SaveFolder { get; protected set; }

		public SaveUpdateFilesService()
		{
			folderTcs = new TaskCompletionSource<bool>();
			Task.Run(() => SetupFile());
		}

		private async Task SetupFile()
		{
			SaveFolder = await FileSystem.Current.LocalStorage.CreateFolderAsync(".wolfUpdating", CreationCollisionOption.OpenIfExists);
			folderTcs.TrySetResult(result: true);
		}

		public async Task CleanUpSavedFiles()
		{
			_ = 3;
			try
			{
				await folderTcs.Task;
				await pairKeySS.WaitAsync();
				await versionSS.WaitAsync();
				(await SaveFolder.GetFilesAsync()).ForEach(async delegate(IFile file)
				{
					await file.DeleteAsync();
				});
			}
			catch (DirectoryNotFoundException)
			{
				iFit.Logger.Log.Error("Updating", "Path Previously Cleaned");
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Updating", $"Error Cleaning Up All Saved Files {arg}");
				throw;
			}
			finally
			{
				pairKeySS.Release();
				versionSS.Release();
			}
		}

		public async Task<IFile> GetFileFromFolder(string path)
		{
			await folderTcs.Task;
			return await SaveFolder.CreateFileAsync(path, CreationCollisionOption.OpenIfExists);
		}

		public async Task<List<Tuple<string, int>>> GetSetOfPreviouslyConnectedMachines()
		{
			List<Tuple<string, int>> results = new List<Tuple<string, int>>();
			string text = await ReadFile("pairKeysSoftwareNumber.txt", pairKeySS);
			if (string.IsNullOrWhiteSpace(text))
			{
				return results;
			}
			string[] source = text.Split(new char[1] { '\n' }, StringSplitOptions.RemoveEmptyEntries);
			results.AddRange(from lineTuple in source.Select(GetTupleFromLine)
				where lineTuple != null
				select lineTuple);
			return results;
		}

		public async Task SaveFile(string fileName, IFile file)
		{
			_ = 1;
			try
			{
				await folderTcs.Task;
				if (!Path.Combine(SaveFolder.Path, fileName).Equals(Path.Combine(SaveFolder.Path, file.Name)))
				{
					await file.MoveAsync(Path.Combine(SaveFolder.Path, fileName));
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error in saving file [{fileName}] to disk", exception);
				throw;
			}
		}

		public async Task SaveUpdateDetails(IFirmware firmware, string pairKey = null)
		{
			_ = 4;
			try
			{
				await SaveVersion(firmware.Version);
				if (string.IsNullOrWhiteSpace(pairKey))
				{
					await SaveFile("usbFirmwareFile.cyacd", firmware.FirmwareFile);
					return;
				}
				await SavePairKey(pairKey);
				await SaveFile("application.hex", firmware.FirmwareFile);
				await SaveFile("application.dat", firmware.MetadataFile);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Problem in `SaveUpdateDetails`", exception);
				throw;
			}
		}

		public async Task<IVersion> GetCurrentUpdateVersion()
		{
			return UpdateVersion.Factory(await ReadFile("version.txt", versionSS));
		}

		public async Task<IFirmware> GetCurrentUpdateFirmware()
		{
			IVersion version = null;
			try
			{
				version = await GetCurrentUpdateVersion();
				if (version == null)
				{
					return null;
				}
				IFile firmware = await GetFileFromFolder("application.hex");
				IFile file = await GetFileFromFolder("application.dat");
				if (firmware != null && file != null && Mvx.TryResolve<IFirmwareFactoryService>(out var service))
				{
					return await service.Create(version, firmware, file);
				}
			}
			catch
			{
			}
			try
			{
				IFile firmware = await GetFileFromFolder("usbFirmwareFile.cyacd");
				if (firmware != null && Mvx.TryResolve<IFirmwareFactoryService>(out var service2))
				{
					return await service2.Create(version, firmware, null);
				}
			}
			catch
			{
			}
			return null;
		}

		public async Task DeleteFileFromFolder(string fileName)
		{
			_ = 3;
			try
			{
				await folderTcs.Task;
				if (await SaveFolder.CheckExistsAsync(fileName) == ExistenceCheckResult.FileExists)
				{
					await (await SaveFolder.GetFileAsync(fileName)).DeleteAsync();
					iFit.Logger.Log.Trace("Updating", "Deleted file [" + fileName + "]");
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error deleting file [" + fileName + "] to disk", exception);
			}
		}

		public async Task CleanUpCurrentUpdateFiles()
		{
			await DeleteFileFromFolder("currentUpdatePairKey.txt");
			await DeleteFileFromFolder("version.txt");
			await DeleteFileFromFolder("application.hex");
			await DeleteFileFromFolder("application.dat");
			await DeleteFileFromFolder("usbFirmwareFile.cyacd");
		}

		public async Task SavePairKeySoftwareNumber(string pairKey, int softwareNumber)
		{
			string contents = await ReadFile("pairKeysSoftwareNumber.txt", pairKeySS);
			if (string.IsNullOrWhiteSpace(contents))
			{
				contents = string.Empty;
			}
			if (ParseFileForPairKey(contents, pairKey) != -1)
			{
				return;
			}
			try
			{
				await folderTcs.Task;
				contents += $"{pairKey}:{softwareNumber}\n";
				await pairKeySS.WaitAsync();
				await (await SaveFolder.CreateFileAsync("pairKeysSoftwareNumber.txt", CreationCollisionOption.OpenIfExists)).WriteAllTextAsync(contents);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error in `SavingPairKeySoftwareNumber`", exception);
			}
			finally
			{
				pairKeySS.Release();
			}
		}

		private async Task SaveVersion(IVersion version)
		{
			_ = 2;
			try
			{
				await folderTcs.Task;
				await (await SaveFolder.CreateFileAsync("version.txt", CreationCollisionOption.ReplaceExisting)).WriteAllTextAsync(version.ToString());
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", string.Format("Error Creating File [{0}] in folder [{1}]", "version.txt", SaveFolder), exception);
				throw;
			}
		}

		protected Tuple<string, int> GetTupleFromLine(string line)
		{
			if (string.IsNullOrWhiteSpace(line))
			{
				return null;
			}
			string[] array = line.Split(new char[1] { ':' }, StringSplitOptions.RemoveEmptyEntries);
			if (array.Length != 2)
			{
				return null;
			}
			if (int.TryParse(array.LastOrDefault(), out var result))
			{
				return new Tuple<string, int>(array[0], result);
			}
			return null;
		}

		protected async Task<string> ReadFile(string fileName, SemaphoreSlim ss)
		{
			_ = 3;
			try
			{
				await folderTcs.Task;
				await ss.WaitAsync();
				return await (await SaveFolder.CreateFileAsync(fileName, CreationCollisionOption.OpenIfExists)).ReadAllTextAsync();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error in `GetSavedSoftwareNumberForPairKey`", exception);
				return null;
			}
			finally
			{
				ss.Release();
			}
		}

		protected int ParseFileForPairKey(string file, string pairKey)
		{
			if (string.IsNullOrWhiteSpace(pairKey) || string.IsNullOrWhiteSpace(file))
			{
				return -1;
			}
			string[] array = file.Split(new char[1] { '\n' }, StringSplitOptions.RemoveEmptyEntries);
			if (array == null)
			{
				return -1;
			}
			string[] array2 = array;
			foreach (string text in array2)
			{
				string[] source = text.Split(new char[1] { ':' }, StringSplitOptions.RemoveEmptyEntries);
				if (pairKey.Equals(source.FirstOrDefault(), StringComparison.OrdinalIgnoreCase) && int.TryParse(source.LastOrDefault(), out var result))
				{
					return result;
				}
			}
			return -1;
		}

		protected async Task SavePairKey(string pairKey)
		{
			_ = 2;
			try
			{
				await folderTcs.Task;
				await (await SaveFolder.CreateFileAsync(Path.Combine(SaveFolder.Path, "currentUpdatePairKey.txt"), CreationCollisionOption.OpenIfExists)).WriteAllTextAsync(pairKey);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", string.Format("Error Creating File [{0}] in folder [{1}]", "currentUpdatePairKey.txt", SaveFolder), exception);
			}
		}

		public async Task<string> GetCurrentUpdatePairKey()
		{
			_ = 2;
			try
			{
				await folderTcs.Task;
				return await (await SaveFolder.CreateFileAsync("currentUpdatePairKey.txt", CreationCollisionOption.OpenIfExists)).ReadAllTextAsync();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error getting current update pair key", exception);
				return null;
			}
		}
	}
