	public interface IVersion : IComparable<IVersion>
	{
		int SoftwareNumber { get; }

		int Major { get; }

		int Minor { get; }
	}
	public class UpdateVersion : IVersion, IComparable<IVersion>
	{
		public const int DefaultValue = -1;

		private const string VersionMatchExpression = "^.*?(?![0-9\\.])";

		public int SoftwareNumber { get; private set; } = -1;

		public int Major { get; private set; } = -1;

		public int Minor { get; private set; } = -1;

		private UpdateVersion()
		{
		}

		public static UpdateVersion Factory(BrainboardUpdate bb, int softwareNumber = -1)
		{
			if (bb != null)
			{
				return Factory(bb.Version, softwareNumber);
			}
			return null;
		}

		public static UpdateVersion Factory(int major, int minor, int softwareNumber = -1)
		{
			return new UpdateVersion
			{
				Major = major,
				Minor = minor,
				SoftwareNumber = softwareNumber
			};
		}

		public static UpdateVersion Factory(string str, int partNumber = -1)
		{
			str = str.RemoveWhiteSpace();
			if (string.IsNullOrWhiteSpace(str))
			{
				return null;
			}
			if (!Regex.IsMatch(str, "^[0-9\\.-]*$"))
			{
				return null;
			}
			string[] array = str.Split(new string[1] { "." }, StringSplitOptions.RemoveEmptyEntries);
			if (array == null)
			{
				return null;
			}
			List<int> list = array.Select((string x) => (!int.TryParse(x, out var result)) ? (-1) : result).ToList();
			return list.Count switch
			{
				1 => new UpdateVersion
				{
					Major = list[0],
					SoftwareNumber = partNumber
				}, 
				2 => new UpdateVersion
				{
					Major = list[0],
					Minor = list[1],
					SoftwareNumber = partNumber
				}, 
				3 => new UpdateVersion
				{
					Major = list[0],
					Minor = list[1],
					SoftwareNumber = list[2]
				}, 
				_ => null, 
			};
		}

		public static UpdateVersion Factory(int softwareNumber)
		{
			return Factory(-1, -1, softwareNumber);
		}

		public static bool CheckVersionStrings(string currentVersion, string remoteVersion)
		{
			try
			{
				Regex regex = new Regex("^.*?(?![0-9\\.])");
				string version = regex.Match(currentVersion).ToString();
				string version2 = regex.Match(remoteVersion).ToString();
				Version version3 = new Version(version);
				Version version4 = new Version(version2);
				return version3 < version4;
			}
			catch
			{
				return false;
			}
		}

		public override string ToString()
		{
			return $"{Major}.{Minor}.{SoftwareNumber}";
		}

		public int CompareTo(IVersion other)
		{
			if (other == null)
			{
				return -1;
			}
			if (Major > other.Major)
			{
				return -1;
			}
			if (Major == other.Major && Minor > other.Minor)
			{
				return -1;
			}
			if (Major == other.Major && Minor == other.Minor)
			{
				return 0;
			}
			return 1;
		}
	}
	public static class IVersionExtensions
	{
		public static bool IsCompatibleWith(this IVersion v1, IVersion v2, bool acceptUnknown = false)
		{
			if (acceptUnknown && (v1.SoftwareNumber == -1 || v2.SoftwareNumber == -1))
			{
				return true;
			}
			if (!acceptUnknown && (v1.SoftwareNumber == -1 || v2.SoftwareNumber == -1))
			{
				return false;
			}
			return v1.SoftwareNumber == v2.SoftwareNumber;
		}

		public static bool IsAnUpgradeFrom(this IVersion v1, IVersion v2, bool isDebug = false)
		{
			if (isDebug && v1.CompareTo(v2) != 0)
			{
				return true;
			}
			return v2.CompareTo(v1) == 1;
		}
	}
}
namespace Shire.Core.Services.Update.Updater
{
	public static class BleKnownParams
	{
		public const int BytesPerPacket = 20;

		public static readonly byte[] EnableDfuPacket = new byte[2] { 1, 4 };

		public static readonly byte[] BeginDfuPacket = new byte[1] { 1 };

		public static readonly byte[] BeginInitPacket = new byte[2] { 2, 0 };

		public static readonly byte[] EndInitPacket = new byte[2] { 2, 1 };

		public static readonly byte[] ReceiveImagePacket = new byte[1] { 3 };

		public static readonly byte[] ValidateFirmwarePacket = new byte[1] { 4 };

		public static readonly byte[] ActivateAndResetPacket = new byte[1] { 5 };

		public static readonly byte[] ResetPacket = new byte[2] { 6, 4 };

		public static readonly byte[] FileSizeResponsePacket = new byte[3] { 16, 1, 1 };

		public static readonly byte[] InitResponsePacket = new byte[3] { 16, 2, 1 };

		public static readonly byte[] ReceiveImageResponsePacket = new byte[3] { 16, 3, 1 };

		public static readonly byte[] ValidateFirmwareResponsePacket = new byte[3] { 16, 4, 1 };

		public static bool IsFileSizeResponsePacket(byte[] bytes)
		{
			if ((bytes?.Length ?? (-1)) < 3)
			{
				return false;
			}
			if (bytes[0] == FileSizeResponsePacket[0])
			{
				return bytes[1] == FileSizeResponsePacket[1];
			}
			return false;
		}

		public static bool IsSuccessfulFileSizeResponsePacket(byte[] bytes)
		{
			if (IsFileSizeResponsePacket(bytes))
			{
				return bytes[2] == FileSizeResponsePacket[2];
			}
			return false;
		}

		public static bool IsInitResponsePacket(byte[] bytes)
		{
			if ((bytes?.Length ?? (-1)) < 3)
			{
				return false;
			}
			if (bytes[0] == InitResponsePacket[0])
			{
				return bytes[1] == InitResponsePacket[1];
			}
			return false;
		}

		public static bool IsSuccessfulInitResponsePacket(byte[] bytes)
		{
			if (IsInitResponsePacket(bytes))
			{
				return bytes[2] == InitResponsePacket[2];
			}
			return false;
		}

		public static bool IsReceiveImageResponsePacket(byte[] bytes)
		{
			if ((bytes?.Length ?? (-1)) < 3)
			{
				return false;
			}
			if (bytes[0] == ReceiveImageResponsePacket[0])
			{
				return bytes[1] == ReceiveImageResponsePacket[1];
			}
			return false;
		}

		public static bool IsSuccessfulReceiveImageResponsePacket(byte[] bytes)
		{
			if (IsReceiveImageResponsePacket(bytes))
			{
				return bytes[2] == ReceiveImageResponsePacket[2];
			}
			return false;
		}

		public static bool IsValidateFirmwareResponsePacket(byte[] bytes)
		{
			if ((bytes?.Length ?? (-1)) < 3)
			{
				return false;
			}
			if (bytes[0] == ValidateFirmwareResponsePacket[0])
			{
				return bytes[1] == ValidateFirmwareResponsePacket[1];
			}
			return false;
		}

		public static bool IsSuccessfulValidateFirmwareResponsePacket(byte[] bytes)
		{
			if (IsValidateFirmwareResponsePacket(bytes))
			{
				return bytes[2] == ValidateFirmwareResponsePacket[2];
			}
			return false;
		}

		public static byte[] FileSizePacket(uint size)
		{
			return new byte[8].Concat(ToLittleEndian(size)).ToArray();
		}

		private static byte[] ToLittleEndian(uint value)
		{
			byte[] array = new byte[4];
			for (int i = 0; i < 4; i++)
			{
				array[i] = (byte)((value >> i * 8) % 256);
			}
			return array;
		}
	}
	public class BleUpdaterService : IUpdater, IDisposable
	{
		private readonly Subject<bool> _whenIsUpdatingChanged = new Subject<bool>();

		private readonly Subject<int> _whenProgressChanged = new Subject<int>();

		private readonly Subject<UpdateState> _whenUpdateStateChanged = new Subject<UpdateState>();

		private string pairKey;

		private IFirmware firmware;

		private bool _isUpdating;

		private readonly IDisposable isUpdatingSub;

		private readonly IBleMachineDisconnect disconnect;

		private readonly ISaveUpdateFilesService saveService;

		private readonly IBleFirmwareUpdaterFactory updaterFactory;

		public int UpdateSize
		{
			get
			{
				IFirmware obj = firmware;
				if (obj == null)
				{
					return -1;
				}
				return obj.Firmware.Length;
			}
		}

		public IObservable<bool> WhenIsUpdatingChanged => _whenIsUpdatingChanged;

		public IObservable<int> WhenProgressChanged => _whenProgressChanged;

		public IObservable<UpdateState> WhenUpdateStateChanged => _whenUpdateStateChanged;

		private bool isUpdating
		{
			get
			{
				return _isUpdating;
			}
			set
			{
				if (value != _isUpdating)
				{
					_isUpdating = value;
					_whenIsUpdatingChanged.OnNext(_isUpdating);
				}
			}
		}

		public BleUpdaterService(IBleMachineDisconnect disconnect, ISaveUpdateFilesService saveService, IBleFirmwareUpdaterFactory updaterFactory)
		{
			this.disconnect = disconnect;
			this.saveService = saveService;
			this.updaterFactory = updaterFactory;
			isUpdatingSub = WhenIsUpdatingChanged.Subscribe(delegate(bool x)
			{
				isUpdating = x;
			});
			isUpdating = false;
		}

		public async Task AttemptUpdateAsync(UpdateArgs args)
		{
			if (string.IsNullOrWhiteSpace(pairKey))
			{
				pairKey = await saveService.GetCurrentUpdatePairKey();
			}
			BleUpdateArgs bleUpdateArgs = args as BleUpdateArgs;
			if ((bleUpdateArgs == null || bleUpdateArgs.PairKey == null) && (bleUpdateArgs == null || bleUpdateArgs.Device?.PairKey == null) && string.IsNullOrWhiteSpace(pairKey))
			{
				return;
			}
			Log($"{bleUpdateArgs?.PairKey ?? pairKey}, {args.Firmware.Version}", "AttemptUpdateAsync");
			if (!isUpdating)
			{
				firmware = args.Firmware;
				string text = bleUpdateArgs?.PairKey ?? pairKey;
				if (text != null)
				{
					pairKey = text;
				}
				if (string.IsNullOrWhiteSpace(text))
				{
					throw new BleFirmwareException("Unable To Resolve Device for Update");
				}
			}
			if (isUpdating)
			{
				return;
			}
			isUpdating = true;
			if (Mvx.TryResolve<IDialogPresenter>(out var presenter) && Mvx.TryResolve<IMvxMainThreadDispatcher>(out var service))
			{
				service.RequestMainThreadAction(delegate
				{
					presenter.CurrentMainViewModel?.ShowUpdateProgressDialog();
				});
			}
			try
			{
				await saveService.SaveUpdateDetails(firmware, pairKey);
			}
			catch (Exception arg)
			{
				Log($"Problem Saving Pair Key {arg}", "AttemptUpdateAsync");
				isUpdating = false;
				throw;
			}
			try
			{
				await StartUpate(pairKey);
			}
			catch (Exception arg2)
			{
				Log($"Cancelation Requested error: {arg2}", "AttemptUpdateAsync");
			}
		}

		private async Task StartUpate(string updatePairKey)
		{
			int tries = 0;
			bool updateSuccess = false;
			try
			{
				if (disconnect != null)
				{
					await disconnect.DisconnectFromCurrentBleMachine();
				}
			}
			catch (Exception)
			{
			}
			while (!updateSuccess && tries < 5)
			{
				tries++;
				Log($"DFU - Attempt number {tries}", "StartUpate");
				updateSuccess = await TryUpdate(firmware, updatePairKey);
			}
			isUpdating = false;
			_whenUpdateStateChanged.OnNext((!updateSuccess) ? UpdateState.Failed : UpdateState.Done);
		}

		private async Task<bool> TryUpdate(IFirmware updateFirmware, string updatePairkey)
		{
			Log($"DFU - PairKey = {updatePairkey}, Firmware Version = {updateFirmware.Version}", "TryUpdate");
			if (!Mvx.TryResolve<IScanner>(out var service))
			{
				return false;
			}
			if (!Mvx.TryResolve<IBleRadioStatusService>(out var service2) || !service2.IsBluetoothRadioEnabled())
			{
				return false;
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			DfuScanner scanner = new DfuScanner(service);
			IBleFirmwareUpdater updater = updaterFactory.CreateUpdater(scanner, updateFirmware);
			IDisposable updateStateSub = updater.WhenUpdateStateChange.Subscribe(delegate(UpdateState x)
			{
				_whenUpdateStateChanged.OnNext(x);
			});
			IDisposable progressSub = updater.WhenUpdateProgressChange.Subscribe(delegate(int x)
			{
				_whenProgressChanged.OnNext(x);
			});
			IDisposable whenDCSub = updater.WhenUpdateStateChange.Where((UpdateState x) => x == UpdateState.DisconnectedBeforeComplete).Take(1).Subscribe(delegate
			{
				Log("DFU - Disconnected before complete detected, failing TryUpdate()", "TryUpdate");
				tcs.TrySetResult(result: false);
			});
			try
			{
				Log("DFU - about to call updater.Update(" + updatePairkey + ")", "TryUpdate");
				await updater.Update(updatePairkey);
				tcs.TrySetResult(result: true);
			}
			catch (Exception ex)
			{
				Log("DFU - update.Update() threw exception: " + ex.Message, "TryUpdate");
				tcs.TrySetResult(result: false);
			}
			finally
			{
				Log("DFU - disposing objects", "TryUpdate");
				updater.Dispose();
				updateStateSub?.Dispose();
				progressSub?.Dispose();
				whenDCSub?.Dispose();
			}
			bool wasSuccess = await tcs.Task;
			if (wasSuccess)
			{
				await saveService.CleanUpCurrentUpdateFiles();
			}
			return wasSuccess;
		}

		protected void Log(string msg, [CallerMemberName] string caller = null)
		{
			iFit.Logger.Log.Trace("Updating", "[BleUpdaterService." + caller + "] -> " + msg);
		}

		public void Dispose()
		{
			isUpdatingSub?.Dispose();
		}
	}
