	public class UsbUpdaterService : IUsbUpdaterService, IUpdater, IDisposable
	{
		private readonly ReplaySubject<bool> _whenIsUpdatingChanged = new ReplaySubject<bool>(1);

		private readonly Subject<int> _whenProgressChanged = new Subject<int>();

		private readonly Subject<UpdateState> _whenUpdateStateChanged = new Subject<UpdateState>();

		private readonly IDisposable whenIsUpdatingSub;

		private readonly IDisposable whenConsoleChangesSub;

		private IFitnessConsole console;

		private IFirmware firmware;

		private bool _isUpdating;

		public int UpdateSize
		{
			get
			{
				IFirmware obj = firmware;
				if (obj == null)
				{
					return -1;
				}
				return obj.Firmware.Length;
			}
		}

		public IObservable<bool> WhenIsUpdatingChanged => _whenIsUpdatingChanged;

		public IObservable<int> WhenProgressChanged => _whenProgressChanged;

		public IObservable<UpdateState> WhenUpdateStateChanged => _whenUpdateStateChanged;

		private bool isUpdating
		{
			get
			{
				return _isUpdating;
			}
			set
			{
				if (value != _isUpdating)
				{
					_isUpdating = value;
					_whenIsUpdatingChanged.OnNext(_isUpdating);
				}
			}
		}

		public UsbUpdaterService(IFitnessConsole curConsole, IObservable<IFitnessConsole> whenDeviceChanged)
		{
			console = curConsole;
			whenConsoleChangesSub = whenDeviceChanged.Subscribe(OnConsoleChange);
			whenIsUpdatingSub = WhenIsUpdatingChanged.Subscribe(delegate(bool x)
			{
				isUpdating = x;
			});
			isUpdating = false;
		}

		private void OnConsoleChange(IFitnessConsole newConsole)
		{
		}

		public async Task AttemptUpdateAsync(UpdateArgs args)
		{
			if (!isUpdating)
			{
				firmware = args.Firmware;
			}
			TaskCompletionSource<bool> tcs = new TaskCompletionSource<bool>();
			(from x in _whenIsUpdatingChanged.Skip(1)
				where !x
				select x).Take(1).Subscribe(delegate
			{
				tcs.TrySetResult(result: true);
			}, delegate(Exception e)
			{
				tcs.TrySetException(e);
			});
			if (!isUpdating)
			{
				try
				{
					isUpdating = true;
					Task.Run((Func<Task>)StartUpate);
				}
				catch (Exception arg)
				{
					Log($"Cancelation Requested error: {arg}", "AttemptUpdateAsync");
				}
			}
			await tcs.Task;
		}

		private async Task StartUpate()
		{
			_ = 2;
			try
			{
				await Task.Delay(TimeSpan.FromSeconds(5.0));
				int i = 0;
				while (i < 100)
				{
					_whenProgressChanged.OnNext(i + 1);
					await Task.Delay(TimeSpan.FromMilliseconds(750.0));
					int num = i + 1;
					i = num;
				}
				await Task.Delay(TimeSpan.FromSeconds(5.0));
			}
			catch (OperationCanceledException)
			{
				throw;
			}
			catch (Exception arg)
			{
				Log($"The attempt to update has failed with message : {arg}", "StartUpate");
				throw;
			}
			finally
			{
				isUpdating = false;
			}
		}

		protected void Log(string msg, [CallerMemberName] string caller = null)
		{
			iFit.Logger.Log.Trace("Updating", caller + " -> " + msg);
		}

		public void Dispose()
		{
			whenIsUpdatingSub?.Dispose();
			whenConsoleChangesSub?.Dispose();
		}
	}
