namespace Shire.Core.Services.Update.Firmware
{
	public class BleFirmware : FirmwareBase
	{
		protected BleFirmware(IVersion version, IAnalytics reporter, IFileDownloaderFactory downloaderFactory, ISaveUpdateFilesService saveService)
			: base(version, reporter, downloaderFactory, saveService)
		{
		}

		public static async Task<IFirmware> Create(List<string> urls, IVersion version, IAnalytics reporter, IFileDownloaderFactory downloadFactory, ISaveUpdateFilesService saveService)
		{
			_ = 2;
			try
			{
				BleFirmware fw = new BleFirmware(version, reporter, downloadFactory, saveService);
				IDownloadUpdate files = await fw.DownloadFiles(urls);
				await fw.TryToEnsureFilesExist(urls, files);
				fw.FirmwareFile = files.Files.Find((IFileToDownload x) => x.Name.Contains(".hex")).DestinationFile;
				fw.MetadataFile = files.Files.Find((IFileToDownload x) => x.Name.Contains(".dat")).DestinationFile;
				await fw.TryToParseFiles(fw.FirmwareFile, fw.MetadataFile);
				return fw;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Problem creating firmware from Urls", exception);
				return null;
			}
		}

		public static async Task<IFirmware> Create(IFile firmware, IFile metadata, IVersion version, IAnalytics reporter, IFileDownloaderFactory downloaderFactory, ISaveUpdateFilesService saveService)
		{
			try
			{
				BleFirmware fw = new BleFirmware(version, reporter, downloaderFactory, saveService)
				{
					FirmwareFile = firmware,
					MetadataFile = metadata
				};
				await fw.TryToParseFiles(firmware, metadata);
				return fw;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Problem creating firmware from IFiles", exception);
				return null;
			}
		}

		protected List<byte[]> GetFirmwarePackages()
		{
			List<byte[]> result = new List<byte[]>();
			base.Firmware.Batch(20).ForEach(delegate(IEnumerable<byte> x)
			{
				result.Add(x.ToArray());
			});
			return result;
		}

		protected async Task<byte[]> GetBytesFromFile(IFile file)
		{
			using FileStream fileStream = await file.OpenAsync(FileAccess.Read);
			List<byte> list = new List<byte>();
			for (int num = fileStream.ReadByte(); num >= 0; num = fileStream.ReadByte())
			{
				list.Add((byte)num);
			}
			return list.ToArray();
		}

		protected async Task TryToEnsureFilesExist(List<string> urls, IDownloadUpdate files)
		{
			IFileToDownload fileToDownload = files.Files.Find((IFileToDownload x) => x.Name.Contains(".hex"));
			IFileToDownload fileToDownload2 = files.Files.Find((IFileToDownload x) => x.Name.Contains(".dat"));
			if ((fileToDownload?.Size ?? (-1)) > 0 && fileToDownload?.DestinationFile != null && (fileToDownload2?.Size ?? (-1)) > 0 && fileToDownload2?.DestinationFile != null)
			{
				return;
			}
			await reporter.Track("Firmware Action Needed", new Dictionary<string, object>
			{
				["machinePartNumber"] = base.Version?.SoftwareNumber,
				["versionMajor"] = base.Version?.Major,
				["versionMinor"] = base.Version?.Minor,
				["machineType"] = "ble",
				["expectedAwsUrls"] = "[" + string.Join(", ", urls) + "]",
				["actualAwsUrls"] = "[" + string.Join(", ", files.Files.Select((IFileToDownload x) => x.Name)) + "]",
				["problem"] = "Downloaded does not contain a either a '.hex' or '.dat' file"
			});
			string text = "Expected these files [" + string.Join(", ", urls) + "] Got these files [" + string.Join(", ", files.Files.Select((IFileToDownload x) => x.Name)) + "]";
			iFit.Logger.Log.Error("Updating", text);
			throw new Exception(text);
		}

		protected async Task<byte[]> TryToGetBinFromFile(IFile file)
		{
			byte[] array = NRF51BinConverter.HexToBin(await GetBytesFromFile(file));
			if (array == null)
			{
				throw new ArgumentNullException("unable to convert HexToBin from file " + file.Name);
			}
			return array;
		}

		protected async Task TryToParseFiles(IFile firmwareFile, IFile metadataFile)
		{
			try
			{
				_firmware = await TryToGetBinFromFile(firmwareFile);
				_metadata = await GetBytesFromFile(metadataFile);
			}
			catch (Exception ex)
			{
				Exception e = ex;
				await reporter.Track("Firmware Action Needed", new Dictionary<string, object>
				{
					["machinePartNumber"] = base.Version?.SoftwareNumber,
					["versionMajor"] = base.Version?.Major,
					["versionMinor"] = base.Version?.Minor,
					["machineType"] = "ble",
					["problem"] = $"trying to parse the .hex and .dat files threw an error {e}",
					["notes"] = "We need to update the files on the admin site to fix this"
				});
				iFit.Logger.Log.Error("Updating", "Could not save fimrware Error", e);
				if (!(ex is Exception source))
				{
					throw ex;
				}
				ExceptionDispatchInfo.Capture(source).Throw();
			}
		}
	}
