	public interface IFirmwareFactoryService
	{
		Task<IFirmware> Create(string url, IVersion version);

		Task<IFirmware> Create(BrainboardUpdate update, int softwareNumber);

		Task<IFirmware> Create(IVersion version, IFile firmware, IFile metadata);

		List<string> GetUrls(string urls);

		Task<IFirmware> RestoreFromDisk();

		Task<IFirmware> RestoreFromDiskIfCompatible(int major, int minor, int partNumber);

		Task<IFirmware> RestoreFromDiskIfCompatible(string version);

		Task<IFirmware> RestoreFromDiskIfCompatible(IVersion requestedVersion);
	}
	public class FirmwareFactoryService : IFirmwareFactoryService
	{
		private readonly ISaveUpdateFilesService saveService;

		private readonly IFileDownloaderFactory downloaderFactory;

		private readonly IAnalytics reporter;

		private readonly IFirmwareCreator creator;

		public FirmwareFactoryService(ISaveUpdateFilesService saveService, IFileDownloaderFactory downloaderFactory, IAnalytics reporter, IFirmwareCreator creator)
		{
			this.saveService = saveService;
			this.downloaderFactory = downloaderFactory;
			this.reporter = reporter;
			this.creator = creator;
		}

		public List<string> GetUrls(string url)
		{
			return creator.GetUrls(saveService, url);
		}

		public async Task<IFirmware> Create(string url, IVersion version)
		{
			List<string> urls = GetUrls(url);
			return await creator.Create(urls, version, reporter, downloaderFactory, saveService);
		}

		public async Task<IFirmware> Create(BrainboardUpdate update, int softwareNumber)
		{
			UpdateVersion version = UpdateVersion.Factory(update, softwareNumber);
			return await Create(update.Url, version);
		}

		public async Task<IFirmware> Create(IVersion version, IFile firmware, IFile metadata)
		{
			return await creator.Create(firmware, metadata, version, reporter, downloaderFactory, saveService);
		}

		public async Task<IFirmware> RestoreFromDisk()
		{
			_ = 2;
			try
			{
				IVersion version = await saveService.GetCurrentUpdateVersion();
				Tuple<IFile, IFile> tuple = await DownloadFilesSavedFiles();
				return await Create(version, tuple.Item1, tuple.Item2);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Problem restoring firmware from disk", exception);
				return null;
			}
		}

		public async Task<IFirmware> RestoreFromDiskIfCompatible(int major, int minor, int partNumber)
		{
			return await RestoreFromDiskIfCompatible(UpdateVersion.Factory(major, minor, partNumber));
		}

		public async Task<IFirmware> RestoreFromDiskIfCompatible(string version)
		{
			return await RestoreFromDiskIfCompatible(UpdateVersion.Factory(version));
		}

		public async Task<IFirmware> RestoreFromDiskIfCompatible(IVersion requestedVersion)
		{
			_ = 1;
			try
			{
				IVersion version = await saveService.GetCurrentUpdateVersion();
				if (!requestedVersion.IsCompatibleWith(version))
				{
					throw new ArgumentException($"The saved firmware [{version}] is incompatible with the requested firmware [{requestedVersion}]");
				}
				return await RestoreFromDisk();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", $"Problem restoring firmware compatible with '{requestedVersion}' from disk", exception);
				return null;
			}
		}

		private async Task<Tuple<IFile, IFile>> DownloadFilesSavedFiles()
		{
			return new Tuple<IFile, IFile>(await creator.GetFirmwareFile(saveService), await creator.GetMetadataFile(saveService));
		}
	}
