	public class UsbFirmware : FirmwareBase
	{
		private UsbFirmware(IVersion version, IAnalytics reporter, IFileDownloaderFactory downloader, ISaveUpdateFilesService saveService)
			: base(version, reporter, downloader, saveService)
		{
			_metadata = new byte[0];
		}

		public static async Task<IFirmware> Create(List<string> urls, IVersion version, IAnalytics reporter, IFileDownloaderFactory downloadFactory, ISaveUpdateFilesService saveService)
		{
			_ = 2;
			try
			{
				UsbFirmware firmware = new UsbFirmware(version, reporter, downloadFactory, saveService);
				IDownloadUpdate files = await firmware.DownloadFiles(urls);
				await firmware.TryToEnsureFileExists(urls, files);
				IFile destinationFile = files.Files.Find((IFileToDownload x) => x.Name.Contains(".cyacd")).DestinationFile;
				UsbFirmware usbFirmware = firmware;
				usbFirmware._firmware = await firmware.GetBytesFromFile(destinationFile);
				if (firmware.Firmware.Length < 1)
				{
					throw new ArgumentNullException("The firmware is invalid " + string.Join(", ", firmware.Firmware));
				}
				return firmware;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Problem creating firmware from Url", exception);
				return null;
			}
		}

		public static async Task<IFirmware> Create(IFile file, IVersion version, IAnalytics reporter, IFileDownloaderFactory downloadFactory, ISaveUpdateFilesService saveService)
		{
			try
			{
				UsbFirmware firmware = new UsbFirmware(version, reporter, downloadFactory, saveService);
				UsbFirmware usbFirmware = firmware;
				usbFirmware._firmware = await firmware.GetBytesFromFile(file);
				if (firmware.Firmware.Length < 1)
				{
					throw new ArgumentNullException("The firmware is invalid " + string.Join(", ", firmware.Firmware));
				}
				return firmware;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Could not save firmware Error", exception);
				return null;
			}
		}

		private async Task<byte[]> GetBytesFromFile(IFile file)
		{
			using FileStream fileStream = await file.OpenAsync(FileAccess.Read);
			List<byte> list = new List<byte>();
			for (int num = fileStream.ReadByte(); num >= 0; num = fileStream.ReadByte())
			{
				list.Add((byte)num);
			}
			return list.ToArray();
		}

		private async Task TryToEnsureFileExists(List<string> urls, IDownloadUpdate files)
		{
			IFileToDownload fileToDownload = files.Files.Find((IFileToDownload x) => x.Name.Contains(".hex"));
			if ((fileToDownload?.Size ?? (-1)) >= 1 && fileToDownload?.DestinationFile != null)
			{
				return;
			}
			await reporter.Track("Firmware Action Needed", new Dictionary<string, object>
			{
				["machinePartNumber"] = base.Version?.SoftwareNumber,
				["versionMajor"] = base.Version?.Major,
				["versionMinor"] = base.Version?.Minor,
				["machineType"] = "usb",
				["expectedAwsUrls"] = "[" + string.Join(", ", urls) + "]",
				["actualAwsUrls"] = "[" + string.Join(", ", files.Files.Select((IFileToDownload x) => x.Name)) + "]",
				["problem"] = "Downloaded does not contain a either a '.hex' or '.dat' file"
			});
			string text = "Expected these files [" + string.Join(", ", urls) + "] Got these files [" + string.Join(", ", files.Files.Select((IFileToDownload x) => x.Name)) + "]";
			iFit.Logger.Log.Error("Updating", text);
			throw new Exception(text);
		}
	}
}
namespace Shire.Core.Services.Update.Ble
{
	public interface IBleFirmwareUpdater : IDisposable
	{
		IObservable<UpdateState> WhenUpdateStateChange { get; }

		IObservable<int> WhenUpdateProgressChange { get; }

		Task Update(IBleDevice device);

		Task Update(string desiredPairKey);
	}
	public class BleFirmwareException : Exception
	{
		public BleFirmwareException(string msg)
			: base(msg)
		{
		}
	}
	public class BleFirmwareUpdater : IBleFirmwareUpdater, IDisposable
	{
		private readonly Subject<UpdateState> _updateState = new Subject<UpdateState>();

		private readonly Subject<int> _updateProgress = new Subject<int>();

		private IDisposable progressTimeoutSub;

		private bool failedFromTimeout;

		private string pairKey;

		private bool isDfuDevice;

		private bool updateComplete;

		private IDisposable controlSub;

		private IDisposable disconnectSub;

		private IBleDevice device;

		private readonly DfuScanner scanner;

		private readonly IFirmware firmware;

		private List<IService> services;

		private DfuResponseHandler responseHandler;

		private ICharacteristic DfuPacketCharacteristic;

		private ICharacteristic DfuControlCharacteristic;

		private ICharacteristic DfuVersionCharacteristic;

		public IObservable<UpdateState> WhenUpdateStateChange => _updateState;

		public IObservable<int> WhenUpdateProgressChange => _updateProgress;

		public BleFirmwareUpdater(DfuScanner scanner, IFirmware firmware)
		{
			this.scanner = scanner;
			this.firmware = firmware;
		}

		public async Task Update(IBleDevice dev)
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Update called");
			device = dev;
			await GetDfuCharacteristics();
			try
			{
				await EnableDfu();
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Exception while enabling DFU", exception);
				throw new BleFirmwareException("Unable to enable DFU");
			}
			await CommonUpdateTasks();
		}

		public async Task Update(string desiredPairKey)
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Recovery update called");
			pairKey = desiredPairKey;
			await CommonEnableDfuTasks();
			await CommonUpdateTasks();
		}

		private async Task CommonUpdateTasks()
		{
			try
			{
				if (!(await CallWithRetry(SendFileSize, 2, "CommonUpdateTasks")))
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Failed to send file size, resetting device now since it could possibly help");
					await ResetDfuDevice();
					throw new BleFirmwareException("Failed to send file size");
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Exception while sending file size", exception);
				throw;
			}
			try
			{
				if (!(await CallWithRetry(SendInitialization, 5, "CommonUpdateTasks")))
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Failed to initialize");
					throw new BleFirmwareException("Failed to initialize");
				}
			}
			catch (Exception exception2)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Exception while sending initialization data", exception2);
				throw;
			}
			try
			{
				if (!(await TransferImage()))
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Failed to transfer image");
					throw new BleFirmwareException("Failed to transfer image");
				}
			}
			catch (Exception exception3)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Exception while transferring image", exception3);
				throw;
			}
			try
			{
				if (!(await CallWithRetry(ValidateFirmware, 5, "CommonUpdateTasks")))
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Failed to validate firmware");
					throw new BleFirmwareException("Failed to validate firmware");
				}
			}
			catch (Exception exception4)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Exception while validating firmware", exception4);
				throw;
			}
			await ActivateAndReset();
			if (device != null)
			{
				await device.Disconnect(forced: true);
			}
		}

		private async Task<bool> CallWithRetry(Func<Task<bool>> func, int maxAttempts = 5, [CallerMemberName] string caller = null)
		{
			int attempts = 1;
			bool flag;
			while (true)
			{
				bool num = await func();
				flag = num;
				if (num)
				{
					break;
				}
				int num2 = attempts + 1;
				attempts = num2;
				if (num2 > maxAttempts)
				{
					break;
				}
				await Delay();
			}
			iFit.Logger.Log.Trace("Updating", string.Format("DFU - {0} to {1} with {2} attempts!", flag ? "Succeeded" : "Failed", caller ?? string.Empty, attempts));
			return flag;
		}

		private async Task EnableDfu()
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Enabling DFU");
			pairKey = device.PairKey;
			iFit.Logger.Log.Trace("Updating", "DFU - Connnected to device with pair key: " + pairKey);
			iFit.Logger.Log.Trace("Updating", "DFU - Enabling notifications from DFU control characteristic");
			await DfuControlCharacteristic.StartUpdates();
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to RebootingDevice");
			_updateState.OnNext(UpdateState.RebootingDevice);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending reboot into DFU packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.EnableDfuPacket);
			await Delay();
			await CommonEnableDfuTasks();
			iFit.Logger.Log.Trace("Updating", "DFU - Done enabling DFU mode");
		}

		private async Task CommonEnableDfuTasks()
		{
			IBleDevice dev = await ScanAndConnect();
			iFit.Logger.Log.Trace("Updating", "DFU - Checking if device is Fitpro");
			iFit.Logger.Log.Trace("Updating", "DFU - Device is: " + (isDfuDevice ? "DFU" : "FITPRO"));
			if (!isDfuDevice)
			{
				iFit.Logger.Log.Trace("Updating", "DFU - Passing device to Update (IDevice) method");
				disconnectSub?.Dispose();
				await Update(dev);
				return;
			}
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to EnablingDfu");
			_updateState.OnNext(UpdateState.EnablingDfu);
			responseHandler = new DfuResponseHandler();
			controlSub = DfuControlCharacteristic.WhenDataChanged.Subscribe(delegate(byte[] x)
			{
				responseHandler.ProcessResponse(x);
			});
			iFit.Logger.Log.Trace("Updating", "DFU - Starting control characteristic stream");
			await DfuControlCharacteristic.StartUpdates();
			await Delay();
			iFit.Logger.Log.Trace("Updating", "DFU - Sending enable DFU packet: " + BitConverter.ToString(BleKnownParams.EnableDfuPacket));
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.EnableDfuPacket);
			await Delay();
			iFit.Logger.Log.Trace("Updating", "DFU - So far things look good. Setting IDevice member variable to current DFU device");
			device = dev;
		}

		private async Task<IBleDevice> ScanAndConnect()
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to ScanningForDevice");
			_updateState.OnNext(UpdateState.ScanningForDevice);
			await ReleaseResources();
			iFit.Logger.Log.Trace("Updating", "DFU - Searching for DFU device with pair key: " + pairKey);
			IBleDevice dev = await scanner.ScanForDfuDeviceWithPairKey(pairKey);
			iFit.Logger.Log.Trace("Updating", "DFU - Done searching, device is: " + ((dev == null) ? string.Empty : "NOT") + " NULL");
			if (dev == null)
			{
				throw new BleFirmwareException("Could not find DFU device");
			}
			await ConnectToDfuDevice(dev);
			disconnectSub = dev.WhenStateChanged.Where((DeviceState x) => x == DeviceState.Disconnected || x == DeviceState.LostConnection).Take(1).Subscribe(delegate
			{
				if (!updateComplete)
				{
					_updateState.OnNext(UpdateState.DisconnectedBeforeComplete);
				}
			});
			iFit.Logger.Log.Trace("Updating", "DFU - Getting DFU characteristics from device");
			try
			{
				device = dev;
				if (await CallWithRetry(GetDfuCharacteristics, 5, "ScanAndConnect"))
				{
					return dev;
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Failed to get characteristics", exception);
			}
			device = null;
			return null;
		}

		private async Task ConnectToDfuDevice(IBleDevice dev)
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to ConnectingToDevice");
			_updateState.OnNext(UpdateState.ConnectingToDevice);
			iFit.Logger.Log.Trace("Updating", "DFU - Connecting to DFU device");
			int connectAttempts = 0;
			while (!(await dev.Connect()))
			{
				connectAttempts++;
				if (connectAttempts > 5)
				{
					throw new BleFirmwareException("Connect attempts exceeded");
				}
				iFit.Logger.Log.Trace("Updating", "DFU - Failed to connect to device, trying again.");
			}
		}

		private async Task<bool> GetDfuCharacteristics()
		{
			_ = 1;
			try
			{
				DisposeCharacteristics();
				services = await device.GetServices();
				isDfuDevice = services.All(delegate(IService x)
				{
					Guid? guid = x?.Id;
					Guid id = KnownServices.FitPro.Id;
					if (!guid.HasValue)
					{
						return true;
					}
					return guid.HasValue && guid.GetValueOrDefault() != id;
				});
				IService service = services.First(delegate(IService x)
				{
					Guid? guid = x?.Id;
					Guid id = KnownServices.Dfu.Id;
					if (!guid.HasValue)
					{
						return false;
					}
					return !guid.HasValue || guid.GetValueOrDefault() == id;
				});
				List<ICharacteristic> source = await service.GetCharacteristics();
				DfuControlCharacteristic = source.First(delegate(ICharacteristic x)
				{
					Guid? guid = x?.Id;
					Guid id = KnownCharacteristics.DfuControlPoint.Id;
					if (!guid.HasValue)
					{
						return false;
					}
					return !guid.HasValue || guid.GetValueOrDefault() == id;
				});
				DfuPacketCharacteristic = source.First(delegate(ICharacteristic x)
				{
					Guid? guid = x?.Id;
					Guid id = KnownCharacteristics.DfuPacket.Id;
					if (!guid.HasValue)
					{
						return false;
					}
					return !guid.HasValue || guid.GetValueOrDefault() == id;
				});
				DfuVersionCharacteristic = source.First(delegate(ICharacteristic x)
				{
					Guid? guid = x?.Id;
					Guid id = KnownCharacteristics.DfuVersion.Id;
					if (!guid.HasValue)
					{
						return false;
					}
					return !guid.HasValue || guid.GetValueOrDefault() == id;
				});
				return true;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Failed to GetDfuCharacteristics due to", exception);
			}
			return false;
		}

		private async Task<bool> SendFileSize()
		{
			DfuResponseHandler.DfuResponseSubscription response = responseHandler.SubscribeTo(responseHandler.DfuEnabled);
			byte[] data = BleKnownParams.FileSizePacket((uint)firmware.Firmware.Length);
			await DfuPacketCharacteristic.WriteAsync(data, withResponse: false);
			await ReadVersion();
			return await response.Tcs.Task;
		}

		private async Task<bool> SendInitialization()
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to InitializingTransfer");
			_updateState.OnNext(UpdateState.InitializingTransfer);
			DfuResponseHandler.DfuResponseSubscription response = responseHandler.SubscribeTo(responseHandler.Initialized);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending begin init packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.BeginInitPacket);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending meta data packet");
			await DfuPacketCharacteristic.WriteAsync(firmware.Metadata, withResponse: false);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending end init packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.EndInitPacket);
			await ReadVersion();
			return await response.Tcs.Task;
		}

		private async Task<bool> TransferImage()
		{
			failedFromTimeout = false;
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to Transfering");
			_updateState.OnNext(UpdateState.Transfering);
			DfuResponseHandler.DfuResponseSubscription response = null;
			iFit.Logger.Log.Trace("Updating", "DFU - Sending receive image packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.ReceiveImagePacket);
			int percent = 0;
			_updateProgress.OnNext(0);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending firmware image");
			List<byte[]> applicationData = new List<byte[]>();
			firmware.Firmware.Batch(20).DoForEach(delegate(IEnumerable<byte> x)
			{
				applicationData.Add(x.ToArray());
			});
			int i = 0;
			while (i < applicationData.Count)
			{
				if (device.State != DeviceState.Connected || failedFromTimeout)
				{
					return false;
				}
				await DfuPacketCharacteristic.WriteAsync(applicationData[i], withResponse: false);
				int num = (int)((double)(i + 1) / (double)applicationData.Count * 100.0);
				if (num != percent)
				{
					percent = num;
					iFit.Logger.Log.Trace("Updating", $"DFU - Firmware image transfered: {percent}%");
					_updateProgress.OnNext(percent);
					progressTimeoutSub?.Dispose();
					progressTimeoutSub = Observable.Timer(TimeSpan.FromSeconds(30.0)).Take(1).SubscribeWithErrorLogging(delegate
					{
						failedFromTimeout = true;
					});
					if (percent == 99)
					{
						iFit.Logger.Log.Trace("Updating", "DFU - 99% of firmware image transfered. Now listening for transfer response");
						response = responseHandler.SubscribeTo(responseHandler.TransferComplete, 30);
					}
				}
				int num2 = i + 1;
				i = num2;
			}
			progressTimeoutSub?.Dispose();
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to TransferComplete");
			_updateState.OnNext(UpdateState.TransferComplete);
			iFit.Logger.Log.Trace("Updating", "DFU - Reading from version characteristic. This helps move along a transfer image response.");
			await ReadVersion();
			if (response != null)
			{
				return await response.Tcs.Task;
			}
			return false;
		}

		private async Task<bool> ValidateFirmware()
		{
			await ReadVersion();
			DfuResponseHandler.DfuResponseSubscription response = responseHandler.SubscribeTo(responseHandler.ValidateFirmware);
			iFit.Logger.Log.Trace("Updating", "DFU - Sending validate firmware packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.ValidateFirmwarePacket);
			await ReadVersion();
			return await response.Tcs.Task;
		}

		private async Task ActivateAndReset()
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Setting update state to ActivateAndReset");
			_updateState.OnNext(UpdateState.ActivateAndReset);
			updateComplete = true;
			disconnectSub?.Dispose();
			iFit.Logger.Log.Trace("Updating", "DFU - Sending activate and reset packet");
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.ActivateAndResetPacket);
			await Delay();
		}

		private async Task ResetDfuDevice()
		{
			disconnectSub?.Dispose();
			await DfuControlCharacteristic.WriteAsync(BleKnownParams.ResetPacket);
			await Delay();
			await CommonEnableDfuTasks();
		}

		private async Task<bool> ReadVersion()
		{
			iFit.Logger.Log.Trace("Updating", "DFU - Reading from version characteristic");
			try
			{
				await DfuVersionCharacteristic.Read();
			}
			catch (Exception)
			{
				iFit.Logger.Log.Trace("Updating", "DFU - Failed to read from version characteristic");
				return false;
			}
			iFit.Logger.Log.Trace("Updating", "DFU - Successfully read from version characteristic");
			return true;
		}

		private static async Task Delay(int seconds = 1)
		{
			await Task.Delay(TimeSpan.FromSeconds(seconds));
		}

		private void DisposeCharacteristics()
		{
			isDfuDevice = false;
			DfuControlCharacteristic?.Dispose();
			DfuPacketCharacteristic?.Dispose();
			DfuVersionCharacteristic?.Dispose();
			DfuControlCharacteristic = null;
			DfuPacketCharacteristic = null;
			DfuVersionCharacteristic = null;
			services?.DoForEach(delegate(IService x)
			{
				x?.Dispose();
			});
			services?.Clear();
		}

		private async Task ReleaseResources()
		{
			controlSub?.Dispose();
			disconnectSub?.Dispose();
			DisposeCharacteristics();
			if (device != null)
			{
				await device.Disconnect(forced: true);
				device = null;
			}
		}

		public void Dispose()
		{
			_updateState?.Dispose();
			_updateProgress?.Dispose();
			Task.Run((Func<Task>)ReleaseResources);
		}
	}
	public class DfuResponseHandler
	{
		public class DfuResponseSubscription
		{
			public TaskCompletionSource<bool> Tcs { get; } = new TaskCompletionSource<bool>();

			public DfuResponseSubscription(IObservable<bool> observedResponse, int timeoutSeconds)
			{
				observedResponse.Take(1).Timeout(TimeSpan.FromSeconds(timeoutSeconds)).Subscribe((Action<bool>)delegate(bool x)
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Response: " + (x ? "SUCCESS" : "FAILED"));
					Tcs.TrySetResult(x);
				}, (Action<Exception>)delegate
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Response timed out");
					Tcs.TrySetResult(result: false);
				});
			}
		}

		private readonly Subject<bool> _dfuEnabled = new Subject<bool>();

		private readonly Subject<bool> _initialized = new Subject<bool>();

		private readonly Subject<bool> _transferComplete = new Subject<bool>();

		private readonly Subject<bool> _validateFirmware = new Subject<bool>();

		public IObservable<bool> DfuEnabled => _dfuEnabled;

		public IObservable<bool> Initialized => _initialized;

		public IObservable<bool> TransferComplete => _transferComplete;

		public IObservable<bool> ValidateFirmware => _validateFirmware;

		public void FailAll()
		{
			_dfuEnabled.OnNext(value: false);
			_initialized.OnNext(value: false);
			_transferComplete.OnNext(value: false);
			_validateFirmware.OnNext(value: false);
		}

		public void ProcessResponse(byte[] response)
		{
			if (response == null)
			{
				return;
			}
			iFit.Logger.Log.Trace("Updating", "DFU - ResponseHandler received bytes: " + BitConverter.ToString(response));
			if (response.Length >= 3)
			{
				if (BleKnownParams.IsFileSizeResponsePacket(response))
				{
					bool flag = BleKnownParams.IsSuccessfulFileSizeResponsePacket(response);
					iFit.Logger.Log.Trace("Updating", $"DFU - ResponseHandler setting DfuEnabled to: {flag}");
					_dfuEnabled.OnNext(flag);
				}
				else if (BleKnownParams.IsInitResponsePacket(response))
				{
					bool flag2 = BleKnownParams.IsSuccessfulInitResponsePacket(response);
					iFit.Logger.Log.Trace("Updating", $"DFU - ResponseHandler setting Initialized to: {flag2}");
					_initialized.OnNext(flag2);
				}
				else if (BleKnownParams.IsReceiveImageResponsePacket(response))
				{
					bool flag3 = BleKnownParams.IsSuccessfulReceiveImageResponsePacket(response);
					iFit.Logger.Log.Trace("Updating", $"DFU - ResponseHandler setting TransferComplete to: {flag3}");
					_transferComplete.OnNext(flag3);
				}
				else if (BleKnownParams.IsValidateFirmwareResponsePacket(response))
				{
					bool flag4 = BleKnownParams.IsSuccessfulValidateFirmwareResponsePacket(response);
					iFit.Logger.Log.Trace("Updating", $"DFU - ResponseHandler setting ValidateFirmware to: {flag4}");
					_validateFirmware.OnNext(flag4);
				}
			}
		}

		public DfuResponseSubscription SubscribeTo(IObservable<bool> response, int timeoutSeconds = 10)
		{
			return new DfuResponseSubscription(response, timeoutSeconds);
		}
	}
	public class DfuScanner
	{
		private const int DefaultTimeoutSeconds = 35;

		private readonly IScanner scanner;

		public DfuScanner(IScanner scanner)
		{
			this.scanner = scanner;
		}

		public async Task<Tuple<string, int>> ScanForDfuPairKeys(List<Tuple<string, int>> tuples)
		{
			iFit.Logger.Log.Trace("Updating", "GetDfuPairKeys was called");
			try
			{
				DfuDeviceFilter filter = new DfuDeviceFilter();
				return await (from x in scanner.ScanWithFilter(filter).Timeout(TimeSpan.FromSeconds(35.0))
					where tuples.Any((Tuple<string, int> t) => t.Item1.Equals(x.PairKey, StringComparison.OrdinalIgnoreCase))
					select tuples.FirstOrDefault((Tuple<string, int> t) => t.Item1.Equals(x.PairKey, StringComparison.OrdinalIgnoreCase))).Take(1).ToTask();
			}
			catch (TimeoutException)
			{
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Updating", "Error in GetUpdatableMachines", exception);
			}
			return null;
		}

		public virtual async Task<IBleDevice> ScanForDfuDeviceWithPairKey(string pairKey)
		{
			iFit.Logger.Log.Trace("Updating", "ScanForDfuDeviceWithPairKey() was called to search for pairkey: " + pairKey);
			try
			{
				DfuDeviceFilter filter = new DfuDeviceFilter(allowsFitPro: true);
				IBleDevice bleDevice = await (from x in scanner.ScanWithFilter(filter)
					where string.Equals(pairKey, x.PairKey, StringComparison.OrdinalIgnoreCase)
					select x).Timeout(TimeSpan.FromSeconds(35.0)).Take(1).ToTask();
				if (bleDevice != null)
				{
					iFit.Logger.Log.Trace("Updating", "DFU - Device with pair key " + pairKey + " found");
					return bleDevice;
				}
			}
			catch (TimeoutException)
			{
				iFit.Logger.Log.Trace("Updating", "Timed out trying to find pair key \"" + pairKey + "\"");
			}
			catch (Exception)
			{
				iFit.Logger.Log.Error("Updating", "DFU - Unable to Get IDevice from scan, setting device to null");
			}
			return null;
		}
	}
	public interface IBleFirmwareUpdaterFactory
	{
		IBleFirmwareUpdater CreateUpdater(DfuScanner scanner, IFirmware firmware);
	}
	public interface IBleMachineDisconnect
	{
		Task<bool> DisconnectFromCurrentBleMachine();
	}
