namespace Shire.Core.Services.StreetView
{
	public class StreetViewNotAvailableException : Exception
	{
		public StreetViewNotAvailableException(string message = "street view is not available")
			: base(message)
		{
		}
	}
	public enum QualityMode
	{
		FullQuality,
		Metered
	}
	public class StreetViewImageUpdate
	{
		public byte[] RawImage { get; private set; }

		public bool IsAtDifferentPoint { get; private set; }

		public StreetViewImageUpdate(byte[] data, bool isAtDifferentPoint)
		{
			RawImage = data;
			IsAtDifferentPoint = isAtDifferentPoint;
		}
	}
	public interface IStreetViewService : IDisposable
	{
		IObservable<Exception> WhenErrorOccurredLoadingImage { get; }

		IObservable<StreetViewImageUpdate> WhenImageAvailableAtCurrentDistance { get; }

		IObservable<bool> WhenImageNotAvailableAtCurrentDistance { get; }

		bool Active { get; set; }

		Task<byte[]> GetImageForDistance(double meters, bool isLandscape, QualityMode qualityMode);

		Task Initialize();
	}
	public class StreetViewService : IStreetViewService, IDisposable
	{
		private readonly int MaxMetersBeforeCancel = 50;

		private readonly float MaxGoogleMapsImageSize = 2048f;

		private readonly Subject<Exception> whenErrorOccurredLoadingImage = new Subject<Exception>();

		private readonly Subject<StreetViewImageUpdate> whenImageAvailableAtCurrentDistance = new Subject<StreetViewImageUpdate>();

		private readonly Subject<bool> whenImageNotAvailableAtCurrentDistance = new Subject<bool>();

		private readonly Subject<double> _distanceUpdate = new Subject<double>();

		private readonly IIfitApiService ifitApi;

		private readonly IIFitGatewayApiService iFitGatewayApi;

		private readonly IFitnessConsole console;

		private readonly string workoutId;

		private readonly List<double> requestDurations = new List<double>();

		private bool isDisposed;

		private List<StreetViewPoints.Point> streetViewPoints;

		private CancellationTokenSource cancelTokenSource;

		private double lastMetersRequested = -1.0;

		private readonly int idealWidth;

		private readonly int idealHeight;

		private int currentQualityIndex;

		private string previousImageHash;

		private StreetViewPoints.Point previousImagePoint;

		private IDisposable startedRunningSubscriber;

		private IDisposable distanceChangeSubscriber;

		private IDisposable streetViewPointsSubscriber;

		private IDisposable distanceChangeSampleSubscriber;

		private ICurrentDistanceFacade currentDistanceFacade;

		public IObservable<Exception> WhenErrorOccurredLoadingImage => whenErrorOccurredLoadingImage;

		public IObservable<StreetViewImageUpdate> WhenImageAvailableAtCurrentDistance => whenImageAvailableAtCurrentDistance;

		public IObservable<bool> WhenImageNotAvailableAtCurrentDistance => whenImageNotAvailableAtCurrentDistance;

		private IObservable<double> distanceUpdate => _distanceUpdate;

		public bool Active { get; set; } = true;

		private List<Tuple<int, int>> Qualities { get; } = new List<Tuple<int, int>>();

		private Tuple<int, int> TargetQuality => Qualities[(Qualities.Count > currentQualityIndex) ? currentQualityIndex : 0];

		public Tuple<int, int> HighestQuality => Qualities[0];

		public Tuple<int, int> LowestQuality => Qualities[Qualities.Count - 1];

		public StreetViewService(IIfitApiService ifitApi, IIFitGatewayApiService iFitGatewayApi, IFitnessConsole console, string workoutId, int idealWidth, int idealHeight)
		{
			this.ifitApi = ifitApi;
			this.iFitGatewayApi = iFitGatewayApi;
			this.console = console;
			this.workoutId = workoutId;
			this.idealWidth = idealWidth;
			this.idealHeight = idealHeight;
			currentDistanceFacade = Mvx.Resolve<ICurrentDistanceFacade>();
			if ((float)this.idealWidth > MaxGoogleMapsImageSize)
			{
				float num = MaxGoogleMapsImageSize / (float)this.idealWidth;
				this.idealWidth = (int)MaxGoogleMapsImageSize;
				this.idealHeight = (int)Math.Round((float)this.idealHeight * num);
			}
			if ((float)this.idealHeight > MaxGoogleMapsImageSize)
			{
				float num2 = MaxGoogleMapsImageSize / (float)this.idealHeight;
				this.idealWidth = (int)Math.Round((float)this.idealWidth * num2);
				this.idealHeight = (int)MaxGoogleMapsImageSize;
			}
			if (console != null && console.ConsoleInfo?.MachineType.IsBike() == true)
			{
				MaxMetersBeforeCancel = 100;
			}
		}

		public void Dispose()
		{
			isDisposed = true;
			startedRunningSubscriber?.Dispose();
			startedRunningSubscriber = null;
			distanceChangeSubscriber?.Dispose();
			distanceChangeSubscriber = null;
			streetViewPointsSubscriber?.Dispose();
			streetViewPointsSubscriber = null;
			streetViewPoints?.Clear();
		}

		public async Task Initialize()
		{
			CreateQualities();
			await LoadStreetViewPoints();
			startedRunningSubscriber?.Dispose();
			StreetViewService streetViewService = this;
			IFitnessConsole fitnessConsole = console;
			object obj;
			if (fitnessConsole == null)
			{
				obj = null;
			}
			else
			{
				IObservable<StateChange> whenStateChanged = fitnessConsole.WhenStateChanged;
				if (whenStateChanged == null)
				{
					obj = null;
				}
				else
				{
					IObservable<StateChange> observable = whenStateChanged.Where((StateChange sc) => sc != null && sc.Old == ConsoleState.WarmUp && sc != null && sc.Current == ConsoleState.Workout);
					obj = ((observable != null) ? Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(observable, async delegate
					{
						if (console?.LatestBasicInfo != null)
						{
							await DistanceUpdated(console.LatestBasicInfo.DistanceMeters);
						}
					}) : null);
				}
			}
			streetViewService.startedRunningSubscriber = (IDisposable)obj;
			distanceChangeSubscriber?.Dispose();
			distanceChangeSubscriber = currentDistanceFacade.ObserveMeterChanges().Where((Func<FitnessValueChange<double>, bool>)delegate
			{
				IFitnessConsole fitnessConsole2 = console;
				return fitnessConsole2 != null && fitnessConsole2.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
			})?.SubscribeWithErrorLogging(delegate(FitnessValueChange<double> x)
			{
				if (x != null)
				{
					_distanceUpdate?.OnNext(x.Current);
				}
			});
			distanceChangeSampleSubscriber?.Dispose();
			StreetViewService streetViewService2 = this;
			IObservable<double> observable2 = distanceUpdate;
			streetViewService2.distanceChangeSampleSubscriber = ((observable2 != null) ? Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(observable2.Sample(TimeSpan.FromSeconds(3.0)), async delegate(double x)
			{
				await DistanceUpdated(x);
			}) : null);
		}

		protected async Task LoadStreetViewPoints()
		{
			if (isDisposed)
			{
				return;
			}
			bool complete = false;
			try
			{
				StreetViewPoints streetViewPoints = await StreetViewPoints.Get(ifitApi, workoutId);
				this.streetViewPoints = streetViewPoints.Points;
				complete = streetViewPoints.Complete;
				iFit.Logger.Log.Trace("Workout", $"StreetViewPoints - point retrieval completed: {complete}");
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Workout", "StreetViewPoints - Exception while retrieving points", exception);
			}
			finally
			{
				if (!complete)
				{
					streetViewPointsSubscriber = Sindarin.Core.Util.ObservableExtensions.SubscribeAsync(Observable.Timer(TimeSpan.FromSeconds(5.0)), (long _) => LoadStreetViewPoints());
				}
			}
		}

		public async Task<byte[]> GetImageForDistance(double meters, bool isLandscape = false, QualityMode qualityMode = QualityMode.Metered)
		{
			return await LoadStreetViewImage(meters, isLandscape, qualityMode);
		}

		private void CreateQualities()
		{
			double num = idealWidth / 8;
			double num2 = idealHeight / 8;
			Qualities.Add(new Tuple<int, int>(idealWidth, idealHeight));
			for (int num3 = 7; num3 > 4; num3--)
			{
				int item = (int)Math.Round(num * (double)num3);
				int item2 = (int)Math.Round(num2 * (double)num3);
				Qualities.Add(new Tuple<int, int>(item, item2));
			}
			currentQualityIndex = (int)Math.Ceiling(4.0) - 1;
		}

		private async Task DistanceUpdated(double meters)
		{
			if (isDisposed)
			{
				return;
			}
			if (meters - lastMetersRequested > (double)MaxMetersBeforeCancel)
			{
				iFit.Logger.Log.Trace("Workout", "DistanceUpdated - Request taking to long, move along. Meters: " + meters + ", lastMetersRequested: " + lastMetersRequested);
				whenImageNotAvailableAtCurrentDistance.OnNext(value: false);
				UpdateDuration(10000.0);
				cancelTokenSource?.Cancel();
			}
			List<StreetViewPoints.Point> list = streetViewPoints;
			if (list == null || list.Count((StreetViewPoints.Point x) => x.Meters >= meters) > 1)
			{
				if (lastMetersRequested >= meters || !Active)
				{
					iFit.Logger.Log.Trace("Workout", "DistanceUpdated - Returned. Active: " + Active + ", Meters: " + meters + ", lastMetersRequested: " + lastMetersRequested);
				}
				else
				{
					lastMetersRequested = meters;
					await LoadStreetViewImage(lastMetersRequested);
				}
			}
		}

		private async Task<byte[]> LoadStreetViewImage(double meters, bool isLandscape = true, QualityMode qualityMode = QualityMode.Metered)
		{
			if (isDisposed)
			{
				iFit.Logger.Log.Trace("Workout", "StreetViewService - Already disposed of");
				return null;
			}
			try
			{
				IFitnessConsole fitnessConsole = console;
				if (fitnessConsole != null && fitnessConsole.LatestBasicInfo?.CurrentState == ConsoleState.Paused)
				{
					return null;
				}
				StreetViewPoints.Point point = streetViewPoints?.LastOrDefault((StreetViewPoints.Point x) => x.Meters <= meters);
				Size size = ((qualityMode == QualityMode.Metered) ? new Size(TargetQuality.Item1, TargetQuality.Item2) : new Size(idealWidth, idealHeight));
				if (isLandscape && size.Height > size.Width)
				{
					int width = size.Width;
					size.Width = size.Height;
					size.Height = width;
				}
				if (point != null)
				{
					iFit.Logger.Log.Trace("Workout", "StreetViewService - Getting new image for point, current meters: " + meters);
					Stopwatch stopwatch = Stopwatch.StartNew();
					cancelTokenSource?.Cancel();
					cancelTokenSource = new CancellationTokenSource();
					byte[] result = await point.GetImage(iFitGatewayApi, size.Width, size.Height, cancelTokenSource.Token);
					stopwatch.Stop();
					if (isDisposed)
					{
						return null;
					}
					if (qualityMode == QualityMode.Metered)
					{
						UpdateDuration(stopwatch.Elapsed.TotalMilliseconds);
					}
					SendImageAvailableIfNewImage(point, result);
					return result;
				}
				iFit.Logger.Log.Trace("Workout", "StreetViewService - Point is null, current meters: " + meters);
			}
			catch (TaskCanceledException ex)
			{
				iFit.Logger.Log.Error("Wifi", "Cancelled loading StreetViewImage", ex);
				whenErrorOccurredLoadingImage?.OnNext(ex);
			}
			catch (ConnectivityException ex2)
			{
				iFit.Logger.Log.Error("Wifi", "Network failure loading StreetViewImage", ex2);
				whenErrorOccurredLoadingImage?.OnNext(ex2);
			}
			catch (Exception ex3)
			{
				iFit.Logger.Log.Error("Api", "Error loading StreetViewImage", ex3);
				whenErrorOccurredLoadingImage?.OnNext(ex3);
			}
			return null;
		}

		private void SendImageAvailableIfNewImage(StreetViewPoints.Point point, byte[] result)
		{
			if (result == null)
			{
				whenImageNotAvailableAtCurrentDistance?.OnNext(value: false);
				return;
			}
			MD5Digest mD5Digest = new MD5Digest();
			mD5Digest.BlockUpdate(result, 0, result.Length);
			byte[] array = new byte[mD5Digest.GetDigestSize()];
			mD5Digest.DoFinal(array, 0);
			string text = BitConverter.ToString(array);
			if (text != previousImageHash)
			{
				IFitnessConsole fitnessConsole = console;
				if (fitnessConsole == null || fitnessConsole.LatestBasicInfo.CurrentState != ConsoleState.Paused)
				{
					whenImageAvailableAtCurrentDistance?.OnNext(new StreetViewImageUpdate(result, point != previousImagePoint));
					whenImageNotAvailableAtCurrentDistance?.OnNext(value: true);
				}
			}
			previousImageHash = text;
			previousImagePoint = point;
		}

		private void UpdateDuration(double duration)
		{
			requestDurations.Add(duration);
			int count = Math.Min(requestDurations.Count, 5);
			IEnumerable<double> source = Enumerable.TakeLast(requestDurations, count);
			double num = source.Average();
			if (num > 2500.0 && currentQualityIndex < Qualities.Count - 1)
			{
				iFit.Logger.Log.Trace("Workout", "Streetview requests are taking too long, downgrading quality");
				currentQualityIndex = Math.Min(Qualities.Count - 1, currentQualityIndex + 3);
			}
			else if (num < 1500.0 && currentQualityIndex > 0)
			{
				iFit.Logger.Log.Trace("Workout", "Streetview requests coming in pretty quick, upgrading quality");
				currentQualityIndex = Math.Max(0, currentQualityIndex - 1);
			}
		}
	}
}
namespace Shire.Core.Services.Playback
{
	public abstract class BaseWorkoutRunner : IWorkoutRunner, IDisposable
	{
