		protected readonly List<ConsoleState> startWarmUpAcceptableStates = new List<ConsoleState>();

		protected readonly List<ConsoleState> startWorkoutAcceptableStates = new List<ConsoleState>();

		protected readonly List<ConsoleState> startCoolDownAcceptableStates = new List<ConsoleState>();

		protected readonly List<ConsoleState> recoveryAcceptableStates = new List<ConsoleState>();

		protected readonly List<ConsoleState> finishWarmUpAcceptableStates = new List<ConsoleState>();

		protected readonly List<ConsoleState> finishWorkoutAcceptableStates = new List<ConsoleState>();

		protected readonly int DefaultWarmUpTimeoutSeconds = (int)TimeSpan.FromMinutes(3.0).TotalSeconds;

		protected readonly int DefaultCoolDownTimeoutSeconds = (int)TimeSpan.FromMinutes(10.0).TotalSeconds;

		protected readonly int DefaultPauseTimeoutSeconds = (int)TimeSpan.FromMinutes(10.0).TotalSeconds;

		protected readonly int MinimumWarmUpTimeoutSeconds = (int)TimeSpan.FromMinutes(1.0).TotalSeconds;

		protected readonly int MinimumCoolDownTimeoutSeconds = (int)TimeSpan.FromMinutes(1.0).TotalSeconds;

		protected readonly int MinimumPauseTimeoutSeconds = (int)TimeSpan.FromMinutes(1.0).TotalSeconds;

		protected IDisposable stateSubscriber;

		protected IDisposable workoutStateStartedSub;

		protected IDisposable warmupStartedSub;

		protected IDisposable workoutStartedSub;

		protected IDisposable coolDownStartedSub;

		protected IDisposable restoredPauseEndedSub;

		protected IDisposable competitionsMomentSub;

		protected bool recovered;

		protected readonly IWorkoutFacade workoutFacade;

		protected readonly IReadWriteFacadeFactoryDependencies facadeFactoryDependencies;

		protected SemaphoreSlim warmUpSemaphore;

		protected SemaphoreSlim workoutSemaphore;

		protected SemaphoreSlim coolDownSemaphore;

		private ReplaySubject<IScalingControlAdapter> _whenScalingControlAdapterChanged = new ReplaySubject<IScalingControlAdapter>(1);

		private IControlAdapter _controlAdapter;

		private IWorkoutChangeLevel _workoutChangeLevel;

		private IHRTrainingService _hrTrainingService;

		protected readonly Subject<object> _whenOverrideDecoratorChanged = new Subject<object>();

		private bool disposedValue;

		public IFitnessConsole Console { get; }

		public ICompetitionService CompetitionService { get; set; }

		public WorkoutRunnerContext RunContext { get; private set; }

		public Workout WarmUp { get; }

		public Workout Workout { get; }

		public Workout CoolDown { get; }

		public bool IsMetric { get; }

		public bool IsRunning
		{
			get
			{
				if (HasStartedWorkout && !HasStartedCoolDown)
				{
					IFitnessConsole console = Console;
					if (console == null)
					{
						return false;
					}
					return console.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
				}
				return false;
			}
		}

		public double UserWeightKgs { get; }

		public TimeSpan AutoChangeThreshold { get; } = TimeSpan.FromMilliseconds(1000.0);

		public List<IControlDecorator> Decorators { get; } = new List<IControlDecorator>();

		public IObservable<IScalingControlAdapter> WhenScalingControlAdapterChanged => _whenScalingControlAdapterChanged;

		public IControlAdapter ControlAdapter
		{
			get
			{
				return _controlAdapter;
			}
			protected set
			{
				_controlAdapter = value;
				if (value is IScalingControlAdapter scalingControlAdapter)
				{
					if (HRTrainingService != null)
					{
						HRTrainingService.ControlAdapter = scalingControlAdapter;
					}
					if (WorkoutChangeLevel != null)
					{
						WorkoutChangeLevel.ControlAdapter = scalingControlAdapter;
					}
					_whenScalingControlAdapterChanged.OnNext(scalingControlAdapter);
				}
			}
		}

		public IWorkoutChangeLevel WorkoutChangeLevel
		{
			get
			{
				return _workoutChangeLevel;
			}
			set
			{
				_workoutChangeLevel = value;
				if (_workoutChangeLevel != null)
				{
					_workoutChangeLevel.RunningOverrides = this;
					_workoutChangeLevel.ControlAdapter = ControlAdapter as IScalingControlAdapter;
				}
			}
		}

		public IHRTrainingService HRTrainingService
		{
			get
			{
				return _hrTrainingService;
			}
			private set
			{
				_hrTrainingService = value;
				if (_hrTrainingService != null)
				{
					_hrTrainingService.ControlAdapter = ControlAdapter as IScalingControlAdapter;
				}
			}
		}

		public string WolfGeneratedId { get; }

		public virtual double WorkoutElapsedSeconds
		{
			get
			{
				return (Console?.LatestBasicInfo?.TimeSeconds).GetValueOrDefault();
			}
			set
			{
			}
		}

		public virtual double WorkoutRunningSeconds
		{
			get
			{
				return (Console?.LatestBasicInfo?.RunningTime).GetValueOrDefault();
			}
			set
			{
			}
		}

		public IObservable<object> WhenOverrideDecoratorChanged => _whenOverrideDecoratorChanged;

		public IObservable<bool> WhenIsLoadingChanged { get; set; }

		public bool HasUserOverrideEnabled => Decorators?.Any((IControlDecorator x) => x is UserOverrideDecorator && x.Enabled) ?? false;

		public bool HasStartedWarmUp { get; protected set; }

		public bool HasStartedWorkout { get; protected set; }

		public bool HasStartedCoolDown { get; protected set; }

		public int? PauseTimeoutSeconds { get; set; }

		protected BaseWorkoutRunner(IFitnessConsole console, bool isMetric, double userWeightKgs, Workout workout, WorkoutRunnerContext workoutContext, ICompetitionService competitionService, Workout warmUp = null, Workout coolDown = null, IObservable<bool> whenIsLoading = null, string wolfGeneratedId = null)
		{
			Console = console;
			WarmUp = warmUp;
			Workout = workout;
			CoolDown = coolDown;
			RunContext = workoutContext;
			IsMetric = isMetric;
			UserWeightKgs = userWeightKgs;
			CompetitionService = competitionService;
			WhenIsLoadingChanged = whenIsLoading;
			WolfGeneratedId = (string.IsNullOrWhiteSpace(wolfGeneratedId) ? Guid.NewGuid().ToString() : wolfGeneratedId);
			Mvx.TryResolve<IHRTrainingService>(out var service);
			if (service != null)
			{
				_hrTrainingService = service;
			}
			workoutFacade = Mvx.Resolve<IWorkoutFacade>();
			facadeFactoryDependencies = Mvx.Resolve<IReadWriteFacadeFactoryDependencies>();
			warmUpSemaphore = new SemaphoreSlim(1);
			workoutSemaphore = new SemaphoreSlim(1);
			coolDownSemaphore = new SemaphoreSlim(1);
		}

		public void Init()
		{
			ConfigureAcceptableStates();
			AddApplicableDecorators(Workout, Console);
			CheckAddCalorieMultiplierToConsole(Workout);
			CheckRecover();
		}

		protected void ConfigureAcceptableStatesList(List<ConsoleState> stateList, params ConsoleState[] states)
		{
			stateList.Clear();
			foreach (ConsoleState item in states)
			{
				stateList.Add(item);
			}
		}

		protected virtual void ConfigureAcceptableStates()
		{
			ConfigureAcceptableStatesList(startWarmUpAcceptableStates, ConsoleState.Idle, ConsoleState.WarmUp, ConsoleState.Paused);
			ConfigureAcceptableStatesList(startWorkoutAcceptableStates, ConsoleState.Idle, ConsoleState.WarmUp, ConsoleState.Workout, ConsoleState.Paused, ConsoleState.PauseOverride);
			ConfigureAcceptableStatesList(startCoolDownAcceptableStates, ConsoleState.Workout, ConsoleState.CoolDown, ConsoleState.Paused, ConsoleState.PauseOverride);
			ConfigureAcceptableStatesList(recoveryAcceptableStates, ConsoleState.WarmUp, ConsoleState.Workout, ConsoleState.CoolDown, ConsoleState.Paused, ConsoleState.PauseOverride);
			ConfigureAcceptableStatesList(finishWarmUpAcceptableStates, ConsoleState.WarmUp, ConsoleState.Paused);
			ConfigureAcceptableStatesList(finishWorkoutAcceptableStates, ConsoleState.Workout, ConsoleState.PauseOverride, ConsoleState.Paused);
		}

		private void CheckAddCalorieMultiplierToConsole(Workout workout)
		{
			if (workout == null || !(workout.Metadata?.CalorieMultipliers?.Count > 0))
			{
				return;
			}
			if (Console.ConsoleInfo.MachineType.IsAerobicMachine())
			{
				AerobicCalorieMultiplierSubstitute item = new AerobicCalorieMultiplierSubstitute(workout.Metadata.CalorieMultipliers.Select((Workout.VideoWorkoutMetadata.CalorieMultiplierEvent x) => x.ConvertMultiplierEvent()).ToList(), UserWeightKgs);
				Console.ChangeManager.Substitutes.Add(item);
				Console.ChangeManager.Decorators.Add(item);
			}
			else
			{
				CalorieMultiplierDecorator item2 = new CalorieMultiplierDecorator(workout.Metadata.CalorieMultipliers.Select((Workout.VideoWorkoutMetadata.CalorieMultiplierEvent x) => x.ConvertMultiplierEvent()).ToList());
				Console.ChangeManager.Decorators.Add(item2);
			}
		}

		protected void CheckRecover()
		{
			if (!recoveryAcceptableStates.Contains(Console.LatestBasicInfo.CurrentState))
			{
				return;
			}
			recovered = true;
			if (Console.LatestBasicInfo.CurrentState == ConsoleState.Paused)
			{
				restoredPauseEndedSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
					where x.Current != ConsoleState.Paused && recoveryAcceptableStates.Contains(x.Current)
					select x, async delegate
				{
					await Recover().ConfigureAwait(continueOnCapturedContext: false);
					restoredPauseEndedSub?.Dispose();
					restoredPauseEndedSub = null;
				});
			}
			else
			{
				Task.Run((Func<Task>)Recover);
			}
		}

		protected virtual async Task Recover()
		{
			if (Console?.LatestBasicInfo != null)
			{
				iFit.Logger.Log.Trace("Workout", "Recovering workout");
				switch (Console.LatestBasicInfo.CurrentState)
				{
				case ConsoleState.WarmUp:
					await StartWarmUpSafely().ConfigureAwait(continueOnCapturedContext: false);
					break;
				case ConsoleState.Workout:
					await StartWorkoutSafely(isRecovering: true).ConfigureAwait(continueOnCapturedContext: false);
					EnableUserOverrides();
					break;
				case ConsoleState.CoolDown:
					await StartCoolDownSafely().ConfigureAwait(continueOnCapturedContext: false);
					break;
				default:
					iFit.Logger.Log.Trace("Workout", "Don't know how to recover workout in state " + Console.LatestBasicInfo.CurrentState);
					break;
				}
			}
		}

		public virtual async Task<bool> Start()
		{
			if (recovered)
			{
				iFit.Logger.Log.Trace("Workout", "Workout Recovered, restarting competition service");
				return true;
			}
			iFit.Logger.Log.Trace("Workout", "Starting workout");
			if (Console.LatestBasicInfo.CurrentState != ConsoleState.Idle)
			{
				throw new WorkoutRunnerException($"Console not in an idle state to start a workout. The console instead is in state: {Console.LatestBasicInfo.CurrentState}");
			}
			try
			{
				iFit.Logger.Log.Trace("Workout", "Calculating preworkout info");
				int timeoutSeconds = GetTimeoutSeconds(WarmUp, DefaultWarmUpTimeoutSeconds, MinimumWarmUpTimeoutSeconds);
				int timeoutSeconds2 = GetTimeoutSeconds(CoolDown, DefaultCoolDownTimeoutSeconds, MinimumCoolDownTimeoutSeconds);
				int pauseTimeoutSeconds = ((!PauseTimeoutSeconds.HasValue) ? DefaultPauseTimeoutSeconds : Math.Max(PauseTimeoutSeconds.Value, MinimumPauseTimeoutSeconds));
				double b = Console?.ConsoleInfo?.MaxWeight ?? 136.078;
				double userWeightKgs = UserWeightKgs.Clamp(45.36, b);
				int targetValue = (int)Workout.TargetValue;
				WorkoutGoal goalType = TargetToGoalType[Workout.Target];
				iFit.Logger.Log.Trace("Workout", "Sending preworkout info to the console");
				await workoutFacade.SetPreWorkoutInfoAsync(IsMetric, userWeightKgs, targetValue, goalType, timeoutSeconds, timeoutSeconds2, pauseTimeoutSeconds);
				iFit.Logger.Log.Trace("Workout", "Preworkout info sent to the console");
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Workout", "Error sending preworkout info to the console", exception);
			}
			if (WarmUp != null)
			{
				return await StartWarmUpSafely().ConfigureAwait(continueOnCapturedContext: false);
			}
			return await StartWorkoutSafely().ConfigureAwait(continueOnCapturedContext: false);
		}

		public void Pause()
		{
			iFit.Logger.Log.Trace("Workout", "Pausing the workout");
			workoutFacade.PauseWorkout();
		}

		public void Resume()
		{
			iFit.Logger.Log.Trace("Workout", "Resuming the workout");
			workoutFacade.ResumeWorkout();
		}

		public async Task StopAsync()
		{
			iFit.Logger.Log.Trace("Workout", "stopping the workout");
			CleanUp();
			(from x in Decorators?.OfType<UserOverrideDecorator>()
				where x != null
				select x).ForEach(delegate(UserOverrideDecorator x)
			{
				x.PropertyChanged -= HandleOverrideDecoratorChanged;
			});
			await workoutFacade.EndWorkoutAsync();
			EndCompetition(workoutComplete: false);
		}

		protected async Task<bool> StartWarmUpSafely()
		{
			_ = 1;
			try
			{
				if (!(await warmUpSemaphore.WaitAsync(TimeSpan.FromSeconds(5.0)).ConfigureAwait(continueOnCapturedContext: false)) || !CheckCanStartWarmUp())
				{
					return HasStartedWarmUp;
				}
				iFit.Logger.Log.Trace("Workout", "starting a warmup");
				await StartWarmUpAsync();
				SetupAdapterOrSubscriptionForWarmUp();
				return true;
			}
			finally
			{
				warmUpSemaphore?.Release();
			}
		}

		protected abstract Task StartWarmUpAsync();

		protected virtual bool CheckCanStartWarmUp()
		{
			if (HasStartedWarmUp)
			{
				return false;
			}
			CleanUp();
			if (WarmUp == null)
			{
				return false;
			}
			return IsConsoleStateAcceptable(startWarmUpAcceptableStates);
		}

		protected virtual void SetupAdapterOrSubscriptionForWarmUp()
		{
			IFitnessConsole console = Console;
			if (console != null && console.LatestBasicInfo.CurrentState == ConsoleState.WarmUp)
			{
				SetUpAdapterForWarmUp();
				return;
			}
			warmupStartedSub = (from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
				where x.Current == ConsoleState.WarmUp
				select x).Subscribe(delegate
			{
				SetUpAdapterForWarmUp();
				warmupStartedSub?.Dispose();
			});
		}

		protected virtual void SetUpAdapterForWarmUp()
		{
			HasStartedWarmUp = true;
			ControlAdapter = new ControlAdapter(WarmUp.Target, Workout.Category(), WarmUp.Controls, Console, Decorators, WhenIsLoadingChanged);
			stateSubscriber = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
				where x.Current == ConsoleState.Workout
				select x, async delegate
			{
				await StartWorkoutSafely().ConfigureAwait(continueOnCapturedContext: false);
			});
			workoutStateStartedSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(Console.WhenStateChanged.Where((StateChange x) => x.Old != ConsoleState.Paused && x.Old != ConsoleState.PauseOverride && x.Current == ConsoleState.Workout), async delegate
			{
				await StartWorkoutSafely().ConfigureAwait(continueOnCapturedContext: false);
			});
		}

		public virtual async Task FinishWarmUp()
		{
			if (!HasStartedWorkout && IsConsoleStateAcceptable(finishWarmUpAcceptableStates))
			{
				iFit.Logger.Log.Trace("Workout", "manually finishing the warmup");
				await StartWorkoutSafely().ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		protected async Task<bool> StartWorkoutSafely(bool isRecovering = false)
		{
			_ = 1;
			try
			{
				if (!(await workoutSemaphore.WaitAsync(TimeSpan.FromSeconds(5.0)).ConfigureAwait(continueOnCapturedContext: false)) || !CheckCanStartWorkout())
				{
					return HasStartedWorkout;
				}
				iFit.Logger.Log.Trace("Workout", "starting the workout");
				await StartWorkoutAsync(isRecovering);
				SetupAdapterOrSubscriptionForWorkout();
				return true;
			}
			finally
			{
				workoutSemaphore?.Release();
			}
		}

		protected abstract Task StartWorkoutAsync(bool isRecovering = false);

		protected virtual bool CheckCanStartWorkout()
		{
			if (HasStartedWorkout)
			{
				return false;
			}
			CleanUp();
			return IsConsoleStateAcceptable(startWorkoutAcceptableStates);
		}

		protected virtual void SetupAdapterOrSubscriptionForWorkout()
		{
			IFitnessConsole console = Console;
			if (console != null && console.LatestBasicInfo?.CurrentState == ConsoleState.Workout)
			{
				SetupAdapterForWorkout();
				StartChangingWorkoutLevelingFeature();
				return;
			}
			workoutStartedSub = (from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
				where x.Current == ConsoleState.Workout
				select x).Subscribe(delegate
			{
				SetupAdapterForWorkout();
				StartChangingWorkoutLevelingFeature();
				workoutStartedSub?.Dispose();
			});
		}

		protected abstract void SetupAdapterForWorkout();

		protected virtual void SetUpLiveWorkoutCaptionTimeUpdateSubscribers()
		{
			ICompetitionService competitionService = CompetitionService;
			if (competitionService != null && competitionService.CompetitionsFeatureEnabled(this))
			{
				IObservable<FitnessValueChange<int>> source = ((Workout.Target == Workout.TargetType.Meters) ? (from x in facadeFactoryDependencies.CurrentDistanceFacade.ObserveMeterChanges()
					select new FitnessValueChange<int>(x.Type, (int)x.Old, (int)x.Current)) : facadeFactoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges());
				competitionsMomentSub = source.Subscribe(delegate(FitnessValueChange<int> x)
				{
					if (IsRunning && x.Current > x.Old)
					{
						CompetitionService?.AddMomentWithInfo(x.Current, Decorators);
					}
					else
					{
						iFit.Logger.Log.Warn("Workout", $"Moment Current {x.Current} is less than Previous {x.Old}");
					}
				});
			}
			else
			{
				iFit.Logger.Log.Trace("Workout", "Competitions not enabled, not starting competitionsMomentSub");
			}
		}

		public virtual async Task<bool> FinishWorkout(bool completed)
		{
			ControlAdapter?.Dispose();
			ControlAdapter = null;
			if (!HasStartedCoolDown)
			{
				facadeFactoryDependencies.GradeFacade.SetGrade(0.0);
				facadeFactoryDependencies.ResistanceFacade.SetResistance(1.0);
			}
			if (HasStartedCoolDown || !IsConsoleStateAcceptable(finishWorkoutAcceptableStates))
			{
				return HasStartedCoolDown;
			}
			iFit.Logger.Log.Trace("Workout", $"manually finishing the workout - completed = {completed}");
			if (CoolDown == null)
			{
				await StopAsync();
				return true;
			}
			EndCompetition(completed);
			return await StartCoolDownSafely().ConfigureAwait(continueOnCapturedContext: false);
		}

		protected async Task<bool> StartCoolDownSafely()
		{
			_ = 1;
			try
			{
				if (!(await coolDownSemaphore.WaitAsync(TimeSpan.FromSeconds(5.0)).ConfigureAwait(continueOnCapturedContext: false)) || !CheckCanStartCoolDown())
				{
					return HasStartedCoolDown;
				}
				iFit.Logger.Log.Trace("Workout", "Starting the cooldown");
				SetDesiredMpsForCoolDown();
				await StartCoolDownAsync();
				SetupAdapterOrSubscriptionForCoolDown();
				return true;
			}
			finally
			{
				coolDownSemaphore?.Release();
			}
		}

		protected abstract Task StartCoolDownAsync();

		protected virtual bool CheckCanStartCoolDown()
		{
			if (HasStartedCoolDown)
			{
				return false;
			}
			CleanUp();
			if (CoolDown == null)
			{
				return false;
			}
			return IsConsoleStateAcceptable(startCoolDownAcceptableStates);
		}

		protected virtual void SetDesiredMpsForCoolDown()
		{
			IFitnessConsole console = Console;
			double desiredMps = ((console != null && console.LatestBasicInfo?.Kph > 0.0) ? Math.Min(UnitUtil.EnsureMps(SpeedUnit.Kph, Console.LatestBasicInfo.Kph), 0.89408) : 0.89408);
			CoolDown?.Controls?.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps).ForEach(delegate(Workout.Control x)
			{
				x.Value = desiredMps;
			});
		}

		protected virtual void SetupAdapterOrSubscriptionForCoolDown()
		{
			IFitnessConsole console = Console;
			if (console != null && console.LatestBasicInfo.CurrentState == ConsoleState.CoolDown)
			{
				SetUpAdapterForCoolDown();
				return;
			}
			coolDownStartedSub = (from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
				where x.Current == ConsoleState.CoolDown
				select x).Subscribe(delegate
			{
				SetUpAdapterForCoolDown();
				coolDownStartedSub?.Dispose();
			});
		}

		protected virtual void SetUpAdapterForCoolDown()
		{
			HasStartedCoolDown = true;
			ControlAdapter = new ControlAdapter(CoolDown.Target, Workout.Category(), CoolDown.Controls, Console, Decorators);
			stateSubscriber = (from x in facadeFactoryDependencies.ConsoleStateFacade.ObserveConsoleStateChanges()
				where x.Current == ConsoleState.Idle || x.Current == ConsoleState.WorkoutResults
				select x).Subscribe(delegate
			{
				CoolDownFinished();
			});
		}

		protected void CoolDownFinished()
		{
			iFit.Logger.Log.Trace("Workout", "cool down completed");
			CleanUp();
		}

		protected virtual void AddApplicableDecorators(Workout workout, IFitnessConsole console)
		{
			if (workout != null && !workout.IsGoogleMap && workout.HasControlsFor(Workout.Control.ControlType.Mps) && console != null && console.ConsoleInfo?.CanSetKph == true)
			{
				Decorators.Add(new UserOverrideSpeedDecorator());
			}
			if ((console == null || console.ConsoleInfo?.MachineType != ConsoleType.SpinBike) && workout.HasControlsFor(Workout.Control.ControlType.Resistance) && console != null && console.ConsoleInfo?.CanSetResistance == true)
			{
				Decorators.Add(new UserOverrideResistanceDecorator());
			}
			if (workout.HasControlsFor(Workout.Control.ControlType.Incline) && console != null && console.ConsoleInfo?.CanSetIncline == true)
			{
				Decorators.Add(new UserOverrideInclineDecorator());
			}
			if (workout.HasControlsFor(Workout.Control.ControlType.Gear) && console != null && console.ConsoleInfo?.CanSetGear == true)
			{
				Decorators.Add(new UserOverrideGearDecorator());
			}
		}

		public virtual bool HasUserOverrideDecoratorOfType(FitnessValue metricType, out Workout.Control.ControlType controlType)
		{
			if (!MetricControlTypeTable.TryGetValue(metricType, out controlType))
			{
				return false;
			}
			Workout.Control.ControlType localControlType = controlType;
			List<IControlDecorator> decorators = Decorators;
			if (decorators == null)
			{
				return false;
			}
			return decorators.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator x) => x != null && x.ControlType == localControlType) == true;
		}

		public bool HasUserOverrideDecoratorOfType(FitnessValue fitnessValue)
		{
			List<IControlDecorator> decorators = Decorators;
			if (decorators == null)
			{
				return false;
			}
			return decorators.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator x) => x != null && x.FitnessValue == fitnessValue) == true;
		}

		public virtual void EnableUserOverride(FitnessValue fitnessValue)
		{
			Decorators?.OfType<UserOverrideDecorator>()?.Where((UserOverrideDecorator x) => x != null && x.FitnessValue == fitnessValue)?.ForEach(delegate(UserOverrideDecorator x)
			{
				x.Enabled = true;
				iFit.Logger.Log.Trace("Workout", $"Enabling user override: {fitnessValue}");
			});
		}

		public virtual void EnableUserOverride(Workout.Control.ControlType controlType)
		{
			Decorators?.OfType<UserOverrideDecorator>()?.Where((UserOverrideDecorator x) => x != null && x.ControlType == controlType && !x.Enabled)?.ForEach(delegate(UserOverrideDecorator x)
			{
				x.Enabled = true;
				iFit.Logger.Log.Trace("Workout", "Enabling user override: " + controlType);
			});
		}

		public void EnableUserOverrides(FitnessValue metricType)
		{
			if (MetricControlTypeTable.TryGetValue(metricType, out var controlType))
			{
				List<IControlDecorator> decorators = Decorators;
				if (decorators == null || decorators.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator x) => x != null && x.ControlType == controlType) != true)
				{
					iFit.Logger.Log.Trace("Workout", $"{controlType} was not found in Decorators, override will not occur");
					return;
				}
			}
			EnableUserOverride(controlType);
		}

		public void EnableUserOverrides(bool forceNotifications = false)
		{
			iFit.Logger.Log.Trace("Workout", "BaseWorkoutRunner.EnableUserOverrides");
			List<IControlDecorator> decorators = Decorators;
			if (decorators != null && decorators.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator x) => !x.Enabled) == true)
			{
				iFit.Logger.Log.Trace("Workout", "Enabling all user overrides");
				Decorators?.OfType<UserOverrideDecorator>()?.ForEach(delegate(UserOverrideDecorator x)
				{
					x.Enabled = true;
				});
			}
			if (forceNotifications)
			{
				_whenOverrideDecoratorChanged.OnNext(null);
			}
		}

		public virtual void DisableUserOverrides(bool resetValues)
		{
			iFit.Logger.Log.Trace("Workout", "Disabling user overrides");
			HashSet<Workout.Control.ControlType> overriddenControlTypes = new HashSet<Workout.Control.ControlType>((from x in Decorators?.OfType<UserOverrideDecorator>()?.Where((UserOverrideDecorator x) => x?.Enabled ?? false)
				select x.ControlType));
			Decorators?.OfType<UserOverrideDecorator>()?.ForEach(delegate(UserOverrideDecorator x)
			{
				x.Enabled = false;
			});
			if (resetValues)
			{
				IEnumerable<Workout.Control.ControlType> excludeTypes = (Enum.GetValues(typeof(Workout.Control.ControlType)) as IEnumerable<Workout.Control.ControlType>).Where((Workout.Control.ControlType x) => !overriddenControlTypes.Contains(x));
				ControlAdapter?.ResetToLatest(excludeTypes);
			}
		}

		public void DisableUserOverride(FitnessValue metricType, bool resetValues)
		{
			iFit.Logger.Log.Trace("Workout", $"Disabling user overrides: metricType:{metricType} resetValues:{resetValues}");
			if (MetricControlTypeTable.TryGetValue(metricType, out var controlType))
			{
				List<IControlDecorator> decorators = Decorators;
				if (decorators == null || decorators.OfType<UserOverrideDecorator>()?.Any((UserOverrideDecorator x) => x != null && x.ControlType == controlType) != true)
				{
					iFit.Logger.Log.Trace("Workout", $"{controlType} was not found in Decorators, disable override will not occur");
					return;
				}
			}
			Decorators?.OfType<UserOverrideDecorator>()?.Where((UserOverrideDecorator x) => x.ControlType == controlType).ForEach(delegate(UserOverrideDecorator x)
			{
				x.Enabled = false;
			});
			if (resetValues)
			{
				IEnumerable<Workout.Control.ControlType> excludeTypes = (Enum.GetValues(typeof(Workout.Control.ControlType)) as IEnumerable<Workout.Control.ControlType>).Where((Workout.Control.ControlType x) => x != controlType);
				ControlAdapter?.ResetToLatest(excludeTypes);
			}
		}

		protected void HandleOverrideDecoratorChanged(object sender, PropertyChangedEventArgs e)
		{
			_whenOverrideDecoratorChanged.OnNext(null);
		}

		protected virtual void HandleControlValueChangedOnConsole(FitnessValue fitnessValue)
		{
			IFitnessConsole console = Console;
			int num;
			if (console != null && console.ConsoleInfo?.MachineType.IsBeltBasedMachine() == true && HasStartedWorkout && !HasStartedCoolDown)
			{
				IFitnessConsole console2 = Console;
				if (console2 == null || console2.LatestBasicInfo?.CurrentState != ConsoleState.Paused)
				{
					IFitnessConsole console3 = Console;
					if (console3 == null || console3.LatestBasicInfo?.CurrentState != ConsoleState.SafetyKeyRemoved)
					{
						IFitnessConsole console4 = Console;
						num = ((console4 != null && console4.LatestBasicInfo?.CurrentState == ConsoleState.Error) ? 1 : 0);
						goto IL_013b;
					}
				}
				num = 1;
			}
			else
			{
				num = 0;
			}
			goto IL_013b;
			IL_013b:
			bool flag = (byte)num != 0;
			bool flag2 = HasUserOverrideDecoratorOfType(fitnessValue);
			if ((IsRunning || flag) && flag2)
			{
				iFit.Logger.Log.Trace("Workout", $"ControlValueChangedOnConsole, {fitnessValue} bit field changed, enabling user override");
				EnableUserOverride(fitnessValue);
				return;
			}
			iFit.Logger.Log.Trace("Workout", $"ControlValueChangedOnConsole, {fitnessValue} changed, but not enabling user override because IsRunning = {IsRunning}, treadmillPausedOrDmkOrError = {flag}, hasUserOverrideDecorator = {flag2}");
		}

		protected virtual async Task StartCompetition(bool isRecovered)
		{
			await Task.Run(async delegate
			{
				if (CompetitionService != null)
				{
					await CompetitionService.StartCompetitionAsync(Console, Workout, this, WolfGeneratedId, isRecovered).ConfigureAwait(continueOnCapturedContext: false);
				}
				else
				{
					iFit.Logger.Log.Trace("Workout", "CompetitionService was null when trying to start it");
				}
			});
		}

		protected virtual void EndCompetition(bool workoutComplete)
		{
			CompetitionService?.EndCompetition(workoutComplete);
			CompetitionService = null;
		}

		protected void StartHRTrainingService()
		{
			HRTrainingService.Start(Console, Workout, Workout.HeartRateZones, WolfGeneratedId);
		}

		protected void StopHRTrainingService()
		{
			HRTrainingService.Stop();
		}

		protected void StartChangingWorkoutLevelingFeature()
		{
			if (WorkoutChangeLevel != null)
			{
				WorkoutChangeLevel.Start();
			}
		}

		protected bool IsConsoleStateAcceptable(List<ConsoleState> acceptableStates)
		{
			if (!acceptableStates.Contains(Console.LatestBasicInfo.CurrentState))
			{
				iFit.Logger.Log.Error("Workout", string.Format("console not in an acceptable state.  Expected one of: {0}.  The console is in state: {1}", acceptableStates.ToDelimitedString(","), Console.LatestBasicInfo.CurrentState));
				return false;
			}
			return true;
		}

		protected int GetTimeoutSeconds(Workout workout, int defaultTimeoutSeconds, int minimumTimeoutSeconds)
		{
			int? num = (int?)workout?.TargetValue;
			if (!num.HasValue)
			{
				return defaultTimeoutSeconds;
			}
			return Math.Max(num.Value, minimumTimeoutSeconds);
		}

		protected virtual void CleanUp()
		{
			iFit.Logger.Log.Trace("Workout", "Cleaning up workout runner");
			ControlAdapter?.Dispose();
			ControlAdapter = null;
			stateSubscriber?.Dispose();
			stateSubscriber = null;
			workoutStateStartedSub?.Dispose();
			workoutStateStartedSub = null;
			restoredPauseEndedSub?.Dispose();
			restoredPauseEndedSub = null;
			warmupStartedSub?.Dispose();
			warmupStartedSub = null;
			workoutStartedSub?.Dispose();
			workoutStartedSub = null;
			coolDownStartedSub?.Dispose();
			coolDownStartedSub = null;
			competitionsMomentSub?.Dispose();
			competitionsMomentSub = null;
		}

		protected virtual void Dispose(bool disposing)
		{
			if (disposedValue)
			{
				return;
			}
			if (disposing)
			{
				DisableUserOverrides(resetValues: false);
				(from x in Decorators?.OfType<UserOverrideDecorator>()
					where x != null
					select x).ForEach(delegate(UserOverrideDecorator x)
				{
					x.PropertyChanged -= HandleOverrideDecoratorChanged;
					x.Dispose();
				});
				Decorators?.Clear();
				Console.ChangeManager.Decorators.RemoveAll((IFitnessValueDecorator x) => x is CalorieMultiplierDecorator);
				Console.ChangeManager.Decorators.RemoveAll((IFitnessValueDecorator x) => x is AerobicCalorieMultiplierSubstitute);
				Console.ChangeManager.Substitutes.Clear();
				CleanUp();
				EndCompetition(workoutComplete: false);
				WorkoutChangeLevel?.Dispose();
				WorkoutChangeLevel = null;
				WarmUp?.Dispose();
				CoolDown?.Dispose();
			}
			disposedValue = true;
		}

		public void Dispose()
		{
			Dispose(disposing: true);
		}
	}
	public class ClubGuestManualWorkoutRunner : ManualWorkoutRunner
