	public interface IControlAdapter : IDisposable
	{
		DateTime LastProgramInclineChange { get; }

		DateTime LastProgramResistanceChange { get; }

		DateTime LastProgramSpeedChange { get; }

		DateTime LastProgramGearChange { get; }

		IObservable<double> WhenTargetMetricChanged { get; }

		void ResetToLatest(IEnumerable<Workout.Control.ControlType> excludeTypes);
	}
	public class ControlAdapter : IControlAdapter, IDisposable
	{
		private readonly IFitnessConsole console;

		private readonly Workout.WorkoutCategory workoutCategory;

		private readonly List<Workout.Control> controls;

		private readonly List<IControlDecorator> decorators;

		private readonly double minResistance;

		private readonly double maxResistance;

		private readonly IConsoleControlValuesFacade consoleControlValuesFacade;

		private readonly ICurrentTimeFacade currentTimeFacade;

		private readonly ICurrentDistanceFacade currentDistanceFacade;

		private readonly ICaloriesFacade caloriesFacade;

		private bool videoIsLoading;

		protected double latestTargetValue;

		private IDisposable targetSubscriber;

		private IDisposable initialTimeSubscriber;

		private IDisposable isLoadingSub;

		protected readonly Subject<double> _whenTargetMetricChanged = new Subject<double>();

		public DateTime LastProgramInclineChange { get; protected set; } = DateTime.UtcNow;

		public DateTime LastProgramResistanceChange { get; protected set; } = DateTime.UtcNow;

		public DateTime LastProgramSpeedChange { get; protected set; } = DateTime.UtcNow;

		public DateTime LastProgramGearChange { get; protected set; } = DateTime.UtcNow;

		public IObservable<double> WhenTargetMetricChanged => _whenTargetMetricChanged;

		public ControlAdapter(Workout.TargetType target, Workout.WorkoutCategory workoutCategory, List<Workout.Control> controls, IFitnessConsole console, List<IControlDecorator> decorators, IObservable<bool> whenIsLoadingChanged = null)
		{
			this.controls = controls;
			this.console = console;
			this.decorators = decorators;
			consoleControlValuesFacade = Mvx.Resolve<IConsoleControlValuesFacade>();
			currentTimeFacade = Mvx.Resolve<ICurrentTimeFacade>();
			currentDistanceFacade = Mvx.Resolve<ICurrentDistanceFacade>();
			caloriesFacade = Mvx.Resolve<ICaloriesFacade>();
			this.workoutCategory = workoutCategory;
			minResistance = console?.ConsoleInfo?.MinResistanceLevel ?? 1.0;
			maxResistance = console?.ConsoleInfo?.MaxResistanceLevel ?? 26.0;
			isLoadingSub?.Dispose();
			isLoadingSub = whenIsLoadingChanged?.SubscribeWithErrorLogging(delegate(bool loading)
			{
				videoIsLoading = loading;
			});
			SetupInitialTimeSubscriber();
			SetupTargetSubscriber(target);
		}

		private void SetupInitialTimeSubscriber()
		{
			initialTimeSubscriber?.Dispose();
			initialTimeSubscriber = (from x in currentTimeFacade.ObserveCurrentTimeChanges()
				where x.Current <= 1
				select x).SubscribeWithErrorLogging(delegate(FitnessValueChange<int> x)
			{
				UpdateControlsFromTarget(x.Current);
				initialTimeSubscriber?.Dispose();
			});
		}

		protected void SetupTargetSubscriber(Workout.TargetType workoutTargetType)
		{
			targetSubscriber?.Dispose();
			targetSubscriber = CreateTargetSubscriber(workoutTargetType);
		}

		protected virtual IDisposable CreateTargetSubscriber(Workout.TargetType target)
		{
			return target switch
			{
				Workout.TargetType.Seconds => currentTimeFacade.ObserveCurrentTimeChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<int> x)
				{
					UpdateControlsFromTarget(x.Current);
				}), 
				Workout.TargetType.Meters => currentDistanceFacade.ObserveMeterChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<double> x)
				{
					UpdateControlsFromTarget(x.Current);
				}), 
				Workout.TargetType.Calories => caloriesFacade.ObserveCalorieChanges().SubscribeWithErrorLogging(delegate(FitnessValueChange<double> x)
				{
					UpdateControlsFromTarget(x.Current);
				}), 
				_ => throw new ArgumentOutOfRangeException("target", target, "Unable to create target subscriber with invalid target"), 
			};
		}

		private void UpdateControlsFromTarget(double targetValue)
		{
			double num = (latestTargetValue = targetValue);
			UpdateControls(num, null, ignoreSentValues: true);
			_whenTargetMetricChanged.OnNext(num);
		}

		public virtual void Dispose()
		{
			isLoadingSub?.Dispose();
			isLoadingSub = null;
			targetSubscriber?.Dispose();
			targetSubscriber = null;
			initialTimeSubscriber?.Dispose();
			initialTimeSubscriber = null;
		}

		public virtual void ResetToLatest(IEnumerable<Workout.Control.ControlType> excludeTypes = null)
		{
			controls.ForEach(delegate(Workout.Control c)
			{
				c.OverriddenByUser = false;
			});
			UpdateControls(latestTargetValue, excludeTypes, ignoreSentValues: false);
		}

		protected virtual void UpdateControls(double at, IEnumerable<Workout.Control.ControlType> excludeTypes, bool ignoreSentValues)
		{
			List<IGrouping<Workout.Control.ControlType, Workout.Control>> list = (from c in controls
				group c by c.Type).ToList();
			List<Workout.Control> list2 = new List<Workout.Control>();
			foreach (IGrouping<Workout.Control.ControlType, Workout.Control> item in list)
			{
				if (excludeTypes == null || !excludeTypes.Contains(item.Key))
				{
					Workout.Control control = item?.LastOrDefault((Workout.Control c) => c.At <= at);
					if (control != null && !(control.HasBeenSent && ignoreSentValues))
					{
						list2.Add(control);
					}
				}
			}
			double? kph;
			double? incline;
			double? resistance;
			int? gear;
			if (!list2.IsNullOrEmpty() && !videoIsLoading)
			{
				kph = null;
				incline = null;
				resistance = null;
				gear = null;
				list2.OrderBy((Workout.Control c) => (c.Type != Workout.Control.ControlType.Incline) ? 1 : 0).ForEach(delegate(Workout.Control c)
				{
					UpdateControl(c, !ignoreSentValues);
				});
				consoleControlValuesFacade.SetControlValues(new ConsoleControlValues
				{
					Kph = kph,
					Incline = incline,
					Resistance = resistance,
					Gear = gear
				});
			}
			void UpdateControl(Workout.Control control2, bool isResettingOverrideByUser)
			{
				foreach (IControlDecorator decorator in decorators)
				{
					decorator.Decorate(control2);
				}
				if (control2.OverriddenByUser)
				{
					iFit.Logger.Log.Trace("Workout", $"Control is overridden by user: {control2.Type}");
				}
				else
				{
					switch (control2.Type)
					{
					case Workout.Control.ControlType.Incline:
						UpdateInclineControl(control2, out incline);
						break;
					case Workout.Control.ControlType.Resistance:
						UpdateResistanceControl(control2, out resistance);
						break;
					case Workout.Control.ControlType.Mps:
						UpdateSpeedControl(control2, out kph);
						break;
					case Workout.Control.ControlType.Gear:
						UpdateGearControl(control2, out gear);
						break;
					case Workout.Control.ControlType.RelativeResistance:
						UpdateRelativeResistanceControl(control2, out resistance);
						break;
					default:
						iFit.Logger.Log.Warn("Workout", "unsupported control type found: " + control2.Type);
						break;
					}
					control2.HasBeenSent = true;
					control2.SentToResetOverrideByUser = isResettingOverrideByUser;
				}
			}
		}

		protected void UpdateInclineControl(Workout.Control control, out double? incline)
		{
			if (console.LatestBasicInfo.Grade.AlmostEqual(control.Value, 1))
			{
				incline = null;
				return;
			}
			iFit.Logger.Log.Trace("Workout", "Updating incline to: " + control.Value);
			LastProgramInclineChange = DateTime.UtcNow;
			incline = control.Value;
		}

		protected virtual void UpdateSpeedControl(Workout.Control control, out double? kph)
		{
			double num = UnitUtil.EnsureKph(SpeedUnit.Mps, control.Value, 1);
			if (console.LatestBasicInfo.Kph.AlmostEqual(num, 1))
			{
				kph = null;
				return;
			}
			iFit.Logger.Log.Trace("Workout", "Updating kph to: " + num + "(" + control.Value + " mps)");
			LastProgramSpeedChange = DateTime.UtcNow;
			kph = num;
		}

		protected void UpdateRelativeResistanceControl(Workout.Control control, out double? resistance)
		{
			double num = MathUtils.Lerp(minResistance, maxResistance, Math.Round(control.Value) / 100.0);
			iFit.Logger.Log.Trace("Workout", $"Converting RelativeResistance control value from {control.Value} to {num}");
			Workout.Control control2 = new Workout.Control
			{
				At = control.At,
				Value = num,
				Type = Workout.Control.ControlType.Resistance
			};
			UpdateResistanceControl(control2, out resistance);
		}

		protected void UpdateResistanceControl(Workout.Control control, out double? resistance)
		{
			if (console.LatestBasicInfo.Resistance.AlmostEqual(control.Value, 1))
			{
				resistance = null;
				return;
			}
			iFit.Logger.Log.Trace("Workout", "Updating resistance level to: " + control.Value);
			LastProgramResistanceChange = DateTime.UtcNow;
			resistance = control.Value;
		}

		protected void UpdateGearControl(Workout.Control control, out int? gear)
		{
			int num = Convert.ToInt32(Math.Round(control.Value)).Clamp(console.ConsoleInfo.MinGear, console.ConsoleInfo.MaxGear);
			if ((console.LatestBasicInfo.Gear?.CurrentGear ?? 1) == num)
			{
				gear = null;
				return;
			}
			iFit.Logger.Log.Trace("Workout", "Updating gear level to: " + num);
			LastProgramGearChange = DateTime.UtcNow;
			gear = num;
		}
	}
	public class CapControlsTracking
	{
		private readonly Dictionary<int, ControlsTracking> mpsControlsTracking;

		private readonly Dictionary<int, ControlsTracking> inclineControlsTracking;

		private readonly Dictionary<string, ControlsTracking> controlsTracking;

		private readonly List<Workout.Control.ControlType> controlTypes;

		private readonly int minScaleLevel;

		private readonly int maxScaleLevel;

		private readonly double userMaxMps;

		private bool ShouldCapSpeeds => controlTypes.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Mps);

		private bool ShouldCapIncline => controlTypes.Any((Workout.Control.ControlType x) => x == Workout.Control.ControlType.Incline);

		public CapControlsTracking(Dictionary<string, ControlsTracking> controlsTracking, List<Workout.Control.ControlType> controlTypes, double userMaxMps, int minScaleLevel, int maxScaleLevel)
		{
			this.controlsTracking = controlsTracking;
			this.controlTypes = controlTypes;
			this.minScaleLevel = minScaleLevel;
			this.maxScaleLevel = maxScaleLevel;
			this.userMaxMps = userMaxMps;
			if (ShouldCapSpeeds)
			{
				mpsControlsTracking = ControlsTrackingForControlType(Workout.Control.ControlType.Mps);
				if (ShouldCapIncline)
				{
					inclineControlsTracking = ControlsTrackingForControlType(Workout.Control.ControlType.Incline);
				}
			}
		}

		private Dictionary<int, ControlsTracking> ControlsTrackingForControlType(Workout.Control.ControlType type)
		{
			Dictionary<int, ControlsTracking> dictionary = new Dictionary<int, ControlsTracking>();
			for (int i = minScaleLevel; i <= maxScaleLevel; i++)
			{
				string key = KeyForControlTracking(type, i);
				dictionary[i] = controlsTracking[key];
			}
			return dictionary;
		}

		public void Run()
		{
			if (ShouldCapSpeeds)
			{
				List<(double, int)> cappedScaleLevels = CapScaleLevelsToGovernor();
				ResetWorkingControlValues(Workout.Control.ControlType.Mps);
				SetWorkingControlValues(Workout.Control.ControlType.Mps, cappedScaleLevels);
				ApplyWorkingControlValues(Workout.Control.ControlType.Mps);
				if (ShouldCapIncline)
				{
					ResetWorkingControlValues(Workout.Control.ControlType.Incline);
					SetWorkingControlValues(Workout.Control.ControlType.Incline, cappedScaleLevels);
					ApplyWorkingControlValues(Workout.Control.ControlType.Incline);
				}
			}
		}

		private void SetWorkingControlValues(Workout.Control.ControlType controlType, List<(double at, int scale)> cappedScaleLevels)
		{
			for (int i = 0; i < cappedScaleLevels.Count; i++)
			{
				double item = cappedScaleLevels[i].at;
				int item2 = cappedScaleLevels[i].scale;
				if (item2 < maxScaleLevel)
				{
					switch (controlType)
					{
					case Workout.Control.ControlType.Mps:
						SetMpsWorkingControlValues(item2, item);
						break;
					case Workout.Control.ControlType.Incline:
						SetInclineWorkingControlValues(item2, item);
						break;
					}
				}
			}
		}

		private void SetMpsWorkingControlValues(int governorScaleLevel, double at)
		{
			for (int i = governorScaleLevel; i <= maxScaleLevel; i++)
			{
				mpsControlsTracking[i].SetWorkingControlValueAt(at, userMaxMps);
			}
		}

		private void SetInclineWorkingControlValues(int governorScaleLevel, double at)
		{
			double value = inclineControlsTracking[governorScaleLevel].OriginalControlValueAt(at);
			for (int i = governorScaleLevel + 1; i <= maxScaleLevel; i++)
			{
				inclineControlsTracking[i].SetWorkingControlValueAt(at, value);
			}
		}

		private List<(double at, int scale)> CapScaleLevelsToGovernor()
		{
			SortedSet<double> sortedSet = AllAtValuesForMps();
			List<(double, int)> list = new List<(double, int)>();
			foreach (double item2 in sortedSet)
			{
				int item = minScaleLevel;
				for (int i = minScaleLevel; i <= maxScaleLevel && !(mpsControlsTracking[i].OriginalControlValueAt(item2) > userMaxMps); i++)
				{
					item = i;
				}
				list.Add((item2, item));
			}
			return list;
		}

		private void ResetWorkingControlValues(Workout.Control.ControlType controlType)
		{
			Dictionary<int, ControlsTracking> dictionary = ControlTypeToControlsTracking(controlType);
			for (int i = minScaleLevel; i <= maxScaleLevel; i++)
			{
				dictionary[i].ResetWorkingControlValues();
			}
		}

		private void ApplyWorkingControlValues(Workout.Control.ControlType controlType)
		{
			Dictionary<int, ControlsTracking> dictionary = ControlTypeToControlsTracking(controlType);
			for (int i = minScaleLevel; i <= maxScaleLevel; i++)
			{
				dictionary[i].ApplyWorkingControlValues();
			}
		}

		private SortedSet<double> AllAtValuesForMps()
		{
			SortedSet<double> sortedSet = new SortedSet<double>();
			for (int i = minScaleLevel; i <= maxScaleLevel; i++)
			{
				foreach (Workout.Control control in mpsControlsTracking[i].controls)
				{
					sortedSet.Add(control.At);
				}
			}
			return sortedSet;
		}

		private Dictionary<int, ControlsTracking> ControlTypeToControlsTracking(Workout.Control.ControlType controlType)
		{
			if (controlType != Workout.Control.ControlType.Mps)
			{
				return inclineControlsTracking;
			}
			return mpsControlsTracking;
		}

		private string KeyForControlTracking(Workout.Control.ControlType controlType, int workoutScale)
		{
			return controlType.ToString() + workoutScale;
		}
	}
	public class ControlsTracking
	{
		public List<Workout.Control> controls;

		private readonly List<double> originalControlValues;

		private List<double> workingControlValues;

		private int currentAtIndex;

		public ControlsTracking(List<Workout.Control> controls)
		{
			if (controls == null || controls.Count == 0)
			{
				throw new Exception("Controls cannot be null.");
			}
			this.controls = controls;
			originalControlValues = controls.Select((Workout.Control x) => x.Value).ToList();
			workingControlValues = controls.Select((Workout.Control x) => x.Value).ToList();
		}

		public void OverriddenByUser(bool overriddenByUser)
		{
			foreach (Workout.Control control in controls)
			{
				control.OverriddenByUser = overriddenByUser;
			}
		}

		public bool DidControlChange(double currentAt)
		{
			Workout.Control control = FindControlNearestToTime(currentAt);
			if (currentAt - control.At >= 0.0 && currentAt - control.At <= 2.0)
			{
				return true;
			}
			return false;
		}

		public double OriginalControlValueAt(double at)
		{
			return originalControlValues[FindIndexNearestToTime(at)];
		}

		public double WorkingControlValueAt(double at)
		{
			return workingControlValues[FindIndexNearestToTime(at)];
		}

		public void SetWorkingControlValueAt(double at, double value)
		{
			workingControlValues[FindIndexNearestToTime(at)] = value;
		}

		private int FindIndexNearestToTime(double at)
		{
			int i = currentAtIndex;
			if (at > controls[i].At)
			{
				for (; i < controls.Count && !(controls[i].At > at); i++)
				{
				}
				i--;
			}
			else
			{
				while (i >= 0 && !(controls[i].At <= at))
				{
					i--;
				}
				if (i == -1)
				{
					i = 0;
				}
			}
			currentAtIndex = i;
			return i;
		}

		public Workout.Control FindControlNearestToTime(double at)
		{
			int i = currentAtIndex;
			if (at > controls[i].At)
			{
				for (; i < controls.Count && !(controls[i].At > at); i++)
				{
				}
				i--;
			}
			else
			{
				while (i >= 0 && !(controls[i].At <= at))
				{
					i--;
				}
				if (i == -1)
				{
					i = 0;
				}
			}
			currentAtIndex = i;
			return controls[i];
		}

		public void ResetWorkingControlValues()
		{
			workingControlValues = originalControlValues.ToList();
		}

		public void ApplyWorkingControlValues()
		{
			for (int i = 0; i < controls.Count; i++)
			{
				controls[i].Value = workingControlValues[i];
			}
		}

		public void DebugPrint(string type, int scale)
		{
			string text = $"{type} original[{scale}]=";
			for (int i = 0; i < controls.Count; i++)
			{
				text += $" [{controls[i].At}={UnitUtil.EnsureMph(SpeedUnit.Mps, originalControlValues[i], 1)}], ";
			}
			text = $"{type} working[{scale}]=";
			for (int j = 0; j < controls.Count; j++)
			{
				text += $" [{controls[j].At}={UnitUtil.EnsureMph(SpeedUnit.Mps, workingControlValues[j], 1)}], ";
			}
			text = $"{type} controls[{scale}]=";
			for (int k = 0; k < controls.Count; k++)
			{
				text += $" [{controls[k].At}={UnitUtil.EnsureMph(SpeedUnit.Mps, controls[k].Value, 1)}], ";
			}
		}
	}
