	public class LiveWorkoutRunner : JustInTimeWorkoutRunner, ILiveWorkoutRunner, IWorkoutRunner, IDisposable
	{
		private readonly Subject<LiveWorkoutState> _whenLiveWorkoutModeChanged = new Subject<LiveWorkoutState>();

		private readonly Subject<LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate> _whenLiveWorkoutTimeUpdated = new Subject<LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate>();

		private double _timeSeconds;

		private double _runningTime;

		private IDisposable controlValueChangedOnConsoleSub;

		private IDisposable captionTimeSub;

		private IDisposable captionStateSub;

		private readonly ILiveWorkoutTranslatorService liveWorkoutTranslatorService;

		public IObservable<LiveWorkoutState> WhenLiveWorkoutModeChanged => _whenLiveWorkoutModeChanged;

		public IObservable<LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate> WhenLiveWorkoutTimeUpdated => _whenLiveWorkoutTimeUpdated;

		public override double WorkoutElapsedSeconds
		{
			get
			{
				return _timeSeconds;
			}
			set
			{
				_timeSeconds = value;
			}
		}

		public override double WorkoutRunningSeconds
		{
			get
			{
				return _runningTime;
			}
			set
			{
				_runningTime = value;
			}
		}

		public LiveWorkoutRunner(IFitnessConsole console, bool isMetric, double userWeightKgs, Workout workout, WorkoutRunnerContext workoutContext, ICompetitionService competitionService, Workout warmUp, Workout coolDown, ILiveWorkoutTranslatorService liveWorkoutTranslatorService, IObservable<bool> whenIsLoading = null, string wolfGeneratedId = null)
			: base(console, isMetric, userWeightKgs, workout, workoutContext, competitionService, warmUp, coolDown, whenIsLoading, wolfGeneratedId)
		{
			this.liveWorkoutTranslatorService = liveWorkoutTranslatorService;
			if (base.WarmUp != null)
			{
				base.WarmUp.TargetValue = 600.0;
			}
			base.Workout.InitializeLiveControls(base.IsMetric);
			liveWorkoutTranslatorService?.Reset();
		}

		protected override void ConfigureAcceptableStates()
		{
			base.ConfigureAcceptableStates();
			startCoolDownAcceptableStates.Add(ConsoleState.WarmUp);
			finishWorkoutAcceptableStates.Add(ConsoleState.WarmUp);
		}

		public override async Task<bool> Start()
		{
			iFit.Logger.Log.Trace("Workout", "Starting Live Workout");
			bool started = await base.Start();
			await StartCompetition(recovered);
			SetUpLiveWorkoutCaptionStateUpdateSubscribers();
			return started;
		}

		protected override async Task StartWarmUpAsync()
		{
			IFitnessConsole console = base.Console;
			if (console == null || console.LatestBasicInfo?.CurrentState != ConsoleState.WarmUp)
			{
				GetInitialValues(out var initialKph, out var initialIncline, out var initialResistance, out var initialGear);
				await workoutFacade.StartWarmUpAsync(initialKph, initialIncline, initialResistance, initialGear);
			}
		}

		protected override async Task StartWorkoutAsync(bool isRecovering = false)
		{
			if (!isRecovering)
			{
				GetInitialValues(out var initialKph, out var initialIncline, out var initialResistance, out var initialGear);
				IWorkoutFacade obj = workoutFacade;
				double initialKph2 = initialKph;
				double initialIncline2 = initialIncline;
				double initialResistance2 = initialResistance;
				int initialGear2 = initialGear;
				IFitnessConsole console = base.Console;
				await obj.StartWorkoutAsync(initialKph2, initialIncline2, initialResistance2, initialGear2, console != null && console.LatestBasicInfo?.CurrentState == ConsoleState.Workout);
			}
			if (base.HasStartedWarmUp)
			{
				DisableUserOverrides(resetValues: false);
			}
			SetUpLiveWorkoutCaptionTimeUpdateSubscribers();
		}

		protected override void SetupAdapterForWorkout()
		{
			base.HasStartedWorkout = true;
			base.ControlAdapter = null;
			SetupStateSubscriber();
			(from x in base.Decorators?.OfType<UserOverrideDecorator>()
				where x != null
				select x).ForEach(delegate(UserOverrideDecorator x)
			{
				x.PropertyChanged -= base.HandleOverrideDecoratorChanged;
				x.PropertyChanged += base.HandleOverrideDecoratorChanged;
			});
			controlValueChangedOnConsoleSub?.Dispose();
			controlValueChangedOnConsoleSub = base.Console?.WhenControlValueChangedOnConsole?.SubscribeWithErrorLogging(HandleControlValueChangedOnConsole);
		}

		private void SetupStateSubscriber()
		{
			IConsoleStateFacade consoleStateFacade = Mvx.Resolve<IConsoleStateFacade>();
			stateSubscriber = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging((from _ in consoleStateFacade.ObserveConsoleStateChanges()
				where _.Current == ConsoleState.CoolDown
				select 0.0 / 0.0).Take(1), async delegate
			{
				EndCompetition(workoutComplete: true);
				await StartCoolDownSafely().ConfigureAwait(continueOnCapturedContext: false);
			});
		}

		private void SetUpLiveWorkoutCaptionStateUpdateSubscribers()
		{
			captionStateSub?.Dispose();
			captionStateSub = liveWorkoutTranslatorService?.WhenCaptionWorkoutStateUpdated?.SubscribeWithErrorLogging(delegate(LiveWorkoutState x)
			{
				_whenLiveWorkoutModeChanged?.OnNext(x);
			});
		}

		protected override void SetUpLiveWorkoutCaptionTimeUpdateSubscribers()
		{
			captionTimeSub?.Dispose();
			captionTimeSub = liveWorkoutTranslatorService?.WhenCaptionWorkoutTimeUpdated.Subscribe(delegate(LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate update)
			{
				if (base.IsRunning && !double.IsNaN(WorkoutElapsedSeconds) && update.CurrentTime > update.PreviousTime)
				{
					base.CompetitionService?.AddMomentWithInfo((int)update.CurrentTime, base.Decorators);
					_whenLiveWorkoutTimeUpdated?.OnNext(update);
				}
				else
				{
					iFit.Logger.Log.Warn("Workout", $"Moment Current {update.CurrentTime} is less or equal to Previous {update.PreviousTime}");
				}
			});
		}

		protected override async Task StartCoolDownAsync()
		{
			IFitnessConsole console = base.Console;
			if (console == null || console.LatestBasicInfo?.CurrentState != ConsoleState.CoolDown)
			{
				GetInitialValues(out var initialKph, out var initialIncline, out var initialResistance, out var initialGear);
				await workoutFacade.StartCoolDownAsync(initialKph, initialIncline, initialResistance, initialGear);
			}
		}

		protected override void SetUpAdapterForCoolDown()
		{
			base.SetUpAdapterForCoolDown();
			DisableUserOverrides(resetValues: false);
			(from x in base.Decorators?.OfType<UserOverrideDecorator>()
				where x != null
				select x).ForEach(delegate(UserOverrideDecorator x)
			{
				x.PropertyChanged -= base.HandleOverrideDecoratorChanged;
			});
		}

		private void GetInitialValues(out double initialKph, out double initialIncline, out double initialResistance, out int initialGear)
		{
			ConsoleControlValues consoleControlValues = liveWorkoutTranslatorService?.LastValuesSentToConsole;
			initialKph = consoleControlValues?.Kph ?? defaultKph;
			initialIncline = (consoleControlValues?.Incline).GetValueOrDefault();
			initialResistance = consoleControlValues?.Resistance ?? 1.0;
			initialGear = consoleControlValues?.Gear ?? 1;
		}

		protected override void AddApplicableDecorators(Workout workout, IFitnessConsole console)
		{
			if (console != null && console.ConsoleInfo?.CanSetKph == true)
			{
				base.Decorators.Add(new UserOverrideSpeedDecorator());
			}
			if (console != null && console.ConsoleInfo?.CanSetIncline == true)
			{
				base.Decorators.Add(new UserOverrideInclineDecorator());
			}
			if (console != null && console.ConsoleInfo?.CanSetGear == true)
			{
				base.Decorators.Add(new UserOverrideGearDecorator());
			}
			else if (console != null && console.ConsoleInfo?.CanSetResistance == true)
			{
				base.Decorators.Add(new UserOverrideResistanceDecorator());
			}
		}

		public override void DisableUserOverrides(bool resetValues)
		{
			base.DisableUserOverrides(resetValues: false);
			if (resetValues)
			{
				liveWorkoutTranslatorService?.ClearLastCaptionsSent();
			}
		}

		public virtual void WorkoutStartedAfterWarmUp()
		{
			base.HasStartedWarmUp = false;
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			controlValueChangedOnConsoleSub?.Dispose();
			controlValueChangedOnConsoleSub = null;
			captionStateSub?.Dispose();
			captionStateSub = null;
			captionTimeSub?.Dispose();
			captionTimeSub = null;
		}
	}
