		IObservable<LiveWorkoutState> WhenCaptionWorkoutStateUpdated { get; }

		IObservable<LiveWorkoutTranslatorService.LiveWorkoutTimeUpdate> WhenCaptionWorkoutTimeUpdated { get; }

		void ApplyControlStringToConsole(string controlStr, IWorkoutRunner runner);

		void ClearLastCaptionsSent();

