	public class LiveWorkoutTranslatorService : ILiveWorkoutTranslatorService
	{
		public class LiveWorkoutTranslatorServiceCoolDownStateException : Exception
		{
			public LiveWorkoutTranslatorServiceCoolDownStateException()
				: base("It appears the user tried to join a live workout that was already in cool down")
			{
			}
		}

		public class LiveWorkoutTimeUpdate
		{
			public double PreviousTime { get; set; }

			public double CurrentTime { get; set; }
		}

		private const double ComparisonEpsilon = 1E-08;

		private const double SafeTreadmillKph = 2.0;

		private readonly ICaptionParser captionParser;

		private readonly IConsoleControlValuesFacade consoleControlValuesFacade;

		private bool hasTransitionedToCoolDown;

		private int captionsAppliedCount;

		private double lastTimeSentToRunner;

		private IDisposable safeWorkoutStartSub;

		private readonly Subject<LiveWorkoutState> _whenCaptionWorkoutStateUpdated = new Subject<LiveWorkoutState>();

		private readonly Subject<LiveWorkoutTimeUpdate> _whenCaptionTimeUpdated = new Subject<LiveWorkoutTimeUpdate>();

		public ConsoleControlValues LastValuesSentToConsole { get; private set; }

		public IObservable<LiveWorkoutState> WhenCaptionWorkoutStateUpdated => _whenCaptionWorkoutStateUpdated;

		public IObservable<LiveWorkoutTimeUpdate> WhenCaptionWorkoutTimeUpdated => _whenCaptionTimeUpdated;

		public LiveWorkoutTranslatorService(ICaptionParser captionParser, IConsoleControlValuesFacade consoleControlValuesFacade)
		{
			this.captionParser = captionParser;
			this.consoleControlValuesFacade = consoleControlValuesFacade;
			LastValuesSentToConsole = new ConsoleControlValues();
		}

		public void ApplyControlStringToConsole(string controlStr, IWorkoutRunner runner)
		{
			if (string.IsNullOrEmpty(controlStr))
			{
				iFit.Logger.Log.Error("Workout", "Can't apply null or empty control string to a console");
				return;
			}
			if (runner == null)
			{
				iFit.Logger.Log.Error("Workout", "ApplyControlStringToConsole has null WorkoutRunner");
				return;
			}
			if (runner.Console == null)
			{
				iFit.Logger.Log.Error("Workout", "ApplyControlStringToConsole has null console");
				return;
			}
			string[] source = controlStr.Split(new string[1] { "\n" }, StringSplitOptions.RemoveEmptyEntries);
			LiveWorkoutControlValues workoutControlValues;
			try
			{
				workoutControlValues = captionParser.GetWorkoutControlValues(source.Last());
			}
			catch (ArgumentException ex)
			{
				iFit.Logger.Log.Error("Workout", "Not applying workout controls: " + ex.Message, ex);
				throw;
			}
			if (workoutControlValues == null)
			{
				iFit.Logger.Log.Error("Workout", "Not applying workout controls: Control values is null");
				return;
			}
			if (workoutControlValues.WorkoutState == LiveWorkoutState.InWorkout)
			{
				if (captionsAppliedCount == 0)
				{
					IFitnessConsole console = runner.Console;
					if (console != null && console.ConsoleInfo?.CanSetKph == true)
					{
						if (runner is ILiveWorkoutRunner liveWorkoutRunner)
						{
							liveWorkoutRunner.WorkoutStartedAfterWarmUp();
						}
						GoToDefaultSafeSpeed(runner);
						goto IL_011c;
					}
				}
				UpdateControls(runner, workoutControlValues);
			}
			goto IL_011c;
			IL_011c:
			_whenCaptionWorkoutStateUpdated?.OnNext(workoutControlValues.WorkoutState);
			switch (workoutControlValues.WorkoutState)
			{
			case LiveWorkoutState.Warmup:
				TransitionToWarmUp(runner);
				break;
			case LiveWorkoutState.InWorkout:
				TransitionToInWorkout(runner, workoutControlValues.CurrentSeconds);
				break;
			case LiveWorkoutState.Cooldown:
				TransitionToCoolDown(runner);
				break;
			}
			captionsAppliedCount++;
		}

		private void GoToDefaultSafeSpeed(IWorkoutRunner runner)
		{
			iFit.Logger.Log.Trace("Workout", "GoToDefaultSafeSpeed");
			runner?.EnableUserOverrides();
			IWorkoutRunner workoutRunner = runner;
			if (workoutRunner != null && workoutRunner.Console?.LatestBasicInfo?.CurrentState == ConsoleState.Workout)
			{
				reallyGoToDefaultSafeSpeed();
				return;
			}
			safeWorkoutStartSub = runner?.Console?.WhenStateChanged.Where((StateChange x) => x.Current == ConsoleState.Workout).Subscribe(delegate
			{
				reallyGoToDefaultSafeSpeed();
				safeWorkoutStartSub?.Dispose();
				safeWorkoutStartSub = null;
			});
			void reallyGoToDefaultSafeSpeed()
			{
				if (runner?.Console != null)
				{
					double value = (runner.IsMetric ? 2.0 : UnitUtil.EnsureKph(SpeedUnit.Mph, 1.0, 1));
					ConsoleControlValues controlValues = new ConsoleControlValues
					{
						Kph = value,
						Incline = 0.0
					};
					consoleControlValuesFacade.SetControlValues(controlValues);
					runner.EnableUserOverrides(forceNotifications: true);
				}
			}
		}

		private void UpdateControls(IWorkoutRunner runner, LiveWorkoutControlValues controlValues)
		{
			iFit.Logger.Log.Trace("Workout", "Updating controls from captions: " + captionsAppliedCount);
			IConsoleInfo consoleInfo = runner.Console.ConsoleInfo;
			if (consoleInfo == null)
			{
				iFit.Logger.Log.Error("Workout", "ApplyControlStringToConsole doesn't have ConsoleInfo");
				return;
			}
			ConsoleSpecs sourceConsole = runner.RunContext?.ScheduleInfo?.SourceConsole;
			IConsoleBasicInfo latestBasicInfo = runner.Console.LatestBasicInfo;
			double? setSpeed = null;
			double? setIncline = null;
			double? setResistance = null;
			int? setGear = null;
			bool flag = false;
			bool flag2 = runner.Decorators.Where((IControlDecorator x) => x is UserOverrideSpeedDecorator && x.Enabled).Any();
			bool flag3 = runner.Decorators.Where((IControlDecorator x) => x is UserOverrideInclineDecorator && x.Enabled).Any();
			if (!flag2 && consoleInfo.CanSetKph)
			{
				flag |= UpdateSpeed(controlValues.SpeedMph, latestBasicInfo.Kph, out setSpeed);
			}
			if (!flag3 && consoleInfo.CanSetIncline)
			{
				flag |= UpdateIncline(consoleInfo, controlValues.Incline, latestBasicInfo.Grade, out setIncline);
			}
			if (consoleInfo.CanSetGear)
			{
				flag |= UpdateGear(sourceConsole, consoleInfo, controlValues.Resistance, latestBasicInfo.Gear?.CurrentGear, out setGear);
			}
			else if (consoleInfo.CanSetResistance)
			{
				flag |= UpdateResistance(sourceConsole, consoleInfo, controlValues.Resistance, latestBasicInfo.Resistance, out setResistance);
			}
			if (flag)
			{
				SendControlsToConsole(setSpeed, setIncline, setGear, setResistance, runner);
			}
		}

		private bool UpdateSpeed(float captionSpeedMph, double latestKph, out double? setSpeed)
		{
			setSpeed = null;
			double num = UnitUtil.EnsureKph(SpeedUnit.Mph, captionSpeedMph, 1);
			if (!LastValuesSentToConsole.Kph.HasValue || (LastValuesSentToConsole.Kph.Value.AlmostEqual(latestKph, 1) && !latestKph.AlmostEqual(num, 1)))
			{
				setSpeed = num;
				return true;
			}
			return false;
		}

		private bool UpdateIncline(IConsoleInfo consoleInfo, float captionIncline, double latestGrade, out double? setIncline)
		{
			setIncline = null;
			double num = MathUtils.Clamp(captionIncline, consoleInfo.MinIncline, consoleInfo.MaxIncline);
			num = Math.Round(num * 2.0, MidpointRounding.AwayFromZero) / 2.0;
			if (!LastValuesSentToConsole.Incline.HasValue || (LastValuesSentToConsole.Incline.Value.AlmostEqual(latestGrade, 1) && !latestGrade.AlmostEqual(num, 1)))
			{
				setIncline = num;
				return true;
			}
			return false;
		}

		private bool UpdateResistance(ConsoleSpecs sourceConsole, IConsoleInfo consoleInfo, float captionResistance, double latestResistance, out double? setResistance)
		{
			setResistance = null;
			double num = Math.Ceiling(ScaleResistance(sourceConsole?.Limits?.MaxResistance ?? consoleInfo.MaxResistanceLevel, consoleInfo.MaxResistanceLevel, captionResistance));
			if (!LastValuesSentToConsole.Resistance.HasValue || (LastValuesSentToConsole.Resistance.Value.AlmostEqual(latestResistance, 1) && !latestResistance.AlmostEqual(num, 1)))
			{
				setResistance = num;
				return true;
			}
			return false;
		}

		private bool UpdateGear(ConsoleSpecs sourceConsole, IConsoleInfo consoleInfo, float captionResistance, int? latestGear, out int? setGear)
		{
			setGear = null;
			int num = ResistanceToGear(sourceConsole?.Limits?.MaxResistance ?? 26.0, consoleInfo.MaxGear, captionResistance);
			if (!LastValuesSentToConsole.Gear.HasValue || (LastValuesSentToConsole.Gear.Value == latestGear && num != latestGear))
			{
				setGear = num;
				return true;
			}
			return false;
		}

		public void ClearLastCaptionsSent()
		{
			LastValuesSentToConsole = new ConsoleControlValues();
			lastTimeSentToRunner = -1.0;
		}

		public void Reset()
		{
			ClearLastCaptionsSent();
			hasTransitionedToCoolDown = false;
			captionsAppliedCount = 0;
			safeWorkoutStartSub?.Dispose();
			safeWorkoutStartSub = null;
		}

		private void SendControlsToConsole(double? setSpeed, double? setIncline, int? setGear, double? setResistance, IWorkoutRunner runner)
		{
			ConsoleControlValues consoleControlValues = new ConsoleControlValues();
			if (setSpeed.HasValue)
			{
				List<IControlDecorator> decorators = runner.Decorators;
				if (decorators == null || decorators.OfType<UserOverrideSpeedDecorator>()?.Any((UserOverrideSpeedDecorator x) => x.Enabled) != true)
				{
					consoleControlValues.Kph = setSpeed;
				}
			}
			if (setIncline.HasValue)
			{
				List<IControlDecorator> decorators2 = runner.Decorators;
				if (decorators2 == null || decorators2.OfType<UserOverrideInclineDecorator>()?.Any((UserOverrideInclineDecorator x) => x.Enabled) != true)
				{
					consoleControlValues.Incline = setIncline;
				}
			}
			if (setGear.HasValue)
			{
				List<IControlDecorator> decorators3 = runner.Decorators;
				if (decorators3 == null || decorators3.OfType<UserOverrideGearDecorator>()?.Any((UserOverrideGearDecorator x) => x.Enabled) != true)
				{
					consoleControlValues.Gear = setGear;
					goto IL_01dd;
				}
			}
			if (setResistance.HasValue)
			{
				List<IControlDecorator> decorators4 = runner.Decorators;
				if (decorators4 == null || decorators4.OfType<UserOverrideResistanceDecorator>()?.Any((UserOverrideResistanceDecorator x) => x.Enabled) != true)
				{
					consoleControlValues.Resistance = setResistance;
				}
			}
			goto IL_01dd;
			IL_01dd:
			consoleControlValuesFacade.SetControlValues(consoleControlValues);
			LastValuesSentToConsole.Kph = consoleControlValues.Kph ?? LastValuesSentToConsole.Kph;
			LastValuesSentToConsole.Incline = consoleControlValues.Incline ?? LastValuesSentToConsole.Incline;
			LastValuesSentToConsole.Gear = consoleControlValues.Gear ?? LastValuesSentToConsole.Gear;
			LastValuesSentToConsole.Resistance = consoleControlValues.Resistance ?? LastValuesSentToConsole.Resistance;
		}

		public double ScaleResistance(double sourceMax, double targetMax, double sourceValue)
		{
			double relativeResistance = ResistanceRelativeResistanceUtil.ResistanceToRelativeResistance(sourceValue, 0.0, sourceMax);
			return ResistanceRelativeResistanceUtil.RelativeResistanceToResistance(relativeResistance, 0.0, targetMax).RoundToNearest(1.0);
		}

		public int ResistanceToGear(double sourceMaxResistance, double targetMaxGear, double sourceValue)
		{
			double relativeResistance = ResistanceRelativeResistanceUtil.ResistanceToRelativeResistance(sourceValue, 0.0, sourceMaxResistance);
			return (int)ResistanceRelativeResistanceUtil.RelativeResistanceToResistance(relativeResistance, 0.0, targetMaxGear, round: true);
		}

		private void TransitionToWarmUp(IWorkoutRunner runner)
		{
			runner.WorkoutElapsedSeconds = 0.0 / 0.0;
			runner.WorkoutRunningSeconds = 0.0 / 0.0;
			hasTransitionedToCoolDown = false;
			if (!runner.HasStartedWarmUp)
			{
				iFit.Logger.Log.Trace("Workout", "Live: transitioning to warmup");
				try
				{
					runner.Start();
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Workout", "Live: exception during start workout from TransitionToWarmUp: {0}", exception);
				}
			}
		}

		private void TransitionToInWorkout(IWorkoutRunner runner, double currentSeconds)
		{
			runner.WorkoutElapsedSeconds = currentSeconds;
			runner.WorkoutRunningSeconds = currentSeconds;
			_whenCaptionTimeUpdated.OnNext(new LiveWorkoutTimeUpdate
			{
				PreviousTime = lastTimeSentToRunner,
				CurrentTime = currentSeconds
			});
			hasTransitionedToCoolDown = false;
			if (!runner.HasStartedWorkout)
			{
				iFit.Logger.Log.Trace("Workout", "Live: ending warmup/starting workout");
				runner.FinishWarmUp();
			}
			lastTimeSentToRunner = currentSeconds;
		}

		private void TransitionToCoolDown(IWorkoutRunner runner)
		{
			runner.WorkoutElapsedSeconds = 0.0 / 0.0;
			runner.WorkoutRunningSeconds = 0.0 / 0.0;
			if (!runner.HasStartedWorkout)
			{
				throw new LiveWorkoutTranslatorServiceCoolDownStateException();
			}
			if (!hasTransitionedToCoolDown)
			{
				hasTransitionedToCoolDown = true;
				iFit.Logger.Log.Trace("Workout", "Live: ending workout/starting cooldown");
				runner.FinishWorkout(completed: true);
			}
		}
	}
