	public abstract class PreDeterminedWorkoutRunner : BaseWorkoutRunner
	{
		protected IDisposable followWorkoutMetricChangedSub;

		protected IDisposable controlValueChangedOnConsoleSub;

		public IWorkoutFeatureService WorkoutFeatureService { get; set; }

		public PreDeterminedWorkoutRunner(IFitnessConsole console, bool isMetric, double userWeightKgs, Workout workout, WorkoutRunnerContext workoutContext, ICompetitionService competitionService, IHRTrainingService hrTrainingService, IWorkoutFeatureService workoutFeatureService, Workout warmUp = null, Workout coolDown = null, IObservable<bool> whenIsLoading = null, string wolfGeneratedId = null)
			: base(console, isMetric, userWeightKgs, workout, workoutContext, competitionService, warmUp, coolDown, whenIsLoading, wolfGeneratedId)
		{
			WorkoutFeatureService = workoutFeatureService;
		}

		public override async Task<bool> Start()
		{
			bool started = await base.Start();
			if (!base.RunContext.DisableCompetition)
			{
				await StartCompetition(recovered);
			}
			return started;
		}

		protected override async Task StartWarmUpAsync()
		{
			IFitnessConsole console = base.Console;
			if (console == null || console.LatestBasicInfo?.CurrentState != ConsoleState.WarmUp)
			{
				GetFirstValues(base.WarmUp, base.IsMetric, out var firstKph, out var firstIncline, out var firstResistance, out var firstGear);
				iFit.Logger.Log.Trace("Workout", (await workoutFacade.StartWarmUpAsync(firstKph, firstIncline, firstResistance, firstGear)) ? "Warm up started successfully" : "Failed to start warm up");
			}
		}

		protected override async Task StartWorkoutAsync(bool isRecovering = false)
		{
			if (!isRecovering)
			{
				GetFirstValues(base.Workout, base.IsMetric, out var firstKph, out var firstIncline, out var firstResistance, out var firstGear);
				double valueOrDefault = (base.Console?.LatestBasicInfo?.Kph).GetValueOrDefault();
				double initialKph = ((base.Workout?.HasControlsFor(Workout.Control.ControlType.Mps) ?? false) ? firstKph : valueOrDefault);
				double initialIncline = ((base.Workout?.HasControlsFor(Workout.Control.ControlType.Incline) ?? false) ? firstIncline : (base.Console?.LatestBasicInfo?.Grade).GetValueOrDefault());
				double initialResistance = ((base.Workout?.HasControlsFor(Workout.Control.ControlType.Resistance) ?? false) ? firstResistance : (base.Console?.LatestBasicInfo?.Resistance ?? 1.0));
				int initialGear = ((base.Workout?.HasControlsFor(Workout.Control.ControlType.Gear) ?? false) ? firstGear : (base.Console?.LatestBasicInfo?.Gear?.CurrentGear ?? 1));
				IWorkoutFacade obj = workoutFacade;
				IFitnessConsole console = base.Console;
				await obj.StartWorkoutAsync(initialKph, initialIncline, initialResistance, initialGear, console != null && console.LatestBasicInfo?.CurrentState == ConsoleState.Workout);
				DisableUserOverrides(resetValues: false);
			}
			StartHRTrainingService();
			SetUpLiveWorkoutCaptionTimeUpdateSubscribers();
		}

		protected override void SetupAdapterForWorkout()
		{
			base.HasStartedWorkout = true;
			base.ControlAdapter = GetControlAdapter();
			SetupStateSubscriber();
			(from x in base.Decorators?.OfType<UserOverrideDecorator>()
				where x != null
				select x).ForEach(delegate(UserOverrideDecorator x)
			{
				x.PropertyChanged -= base.HandleOverrideDecoratorChanged;
				x.PropertyChanged += base.HandleOverrideDecoratorChanged;
			});
			controlValueChangedOnConsoleSub?.Dispose();
			controlValueChangedOnConsoleSub = base.Console?.WhenControlValueChangedOnConsole?.SubscribeWithErrorLogging(HandleControlValueChangedOnConsole);
		}

		protected abstract IControlAdapter GetControlAdapter();

		protected abstract void SetupStateSubscriber();

		protected override async Task StartCoolDownAsync()
		{
			IFitnessConsole console = base.Console;
			if (console == null || console.LatestBasicInfo?.CurrentState != ConsoleState.CoolDown)
			{
				GetFirstValues(base.CoolDown, base.IsMetric, out var firstKph, out var firstIncline, out var firstResistance, out var firstGear);
				await workoutFacade.StartCoolDownAsync(firstKph, firstIncline, firstResistance, firstGear);
			}
		}

		protected override void SetUpAdapterForCoolDown()
		{
			base.SetUpAdapterForCoolDown();
			DisableUserOverrides(resetValues: false);
			(from x in base.Decorators?.OfType<UserOverrideDecorator>()
				where x != null
				select x).ForEach(delegate(UserOverrideDecorator x)
			{
				x.PropertyChanged -= base.HandleOverrideDecoratorChanged;
			});
		}

		public static void GetFirstValues(Workout workout, bool isMetric, out double firstKph, out double firstIncline, out double firstResistance, out int firstGear)
		{
			double num = (isMetric ? 2.0 : UnitUtil.EnsureKph(SpeedUnit.Mph, 1.0, 1));
			Workout.Control control = workout?.Controls?.LastOrDefault((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps && x.At.AlmostEqual(0.0));
			Workout.Control control2 = workout?.Controls?.LastOrDefault((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline && x.At.AlmostEqual(0.0));
			Workout.Control control3 = workout?.Controls?.LastOrDefault((Workout.Control x) => x.Type == Workout.Control.ControlType.Resistance && x.At.AlmostEqual(0.0));
			Workout.Control control4 = workout?.Controls?.LastOrDefault((Workout.Control x) => x.Type == Workout.Control.ControlType.Gear && x.At.AlmostEqual(0.0));
			if (control != null)
			{
				control.HasBeenSent = true;
			}
			if (control2 != null)
			{
				control2.HasBeenSent = true;
			}
			if (control3 != null)
			{
				control3.HasBeenSent = true;
			}
			if (control4 != null)
			{
				control4.HasBeenSent = true;
			}
			firstKph = ((control == null) ? num : UnitUtil.EnsureKph(SpeedUnit.Mps, control.Value, 1));
			firstIncline = control2?.Value ?? 0.0;
			firstResistance = control3?.Value ?? 1.0;
			firstGear = (int)(control4?.Value ?? 1.0);
		}

		protected override void CleanUp()
		{
			base.CleanUp();
			followWorkoutMetricChangedSub?.Dispose();
			followWorkoutMetricChangedSub = null;
			controlValueChangedOnConsoleSub?.Dispose();
			controlValueChangedOnConsoleSub = null;
			StopHRTrainingService();
		}
	}
