		private double savedMpsSpeedGovernorNextLevel;

		private Workout.Control.ControlType dominantControlToScale;

		protected double userMaxMps = 1.7976931348623157E+308;

		protected double previousMps;

		private const int BaseScaleLevel = 0;

		private readonly Subject<Workout.Control.ControlType> _scaleChangedForControlType = new Subject<Workout.Control.ControlType>();

		private readonly Subject<double> _userMaxMpsChanged = new Subject<double>();

		private readonly Subject<(FitnessValue metric, string msg)> _debugScaleLevels = new Subject<(FitnessValue, string)>();

		private bool canSetMaxSpeedGovernor;

		private bool enableMaxSpeedGovernor;

		private SpeedUnit CurrentSpeedUnit
		{
			get
			{
				if (!isMetric)
				{
					return SpeedUnit.Mph;
				}
				return SpeedUnit.Kph;
			}
		}

		public IObservable<Workout.Control.ControlType> ScaleChangedForControlType => _scaleChangedForControlType;

		public IObservable<double> UserMaxMpsChanged => _userMaxMpsChanged;

		public IObservable<(FitnessValue metric, string msg)> DebugScaleLevels => _debugScaleLevels;

		public bool EnableScalingDebug { get; set; }

		public int MaxScaleLevelAllowed => CurrentMaxDominantScaleLevel();

		public bool EnableMaxSpeedGovernor
		{
			get
			{
				return enableMaxSpeedGovernor;
			}
			set
			{
				if (value != enableMaxSpeedGovernor && canSetMaxSpeedGovernor)
				{
					enableMaxSpeedGovernor = value;
					EnableMaxSpeedGovernorSettings(enableMaxSpeedGovernor);
				}
			}
		}

		public int CurrentScale => (scaleControlsInfo?.Values.First()?.Scale).GetValueOrDefault();

		public ScalingControlAdapter(List<Workout.Control> controls, IFitnessConsole console, List<IControlDecorator> decorators, bool useStartingLevel, bool isMetric, IObservable<bool> whenIsLoadingChanged = null, Workout.ScaledWorkoutDetails scaledWorkoutDetails = null)
			: base(controls, console, decorators, whenIsLoadingChanged)
		{
			this.console = console;
			this.decorators = decorators;
			this.isMetric = isMetric;
			kphFacade = Mvx.Resolve<IKphFacade>();
			Mvx.TryResolve<IInAppNotificationService>(out inAppNotificationService);
			Mvx.TryResolve<IIfitApiService>(out ifitApi);
			canSetMaxSpeedGovernor = console.ConsoleInfo.CanSetKph;
			if (canSetMaxSpeedGovernor)
			{
				enableMaxSpeedGovernor = true;
			}
			hasScaledControls = scaledWorkoutDetails != null;
			InitializeCanSet(controls);
			InitializeControlsTracking(controls, scaledWorkoutDetails);
			InitializeScaleControlInfo(scaledWorkoutDetails, useStartingLevel);
			InitializeDominantControlToScale();
			isLoadingSub?.Dispose();
			isLoadingSub = whenIsLoadingChanged?.SubscribeWithErrorLogging(delegate(bool loading)
			{
				videoIsLoading = loading;
			});
			speedSub?.Dispose();
			if (console != null && console.ConsoleInfo.MachineType.IsBeltBasedMachine())
			{
				speedSub = kphFacade.ObserveKphChanges().Subscribe(SpeedChanged);
			}
			if (inAppNotificationService != null)
			{
				inAppNotificationsSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(inAppNotificationService.NotificationChanges, InAppNotification);
			}
			iFit.Logger.Log.Info("ScalingControl", $"Constructor: useStartingLevel={useStartingLevel} StartingLevel={scaledWorkoutDetails?.StartingLevel} CurrentSpeedUnit={CurrentSpeedUnit} HasScaledControls={hasScaledControls}");
			DebugDump("Constructor");
			SetupTargetSubscriber(Workout.TargetType.Seconds);
		}

		private void InitializeCanSet(List<Workout.Control> controls)
		{
			iFit.Logger.Log.Info("ScalingControl", $"CanSet: Kph={console.ConsoleInfo.CanSetKph} Gear={console.ConsoleInfo.CanSetGear} Resistance={console.ConsoleInfo.CanSetResistance} Incline={console.ConsoleInfo.CanSetIncline}");
			if ((console.ConsoleInfo.CanSetKph || console.FitnessValueSupported(FitnessValue.Kph)) && controls.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps))
			{
				canSetControlTypes.Add(Workout.Control.ControlType.Mps);
			}
			if (console.ConsoleInfo.CanSetGear && controls.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.Gear))
			{
				canSetControlTypes.Add(Workout.Control.ControlType.Gear);
			}
			if (console.ConsoleInfo.CanSetResistance && !console.ConsoleInfo.CanSetGear)
			{
				if (controls.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.Resistance))
				{
					canSetControlTypes.Add(Workout.Control.ControlType.Resistance);
				}
				else if (controls.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.RelativeResistance))
				{
					canSetControlTypes.Add(Workout.Control.ControlType.RelativeResistance);
				}
			}
			if (console.ConsoleInfo.CanSetIncline && controls.Any((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline))
			{
				canSetControlTypes.Add(Workout.Control.ControlType.Incline);
			}
		}

		private void InitializeControlsTracking(List<Workout.Control> allWorkoutControls, Workout.ScaledWorkoutDetails scaledWorkoutDetails)
		{
			if (hasScaledControls)
			{
				minScaleLevel = scaledWorkoutDetails.MinScaleLevel;
				maxScaleLevel = scaledWorkoutDetails.MaxScaleLevel;
				foreach (Workout.Control.ControlType controlType in from x in scaledWorkoutDetails.ScaledControls[0].DistinctBy((Workout.Control arg) => arg.Type)
					select x.Type)
				{
					if (canSetControlTypes.All((Workout.Control.ControlType x) => x != controlType))
					{
						continue;
					}
					iFit.Logger.Log.Info("ScalingControl", $"InitializeControlsTracking: {controlType}");
					for (int num = minScaleLevel; num <= maxScaleLevel; num++)
					{
						string key = KeyForControlTracking(controlType, num);
						List<Workout.Control> list = (from x in scaledWorkoutDetails.ScaledControls[num]
							where x.Type == controlType
							orderby x.At
							select x).DistinctBy((Workout.Control x) => x.At).ToList();
						controlsTracking.Add(key, new ControlsTracking(list));
					}
				}
				Task.Run(async delegate
				{
					await RecalculateGovernorMaxAllowedScale();
					DebugDump("InitializeControlsTracking");
				});
				return;
			}
			foreach (Workout.Control.ControlType controlType2 in from x in allWorkoutControls.DistinctBy((Workout.Control arg) => arg.Type)
				select x.Type)
			{
				string key2 = KeyForControlTracking(controlType2, 0);
				List<Workout.Control> list2 = (from x in allWorkoutControls
					where x.Type == controlType2
					orderby x.At
					select x).DistinctBy((Workout.Control x) => x.At).ToList();
				controlsTracking.Add(key2, new ControlsTracking(list2));
			}
		}

		private void InitializeControlsTrackingForTargetMetrics(Workout.ScaledWorkoutDetails scaledWorkoutDetails)
		{
			List<Workout.Control.ControlType> controlTypesForTargetMetrics = new List<Workout.Control.ControlType>
			{
				Workout.Control.ControlType.Mps,
				Workout.Control.ControlType.Rpm
			};
			Dictionary<int, List<Workout.Control>> dictionary = scaledWorkoutDetails?.ScaledControls;
			if (dictionary == null || dictionary.IsEmpty())
			{
				return;
			}
			(from control in dictionary?[0].DistinctBy((Workout.Control control) => control.Type)
				select control.Type).ForEach(delegate(Workout.Control.ControlType controlType)
			{
				if (controlTypesForTargetMetrics.Contains(controlType))
				{
					for (int i = minScaleLevel; i <= maxScaleLevel; i++)
					{
						string key = KeyForControlTracking(controlType, i);
						List<Workout.Control> list = (from control in scaledWorkoutDetails.ScaledControls[i]
							where control.Type == controlType
							orderby control.At
							select control).DistinctBy((Workout.Control control) => control.At).ToList();
						controlsTrackingForTargetMetrics.Add(key, new ControlsTracking(list));
					}
				}
			});
		}

		private void InitializeDominantControlToScale()
		{
			if (canSetControlTypes.Contains(Workout.Control.ControlType.Mps))
			{
				dominantControlToScale = Workout.Control.ControlType.Mps;
			}
			else if (canSetControlTypes.Contains(Workout.Control.ControlType.Gear))
			{
				dominantControlToScale = Workout.Control.ControlType.Gear;
			}
			else if (canSetControlTypes.Contains(Workout.Control.ControlType.Resistance))
			{
				dominantControlToScale = Workout.Control.ControlType.Resistance;
			}
			else if (canSetControlTypes.Contains(Workout.Control.ControlType.Incline))
			{
				dominantControlToScale = Workout.Control.ControlType.Incline;
			}
			else
			{
				dominantControlToScale = canSetControlTypes.FirstOrDefault();
			}
		}

		private async Task RecalculateGovernorMaxAllowedScale()
		{
			if (ifitApi != null && ifitApi.CurrentlyAuthenticatedUser != null)
			{
				WorkoutScalingSettings workoutScalingSettings = await (await User.GetMe(ifitApi).ConfigureAwait(continueOnCapturedContext: false)).GetWorkoutScalingSettings(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
				if (workoutScalingSettings != null)
				{
					userMaxMps = workoutScalingSettings.MaxTreadmillMPS;
					iFit.Logger.Log.Info("ScalingControl", "RecalculateGovernorMaxAllowedScale: userMaxMps=" + DebugMpsToCurrent(userMaxMps));
					CapControlsTracking capControlsTracking = new CapControlsTracking(controlsTracking, canSetControlTypes, userMaxMps, minScaleLevel, maxScaleLevel);
					capControlsTracking.Run();
					_userMaxMpsChanged.OnNext(userMaxMps);
				}
			}
		}

		private void EnableMaxSpeedGovernorSettings(bool enable)
		{
			iFit.Logger.Log.Info("ScalingControl", string.Format("{0}: enable={1} userMaxMps={2}", "EnableMaxSpeedGovernorSettings", enable, DebugMpsToCurrent(userMaxMps)));
			double num = (enable ? userMaxMps : 100.0);
			CapControlsTracking capControlsTracking = new CapControlsTracking(controlsTracking, canSetControlTypes, num, minScaleLevel, maxScaleLevel);
			capControlsTracking.Run();
		}

		private void SpeedChanged(FitnessValueChange<double> obj)
		{
			double value = UnitUtil.EnsureMps(SpeedUnit.Kph, obj.Current);
			if (IsBeyondMaxGovernorSpeed(obj.Current))
			{
				savedMpsUserMaxSpeedTo = value;
				iFit.Logger.Log.Info("ScalingControl", "SpeedChanged: User exceeding max speed. userMaxMps=" + DebugMpsToCurrent(userMaxMps) + ", user requested=" + DebugMpsToCurrent(value));
				string value2 = (isMetric ? $"{UnitUtil.EnsureKph(SpeedUnit.Mps, userMaxMps, 1)} KPH" : $"{UnitUtil.EnsureMph(SpeedUnit.Mps, userMaxMps, 1)} MPH");
				inAppNotificationService?.Post(new CoachingMessageNotificationData(HowlSmartAdjustType.MaxSpeedUserOverride, new Dictionary<string, string> { { "maxspeed", value2 } }));
			}
			previousMps = value;
		}

		protected bool IsBeyondMaxGovernorSpeed(double kph)
		{
			if (userMaxMps >= 1.7976931348623157E+308 || !enableMaxSpeedGovernor)
			{
				return false;
			}
			Workout.Control control = controlsTracking[KeyForControlTracking(Workout.Control.ControlType.Mps)].FindControlNearestToTime(latestTargetValue);
			ApplyDecorators(control);
			if (control.OverriddenByUser)
			{
				return false;
			}
			double num = UnitUtil.EnsureMps(SpeedUnit.Kph, kph, 2);
			double num2 = UnitUtil.EnsureMps(SpeedUnit.Mps, userMaxMps, 2);
			double a = UnitUtil.EnsureMps(SpeedUnit.Mps, previousMps, 2);
			if (num > num2)
			{
				return !a.AlmostEqual(num);
			}
			return false;
		}

		private void InitializeScaleControlInfo(Workout.ScaledWorkoutDetails scaledWorkoutDetails, bool useStartingLevel)
		{
			int scale = 0;
			if (hasScaledControls && useStartingLevel)
			{
				scale = scaledWorkoutDetails.StartingLevel;
			}
			foreach (Workout.Control.ControlType canSetControlType in canSetControlTypes)
			{
				scaleControlsInfo.Add(canSetControlType, new ScaleControlInfo
				{
					ControlType = canSetControlType,
					Scale = scale,
					Pending = new PendingScaleValue()
				});
			}
			SaveWorkoutScales();
		}

		public void SetWorkoutScale(Workout.Control.ControlType controlType, int scale, bool pending)
		{
			if (!scaleControlsInfo.ContainsKey(controlType))
			{
				throw new Exception($"Control Adapter does not have controlType: {controlType}");
			}
			iFit.Logger.Log.Info("ScalingControl", string.Format("{0} Setting new scale level:  controlType={1} scale={2} pending={3}", "SetWorkoutScale", controlType, scale, pending));
			if (pending)
			{
				scaleControlsInfo[controlType].Pending.Scale = scale;
				_scaleChangedForControlType.OnNext(controlType);
			}
			else
			{
				scaleControlsInfo[controlType].Scale = scale;
			}
		}

		public void SetWorkoutScale(int scale)
		{
			iFit.Logger.Log.Info("ScalingControl", string.Format("{0} Setting new scale level for ALL: scale={1}", "SetWorkoutScale", scale));
			foreach (Workout.Control.ControlType key in scaleControlsInfo.Keys)
			{
				scaleControlsInfo[key].Scale = scale;
				scaleControlsInfo[key].Pending.Scale = scale;
				_scaleChangedForControlType.OnNext(key);
			}
			ResetToLatest();
		}

		public void SaveWorkoutScales()
		{
			foreach (ScaleControlInfo value in scaleControlsInfo.Values)
			{
				value.Save();
			}
		}

		public void RestoreWorkoutScales()
		{
			foreach (ScaleControlInfo value in scaleControlsInfo.Values)
			{
				value.Restore();
				_scaleChangedForControlType.OnNext(value.ControlType);
			}
			ResetToLatest();
		}

		public int ScaleForControlType(Workout.Control.ControlType controlType)
		{
			if (!scaleControlsInfo.ContainsKey(controlType))
			{
				throw new Exception($"Control Adapter does not have controlType: {controlType}");
			}
			if (!scaleControlsInfo.TryGetValue(controlType, out var value))
			{
				return 0;
			}
			if (!value.Pending.HasPending)
			{
				return value.Scale;
			}
			return value.Pending.Scale;
		}

		public Dictionary<int, double> ScaleValuesForControlType(Workout.Control.ControlType controlType)
		{
			Dictionary<int, double> dictionary = new Dictionary<int, double>();
			for (int i = minScaleLevel; i <= maxScaleLevel; i++)
			{
				string key = KeyForControlTracking(controlType, i);
				if (controlsTracking.ContainsKey(key))
				{
					dictionary.Add(i, controlsTracking[key].FindControlNearestToTime(latestTargetValue).Value);
				}
			}
			return dictionary;
		}

		public override void Dispose()
		{
			base.Dispose();
			speedSub?.Dispose();
			speedSub = null;
			isLoadingSub?.Dispose();
			isLoadingSub = null;
			inAppNotificationsSub?.Dispose();
			inAppNotificationsSub = null;
			canSetMaxSpeedGovernor = false;
		}

		public override void ResetToLatest(IEnumerable<Workout.Control.ControlType> excludeTypes = null)
		{
			foreach (ControlsTracking value in controlsTracking.Values)
			{
				value.OverriddenByUser(overriddenByUser: false);
			}
			UpdatePendingScaleControls(latestTargetValue, forceOverride: true);
			UpdateControls(latestTargetValue, excludeTypes, ignoreSentValues: false);
		}

		public void ChangeWorkoutScaleBy(int changeLevelsBy, bool suppressNotifications = false)
		{
			if (changeLevelsBy == 0)
			{
				return;
			}
			iFit.Logger.Log.Info("ScalingControl", string.Format("{0} Changing scaling by: changeLevelsBy={1} suppressNotifications={2}", "ChangeWorkoutScaleBy", changeLevelsBy, suppressNotifications));
			UpdatePendingScaleControls(0.0, forceOverride: true);
			if (!hasScaledControls)
			{
				return;
			}
			if (changeLevelsBy < 0)
			{
				changeLevelsBy += NumCappedScaleLevelsFromCurrent() * -1;
			}
			foreach (ScaleControlInfo value in scaleControlsInfo.Values)
			{
				value.Scale += changeLevelsBy;
				value.Scale = Math.Min(value.Scale, maxScaleLevel);
				value.Scale = Math.Max(value.Scale, minScaleLevel);
				_scaleChangedForControlType.OnNext(value.ControlType);
			}
			DebugDump("ChangeWorkoutScaleBy");
			UpdateControls(latestTargetValue, null, ignoreSentValues: false);
			if (!(SuppressScaleNotification(changeLevelsBy) || suppressNotifications))
			{
				PostScaleChangeNotification(changeLevelsBy);
			}
		}

		public bool SuppressScaleNotification(int changedLevelsBy)
		{
			if (scaleControlsInfo.ContainsKey(Workout.Control.ControlType.Mps))
			{
				int scale = scaleControlsInfo[Workout.Control.ControlType.Mps].Scale;
				int val = scale - changedLevelsBy;
				val = Math.Max(Math.Min(val, maxScaleLevel), minScaleLevel);
				string key = KeyForControlTracking(Workout.Control.ControlType.Mps, scale);
				string key2 = KeyForControlTracking(Workout.Control.ControlType.Mps, val);
				double value = controlsTracking[key].FindControlNearestToTime(latestTargetValue).Value;
				double value2 = controlsTracking[key2].FindControlNearestToTime(latestTargetValue).Value;
				double a = UnitUtil.Ensure(SpeedUnit.Mps, CurrentSpeedUnit, value, 1);
				double b = UnitUtil.Ensure(SpeedUnit.Mps, CurrentSpeedUnit, value2, 1);
				return a.AlmostEqual(b);
			}
			return false;
		}

		private void PostScaleChangeNotification(int changeLevelsBy)
		{
			HowlActivePulseType activePulseNotification = ((changeLevelsBy > 0) ? HowlActivePulseType.ScaleUp : HowlActivePulseType.ScaleDown);
			CoachingMessageNotificationData notification = new CoachingMessageNotificationData(activePulseNotification);
			inAppNotificationService?.Post(notification);
		}

		private int NumCappedScaleLevelsFromCurrent()
		{
			int result = 0;
			Workout.Control.ControlType controlType = Workout.Control.ControlType.Mps;
			if (canSetControlTypes.Contains(controlType))
			{
				int scale = scaleControlsInfo[controlType].Scale;
				double value = controlsTracking[KeyForControlTracking(controlType, scale)].FindControlNearestToTime(latestTargetValue).Value;
				if (value.AlmostEqual(userMaxMps))
				{
					for (int num = scale - 1; num >= minScaleLevel; num--)
					{
						double value2 = controlsTracking[KeyForControlTracking(controlType, num)].FindControlNearestToTime(latestTargetValue).Value;
						if (value2.AlmostEqual(userMaxMps))
						{
							result = scale - num - 1;
							break;
						}
					}
				}
			}
			return result;
		}

		public void LockWorkoutScale(Workout.Control.ControlType controlType)
		{
			if (!scaleControlsInfo.ContainsKey(controlType))
			{
				return;
			}
			PendingScaleValue pending = scaleControlsInfo[controlType].Pending;
			if (pending == null || !pending.HasPending)
			{
				return;
			}
			foreach (ScaleControlInfo value in scaleControlsInfo.Values)
			{
				value.Pending.Scale = pending.Scale;
			}
		}

		private void UpdatePendingScaleControls(double at, bool forceOverride = false)
		{
			foreach (ScaleControlInfo value in scaleControlsInfo.Values)
			{
				if (value.Pending.HasPending)
				{
					string key = KeyForControlTracking(value.ControlType);
					if (controlsTracking[key].DidControlChange(at) || forceOverride)
					{
						iFit.Logger.Log.Info("ScalingControl", string.Format("{0}: [{1}] Scale {2} => Pending {3}", "UpdatePendingScaleControls", value.ControlType, value.Scale, value.Pending.Scale));
						value.Pending.ClearPending();
						value.Scale = value.Pending.Scale;
					}
				}
			}
		}

		private List<Workout.Control> ControlsToUpdate(double at, IEnumerable<Workout.Control.ControlType> excludeTypes, bool ignoreSentValues)
		{
			List<Workout.Control> list = new List<Workout.Control>();
			foreach (Workout.Control.ControlType canSetControlType in canSetControlTypes)
			{
				if (excludeTypes == null || !excludeTypes.Contains(canSetControlType))
				{
					Workout.Control control = controlsTracking[KeyForControlTracking(canSetControlType)].FindControlNearestToTime(at);
					if (control != null && !(control.HasBeenSent && ignoreSentValues))
					{
						list.Add(control);
					}
				}
			}
			return list;
		}

		protected override void UpdateControls(double at, IEnumerable<Workout.Control.ControlType> excludeTypes, bool ignoreSentValues)
		{
			SendDebugScaleLevelsUpdate();
			if (at < 5.0)
			{
				base.UpdateControls(at, excludeTypes, ignoreSentValues);
				return;
			}
			UpdatePendingScaleControls(at);
			List<Workout.Control> list = ControlsToUpdate(at, excludeTypes, ignoreSentValues);
			double? kph;
			double? incline;
			double? resistance;
			int? gear;
			if (!list.IsNullOrEmpty() && !videoIsLoading)
			{
				iFit.Logger.Log.Info("ScalingControl", string.Format("{0}: at={1} Control Update Happening", "UpdateControls", at));
				DebugDump("UpdateControls");
				kph = null;
				incline = null;
				resistance = null;
				gear = null;
				list.OrderBy((Workout.Control c) => (c.Type != Workout.Control.ControlType.Incline) ? 1 : 0).ForEach(delegate(Workout.Control c)
				{
					UpdateControl(c, !ignoreSentValues);
				});
				IConsoleControlValuesFacade consoleControlValuesFacade = Mvx.Resolve<IConsoleControlValuesFacade>();
				consoleControlValuesFacade.SetControlValues(new ConsoleControlValues
				{
					Kph = kph,
					Incline = incline,
					Resistance = resistance,
					Gear = gear
				});
			}
			void UpdateControl(Workout.Control control, bool isResetingOverrideByUser)
			{
				ApplyDecorators(control);
				if (control.OverriddenByUser)
				{
					iFit.Logger.Log.Info("ScalingControl", string.Format("{0}: user overriden type={1}", "UpdateControls", control.Type));
				}
				else
				{
					switch (control.Type)
					{
					case Workout.Control.ControlType.Incline:
						UpdateInclineControl(control, out incline);
						break;
					case Workout.Control.ControlType.Resistance:
						UpdateResistanceControl(control, out resistance);
						break;
					case Workout.Control.ControlType.Mps:
						UpdateSpeedControl(control, out kph);
						break;
					case Workout.Control.ControlType.Gear:
						UpdateGearControl(control, out gear);
						break;
					case Workout.Control.ControlType.RelativeResistance:
						UpdateRelativeResistanceControl(control, out resistance);
						break;
					default:
						iFit.Logger.Log.Warn("ScalingControl", "UpdateControls: Unsupported control type found: " + control.Type);
						break;
					}
					control.HasBeenSent = true;
					control.SentToResetOverrideByUser = isResetingOverrideByUser;
				}
			}
		}

		protected override void UpdateSpeedControl(Workout.Control control, out double? kph)
		{
			base.UpdateSpeedControl(control, out kph);
			if (IsReachedMaxGovernorSpeed(kph))
			{
				double value = UnitUtil.EnsureKph(SpeedUnit.Mps, controlsTracking[KeyForControlTracking(control.Type, MaxScaleLevelAllowed + 1)].OriginalControlValueAt(latestTargetValue), 1);
				savedMpsSpeedGovernorNextLevel = UnitUtil.EnsureMps(SpeedUnit.Kph, value);
				inAppNotificationService?.Post(new CoachingMessageNotificationData(HowlSmartAdjustType.SpeedGovernorLimitsReached));
				iFit.Logger.Log.Info("ScalingControl", "UpdateSpeedControl: Max governor speed has been reached. userMaxMps=" + DebugMpsToCurrent(userMaxMps) + " savedSpeedGovernorNextLevelTo=" + DebugMpsToCurrent(savedMpsSpeedGovernorNextLevel));
			}
		}

		protected bool IsReachedMaxGovernorSpeed(double? kph)
		{
			if (!kph.HasValue || userMaxMps >= 1.7976931348623157E+308 || !enableMaxSpeedGovernor)
			{
				return false;
			}
			double num = UnitUtil.EnsureKph(SpeedUnit.Mps, userMaxMps, 1);
			int scale = scaleControlsInfo[Workout.Control.ControlType.Mps].Scale;
			if ((kph.Value.AlmostEqual(num) || kph.Value > num) && scale >= MaxScaleLevelAllowed)
			{
				return scale < maxScaleLevel;
			}
			return false;
		}

		private void ApplyDecorators(Workout.Control control)
		{
			foreach (IControlDecorator decorator in decorators)
			{
				decorator.Decorate(control);
			}
		}

		private string KeyForControlTracking(Workout.Control.ControlType controlType, int workoutScale)
		{
			return controlType.ToString() + workoutScale;
		}

		private string KeyForControlTracking(Workout.Control.ControlType controlType)
		{
			return controlType.ToString() + scaleControlsInfo[controlType].Scale;
		}

		private int CurrentMaxDominantScaleLevel()
		{
			Dictionary<int, double> dictionary = ScaleValuesForControlType(dominantControlToScale);
			if (!dictionary.Keys.Any())
			{
				return 0;
			}
			int num = dictionary.Keys.Max();
			double b = dictionary[num];
			for (int num2 = num; num2 >= 0; num2--)
			{
				if (dictionary.ContainsKey(num2))
				{
					if (!dictionary[num2].AlmostEqual(b))
					{
						break;
					}
					num = num2;
					b = dictionary[num];
				}
			}
			return num;
		}

		protected async Task InAppNotification((NotificationChangeType type, NotificationData data) obj)
		{
			CoachingMessageNotificationData coachingMessageNotificationData = obj.data as CoachingMessageNotificationData;
			if (((coachingMessageNotificationData != null) & (obj.type == NotificationChangeType.Remove)) && obj.data is CoachingMessageNotificationData && obj.data.ActionHappened)
			{
				if (coachingMessageNotificationData.IsMessage(HowlSmartAdjustType.MaxSpeedUserOverride))
				{
					await UpdateMaxSpeed(savedMpsUserMaxSpeedTo);
				}
				else if (coachingMessageNotificationData.IsMessage(HowlSmartAdjustType.SpeedGovernorLimitsReached))
				{
					await UpdateMaxSpeed(savedMpsSpeedGovernorNextLevel, updateConsoleValue: true);
				}
			}
		}

		protected async Task UpdateMaxSpeed(double mpsMaxSpeedTo, bool updateConsoleValue = false)
		{
			if (!enableMaxSpeedGovernor)
			{
				return;
			}
			await userMaxMpsLock.WaitAsync().ConfigureAwait(continueOnCapturedContext: false);
			try
			{
				if (mpsMaxSpeedTo > userMaxMps)
				{
					mpsMaxSpeedTo = RoundMaxSpeed(mpsMaxSpeedTo);
					iFit.Logger.Log.Info("ScalingControl", "UpdateMaxSpeed: userMaxMps=" + DebugMpsToCurrent(userMaxMps) + " => mpsMaxSpeedTo=" + DebugMpsToCurrent(mpsMaxSpeedTo));
					User user = await User.GetMe(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
					WorkoutScalingSettings workoutScalingSettings = await user.GetWorkoutScalingSettings(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
					if (workoutScalingSettings == null)
					{
						return;
					}
					workoutScalingSettings.MaxTreadmillMPS = mpsMaxSpeedTo;
					await user.UpdateWorkoutScalingSettings(ifitApi).ConfigureAwait(continueOnCapturedContext: false);
					await RecalculateGovernorMaxAllowedScale().ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			finally
			{
				userMaxMpsLock.Release();
			}
			if (updateConsoleValue)
			{
				kphFacade.SetKph(UnitUtil.EnsureKph(SpeedUnit.Mps, mpsMaxSpeedTo));
			}
		}

		protected double RoundMaxSpeed(double newMpsMaxSpeed)
		{
			double num = (isMetric ? WorkoutScalingSettings.MaxKphRoundingStep : WorkoutScalingSettings.MaxMphRoundingStep);
			double num2 = 1.0 / num;
			double num3 = UnitUtil.EnsureMph(SpeedUnit.Mps, newMpsMaxSpeed, 1);
			if (isMetric)
			{
				num3 = UnitUtil.EnsureKph(SpeedUnit.Mps, newMpsMaxSpeed, 1);
			}
			double num4 = Math.Round(num3 * num2) / num2;
			if (num4 < num3)
			{
				num4 += num;
			}
			double result = UnitUtil.EnsureMps(SpeedUnit.Mph, num4);
			if (isMetric)
			{
				result = UnitUtil.EnsureMps(SpeedUnit.Kph, num4);
			}
			return result;
		}

		private void DebugDump(string label)
		{
			Task.Run(async delegate
			{
				await debugDumpGate.WaitAsync();
				iFit.Logger.Log.Info("ScalingControl", $"{label}: userMaxMps={DebugMpsToCurrent(userMaxMps)} minScaleLevel={minScaleLevel} maxScaleLevel={maxScaleLevel} MaxScaleLevelAllowed={MaxScaleLevelAllowed} EnableMaxSpeedGovernor={EnableMaxSpeedGovernor}");
				foreach (Workout.Control.ControlType canSetControlType in canSetControlTypes)
				{
					string text = ((canSetControlType == Workout.Control.ControlType.Mps) ? CurrentSpeedUnit.ToString() : canSetControlType.ToString());
					iFit.Logger.Log.Info("ScalingControl", label + ": " + text + " " + DebugScales(canSetControlType));
				}
				debugDumpGate.Release();
			});
		}

		private string DebugScales(Workout.Control.ControlType controlType)
		{
			StringBuilder stringBuilder = new StringBuilder();
			Dictionary<int, double> dictionary = ScaleValuesForControlType(controlType);
			if (dictionary.Count == 0)
			{
				return "";
			}
			int num = -2147483648;
			if (scaleControlsInfo.TryGetValue(controlType, out var value))
			{
				num = value.Scale;
			}
			stringBuilder.Append($"[{num}]");
			if (value != null && value.Pending.HasPending)
			{
				stringBuilder.Append($"=>[{value.Pending.Scale}]");
			}
			stringBuilder.Append(" Scales=");
			for (int num2 = maxScaleLevel; num2 >= minScaleLevel; num2--)
			{
				double num3 = dictionary[num2];
				if (controlType == Workout.Control.ControlType.Mps)
				{
					num3 = (isMetric ? UnitUtil.EnsureKph(SpeedUnit.Mps, num3, 1) : UnitUtil.EnsureMph(SpeedUnit.Mps, num3, 1));
				}
				stringBuilder.Append((num2 == num) ? $"[{num2}={num3}]  " : $"{num2}={num3}  ");
			}
			return stringBuilder.ToString();
		}

		private void SendDebugScaleLevelsUpdate()
		{
			if (!EnableScalingDebug)
			{
				return;
			}
			foreach (Workout.Control.ControlType canSetControlType in canSetControlTypes)
			{
				SendDebugScaleLevelsUpdate(canSetControlType);
			}
		}

		private void SendDebugScaleLevelsUpdate(Workout.Control.ControlType controlType)
		{
			StringBuilder stringBuilder = new StringBuilder();
			AddControlTypeToDebugMessage(stringBuilder, controlType);
			int scale = scaleControlsInfo[controlType].Scale;
			int pendingScale = -2147483648;
			if (scaleControlsInfo[controlType].Pending.HasPending)
			{
				pendingScale = scaleControlsInfo[controlType].Pending.Scale;
			}
			Dictionary<int, double> dictionary = ScaleValuesForControlType(controlType);
			for (int num = maxScaleLevel; num >= minScaleLevel; num--)
			{
				if (dictionary.TryGetValue(num, out var value))
				{
					value = GetControlValueForDebugMessage(controlType, value);
					AddScaleValuesToDebugMessage(stringBuilder, num, scale, pendingScale, value);
				}
			}
			_debugScaleLevels.OnNext((MetricConversions.ControlTypeToMetricType(controlType), stringBuilder.ToString()));
		}

		private void AddControlTypeToDebugMessage(StringBuilder msg, Workout.Control.ControlType controlType)
		{
			switch (controlType)
			{
			case Workout.Control.ControlType.Mps:
			{
				string text = (isMetric ? "KPH" : "MPH");
				msg.AppendLine(text ?? "");
				break;
			}
			case Workout.Control.ControlType.Resistance:
				msg.AppendLine("Resist");
				break;
			default:
				msg.AppendLine($"{controlType}");
				break;
			}
		}

		private double GetControlValueForDebugMessage(Workout.Control.ControlType controlType, double value)
		{
			if (controlType != Workout.Control.ControlType.Mps)
			{
				return value;
			}
			if (!isMetric)
			{
				return UnitUtil.EnsureMph(SpeedUnit.Mps, value, 1);
			}
			return UnitUtil.EnsureKph(SpeedUnit.Mps, value, 1);
		}

		private void AddScaleValuesToDebugMessage(StringBuilder msg, int scale, int currScale, int pendingScale, double value)
		{
			if (scale == currScale)
			{
				msg.AppendLine($"[{scale}={value}]");
			}
			else if (scale == pendingScale)
			{
				msg.AppendLine($"*{scale}={value}*");
			}
			else
			{
				msg.AppendLine($"{scale}={value}");
			}
		}

		private string DebugMpsToCurrent(double value)
		{
			if (isMetric)
			{
				return $"{value} [{UnitUtil.EnsureKph(SpeedUnit.Mps, value, 1)} kph]";
			}
			return $"{value} [{UnitUtil.EnsureMph(SpeedUnit.Mps, value, 1)} mph]";
		}
	}
