	public class ScaleControlInfo
	{
		private int saved = -2147483648;

		public Workout.Control.ControlType ControlType { get; set; }

		public int Scale { get; set; }

		public PendingScaleValue Pending { get; set; }

		public void Save()
		{
			if (Pending.HasPending)
			{
				saved = Pending.Scale;
			}
			else
			{
				saved = Scale;
			}
		}

		public void Restore()
		{
			if (saved != -2147483648)
			{
				Scale = saved;
				Pending.Scale = saved;
				Pending.ClearPending();
			}
		}

		public override string ToString()
		{
			return $"{ControlType}: Scale: {Scale}  Pending: [{Pending}]";
		}
	}
