				if (_combinedAudioVideoPlayer == null && Mvx.TryResolve<IVideoService>(out var service))
				{
					_combinedAudioVideoPlayer = service.PreBufferedVideoPlayer;
				}
				return _combinedAudioVideoPlayer;
			}
