			: base(Workout.TargetType.Seconds, Workout.WorkoutCategory.Video, controls, console, decorators, whenIsLoadingChanged)
		{
		}

		protected override IDisposable CreateTargetSubscriber(Workout.TargetType target)
		{
			if (combinedAudioVideoPlayer == null)
			{
				iFit.Logger.Log.Trace("Video", "Falling back onto base target subscriber for VideoWorkoutControlAdapter");
				return base.CreateTargetSubscriber(target);
			}
			return combinedAudioVideoPlayer.WhenVideoPositionSecondsChanged.Subscribe(delegate(double current)
			{
				latestTargetValue = current;
				UpdateControls(current, null, ignoreSentValues: true);
				_whenTargetMetricChanged.OnNext(current);
			});
