	public static class MetricConversions
	{
		public static Workout.Control.ControlType MetricTypeToControlType(FitnessValue metricType)
		{
			return metricType switch
			{
				FitnessValue.Gear => Workout.Control.ControlType.Gear, 
				FitnessValue.Grade => Workout.Control.ControlType.Incline, 
				FitnessValue.Kph => Workout.Control.ControlType.Mps, 
				FitnessValue.Resistance => Workout.Control.ControlType.Resistance, 
				_ => throw new Exception($"Unknown MetricType: [{metricType}] to convert to ControlType."), 
			};
		}

		public static FitnessValue ControlTypeToMetricType(Workout.Control.ControlType controlType)
		{
			return controlType switch
			{
				Workout.Control.ControlType.Gear => FitnessValue.Gear, 
				Workout.Control.ControlType.Incline => FitnessValue.Grade, 
				Workout.Control.ControlType.Mps => FitnessValue.Kph, 
				Workout.Control.ControlType.Resistance => FitnessValue.Resistance, 
				_ => throw new Exception($"Unknown ControlType: [{controlType}] to convert to MetricType."), 
			};
		}

		public static Dictionary<int, double> MpsToKph(Dictionary<int, double> mpsDictionary)
		{
			Dictionary<int, double> dictionary = new Dictionary<int, double>();
			foreach (KeyValuePair<int, double> item in mpsDictionary)
			{
				dictionary.Add(item.Key, UnitUtil.EnsureKph(SpeedUnit.Mps, item.Value, 1));
			}
			return dictionary;
		}

		public static Dictionary<int, double> MpsToMph(Dictionary<int, double> mpsDictionary)
		{
			Dictionary<int, double> dictionary = new Dictionary<int, double>();
			foreach (KeyValuePair<int, double> item in mpsDictionary)
			{
				dictionary.Add(item.Key, UnitUtil.EnsureMph(SpeedUnit.Mps, item.Value, 1));
			}
			return dictionary;
		}
	}
	public static class ScalableTypeExtensions
	{
		public static bool IsFitnessValueScalable(this FitnessValue fitnessValue)
		{
			if (fitnessValue != FitnessValue.Kph && fitnessValue != FitnessValue.Grade && fitnessValue != FitnessValue.Resistance)
			{
				return fitnessValue == FitnessValue.Gear;
			}
			return true;
		}

		public static bool IsMetricTypeScalable(this FitnessValue type)
		{
			if (type != FitnessValue.Kph && type != FitnessValue.Gear && type != FitnessValue.Resistance)
			{
				return type == FitnessValue.Grade;
			}
			return true;
		}
	}
