		private double userKphChangeCountWarmUp;

		private double userKphChangesSumWorkout;

		private double userKphChangeCountWorkout;

		private double userKphChangesSumCoolDown;

		private double userKphChangeCountCoolDown;

		private FitnessValueChange<double> lastKphChange = new FitnessValueChange<double>(FitnessValue.Kph, 0.0, 2.0);

		private double userGradeChangesSumWarmUp;

		private double userGradeChangeCountWarmUp;

		private double userGradeChangesSumWorkout;

		private double userGradeChangeCountWorkout;

		private double userGradeChangesSumCoolDown;

		private double userGradeChangeCountCoolDown;

		private FitnessValueChange<double> lastGradeChange = new FitnessValueChange<double>(FitnessValue.Grade, 0.0, 0.0);

		private double userResistanceChangesSumWarmUp;

		private double userResistanceChangeCountWarmUp;

		private double userResistanceChangesSumWorkout;

		private double userResistanceChangeCountWorkout;

		private double userResistanceChangesSumCoolDown;

		private double userResistanceChangeCountCoolDown;

		private FitnessValueChange<double> lastResistanceChange = new FitnessValueChange<double>(FitnessValue.Resistance, 0.0, 1.0);

		private KeyValuePair<bool, bool> followingTrainerChange = new KeyValuePair<bool, bool>(key: true, value: true);

		private IScalingControlAdapter _controlAdapter;

		private IInWorkoutMetricsManager _pulseUsabilityMetrics;

		private Subject<(FitnessValue metric, string msg)> _DebugScaleLevels = new Subject<(FitnessValue, string)>();

		public bool EnableUserOverride
		{
			get
			{
				if (workoutFeatureService.ScalingMode != ScalingMode.Manual)
				{
					return workoutFeatureService.ScalingMode == ScalingMode.Legacy;
