		public IObservable<(FitnessValue metric, string msg)> DebugScaleLevels => _DebugScaleLevels;

		public WorkoutChangeLevel(IChangeLevelFactory changeLevelFactory, IWorkoutFeatureService workoutFeatureService, IInAppNotificationService inAppNotificationService, IFitnessConsole console, Workout workout, bool isMetric)
		{
			this.isMetric = isMetric;
			this.workoutFeatureService = workoutFeatureService;
			this.changeLevelFactory = changeLevelFactory;
			this.inAppNotificationService = inAppNotificationService;
			this.console = console;
			canSetControlTypes = new CanSetControlTypes(console.ConsoleInfo.CanSetKph, console.ConsoleInfo.CanSetGear, console.ConsoleInfo.CanSetResistance, console.ConsoleInfo.CanSetIncline);
			isMissingScaledControls = workout.IsMissingScaledControls();
			changeLevelModeSub = workoutFeatureService.WhenScalingModeChanged.Subscribe(HandleChangeMode);
			IReadWriteFacadeFactoryDependencies readWriteFacadeFactoryDependencies = Mvx.Resolve<IReadWriteFacadeFactoryDependencies>();
			List<IObservable<FitnessValueChange<double>>> sources = new List<IObservable<FitnessValueChange<double>>>
			{
				readWriteFacadeFactoryDependencies.GradeFacade.ObserveGradeChanges(),
				readWriteFacadeFactoryDependencies.KphFacade.ObserveKphChanges(),
				readWriteFacadeFactoryDependencies.ResistanceFacade.ObserveResistanceChanges(),
				from x in readWriteFacadeFactoryDependencies.GearFacade.ObserveGearChanges()
					select new FitnessValueChange<double>(x.Type, x.Old.CurrentGear, x.Current.CurrentGear)
			};
			whenMetricChangedSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(sources.Merge(), OnWhenMetricChanged);
			object obj;
			if (console == null)
			{
				obj = null;
			}
			else
			{
				IObservable<FitnessValue> whenControlValueChangedOnConsole = console.WhenControlValueChangedOnConsole;
				obj = ((whenControlValueChangedOnConsole != null) ? Sindarin.Core.Util.ObservableExtensions.SubscribeAsyncWithErrorLogging(whenControlValueChangedOnConsole, OnControlValueChangedOnConsole) : null);
			}
			controlValueChangedOnConsoleSub = (IDisposable)obj;
			whenStateChangedSub = console?.WhenStateChanged.SubscribeWithErrorLogging(OnConsoleStateChange);
			subNotificationChanges = inAppNotificationService.NotificationChanges.Where(((NotificationChangeType type, NotificationData data) x) => x.type == NotificationChangeType.Remove && x.data is FollowNotificationData).Subscribe(delegate
			{
				followingTrainerChange = new KeyValuePair<bool, bool>(key: false, value: true);
			});
		}

		public void Dispose()
		{
			controlValueChangedOnConsoleSub?.Dispose();
			controlValueChangedOnConsoleSub = null;
			whenMetricChangedSub?.Dispose();
			whenMetricChangedSub = null;
			whenStateChangedSub?.Dispose();
			whenStateChangedSub = null;
			changeLevelModeSub?.Dispose();
			changeLevelModeSub = null;
			runningChangeLevel?.Dispose();
			runningChangeLevel = null;
			changeLevelFactory?.Dispose();
			changeLevelFactory = null;
			subNotificationChanges?.Dispose();
			subNotificationChanges = null;
		}

		public void Start()
		{
			InWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.UserDuration);
			if (workoutFeatureService.IsSmartAdjustAvailableInWorkout())
			{
				HandleChangeMode(workoutFeatureService.ScalingMode);
			}
		}

		public void UserChangingControl(FitnessValue metricType, double newValue)
		{
			if (!paused && canSetControlTypes.CanSet(metricType))
			{
				followingTrainerChange = new KeyValuePair<bool, bool>(key: true, value: false);
				PostScaleChangeNotification(metricType, newValue);
				IncrementControlChangeMetric(metricType);
				UpdateControlChangeAverage(metricType, newValue);
			}
		}

		public void UserToggledSoftwareControls(bool isVisible)
		{
			if (isVisible)
			{
				InWorkoutMetricsManager?.StartRecordingMetricTime(WorkoutControlChangeMetric.SoftwareSlidersTime, currentWorkoutState);
				InWorkoutMetricsManager?.IncrementControlChangeMetricBy1(WorkoutControlChangeMetric.SoftwareSlidersCount, currentWorkoutState);
			}
			else
			{
				InWorkoutMetricsManager?.StopRecordingMetricTime(WorkoutControlChangeMetric.SoftwareSlidersTime, DateTime.UtcNow, currentWorkoutState);
			}
		}

		private void IncrementControlChangeMetric(FitnessValue fitnessValue, bool isHardwareChange = false)
		{
			switch (fitnessValue)
			{
			case FitnessValue.Kph:
				InWorkoutMetricsManager?.IncrementControlChangeMetricBy1(isHardwareChange ? WorkoutControlChangeMetric.HardwareSpeedChanges : WorkoutControlChangeMetric.SoftwareSpeedChanges, currentWorkoutState);
				break;
			case FitnessValue.Resistance:
			case FitnessValue.Gear:
				InWorkoutMetricsManager?.IncrementControlChangeMetricBy1(isHardwareChange ? WorkoutControlChangeMetric.HardwareResistanceChanges : WorkoutControlChangeMetric.SoftwareResistanceChanges, currentWorkoutState);
				break;
			case FitnessValue.Grade:
				InWorkoutMetricsManager?.IncrementControlChangeMetricBy1(isHardwareChange ? WorkoutControlChangeMetric.HardwareInclineChanges : WorkoutControlChangeMetric.SoftwareInclineChanges, currentWorkoutState);
				break;
			}
		}

		private void UpdateControlChangeAverage(FitnessValue metricType, double newValue)
		{
			switch (metricType)
			{
			case FitnessValue.Kph:
				UpdateControlChangeAverageKph(newValue);
				break;
			case FitnessValue.Resistance:
			case FitnessValue.Gear:
				UpdateControlChangeAverageResistance(newValue);
				break;
			case FitnessValue.Grade:
				UpdateControlChangeAverageGrade(newValue);
				break;
			}
		}

		private void UpdateControlChangeAverage(FitnessValueChange<double> lastChange, double newValue, ref double sum, ref double count, WorkoutControlChangeMetric changeMetric)
		{
			double num = ((Math.Abs(lastChange.Current - newValue) < 0.1) ? Math.Abs(lastChange.Old - lastChange.Current) : Math.Abs(newValue - lastChange.Current));
			count += 1.0;
			sum += num;
			double newValue2 = sum / count;
			InWorkoutMetricsManager?.UpdateControlChangeMetric(changeMetric, currentWorkoutState, newValue2);
		}

		private void UpdateControlChangeAverageKph(double newValue)
		{
			switch (currentWorkoutState)
			{
			case ConsoleState.WarmUp:
				UpdateControlChangeAverage(lastKphChange, newValue, ref userKphChangesSumWarmUp, ref userKphChangeCountWarmUp, WorkoutControlChangeMetric.AverageSpeedChange);
				break;
			case ConsoleState.Workout:
				UpdateControlChangeAverage(lastKphChange, newValue, ref userKphChangesSumWorkout, ref userKphChangeCountWorkout, WorkoutControlChangeMetric.AverageSpeedChange);
				break;
			case ConsoleState.CoolDown:
				UpdateControlChangeAverage(lastKphChange, newValue, ref userKphChangesSumCoolDown, ref userKphChangeCountCoolDown, WorkoutControlChangeMetric.AverageSpeedChange);
				break;
			}
		}

		private void UpdateControlChangeAverageResistance(double newValue)
		{
			switch (currentWorkoutState)
			{
			case ConsoleState.WarmUp:
				UpdateControlChangeAverage(lastResistanceChange, newValue, ref userResistanceChangesSumWarmUp, ref userResistanceChangeCountWarmUp, WorkoutControlChangeMetric.AverageResistanceChange);
				break;
			case ConsoleState.Workout:
				UpdateControlChangeAverage(lastResistanceChange, newValue, ref userResistanceChangesSumWorkout, ref userResistanceChangeCountWorkout, WorkoutControlChangeMetric.AverageResistanceChange);
				break;
			case ConsoleState.CoolDown:
				UpdateControlChangeAverage(lastResistanceChange, newValue, ref userResistanceChangesSumCoolDown, ref userResistanceChangeCountCoolDown, WorkoutControlChangeMetric.AverageResistanceChange);
				break;
			}
		}

		private void UpdateControlChangeAverageGrade(double newValue)
		{
			switch (currentWorkoutState)
			{
			case ConsoleState.WarmUp:
				UpdateControlChangeAverage(lastGradeChange, newValue, ref userGradeChangesSumWarmUp, ref userGradeChangeCountWarmUp, WorkoutControlChangeMetric.AverageInclineChange);
				break;
			case ConsoleState.Workout:
				UpdateControlChangeAverage(lastGradeChange, newValue, ref userGradeChangesSumWorkout, ref userGradeChangeCountWorkout, WorkoutControlChangeMetric.AverageInclineChange);
				break;
			case ConsoleState.CoolDown:
				UpdateControlChangeAverage(lastGradeChange, newValue, ref userGradeChangesSumCoolDown, ref userGradeChangeCountCoolDown, WorkoutControlChangeMetric.AverageInclineChange);
				break;
			}
		}

		private void OnConsoleStateChange(StateChange stateChange)
		{
			currentWorkoutState = stateChange.Current;
			if (stateChange.Current == ConsoleState.Paused || stateChange.Current == ConsoleState.WorkoutResults)
			{
				paused = true;
			}
			if (stateChange.Old == ConsoleState.Paused && paused)
			{
				paused = false;
				if (stateChange.Current != ConsoleState.WorkoutResults && stateChange.Current != ConsoleState.WarmUp)
				{
					workoutFeatureService.TurnMode(ScalingMode.Manual, on: true);
				}
			}
			InWorkoutMetricsManager?.StopRecordingMetricTime(WorkoutControlChangeMetric.ConsoleStateDuration, DateTime.UtcNow, stateChange.Old);
			if (stateChange.Current == ConsoleState.WarmUp || stateChange.Current == ConsoleState.Workout || stateChange.Current == ConsoleState.CoolDown)
			{
				InWorkoutMetricsManager?.StartRecordingMetricTime(WorkoutControlChangeMetric.ConsoleStateDuration, stateChange.Current);
			}
		}

		private async Task OnWhenMetricChanged(FitnessValueChange<double> metricChange)
		{
			if (!paused && canSetControlTypes.CanSet(metricChange.Type))
			{
				await SetMetricValues(metricChange.Type, metricChange.Current);
				CheckUpdateLastControlValue(metricChange);
			}
		}

		private void CheckUpdateLastControlValue(FitnessValueChange<double> metricChange)
		{
			bool flag = false;
			if (!followingTrainerChange.Key && followingTrainerChange.Value)
			{
				followingTrainerChange = new KeyValuePair<bool, bool>(key: true, value: true);
				flag = true;
			}
			switch (metricChange.Type)
			{
			case FitnessValue.Kph:
				lastKphChange = metricChange;
				if (flag)
				{
					UpdateControlChangeAverageKph(metricChange.Current);
				}
				break;
			case FitnessValue.Resistance:
			case FitnessValue.Gear:
				lastResistanceChange = metricChange;
				if (flag)
				{
					UpdateControlChangeAverageResistance(metricChange.Current);
				}
				break;
			case FitnessValue.Grade:
				lastGradeChange = metricChange;
				if (flag)
				{
					UpdateControlChangeAverageGrade(metricChange.Current);
				}
				break;
			}
		}

		private async Task OnControlValueChangedOnConsole(FitnessValue fitnessValue)
		{
			if (!paused && canSetControlTypes.CanSet(fitnessValue))
			{
				double metricValue = await GetMetricValues(fitnessValue);
				await controlValuesLock.WaitAsync();
				try
				{
					PostScaleChangeNotification(fitnessValue, metricValue);
				}
				finally
				{
					controlValuesLock.Release();
				}
				followingTrainerChange = new KeyValuePair<bool, bool>(key: true, value: false);
				IncrementControlChangeMetric(fitnessValue, isHardwareChange: true);
				UpdateControlChangeAverage(fitnessValue, metricValue);
			}
		}

		private void PostScaleChangeNotification(FitnessValue metricType, double newValue)
		{
			if (ControlAdapter != null && !isMissingScaledControls && (!(newValue <= 0.0) || metricType == FitnessValue.Grade))
			{
				iFit.Logger.Log.Info("ScalingControl", string.Format("{0}:{1}  User changed control. metricType={2} newValue={3}", className, "PostScaleChangeNotification", metricType, DebugMetricValue(metricType, newValue)));
				workoutFeatureService.UserChangedMetric.OnNext(metricType);
				runningChangeLevel?.UserChangedLevel(metricType, newValue);
				ShowTurnOnSmartAdjustMessage(metricType);
			}
		}

		private async Task<double> GetMetricValues(FitnessValue type)
		{
			await controlValuesLock.WaitAsync();
			try
			{
				if (!currentMetricValues.ContainsKey(type))
				{
					currentMetricValues.Add(type, 0.0);
				}
				return currentMetricValues[type];
			}
			finally
			{
				controlValuesLock.Release();
			}
		}

		private async Task SetMetricValues(FitnessValue type, double current)
		{
			await controlValuesLock.WaitAsync();
			try
			{
				if (!currentMetricValues.ContainsKey(type))
				{
					currentMetricValues.Add(type, 0.0);
				}
				currentMetricValues[type] = current;
			}
			finally
			{
				controlValuesLock.Release();
			}
		}

		private void HandleChangeMode(ScalingMode modeChange)
		{
			if (currentWorkoutState != ConsoleState.WarmUp)
			{
				iFit.Logger.Log.Info("ScalingControl", string.Format("{0}:{1}  modeChange={2}", className, "HandleChangeMode", modeChange));
				switch (modeChange)
				{
				case ScalingMode.SmartAdjust:
					InWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.TimeSmartAdjustEnabled);
					break;
				case ScalingMode.ActivePulse:
					InWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.TimeActivePulseEnabled);
					break;
				case ScalingMode.Legacy:
					InWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.Legacy);
					break;
				case ScalingMode.Manual:
					InWorkoutMetricsManager?.StartRecordingMetricTime(InWorkoutMetric.Manual);
					break;
				}
				IChangeLevel changeLevel = changeLevelFactory.ChangeLevel(modeChange);
				if (changeLevel != runningChangeLevel)
				{
					runningChangeLevel?.Stop();
					runningChangeLevel = changeLevel;
					runningChangeLevel.Start();
				}
			}
		}

		private void ShowTurnOnSmartAdjustMessage(FitnessValue fitnessValue)
		{
			if ((workoutFeatureService.IsScalingModeEnabled(ScalingMode.Legacy) || workoutFeatureService.IsScalingModeEnabled(ScalingMode.Manual)) && (fitnessValue != FitnessValue.Grade || !console.ConsoleInfo.MachineType.IsAerobicMachine() || (!workoutFeatureService.IsScalingModeEnabled(ScalingMode.Legacy) && !workoutFeatureService.IsScalingModeEnabled(ScalingMode.Manual))))
			{
				userChangeLegacyManualCount++;
				int num = userChangeLegacyManualCount;
				if (num == 2 || num == 5 || num == 10)
				{
					inAppNotificationService.Post(new CoachingMessageNotificationData(HowlSmartAdjustType.TurnOnSmartAdjust));
				}
			}
		}

		public void ScaleUp()
		{
			ControlAdapter.ChangeWorkoutScaleBy(1);
		}

		public void ScaleDown()
		{
			ControlAdapter.ChangeWorkoutScaleBy(-1);
		}

		private string DebugMetricValue(FitnessValue metric, double value)
		{
			if (!isMetric && metric == FitnessValue.Kph)
			{
				return $"{UnitUtil.EnsureMph(SpeedUnit.Kph, value, 1)}";
			}
			return $"{value:0.##}";
		}
	}
	public class WorkoutLevelUpdate
	{
		public bool Pending { get; set; }

		public Workout.Control.ControlType ControlType { get; }

		public WorkoutLevelChange Change { get; }

		public int DeltaScale { get; }

		public IReadOnlyDictionary<string, object> ReasonForChange { get; }

		public bool TriggerPause { get; set; }

		private WorkoutLevelUpdate(WorkoutLevelChange change, Dictionary<string, object> reason)
		{
			Change = change;
			ReasonForChange = reason ?? new Dictionary<string, object>();
		}

		private WorkoutLevelUpdate(int deltaScale, bool triggerPause, Dictionary<string, object> reason)
		{
			DeltaScale = deltaScale;
			Change = WorkoutLevelChange.ScaleChange;
			TriggerPause = triggerPause;
			ReasonForChange = reason ?? new Dictionary<string, object>();
		}

		public static WorkoutLevelUpdate CreateWithResponse(WorkoutScaleResponse response)
		{
			return new WorkoutLevelUpdate(ScaledConverterHelper.ScaleNameToLevel(response.Scale), response.TriggerPause, response.Reason);
		}

		public static WorkoutLevelUpdate CreateWithError()
		{
			return new WorkoutLevelUpdate(WorkoutLevelChange.Error, null);
		}

		public static WorkoutLevelUpdate CreateWithActivePulseDisabled()
		{
			return new WorkoutLevelUpdate(WorkoutLevelChange.ActivePulseDisabled, null);
		}

		public static WorkoutLevelUpdate CreateWithNoChange()
		{
			return new WorkoutLevelUpdate(WorkoutLevelChange.NoChange, null);
		}
	}
	public enum WorkoutLevelChange
	{
		Error,
		NoChange,
		ScaleChange,
		ScaleTo,
		ActivePulseDisabled
	}
}
namespace Shire.Core.Services.Maps
{
	public class ElevationGainWorkoutControlService : IElevationGainWorkoutControlService
	{
		public const double InclineControlSpacing = 20.0;

		public IRouteElevationService RouteElevationService { get; private set; }

		public ElevationGainWorkoutControlService(IRouteElevationService routeElevationService)
		{
			RouteElevationService = routeElevationService;
		}

		public async Task<ElevationGainWorkoutControlResult> CalculateElevationGainAndWorkoutControls(List<iFit.Api.Google.LatLng> routeCoordinates, bool isMetric, double? mps = null)
		{
			List<Workout.Control> controlList = new List<Workout.Control>();
			double cumulativeDistance = 0.0;
			controlList.Add(new Workout.Control
			{
				At = 0.0,
				Type = Workout.Control.ControlType.Mps,
				Value = (mps.HasValue ? mps.Value : (isMetric ? UnitUtil.EnsureMps(SpeedUnit.Kph, 2.0) : UnitUtil.EnsureMps(SpeedUnit.Mph, 1.0)))
			});
			double elevationGain = 0.0;
			double elevationLoss = 0.0;
			List<Elevations.ElevationResults> list = await RouteElevationService.GetRouteElevationPoints(routeCoordinates);
			if (list.CountSafe() < 2)
			{
				return null;
			}
			double num = 0.0;
			double elevation = list[0].Elevation;
			for (int i = 1; i < list.Count; i++)
			{
				Elevations.ElevationResults elevationResults = list[i];
				Elevations.ElevationResults elevationResults2 = list[i - 1];
				double distanceTo = elevationResults2.Location.GetDistanceTo(elevationResults.Location);
				cumulativeDistance += distanceTo;
				num += distanceTo;
				if (num > 20.0)
				{
					double num2 = elevationResults.Elevation - elevation;
					elevation = elevationResults.Elevation;
					if (num2 > 0.0)
					{
						elevationGain += num2;
					}
					else if (num2 < 0.0)
					{
						elevationLoss += Math.Abs(num2);
					}
					double num3 = Math.Atan(num2 / num) * (180.0 / Math.PI);
					double num4 = num3 / 90.0 * 100.0;
					if (double.IsNaN(num4))
					{
						num4 = 0.0;
					}
					double value = Math.Round(num4 * 2.0) / 2.0;
					controlList.Add(new Workout.Control
					{
						At = cumulativeDistance,
						Type = Workout.Control.ControlType.Incline,
						Value = value
					});
					num = 0.0;
				}
			}
			controlList.Add(new Workout.Control
			{
				Type = Workout.Control.ControlType.Incline,
				At = cumulativeDistance,
				Value = 0.0
			});
			controlList.Add(new Workout.Control
			{
				Type = Workout.Control.ControlType.Mps,
				At = cumulativeDistance,
				Value = 0.0
			});
			return new ElevationGainWorkoutControlResult(controlList, list, elevationGain, elevationLoss);
		}
	}
	public interface IElevationGainWorkoutControlService
	{
		IRouteElevationService RouteElevationService { get; }

		Task<ElevationGainWorkoutControlResult> CalculateElevationGainAndWorkoutControls(List<iFit.Api.Google.LatLng> routeCoordinates, bool isMetric, double? initialSpeed = null);
	}
	public interface IRouteElevationService
	{
		Task<List<Elevations.ElevationResults>> GetRouteElevationPoints(IList<iFit.Api.Google.LatLng> routePoints);
	}
	public class RouteElevationService : IRouteElevationService
	{
		private const int BatchSize = 512;

		private const int DownloadRetryCount = 5;

		private readonly object cacheReadLock = new object();

		private readonly Dictionary<string, Elevations.ElevationResults> elevationDataCache = new Dictionary<string, Elevations.ElevationResults>();

		private readonly IGoogleApiService googleApi;

		public int CacheSize => elevationDataCache?.Count ?? 0;

		public RouteElevationService(IGoogleApiService googleApi)
		{
			this.googleApi = googleApi;
		}

		public void ClearCache()
		{
			elevationDataCache?.Clear();
		}

		public async Task<List<Elevations.ElevationResults>> GetRouteElevationPoints(IList<iFit.Api.Google.LatLng> routePoints)
		{
			if (routePoints == null)
			{
				return null;
			}
			List<iFit.Api.Google.LatLng> list = routePoints.Where((iFit.Api.Google.LatLng point) => !elevationDataCache.ContainsKey(LatLngPointKey(point))).ToList();
			if (list.Count > 0)
			{
				await GetPointsAndAddToCache(list);
			}
			List<Elevations.ElevationResults> list2 = new List<Elevations.ElevationResults>();
			foreach (iFit.Api.Google.LatLng routePoint in routePoints)
			{
				string key = LatLngPointKey(routePoint);
				lock (cacheReadLock)
				{
					if (elevationDataCache.ContainsKey(key))
					{
						list2.Add(elevationDataCache[key]);
					}
				}
			}
			return (list2.Count >= 2) ? list2 : null;
		}

		private async Task GetPointsAndAddToCache(IList<iFit.Api.Google.LatLng> points)
		{
			if (points == null)
			{
				throw new ArgumentNullException("points");
			}
			int num = 0;
			List<Task> list = new List<Task>();
			while (num < points.Count)
			{
				List<iFit.Api.Google.LatLng> list2 = points.Skip(num).Take(512).ToList();
				num += list2.Count;
				Task item = ProcessPointBatch(list2);
				list.Add(item);
			}
			await Task.WhenAll(list);
		}

		private async Task ProcessPointBatch(List<iFit.Api.Google.LatLng> points)
		{
			if (points == null)
			{
				throw new ArgumentNullException("points");
			}
			if (points.Count <= 0)
			{
				return;
			}
			if (points.Count > 512)
			{
				throw new ArgumentException($"Provided point batch has more than {512:N0} elements.", "points");
			}
			int retryCount = 0;
			Elevations batchResponse = null;
			bool batchSuccess = false;
			while (!batchSuccess && 5 > retryCount++)
			{
				try
				{
					batchResponse = await Elevations.GetFromPoints(googleApi, points);
					if (batchResponse?.Results == null)
					{
						iFit.Logger.Log.Error("Api", "Google elevation request failed. Response, or response's results list, is null.");
					}
					else if (batchResponse.Status != BaseGoogleDataObject.ResponseStatusType.Ok && batchResponse.Status != BaseGoogleDataObject.ResponseStatusType.ZeroResults)
					{
						iFit.Logger.Log.Error("Api", $"Google elevation request failed. Status: {batchResponse.Status}");
					}
					else
					{
						batchSuccess = true;
					}
				}
				catch
				{
					iFit.Logger.Log.Error("Api", $"Retrying Google elevation request (Attempt {retryCount:N0}/{5:N0})");
				}
			}
			if (!batchSuccess)
			{
				iFit.Logger.Log.Error("Api", "Could not download elevation data from Google.");
				return;
			}
			foreach (Elevations.ElevationResults result in batchResponse.Results)
			{
				lock (cacheReadLock)
				{
					string key = LatLngPointKey(result.Location);
					if (elevationDataCache.ContainsKey(key))
					{
						elevationDataCache[key] = result;
					}
					else
					{
						elevationDataCache.Add(key, result);
					}
				}
			}
		}

		private static string LatLngPointKey(iFit.Api.Google.LatLng point)
		{
			double num = Math.Round(point.Lat * 100000.0) / 100000.0;
			double num2 = Math.Round(point.Lng * 100000.0) / 100000.0;
			return $"{num:0.00000},{num2:0.00000}";
		}
	}
}
namespace Shire.Core.Services.Login
{
	public interface IIfitLoginService
	{
		Task<LoginResult> Authenticate(string username, string password);

		Task<LoginResult> Authenticate(string username, string password, bool forceAuthentication);

		Task<LoginResult> SwitchToLoggedInUser(string user);

		Task<LoginResult> ReattemptAuthentication(string username, string password);

		Task<User> GetCurrentUser();

		Task LogoutAllUsers();

		Task LogoutCurrentUser();

		Task LogoutUserByHandle(string usernameOrEmail);
	}
	public class IfitLoginService : IIfitLoginService
	{
		public class IfitLoginResult
		{
			public bool IsSuccess { get; set; }
		}

		private const string Tag = "LoginService";

		private readonly IIfitApiService api;

		public IfitLoginService(IIfitApiService api)
		{
			this.api = api;
		}

		public async Task<LoginResult> Authenticate(string username, string password)
		{
			return await api.Login(username, password);
		}

		public async Task<LoginResult> Authenticate(string username, string password, bool forceAuthentication)
		{
			return await api.Login(username, password, forceAuthentication).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task<LoginResult> SwitchToLoggedInUser(string user)
		{
			User user2 = (await api.GetAuthenticatedUsers()).Find((User u) => u.Username.Equals(user) || u.Email.Equals(user));
			if (user2 == null)
			{
				return LoginResult.UserNotAuthenticated;
			}
			try
			{
				await api.SwitchUser(user2.Id);
				return LoginResult.Success;
			}
			catch (Exception)
			{
				return LoginResult.UserNotAuthenticated;
			}
		}

		public async Task<LoginResult> ReattemptAuthentication(string username, string password)
		{
			_ = 1;
			try
			{
				await api.Logout(username);
				return await Authenticate(username, password);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Fatal("LoginService", "Failed to reattempt authentication", exception);
				return LoginResult.UnknownFailure;
			}
		}

		public async Task<User> GetCurrentUser()
		{
			if (!api.HasLoggedInUser)
			{
				return null;
			}
			User user = null;
			try
			{
				user = await User.GetMe(api);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", $"Error retrieving user status - {ex.GetBaseException()}");
			}
			return user;
		}

		public async Task LogoutAllUsers()
		{
			await api.Logout(logoutAllUsers: true);
		}

		public async Task LogoutCurrentUser()
		{
			await api.Logout();
		}

		public async Task LogoutUserByHandle(string usernameOrEmail)
		{
			await api.Logout(usernameOrEmail);
		}
	}
	public abstract class ThirdPartyLoginResponse
	{
		[JsonProperty(PropertyName = "error")]
		public string Error { get; set; }
	}
	public interface IThirdPartyLoginService : IDisposable
	{
		bool IsLoginWithAppleEnabled { get; }

		Task<LoginResult> LoginWithFacebook();

		Task<User> GetUserInfoFromFacebook(User user);

		Task<bool> GenerateAndCacheFacebookAccessToken();

		Task<Auth0Response> LoginWithAuth0(Auth0InitializationData data);

		Task<AppleResponse> LoginWithApple();

		void CleanUp();
	}
	public abstract class ThirdPartyLoginService<TFacebookLogin, TAuth0Login, TAppleLogin> : IThirdPartyLoginService, IDisposable where TFacebookLogin : IFacebookLoginUtil where TAuth0Login : IAuth0LoginUtil where TAppleLogin : IAppleLoginUtil
	{
		private readonly IIfitApiService api;

		private string facebookAccessToken;

		public bool IsLoginWithAppleEnabled => AppleUtil.IsLoginEnabled;

		protected TFacebookLogin FacebookUtil { get; private set; }

		protected TAuth0Login Auth0Util { get; private set; }

		protected TAppleLogin AppleUtil { get; private set; }

		protected ThirdPartyLoginService(IIfitApiService api, TFacebookLogin facebookUtil, TAuth0Login auth0Util, TAppleLogin appleUtil)
		{
			this.api = api;
			FacebookUtil = facebookUtil;
			Auth0Util = auth0Util;
			AppleUtil = appleUtil;
		}

		public virtual void Dispose()
		{
			CleanUp();
			TFacebookLogin facebookUtil = FacebookUtil;
			if (facebookUtil != null)
			{
				facebookUtil.DisposeIfDisposable();
			}
			TAuth0Login auth0Util = Auth0Util;
			if (auth0Util != null)
			{
				auth0Util.DisposeIfDisposable();
			}
			TAppleLogin appleUtil = AppleUtil;
			if (appleUtil != null)
			{
				appleUtil.DisposeIfDisposable();
			}
		}

		public async Task<LoginResult> LoginWithFacebook()
		{
			_ = 1;
			try
			{
				facebookAccessToken = await FacebookUtil.LoginWithReadPermissions().ConfigureAwait(continueOnCapturedContext: false);
				return await AuthenticateWithProviderToken(facebookAccessToken, LoginProvider.facebook);
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Api", $"Exception logging in with Facebook: {arg}");
				return LoginResult.FacebookFailure;
			}
		}

		public async Task<User> GetUserInfoFromFacebook(User user)
		{
			try
			{
				TFacebookLogin facebookUtil = FacebookUtil;
				string accessToken = facebookAccessToken;
				return await facebookUtil.GetUserInfoFromFacebook(user, accessToken).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", $"Exception getting user info from Facebook: {ex.GetBaseException()}");
				return user;
			}
		}

		private async Task<LoginResult> AuthenticateWithProviderToken(string token, LoginProvider provider)
		{
			if (string.IsNullOrWhiteSpace(token))
			{
				return LoginResult.InvalidToken;
			}
			return await api.LoginViaProvider(token, provider);
		}

		public async Task<bool> GenerateAndCacheFacebookAccessToken()
		{
			try
			{
				facebookAccessToken = await FacebookUtil.LoginWithReadPermissions();
				return !string.IsNullOrWhiteSpace(facebookAccessToken);
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Api", $"Exception generating Facebook auth token: {arg}");
				return false;
			}
		}

		public async Task<Auth0Response> LoginWithAuth0(Auth0InitializationData data)
		{
			try
			{
				return await Auth0Util.Login(data);
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Api", $"Exception logging in with Auth0: {arg}");
				return null;
			}
		}

		public async Task<AppleResponse> LoginWithApple()
		{
			try
			{
				return await AppleUtil.Login();
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Api", $"Exception logging in with Apple: {arg}");
				return null;
			}
		}

		public void CleanUp()
		{
			TFacebookLogin facebookUtil = FacebookUtil;
			if (facebookUtil != null)
			{
				facebookUtil.CleanUp();
			}
		}
	}
}
namespace Shire.Core.Services.InAppNotifications
{
	public enum NotificationChangeType
	{
		Add,
		Remove
	}
	public interface IInAppNotificationService
	{
		bool SuppressAll { get; set; }

		IObservable<(NotificationChangeType type, NotificationData data)> NotificationChanges { get; }

		bool Exists(string guid);

		bool Exists(Type type);

		NotificationData Get(string guid);

		TData Get<TData>(string guid) where TData : NotificationData;

		void Post(NotificationData notification, bool ignoreSuppressed = false);

		void Dismiss(string guid = null);

		void Dismiss(Type type);

		void Suppress(Type type);

		void Unsuppress(Type type);

		void UnsuppressAll();

		void DismissAll();

		void DismissAll(Type type);

		void Pause(Type type, TimeSpan pausedFor);

		void CreateHelpersForNewWorkout();

		void DestroyHelpers();
	}
	public class InAppNotificationService : IInAppNotificationService
	{
		public static readonly string Tag = "InAppNotificationService";

		protected Dictionary<Type, IBaseNotificationHelper> helpers = new Dictionary<Type, IBaseNotificationHelper>();

		private readonly Subject<(NotificationChangeType type, NotificationData data)> _notificationChanges = new Subject<(NotificationChangeType, NotificationData)>();

		protected HashSet<Type> SuppressTypes = new HashSet<Type>();

		public IObservable<(NotificationChangeType type, NotificationData data)> NotificationChanges => _notificationChanges;

		public bool SuppressAll { get; set; }

		public void CreateHelpersForNewWorkout()
		{
			ConfigureHelpers();
		}

		private void ConfigureHelpers()
		{
			DestroyHelpers();
			QueueNewOnPost value = new QueueNewOnPost(_notificationChanges);
			helpers.Add(typeof(CoachingMessageNotificationData), value);
			helpers.Add(typeof(FeedFmNotificationData), new QueueNewOnPost(_notificationChanges));
			helpers.Add(typeof(FollowNotificationData), new DismissOldOnPost(_notificationChanges));
		}

		public void DestroyHelpers()
		{
			helpers?.DoForEach(delegate(KeyValuePair<Type, IBaseNotificationHelper> x)
			{
				x.Value?.Dispose();
			}, ignoreNulls: true);
			helpers?.Clear();
		}

		public void Post(NotificationData notification, bool ignoreSuppressed = false)
		{
			if (!SuppressAll || ignoreSuppressed)
			{
				Type type = notification.GetType();
				if ((!SuppressTypes.Contains(type) || ignoreSuppressed) && helpers.TryGetValue(notification.GetType(), out var value))
				{
					value?.Post(notification);
				}
			}
		}

		public NotificationData Get(string guid)
		{
			foreach (IBaseNotificationHelper value in helpers.Values)
			{
				NotificationData notificationData = value.Get(guid);
				if (notificationData != null)
				{
					return notificationData;
				}
			}
			return null;
		}

		public TData Get<TData>(string guid) where TData : NotificationData
		{
			return (TData)Get(guid);
		}

		public bool Exists(string guid)
		{
			return Get(guid) != null;
		}

		public bool Exists(Type type)
		{
			if (helpers.TryGetValue(type, out var value))
			{
				return value.AnyRunning();
			}
			return false;
		}

		public void Dismiss(string guid)
		{
			foreach (IBaseNotificationHelper value in helpers.Values)
			{
				if (value.Dismiss(guid))
				{
					break;
				}
			}
		}

		public void Dismiss(Type type)
		{
			if (helpers.TryGetValue(type, out var value))
			{
				value.Dismiss();
			}
		}

		public void Suppress(Type type)
		{
			SuppressTypes.Add(type);
		}

		public void Unsuppress(Type type)
		{
			if (SuppressTypes.Contains(type))
			{
				SuppressTypes.Remove(type);
			}
		}

		public void UnsuppressAll()
		{
			SuppressTypes.Clear();
		}

		public void DismissAll()
		{
			Dictionary<Type, IBaseNotificationHelper> dictionary = helpers.Where((KeyValuePair<Type, IBaseNotificationHelper> h) => h.Key != typeof(FeedFmNotificationData)).ToDictionary((KeyValuePair<Type, IBaseNotificationHelper> h) => h.Key, (KeyValuePair<Type, IBaseNotificationHelper> h) => h.Value);
			foreach (IBaseNotificationHelper value in dictionary.Values)
			{
				value.DismissAll();
			}
		}

		public void DismissAll(Type type)
		{
			if (helpers.TryGetValue(type, out var value))
			{
				value.DismissAll();
			}
		}

		public void Pause(Type type, TimeSpan pausedFor)
		{
			if (helpers.TryGetValue(type, out var value))
			{
				value.Pause(pausedFor);
			}
		}
	}
	public abstract class NotificationData
	{
		public static readonly TimeSpan DefaultNotificationTime = TimeSpan.FromSeconds(5.0);

		public readonly string Id;

		public bool Dismissed { get; set; }

		public TimeSpan Duration { get; set; }

		public bool ActionHappened { get; set; }

		protected NotificationData(TimeSpan displayDuration)
		{
			Id = Guid.NewGuid().ToString();
			Duration = displayDuration;
		}

		protected NotificationData()
		{
			Id = Guid.NewGuid().ToString();
			Duration = DefaultNotificationTime;
		}

		public virtual bool IsDuplicateMessage(NotificationData notification)
		{
			return false;
		}
	}
	public class FeedFmNotificationData : NotificationData
	{
		private static readonly TimeSpan MinimumNotificationTime = TimeSpan.FromSeconds(0.0);

		public readonly AudioTrack AudioTrack;

		public FeedFmNotificationData(AudioTrack audioTrack)
			: base(MinimumNotificationTime)
		{
			AudioTrack = audioTrack;
		}
	}
	public class CoachingMessageNotificationData : NotificationData
	{
		public static readonly TimeSpan DefaultSystemNotificationTime = TimeSpan.FromSeconds(7.0);

		private readonly HowlSmartAdjustType smartAdjustNotification;

		private readonly HowlActivePulseType activePulseNotification;

		private readonly Dictionary<string, string> messageVariables;

		public HowlTriggerType TriggerType { get; private set; }

		public bool RequiresArrowUp
		{
			get
			{
				if (TriggerType == HowlTriggerType.ActivePulse)
				{
					return activePulseNotification == HowlActivePulseType.ScaleUp;
				}
				return false;
			}
		}

		public bool RequiresArrowDown
		{
			get
			{
				if (TriggerType == HowlTriggerType.ActivePulse)
				{
					return activePulseNotification == HowlActivePulseType.ScaleDown;
				}
				return false;
			}
		}

		public bool IsSystemNotification
		{
			get
			{
				if (TriggerType != HowlTriggerType.SystemNotification && (TriggerType != HowlTriggerType.ActivePulse || !activePulseNotification.IsSystemNotification()))
				{
					if (TriggerType == HowlTriggerType.SmartAdjust)
					{
						return smartAdjustNotification.IsSystemNotification();
					}
					return false;
				}
				return true;
			}
		}

		public CoachingMessageNotificationData(HowlSmartAdjustType smartAdjustNotification, TimeSpan timeSpan)
			: base(timeSpan)
		{
			TriggerType = HowlTriggerType.SmartAdjust;
			this.smartAdjustNotification = smartAdjustNotification;
		}

		public CoachingMessageNotificationData(HowlSmartAdjustType smartAdjustNotification, Dictionary<string, string> messageVariables = null)
		{
			TriggerType = HowlTriggerType.SmartAdjust;
			this.smartAdjustNotification = smartAdjustNotification;
			this.messageVariables = messageVariables;
			SetDuration();
		}

		public CoachingMessageNotificationData(HowlActivePulseType activePulseNotification, Dictionary<string, string> messageVariables = null)
		{
			TriggerType = HowlTriggerType.ActivePulse;
			this.activePulseNotification = activePulseNotification;
			this.messageVariables = messageVariables;
			SetDuration();
		}

		public (string message, string actionMessage) Message(IHowlService howl)
		{
			return TriggerType switch
			{
				HowlTriggerType.ActivePulse => howl.GetTriggerNotification(activePulseNotification, messageVariables), 
				HowlTriggerType.SmartAdjust => howl.GetTriggerNotification(smartAdjustNotification, messageVariables), 
				_ => (message: "", actionMessage: ""), 
			};
		}

		public bool IsMessage(HowlSmartAdjustType type)
		{
			if (TriggerType == HowlTriggerType.SmartAdjust)
			{
				return smartAdjustNotification == type;
			}
			return false;
		}

		public bool IsMessage(HowlActivePulseType type)
		{
			if (TriggerType == HowlTriggerType.ActivePulse)
			{
				return activePulseNotification == type;
			}
			return false;
		}

		public override bool IsDuplicateMessage(NotificationData notification)
		{
			if (!(notification is CoachingMessageNotificationData))
			{
				return false;
			}
			CoachingMessageNotificationData coachingMessageNotificationData = (CoachingMessageNotificationData)notification;
			if (coachingMessageNotificationData.TriggerType != TriggerType)
			{
				return false;
			}
			if (TriggerType != HowlTriggerType.ActivePulse || activePulseNotification != coachingMessageNotificationData.activePulseNotification)
			{
				if (TriggerType == HowlTriggerType.SmartAdjust)
				{
					return smartAdjustNotification == coachingMessageNotificationData.smartAdjustNotification;
				}
				return false;
			}
			return true;
		}

		private void SetDuration()
		{
			if (IsSystemNotification)
			{
				base.Duration = DefaultSystemNotificationTime;
			}
			else
			{
				base.Duration = NotificationData.DefaultNotificationTime;
			}
		}

		public override string ToString()
		{
			return TriggerType switch
			{
				HowlTriggerType.ActivePulse => $"[Coach: Id={Id} ActivePulse={activePulseNotification} Duration={base.Duration}]", 
				HowlTriggerType.SmartAdjust => $"[Coach: Id={Id} SmartAdjust={smartAdjustNotification} Duration={base.Duration}]", 
				_ => $"[Coach: Id={Id} UNKNOWN Duration={base.Duration}]", 
			};
		}
	}
	public class FollowNotificationData : NotificationData
	{
		public enum FollowNotificationType
		{
			Gear,
			Incline,
			Resistance,
			Speed,
			Workout,
			TurnOnTrainingMode,
			Legacy
		}

		public readonly FollowNotificationType NotificationType;

		public FollowNotificationData(FollowNotificationType notificationType)
			: base(TimeSpan.Zero)
		{
			NotificationType = notificationType;
		}

		public override string ToString()
		{
			return $"[Follow: Id={Id} type={NotificationType}]";
		}
	}
	public abstract class NotificationViewModel<TData> : ShireBaseViewModel where TData : NotificationData
	{
		private readonly IInAppNotificationService notificationService;

		protected readonly IHowlService howlService;

		public TData Data { get; set; }

		protected NotificationViewModel(IInAppNotificationService notificationService, IHowlService howlService)
		{
			this.notificationService = notificationService;
			this.howlService = howlService;
		}

		public virtual Task Init(string guid)
		{
			Data = notificationService.Get<TData>(guid);
			return Task.FromResult(0);
		}

		protected void ReloadData(string guid)
		{
			Data = notificationService.Get<TData>(guid);
		}

		public void DismissNotification()
		{
			notificationService.Dismiss(Data?.Id);
		}
	}
