				new List<string> { AppStrings.turn_off_adaptive_training_message_1 }
			},
			{
				"turn_on_adaptive_training",
				new List<string> { AppStrings.turn_on_adaptive_training_message_1 }
			}
		};

		protected readonly Dictionary<string, string> TriggerNameToDefaultActionMessageMapping = new Dictionary<string, string>
		{
			{
				"workout_not_active_pulse_optimized",
				AppStrings.workout_not_active_pulse_optimized_button
			},
			{
