		public HowlService(IIfitApiService ifitApiService)
		{
			this.ifitApiService = ifitApiService;
		}

		public async Task Retrieve(List<string> workoutNotificationFilters, string consoleType, string languageCode)
		{
			HowlNotifications howlNotifications;
			try
			{
				string workoutNotificationFilters2 = ((workoutNotificationFilters != null) ? string.Join(",", workoutNotificationFilters) : string.Empty);
				howlNotifications = await ifitApiService.GatewayService.HowlNotifications(languageCode, consoleType ?? string.Empty, triggerTypes, workoutNotificationFilters2).ConfigureAwait(continueOnCapturedContext: false);
				if (howlNotifications.TriggerBasedNotifications == null || howlNotifications.TriggerBasedNotifications.Count == 0)
				{
					iFit.Logger.Log.Error("Workout", "ERROR empty notifications coming back from howl service. Using default.");
					howlNotifications = LoadDefaultHowl(JsonDefaultFile);
				}
			}
			catch (Exception ex)
			{
				howlNotifications = LoadDefaultHowl(JsonDefaultFile);
				iFit.Logger.Log.Error("Workout", "ERROR unable to get howl notifications and loaded default howl notifications: " + ex.Message, ex);
			}
			messages = howlNotifications.TriggerBasedNotifications;
			await LanguageTokenizing().ConfigureAwait(continueOnCapturedContext: false);
		}

		public (string message, string actionMessage) GetTriggerNotification(HowlSmartAdjustType type)
		{
			return GetTriggerNotification(HowlTriggerType.SmartAdjust.ToEnumMemberAttrValue(), type.ToEnumMemberAttrValue());
		}

		public (string message, string actionMessage) GetTriggerNotification(HowlActivePulseType type)
		{
			return GetTriggerNotification(HowlTriggerType.ActivePulse.ToEnumMemberAttrValue(), type.ToEnumMemberAttrValue());
		}

		public (string message, string actionMessage) GetTriggerNotification(HowlSmartAdjustType type, Dictionary<string, string> messageVariables)
		{
			return GetTriggerNotification(HowlTriggerType.SmartAdjust.ToEnumMemberAttrValue(), type.ToEnumMemberAttrValue(), messageVariables);
		}

		public (string message, string actionMessage) GetTriggerNotification(HowlActivePulseType type, Dictionary<string, string> messageVariables)
		{
			return GetTriggerNotification(HowlTriggerType.ActivePulse.ToEnumMemberAttrValue(), type.ToEnumMemberAttrValue(), messageVariables);
		}

		private (string message, string actionMessage) GetTriggerNotification(string triggerType, string trigger, Dictionary<string, string> messageVariables = null)
		{
			HowlNotifications.TriggerMessage triggerMessage = messages?.FirstOrDefault((HowlNotifications.TriggerMessage x) => x.TriggerType.Equals(triggerType) && x.TriggerName.Equals(trigger));
			if (triggerMessage == null)
			{
				iFit.Logger.Log.Warn("Api", "Warning howl message does not exist:  triggerType=" + triggerType + "  trigger=" + trigger);
				return (message: "", actionMessage: "");
			}
			string text = triggerMessage.NextMessage();
			if (messageVariables != null)
			{
				text = MessageVariablesTokenizing(text, messageVariables);
			}
			string item = ((triggerMessage.ActionMessage == null) ? "" : triggerMessage.ActionMessage);
			return (message: text, actionMessage: item);
		}

		private string MessageVariablesTokenizing(string message, Dictionary<string, string> messageVariables)
		{
			string text = message;
			foreach (KeyValuePair<string, string> messageVariable in messageVariables)
			{
				text = text.Replace("{" + messageVariable.Key + "}", messageVariable.Value);
			}
			return text;
		}

		private async Task LanguageTokenizing()
		{
			try
			{
				User user = await User.GetMe(ifitApiService).ConfigureAwait(continueOnCapturedContext: false);
				foreach (HowlNotifications.TriggerMessage message in messages)
				{
					message.LanguageTokenizing("{{FIRSTNAME}}", user.Firstname);
				}
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Workout", ex.Message);
			}
		}

		protected HowlNotifications LoadDefaultHowl(string jsonFile)
		{
			try
			{
				string value = EmbeddedResourceUtil.ReadEmbeddedResourceText(typeof(HowlService), jsonFile);
				HowlNotifications howlNotifications = JsonConvert.DeserializeObject<HowlNotifications>(value);
				PopulateHowlWithDefaultAppStrings(howlNotifications);
				return howlNotifications;
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Workout", "Error loading json configuration file", exception);
			}
			return new HowlNotifications();
		}

		private void PopulateHowlWithDefaultAppStrings(HowlNotifications howlNotifications)
		{
			foreach (HowlNotifications.TriggerMessage triggerBasedNotification in howlNotifications.TriggerBasedNotifications)
			{
				try
				{
					triggerBasedNotification.Messages = TriggerNameToDefaultMessagesMapping[triggerBasedNotification.TriggerName];
					if (TriggerNameToDefaultActionMessageMapping.ContainsKey(triggerBasedNotification.TriggerName))
					{
						triggerBasedNotification.ActionMessage = TriggerNameToDefaultActionMessageMapping[triggerBasedNotification.TriggerName];
					}
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Workout", "An error occurred finding appstring for " + (triggerBasedNotification?.TriggerName ?? "null") + " trigger", exception);
				}
			}
		}
	}
