	public interface ICompetitionCohortRetriever
	{
		Task<List<CompetitionParticipant>> GetCompetitionCohort(Workout workout);
	}
	public class CompetitionCohortRetriever : ICompetitionCohortRetriever
	{
		private readonly IIfitApiService api;

		public CompetitionCohortRetriever(IIfitApiService api)
		{
			this.api = api;
		}

		public async Task<List<CompetitionParticipant>> GetCompetitionCohort(Workout workout)
		{
			List<CompetitionParticipant> dudes = new List<CompetitionParticipant>();
			try
			{
				Cohort cohort = await Cohort.GetCohort(api, workout.Id);
				List<string> userIds = cohort.Users.Select((CohortUser x) => x.UserId).ToList();
				List<Tron> source = await Tron.GetTronUsers(api, userIds);
				foreach (CohortUser cohortUser in cohort.Users)
				{
					Tron tron = source.FirstOrDefault((Tron x) => x.Id.Equals(cohortUser.UserId));
					if (tron != null)
					{
						CompetitionParticipant item = cohortUser.ToParticipant(workout.TargetValue, tron);
						dudes.Add(item);
					}
				}
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Cohort", $"Unable to get cohort users: {arg}");
			}
			return dudes;
		}
	}
	public static class CohortExtensions
	{
		public static CompetitionParticipant ToParticipant(this CohortUser cohortUser, double targetValue, Tron tron)
		{
			ParticipantStats stats = cohortUser.ConvertDistanceToStats(targetValue);
			return new CompetitionParticipant
			{
				UserId = cohortUser.UserId,
				Name = tron.Name,
				AvatarUrl = tron.Avatar,
				Gender = tron.Gender,
				Age = tron.Age,
				Type = ParticipantType.Other,
				Stats = stats
			};
		}

		public static object PostWorkoutParticipantClean(this CompetitionParticipant participant)
		{
			return new
			{
				Name = participant.Name,
				Age = participant.Age,
				Gender = participant.Gender,
				UserId = participant.UserId,
				Rank = participant.Rank,
				AvatarUrl = participant.AvatarUrl,
				TotalDistance = participant.TotalDistance,
				Type = participant.Type.ToString()
			};
		}

		public static ParticipantStats ConvertDistanceToStats(this CohortUser cohortUser, double targetValue)
		{
			CohortMetric cohortMetric = cohortUser.Metrics.FirstOrDefault((CohortMetric x) => x.Metric == CohortMetric.MetricType.Distance);
			CohortMetric.EncodingType? encodingType = cohortMetric?.Encoding;
			if (encodingType.HasValue && encodingType.GetValueOrDefault() == CohortMetric.EncodingType.Linear)
			{
				return cohortMetric.Data.LinearDistanceToStatDistance(targetValue);
			}
			return new ParticipantStats();
		}

		public static ParticipantStats LinearDistanceToStatDistance(this List<CohortDistance> cohortDistances, double targetValue)
		{
			ParticipantStats participantStats = new ParticipantStats();
			if (cohortDistances.Count == 0)
			{
				return participantStats;
			}
			int num = 0;
			double num2 = 0.0;
			for (int i = 0; (double)i < targetValue; i++)
			{
				if (num < cohortDistances.Count - 1 && cohortDistances[num + 1].Offset <= i)
				{
					num++;
					num2 = (double)i * cohortDistances[num].Value.Slope + cohortDistances[num].Value.Intercept;
				}
				else
				{
					double slope = cohortDistances[num].Value.Slope;
					num2 += slope;
				}
				participantStats.Distance.Add(new StatDataPoint(i, num2));
			}
			return participantStats;
		}
	}
