	public class NativeCompetitionDatabase : INativeCompetitionDatabase
	{
		private IIfitApiService ifitApi;

		private ICurrentConsoleService consoleService;

		private IWorkoutControlToParticipantConverter controlConverter;

		private ICompetitionCohortRetriever cohortRetriever;

		private IFeatureFlagManager featureFlagManager;

		public List<CompetitionParticipant> Cohorts { get; set; } = new List<CompetitionParticipant>();

		public NativeCompetitionDatabase(IIfitApiService ifitApi, ICurrentConsoleService consoleService, IWorkoutControlToParticipantConverter controlConverter, IFeatureFlagManager featureFlagManager, ICompetitionCohortRetriever cohortRetriever)
		{
			this.ifitApi = ifitApi;
			this.consoleService = consoleService;
			this.controlConverter = controlConverter;
			this.cohortRetriever = cohortRetriever;
			this.featureFlagManager = featureFlagManager;
		}

		public async Task<List<CompetitionParticipant>> LoadParticipants(Workout workout)
		{
			List<CompetitionParticipant> competitionParticipants = new List<CompetitionParticipant>();
			CompetitionParticipant competitionParticipant = await controlConverter.Create(workout, consoleService, ifitApi);
			competitionParticipant.ProgressPercent = 0.0;
			competitionParticipants.Add(competitionParticipant);
			CompetitionParticipant item = new CompetitionParticipant
			{
				UserId = ifitApi.CurrentlyAuthenticatedUser.Id,
				Name = $"{ifitApi.CurrentlyAuthenticatedUser.Firstname} {ifitApi.CurrentlyAuthenticatedUser.Lastname[0]}.",
				AvatarUrl = ifitApi.CurrentlyAuthenticatedUser.ImageUrl,
				Type = ParticipantType.You,
				ProgressPercent = 1.0,
				ProgressOpacity = 0.8,
				Stats = new ParticipantStats()
			};
			competitionParticipants.Add(item);
			if (featureFlagManager.IsFeatureEnabled(FeatureFlags.NativeLeaderboardCohortEnabled))
			{
				List<CompetitionParticipant> list = competitionParticipants;
				list.AddRange(await cohortRetriever.GetCompetitionCohort(workout));
			}
			Cohorts = competitionParticipants;
			return competitionParticipants;
		}
	}
	public interface INativeCompetitionService
	{
		List<CompetitionParticipant> Participants { get; }

		IObservable<bool> ParticipantsUpdated { get; }

		bool IsGoogleMap { get; set; }

		Task StartCompetitionAsync(Workout workout);

		void EndCompetition(bool workoutFinished);
	}
	public class NativeCompetitionService : INativeCompetitionService
	{
		private IIfitApiService ifitApi;

		private IReadWriteFacadeFactoryDependencies factoryDependencies;

		private INativeCompetitionDatabase competitionDatabase;

		private IDisposable competitionsMomentSub;

		private const string LogTag = "NativeCompetition";

		private readonly Subject<bool> _participantsUpdated = new Subject<bool>();

		public bool IsGoogleMap { get; set; }

		public List<CompetitionParticipant> Participants { get; private set; }

		public IObservable<bool> ParticipantsUpdated => _participantsUpdated;

		public NativeCompetitionService(IIfitApiService ifitApi, IReadWriteFacadeFactoryDependencies factoryDependencies, INativeCompetitionDatabase competitionDatabase)
		{
			this.ifitApi = ifitApi;
			this.factoryDependencies = factoryDependencies;
			this.competitionDatabase = competitionDatabase;
		}

		public async Task StartCompetitionAsync(Workout workout)
		{
			if (workout.IsGoogleMap)
			{
				IsGoogleMap = true;
				return;
			}
			IsGoogleMap = false;
			Participants = await competitionDatabase.LoadParticipants(workout);
			LogParticipants();
			IObservable<FitnessValueChange<int>> obs = factoryDependencies.CurrentTimeFacade.ObserveCurrentTimeChanges();
			competitionsMomentSub = obs.SubscribeWithErrorLogging(OnNext);
		}

		private void OnNext(FitnessValueChange<int> change)
		{
			if (change.Current > change.Old)
			{
				UpdateDistances(change);
				UpdateRanks();
				UpdateProgressPercentAndOpacity();
				LogParticipantRanks();
				_participantsUpdated.OnNext(value: true);
			}
			else
			{
				iFit.Logger.Log.Warn("NativeCompetition", $"Moment Current {change.Current} is less than Previous {change.Old}");
			}
		}

		private void UpdateDistances(FitnessValueChange<int> change)
		{
			foreach (CompetitionParticipant participant in Participants)
			{
				if (participant.Type == ParticipantType.You)
				{
					participant.Value = factoryDependencies.CurrentDistanceFacade.GetMostRecentValue();
					participant.Stats.Distance.Add(new StatDataPoint(change.Current, participant.Value));
				}
				else
				{
					participant.Value = (participant.Stats?.Distance?.FirstOrDefault((StatDataPoint x) => Math.Abs(x.Timestamp - (double)change.Current) < 1.0))?.Value ?? participant.Value;
				}
			}
		}

		private void UpdateRanks()
		{
			if (Participants.Count == 2)
			{
				Participants[0].Rank = 0;
				Participants[1].Rank = 0;
				return;
			}
			List<CompetitionParticipant> list = Participants.OrderByDescending((CompetitionParticipant x) => x.Value).ToList();
			list.Remove(list.FirstOrDefault((CompetitionParticipant x) => x.Type == ParticipantType.Trainer));
			foreach (CompetitionParticipant participant in Participants)
			{
				participant.Rank = list.IndexOf(participant) + 1;
			}
		}

		private void UpdateProgressPercentAndOpacity()
		{
			if (Participants.Count <= 2)
			{
				return;
			}
			double num = Participants.Max((CompetitionParticipant x) => x.Value);
			double num2 = Participants.Min((CompetitionParticipant x) => x.Value);
			foreach (CompetitionParticipant participant in Participants)
			{
				if (participant.Type == ParticipantType.Trainer)
				{
					participant.ProgressOpacity = 0.6;
				}
				else
				{
					participant.ProgressOpacity = (double)(Participants.Count - participant.Rank) / ((double)Participants.Count - 1.0) * 0.6 + 0.2;
				}
				participant.ProgressPercent = (participant.Value - num2) / (num - num2) * 0.8 + 0.2;
			}
		}

		public void EndCompetition(bool workoutFinished)
		{
			competitionsMomentSub?.Dispose();
		}

		private void LogParticipants()
		{
			StringBuilder stringBuilder = new StringBuilder("Participants: \n");
			foreach (CompetitionParticipant participant in Participants)
			{
				stringBuilder.Append($"UserId {participant.UserId}, Name: {participant.Name}, Type: {participant.Type}");
				int? num = participant.Stats?.Distance?.Count;
				if (num.HasValue)
				{
					int valueOrDefault = num.GetValueOrDefault();
					stringBuilder.Append($", {valueOrDefault} points");
				}
				stringBuilder.AppendLine();
			}
			iFit.Logger.Log.Trace("NativeCompetition", stringBuilder.ToString().TrimEnd('\n'));
		}

		private void LogParticipantRanks()
		{
			StringBuilder stringBuilder = new StringBuilder("Participants rank: ");
			foreach (CompetitionParticipant participant in Participants)
			{
				stringBuilder.Append(string.Format("{0} ({1}), ", participant.Rank, participant.Value.ToString("F3")));
			}
			iFit.Logger.Log.Trace("NativeCompetition", stringBuilder.ToString().TrimEnd(',', ' '));
		}
	}
	public interface IWorkoutControlToParticipantConverter
	{
		Task<CompetitionParticipant> Create(Workout workout, ICurrentConsoleService consoleService, IIfitApiService ifitApi);
	}
	public class WorkoutControlToParticipantConverter : IWorkoutControlToParticipantConverter
	{
		public async Task<CompetitionParticipant> Create(Workout workout, ICurrentConsoleService consoleService, IIfitApiService ifitApi)
		{
			if (workout.Metadata.Trainer == null)
			{
				Workout.VideoWorkoutMetadata metadata = workout.Metadata;
				metadata.Trainer = await Trainer.Get(ifitApi, workout.Metadata.TrainerId).ConfigureAwait(continueOnCapturedContext: false);
			}
			CompetitionParticipant competitionParticipant = new CompetitionParticipant
			{
				UserId = workout.Metadata.TrainerId,
				AvatarUrl = workout.Metadata.Trainer.ProfileImageThumbnailUrl,
				Name = $"{workout.Metadata.Trainer.FirstName} {workout.Metadata.Trainer.LastName[0]}.",
				Type = ParticipantType.Trainer
			};
			switch (workout.Target)
			{
			case Workout.TargetType.Seconds:
				competitionParticipant.Stats = workout.GetStatsFromSeconds(consoleService);
				break;
			default:
				throw new ArgumentOutOfRangeException();
			case Workout.TargetType.Meters:
			case Workout.TargetType.Calories:
			case Workout.TargetType.Unknown:
				break;
			}
			return competitionParticipant;
		}
	}
	public static class WorkoutControlsExtensions
	{
		private const double AverageHeight = 1.727201016;

		public static ParticipantStats GetStatsFromSeconds(this Workout workout, ICurrentConsoleService consoleService)
		{
			Workout.Control.ControlType type;
			Func<Workout.TimestampedValue, double> mpsFunc;
			if (workout.CountType(Workout.Control.ControlType.Mps) > 1)
			{
				type = Workout.Control.ControlType.Mps;
				mpsFunc = (Workout.TimestampedValue control) => control.Value;
			}
			else if (workout.CountType(Workout.Control.ControlType.Rpm) > 0)
			{
				type = Workout.Control.ControlType.Rpm;
				mpsFunc = (Workout.TimestampedValue control) => MpsRpmUtil.RpmToMps(consoleService.Console.ConsoleInfo, control.Value);
			}
			else
			{
				if (workout.CountType(Workout.Control.ControlType.SPM) <= 0)
				{
					return new ParticipantStats();
				}
				type = Workout.Control.ControlType.SPM;
				mpsFunc = (Workout.TimestampedValue control) => Shire.Core.Util.RowerEstimator.CalculateEstimatedDistance(control.Value, 1.0, 1.727201016);
			}
			return ControlOps.GetStatsFromSecondsFromControls(workout.TargetValue, workout.OnlyControlsOrderedByAt(type), mpsFunc);
		}
	}
	public static class ControlOps
	{
		public static ParticipantStats GetStatsFromSecondsFromControls<T>(double targetValue, List<T> controls, Func<T, double> mpsFunc) where T : Workout.TimestampedValue
		{
			ParticipantStats participantStats = new ParticipantStats();
			if (controls.Count == 0)
			{
				return participantStats;
			}
			int num = 0;
			double num2 = 0.0;
			for (int i = 0; (double)i < targetValue; i++)
			{
				if (num < controls.Count - 1 && controls[num + 1].At <= (double)i)
				{
					num++;
				}
				double num3 = mpsFunc(controls[num]);
				num2 += num3;
				participantStats.Distance.Add(new StatDataPoint(i, num2));
			}
			return participantStats;
		}
	}
}
namespace Shire.Core.Services.Charts
{
	public class ChartDataProcessor : IDisposable
	{
		private const int RoundSpeedTo = 5;

		private const int RoundInclineTo = 2;

		private const int RoundResistanceTo = 2;

		private Workout workout;

		private bool isMetric;

		private IFitnessConsole console;

		private double? userHeightMeters;

		private double? userKg;

		private double? userAge;

		private bool? userMale;

		public float SpeedMinimum { get; protected set; }

		public float SpeedMaximum { get; protected set; }

		public float InclineMinimum { get; protected set; }

		public float InclineMaximum { get; protected set; }

		public float ResistanceMinimum { get; protected set; }

		public float ResistanceMaximum { get; protected set; }

