		public double PredictedDistance { get; protected set; }

		public List<Tuple<double, double>> SpeedData { get; protected set; }

		public List<Tuple<double, double>> InclineData { get; protected set; }

		public List<Tuple<double, double>> ResistanceData { get; protected set; }

		public List<Tuple<double, double>> PredictedElevationProfile { get; protected set; }

		public ChartDataProcessor(Workout workout, bool isMetric, IFitnessConsole console, double? userKg, double userHeightMeters, double? userAge, bool? userMale)
		{
			this.workout = workout;
