		public void UpdateUserKgs(double userKgs)
		{
			userKg = userKgs;
		}

		public async Task ProcessControls()
		{
			await ProcessControlsForTarget(workout.TargetValue);
		}

		public async Task ProcessControlsForTarget(double targetValue)
		{
			List<Workout.Control> speedData = GetSpeedData();
			List<Workout.Control> inclineData = GetInclineData();
			List<Workout.Control> resistanceData = GetResistanceData();
			ClearData();
			int speedIndex = 0;
			int speedAt = 0;
			int inclineIndex = 0;
			int inclineAt = 0;
			int resistanceIndex = 0;
			int resistanceAt = 0;
			long num = (long)Math.Ceiling(targetValue);
			for (long num2 = 1L; num2 <= num; num2++)
			{
				UpdateSpeedData(num2, ref speedData, ref speedAt, ref speedIndex);
				UpdateInclineData(num2, ref inclineData, ref inclineAt, ref inclineIndex);
				UpdateResistanceData(num2, ref resistanceData, ref resistanceAt, ref resistanceIndex);
			}
			await ProcessPredictions();
		}

		private void ClearData()
		{
			SpeedData?.Clear();
			InclineData?.Clear();
			ResistanceData?.Clear();
		}

		private async Task ProcessPredictions()
		{
			IWorkoutEstimator workoutEstimator = WorkoutEstimator.Factory(console, userKg, userHeightMeters, userAge, userMale, provideElevationProfile: true);
			WorkoutEstimator.Stats stats = await workoutEstimator.Estimate(workout);
			PredictedElevationGain = stats.ElevationMetersNet;
			PredictedDistance = stats.Meters;
			PredictedElevationProfile = stats.PredictedElevationProfile;
		}

		private void UpdateSpeedData(long i, ref List<Workout.Control> speedData, ref int speedAt, ref int speedIndex)
		{
			if (speedAt <= i && speedAt != -1)
			{
				if (speedIndex < speedData.Count)
				{
					float num = (float)speedData[speedIndex].Value;
					SpeedData.Add(new Tuple<double, double>(i, num));
				}
				do
				{
					speedIndex++;
					speedAt = ((speedIndex >= speedData.Count) ? (-1) : ((int)speedData[speedIndex].At));
				}
				while (speedAt != -1 && speedAt <= i);
			}
		}

		private void UpdateInclineData(long i, ref List<Workout.Control> inclineData, ref int inclineAt, ref int inclineIndex)
		{
			if (inclineAt <= i && inclineAt != -1)
			{
				if (inclineIndex < inclineData.Count)
				{
					float num = (float)inclineData[inclineIndex].Value;
					InclineData.Add(new Tuple<double, double>(i, num / 100f));
				}
				do
				{
					inclineIndex++;
					inclineAt = ((inclineIndex >= inclineData.Count) ? (-1) : ((int)inclineData[inclineIndex].At));
				}
				while (inclineAt <= i && inclineAt != -1);
			}
		}

		private void UpdateResistanceData(long i, ref List<Workout.Control> resistanceData, ref int resistanceAt, ref int resistanceIndex)
		{
			if (resistanceAt <= i && resistanceAt != -1)
			{
				if (resistanceIndex < resistanceData.Count)
				{
					float num = (float)resistanceData[resistanceIndex].Value;
					ResistanceData.Add(new Tuple<double, double>(i, num));
				}
				do
				{
					resistanceIndex++;
					resistanceAt = ((resistanceIndex >= resistanceData.Count) ? (-1) : ((int)resistanceData[resistanceIndex].At));
				}
				while (resistanceAt != -1 && resistanceAt <= i);
			}
		}

		private List<Workout.Control> GetSpeedData()
		{
			List<Workout.Control> list = workout.Controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Mps).ToList();
			if (console?.ConsoleInfo != null)
			{
				list = list.BoundDataWithoutModification((Workout.Control c) => c.Value, (Workout.Control c, double v) => new Workout.Control
				{
					At = c.At,
					Type = c.Type,
					OverriddenByUser = c.OverriddenByUser,
					Value = v
				}, UnitUtil.EnsureMps(SpeedUnit.Kph, console.ConsoleInfo.MinKph), UnitUtil.EnsureMps(SpeedUnit.Kph, console.ConsoleInfo.MaxKph));
			}
			float value = 0f;
			float value2 = 0f;
			if (list.Count > 1)
			{
				value = (float)Math.Floor(list.Min((Workout.Control arg) => arg.Value));
				value2 = (float)Math.Ceiling(list.Max((Workout.Control arg) => arg.Value));
			}
			SpeedMinimum = RoundToMultipleOf(value, 5L);
			SpeedMaximum = RoundToMultipleOf(value2, 5L);
			if (SpeedMaximum.AlmostEqual(SpeedMinimum))
			{
				SpeedMaximum += 5f;
			}
			return list;
		}

		private List<Workout.Control> GetInclineData()
		{
			List<Workout.Control> list = workout.Controls.Where((Workout.Control x) => x.Type == Workout.Control.ControlType.Incline).ToList();
			if (console?.ConsoleInfo != null)
			{
				list = list.BoundDataWithoutModification((Workout.Control c) => c.Value, (Workout.Control c, double v) => new Workout.Control
				{
					At = c.At,
					Type = c.Type,
					OverriddenByUser = c.OverriddenByUser,
					Value = v
				}, console.ConsoleInfo.MinIncline, console.ConsoleInfo.MaxIncline);
			}
			float num = 0f;
			float num2 = 0f;
			if (list.Count > 0)
			{
				num = (float)Math.Floor(list.Min((Workout.Control arg) => arg.Value));
				num2 = (float)Math.Ceiling(list.Max((Workout.Control arg) => arg.Value));
			}
			InclineMinimum = RoundToMultipleOf(num, 2L);
			InclineMaximum = RoundToMultipleOf(num2, 2L);
			if (InclineMinimum.AlmostEqual(num))
			{
				InclineMinimum -= 2f;
			}
			if (InclineMaximum.AlmostEqual(num2))
			{
				InclineMaximum += 2f;
			}
			if (InclineMinimum.AlmostEqual(InclineMaximum))
			{
				InclineMaximum += 2f;
			}
			return list;
		}

		private List<Workout.Control> GetResistanceData()
		{
			Workout.Control.ControlType resistanceControlType = Workout.Control.ControlType.Resistance;
			if (!workout.Controls.Any((Workout.Control c) => c.Type == resistanceControlType) && workout.Controls.Any((Workout.Control c) => c.Type == Workout.Control.ControlType.RelativeResistance))
			{
				resistanceControlType = Workout.Control.ControlType.RelativeResistance;
			}
			if (!workout.Controls.Any((Workout.Control c) => c.Type == resistanceControlType) && workout.Controls.Any((Workout.Control c) => c.Type == Workout.Control.ControlType.Gear))
			{
				resistanceControlType = Workout.Control.ControlType.Gear;
			}
			List<Workout.Control> list = workout.Controls.Where((Workout.Control x) => x.Type == resistanceControlType).ToList();
			if (console?.ConsoleInfo != null)
			{
				double value = console.ConsoleInfo.MinResistanceLevel;
				double value2 = console.ConsoleInfo.MaxResistanceLevel;
				if (!console.ConsoleInfo.CanSetResistance && console.ConsoleInfo.CanSetGear)
				{
					value = console.ConsoleInfo.MinGear;
					value2 = console.ConsoleInfo.MaxGear;
				}
				list = list.BoundDataWithoutModification((Workout.Control c) => c.Value, (Workout.Control c, double v) => new Workout.Control
				{
					At = c.At,
					Type = c.Type,
					OverriddenByUser = c.OverriddenByUser,
					Value = v
				}, value, value2);
			}
			float value3 = 0f;
			float value4 = 0f;
			if (list.Count > 1)
			{
				value3 = (float)Math.Floor(list.Min((Workout.Control arg) => arg.Value));
				value4 = (float)Math.Ceiling(list.Max((Workout.Control arg) => arg.Value));
			}
			ResistanceMinimum = RoundToMultipleOf(value3, 2L);
			ResistanceMaximum = RoundToMultipleOf(value4, 2L);
			if (ResistanceMaximum.AlmostEqual(ResistanceMinimum))
			{
				ResistanceMaximum += 2f;
			}
			return list;
		}

		private long RoundToMultipleOf(float value, long multiple)
		{
			float num = value / (float)multiple;
			num = (float)Math.Round(num, MidpointRounding.AwayFromZero);
			return multiple * (long)num;
		}
	}
	public class ElevationAxisScaler : IChartAxisScaler
	{
		private readonly double rawMin;

		private readonly double rawDelta;

		private readonly double targetMin;

		private readonly double targetDelta;

		private readonly bool isPercent;

		public bool IsMetric { get; set; } = true;

		public ElevationAxisScaler(double targetMax, double targetMin, double rawMax, double rawMin, bool isPercent = false)
		{
			this.rawMin = rawMin;
			rawDelta = rawMax - rawMin;
			this.targetMin = targetMin;
			targetDelta = targetMax - targetMin;
			this.isPercent = isPercent;
		}

		public double ScaleValue(double value)
		{
			double num = 0.0;
			double num2 = targetMin + (value - rawMin) * targetDelta / rawDelta;
			if (num2.IsFinite())
			{
				num = (isPercent ? (num2 / 100.0) : num2);
			}
			else
			{
				iFit.Logger.Log.Error("Charting", $"Something went wrong with calculating the scale value. Returning {num}");
			}
			return num;
		}
	}
	public interface IChartAxisScaler
	{
		bool IsMetric { get; set; }

		double ScaleValue(double value);
	}
	public class PredictedGearChartDataProvider : PredictedChartDataProviderBase
	{
		private readonly double minGear;

		private readonly double maxGear;

		public PredictedGearChartDataProvider(IFitnessConsole console, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey = FitnessValue.CurrentTime)
			: base(console, workout, chartType, metricKey, FitnessValue.Gear)
		{
			minGear = console?.ConsoleInfo?.MinGear ?? 1;
			maxGear = console?.ConsoleInfo?.MaxGear ?? 26;
			base.ControlType = Workout.Control.ControlType.Gear;
		}

		public override Task InitAsync()
		{
			List<Tuple<double, double>> scalingRawData = GetScalingRawData();
			if (scalingRawData.Count > 0)
			{
				ProviderData.AddRange(scalingRawData);
			}
			return Task.FromResult(0);
		}

		protected override List<Tuple<double, double>> GetScalingRawData()
		{
			double num = 0.0;
			List<Tuple<double, double>> list = new List<Tuple<double, double>>();
			List<Workout.Control> controlsList = GetControlsList();
			List<Workout.Control> list2 = controlsList.Where((Workout.Control x) => x.Type == base.ControlType).ToList();
			if (list2 != null && list2.Count > 0)
			{
				list.Add(new Tuple<double, double>(0.0, list2.First().Value));
				double num2 = 0.0;
				foreach (Workout.Control item in list2)
				{
					num2 = Math.Min(Math.Max(minGear, item.Value), maxGear);
					list.Add(new Tuple<double, double>(item.At, num2));
				}
				num = Math.Ceiling(workout.TargetValue);
				list.Add(new Tuple<double, double>(num, list2.Last().Value));
			}
			return list;
		}
	}
	public class PredictedHeartRateChartDataProvider : PredictedChartDataProviderBase
	{
		protected int zone1MinimumHR;

		public PredictedHeartRateChartDataProvider(IFitnessConsole console, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey = FitnessValue.CurrentTime)
			: base(console, workout, chartType, metricKey, FitnessValue.Resistance)
		{
		}

		public override async Task InitAsync()
		{
			_ = 1;
			try
			{
				List<Tuple<double, double>> rawData = new List<Tuple<double, double>>();
				if (!Mvx.TryResolve<IIfitApiService>(out var api))
				{
					return;
				}
				Dictionary<int, int> hrZonesAvgHeartRate = new Dictionary<int, int>();
				UserHeartRateSettings userHeartRateSettings = await (await User.GetMe(api)).GetHeartRateSettings(api, force: true);
				foreach (UserHeartRateZone zone in userHeartRateSettings.Zones)
				{
					hrZonesAvgHeartRate[zone.ZoneNumber] = Convert.ToInt32((double)(zone.MinBpm + zone.MaxBpm) / 2.0);
				}
				zone1MinimumHR = userHeartRateSettings.Zones[0].MinBpm;
				for (int i = 1; i <= 5; i++)
				{
					if (!hrZonesAvgHeartRate.ContainsKey(i))
					{
						return;
					}
				}
				if (workout.HeartRateZones.Count == 0)
				{
					return;
				}
				rawData.Add(new Tuple<double, double>(0.0, workout.HeartRateZones.First().Value));
				foreach (Workout.TimestampedValue heartRateZone in workout.HeartRateZones)
				{
					int key = Convert.ToInt32(heartRateZone.Value);
					if (hrZonesAvgHeartRate.ContainsKey(key))
					{
						rawData.Add(new Tuple<double, double>(heartRateZone.At, hrZonesAvgHeartRate[key]));
					}
				}
				double item = Math.Ceiling(workout.TargetValue);
				rawData.Add(new Tuple<double, double>(item, workout.HeartRateZones.Last().Value));
				ProviderData.AddRange(rawData);
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("PredictedHeartRateChartDataProvider", "ERROR getting user HR settings", exception);
			}
		}
	}
