	public class PredictedSmoothHeartRateChartDataProvider : PredictedHeartRateChartDataProvider
	{
		private IDisposable hrMetricSub;

		protected int currentHR;

		protected bool currentHRInserted;

		protected const int DefaultTransitionTime = 30;

		public PredictedSmoothHeartRateChartDataProvider(IFitnessConsole console, Workout workout, ChartMetricConfiguration.MetricType chartType, FitnessValue metricKey = FitnessValue.CurrentTime)
			: base(console, workout, chartType, metricKey)
		{
			PredictedSmoothHeartRateChartDataProvider predictedSmoothHeartRateChartDataProvider = this;
			hrMetricSub?.Dispose();
			IPulseFacade pulseFacade = Mvx.Resolve<IPulseFacade>();
			hrMetricSub = pulseFacade.ObservePulseChanges().Where((Func<FitnessValueChange<Sindarin.Core.DataObjects.Pulse>, bool>)delegate
			{
				IFitnessConsole fitnessConsole = console;
				return fitnessConsole != null && fitnessConsole.LatestBasicInfo?.CurrentState == ConsoleState.Workout;
			}).SubscribeWithErrorLogging(delegate(FitnessValueChange<Sindarin.Core.DataObjects.Pulse> x)
			{
				predictedSmoothHeartRateChartDataProvider.currentHR = x.Current.UserPulse;
			});
		}

		protected override void UpdateData()
		{
			double latestKeyForType = GetLatestKeyForType(KeyMetric);
			List<Tuple<double, double>> addList = AddTransitionFromCurrentHRToTarget(latestKeyForType);
			ProviderData.RemoveAllAndAddList(addList);
		}

		protected List<Tuple<double, double>> AddTransitionFromCurrentHRToTarget(double currentTime)
		{
			List<Tuple<double, double>> list = ProviderData.ToList();
			if (currentHRInserted)
			{
				Tuple<double, double> tuple = list.ElementAtOrDefault(0);
				Tuple<double, double> tuple2 = list.ElementAtOrDefault(1);
				double item = tuple.Item1;
				double item2 = tuple2.Item2;
				list.RemoveRange(0, 2);
				Tuple<double, double> item3 = new Tuple<double, double>(item, item2);
				list.Insert(0, item3);
				currentHRInserted = false;
			}
			Tuple<double, double> tuple3 = list.LastOrDefault((Tuple<double, double> x) => x.Item1 <= currentTime);
			if (tuple3 == null)
			{
				return list;
			}
			list.RemoveAll((Tuple<double, double> x) => x.Item1 <= currentTime);
			if (currentHR > 0)
			{
				Tuple<double, double> tuple4 = list.FirstOrDefault();
				int num = ForwardProject(tuple4, currentTime);
				if (tuple4 != null && tuple4.Item1 < currentTime + (double)num)
				{
					num = ((int)tuple4.Item1 - (int)currentTime) / 2;
				}
				int num2 = Math.Max(currentHR, zone1MinimumHR);
				Tuple<double, double> item4 = new Tuple<double, double>(currentTime, num2);
				Tuple<double, double> item5 = new Tuple<double, double>(currentTime + (double)num, tuple3.Item2);
				list.Insert(0, item5);
				list.Insert(0, item4);
				currentHRInserted = true;
			}
			else
			{
				Tuple<double, double> item6 = new Tuple<double, double>(currentTime, tuple3.Item2);
				list.Insert(0, item6);
			}
			list.Insert(0, new Tuple<double, double>(currentTime, 0.0));
			return list;
		}

		private int ForwardProject(Tuple<double, double> nextTargetHR, double currentTime)
		{
			int num = 30;
			if (nextTargetHR != null && nextTargetHR.Item1 < currentTime + (double)num)
			{
				num = ((int)nextTargetHR.Item1 - (int)currentTime) / 2;
			}
			return num;
		}

		public override void Dispose()
		{
			base.Dispose();
			hrMetricSub?.Dispose();
			hrMetricSub = null;
		}
	}
