namespace Shire.Core.Services.Pulse
{
	public interface IActivePulseService
	{
		Task<WorkoutScaleResponse> WorkoutScaleCheck(WorkoutScaleRequest workoutScaleRequest, string logLevel);

		void InjectScale(ActivePulseService.InjectScaleLevel scaleLevel);

		void InjectTriggerPause();
	}
	public class ActivePulseService : IActivePulseService
	{
		public enum InjectScaleLevel
		{
			Plus1,
			Plus2,
			Minus1,
			Minus2,
			Zero,
			Nope
		}

		private readonly IIfitApiService ifitApiService;

		private InjectScaleLevel injectScaleLevel = InjectScaleLevel.Nope;

		private bool needTriggerPause;

		private WorkoutScaleResponse lastResponse;

		private bool NeedAnyInjection
		{
			get
			{
				if (lastResponse != null)
				{
					if (injectScaleLevel == InjectScaleLevel.Nope)
					{
						return needTriggerPause;
					}
					return true;
				}
				return false;
			}
		}

		public ActivePulseService(IIfitApiService ifitApiService)
		{
			this.ifitApiService = ifitApiService;
		}

		public async Task<WorkoutScaleResponse> WorkoutScaleCheck(WorkoutScaleRequest workoutScaleRequest, string logLevel)
		{
			if (NeedAnyInjection)
			{
				iFit.Logger.Log.Trace("ScalingControl", string.Format("{0}::{1}():{2} is true. Injecting last response. {3} is {4}", "ActivePulseService", "WorkoutScaleCheck", "NeedAnyInjection", "injectScaleLevel", injectScaleLevel));
				return InjectLastResponse();
			}
			lastResponse = await ifitApiService.GatewayService.WorkoutScaleCheck(workoutScaleRequest, logLevel).ConfigureAwait(continueOnCapturedContext: false);
			return lastResponse;
		}

		public void InjectScale(InjectScaleLevel scaleLevel)
		{
			injectScaleLevel = scaleLevel;
		}

		public void InjectTriggerPause()
		{
			needTriggerPause = true;
		}

		private WorkoutScaleResponse InjectLastResponse()
		{
			if (needTriggerPause)
			{
				needTriggerPause = false;
				lastResponse.TriggerPause = true;
			}
			if (injectScaleLevel != InjectScaleLevel.Nope)
			{
				lastResponse.Scale = injectScaleLevel.ToScale();
				injectScaleLevel = InjectScaleLevel.Nope;
			}
			return lastResponse;
		}
	}
	public static class InjectScaleLevelExtensions
	{
		public static string ToScale(this ActivePulseService.InjectScaleLevel lvl)
		{
			return lvl switch
			{
				ActivePulseService.InjectScaleLevel.Minus1 => "minus_1", 
				ActivePulseService.InjectScaleLevel.Minus2 => "minus_2", 
				ActivePulseService.InjectScaleLevel.Plus1 => "plus_1", 
				ActivePulseService.InjectScaleLevel.Plus2 => "plus_2", 
				ActivePulseService.InjectScaleLevel.Zero => "zero", 
				_ => "", 
			};
		}
	}
}
