	public class WorkoutVideo
	{
		public class Timestamp : List<int>
		{
			public int Start
			{
				get
				{
					if (base.Count < 1)
					{
						return 0;
					}
					return this.Min();
				}
			}

			public int End
			{
				get
				{
					if (base.Count < 2)
					{
						return Start;
					}
					return this.Max();
				}
			}

			public bool IsValid
			{
				get
				{
					if (base.Count >= 2)
					{
						return End > Start;
					}
					return false;
				}
			}

			public Timestamp()
			{
			}

			public Timestamp(int capacity)
				: base(capacity)
			{
			}

			public Timestamp(int start, int end)
				: base(2)
			{
				Add(start);
				Add(end);
			}

			public override string ToString()
			{
				return string.Format("[{0} {1}={2}, {3}={4}, {5}={6}]", "Timestamp", "Start", Start, "End", End, "IsValid", IsValid);
			}

			public override bool Equals(object obj)
			{
				if (obj == null)
				{
					return false;
				}
				if (obj == this)
				{
					return true;
				}
				if (obj is Timestamp timestamp)
				{
					if (Start == timestamp.Start && End == timestamp.End)
					{
						return IsValid == timestamp.IsValid;
					}
					return false;
				}
				return false;
			}

			public override int GetHashCode()
			{
				return ToString().GetHashCode();
			}
		}

