namespace Shire.Core.FitPro
{
	public interface IFitnessConsoleRegisterService
	{
		Task<bool> Register(IFitnessConsole console, IIfitApiService ifitApi);
	}
	public class FitnessConsoleRegisterService : IFitnessConsoleRegisterService
	{
		public async Task<bool> Register(IFitnessConsole console, IIfitApiService ifitApi)
		{
			if (console?.ConsoleInfo == null)
			{
				iFit.Logger.Log.Trace("UserEquipment", "Could not create user equipment, console was null.");
				return false;
			}
			if (console.IsNonconnectedConsole())
			{
				iFit.Logger.Log.Trace("UserEquipment", "Do not register NonConnected Devices.");
				return false;
			}
			if (!ifitApi.HasLoggedInUser)
			{
				iFit.Logger.Log.Trace("UserEquipment", "Could not create user equipment, user is not logged in.");
				return false;
			}
			ConsoleInfoFromJson consoleInfo = ConsoleInfoFromJson.ConsoleInfoToConsoleInfoJson(console.ConsoleInfo);
			UserEquipment userEquipment = new UserEquipment
			{
				MachineId = console.ConsoleInfo.BrainboardSerialNumber,
				SoftwareNumber = console.ConsoleInfo.PartNumber,
				ConsoleInfo = consoleInfo
			};
			try
			{
				await userEquipment.CreateOrUpdate(ifitApi);
				return true;
			}
			catch (ConnectivityException)
			{
				iFit.Logger.Log.Trace("UserEquipment", "Could not create user equipment, internet was lost");
			}
			catch (ApiException ex2)
			{
				iFit.Logger.Log.Trace("UserEquipment", "Unable to add user equipment due to: " + ex2.Message);
			}
			return false;
		}
	}
}
namespace Shire.Core.FitPro.Updater
{
	public class FirmwareFile
	{
		public const string SoftdeviceAndBootloader = "softdeviceandbootloader";

		private const byte SoftdeviceAndBootloaderFileType = 3;

		private const byte ApplicationFileType = 4;

		public string Url { get; set; }

		public string Name { get; set; }

		public string Version { get; set; }

		public string Type { get; set; }

		public string MetadataUrl { get; set; }

		public string BootloaderUrl { get; set; }

		public string Model { get; set; }

		public string Build { get; set; }

		public string Time { get; set; }

		public string PartNumber { get; set; }

		public bool Approved { get; set; }

		public byte[] Bin { get; private set; }

		public byte[] Metadata { get; private set; }

		public byte[] Bootloader { get; private set; }

		public bool IsFileSoftDeviceAndBootloader => Type == "softdeviceandbootloader";

		public byte FileType
		{
			get
			{
				if (!IsFileSoftDeviceAndBootloader)
				{
					return 4;
				}
				return 3;
			}
		}

		public byte[] FileSize
		{
			get
			{
				byte[] array = new byte[12];
				if (IsFileSoftDeviceAndBootloader)
				{
					SetIntBackwards(array, 0, 4, Bin.Length);
					SetIntBackwards(array, 4, 4, Bootloader.Length);
				}
				else
				{
					SetIntBackwards(array, 8, 4, Bin.Length);
				}
				return array;
			}
		}

		public void SetDownloadedFiles(byte[] bin, byte[] metadata, byte[] bootloader)
		{
			Bin = bin;
			Metadata = metadata;
			Bootloader = bootloader;
		}

		protected void SetIntBackwards(byte[] data, int index, int length, int value)
		{
			for (int i = 0; i < length; i++)
			{
				byte b = (byte)((value >> i * 8) % 256);
				data[index + i] = b;
			}
		}
	}
