namespace Shire.Core.Converters
{
	public class BleDeviceNameConverter : MvxValueConverter<IBleDevice, string>
	{
		private readonly IBleDeviceSupplementaryDataService supplementaryDataService;

		private readonly string defaultName;

		public BleDeviceNameConverter(IBleDeviceSupplementaryDataService supplementaryDataService, string defaultName = "")
		{
			this.supplementaryDataService = supplementaryDataService;
			this.defaultName = defaultName;
		}

		protected override string Convert(IBleDevice value, Type targetType, object parameter, CultureInfo culture)
		{
			return ConvertName(value);
		}

		public string ConvertName(IBleDevice device)
		{
			if (device == null || supplementaryDataService == null)
			{
				return device?.Name?.Trim() ?? defaultName;
			}
			BleHardwareTypeInfo hardwareTypeInfo = device.GetHardwareTypeInfo();
			if (hardwareTypeInfo == null || hardwareTypeInfo.DeviceHardwareType?.Length != 2)
			{
				return device.Name?.Trim() ?? defaultName;
			}
			string hardwareTypeKey = $"{hardwareTypeInfo.DeviceHardwareType[0]:X2}{hardwareTypeInfo.DeviceHardwareType[1]:X2}";
			BleDeviceSupplementaryData bleDeviceSupplementaryData = supplementaryDataService.SupplementaryDataForDevice(hardwareTypeKey);
			if (string.IsNullOrWhiteSpace(bleDeviceSupplementaryData?.Name))
			{
				return device.Name?.Trim() ?? defaultName;
			}
			return bleDeviceSupplementaryData.Name.Trim();
		}
	}
	[MvxUnconventional]
	public class BoolToFloatValueConverter : MvxValueConverter<bool, float>
	{
		public readonly float falseValue;

		public readonly float trueValue;

		public BoolToFloatValueConverter(float trueValue = 1f, float falseValue = 0f)
		{
			this.falseValue = falseValue;
			this.trueValue = trueValue;
		}

		protected override float Convert(bool value, Type targetType, object parameter, CultureInfo culture)
		{
			if (!value)
			{
				return falseValue;
			}
			return trueValue;
		}

		protected override bool ConvertBack(float value, Type targetType, object parameter, CultureInfo culture)
		{
			return value.Equals(trueValue);
		}
	}
	public class BoolToStringConverter : MvxValueConverter<bool?, string>
	{
		private readonly string trueValue;

		private readonly string falseValue;

		private readonly string nullValue;

		public BoolToStringConverter(string trueValue, string falseValue, string nullValue = null)
		{
			this.trueValue = trueValue;
			this.falseValue = falseValue;
			this.nullValue = nullValue;
		}

		protected override string Convert(bool? value, Type targetType, object parameter, CultureInfo culture)
		{
			if (!value.HasValue)
			{
				return nullValue;
			}
			if (value.Value)
			{
				return trueValue;
			}
			return falseValue;
		}

		protected override bool? ConvertBack(string value, Type targetType, object parameter, CultureInfo culture)
		{
			if (string.Equals(trueValue, value))
			{
				return true;
			}
			if (string.Equals(falseValue, value))
			{
				return false;
			}
			return null;
		}
	}
