				num = 1.0;
			}
			return value / num;
		}
	}
	public class DoubleToIntValueConverter : MvxValueConverter<double, int>
	{
		public enum DoubleRoundingMode
		{
			Ceiling,
			Nearest,
			Floor
		}

		public DoubleRoundingMode RoundingMode { get; set; }

		public DoubleToIntValueConverter(DoubleRoundingMode roundingMode = DoubleRoundingMode.Nearest)
		{
			RoundingMode = roundingMode;
		}

		protected override int Convert(double value, Type targetType, object parameter, CultureInfo culture)
		{
			double value2 = 0.0;
			switch (RoundingMode)
			{
			case DoubleRoundingMode.Ceiling:
				value2 = Math.Ceiling(value);
				break;
			case DoubleRoundingMode.Nearest:
				value2 = Math.Round(value);
				break;
			case DoubleRoundingMode.Floor:
				value2 = Math.Floor(value);
				break;
			}
			return System.Convert.ToInt32(value2);
		}

		protected override double ConvertBack(int value, Type targetType, object parameter, CultureInfo culture)
		{
			return value;
		}
	}
