	public abstract class NumberToStringValueConverter<TNumber> : MvxValueConverter<TNumber, string> where TNumber : IFormattable
	{
		private readonly string prefix;

		private readonly string format;

		public NumberToStringValueConverter(int decimalPlaces = -1, bool showLeadingZero = true, bool showThousandSeparator = false, string prefix = null)
		{
			this.prefix = prefix;
			if (decimalPlaces < 0)
			{
				format = "{0}";
				return;
			}
			StringBuilder stringBuilder = new StringBuilder();
			if (showThousandSeparator)
			{
				stringBuilder.Append("n");
				if (decimalPlaces >= 0)
				{
					stringBuilder.Append(decimalPlaces);
				}
			}
			else
			{
				if (showLeadingZero || decimalPlaces < 1)
				{
					stringBuilder.Append("0");
				}
				else
				{
					stringBuilder.Append("#");
				}
				if (decimalPlaces >= 0)
				{
					stringBuilder.Append(".");
					for (int i = 0; i < decimalPlaces; i++)
					{
						stringBuilder.Append("0");
					}
				}
			}
			format = "{0:" + stringBuilder?.ToString() + "}";
		}

		protected override string Convert(TNumber value, Type targetType, object parameter, CultureInfo culture)
		{
			return (prefix ?? string.Empty) + string.Format(format, value);
		}
	}
