	public class StringConcatenationConverter : IMvxValueConverter
	{
		public enum StringConcatenationMode
		{
			ParameterSecond,
			ParameterFirst
		}

		public enum StringTransformationMode
		{
			Default,
			Uppercase,
			Lowercase
		}

		public StringConcatenationMode ConcatenationMode { get; set; } = StringConcatenationMode.ParameterFirst;

		public bool SpaceSeparating { get; set; }

		public StringTransformationMode TransformationMode { get; set; }

		public object Convert(object value, Type targetType, object parameter, CultureInfo culture)
		{
			string text = "";
			switch (ConcatenationMode)
			{
			case StringConcatenationMode.ParameterFirst:
				text = string.Format("{0}{1}{2}", parameter, SpaceSeparating ? " " : "", value);
				break;
			case StringConcatenationMode.ParameterSecond:
				text = string.Format("{0}{1}{2}", value, SpaceSeparating ? " " : "", parameter);
				break;
			}
			if (TransformationMode == StringTransformationMode.Lowercase)
			{
				text = text.ToLower();
			}
			if (TransformationMode == StringTransformationMode.Uppercase)
			{
				text = text.ToUpper();
			}
			return text;
		}

		public object ConvertBack(object value, Type targetType, object parameter, CultureInfo culture)
		{
			return value;
		}
	}
	[MvxUnconventional]
	public class StringValidBoolValueConverter : MvxValueConverter<string, bool>
	{
		public enum NullConversionSetting
		{
			FalseIfNull,
			TrueIfNull
		}

		public NullConversionSetting ConversionSetting { get; set; }

		public StringValidBoolValueConverter(NullConversionSetting conversionSetting = NullConversionSetting.FalseIfNull)
		{
			ConversionSetting = conversionSetting;
		}

		protected override bool Convert(string value, Type targetType, object parameter, CultureInfo culture)
		{
			bool flag = ConversionSetting == NullConversionSetting.TrueIfNull;
			if (!string.IsNullOrWhiteSpace(value))
			{
				return !flag;
			}
			return flag;
		}
	}
	public class TimeSecondsFormatterValueConverter : MvxValueConverter<double, string>
	{
		protected override string Convert(double value, Type targetType, object parameter, CultureInfo culture)
		{
			return ValueFormatters.SecondsFormatter.Format(value);
		}
	}
	public class TrailingColonValueConverter : MvxValueConverter<string, string>
	{
		protected override string Convert(string value, Type targetType, object parameter, CultureInfo culture)
		{
			return AddTrailingColon(value);
		}

		public static string AddTrailingColon(string input)
		{
			return input + ":";
		}
	}
	public static class TypeResolver
	{
		public static bool GetBool(object obj, bool defaultValue = false)
		{
			bool result = defaultValue;
			if (obj is NC<bool> nC)
			{
				result = nC.Value;
			}
			else if (obj != null)
			{
				result = (bool)obj;
			}
			return result;
		}
	}
	public class UpperCaseValueConverter : MvxValueConverter<string, string>
	{
		protected override string Convert(string value, Type targetType, object parameter, CultureInfo culture)
		{
			return value.ToUpper();
		}
	}
	public class ValueConverterDecorator<TStart, TFinish> : MvxValueConverter<TStart, TFinish>
	{
		private readonly IEnumerable<IMvxValueConverter> converters;

		public ValueConverterDecorator(params IMvxValueConverter[] converters)
		{
			this.converters = converters;
		}

		protected override TFinish Convert(TStart value, Type targetType, object parameter, CultureInfo culture)
		{
			object obj = value;
			foreach (IMvxValueConverter converter in converters)
			{
				obj = converter.Convert(obj, targetType, parameter, culture);
			}
			return (TFinish)obj;
		}
	}
