namespace Shire.Core.ConnectedApps.HealthKit
{
	public class HealthKitStat
	{
		public DateTime Timestamp { get; set; }

		public double Value { get; set; }

		public HealthKitStat(DateTime timestamp, double value)
		{
			Timestamp = timestamp;
			Value = value;
		}
	}
	public class HKWorkoutToMetricStatsTranslator : IHKWorkoutToMetricStatsTranslator
	{
		public MetricStats ToMetricStats(IHKWorkoutWrapper workout)
		{
			if (workout == null)
			{
				throw new ArgumentNullException("workout", "IHKWorkoutWrapper must be non-null");
			}
			return CreateMetricStatGroup(workout);
		}

		private MetricStats CreateMetricStatGroup(IHKWorkoutWrapper workout)
		{
			MetricStats metricStats = new MetricStats();
			PopulateMetricStatListWithFallback(metricStats.CalorieChanges, workout.Calories, workout, transformToCumulativeSum: true, workout.TotalCalories, "calorie");
			PopulateMetricStatListWithFallback(metricStats.DistanceChanges, workout.WalkRunDistances.IsNullOrEmpty() ? workout.CycleDistances : workout.WalkRunDistances, workout, transformToCumulativeSum: true, workout.TotalDistance, "distance");
			PopulateMetricStatListWithFallback(metricStats.VerticalMetersNetChanges, workout.ElevationGained, workout, transformToCumulativeSum: true, workout.TotalElevationGain, "elevationGain");
			PopulateMetricStatList(metricStats.PulseChanges, workout.HeartRates, workout, transformToCumulativeSum: false, "heartrate");
			return metricStats;
		}

		private void PopulateMetricStatListWithFallback(MetricStatList destination, List<HealthKitStat> source, IHKWorkoutWrapper workout, bool transformToCumulativeSum, double summaryFallbackValue, string statTypeDebugName = "")
		{
			double num = PopulateMetricStatList(destination, source, workout, transformToCumulativeSum, statTypeDebugName);
			if (num < summaryFallbackValue)
			{
				destination.Clear();
				destination.RecordStat(0.0, 0.0);
				destination.RecordStat(workout.DurationInSeconds, summaryFallbackValue);
			}
		}

		private double PopulateMetricStatList(MetricStatList destination, List<HealthKitStat> source, IHKWorkoutWrapper workout, bool transformToCumulativeSum, string statTypeDebugName = "")
		{
			double num = 0.0;
			foreach (HealthKitStat item in source)
			{
				if (!TimestampIsWithinWorkoutTimeFrame(item.Timestamp, workout.StartDateUtc, workout.EndDateUtc))
				{
					iFit.Logger.Log.Debug("HealthKit", $"Skipping {statTypeDebugName} stat ${item.Timestamp} ${item.Value} when converting HealthKitStat List to MetricStatList - stat is not contained within hkworkout timeframe (start: {workout.StartDateUtc} end: {workout.EndDateUtc})");
				}
				else
				{
					double totalSeconds = (item.Timestamp - workout.StartDateUtc).TotalSeconds;
					double num2 = (transformToCumulativeSum ? (item.Value + num) : item.Value);
					num = num2;
					destination.RecordStat(totalSeconds, num2);
				}
			}
			if (destination.Count > 0 && destination.Last.Timestamp != (double)workout.DurationInSeconds)
			{
				destination.RecordStat(workout.DurationInSeconds, destination.Last.Value);
			}
			return num;
		}

		private bool TimestampIsWithinWorkoutTimeFrame(DateTime timestamp, DateTime startDate, DateTime endDate)
		{
			if (startDate <= timestamp)
			{
				return timestamp <= endDate;
			}
			return false;
		}
	}
	public interface IHKWorkoutToMetricStatsTranslator
	{
		MetricStats ToMetricStats(IHKWorkoutWrapper workout);
	}
	public interface IHKWorkoutWrapper
	{
		DateTime StartDateUtc { get; }

