namespace Shire.Core.ConnectedApps.Api.DataObjects
{
	public class AuthorizationResult
	{
		public const string ParamThirdPartyConnectionSuccess = "thirdPartyConnectionSuccess";

		public const string ParamErrorMessage = "errorMessage";

		public const string ParamCode = "code";

		public const string ParamTextCode = "textCode";

		[JsonProperty("thirdPartyConnectionSuccess")]
		public bool ThirdPartyConnectionSuccess { get; set; }

		[JsonProperty("errorMessage")]
		public string ErrorMessage { get; set; }

		[JsonProperty("code")]
		public int Code { get; set; }

		[JsonProperty("textCode")]
		public string TextCode { get; set; }

		public AuthorizationResult()
		{
		}

		public AuthorizationResult(IDictionary<string, string> obj)
		{
			if (obj.TryGetValue("thirdPartyConnectionSuccess", out var value))
			{
				value = RemoveSpecialCharacters(value);
				bool.TryParse(value, out var result);
				ThirdPartyConnectionSuccess = result;
			}
			if (obj.TryGetValue("errorMessage", out var value2))
			{
				ErrorMessage = value2;
			}
			if (obj.TryGetValue("code", out var value3))
			{
				int.TryParse(value3, out var result2);
				Code = result2;
			}
			if (obj.TryGetValue("textCode", out var value4))
			{
				TextCode = value4;
			}
		}

		public override string ToString()
		{
			return JsonConvert.SerializeObject(this);
		}

		private string RemoveSpecialCharacters(string source)
		{
			return Regex.Replace(source, "[^a-zA-Z0-9_.]+", "", RegexOptions.Compiled);
		}
	}
