namespace Shire.Core.ConnectedApps.Api.DataObjects.Converters
{
	public class SyncSettingsConverter : JsonConverter
	{
		public override bool CanConvert(Type objectType)
		{
			return typeof(ISyncSettings).IsAssignableFrom(objectType);
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			JObject jObject = JObject.Load(reader);
			ISyncSettings syncSettings = Create(objectType, jObject);
			serializer.Populate(jObject.CreateReader(), syncSettings);
			return syncSettings;
		}

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			serializer.Serialize(writer, value);
		}

		private ISyncSettings Create(Type objectType, JObject jsonObject)
		{
			if (jsonObject["toThirdParty"] != null)
			{
				return new TwoWaySyncSettings();
			}
			if (jsonObject["fromThirdParty"] != null)
			{
				return new OneWaySyncSettings();
			}
			throw new NotSupportedException(string.Format("Not supported {0} object: {1}", "ISyncSettings", jsonObject));
		}
	}
