namespace Shire.Core.Competitions
{
	public class CompetitionLog
	{
		public class Second
		{
			private double initialPausedTime;

			private readonly User user;

			private readonly ConsoleStateStats consoleStateStats;

			private readonly IConsoleInfo consoleInfo;

			private readonly IConsoleBasicInfo latestBasicInfo;

			private readonly IWorkoutRunner workoutRunner;

			protected JsonBuilder Builder;

			private const int DigitsToRoundTo = 3;

			private const int XScoreRound = 0;

			public CumulativeWattHours CumulativeWHrs { get; set; }

			private double Time => workoutRunner?.WorkoutRunningSeconds ?? 0.0;

			private double Distance => latestBasicInfo?.DistanceMeters ?? 0.0;

			private double Mps => GetMps();

			private double Grade => latestBasicInfo?.Grade ?? 0.0;

			private double VerticalGain => latestBasicInfo?.VerticalMetersGain ?? 0.0;

			private double VerticalNet => latestBasicInfo?.VerticalMetersNet ?? 0.0;

			private double Resistance => latestBasicInfo?.Resistance ?? 0.0;

			private double Pulse => (latestBasicInfo?.CurrentPulse?.UserPulse).GetValueOrDefault();

			private double PausedTime => Math.Max(((double?)latestBasicInfo?.PausedTime) ?? (0.0 - initialPausedTime), 0.0);

			private double Strokes => (consoleStateStats?.RunningStats?.StrokeChanges?.Last?.Value).GetValueOrDefault();

			private double Calories => (consoleStateStats?.RunningStats?.CalorieChanges?.Last?.Value).GetValueOrDefault();

			private double EffortScore => (consoleStateStats?.RunningStats?.XScore?.Last?.Value).GetValueOrDefault();

			private async Task<double> GetTotalRotations()
			{
				if (consoleStateStats?.RunningStats == null)
				{
					return 0.0;
				}
				return await consoleStateStats.RunningStats.GetAverageRpm(Time) * Time / 60.0;
			}

			private async Task<double> GetWattHoursFromConsole()
			{
				if (consoleStateStats?.RunningStats == null)
				{
					return 0.0;
				}
				return await (consoleStateStats.RunningStats?.GetAverageWatts(Time)) * Time / 3600.0;
			}

			private string GetGenderFromUser()
			{
				return user.Gender switch
				{
					"male" => "M", 
					"female" => "F", 
					"nonbinary" => "NB", 
					_ => "-", 
				};
			}

			public Second(User user, IConsoleInfo consoleInfo, IConsoleBasicInfo latestBasicInfo, ConsoleStateStats consoleStateStats, IWorkoutRunner workoutRunner, string workoutId, Workout.TargetType workoutTargetType, string wolfGeneratedId, double? initialPausedTime = null)
			{
				this.user = user;
				this.consoleInfo = consoleInfo;
				this.latestBasicInfo = latestBasicInfo;
				this.consoleStateStats = consoleStateStats;
				this.workoutRunner = workoutRunner;
				this.initialPausedTime = initialPausedTime.GetValueOrDefault();
				Builder = new JsonBuilder();
				if (user != null)
				{
					Builder.AddString("u", user.Id);
					Builder.AddString("g", GetGenderFromUser());
					Builder.AddInt("a", user.Age);
					Builder.AddBool("p", user.Private == true);
					Builder.AddDouble("k", UnitUtil.Round(user.Weight, 3));
				}
				if (consoleInfo != null)
				{
					Builder.AddInt("sw", consoleInfo.PartNumber);
					Builder.AddString("e", consoleInfo.MachineType.ToString());
					Builder.AddDouble("xm", UnitUtil.EnsureMps(SpeedUnit.Kph, consoleInfo.MaxKph, 3));
					Builder.AddDouble("mi", consoleInfo.MinIncline);
					Builder.AddDouble("xi", consoleInfo.MaxIncline);
					Builder.AddDouble("xr", consoleInfo.MaxResistanceLevel);
				}
				Builder.AddString("mf", (workoutTargetType == Workout.TargetType.Meters) ? "meters" : "seconds");
				Builder.AddString("w", workoutId);
				Builder.AddString("al", wolfGeneratedId);
			}

			public void AddRawMetrics()
			{
				Builder.AddDouble("s", Time);
				Builder.AddDouble("m", UnitUtil.Round(Distance, 3));
				Builder.AddDouble("j", UnitUtil.Round(Mps, 3));
				Builder.AddDouble("i", UnitUtil.Round(Grade, 3));
				IConsoleInfo obj = consoleInfo;
				if (obj != null && obj.MachineType.IsRower())
				{
					Builder.AddDouble("sm", UnitUtil.Round(Strokes, 3));
				}
				Builder.AddDouble("eg", UnitUtil.Round(VerticalGain, 3));
				Builder.AddDouble("en", UnitUtil.Round(VerticalNet, 3));
				Builder.AddDouble("rs", UnitUtil.Round(Resistance, 3));
				Builder.AddDouble("ps", PausedTime);
				Builder.AddInt("b", (int)UnitUtil.Round(Pulse, 0));
			}

			public void AddDecorators(bool followingSpeed, bool followingIncline, bool followingResistance)
			{
				Builder.AddBool("fs", followingSpeed);
				Builder.AddBool("fi", followingIncline);
				Builder.AddBool("fr", followingResistance);
			}

			public void AddCumulativeOverrideSeconds(double speedSeconds, double inclineSeconds, double resistanceSeconds)
			{
				Builder.AddInt("mss", (int)speedSeconds);
				Builder.AddInt("mis", (int)inclineSeconds);
				Builder.AddInt("mrs", (int)resistanceSeconds);
			}

			public async Task AddCalculatedMetrics()
			{
				try
				{
					double num;
					if (CompetitionCalculations.ShouldCalculateWatts(latestBasicInfo, consoleInfo))
					{
						if (CumulativeWHrs == null)
						{
							CumulativeWHrs = new CumulativeWattHours();
						}
						num = CompetitionCalculations.CalculateWattHours(user, latestBasicInfo, consoleInfo, CumulativeWHrs);
						CumulativeWHrs.Update(num, latestBasicInfo);
					}
					else
					{
						num = await GetWattHoursFromConsole();
					}
					Builder.AddDouble("wa", UnitUtil.Round(num, 3));
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Workout", "ERROR calculating watt hours", exception);
				}
				if (consoleInfo != null && !consoleInfo.MachineType.IsRower() && !consoleInfo.MachineType.IsBeltBasedMachine())
				{
					double value = await GetTotalRotations();
					Builder.AddDouble("r", UnitUtil.Round(value, 3));
				}
				Builder.AddDouble("c", UnitUtil.Round(Calories, 3));
				Builder.AddDouble("xs", UnitUtil.Round(EffortScore, 0));
			}

			public void HandleLastMoment(Workout.TargetType target, double targetValue)
			{
				Builder.AddBool("lm", value: true);
				if (target == Workout.TargetType.Seconds && Time < targetValue)
				{
					Builder.RemoveElement("s");
					Builder.AddDouble("s", targetValue);
				}
				if (target == Workout.TargetType.Meters && (latestBasicInfo?.DistanceMeters ?? 0.0) < targetValue)
				{
					Builder.RemoveElement("m");
					Builder.AddDouble("m", targetValue);
				}
			}

			public string ToJson()
			{
				return Builder.ToString();
			}

			private double GetMps()
			{
				if (latestBasicInfo == null)
				{
					return 0.0;
				}
				IConsoleInfo obj = consoleInfo;
				FitnessValue fitnessValue = ((obj != null && !obj.MachineType.IsBeltBasedMachine()) ? FitnessValue.ActualKph : FitnessValue.Kph);
				double value = ((fitnessValue == FitnessValue.ActualKph) ? latestBasicInfo.ActualKph : latestBasicInfo.Kph);
				return UnitUtil.EnsureMps(SpeedUnit.Kph, value, 3);
			}
		}

		protected string Topic;

		protected string ClientId;

		protected IMqttPipe Pipe;

		protected readonly IFeatureFlagManager featureFlagManager;

		protected User ActiveUser;

		protected Workout Workout;

		protected string WolfGeneratedId;

		protected Second LastSecond;

		protected CumulativeWattHours CumulativeWHrs = new CumulativeWattHours();

		protected ConsoleStateStats consoleStateStats;

		private CompetitionOverride speedOverride = new CompetitionOverride(typeof(UserOverrideSpeedDecorator));

		private CompetitionOverride inclineOverride = new CompetitionOverride(typeof(UserOverrideInclineDecorator));

		private CompetitionOverride resistanceOverride = new CompetitionOverride(typeof(UserOverrideResistanceDecorator));

		private CompetitionOverride gearOverride = new CompetitionOverride(typeof(UserOverrideGearDecorator));

		private List<CompetitionOverride> competitionOverrides;

		private double? initialPausedTime;

		private IWorkoutRunner workoutRunner;

		public IFitnessConsole Console { get; private set; }

		protected string WorkoutId => Workout.Id;

		private CompetitionOverride ShouldUseResistanceOrGearOverride
		{
			get
			{
				if (!gearOverride.Enabled && !(gearOverride.TotalSecondsEnabled > 0.0))
				{
					return resistanceOverride;
				}
				return gearOverride;
			}
		}

		public CompetitionLog(User user, IFitnessConsole console, IFeatureFlagManager featureFlagManager, Workout workout, IWorkoutRunner workoutRunner, string wolfGeneratedId, CompetitionActivity recoveredLog, ConsoleStateStats consoleStateStats = null)
		{
			Console = console;
			ActiveUser = user;
			Workout = workout;
			this.workoutRunner = workoutRunner;
			WolfGeneratedId = wolfGeneratedId;
			this.featureFlagManager = featureFlagManager;
			this.consoleStateStats = consoleStateStats;
			competitionOverrides = new List<CompetitionOverride> { speedOverride, inclineOverride, resistanceOverride, gearOverride };
			if (recoveredLog != null)
			{
				LoadRecoveredLogValues(recoveredLog);
			}
		}

		private void LoadRecoveredLogValues(CompetitionActivity log)
		{
			int valueOrDefault = (log?.seconds?.LastOrDefault()).GetValueOrDefault();
			if (valueOrDefault <= 0)
			{
				iFit.Logger.Log.Trace("Workout", "Recovered log had invalid seconds");
			}
			else
			{
				CumulativeWHrs = new CumulativeWattHours(log.watts.LastOrDefault(), log.meters.LastOrDefault(), valueOrDefault);
			}
		}

		public async Task InitializeAndConnectAsync(MqttClientConfigs configs)
		{
			if (Pipe == null)
			{
				if (!Mvx.TryResolve<IMqttPipe>(out var service))
				{
					iFit.Logger.Log.Error("Workout", "ERROR resolving IMqttPipe for Competitions.");
					return;
				}
				iFit.Logger.Log.Trace("Workout", "CompetitionLog: init with new pipe");
				Pipe = service;
			}
			else if (Pipe?.IsConnected ?? false)
			{
				iFit.Logger.Log.Trace("Workout", "CompetitionLog: init with already-connected pipe. Doing nothing.");
				return;
			}
			Topic = configs.Topic;
			await Pipe.InitializeClientAndConnect(configs).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task AddSecondWithInfo(IList<IControlDecorator> decorators)
		{
			if (!initialPausedTime.HasValue)
			{
				if (Console.LatestBasicInfo.PausedTime > Console.LatestBasicInfo.RunningTime)
				{
					initialPausedTime = Console.LatestBasicInfo.PausedTime;
				}
				else
				{
					initialPausedTime = 0.0;
				}
			}
			Second second = new Second(ActiveUser, Console?.ConsoleInfo, Console?.LatestBasicInfo, consoleStateStats, workoutRunner, WorkoutId, Workout?.Target ?? Workout.TargetType.Seconds, WolfGeneratedId, initialPausedTime);
			second.CumulativeWHrs = CumulativeWHrs;
			second.AddRawMetrics();
			AddDecorators(decorators, second);
			await second.AddCalculatedMetrics();
			LastSecond = second;
			try
			{
				if (Pipe != null)
				{
					await Pipe.PutRecord(Topic, second.ToJson()).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception exception)
			{
				if (featureFlagManager.IsFeatureEnabled(FeatureFlags.LogMQTTVerbose))
				{
					iFit.Logger.Log.Error("Workout", "ERROR putting mqtt record", exception);
				}
			}
		}

		public void AddDecorators(IList<IControlDecorator> decorators, Second s)
		{
			foreach (IControlDecorator decorator in decorators)
			{
				competitionOverrides.FirstOrDefault((CompetitionOverride x) => x.Decorator == decorator.GetType())?.Update(decorator.Enabled, workoutRunner.WorkoutRunningSeconds);
			}
			CompetitionOverride shouldUseResistanceOrGearOverride = ShouldUseResistanceOrGearOverride;
			s.AddDecorators(speedOverride.FollowingWorkout, inclineOverride.FollowingWorkout, shouldUseResistanceOrGearOverride.FollowingWorkout);
			s.AddCumulativeOverrideSeconds(speedOverride.TotalSecondsEnabled, inclineOverride.TotalSecondsEnabled, shouldUseResistanceOrGearOverride.TotalSecondsEnabled);
		}

		public async Task AddFinalSecond()
		{
			if (LastSecond == null)
			{
				return;
			}
			LastSecond.HandleLastMoment(Workout.Target, Workout.TargetValue);
			iFit.Logger.Log.Trace("Workout", "CompetitionLog: adding final moment");
			try
			{
				if (Pipe != null)
				{
					await Pipe.PutRecord(Topic, LastSecond.ToJson()).ConfigureAwait(continueOnCapturedContext: false);
				}
			}
			catch (Exception exception)
			{
				if (featureFlagManager.IsFeatureEnabled(FeatureFlags.LogMQTTVerbose))
				{
					iFit.Logger.Log.Error("Workout", "ERROR putting mqtt record", exception);
				}
			}
		}

		public void Finish(bool workoutComplete, ICoreAnalytics analytics)
		{
			iFit.Logger.Log.Trace("Workout", $"Finishing Competition... workout complete - {workoutComplete}");
			IMqttPipe pipe = Pipe;
			if (pipe != null && !pipe.HasEverSuccessfullyConnected)
			{
				analytics.CompetitionsNeverConnectedMqtt(WorkoutId, workoutRunner?.WorkoutRunningSeconds ?? 0.0);
			}
			Task.Run(async delegate
			{
				if (workoutComplete)
				{
					await AddFinalSecond().ConfigureAwait(continueOnCapturedContext: false);
				}
				try
				{
					if (Pipe != null)
					{
						await Pipe.Close().ConfigureAwait(continueOnCapturedContext: false);
					}
				}
				catch (Exception exception)
				{
					iFit.Logger.Log.Error("Workout", "> ERROR Finishing competitionLog", exception);
				}
				finally
				{
					Console = null;
					Pipe = null;
				}
			});
		}
	}
	public class CompetitionOverride
	{
		public Type Decorator { get; private set; }

		public bool Enabled { get; private set; }

		public bool FollowingWorkout => !Enabled;

		public double LastTimeEnabled { get; private set; }

		public double TotalSecondsEnabled { get; private set; }

		public CompetitionOverride(Type decoratorType)
		{
			Decorator = decoratorType;
		}

		public void Update(bool decoratorEnabled, double consoleRunningTime)
		{
			if (Enabled)
			{
				TotalSecondsEnabled += consoleRunningTime - LastTimeEnabled;
			}
			Enabled = decoratorEnabled;
			if (Enabled)
			{
				LastTimeEnabled = consoleRunningTime;
			}
		}
	}
	public static class LeaderboardFeatureFlagExtensions
	{
		public static bool IsLeaderboardDataUploadEnabledForWorkout(this IFeatureFlagManager featureFlagManager, Workout.WorkoutContext context)
		{
			if (context == Workout.WorkoutContext.ScheduledLive)
			{
				return featureFlagManager.IsFeatureEnabled(FeatureFlags.LeaderboardDataUploadLiveStream);
			}
			return featureFlagManager.IsFeatureEnabled(FeatureFlags.LeaderboardDataUpload);
		}

		public static bool IsLeaderboardFeatureEnabledForWorkout(this IFeatureFlagManager featureFlagManager, Workout.WorkoutContext context)
		{
			if (context == Workout.WorkoutContext.ScheduledLive)
			{
				return featureFlagManager.IsFeatureEnabled(FeatureFlags.LeaderboardFeatureEnabledLiveStream);
			}
			if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.NativeLeaderboardEnabled))
			{
				return featureFlagManager.IsFeatureEnabled(FeatureFlags.LeaderboardFeatureEnabled);
			}
			return true;
		}

		public static bool ShouldUseNativeCompetitionService(this IFeatureFlagManager featureFlagManager, Workout.WorkoutContext context)
		{
			if (context == Workout.WorkoutContext.ScheduledLive)
			{
				return false;
			}
			return featureFlagManager.IsFeatureEnabled(FeatureFlags.NativeLeaderboardEnabled);
		}
	}
