			Current2,
			Current3,
			Current4,
			Current5,
			Current6
		}

		protected IDisposable subscription;

		protected IEnumerable<Tuple<double, double>> metric;

		protected bool _showMetric;

		private IChartAxisScaler _scaler;

		private bool _isMetric = true;

		public DataSetId MetricId { get; protected set; }

		public string Label { get; set; }

		public IEnumerable<Tuple<double, double>> Metric
		{
			get
			{
				return metric;
			}
			set
			{
				SetMetricData(value);
			}
		}

		public bool ShowMetric
		{
