				SetShowMetric(value);
			}
		}

		public IChartAxisScaler Scaler
		{
			get
			{
				return _scaler;
			}
			set
			{
				_scaler = value;
				if (ThreadConsolidator != null)
				{
					ThreadConsolidator.Scaler = value;
				}
			}
		}

		public bool IsMetric
		{
			get
			{
				return _isMetric;
			}
			set
			{
				if (_isMetric != value)
				{
					_isMetric = value;
					if (ReconstructOnUnitChange)
					{
						Reconstruct(value);
					}
				}
			}
		}

		public bool ReconstructOnUnitChange { get; set; }

		public BaseDataThreadConsolidator ThreadConsolidator { get; protected set; }

		protected BaseChartMetric(DataSetId id)
		{
			MetricId = id;
		}

		public abstract Task ApplyDataChanges();

		public abstract void AdjustXAxisMaxValue(double newIndex);

		protected abstract void InitializeMetricDataSet();

		protected abstract void SetShowMetric(bool value);

		protected void SetMetricData(IEnumerable<Tuple<double, double>> value)
		{
			if (metric != value)
			{
				if (subscription != null)
				{
					subscription?.Dispose();
					subscription = null;
				}
				metric = value;
				InitializeMetricDataSet();
				if (metric is INotifyCollectionChanged notifyCollectionChanged)
				{
					subscription = notifyCollectionChanged?.WeakSubscribe(CollectionChanged);
				}
			}
		}

		public virtual void Dispose()
		{
			subscription?.Dispose();
			metric = null;
			Scaler = null;
			ThreadConsolidator?.Dispose();
			ThreadConsolidator = null;
		}

		protected async Task Reconstruct(bool isMetric)
		{
			await ThreadConsolidator.LockUpdates();
			try
			{
				if (Scaler != null)
				{
					Scaler.IsMetric = isMetric;
					InitializeMetricDataSet();
				}
			}
			finally
			{
				ThreadConsolidator.UnlockUpdates();
			}
		}

		protected void CollectionChanged(object sender, NotifyCollectionChangedEventArgs e)
		{
			switch (e.Action)
			{
			case NotifyCollectionChangedAction.Add:
				ThreadConsolidator.AddData(e.NewItems);
				break;
			case NotifyCollectionChangedAction.Remove:
				ThreadConsolidator.RemoveData(e.OldItems);
				break;
			case NotifyCollectionChangedAction.Move:
				throw new NotImplementedException("Chart entry move not yet implemented");
			case NotifyCollectionChangedAction.Replace:
				ThreadConsolidator.ReplaceData(e.OldItems, e.NewItems);
				break;
			}
		}
	}
	public class BaseDataThreadConsolidator : IDisposable
	{
		protected class ReplaceDataContainer
		{
			public readonly List<Tuple<double, double>> OldData;

			public readonly List<Tuple<double, double>> NewData;

			public ReplaceDataContainer(IList oldData, IList newData)
			{
				OldData = new List<Tuple<double, double>>(oldData.Cast<Tuple<double, double>>());
				NewData = new List<Tuple<double, double>>(newData.Cast<Tuple<double, double>>());
			}
		}

		protected BaseChartMetric parent;

		protected IMvxMainThreadDispatcher dispatcher;

		protected readonly SemaphoreSlim dataIntegrityLock;

		protected readonly SemaphoreSlim dataProcessingLock;

		protected readonly List<Tuple<double, double>> AddList;

		protected readonly List<Tuple<double, double>> RemoveList;

		protected readonly List<ReplaceDataContainer> ReplaceList;

		public IChartAxisScaler Scaler { get; set; }

		public BaseDataThreadConsolidator(BaseChartMetric parent)
		{
			this.parent = parent;
			dataIntegrityLock = new SemaphoreSlim(1);
			dataProcessingLock = new SemaphoreSlim(1);
			AddList = new List<Tuple<double, double>>();
			RemoveList = new List<Tuple<double, double>>();
			ReplaceList = new List<ReplaceDataContainer>();
			Mvx.TryResolve<IMvxMainThreadDispatcher>(out dispatcher);
		}

		public virtual void Dispose()
		{
			AddList.Clear();
			RemoveList.Clear();
			ReplaceList.Clear();
			parent = null;
			Scaler = null;
		}

		public async Task LockUpdates()
		{
			await dataIntegrityLock.WaitAsync();
		}

		public void UnlockUpdates()
		{
			dataIntegrityLock.Release();
		}

		public void AddData(IList newData)
		{
			dataIntegrityLock.Wait();
			foreach (Tuple<double, double> newDatum in newData)
			{
				AddList.Add(newDatum);
			}
			dataIntegrityLock.Release();
		}

		public void RemoveData(IList oldData)
		{
			dataIntegrityLock.Wait();
			foreach (Tuple<double, double> oldDatum in oldData)
			{
				RemoveList.Add(oldDatum);
			}
			dataIntegrityLock.Release();
		}

		public void ReplaceData(IList oldData, IList newData)
		{
			dataIntegrityLock.Wait();
			ReplaceList.Add(new ReplaceDataContainer(oldData, newData));
			dataIntegrityLock.Release();
		}
	}
