		{
			get
			{
				if (Metric != MetricType.Resistance)
				{
					return Metric == MetricType.PredictedResistance;
				}
				return true;
			}
		}

		[JsonIgnore]
		public bool RequiresGear
		{
			get
			{
				if (Metric != MetricType.Gear)
				{
					return Metric == MetricType.PredictedGear;
				}
				return true;
			}
		}

		[JsonIgnore]
		public bool RequiresHeartMonitor => Metric == MetricType.HeartRate;

		[JsonIgnore]
		public bool RequiresVerticalGain
		{
			get
			{
				if (Metric != MetricType.PredictedElevation)
				{
					return Metric == MetricType.Elevation;
				}
				return true;
			}
		}

		[JsonIgnore]
		public bool RequiresVerticalNet
		{
			get
			{
				if (Metric != MetricType.PredictedElevation)
				{
					return Metric == MetricType.Elevation;
				}
				return true;
			}
		}

		[JsonIgnore]
		public IList<FitnessValue> RequiredFitnessValues => null;

		public static bool IsMetricGoalBased(MetricType metric)
		{
			switch (metric)
			{
			case MetricType.PredictedSpeed:
			case MetricType.PredictedIncline:
			case MetricType.PredictedElevation:
			case MetricType.PredictedGear:
			case MetricType.PredictedResistance:
				return true;
			default:
				return false;
			}
		}
	}
