namespace Shire.Core.BuiltIn.UpdateCheck
{
	public static class AppFqn
	{
		public static string Eru = "com.ifit.eru";

		public static string Launcher = "com.ifit.launcher";

		public static string Standalone = "com.ifit.standalone";

		public static string Webview = "com.android.webview";

		public static string NotInstalled = "package-not-installed";
	}
	public enum UpdatePool
	{
		Production,
		Beta,
		Alpha
	}
	public struct UpdateInfo
	{
		public Guid Guid { get; set; }

		public UpdatePool Pool { get; set; }
	}
	public interface IConsoleUpdateInfo
	{
		Task<UpdateInfo> GetInfo();
	}
	public class ConsoleUpdateInfo : IConsoleUpdateInfo
	{
		private const string InfoFile = ".ConsoleUpdateId";

		private const string InfoFolderLocation = "/sdcard/";

		private readonly IFileSystem fileSystem;

		private bool hasAttemptedFileLoad;

		private UpdateInfo updateInfo;

		private string InfoFileLocation => Path.Combine("/sdcard/", ".ConsoleUpdateId");

		public ConsoleUpdateInfo(IFileSystem fileSystem)
		{
			this.fileSystem = fileSystem;
		}

		public async Task<UpdateInfo> GetInfo()
		{
			if (!hasAttemptedFileLoad)
			{
				hasAttemptedFileLoad = true;
				await LoadInfo();
			}
			return updateInfo;
		}

		private async Task LoadInfo()
		{
			_ = 1;
			try
			{
				IFile file = await fileSystem.LocalStorage.GetFileAsync(InfoFileLocation);
				if (file != null)
				{
					updateInfo = JsonConvert.DeserializeObject<UpdateInfo>(await file.ReadAllTextAsync());
				}
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("UpdateInfo", "Error loading Update Info: " + ex.Message);
			}
		}
	}
	public interface IConsoleUpdatePool
	{
		Task Send(UpdateInfo updateInfo, string osVersion = "", int softwareNumber = -1, bool testEnvironment = false);
	}
	public interface IPlatformCurrentVersion
	{
		Task<string> GetCurrentAppVersion(string fqn);

		Task<string> GetCurrentBrainboardVersion();

		Task<string> GetCurrentSystemVersion();
	}
	public interface IUpdateAvailableCheckService
	{
		Task<UpdateCheckResult> GetAvailableUpdates(bool enableDowngrade, bool useFallback, IProgress<UpdateType> progress = null);

		Task<bool> GetAreUpdatesAvailable(bool useFallback = false);
	}
	public interface IUpdateManifestSource
	{
		Task<ConsoleAppsUpdates> GetConsoleAppsManifest(bool useFallback = false);

		Task<BrainboardUpdate> GetBrainboardManifest(bool useFallback = false);

		Task<AndroidFirmwareUpdate> GetSystemFirmwareManifest(bool useFallback = false);
	}
	public class OnlineUpdateManifestSource : IUpdateManifestSource
	{
		private readonly IIfitApiService apiService;

		private readonly string osIncremental;

		private readonly int softwareNumber;

		private readonly IConsoleUpdateInfo consoleUpdateInfo;

		private string guidString;

		private readonly Task initialization;

		private Func<bool, string> apiString = (bool isFallback) => (!isFallback) ? "wolf-updates" : "public api";

		public OnlineUpdateManifestSource(IIfitApiService apiService, IConsoleUpdateInfo consoleUpdateInfo, string osIncremental, int softwareNumber)
		{
			OnlineUpdateManifestSource onlineUpdateManifestSource = this;
			this.apiService = apiService;
			this.osIncremental = osIncremental;
			this.softwareNumber = softwareNumber;
			this.consoleUpdateInfo = consoleUpdateInfo;
			initialization = Task.Run(async delegate
			{
				UpdateInfo updateInfo = await consoleUpdateInfo.GetInfo();
				return onlineUpdateManifestSource.guidString = updateInfo.Guid.ToString();
			});
		}

		public async Task<ConsoleAppsUpdates> GetConsoleAppsManifest(bool useFallback = false)
		{
			iFit.Logger.Log.Info("OnlineUpdateCheck", "Checking " + apiString(useFallback) + " service for available App Updates using LD User: " + guidString);
			await initialization;
			ConsoleAppsUpdates consoleAppsUpdates = new ConsoleAppsUpdates();
			try
			{
				ConsoleAppsUpdates.InfoContainer infoContainer = ((!useFallback) ? (await ConsoleAppsUpdates.DetermineAppUpdate(apiService, guidString)) : (await ConsoleAppsUpdates.Get(apiService, softwareNumber))?.Info);
				infoContainer?.Apps?.Updates?.DoForEach(delegate(ConsoleAppsUpdates.AppUpdate x)
				{
					iFit.Logger.Log.Trace("OnlineUpdateCheck", "App update found: " + x.Fqn + ", version: " + x.Version);
				});
				consoleAppsUpdates.SoftwareNumbers = new List<int> { softwareNumber };
				consoleAppsUpdates.Info = infoContainer;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Trace("OnlineUpdateCheck", $"Failed to get Console Apps updates using wolf-updates service and LD:  Exception: {ex.GetBaseException()}");
				iFit.Logger.Log.Info("OnlineUpdateCheck", $"Checking ifit api for available App Updates online on {apiService.Environment.Name} server from SWN: {softwareNumber}");
				consoleAppsUpdates = await ConsoleAppsUpdates.Get(apiService, softwareNumber);
			}
			return consoleAppsUpdates;
		}

		public async Task<BrainboardUpdate> GetBrainboardManifest(bool useFallback = false)
		{
			iFit.Logger.Log.Info("OnlineUpdateCheck", "Checking " + apiString(useFallback) + " service for available Brainboard update using LD User: " + guidString);
			await initialization;
			BrainboardUpdate brainboardUpdate;
			try
			{
				brainboardUpdate = ((!useFallback) ? (await BrainboardUpdate.DetermineBrainboardUpdate(apiService, guidString, softwareNumber)) : (await BrainboardUpdate.Get(apiService, softwareNumber)));
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Trace("OnlineUpdateCheck", $"Failed to get BB update using wolf-updates service and LD:  Exception: {ex.GetBaseException()}");
				iFit.Logger.Log.Info("OnlineUpdateCheck", $"Checking iFIT API for available BB updates on {apiService.Environment.Name} server using SWN: {softwareNumber}");
				brainboardUpdate = await BrainboardUpdate.Get(apiService, softwareNumber);
			}
			if (!BuiltInUtil.IsValidSoftwareNumberInList(brainboardUpdate?.SoftwareNumbers ?? null, softwareNumber))
			{
				return null;
			}
			return brainboardUpdate;
		}

		public async Task<AndroidFirmwareUpdate> GetSystemFirmwareManifest(bool useFallback = false)
		{
			iFit.Logger.Log.Info("OnlineUpdateCheck", "Checking " + apiString(useFallback) + " service for Android System update using LD User: " + guidString);
			await initialization;
			AndroidFirmwareUpdate androidUpdate;
			try
			{
				androidUpdate = ((!useFallback) ? (await AndroidFirmwareUpdate.DetermineAndroidUpdate(apiService, guidString, osIncremental)) : (await AndroidFirmwareUpdate.Get(apiService, osIncremental)));
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Trace("OnlineUpdateCheck", $"Failed to get System update using wolf-updates service and LD.  Exception: {ex.GetBaseException()}");
				iFit.Logger.Log.Info("OnlineUpdateCheck", "Checking iFIt API for available system update online");
				androidUpdate = await AndroidFirmwareUpdate.Get(apiService, osIncremental);
			}
			return androidUpdate;
		}
	}
	public class UpdateAvailableCheckService : IUpdateAvailableCheckService
	{
		private readonly IPlatformCurrentVersion platformCurrentVersion;

		private readonly IFileSystem fileSystem;

		private List<IUpdateManifestSource> sources;

		protected static SortedDictionary<string, UpdateType> FqnToInstallType = new SortedDictionary<string, UpdateType>
		{
			{
				AppFqn.Eru,
				UpdateType.Eru
			},
			{
				AppFqn.Launcher,
				UpdateType.Launcher
			},
			{
				AppFqn.Standalone,
				UpdateType.Standalone
			},
			{
				AppFqn.Webview,
				UpdateType.Webview
			}
		};

		public UpdateAvailableCheckService(IPlatformCurrentVersion platformCurrentVersion, IFileSystem fileSystem, List<IUpdateManifestSource> sources)
		{
			this.platformCurrentVersion = platformCurrentVersion;
			this.fileSystem = fileSystem;
			this.sources = sources;
		}

		public async Task<UpdateCheckResult> GetAvailableUpdates(bool enableDowngrade, bool useFallback, IProgress<UpdateType> progress = null)
		{
			UpdateCheckResult result = new UpdateCheckResult
			{
				AvailableUpdates = new SortedDictionary<UpdateType, (string, string)>()
			};
			Dictionary<string, string> appVersions = await GetCurrentAppVersions();
			foreach (IUpdateManifestSource source in sources)
			{
				iFit.Logger.Log.Trace("UpdateCheck", $"Checking source: {source.GetType()} for updates");
				bool flag;
				try
				{
					flag = await CheckAvailableAppUpdates(source, appVersions, enableDowngrade, useFallback, result);
				}
				catch (Exception ex)
				{
					iFit.Logger.Log.Trace("OnlineUpdateCheck", "Exception when calling GetAvailableUpdates: " + ex.ToString());
					flag = false;
				}
				if (flag)
				{
					sources = new List<IUpdateManifestSource> { source };
					break;
				}
			}
			progress?.Report(UpdateType.Brainboard);
			string brainboardVersion = await GetCurrentBrainboardVersion();
			foreach (IUpdateManifestSource source in sources)
			{
				if (await CheckAvailableBrainboardUpdate(source, brainboardVersion, useFallback, result))
				{
					sources = new List<IUpdateManifestSource> { source };
					break;
				}
			}
			progress?.Report(UpdateType.System);
			foreach (IUpdateManifestSource source2 in sources)
			{
				if (await CheckAvailableSystemUpdate(source2, useFallback, result))
				{
					break;
				}
			}
			result.AvailableUpdates.OrderBy((KeyValuePair<UpdateType, (string currentVersion, string newVersion)> x) => (int)x.Key);
			iFit.Logger.Log.Trace("UpdateCheck", $"GetAvailableUpdates result: {result}");
			return result;
		}

		public async Task<bool> GetAreUpdatesAvailable(bool useFallback = false)
		{
			return (await GetAvailableUpdates(enableDowngrade: false, useFallback)).AvailableUpdates.Count > 0;
		}

		protected async Task<bool> CheckAvailableAppUpdates(IUpdateManifestSource source, Dictionary<string, string> appVersions, bool enableDowngrade, bool useFallback, UpdateCheckResult result)
		{
			ConsoleAppsUpdates consoleAppsUpdates = await (source?.GetConsoleAppsManifest(useFallback));
			if (consoleAppsUpdates?.Info?.Apps != null)
			{
				List<ConsoleAppsUpdates.AppUpdate> list = PruneUpdatedApps(consoleAppsUpdates.Info.Apps.Updates, appVersions, enableDowngrade);
				consoleAppsUpdates.Info.Apps.Updates = list;
				result.Apps = consoleAppsUpdates;
				result.Apps.Info = new ConsoleAppsUpdates.InfoContainer();
				if (result.Apps.Info.Apps == null)
				{
					result.Apps.Info.Apps = new ConsoleAppsUpdates.AppsContainer();
				}
				result.Apps.Info.Apps.Updates = list;
				MapManifestToUpdateType(list, appVersions, result);
				return list.Count > 0;
			}
			return false;
		}

		private List<ConsoleAppsUpdates.AppUpdate> PruneUpdatedApps(List<ConsoleAppsUpdates.AppUpdate> updates, Dictionary<string, string> appVersions, bool enableDowngrade)
		{
			List<ConsoleAppsUpdates.AppUpdate> list = new List<ConsoleAppsUpdates.AppUpdate>();
			if (updates == null)
			{
				iFit.Logger.Log.Info("UpdateCheck", "No apps to prune in manifest");
				return list;
			}
			iFit.Logger.Log.Info("UpdateCheck", "Pruning updated apps from update list");
			foreach (ConsoleAppsUpdates.AppUpdate update in updates)
			{
				if (appVersions.ContainsKey(update.Fqn) && AppNeedsUpdating(update.Fqn, appVersions[update.Fqn], update.Version, update.Url, enableDowngrade))
				{
					iFit.Logger.Log.Info("OnlineUpdateCheck", "Found that app needs an update: " + update.Fqn + ", " + update.Url + ", " + update.Version);
					list.Add(update);
				}
			}
			return list;
		}

		private bool AppNeedsUpdating(string packageName, string currentVersion, string remoteVersion, string url, bool enableDowngrade)
		{
			try
			{
				iFit.Logger.Log.Info("UpdateCheck", $"Checking {packageName} {currentVersion} against {remoteVersion}. EnableDowngrade: {enableDowngrade}");
				bool flag = enableDowngrade && currentVersion != remoteVersion;
				bool flag2 = BuiltInUtil.CheckVersionStrings(currentVersion, remoteVersion);
				bool flag3 = !url.Contains(currentVersion);
				bool flag4 = (flag || flag2) && flag3;
				iFit.Logger.Log.Trace("UpdateCheck", $"AppsNeedUpdating result: {flag4}");
				return flag4;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Info("UpdateCheck", "Error Checking App Version");
				iFit.Logger.Log.Info("UpdateCheck", ex.Message);
				return false;
			}
		}

		private static void MapManifestToUpdateType(List<ConsoleAppsUpdates.AppUpdate> pruned, Dictionary<string, string> appVersions, UpdateCheckResult result)
		{
			foreach (ConsoleAppsUpdates.AppUpdate item in pruned)
			{
				result.AvailableUpdates[FqnToInstallType[item.Fqn]] = (appVersions[item.Fqn], item.Version);
			}
		}

		private async Task<Dictionary<string, string>> GetCurrentAppVersions()
		{
			Dictionary<string, string> versions = new Dictionary<string, string>();
			foreach (string package in FqnToInstallType.Keys)
			{
				string text = await platformCurrentVersion.GetCurrentAppVersion(package);
				if (text == AppFqn.NotInstalled)
				{
					iFit.Logger.Log.Info("UpdateCheck", package + " not installed.  Defaulting to 0.0");
					text = "0.0";
				}
				versions.Add(package, text);
			}
			return versions;
		}

		private async Task<bool> CheckAvailableBrainboardUpdate(IUpdateManifestSource source, string currentVersion, bool useFallback, UpdateCheckResult result)
		{
			try
			{
				iFit.Logger.Log.Info("UpdateCheck", $"Getting brainboard version from {source.GetType()}");
				BrainboardUpdate brainboardUpdate = await source.GetBrainboardManifest(useFallback);
				iFit.Logger.Log.Info("UpdateCheck", "Checking if versions were obtained");
				if (currentVersion == null || brainboardUpdate == null)
				{
					iFit.Logger.Log.Info("UpdateCheck", "Unable to retrieve brainboard version");
					return false;
				}
				iFit.Logger.Log.Info("UpdateCheck", "Checking bbUpdate version: " + brainboardUpdate.Version + " against currentVersion: " + currentVersion);
				if (!BuiltInUtil.CheckVersionStrings(currentVersion, brainboardUpdate.Version))
				{
					iFit.Logger.Log.Info("UpdateCheck", "Brainboard version " + currentVersion + " is up to date");
					return false;
				}
				result.Brainboard = brainboardUpdate;
				result.AvailableUpdates.Add(UpdateType.Brainboard, (currentVersion, brainboardUpdate.Version));
				return true;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Info("UpdateCheck", "Error checking brainboard update");
				iFit.Logger.Log.Info("UpdateCheck", ex.Message);
				return false;
			}
		}

		private async Task<string> GetCurrentBrainboardVersion()
		{
			try
			{
				iFit.Logger.Log.Info("UpdateCheck", "Getting Current Brainboard Version");
				return await platformCurrentVersion.GetCurrentBrainboardVersion();
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Info("UpdateCheck", "Error getting current brainboard version");
				iFit.Logger.Log.Info("UpdateCheck", ex.Message);
				return null;
			}
		}

		private async Task<bool> CheckAvailableSystemUpdate(IUpdateManifestSource source, bool useFallback, UpdateCheckResult result)
		{
			try
			{
				AndroidFirmwareUpdate androidFirmwareUpdate = await source.GetSystemFirmwareManifest(useFallback);
				if (androidFirmwareUpdate == null || androidFirmwareUpdate.UpdateVersion == null)
				{
					return false;
				}
				result.AvailableUpdates.Add(UpdateType.System, (androidFirmwareUpdate.Version, androidFirmwareUpdate.UpdateVersion));
				result.FirmwareUpdate = androidFirmwareUpdate;
				return true;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Info("UpdateCheck", "Error checking system update");
				iFit.Logger.Log.Info("UpdateCheck", ex.Message);
				return false;
			}
		}
	}
	public enum UpdateType
	{
		Eru,
		Launcher,
		Standalone,
		Brainboard,
		System,
		Webview
	}
	public class UpdateCheckResult
	{
		public SortedDictionary<UpdateType, (string currentVersion, string newVersion)> AvailableUpdates { get; set; }

		public ConsoleAppsUpdates Apps { get; set; }

		public BrainboardUpdate Brainboard { get; set; }

		public AndroidFirmwareUpdate FirmwareUpdate { get; set; }

		public override string ToString()
		{
			StringBuilder sb = new StringBuilder("UpdateCheckResult:\n");
			sb.AppendLine("AvailableUpdates: ");
			if (AvailableUpdates != null)
			{
				AvailableUpdates?.ForEach<KeyValuePair<UpdateType, (string, string)>>(delegate(KeyValuePair<UpdateType, (string currentVersion, string newVersion)> x)
				{
					sb.AppendLine($"Key: {x.Key}; Value: {x.Value}");
				});
			}
			if (Apps != null)
			{
				sb.AppendLine($"Apps: {Apps}");
			}
			if (Brainboard != null)
			{
				string value = "Brainboard: Id: " + Brainboard?.Id + "; Name: " + Brainboard?.Name + "; " + $"SoftwareNumber: {Brainboard?.SoftwareNumber};" + ((Brainboard?.SoftwareNumbers != null) ? ("SoftwareNumbers: " + string.Join(",", Brainboard?.SoftwareNumbers)) : string.Empty) + "Url: " + Brainboard?.Url + ", Version: " + Brainboard?.Version;
				sb.AppendLine(value);
			}
			if (FirmwareUpdate != null)
			{
				string value2 = "FirmwareUpdate: Name: " + FirmwareUpdate?.Name + "; BaseVersion: " + FirmwareUpdate?.BaseVersion + "; NewVersion: " + FirmwareUpdate?.NewVersion + "; Version: " + FirmwareUpdate?.Version + ", Url: " + FirmwareUpdate?.Url + ", UpdateVersion: " + FirmwareUpdate?.UpdateVersion;
				sb.AppendLine(value2);
			}
			return sb.ToString();
		}
	}
}
namespace Shire.Core.Ble
{
	public class PersistentBluetoothDevices : IPersistentBluetoothDevices
	{
		private readonly IBlobCacheService cacheService;

		private readonly IIfitApiService ifitApi;

		private Dictionary<string, HashSet<Guid>> savedBluetoothDevices = new Dictionary<string, HashSet<Guid>>();

		private HashSet<Guid> savedBondedHrmDevices = new HashSet<Guid>();

		public PersistentBluetoothDevices(IBlobCacheService cacheService, IIfitApiService apiService)
		{
			this.cacheService = cacheService;
			ifitApi = apiService;
		}

		private async Task<IPersistentBluetoothDevices> InitializeAsync()
		{
			savedBluetoothDevices = (await cacheService.GetFromCache<Dictionary<string, HashSet<Guid>>>("savedBluetoothDevices", "IPersistentBluetoothDevices")) ?? new Dictionary<string, HashSet<Guid>>();
			savedBondedHrmDevices = (await cacheService.GetFromCache<HashSet<Guid>>("savedBondedHrmDevices", "IPersistentBluetoothDevices")) ?? new HashSet<Guid>();
			return this;
		}

		public static Task<IPersistentBluetoothDevices> CreateAsync(IBlobCacheService cacheService, IIfitApiService ifitApiService)
		{
			PersistentBluetoothDevices persistentBluetoothDevices = new PersistentBluetoothDevices(cacheService, ifitApiService);
			return persistentBluetoothDevices.InitializeAsync();
		}

		public bool IsDeviceSaved(Guid deviceId)
		{
			if (ifitApi?.CurrentlyAuthenticatedUserId == null)
			{
				return false;
			}
			string key = ifitApi?.CurrentlyAuthenticatedUserId;
			if (savedBluetoothDevices == null || savedBluetoothDevices.IsEmpty())
			{
				return false;
			}
			if (!savedBluetoothDevices.ContainsKey(key))
			{
				return false;
			}
			if (!savedBluetoothDevices[key].Contains(deviceId))
			{
				return false;
			}
			iFit.Logger.Log.Trace("Settings", $"Device: {deviceId} exists in persistent settings.");
			return true;
		}

		public async Task SaveDevice(Guid deviceId)
		{
			if (ifitApi?.CurrentlyAuthenticatedUserId == null)
			{
				return;
			}
			string key = ifitApi?.CurrentlyAuthenticatedUserId;
			if (IsDeviceSaved(deviceId))
			{
				return;
			}
			if (!savedBluetoothDevices.ContainsKey(key))
			{
				savedBluetoothDevices.TryAdd(key, new HashSet<Guid>());
			}
			try
			{
				savedBluetoothDevices[key].Add(deviceId);
				await cacheService.Flush(savedBluetoothDevices, "savedBluetoothDevices", "IPersistentBluetoothDevices");
				iFit.Logger.Log.Trace("Settings", string.Format("Persisting device {0} to {1} ", deviceId, "savedBluetoothDevices"));
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Settings", $"Exception caught trying to add device to persistent bluetooth settings. {arg}");
			}
		}

		public async Task DeleteDevice(Guid deviceId)
		{
			if (!IsDeviceSaved(deviceId))
			{
				return;
			}
			string text = ifitApi?.CurrentlyAuthenticatedUserId;
			if (text == null)
			{
				return;
			}
			try
			{
				savedBluetoothDevices[text].Remove(deviceId);
				await cacheService.Flush(savedBluetoothDevices, "savedBluetoothDevices", "IPersistentBluetoothDevices");
				iFit.Logger.Log.Trace("Settings", $"Removing saved device from list: {deviceId}");
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Settings", $"Exception caught trying to remove device from persistent bluetooth settings. {arg}");
			}
		}

		public async Task SaveBondedHrm(Guid deviceId)
		{
			if (IsBondedHrmDeviceSaved(deviceId))
			{
				return;
			}
			try
			{
				savedBondedHrmDevices.Add(deviceId);
				await cacheService.Flush(savedBondedHrmDevices, "savedBondedHrmDevices", "IPersistentBluetoothDevices");
				iFit.Logger.Log.Trace("Settings", string.Format("Persisting bonded hrm device {0} to {1} ", deviceId, "savedBondedHrmDevices"));
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Settings", $"Exception caught trying to add bonded hrm device to persistent bluetooth settings. {arg}");
			}
		}

		public async Task DeleteBondedHrm(Guid deviceId)
		{
			if (!IsBondedHrmDeviceSaved(deviceId))
			{
				return;
			}
			try
			{
				savedBondedHrmDevices.Remove(deviceId);
				await cacheService.Flush(savedBondedHrmDevices, "savedBondedHrmDevices", "IPersistentBluetoothDevices");
				iFit.Logger.Log.Trace("Settings", $"Removing saved bonded hrm device from list: {deviceId}");
			}
			catch (Exception arg)
			{
				iFit.Logger.Log.Error("Settings", $"Exception caught trying to remove bonded hrm device from persistent bluetooth settings. {arg}");
			}
		}

		private bool IsBondedHrmDeviceSaved(Guid deviceId)
		{
			if (savedBondedHrmDevices == null || savedBondedHrmDevices.IsEmpty())
			{
				return false;
			}
			if (!savedBondedHrmDevices.Contains(deviceId))
			{
				return false;
			}
			iFit.Logger.Log.Trace("Settings", $"Device: {deviceId} exists in persistent settings.");
			return true;
		}

		public bool IsBondedDeviceAnHrm(Guid deviceId)
		{
			return IsBondedHrmDeviceSaved(deviceId);
		}
	}
}
namespace Shire.Core.Ble.Mocks
{
	public static class MockSupportExtensions
	{
		public static MockType ToMockType(this Workout.WorkoutType type)
		{
			switch (type)
			{
			case Workout.WorkoutType.Row:
			case Workout.WorkoutType.Rowing:
				return MockType.Rower;
			case Workout.WorkoutType.Strength:
				return MockType.Strength;
			case Workout.WorkoutType.Cycle:
				return MockType.Bike;
			case Workout.WorkoutType.Run:
