	public abstract class HeadphoneConnectionHelperBase : IDisposable
	{
		protected const string LogTag = "HeadphoneConnectionHelper";

		public static readonly IEnumerable<string> AllowedHeadphoneNamesIgnoringCase = new string[3] { "airpods", "airpod pros", "wh-1000xm" };

		protected readonly IHeadphoneScanner Scanner;

		protected readonly HeadphoneDeviceFilterBase Filter;

		private readonly IBleRadioStatusService bleRadioStatusService;

		private readonly ICoreAnalytics coreAnalytics;

		private readonly ISet<Guid> bondingConnectingHeadphones;

		private IDisposable scannerSub;

		private CancellationTokenSource enableCanceller;

		private CancellationTokenSource bondCanceller;

		protected Subject<IHeadphone> _onDeviceFound = new Subject<IHeadphone>();

		protected Subject<Guid> _onStateChanged = new Subject<Guid>();

		protected Subject<bool> _OnConnected = new Subject<bool>();

		protected virtual TimeSpan BondUnbondTimeout => TimeSpan.FromSeconds(15.0);

		public virtual bool DoesConnectingDuringPlaybackStopBuffering => false;

		public virtual IObservable<IHeadphone> OnDeviceFound => _onDeviceFound;

		public virtual IObservable<Guid> OnStateChanged => _onStateChanged;

		public virtual IObservable<bool> OnConnected => _OnConnected;

		public abstract event EventHandler ScanEnded;

		protected HeadphoneConnectionHelperBase(IHeadphoneScanner scanner, IBleRadioStatusService bleRadioStatusService, HeadphoneDeviceFilterBase filter, ICoreAnalytics coreAnalytics)
		{
			Scanner = scanner;
			this.bleRadioStatusService = bleRadioStatusService;
			Filter = filter;
			this.coreAnalytics = coreAnalytics;
			bondingConnectingHeadphones = new HashSet<Guid>(1);
		}

		public abstract bool IsConnected();

		protected abstract ConnectionState GetConnectionState(IHeadphone headphone);

		protected abstract bool IsReceivingBroadcasts();

		public virtual HeadphoneDeviceState GetState(IHeadphone headphone)
		{
			if (headphone == null)
			{
				return HeadphoneDeviceState.Disconnected;
			}
			BondState currentBondState = GetCurrentBondState(headphone);
			ConnectionState connectionState = GetConnectionState(headphone);
			if (currentBondState == BondState.Bonded && connectionState == ConnectionState.Connected)
			{
				return HeadphoneDeviceState.Connected;
			}
			if (currentBondState == BondState.Bonding || connectionState == ConnectionState.Connecting || bondingConnectingHeadphones.Contains(headphone.Id))
			{
				return HeadphoneDeviceState.Connecting;
			}
			return HeadphoneDeviceState.Disconnected;
		}

		public abstract BondState GetCurrentBondState(IHeadphone headphone);

		protected abstract Task DoStart();

		public virtual async Task Start()
		{
			if (!bleRadioStatusService.IsBluetoothRadioEnabled())
			{
				enableCanceller?.Cancel();
				enableCanceller?.Dispose();
				enableCanceller = new CancellationTokenSource();
				Task<bool> task = bleRadioStatusService.WhenBluetoothRadioEnabledChanged.Where((bool enabled) => enabled).FirstAsync().ToTask(enableCanceller.Token);
				bleRadioStatusService.RequestEnableBluetooth(notifyIfCannotEnable: true);
				try
				{
					await task.ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (OperationCanceledException exception)
				{
					iFit.Logger.Log.Info("Headphone", "Cancelled enabling Bluetooth", exception);
					return;
				}
			}
			await DoStart().ConfigureAwait(continueOnCapturedContext: false);
		}

		public virtual void Stop()
		{
			enableCanceller?.Cancel();
			enableCanceller?.Dispose();
			enableCanceller = null;
			bondCanceller?.Cancel();
			bondCanceller?.Dispose();
			bondCanceller = null;
		}

		protected abstract void PopulateBondedDevices();

		public virtual void BeginScan(int? timeoutSeconds = null)
		{
			iFit.Logger.Log.Trace("Headphone", "Starting scanning");
			PopulateBondedDevices();
			scannerSub?.Dispose();
			scannerSub = Scanner.ScanWithFilter(Filter, timeoutSeconds).SubscribeWithErrorLogging(_onDeviceFound.OnNext);
		}

		public virtual void EndScan()
		{
			scannerSub?.Dispose();
			scannerSub = null;
			Scanner.StopScan();
		}

		protected abstract bool CreateBond(IHeadphone headphone);

		protected abstract Task<bool> TryConnect(IHeadphone headphone, bool retry);

		protected abstract IObservable<Guid> GetBondingHeadphoneIds();

		protected abstract IObservable<IHeadphone> GetConnectingHeadphones();

		protected abstract Task Bounce();

		public virtual async Task BondWithDevice(IHeadphone headphone)
		{
			await BondWithDevice(headphone, retry: true).ConfigureAwait(continueOnCapturedContext: false);
			if (IsConnected())
			{
				await PostHeadphonesPairedEvent(headphone?.Name).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task BondWithDevice(IHeadphone headphone, bool retry)
		{
			bool flag = GetCurrentBondState(headphone) != BondState.Unbonded;
			bool flag2 = flag;
			if (flag2)
			{
				flag2 = await TryConnect(headphone, retry);
			}
			if (!flag2)
			{
				await UnbondWithAllDevices().ConfigureAwait(continueOnCapturedContext: false);
				await BondThenConnect(headphone, bond: true, retry).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		protected async Task BondThenConnect(IHeadphone headphone, bool bond, bool retry)
		{
			if (!IsReceivingBroadcasts())
			{
				iFit.Logger.Log.Trace("HeadphoneConnectionHelper", "Not receiving broadcasts when attempting to BondThenConnect.");
				return;
			}
			bondCanceller?.Cancel();
			bondCanceller?.Dispose();
			bondCanceller = new CancellationTokenSource();
			try
			{
				bondingConnectingHeadphones.Add(headphone.Id);
				bool flag = bond;
				bool flag2 = flag;
				if (flag2)
				{
					flag2 = !(await TryBond(headphone, retry));
				}
				if (flag2)
				{
					return;
				}
				if (GetConnectionState(headphone) == ConnectionState.Connected)
				{
					iFit.Logger.Log.Trace("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - already connected");
					return;
				}
				if (!IsReceivingBroadcasts())
				{
					iFit.Logger.Log.Trace("HeadphoneConnectionHelper", "Not receiving broadcasts when attempting to Connect after bonding..");
					return;
				}
				iFit.Logger.Log.Trace("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - waiting to connect");
				Task<IHeadphone> task = (from h in GetConnectingHeadphones()
					where h.Id == headphone.Id && GetConnectionState(h) != ConnectionState.Connecting
					select h).Timeout(BondUnbondTimeout).FirstAsync().ToTask(bondCanceller.Token);
				await task.ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (OperationCanceledException exception)
			{
				iFit.Logger.Log.Trace("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - cancelled", exception);
			}
			catch (TimeoutException exception2)
			{
				iFit.Logger.Log.Error("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - no bond change within {BondUnbondTimeout}", exception2);
				if (retry)
				{
					await BounceAndBond(headphone).ConfigureAwait(continueOnCapturedContext: false);
					return;
				}
				iFit.Logger.Log.Warn("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - not retrying, state={GetState(headphone)}");
				if (!Filter.IsDeviceValid(headphone))
				{
					iFit.Logger.Log.Warn("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - couldn't connect and device doesn't appear to be headphones - starting unbond");
					await UnbondWithDevice(headphone);
				}
			}
			finally
			{
				bondCanceller?.Dispose();
				bondCanceller = null;
				if (bondingConnectingHeadphones.Remove(headphone.Id))
				{
					_onStateChanged.OnNext(headphone.Id);
				}
				iFit.Logger.Log.Trace("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - done, state={GetState(headphone)}");
			}
		}

		private async Task<bool> TryBond(IHeadphone headphone, bool retry)
		{
			iFit.Logger.Log.Trace("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - bonding");
			Task<Guid> task = (from id in GetBondingHeadphoneIds()
				where id == headphone.Id
				select id).Timeout(BondUnbondTimeout).FirstAsync().ToTask(bondCanceller.Token);
			if (!CreateBond(headphone))
			{
				bondCanceller?.Cancel();
				iFit.Logger.Log.Warn("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - CreateBond failed with immediate error.");
				return false;
			}
			await task.ConfigureAwait(continueOnCapturedContext: false);
			if (GetCurrentBondState(headphone) != BondState.Unbonded)
			{
				return true;
			}
			iFit.Logger.Log.Warn("HeadphoneConnectionHelper", $"BondThenConnect {headphone} - bonding failed!");
			if (retry)
			{
				await BounceAndBond(headphone).ConfigureAwait(continueOnCapturedContext: false);
			}
			return false;
		}

		private async Task BounceAndBond(IHeadphone headphone)
		{
			await Bounce().ConfigureAwait(continueOnCapturedContext: false);
			if (!(bondCanceller?.IsCancellationRequested ?? true))
			{
				await BondWithDevice(headphone, retry: false).ConfigureAwait(continueOnCapturedContext: false);
			}
		}

		private async Task PostHeadphonesPairedEvent(string deviceName)
		{
			if (deviceName == null)
			{
				await coreAnalytics.HeadphonesPaired("null");
				return;
			}
			IEnumerable<string> source = AllowedHeadphoneNamesIgnoringCase.Concat(new string[10] { "bose", "sony", "beats", "skullcandy", "jabra", "anker", "jaybird", "anc", "aftershokz", "jbl" });
			List<string> list = source.Where((string x) => deviceName.IndexOf(x, StringComparison.OrdinalIgnoreCase) > -1).ToList();
			if (list.Count > 0)
			{
				IEnumerable<Task> tasks = list.Select(coreAnalytics.HeadphonesPaired);
				await Task.WhenAll(tasks);
			}
			else
			{
				await coreAnalytics.HeadphonesPaired(deviceName);
			}
		}

		public abstract Task<bool> UnbondWithDevice(IHeadphone headphone);

		protected abstract IEnumerable<IHeadphone> GetBondedHeadphones();

		public virtual async Task UnbondWithAllDevices()
		{
			IEnumerable<IHeadphone> enumerable = from x in GetBondedHeadphones()
				where Filter.IsDeviceValid(x)
				select x;
			foreach (IHeadphone bondedDevice in enumerable)
			{
				try
				{
					await UnbondWithDevice(bondedDevice).ConfigureAwait(continueOnCapturedContext: false);
				}
				catch (Exception ex)
				{
					iFit.Logger.Log.Error("HeadphoneConnectionHelper", "Exception thrown unbonding with device " + bondedDevice.Name, ex.GetBaseException());
				}
			}
		}

		protected virtual void DisposeCancellersAndCleanupBroadcastReceiver()
		{
			bondCanceller?.Dispose();
			bondCanceller = null;
		}

		public virtual void Dispose()
		{
			EndScan();
			enableCanceller?.Dispose();
			enableCanceller = null;
			_onDeviceFound?.Dispose();
			_onDeviceFound = null;
			_onStateChanged?.Dispose();
			_onStateChanged = null;
			_OnConnected?.Dispose();
			_OnConnected = null;
		}
	}
	public abstract class HeadphoneDeviceFilterBase
	{
		public virtual bool IsDeviceValid(IHeadphone device)
		{
			if (device == null)
			{
				iFit.Logger.Log.Error("Headphone", "IsDeviceValid got null");
				return false;
			}
			if (!IsNameValid(device))
			{
				iFit.Logger.Log.Warn("Headphone", $"IsDeviceValid got bad name for {device}");
				return false;
			}
			if (!IsAudioDevice(device))
			{
				return false;
			}
			return true;
		}

		private static bool IsNameValid(IHeadphone headphone)
		{
			return !string.IsNullOrWhiteSpace(headphone.Name);
		}

		protected bool IsAudioVideoLoudspeakerValid()
		{
			if (Mvx.TryResolve<IClubService>(out var service))
			{
				if (service == null)
				{
					return false;
				}
				return !service.IsCurrentConsoleClub;
			}
			return false;
		}

		protected abstract bool IsAudioDevice(IHeadphone headphone);
	}
	public interface IHeadphoneScanner : IDisposable
	{
		event EventHandler Ended;

		IObservable<IHeadphone> ScanWithFilter(HeadphoneDeviceFilterBase filter, int? requestedScanSeconds = null);

		void StopScan();
	}
	public abstract class HeadphoneScannerBase : IHeadphoneScanner, IDisposable
	{
		private readonly Subject<IHeadphone> whenDeviceFound = new Subject<IHeadphone>();

		private IDisposable scanTimeoutSub;

		public event EventHandler Ended;

		public IObservable<IHeadphone> ScanWithFilter(HeadphoneDeviceFilterBase filter, int? requestedScanSeconds)
		{
			scanTimeoutSub?.Dispose();
			scanTimeoutSub = (requestedScanSeconds.HasValue ? Observable.Timer(TimeSpan.FromSeconds(requestedScanSeconds.Value)).Subscribe(delegate
			{
				StopScan();
			}) : null);
			StopScanNative();
			iFit.Logger.Log.Info("Headphone", "Scanning for " + (requestedScanSeconds?.ToString() ?? "inf.") + " seconds");
			DateTime startDateTime = DateTime.UtcNow;
			ScanNative();
			return whenDeviceFound.Where(filter.IsDeviceValid).Select(delegate(IHeadphone d)
			{
				double totalSeconds = (DateTime.UtcNow - startDateTime).TotalSeconds;
				iFit.Logger.Log.Info("Headphone", string.Format("{0} found {1} after {2} s", "HeadphoneScannerBase", d, totalSeconds));
				return d;
			});
		}

		public void StopScan()
		{
			iFit.Logger.Log.Trace("Headphone", "Stopping scanning");
			scanTimeoutSub?.Dispose();
			scanTimeoutSub = null;
			StopScanNative();
		}

		protected abstract void StopScanNative();

		protected abstract void ScanNative();

		protected void OnDeviceFound(IHeadphone device)
		{
			whenDeviceFound.OnNext(device);
		}

		protected void InvokeEnded()
		{
			this.Ended?.Invoke(this, EventArgs.Empty);
		}

		public virtual void Dispose()
		{
			StopScan();
		}
	}
}
namespace Shire.Core.Bindings
{
	public class AlertMessageTargetBinding : MvxTargetBinding<IShowAlertMessage, string>
	{
		public override string BindingName => "AlertMessage";

		public override MvxBindingMode DefaultMode => MvxBindingMode.TwoWay;

		public AlertMessageTargetBinding(IShowAlertMessage target)
			: base((object)target)
		{
			if (target == null)
			{
				throw new ArgumentNullException("target", "Object must implement IShowAlertMessage");
			}
		}

		public override void SetValue(object value)
		{
			string text = (string)value;
			if (!string.IsNullOrWhiteSpace(text))
			{
				base.Target?.ShowAlertMessage(text);
			}
		}
	}
	public static class BindingNames
	{
		public const string Message = "Message";

		public const string AlertMessage = "AlertMessage";
	}
	public class MessageTargetBinding : MvxTargetBinding<IShowMessage, string>
	{
		public override string BindingName => "Message";

		public override MvxBindingMode DefaultMode => MvxBindingMode.TwoWay;

		public MessageTargetBinding(IShowMessage target)
			: base((object)target)
		{
			if (target == null)
			{
				throw new ArgumentNullException("target", "Object must implement IShowMessage");
			}
			target.OnMessageShown -= OnMessageShown;
			target.OnMessageShown += OnMessageShown;
		}

		protected override void Dispose(bool isDisposing)
		{
			if (base.Target != null)
			{
				base.Target.OnMessageShown -= OnMessageShown;
			}
			base.Dispose(isDisposing);
		}

		public override void SetValue(object value)
		{
			string text = (string)value;
			if (!string.IsNullOrWhiteSpace(text))
			{
				base.Target?.ShowMessage(text);
			}
		}

		private void OnMessageShown(object sender, EventArgs e)
		{
			FireValueChanged("");
		}
	}
	public abstract class MvxTargetBinding<TTarget, TValue> : MvxTargetBinding
	{
		protected new TTarget Target => (TTarget)base.Target;

		public override Type TargetType => typeof(TValue);

		public abstract string BindingName { get; }

		protected MvxTargetBinding(object target)
			: base(target)
		{
		}
	}
