namespace Shire.Core.Source.Util.SystemResources
{
	public interface ISystemResources
	{
		ulong InternalFreeDiskSpace { get; }

		ulong InternalPercentFreeDiskSpace { get; }

		ulong ExternalFreeDiskSpace { get; }

		ulong ExternalPercentFreeDiskSpace { get; }
	}
	public abstract class SystemResources : ISystemResources
	{
		public abstract ulong InternalFreeDiskSpace { get; }

		public abstract ulong InternalTotalDiskSpace { get; }

		public abstract ulong ExternalFreeDiskSpace { get; }

		public abstract ulong ExternalTotalDiskSpace { get; }

		public ulong InternalPercentFreeDiskSpace => (ulong)((double)InternalFreeDiskSpace * 1.0 / ((double)InternalTotalDiskSpace * 1.0) * 100.0);

		public ulong ExternalPercentFreeDiskSpace => (ulong)((double)ExternalFreeDiskSpace * 1.0 / ((double)ExternalTotalDiskSpace * 1.0) * 100.0);
	}
	public static class BytesExtensions
	{
		public static ulong ToMegaBytes(this ulong bytes)
		{
			return bytes / 1024 / 1024;
		}
	}
	public class DiskSpaceEvent
	{
		public static class Key
		{
			public const string HasLowStorage = "hasLowStorage";

			public const string CleanupAttempted = "cleanupAttempted";

			public const string PreExternalFreeSpaceMb = "preExternalFreeSpaceMB";

			public const string PostExternalFreeSpaceMb = "postExternalFreeSpaceMB";

			public const string ExternalSpaceFreed = "externalSpaceFreedMB";

			public const string ExternalFreeSpaceExpectedMb = "externalFreeSpaceExpectedMB";

			public const string PreExternalFreePercent = "preExternalFreePercent";

			public const string PostExternalFreePercent = "postExternalFreePercent";

			public const string ExternalPercentFreed = "externalPercentFreed";

			public const string ExternalFreePercentExpected = "externalFreePercentExpected";

			public const string PreInternalFreeSpaceMb = "preInternalFreeSpaceMB";

			public const string PostInternalFreeSpaceMb = "postInternalFreeSpaceMB";

			public const string InternalSpaceFreed = "internalSpaceFreedMB";

			public const string InternalFreeSpaceExpectedMb = "internalFreeSpaceExpectedMB";

			public const string PreInternalFreePercent = "preInternalFreePercent";

			public const string PostInternalFreePercent = "postInternalFreePercent";

			public const string InternalPercentFreed = "internalPercentFreed";

			public const string InternalFreePercentExpected = "internalFreePercentExpected";
		}

		private readonly bool hasLowStorage;

		private bool cleanupAttempted;

		private readonly ulong preExternalFreeSpace;

		private ulong postExternalFreeSpace;

		private readonly ulong externalFreeSpaceExpected;

		private ulong externalBytesFreed;

		private readonly ulong preInternalFreeSpace;

		private ulong postInternalFreeSpace;

		private readonly ulong internalFreeSpaceExpected;

		private ulong internalBytesFreed;

		private readonly ulong preExternalFreePercent;

		private ulong postExternalFreePercent;

		private readonly ulong externalFreePercentExpected;

		private ulong externalPercentFreed;

		private readonly ulong preInternalFreePercent;

		private ulong postInternalFreePercent;

		private readonly ulong internalFreePercentExpected;

		private ulong internalPercentFreed;

		public DiskSpaceEvent(ulong externalFreeSpace, ulong externalFreeSpaceExpected, ulong internalFreeSpace, ulong internalFreeSpaceExpected, ulong externalFreePercent, ulong externalFreePercentExpected, ulong internalFreePercent, ulong internalFreePercentExpected, bool hasLowStorage = true)
		{
			preExternalFreeSpace = externalFreeSpace;
			this.externalFreeSpaceExpected = externalFreeSpaceExpected;
			preInternalFreeSpace = internalFreeSpace;
			this.internalFreeSpaceExpected = internalFreeSpaceExpected;
			preExternalFreePercent = externalFreePercent;
			this.externalFreePercentExpected = externalFreePercentExpected;
			preInternalFreePercent = internalFreePercent;
			this.internalFreePercentExpected = internalFreePercentExpected;
			this.hasLowStorage = hasLowStorage;
		}

		public void AddPostCleanupData(ulong externalFreeSpace, ulong internalFreeSpace, ulong externalFreePercent, ulong internalFreePercent)
		{
			cleanupAttempted = true;
			postExternalFreeSpace = externalFreeSpace;
			externalBytesFreed = postExternalFreeSpace - preExternalFreeSpace;
			postInternalFreeSpace = internalFreeSpace;
			internalBytesFreed = postInternalFreeSpace - preInternalFreeSpace;
			postExternalFreePercent = externalFreePercent;
			externalPercentFreed = postExternalFreePercent - preExternalFreePercent;
			postInternalFreePercent = internalFreePercent;
			internalPercentFreed = postInternalFreePercent - preInternalFreePercent;
		}

		public IDictionary<string, object> AnalyticsProperties()
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>
			{
				{ "hasLowStorage", hasLowStorage },
				{ "cleanupAttempted", cleanupAttempted },
				{
					"preExternalFreeSpaceMB",
					preExternalFreeSpace.ToMegaBytes()
				},
				{
					"externalFreeSpaceExpectedMB",
					externalFreeSpaceExpected.ToMegaBytes()
				},
				{ "preExternalFreePercent", preExternalFreePercent },
				{ "externalFreePercentExpected", externalFreePercentExpected },
				{
					"preInternalFreeSpaceMB",
					preInternalFreeSpace.ToMegaBytes()
				},
				{
					"internalFreeSpaceExpectedMB",
					internalFreeSpaceExpected.ToMegaBytes()
				},
				{ "preInternalFreePercent", preInternalFreePercent },
				{ "internalFreePercentExpected", internalFreePercentExpected }
			};
			if (cleanupAttempted)
			{
				dictionary.Add("postExternalFreeSpaceMB", postExternalFreeSpace.ToMegaBytes());
				dictionary.Add("externalSpaceFreedMB", externalBytesFreed.ToMegaBytes());
				dictionary.Add("postExternalFreePercent", postExternalFreePercent);
				dictionary.Add("externalPercentFreed", externalPercentFreed);
				dictionary.Add("postInternalFreeSpaceMB", postInternalFreeSpace.ToMegaBytes());
				dictionary.Add("internalSpaceFreedMB", internalBytesFreed.ToMegaBytes());
				dictionary.Add("postInternalFreePercent", postInternalFreePercent);
				dictionary.Add("internalPercentFreed", internalPercentFreed);
			}
			return dictionary;
		}

		public override string ToString()
		{
			string text = $"a:{preExternalFreeSpace.ToMegaBytes()}mb,e:{externalFreeSpaceExpected.ToMegaBytes()}mb";
			string text2 = $"a:{preExternalFreePercent}%,e:{externalFreePercentExpected}%";
			string text3 = "External:(" + text + ")(" + text2 + ")";
			string text4 = $"a:{preInternalFreeSpace.ToMegaBytes()}mb,e:{internalFreeSpaceExpected.ToMegaBytes()}mb";
			string text5 = $"a:{preInternalFreePercent}%,e:{internalFreePercentExpected}%";
			string text6 = "Internal:(" + text4 + ")(" + text5 + ")";
			return "[" + text3 + "][" + text6 + "]";
		}
	}
	public class StorageSpaceMonitor
	{
		public delegate Task DiskSpaceEventHandler(DiskSpaceEvent e);

		private const string LogTag = "DiskSpace";

		private readonly ISystemResources systemResources;

		private readonly IFeatureFlagManager featureFlagManager;

		private readonly bool isBuiltIn;

		private readonly TimeSpan minMonitorInterval = TimeSpan.FromSeconds(1.0);

		private IDisposable periodicMonitorSub;

		public event DiskSpaceEventHandler LowDiskSpaceEvent;

		public StorageSpaceMonitor(ISystemResources systemResources, IFeatureFlagManager featureFlagManager, bool isBuiltIn = false)
		{
			this.systemResources = systemResources;
			this.featureFlagManager = featureFlagManager;
			this.isBuiltIn = isBuiltIn;
			ResetMonitor();
		}

		private void ResetMonitor()
		{
			if (isBuiltIn)
			{
				if (!featureFlagManager.IsFeatureEnabled(FeatureFlags.StorageSpaceCheckEnabled))
				{
					StopMonitoring();
					return;
				}
				TimeSpan timeSpan = TimeSpan.FromSeconds(featureFlagManager.GetInt(FeatureFlags.StorageSpaceCheckInterval));
				timeSpan = TimeSpan.FromSeconds(Math.Max(minMonitorInterval.TotalSeconds, timeSpan.TotalSeconds));
				StartMonitoring(timeSpan);
			}
		}

		public void StartMonitoring(TimeSpan interval)
		{
			iFit.Logger.Log.Trace("DiskSpace", $"Beginning periodic storage space monitoring with interval {interval}.");
			StopMonitoring();
			Task.Run((Action)CheckStorageSpace);
			periodicMonitorSub = Observable.Interval(interval).SubscribeWithErrorLogging(delegate
			{
				Task.Run((Action)CheckStorageSpace);
			});
		}

		public void StopMonitoring()
		{
			iFit.Logger.Log.Trace("DiskSpace", "Stopping periodic storage space monitoring.");
			periodicMonitorSub?.Dispose();
			periodicMonitorSub = null;
		}

		private void CheckStorageSpace()
		{
			iFit.Logger.Log.Trace("DiskSpace", "Checking available storage space...");
			if (systemResources.InternalFreeDiskSpace < (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceInternalLowBytes))
			{
				RaiseLowDiskSpaceEvent();
				return;
			}
			if (systemResources.ExternalFreeDiskSpace < (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceExternalLowBytes))
			{
				RaiseLowDiskSpaceEvent();
				return;
			}
			if (systemResources.InternalPercentFreeDiskSpace < (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceInternalLowPercent))
			{
				RaiseLowDiskSpaceEvent();
				return;
			}
			if (systemResources.ExternalPercentFreeDiskSpace < (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceExternalLowPercent))
			{
				RaiseLowDiskSpaceEvent();
				return;
			}
			iFit.Logger.Log.Trace("DiskSpace", $"Finished checking available disk space. (External:{systemResources.ExternalFreeDiskSpace.ToMegaBytes()}MB|{systemResources.ExternalPercentFreeDiskSpace}%)(Internal:{systemResources.InternalFreeDiskSpace.ToMegaBytes()}MB|{systemResources.InternalPercentFreeDiskSpace}%)");
		}

		private void RaiseLowDiskSpaceEvent()
		{
			DiskSpaceEvent diskSpaceEvent = new DiskSpaceEvent(systemResources.ExternalFreeDiskSpace, (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceExternalLowBytes), systemResources.InternalFreeDiskSpace, (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceInternalLowBytes), systemResources.ExternalPercentFreeDiskSpace, (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceExternalLowPercent), systemResources.InternalPercentFreeDiskSpace, (ulong)featureFlagManager.GetInt(FeatureFlags.StorageSpaceInternalLowPercent));
			iFit.Logger.Log.Warn("DiskSpace", $"LOW DISK SPACE: {diskSpaceEvent}");
			this.LowDiskSpaceEvent?.Invoke(diskSpaceEvent);
		}
	}
