	public class CanSetControlTypes
	{
		private readonly bool mps;

		private readonly bool gear;

		private readonly bool resistance;

		private readonly bool incline;

		public CanSetControlTypes(bool mps, bool gear, bool resistance, bool incline)
		{
			this.mps = mps;
			this.gear = gear;
			if (!gear)
			{
				this.resistance = resistance;
			}
			this.incline = incline;
		}

		public bool CanSet(FitnessValue type)
		{
			return type switch
			{
				FitnessValue.Kph => mps, 
				FitnessValue.Gear => gear, 
				FitnessValue.Resistance => resistance, 
				FitnessValue.Grade => incline, 
				_ => false, 
			};
