	public interface IChangeLevelFactory : IDisposable
	{
		IScalingControlAdapter ControlAdapter { set; }

		IWorkoutRunner RunningOverrides { set; }

		IInWorkoutMetricsManager InWorkoutMetricsManager { set; }

		IChangeLevel ChangeLevel(ScalingMode modeChange);
	}
	public class ChangeLevelFactory : IChangeLevelFactory, IDisposable
	{
		protected Dictionary<ScalingMode, IChangeLevel> scalingToChangeLevel = new Dictionary<ScalingMode, IChangeLevel>();

		public IScalingControlAdapter ControlAdapter
		{
			set
			{
				foreach (IChangeLevel value2 in scalingToChangeLevel.Values)
				{
					value2.ControlAdapter = value;
				}
			}
		}

		public IWorkoutRunner RunningOverrides
		{
			set
			{
				foreach (IChangeLevel value2 in scalingToChangeLevel.Values)
				{
					value2.RunningOverrides = value;
				}
			}
		}

		public IInWorkoutMetricsManager InWorkoutMetricsManager
		{
			set
			{
				foreach (IChangeLevel value2 in scalingToChangeLevel.Values)
				{
					value2.InWorkoutMetricsManager = value;
				}
			}
		}

		public ChangeLevelFactory(IInAppNotificationService inAppNotificationService, IWorkoutFeatureService workoutFeatureService, Workout workout, bool isMetric, IFitnessConsole console)
		{
			scalingToChangeLevel.Add(ScalingMode.Legacy, new LegacyChangeLevel(inAppNotificationService, workoutFeatureService));
			scalingToChangeLevel.Add(ScalingMode.Manual, new ManualModeChangeLevel(inAppNotificationService, workoutFeatureService));
			CoachingChangeLevel value = new CoachingChangeLevel(inAppNotificationService, workoutFeatureService, workout, isMetric, console);
			scalingToChangeLevel.Add(ScalingMode.ActivePulse, value);
			scalingToChangeLevel.Add(ScalingMode.SmartAdjust, value);
		}

		public IChangeLevel ChangeLevel(ScalingMode modeChange)
		{
			scalingToChangeLevel.TryGetValue(modeChange, out var value);
			if (value == null)
			{
				throw new ArgumentOutOfRangeException("modeChange", modeChange, null);
			}
			return value;
		}

		public void Dispose()
		{
			foreach (IChangeLevel value in scalingToChangeLevel.Values)
			{
				value.Dispose();
			}
			scalingToChangeLevel = null;
		}
	}
	public class ChangedLevel
	{
		public bool RunningTimer { get; set; }

		public FitnessValue MetricType { get; set; }

		public double CurrValue { get; set; }
	}
	public class CoachingChangeLevel : AbstractChangeLevel
	{
		private const double oneStepMinValue = 0.101;

		private readonly Workout workout;

		private readonly bool isMetric;

		private readonly IFitnessConsole console;

		private readonly ConcurrentDictionary<FitnessValue, ChangedLevel> userChangedLevelTimer = new ConcurrentDictionary<FitnessValue, ChangedLevel>();

		private DateTime lastUserChange;

		private DateTime lastManualAdjustment = DateTime.MinValue;

		protected IDisposable inAppNotificationServiceSub;

		protected TimeSpan delayWaitForSecondInput = TimeSpan.FromSeconds(1.0);

		protected TimeSpan manualModeCheck = TimeSpan.FromSeconds(10.0);

		protected double previousValue;

		protected CancellationTokenSource cts;

		public TimeSpan ManualAdjustmentNotificationCadence => TimeSpan.FromMinutes(2.0);

		protected virtual DateTime Now => DateTime.Now;

		public CoachingChangeLevel(IInAppNotificationService inAppNotificationService, IWorkoutFeatureService workoutFeatureService, Workout workout, bool isMetric, IFitnessConsole console)
			: base(inAppNotificationService, workoutFeatureService)
		{
			this.workout = workout;
			this.isMetric = isMetric;
			this.console = console;
			inAppNotificationServiceSub = inAppNotificationService.NotificationChanges.Subscribe(InAppNotification);
		}

		public override void Dispose()
		{
			base.Dispose();
			inAppNotificationServiceSub?.Dispose();
			inAppNotificationServiceSub = null;
		}

		public override void Start()
		{
			base.RunningOverrides?.DisableUserOverrides(resetValues: true);
			inAppNotificationService.DismissAll(typeof(FollowNotificationData));
			base.ControlAdapter?.RestoreWorkoutScales();
		}

		public override void Stop()
		{
			cts?.Cancel();
			base.ControlAdapter?.SaveWorkoutScales();
			inAppNotificationService.DismissAll(typeof(CoachingMessageNotificationData));
			base.InWorkoutMetricsManager?.IncrementMetricBy1(InWorkoutMetric.LegacyModeSwitch);
		}

		public override void UserChangedLevel(FitnessValue metricType, double currValue)
		{
			if (!userChangedLevelTimer.ContainsKey(metricType))
			{
				userChangedLevelTimer.TryAdd(metricType, new ChangedLevel());
			}
			ChangedLevel changedLevel = userChangedLevelTimer[metricType];
			changedLevel.MetricType = metricType;
			changedLevel.CurrValue = currValue;
			if (!changedLevel.RunningTimer)
			{
				DelayUserChangedLevel(changedLevel);
			}
		}

		protected async Task DelayUserChangedLevel(ChangedLevel changeLevel)
		{
			changeLevel.RunningTimer = true;
			cts?.Cancel();
			cts = new CancellationTokenSource();
			await DelayForInput();
			if (!cts.IsCancellationRequested)
			{
				UserChangedLevelHelper(changeLevel.MetricType, changeLevel.CurrValue);
				changeLevel.RunningTimer = false;
			}
		}

		protected virtual async Task DelayForInput()
		{
			await Task.Delay(delayWaitForSecondInput);
		}

		protected void UserChangedLevelHelper(FitnessValue fitnessValue, double currValue)
		{
			ShouldUserBeInManualMode(fitnessValue, currValue);
			double diffValue = currValue - previousValue;
			(int, bool) tuple = MetricValueToScale(fitnessValue, currValue, diffValue);
			ShowCoachingNotification(fitnessValue);
			switch (fitnessValue)
			{
			case FitnessValue.Kph:
				base.InWorkoutMetricsManager.IncrementMetricBy1(ChangedUp() ? InWorkoutMetric.SpeedIncreased : InWorkoutMetric.SpeedDecreased);
				break;
			case FitnessValue.Resistance:
			case FitnessValue.Gear:
				base.InWorkoutMetricsManager.IncrementMetricBy1(ChangedUp() ? InWorkoutMetric.ResistanceIncreased : InWorkoutMetric.ResistanceDecreased);
				break;
			case FitnessValue.Grade:
				base.InWorkoutMetricsManager.IncrementMetricBy1(ChangedUp() ? InWorkoutMetric.InclineIncreased : InWorkoutMetric.InclineDecreased);
				break;
			}
			previousValue = currValue;
			if (tuple.Item2)
			{
				base.ControlAdapter.SetWorkoutScale(MetricConversions.MetricTypeToControlType(fitnessValue), tuple.Item1, pending: true);
			}
			bool ChangedUp()
			{
				return currValue > previousValue;
			}
		}

		private void ShowCoachingNotification(FitnessValue fitnessValue)
		{
			if ((fitnessValue != FitnessValue.Grade || !console.ConsoleInfo.MachineType.IsAerobicMachine()) && !(Now - lastManualAdjustment < ManualAdjustmentNotificationCadence) && inAppNotificationService != null)
			{
				lastManualAdjustment = Now;
				inAppNotificationService.Post(new CoachingMessageNotificationData(HowlSmartAdjustType.ManualAdjustment));
			}
		}

		protected void ShouldUserBeInManualMode(FitnessValue metricType, double currValue)
		{
			if ((!console.ConsoleInfo.MachineType.IsAerobicMachine() || metricType != FitnessValue.Grade) && (metricType != FitnessValue.Kph || !IsSmallestSpeedIncrement(currValue)))
			{
				TimeSpan timeSpan = Now - lastUserChange;
				if (timeSpan >= manualModeCheck && timeSpan < ManualAdjustmentNotificationCadence)
				{
					inAppNotificationService.Post(new CoachingMessageNotificationData(HowlSmartAdjustType.TurnOffSmartAdjust));
				}
				lastUserChange = Now;
			}
		}

		private bool IsSmallestSpeedIncrement(double currValue)
		{
			double num = (isMetric ? Math.Abs(currValue - previousValue) : Math.Abs(UnitUtil.EnsureMph(SpeedUnit.Kph, currValue, 1) - UnitUtil.EnsureMph(SpeedUnit.Kph, previousValue, 1)));
			return num <= 0.101;
		}

		private (int newScale, bool changeScale) MetricValueToScale(FitnessValue metricType, double newValue, double diffValue)
		{
			Dictionary<int, double> dictionary = base.ControlAdapter.ScaleValuesForControlType(MetricConversions.MetricTypeToControlType(metricType));
			if (IsAllLevelsSame(dictionary))
			{
				return (newScale: 0, changeScale: false);
			}
			if (metricType == FitnessValue.Kph)
			{
				if (isMetric)
				{
					dictionary = MetricConversions.MpsToKph(dictionary);
				}
				else
				{
					dictionary = MetricConversions.MpsToMph(dictionary);
					diffValue = UnitUtil.EnsureMph(SpeedUnit.Kph, diffValue, 1);
					newValue = UnitUtil.EnsureMph(SpeedUnit.Kph, newValue, 1);
				}
			}
			int item = MatchValueToScaleLevel(dictionary, newValue, diffValue >= 0.0);
			return (newScale: item, changeScale: true);
		}

		private void InAppNotification((NotificationChangeType type, NotificationData data) obj)
		{
			if (obj.type == NotificationChangeType.Remove && obj.data is CoachingMessageNotificationData && obj.data.ActionHappened)
			{
				CoachingMessageNotificationData coachingMessageNotificationData = obj.data as CoachingMessageNotificationData;
				if (coachingMessageNotificationData.IsMessage(HowlSmartAdjustType.TurnOffSmartAdjust))
				{
					workoutFeatureService.TurnMode(ScalingMode.SmartAdjust, on: false);
				}
				else if (coachingMessageNotificationData.IsMessage(HowlSmartAdjustType.TurnOnSmartAdjust))
				{
					workoutFeatureService.TurnMode(ScalingMode.SmartAdjust, on: true);
				}
			}
		}

		protected int MatchValueToScaleLevel(Dictionary<int, double> values, double matchValue, bool up)
		{
			int num = MinScaleLevel(values);
			int num2 = MaxScaleLevel(values);
			int num3 = 0;
			if (up)
			{
				num3 = num;
				for (int i = num; i <= num2; i++)
				{
					if (matchValue >= values[i])
					{
						num3 = i;
					}
				}
			}
			else
			{
				num3 = num2;
				for (int num4 = num2; num4 >= num; num4--)
				{
					if (matchValue <= values[num4])
					{
						num3 = num4;
					}
				}
			}
			return num3;
		}

		protected int MaxScaleLevel(Dictionary<int, double> values)
		{
			int num = values.Keys.Max();
			double b = values[num];
			int num2 = num;
			while (num2 >= 0 && values[num2].AlmostEqual(b))
			{
				num = num2;
				b = values[num];
				num2--;
			}
			return num;
		}

		protected int MinScaleLevel(Dictionary<int, double> values)
		{
			int num = values.Keys.Min();
			double b = values[num];
			for (int i = num; i < 0 && values[i].AlmostEqual(b); i++)
			{
				num = i;
				b = values[num];
			}
			return num;
		}

		private bool IsAllLevelsSame(Dictionary<int, double> values)
		{
			if (values.Count == 0)
			{
				return true;
			}
			double value = values.First().Value;
			foreach (double value2 in values.Values)
			{
				if (!value2.AlmostEqual(value))
				{
					return false;
				}
			}
			return true;
		}

		private string DebugScales(Dictionary<int, double> values)
		{
			string text = "";
			for (int num = workout.MaxWorkoutScale; num >= workout.MinWorkoutScale; num--)
			{
				double num2 = values[num];
				if (!isMetric)
				{
					num2 = UnitUtil.EnsureMph(SpeedUnit.Kph, num2, 1);
				}
				text += $"{num}={num2}\n";
			}
			return text;
		}

		private string DebugMetricValue(FitnessValue metric, double value)
		{
			if (!isMetric && metric == FitnessValue.Kph)
			{
				return $"{UnitUtil.EnsureMph(SpeedUnit.Kph, value, 1)}";
			}
			return $"{value:0.##}";
		}
	}
	public class LegacyChangeLevel : AbstractChangeLevel
	{
		private bool showFollowTrainer;

		private IDisposable subNotificationChanges;

		public LegacyChangeLevel(IInAppNotificationService inAppNotificationService, IWorkoutFeatureService workoutFeatureService)
			: base(inAppNotificationService, workoutFeatureService)
		{
			subNotificationChanges = inAppNotificationService.NotificationChanges.Where(((NotificationChangeType type, NotificationData data) x) => x.type == NotificationChangeType.Remove && x.data is FollowNotificationData).Subscribe(delegate
			{
				FollowNotificationDismissed();
			});
		}

		public override void UserChangedLevel(FitnessValue metricType, double currValue)
		{
			if (!showFollowTrainer)
			{
				showFollowTrainer = true;
				inAppNotificationService.Post(new FollowNotificationData(FollowNotificationData.FollowNotificationType.Legacy));
			}
		}

		public override void Start()
		{
			if (base.ControlAdapter != null)
			{
				showFollowTrainer = false;
				base.ControlAdapter.EnableMaxSpeedGovernor = false;
				base.ControlAdapter.SetWorkoutScale(0);
			}
		}

		public override void Stop()
		{
			if (base.ControlAdapter != null)
			{
				showFollowTrainer = false;
				base.ControlAdapter.EnableMaxSpeedGovernor = true;
			}
		}

		private void FollowNotificationDismissed()
		{
			if (workoutFeatureService.IsScalingModeEnabled(ScalingMode.Legacy))
			{
				showFollowTrainer = false;
				base.RunningOverrides.DisableUserOverrides(resetValues: true);
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			subNotificationChanges?.Dispose();
			subNotificationChanges = null;
		}
	}
	public class ManualModeChangeLevel : AbstractChangeLevel
	{
		protected IDisposable inAppNotificationServiceSub;

		public ManualModeChangeLevel(IInAppNotificationService inAppNotificationService, IWorkoutFeatureService workoutFeatureService)
			: base(inAppNotificationService, workoutFeatureService)
		{
			inAppNotificationServiceSub = inAppNotificationService.NotificationChanges.Subscribe(InAppNotification);
		}

		public override void Start()
		{
			FollowNotificationData notification = ((workoutFeatureService.SavedScalingMode == ScalingMode.Legacy) ? new FollowNotificationData(FollowNotificationData.FollowNotificationType.Legacy) : new FollowNotificationData(FollowNotificationData.FollowNotificationType.TurnOnTrainingMode));
			inAppNotificationService.Post(notification);
			base.RunningOverrides.EnableUserOverrides();
		}

		public override void Stop()
		{
			base.RunningOverrides.DisableUserOverrides(resetValues: true);
		}

		private void InAppNotification((NotificationChangeType type, NotificationData data) obj)
		{
			if (obj.type == NotificationChangeType.Remove && obj.data is FollowNotificationData { ActionHappened: not false })
			{
				workoutFeatureService.TurnMode(ScalingMode.Manual, on: false);
			}
		}

		public override void Dispose()
		{
			base.Dispose();
			inAppNotificationServiceSub?.Dispose();
			inAppNotificationServiceSub = null;
		}
	}
}
namespace Shire.Core.Source.Services.ConnectivityService
{
	public enum ConnectivityStatus
	{
		Internet,
		InternetNoAccess,
		Local,
		ConstrainedInternet,
		None,
		Unknown
