		private void StopRecordingNonScalingMetrics(DateTime time)
		{
			StopRecordingMetricTime(InWorkoutMetric.Legacy, time);
			StopRecordingMetricTime(InWorkoutMetric.Manual, time);
		}

		private void IfMetricIsNotRunningBeginTracking(InWorkoutMetric metric, DateTime time)
		{
			if (runningTimeMetric.TryGetValue(metric, out var value) && !value.IsMetricRunning)
			{
				runningTimeMetric[metric] = new TimeBasedMetric(isMetricRunning: true, time);
			}
		}

		private void IfMetricIsNotRunningBeginTracking(WorkoutControlChangeMetric metric, DateTime time, Dictionary<WorkoutControlChangeMetric, TimeBasedMetric> timeMetricDict)
		{
			if (!timeMetricDict.TryGetValue(metric, out var value))
			{
				value = new TimeBasedMetric(isMetricRunning: false, time);
				timeMetricDict.Add(metric, value);
			}
			if (!value.IsMetricRunning)
			{
				timeMetricDict[metric] = new TimeBasedMetric(isMetricRunning: true, time);
			}
		}

		private void IfMetricIsRunningStopTracking(InWorkoutMetric metric, DateTime time)
		{
			if (runningTimeMetric.TryGetValue(metric, out var value) && value.IsMetricRunning)
			{
				StopRecordingMetricTime(metric, time);
			}
		}

		public void StartRecordingMetricTime(InWorkoutMetric metric)
		{
			DateTime utcNow = DateTime.UtcNow;
			IfMetricIsNotRunningBeginTracking(metric, utcNow);
			switch (metric)
			{
			case InWorkoutMetric.Legacy:
				StopRecordingMetricTime(InWorkoutMetric.Manual, utcNow);
				StopRecordingMetricTime(InWorkoutMetric.TimeActivePulseEnabled, utcNow);
				StopRecordingMetricTime(InWorkoutMetric.TimeSmartAdjustEnabled, utcNow);
				StopRecordingZoneTimeMetrics(utcNow);
				break;
			case InWorkoutMetric.TimeActivePulseEnabled:
				StopRecordingNonScalingMetrics(utcNow);
				IfMetricIsNotRunningBeginTracking(InWorkoutMetric.TimeSmartAdjustEnabled, utcNow);
				break;
			case InWorkoutMetric.TimeSmartAdjustEnabled:
				StopRecordingNonScalingMetrics(utcNow);
				IfMetricIsRunningStopTracking(InWorkoutMetric.TimeActivePulseEnabled, utcNow);
				break;
			}
		}

		public void StartRecordingMetricTime(WorkoutControlChangeMetric metric, ConsoleState currentState)
		{
			DateTime utcNow = DateTime.UtcNow;
			switch (currentState)
			{
			case ConsoleState.WarmUp:
				IfMetricIsNotRunningBeginTracking(metric, utcNow, warmUpControlsTimeMetrics);
				break;
			case ConsoleState.Workout:
				IfMetricIsNotRunningBeginTracking(metric, utcNow, runningControlsTimeMetrics);
				break;
			case ConsoleState.CoolDown:
				IfMetricIsNotRunningBeginTracking(metric, utcNow, coolDownControlsTimeMetrics);
				break;
			}
		}

		public void StopRecordingMetricTime(InWorkoutMetric metric, DateTime stopTime)
		{
			if (!runningTimeMetric.TryGetValue(metric, out var value) || !value.IsMetricRunning)
			{
				return;
			}
			DateTime startTime = value.StartTime;
			if (MetricDictionary.TryGetValue(metric, out var value2))
			{
				double num = stopTime.Subtract(startTime).TotalSeconds + (double)value2.Value;
				if (num >= 0.0)
				{
					value2.Value = (int)num;
					value2.DoubleValue = num;
					value.IsMetricRunning = false;
				}
			}
		}

		public void StopRecordingMetricTime(WorkoutControlChangeMetric metric, DateTime stopTime, ConsoleState currentState)
		{
			switch (currentState)
			{
			case ConsoleState.WarmUp:
				StopRecordingSliderMetricTime(metric, stopTime, warmUpControlsTimeMetrics, WarmupControlChangesDictionary);
				break;
			case ConsoleState.Workout:
				StopRecordingSliderMetricTime(metric, stopTime, runningControlsTimeMetrics, RunningControlChangesDictionary);
				break;
			case ConsoleState.CoolDown:
				StopRecordingSliderMetricTime(metric, stopTime, coolDownControlsTimeMetrics, CooldownControlChangesDictionary);
				break;
			}
		}

		private void StopRecordingSliderMetricTime(WorkoutControlChangeMetric metric, DateTime stopTime, IReadOnlyDictionary<WorkoutControlChangeMetric, TimeBasedMetric> timeBasedMetricDict, IReadOnlyDictionary<WorkoutControlChangeMetric, MetricEntry> controlChangesDict)
		{
			if (!timeBasedMetricDict.TryGetValue(metric, out var value) || !value.IsMetricRunning)
			{
				return;
			}
			DateTime startTime = value.StartTime;
			if (controlChangesDict.TryGetValue(metric, out var value2))
			{
				double num = stopTime.Subtract(startTime).TotalSeconds + (double)value2.Value;
				if (num >= 0.0)
				{
					value2.Value = (int)num;
					value2.DoubleValue = num;
					value.IsMetricRunning = false;
				}
			}
		}

		public void StopAllPulseTimeBasedMetrics(DateTime stopTime)
		{
			foreach (KeyValuePair<InWorkoutMetric, TimeBasedMetric> item in runningTimeMetric)
			{
				StopRecordingMetricTime(item.Key, stopTime);
			}
			runningTimeMetric.Clear();
		}

		public Dictionary<string, object> HrmConnectedToAnalytics()
		{
			bool flag = MetricDictionary[InWorkoutMetric.HeartRateMonitorConnected].Value > 0;
			return new Dictionary<string, object> { { "hrmConnected", flag } };
		}

		public Dictionary<string, object> PulsePercentageMetricsToAnalytics()
		{
			double num = DurationToPercent(InWorkoutMetric.TimeActivePulseEnabled);
			double num2 = DurationToPercent(InWorkoutMetric.TimeSmartAdjustEnabled);
			double num3 = DurationToPercent(InWorkoutMetric.Legacy);
			double num4 = DurationToPercent(InWorkoutMetric.Manual);
			return new Dictionary<string, object>
			{
				{ "activePulsePct", num },
				{ "smartAdjustPct", num2 },
				{ "legacyPct", num3 },
				{ "manualPct", num4 }
			};
		}

		public Dictionary<string, object> PulseCorrectZoneMetricsToAnalytics(string pulseAlgorithm)
		{
			double doubleValue = MetricDictionary[InWorkoutMetric.TimeInTargetZoneOne].DoubleValue;
			double doubleValue2 = MetricDictionary[InWorkoutMetric.TimeInTargetZoneTwo].DoubleValue;
			double doubleValue3 = MetricDictionary[InWorkoutMetric.TimeInTargetZoneThree].DoubleValue;
			double doubleValue4 = MetricDictionary[InWorkoutMetric.TimeInTargetZoneFour].DoubleValue;
			double doubleValue5 = MetricDictionary[InWorkoutMetric.TimeInTargetZoneFive].DoubleValue;
			double num = doubleValue + doubleValue2 + doubleValue3 + doubleValue4 + doubleValue5;
			double num2 = DurationToPercent(InWorkoutMetric.TimeInTargetZoneOne, InWorkoutMetric.TimeWorkoutInZoneOne);
			double num3 = DurationToPercent(InWorkoutMetric.TimeInTargetZoneTwo, InWorkoutMetric.TimeWorkoutInZoneTwo);
			double num4 = DurationToPercent(InWorkoutMetric.TimeInTargetZoneThree, InWorkoutMetric.TimeWorkoutInZoneThree);
			double num5 = DurationToPercent(InWorkoutMetric.TimeInTargetZoneFour, InWorkoutMetric.TimeWorkoutInZoneFour);
			double num6 = DurationToPercent(InWorkoutMetric.TimeInTargetZoneFive, InWorkoutMetric.TimeWorkoutInZoneFive);
			double num7 = Math.Round(num / MetricDictionary[InWorkoutMetric.TimeActivePulseEnabled].DoubleValue, 2);
			int value = MetricDictionary[InWorkoutMetric.EnteredZoneOne].Value;
			int value2 = MetricDictionary[InWorkoutMetric.EnteredZoneTwo].Value;
			int value3 = MetricDictionary[InWorkoutMetric.EnteredZoneThree].Value;
			int value4 = MetricDictionary[InWorkoutMetric.EnteredZoneFour].Value;
			int value5 = MetricDictionary[InWorkoutMetric.EnteredZoneFive].Value;
			return new Dictionary<string, object>
			{
				{ "timeInTargetZone", num },
				{ "timeInZoneOne", doubleValue },
				{ "timeInZoneTwo", doubleValue2 },
				{ "timeInZoneThree", doubleValue3 },
				{ "timeInZoneFour", doubleValue4 },
				{ "timeInZoneFive", doubleValue5 },
				{ "pulseAlgorithm", pulseAlgorithm },
				{ "InZoneOnePct", num2 },
				{ "InZoneTwoPct", num3 },
				{ "InZoneThreePct", num4 },
				{ "InZoneFourPct", num5 },
				{ "InZoneFivePct", num6 },
				{ "InTargetZoneActivePulsePct", num7 },
				{ "workoutEnteredZoneOne", value },
				{ "workoutEnteredZoneTwo", value2 },
				{ "workoutEnteredZoneThree", value3 },
				{ "workoutEnteredZoneFour", value4 },
				{ "workoutEnteredZoneFive", value5 }
			};
		}

		private double DurationToPercent(InWorkoutMetric state)
		{
			double doubleValue = MetricDictionary[InWorkoutMetric.UserDuration].DoubleValue;
			double value = MetricDictionary[state].DoubleValue / doubleValue * 100.0;
			return Math.Round(value, 1);
		}

		private double DurationToPercent(InWorkoutMetric numeration, InWorkoutMetric denomination)
		{
			double doubleValue = MetricDictionary[numeration].DoubleValue;
			double doubleValue2 = MetricDictionary[denomination].DoubleValue;
			if (doubleValue == 0.0 || doubleValue2 == 0.0)
			{
				return 0.0;
			}
			double value = doubleValue / doubleValue2;
			return Math.Round(value, 2);
		}

		private double DurationToPercent(IReadOnlyDictionary<WorkoutControlChangeMetric, MetricEntry> changeDictionary, WorkoutControlChangeMetric changeMetric)
		{
			double doubleValue = changeDictionary[changeMetric].DoubleValue;
			double doubleValue2 = changeDictionary[WorkoutControlChangeMetric.ConsoleStateDuration].DoubleValue;
			if (doubleValue == 0.0 || doubleValue2 == 0.0)
			{
				return 0.0;
			}
			return Math.Round(doubleValue / doubleValue2, 2);
		}

		public Dictionary<string, object> PulseControlMetricsToAnalytics()
		{
			int value = MetricDictionary[InWorkoutMetric.SpeedIncreased].Value;
			int value2 = MetricDictionary[InWorkoutMetric.SpeedDecreased].Value;
			int value3 = MetricDictionary[InWorkoutMetric.InclineIncreased].Value;
			int value4 = MetricDictionary[InWorkoutMetric.InclineDecreased].Value;
			int value5 = MetricDictionary[InWorkoutMetric.ResistanceIncreased].Value;
			int value6 = MetricDictionary[InWorkoutMetric.ResistanceDecreased].Value;
			return new Dictionary<string, object>
			{
				{ "speedIncreased", value },
				{ "speedDecreased", value2 },
				{ "inclineIncreased", value3 },
				{ "inclineDecreased", value4 },
				{ "resistanceIncreased", value5 },
				{ "resistanceDecreased", value6 }
			};
		}

		public Dictionary<string, object> ControlChangeMetricsToAnalytics()
		{
			double num = DurationToPercent(WarmupControlChangesDictionary, WorkoutControlChangeMetric.SoftwareSlidersTime);
			Dictionary<string, object> value = new Dictionary<string, object>
			{
				{
					"softwareSpeedChanges",
					WarmupControlChangesDictionary[WorkoutControlChangeMetric.SoftwareSpeedChanges].Value
				},
				{
					"hardwareSpeedChanges",
					WarmupControlChangesDictionary[WorkoutControlChangeMetric.HardwareSpeedChanges].Value
				},
				{
					"speedAverageChange",
					WarmupControlChangesDictionary[WorkoutControlChangeMetric.AverageSpeedChange].DoubleValue
				},
				{
					"softwareInclineChanges",
					WarmupControlChangesDictionary[WorkoutControlChangeMetric.SoftwareInclineChanges].Value
				},
				{
					"hardwareInclineChanges",
					WarmupControlChangesDictionary[WorkoutControlChangeMetric.HardwareInclineChanges].Value
				},
