			}
			case ConsoleState.Workout:
			{
				if (RunningControlChangesDictionary.TryGetValue(workoutControlChanges, out var value3))
				{
					value3.Value++;
				}
				break;
			}
			case ConsoleState.CoolDown:
			{
				if (CooldownControlChangesDictionary.TryGetValue(workoutControlChanges, out var value))
				{
					value.Value++;
				}
				break;
			}
