	public class DeliminatorSeparatedPropertyNamesContractResolver : DefaultContractResolver
	{
		private readonly string Separator;

		protected DeliminatorSeparatedPropertyNamesContractResolver(char separator)
		{
			Separator = separator.ToString();
		}

		protected override string ResolvePropertyName(string propertyName)
		{
			List<string> list = new List<string>();
			StringBuilder stringBuilder = new StringBuilder();
			foreach (char c in propertyName)
			{
				if (char.IsUpper(c) && stringBuilder.Length > 0)
				{
					list.Add(stringBuilder.ToString());
					stringBuilder.Clear();
				}
				stringBuilder.Append(char.ToLower(c));
			}
			if (stringBuilder.Length > 0)
			{
				list.Add(stringBuilder.ToString());
			}
			return string.Join(Separator, list.ToArray());
		}
	}
	public class UnixTimeConverter : DateTimeConverterBase
	{
		protected static readonly DateTime _epoch = new DateTime(1970, 1, 1, 0, 0, 0, DateTimeKind.Utc);

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			if (value == null || (DateTime)value < _epoch)
			{
				writer.WriteValue(0);
			}
			else
			{
				writer.WriteValue(Math.Round(((DateTime)value - _epoch).TotalMilliseconds).ToString());
			}
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			if (reader.Value == null)
			{
				return null;
			}
			if (reader.Value is long num && num <= 0)
			{
				return _epoch;
			}
			long num2 = ((reader.Value is long num3) ? num3 : Convert.ToInt64((string)reader.Value));
			return _epoch.AddMilliseconds(num2);
		}
	}
	public class UnixTimeConverterLong : UnixTimeConverter
	{
		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			if (value == null || (DateTime)value < UnixTimeConverter._epoch)
			{
				writer.WriteValue(0);
				return;
			}
			double value2 = Math.Round(((DateTime)value - UnixTimeConverter._epoch).TotalMilliseconds);
			writer.WriteValue(value2);
		}
	}
