	internal class TimeSpanConverter : JsonConverter
	{
		private const int MaxAllowedMinutes = 1439;

		private const string MaxTimeString = "23:59";

		private const string MinTimeString = "00:00";

		public override bool CanConvert(Type objectType)
		{
			return true;
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			string text = reader.Value as string;
			return string.IsNullOrEmpty(text) ? TimeSpan.FromSeconds(0.0) : DateTime.ParseExact(text, "HH:mm", CultureInfo.InvariantCulture).TimeOfDay;
		}

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			TimeSpan timeSpan = (TimeSpan)value;
			if (timeSpan.TotalMinutes <= 0.0)
			{
				writer.WriteValue("00:00");
				return;
			}
			if (timeSpan.TotalMinutes >= 1439.0)
			{
				writer.WriteValue("23:59");
				return;
			}
			string value2 = timeSpan.ToString("hh\\:mm");
			writer.WriteValue(value2);
		}
	}
