	public static class ScaledConverterHelper
	{
		public static string ScaleLevelToName(int level)
		{
			if (level < 0)
			{
				return $"minus_{Math.Abs(level)}";
			}
			if (level > 0)
			{
				return $"plus_{level}";
			}
			return "zero";
		}

		public static int ScaleNameToLevel(string name)
		{
			string[] array = name.Split('_');
			if (array.Count() != 2)
			{
				return 0;
			}
			try
			{
				int num = Convert.ToInt32(array[1]);
				if (array[0].Equals("minus"))
				{
					num *= -1;
				}
				return num;
			}
			catch (Exception ex)
			{
				iFit.Logger.Log.Error("Api", "Unable to parse scaled name: " + name + ". " + ex.Message, ex);
			}
			return 0;
		}
	}
	public class ScaledLevelValueConverter : JsonConverter
	{
		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			writer.WriteValue(ScaledConverterHelper.ScaleLevelToName((int)value));
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			if (reader.TokenType == JsonToken.String)
			{
				return ScaledConverterHelper.ScaleNameToLevel((string)reader.Value);
			}
			return 0;
		}

		public override bool CanConvert(Type objectType)
		{
			return objectType == typeof(int);
		}
	}
	public class ScaledWorkoutControlsConverter : JsonConverter
	{
		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			Dictionary<int, List<Workout.Control>> dictionary = (Dictionary<int, List<Workout.Control>>)value;
			writer.WriteStartObject();
			foreach (KeyValuePair<int, List<Workout.Control>> item in dictionary)
			{
				if (item.Key != 0)
				{
					writer.WritePropertyName(ScaledConverterHelper.ScaleLevelToName(item.Key));
					serializer.Serialize(writer, dictionary[item.Key]);
				}
			}
			writer.WriteEndObject();
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			Dictionary<int, List<Workout.Control>> dictionary = new Dictionary<int, List<Workout.Control>>();
			if (reader.TokenType == JsonToken.StartObject)
			{
				JObject jObject = JObject.Load(reader);
				foreach (JProperty item in jObject.Properties())
				{
					int key = ScaledConverterHelper.ScaleNameToLevel(item.Name);
					dictionary.Add(key, jObject[item.Name].ToObject<List<Workout.Control>>(serializer));
				}
			}
			return dictionary;
		}

		public override bool CanConvert(Type objectType)
		{
			return objectType == typeof(Dictionary<int, List<Workout.Control>>);
		}
	}
	public class NumberIntConverter : JsonConverter
	{
		public override bool CanConvert(Type objectType)
		{
			if (!(objectType == typeof(decimal)) && !(objectType == typeof(decimal?)))
			{
				return objectType == typeof(string);
			}
			return true;
		}

		public override object ReadJson(JsonReader reader, Type objectType, object existingValue, JsonSerializer serializer)
		{
			JToken jToken = JToken.Load(reader);
			if (jToken.Type == JTokenType.Float || jToken.Type == JTokenType.Integer || jToken.Type == JTokenType.String)
			{
				decimal d = jToken.ToObject<decimal>();
				if (objectType == typeof(int))
				{
					return decimal.ToInt32(d);
				}
				if (objectType == typeof(long))
				{
					return decimal.ToInt64(d);
				}
				if (objectType == typeof(uint))
				{
					return decimal.ToUInt32(d);
				}
				if (objectType == typeof(ulong))
				{
					return decimal.ToUInt64(d);
				}
				if (objectType == typeof(float))
				{
					return decimal.ToSingle(d);
				}
				if (objectType == typeof(double))
				{
					return decimal.ToDouble(d);
				}
			}
			if (jToken.Type == JTokenType.Null && objectType == typeof(decimal?))
			{
				return 0.0;
			}
			throw new JsonSerializationException("Unexpected token type: " + jToken.Type);
		}

		public override void WriteJson(JsonWriter writer, object value, JsonSerializer serializer)
		{
			writer.WriteValue(value);
		}
	}
