		public static async Task<List<Tron>> FetchTronUsers(IIfitApiService api, IEnumerable<string> userIds)
		{
			try
			{
				string userIdsString = string.Join(",", userIds);
				return await WebDataObject.DefaultPolicy.ExecuteAsync(async () => await api.GatewayService.TronUsers(userIdsString));
			}
			catch (ConnectivityException exception)
			{
				iFit.Logger.Log.Error("Api", "ConnectivityException occurred during $User.FetchTronUsers() request", exception);
				return null;
			}
			catch (Exception exception2)
			{
				iFit.Logger.Log.Trace("Api", "FetchTronUsers failed. Returning a null list of tron users", exception2);
				return null;
			}
		}
