	public static class WorkoutTypeExtensions
	{
		public static bool IsRowWorkout(this Workout.WorkoutType type)
		{
			if (type != Workout.WorkoutType.Row)
			{
				return type == Workout.WorkoutType.Rowing;
			}
			return true;
		}

		public static bool IsStrengthWorkout(this Workout workout)
		{
			if (workout == null)
			{
				return false;
			}
			return workout.Type == Workout.WorkoutType.Strength;
		}
	}
