namespace Shire.Core.Api.CyberSource.Service
{
	public interface ITransactionRunner
	{
		Task<ReplyResponse> RunTransaction(XDocument request, bool sendToProduction = true);
	}
	public class TransactionRunner : ITransactionRunner
	{
		private HttpClient client;

		public TransactionRunner(HttpClient client = null)
		{
			this.client = client;
			if (client == null)
			{
				this.client = new HttpClient();
			}
		}

		public async Task<ReplyResponse> RunTransaction(XDocument request, bool sendToProduction = true)
		{
			byte[] bytes = Encoding.UTF8.GetBytes(request.ToString());
			Uri uri = new Uri(sendToProduction ? "https://ics2wsa.ic3.com/commerce/1.x/transactionProcessor" : "https://ics2wstesta.ic3.com/commerce/1.x/transactionProcessor");
			client = new HttpClient(new NativeMessageHandler())
			{
				BaseAddress = uri
			};
			client.DefaultRequestHeaders.Add("SOAPAction", "");
			client.DefaultRequestHeaders.Accept.Add(new MediaTypeWithQualityHeaderValue("text/xml"));
			client.Timeout = TimeSpan.FromMilliseconds(30000.0);
			client.DefaultRequestHeaders.Add("User-Agent", ".NET XML");
			HttpContent httpContent = new StringContent(request.ToString());
			httpContent.Headers.ContentLength = bytes.Length;
			httpContent.Headers.ContentType.CharSet = "UTF-8";
			httpContent.Headers.ContentType.MediaType = "application/soap+xml";
			XDocument reply = XDocument.Load(await (await client.PostAsync(uri, httpContent)).Content.ReadAsStreamAsync());
			ReplyParser replyParser = new ReplyParser();
			return replyParser.ParseReply(reply);
		}
	}
}
