namespace Shire.Core.Api.CyberSource.Reply
{
	public static class ReplyFields
	{
		public const string ReplyMessage = "replyMessage";

		public const string Decision = "decision";

		public const string MerchantReferenceCode = "merchantReferenceCode";

		public const string RequestToken = "requestToken";

		public const string PaySubscriptionReply = "paySubscriptionCreateReply";

		public const string SubscriptionId = "subscriptionID";

		public const string PurchaseTotals = "purchaseTotals";

		public const string Currency = "currency";

		public const string ReasonCode = "reasonCode";

		public const string RequestId = "requestID";

		public const string CCAuthReply = "ccAuthReply";

		public const string Amount = "amount";

		public const string AuthorizationCode = "authorizationCode";

		public const string AvsCode = "avsCode";

		public const string AvsCodeRaw = "avsCodeRaw";

		public const string AuthorizedDateTime = "authorizedDateTime";

		public const string ProcessorResponse = "processorResponse";

		public const string ReconciliationId = "reconciliationID";

		public const string AuthRecord = "authRecord";
	}
	public class ReplyParser
	{
		private ReplyResponse replyResponse;

		private readonly XNamespace ns = "urn:schemas-cybersource-com:transaction-data-1.127";

		private readonly XNamespace soap = "http://schemas.xmlsoap.org/soap/envelope/";

		public ReplyResponse ParseReply(XDocument reply)
		{
			replyResponse = new ReplyResponse();
			var source = from body in reply.Descendants(soap + "Body")
				let header = body.Element(ns + "replyMessage")
				select new
				{
					MerchantReferenceCode = (string)header.Element(ns + "merchantReferenceCode"),
					RequestId = (string)header.Element(ns + "requestID"),
					Decision = (string)header.Element(ns + "decision"),
					ReasonCode = (string)header.Element(ns + "reasonCode"),
					RequestToken = (string)header.Element(ns + "requestToken")
				};
			var anon = source.ElementAt(0);
			ReasonExtensions.Reason reason = ParseReasonCodeToEnum(anon.ReasonCode);
			if (reason == ReasonExtensions.Reason.OneHundred)
			{
				var source2 = from replyMessage in reply.Descendants(ns + "replyMessage")
					let header = replyMessage.Element(ns + "ccAuthReply")
					select new
					{
						ReasonCode = (string)header.Element(ns + "reasonCode"),
						AuthorizationCode = (string)header.Element(ns + "authorizationCode"),
						AvsCode = (string)header.Element(ns + "avsCode"),
						AvsRawCode = (string)header.Element(ns + "avsCodeRaw"),
						AuthorizationDateTime = (string)header.Element(ns + "authorizedDateTime"),
						ProcessorResponse = (string)header.Element(ns + "processorResponse"),
						ReconciliationId = (string)header.Element(ns + "reconciliationID"),
						AuthRecord = (string)header.Element(ns + "authRecord")
					};
				var source3 = from replyMessage in reply.Descendants(ns + "replyMessage")
					let header = replyMessage.Element(ns + "paySubscriptionCreateReply")
					select new
					{
						ReasonCode = (string)header.Element(ns + "reasonCode"),
						SubscriptionId = (string)header.Element(ns + "subscriptionID")
					};
				replyResponse.AvsResponseCode = source2.ElementAt(0).AvsCode;
				replyResponse.AvsResponseCodeIsValid = AddressVerification.AvsSuccessful(replyResponse.AvsResponseCode);
				replyResponse.PaySubscriptionReplySubscriptionId = source3.ElementAt(0).SubscriptionId;
			}
			replyResponse.ReasonCode = anon.ReasonCode;
			replyResponse.ReasonCodeDefinition = reason.GetDefinitions();
			replyResponse.Decision = anon.Decision;
			replyResponse.RequestId = anon.RequestId;
			return replyResponse;
		}

		private ReasonExtensions.Reason ParseReasonCodeToEnum(string reasonCode)
		{
			return (ReasonExtensions.Reason)Enum.ToObject(typeof(ReasonExtensions.Reason), int.Parse(reasonCode));
		}
	}
	public class ReplyResponse
	{
		public const string DecisionAccept = "ACCEPT";

		public const string SuccessResponse = "100";

		public string Decision { get; set; }

		public string MerchantReferenceCode { get; set; }

		public string PaySubscriptionReplyReasonCode { get; set; }

		public string PaySubscriptionReplySubscriptionId { get; set; }

		public string PurchaseTotalsCurrency { get; set; }

		public string ReasonCode { get; set; }

		public string ReasonCodeDefinition { get; set; }

		public string RequestId { get; set; }

		public bool AvsResponseCodeIsValid { get; set; }

		public string AvsResponseCode { get; set; }

		public bool IsSuccessfulResponse()
		{
			if (AvsResponseCodeIsValid && Decision.Equals("ACCEPT"))
			{
				return ReasonCode.Equals("100");
			}
			return false;
		}
	}
}
