namespace Shire.Core.Api.Apple
{
	public static class iTunesApiService
	{
		private const string iTunesSandboxApiUrl = "https://sandbox.itunes.apple.com";

		private const string iTunesProductionApiUrl = "https://buy.itunes.apple.com";

		private static IReceiptDataFetcher ReceiptFetcher;

		public static IiTunesApi CreateProductionApi()
		{
			return CreateApi<IiTunesApi>("https://buy.itunes.apple.com");
		}

		public static IiTunesSandboxApi CreateSandboxApi()
		{
			return CreateApi<IiTunesSandboxApi>("https://sandbox.itunes.apple.com");
		}

		private static T CreateApi<T>(string apiUrl)
		{
			RefitSettings settings = new RefitSettings
			{
				ContentSerializer = new NewtonsoftJsonContentSerializer(new JsonSerializerSettings
				{
					ContractResolver = new SnakeCasePropertyNamesContractResolver(),
					NullValueHandling = NullValueHandling.Ignore
				})
			};
			HttpClient client = new HttpClient(new NativeMessageHandler())
			{
				BaseAddress = new Uri(apiUrl)
			};
			return RestService.For<T>(client, settings);
		}

		public static ValidationRequest CreateValidationRequest(bool excludeOldTransactions = true)
		{
			if (ReceiptFetcher == null)
			{
				ReceiptFetcher = Mvx.Resolve<IReceiptDataFetcher>();
			}
			ValidationRequest validationRequest = new ValidationRequest();
			validationRequest.ReceiptData = ReceiptFetcher.ExtractReceiptData();
			validationRequest.Password = ReconstructPassword(new int[8] { 3, 0, 1, 7, 2, 5, 4, 6 }, new string[8] { "583c", "f87b", "9420", "7983", "7425", "d9cb", "8add", "4910" });
			validationRequest.ExcludeOldTransactions = excludeOldTransactions;
			return validationRequest;
		}

		private static string ReconstructPassword(int[] order, string[] pieces)
		{
			string text = string.Empty;
			foreach (int num in order)
			{
				text += pieces[num];
			}
			return text;
		}
	}
	public class NoReceiptFoundException : Exception
	{
	}
}
