		private const string EventDeepLinkNavigationFailed = "Deep Link Navigation Failed";

		private const string EventRaygunReportAppCrashed = "Raygun Report: App Crash";

		private const string GoogleEventRaygunReportAppCrashed = "Raygun_Report_App_Crash";

		private const int AnalyticsMaxStringLength = 100;

		protected const string WolfGeneratedIdKey = "wolfGeneratedId";

		protected const string WorkoutIdKey = "workoutId";

		protected const string WorkoutInstanceId = "workoutInstanceId";

		private const string LinkKey = "link";

		public const string GoogleTrackBufferCacheName = "GoogleEvents";

		private IFeatureFlagManager _featureFlagManager;

		private readonly IHardwareInfo hardwareInfo;

		protected Task initialOnUserChangedTask;

		private IDisposable whenApiEnvironmentChangedSub;

		private readonly bool isDebug;

		private readonly IGoogleAnalytics googleAnalytics;

		private bool? isFirebaseAnalyticsCollectionEnabled;

		private bool wasUserIdSetWhileFirebaseAnalyticsCollectionDisabled;

		private readonly IDictionary<string, string> userPropertiesSetWhileFirebaseAnalyticsCollectionDisabled = new Dictionary<string, string>();

		private Queue<GoogleAnalyticsEvent> googleTrackBuffer;

		private IBlobCacheService blobCacheService;

		public IFeatureFlagManager FeatureFlagManager
		{
			get
			{
				return _featureFlagManager;
			}
			set
			{
				_featureFlagManager = value;
				if (value != null)
				{
					GetIsGoogleAnalyticsFeatureFlagEnabled();
				}
			}
		}

		private IDisposable WhenDateChangedSub { get; set; }

		private IDisposable UserChangeSubscription { get; set; }

		protected IDisposable WhenConsoleChangedSub { get; set; }

		protected IDisposable WhenConsoleInitializedSub { get; set; }

		protected virtual bool IsBuiltIn => false;

		protected virtual bool IsBuiltInClub => false;

		public bool VisibleAnalytics { get; private set; }

		protected IFitnessConsole Console { get; set; }

		protected IConsoleInfo ClubConsoleInfo { get; set; }

		protected IIfitApiService IfitApi { get; }

		private ISchedulerService SchedulerService { get; }

		private IAppVersionService AppVersionService { get; }

		protected IIpcVersionInfo IpcVersionInfo { get; set; }

		public bool IsSegmentEnabled => IsServiceEnabled("segment");

		protected CoreAnalytics(IGoogleAnalytics googleAnalytics, IIfitApiService ifitApi, IFitnessConsole console, IHardwareInfo hardwareInfo, IAppVersionService appVersionService, ISchedulerService schedulerService, IIpcVersionInfo ipcVersionInfo, IConnectivity connectivity, bool isDebug)
			: base(delegate(string s)
			{
				iFit.Logger.Log.Error("Analytics", s);
			}, connectivity)
		{
			this.googleAnalytics = googleAnalytics;
			this.hardwareInfo = hardwareInfo;
			IfitApi = ifitApi;
			Console = console;
			SchedulerService = schedulerService;
			AppVersionService = appVersionService;
			IpcVersionInfo = ipcVersionInfo;
			this.isDebug = isDebug;
			SetupGoogleAnalyticsEnvironmentUserProperty();
		}

		protected CoreAnalytics(IGoogleAnalytics googleAnalytics, IIfitApiService ifitApi, IFitnessConsole console, IHardwareInfo hardwareInfo, IAppVersionService appVersionService, ISchedulerService schedulerService, IConnectivity connectivity, bool isDebug, IClient client)
			: base(client, connectivity)
		{
			this.googleAnalytics = googleAnalytics;
			this.hardwareInfo = hardwareInfo;
			IfitApi = ifitApi;
			Console = console;
			SchedulerService = schedulerService;
			AppVersionService = appVersionService;
			this.isDebug = isDebug;
			SetupGoogleAnalyticsEnvironmentUserProperty();
		}

		private void SetupGoogleAnalyticsEnvironmentUserProperty()
		{
			SetGoogleAnalyticsEnvironmentUserProperty(IfitApi.Environment);
			whenApiEnvironmentChangedSub?.Dispose();
			whenApiEnvironmentChangedSub = IfitApi.WhenApiEnvironmentChanged.SubscribeWithErrorLogging(SetGoogleAnalyticsEnvironmentUserProperty);
		}

		private void SetGoogleAnalyticsEnvironmentUserProperty(IIfitEnvironment environment)
		{
			SetGoogleAnalyticsUserProperty("environment", environment?.Name?.ToLower());
		}

		public virtual async Task Initialize(string apiKey, string currentlyLoggedInUserId, Config config = null)
		{
			await base.Initialize(apiKey, currentlyLoggedInUserId, hardwareInfo.OperatingSystem, hardwareInfo.AnalyticsDeviceId, config);
			UserChangeSubscription = Sindarin.Core.Util.ObservableExtensions.SubscribeAsync(IfitApi.WhenCurrentUserIdChanged, (string _) => OnUserChanged());
			WhenDateChangedSub = Sindarin.Core.Util.ObservableExtensions.SubscribeAsync(SchedulerService.WhenDayChanged, OnDateChanged);
			initialOnUserChangedTask = Task.Run(async delegate
			{
				await OnUserChanged().ConfigureAwait(continueOnCapturedContext: false);
				initialOnUserChangedTask = null;
			});
		}

		public void Dispose()
		{
			WhenDateChangedSub?.Dispose();
			WhenDateChangedSub = null;
			UserChangeSubscription?.Dispose();
			UserChangeSubscription = null;
			WhenConsoleChangedSub?.Dispose();
			WhenConsoleChangedSub = null;
			WhenConsoleInitializedSub?.Dispose();
			WhenConsoleInitializedSub = null;
			whenApiEnvironmentChangedSub?.Dispose();
			whenApiEnvironmentChangedSub = null;
			Console = null;
			ClubConsoleInfo = null;
		}

		public async Task SendPersistedEvents(IBlobCacheService cacheService)
		{
			if (googleAnalytics.TrackWithWebViewLags)
			{
				blobCacheService = cacheService;
			}
			GoogleAnalyticsEvent[] array = await cacheService.GetFromCache<GoogleAnalyticsEvent[]>("GoogleEvents", "CoreAnalytics");
			if (array == null)
			{
				return;
			}
			GoogleAnalyticsEvent[] array2 = array;
			foreach (GoogleAnalyticsEvent googleAnalyticsEvent in array2)
			{
				if (googleAnalyticsEvent == null)
				{
					iFit.Logger.Log.Error("Analytics", "GoogleEvents cache somehow contained null, event may have been lost, ignoring.");
				}
				else
				{
					googleAnalytics.Track(googleAnalyticsEvent.Name, googleAnalyticsEvent.Properties, throwIfInvalid: false);
				}
			}
			await DeleteGoogleTrackBuffer();
		}

		private Task DeleteGoogleTrackBuffer()
		{
			return PersistGoogleTrackBuffer(null);
		}

		private async Task PersistGoogleTrackBuffer(Queue<GoogleAnalyticsEvent> buffer)
		{
			IBlobCacheService blobCacheService = this.blobCacheService;
			if (blobCacheService != null)
			{
				await blobCacheService.Flush(buffer?.ToArray(), "GoogleEvents", "CoreAnalytics");
			}
		}

		public async Task SetConsoleUuid(IConsoleUpdateInfo consoleUpdateInfo)
		{
			await SetGoogleAnalyticsUserProperties(async delegate(Dictionary<string, object> props)
			{
				await AddConsoleUuid(props, consoleUpdateInfo);
			});
		}

		public void IsBuiltInDidChange()
		{
			SetGoogleAnalyticsUserProperties((Action<Dictionary<string, object>>)AddIsBuiltInProperty);
		}

		public void WebViewMayBeShownSoon()
		{
			if (googleAnalytics.TrackWithWebViewLags && googleTrackBuffer == null)
			{
				googleTrackBuffer = new Queue<GoogleAnalyticsEvent>();
			}
		}

		public void WebViewIsGone()
		{
			Queue<GoogleAnalyticsEvent> queue = googleTrackBuffer;
			googleTrackBuffer = null;
			while (queue != null && queue.Count > 0)
			{
				GoogleAnalyticsEvent googleAnalyticsEvent = queue.Dequeue();
				googleAnalytics.Track(googleAnalyticsEvent.Name, googleAnalyticsEvent.Properties, throwIfInvalid: false);
			}
			if (queue != null)
			{
				DeleteGoogleTrackBuffer();
			}
		}

		protected async Task OnUserChanged()
		{
			User loggedInUser = IfitApi.CurrentlyAuthenticatedUser;
			SetGoogleAnalyticsUserProperties(delegate(Dictionary<string, object> props)
			{
				AddCoreUserInfo(props, loggedInUser);
			});
			if (isFirebaseAnalyticsCollectionEnabled == true)
			{
				googleAnalytics.SetUserId(GoogleAnalyticsUtils.GetUserPropertyValue(loggedInUser?.Id));
			}
			else
			{
				wasUserIdSetWhileFirebaseAnalyticsCollectionDisabled = true;
			}
			Dictionary<string, object> properties = PropertiesForUser(loggedInUser);
			string advertisingId = await hardwareInfo.GetAdvertisingId();
			await Identify(loggedInUser?.Id, properties, null, advertisingId).ConfigureAwait(continueOnCapturedContext: false);
		}

		protected async Task OnDateChanged(DateTime date)
		{
			await OnUserChanged().ConfigureAwait(continueOnCapturedContext: false);
		}

		public virtual async Task<bool> PostEvent(string eventName, IDictionary<string, object> properties = null)
		{
			properties = properties ?? new Dictionary<string, object>();
			if (VisibleAnalytics && Mvx.TryResolve<IDialogPresenter>(out var service))
			{
				service?.ShowToast("Posting analytics event: " + eventName, 1000.0);
			}
			AddSharedEventProperties(properties, forGoogleAnalytics: false);
			string advertisingId = await hardwareInfo.GetAdvertisingId();
			bool success = false;
			try
			{
				success = await Track(eventName, properties, null, advertisingId).ConfigureAwait(continueOnCapturedContext: false);
			}
			catch (InvalidOperationException ex)
			{
				iFit.Logger.Log.Error("Analytics", ex.GetType().Name + " occurred in CoreAnalytics.PostEvent ", ex);
			}
			return success;
		}

		public void UpdateVisibleAnalytics(bool value)
		{
			VisibleAnalytics = value;
		}

		public async Task HeadphonesPaired(string deviceName)
		{
			Dictionary<string, object> properties = new Dictionary<string, object> { { "headphoneName", deviceName } };
			await PostEvent("Headphones Paired", properties);
		}

		protected async Task SuccessfulInAppPurchase(string app, IDictionary<string, string> info)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object> { ["app"] = app };
			foreach (KeyValuePair<string, string> item in info)
			{
				dictionary[item.Key] = item.Value;
			}
			await PostEvent("In App Purchase Successful", dictionary).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task RatedWorkout(Workout workout, int rating)
		{
			IDictionary<string, object> dictionary = WorkoutProperties(workout);
			dictionary["rating"] = rating;
			await PostEvent("Rated Workout", dictionary).ConfigureAwait(continueOnCapturedContext: false);
		}

		public async Task SharedWorkout(Workout workout, SocialShareProvider socialNetwork)
		{
			IDictionary<string, object> dictionary = WorkoutProperties(workout);
			dictionary["shareProvider"] = socialNetwork.ToString();
			await PostEvent("Shared Workout", dictionary).ConfigureAwait(continueOnCapturedContext: false);
		}

		public IDictionary<string, object> WorkoutProperties(Workout workout)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>
			{
				{
					"workoutCategory",
					workout.Category().ToString()
				},
				{
					"workoutType",
					workout.Type.ToString()
				},
				{
					"targetType",
					workout.Target.ToString()
				},
				{ "isLiveWorkout", workout.IsLiveWorkout }
			};
			if (IfitApi.CurrentlyAuthenticatedUser != null)
			{
				dictionary["email"] = IfitApi.CurrentlyAuthenticatedUser.Email;
			}
			if (workout.Id != null)
			{
				dictionary["workoutId"] = workout.Id;
			}
			if (workout.Difficulty != null)
			{
				dictionary["difficulty"] = workout.Difficulty.Rating.ToString();
			}
			return dictionary;
		}

		protected IDictionary<string, object> PostWorkoutProperties(Workout workout, ConsoleStateStats stats)
		{
			if (workout != null && workout.IsStrengthWorkout())
			{
				return PostWorkoutPropertiesForStrengthWorkout(stats);
			}
			return PostWorkoutPropertiesForWorkout(stats);
		}

		private static IDictionary<string, object> PostWorkoutPropertiesForWorkout(ConsoleStateStats stats)
		{
			Dictionary<string, object> dictionary = new Dictionary<string, object>();
			StatDataPoint statDataPoint = stats?.RunningStats?.DistanceChanges?.Last;
			double num = statDataPoint?.Value ?? 0.0;
			double valueOrDefault = (stats?.RunningStats?.DistanceChanges?.Last?.Timestamp).GetValueOrDefault();
			StatDataPoint statDataPoint2 = stats?.RunningStats?.CalorieChanges?.Last;
			double a = statDataPoint2?.Value ?? 0.0;
			double valueOrDefault2 = (stats?.RunningStats?.KphChanges?.MaxValue).GetValueOrDefault();
			if (valueOrDefault > 0.0 && statDataPoint != null && statDataPoint2 != null)
			{
				dictionary["workoutTime"] = (int)Math.Round(valueOrDefault);
				dictionary["workoutDistance"] = (int)Math.Round(num);
				dictionary["workoutCalories"] = (int)Math.Round(a);
				dictionary["workoutAverageSpeed"] = (int)Math.Round(num / valueOrDefault);
				dictionary["workoutMaxSpeed"] = (int)Math.Round(UnitUtil.EnsureMps(isMetric: true, valueOrDefault2));
			}
			return dictionary;
		}

