		protected virtual void AddSharedEventProperties(IDictionary<string, object> properties, bool forGoogleAnalytics)
		{
			AddIsBuiltInProperty(properties);
			if (!forGoogleAnalytics)
			{
				properties["isDebug"] = isDebug;
			}
			AddSharedEventHardwareProperties(properties, forGoogleAnalytics);
			if (AppVersionService != null)
			{
				if (!forGoogleAnalytics)
				{
					properties["appVersion"] = AppVersionService.MainAppVersionInfo.FullAppVersion;
				}
				if (AppVersionService.SupplementalVersionInfo.Count > 0)
				{
					AppVersionService.SupplementalVersionInfo.DoForEach(delegate(KeyValuePair<string, VersionInfo> tuple)
					{
						properties[tuple.Key] = tuple.Value.FullAppVersion;
					});
				}
			}
			AddSharedEventUserProperties(properties, forGoogleAnalytics);
			IConsoleInfo consoleInfo = Console?.ConsoleInfo ?? ClubConsoleInfo;
			if (consoleInfo != null)
			{
				AddCoreConsoleInfo(properties, consoleInfo);
				if (!forGoogleAnalytics)
				{
					properties["isClubUnit"] = consoleInfo.IsClub;
					properties["masterLibraryVersion"] = consoleInfo.MasterLibraryVersion;
					properties["masterLibraryBuild"] = consoleInfo.MasterLibraryBuild;
					properties["maxKph"] = (int)Math.Round(consoleInfo.MaxKph);
					properties["minKph"] = (int)Math.Round(consoleInfo.MinKph);
					properties["maxIncline"] = (int)Math.Round(consoleInfo.MaxIncline);
					properties["minIncline"] = (int)Math.Round(consoleInfo.MinIncline);
					properties["maxResistanceLevel"] = (int)Math.Round(consoleInfo.MaxResistanceLevel);
					properties["maxWeight"] = (int)Math.Round(consoleInfo.MaxWeight);
					properties["canSetKph"] = consoleInfo.CanSetKph;
					properties["canSetActivationLock"] = consoleInfo.CanSetActivationLock;
					properties["canSetIncline"] = consoleInfo.CanSetIncline;
					properties["canSetResistance"] = consoleInfo.CanSetResistance;
				}
			}
			if (IpcVersionInfo?.EruVersion != null)
			{
				properties["adminVersion"] = IpcVersionInfo?.EruVersion;
			}
			if (IpcVersionInfo?.LauncherVersion != null)
			{
				properties["launcherVersion"] = IpcVersionInfo?.LauncherVersion;
			}
			if (IpcVersionInfo?.SystemVersion != null)
			{
				properties["systemVersion"] = IpcVersionInfo?.SystemVersion;
			}
		}

