		public async Task AddConsoleUuid(IDictionary<string, object> properties, IConsoleUpdateInfo updateInfo = null)
		{
			try
			{
				if (properties == null)
				{
					iFit.Logger.Log.Error("Analytics", "CoreAnalytics.AddConsoleUuid Cannot add the console UUID to a null dictionary.");
					return;
				}
				if (updateInfo == null)
				{
					Mvx.TryResolve<IConsoleUpdateInfo>(out var service);
					updateInfo = service;
				}
				if (updateInfo != null)
				{
					Guid guid = (await updateInfo.GetInfo()).Guid;
					if (guid != Guid.Empty)
					{
						properties["uuid"] = guid.ToString();
					}
					else
					{
						iFit.Logger.Log.Error("Analytics", "CoreAnalytics.AddConsoleUuid Unable to load and add console UUID to properties.");
					}
				}
			}
			catch (Exception exception)
			{
				iFit.Logger.Log.Error("Analytics", "CoreAnalytics.AddConsoleUuid Unable to add console UUID to properties.", exception);
			}
		}

