		public async Task TrackWithGoogleAnalytics(string eventName, IDictionary<string, object> properties, bool throwIfInvalid)
		{
			if (GetIsGoogleAnalyticsFeatureFlagEnabled())
			{
				properties.NormalizeStringLengths(100);
				if (googleTrackBuffer == null)
				{
					googleAnalytics.Track(eventName, properties, throwIfInvalid);
					return;
				}
				GoogleAnalyticsEvent item = new GoogleAnalyticsEvent(eventName, properties);
				googleTrackBuffer?.Enqueue(item);
				await PersistGoogleTrackBuffer(googleTrackBuffer);
			}
		}

		private void AddSharedEventHardwareProperties(IDictionary<string, object> properties, bool forGoogleAnalytics)
		{
			properties["devicePlatform"] = GetDevicePlatform();
			properties["deviceCategory"] = (hardwareInfo.IsTablet ? "tablet" : "phone");
			if (!forGoogleAnalytics)
			{
				properties["osPlatform"] = hardwareInfo.OperatingSystem;
				properties["osVersion"] = hardwareInfo.OperatingSystemVersion;
			}
			if (hardwareInfo.IsAndroid)
			{
				properties["incrementalOsVersion"] = hardwareInfo.AndroidOsIncrementalVersion;
			}
		}

		private string GetDevicePlatform()
		{
			if (IsBuiltInClub)
			{
				return "Club";
			}
			if (IsBuiltIn)
			{
				return "Embedded";
			}
			if (hardwareInfo.OperatingSystem == "iOS")
			{
				if (hardwareInfo.IsTablet)
				{
					return "iPad";
				}
				return "iPhone";
			}
			if (hardwareInfo.OperatingSystem == "Android")
			{
				if (hardwareInfo.IsTablet)
				{
					return "Android Tablet";
				}
				return "Android Phone";
			}
			iFit.Logger.Log.Error("Analytics", "Unhandled case in GetDevicePlatform");
			return "Unknown";
		}

		private bool GetIsGoogleAnalyticsFeatureFlagEnabled()
		{
			bool flag = IsServiceEnabled("firebase");
			if (flag == isFirebaseAnalyticsCollectionEnabled)
			{
				return flag;
			}
			googleAnalytics.SetEnabled(flag);
			isFirebaseAnalyticsCollectionEnabled = flag;
			if (flag)
			{
				if (wasUserIdSetWhileFirebaseAnalyticsCollectionDisabled)
				{
					googleAnalytics.SetUserId(GoogleAnalyticsUtils.GetUserPropertyValue(IfitApi.CurrentlyAuthenticatedUserId));
					wasUserIdSetWhileFirebaseAnalyticsCollectionDisabled = false;
				}
				foreach (KeyValuePair<string, string> item in userPropertiesSetWhileFirebaseAnalyticsCollectionDisabled)
				{
					googleAnalytics.SetUserProperty(item.Key, item.Value);
				}
				userPropertiesSetWhileFirebaseAnalyticsCollectionDisabled.Clear();
			}
			return flag;
		}

		private bool IsServiceEnabled(string serviceName)
		{
			if (FeatureFlagManager == null)
			{
				return true;
			}
			string text = FeatureFlagManager.GetString(FeatureFlags.AnalyticsServices);
			if (!string.IsNullOrEmpty(text))
			{
				return text.ToLowerInvariant().Contains(serviceName);
			}
			return false;
		}

