	public static class GoogleAnalyticsUtils
	{
		private const int MaxUserPropertyNameLength = 24;

		private const int MaxUserPropertyValueLength = 36;

		public const int MaxStringParameterValueLength = 100;

		public const int MaxPropertyCount = 25;

		public static string GetUserPropertyValue(string value)
		{
			return value;
		}

		public static void ValidateUserPropertyName(string name)
		{
			if (name == null)
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name null");
			}
			else if (name.Length < 1)
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name empty");
			}
			else if (name.Length > 24)
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name '" + name + "' too long");
			}
			else if (!name.All((char c) => c == '_' || char.IsLetterOrDigit(c)))
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name '" + name + "' should only contain alphanumeric characters or underscores");
			}
			else if (!char.IsLetter(name[0]))
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name '" + name + "' should start with an alphabetic character");
			}
			else if (name.StartsWith("firebase_") || name.StartsWith("google_") || name.StartsWith("ga_"))
			{
				iFit.Logger.Log.Error("Analytics", "GoogleAnalyticsUtils invalid user property name '" + name + "' starts with reserved prefix");
			}
		}

		public static string NormalizeUserPropertyValue(string value)
		{
			if (value == null || value.Length <= 36)
			{
				return value;
			}
			iFit.Logger.Log.Error("Analytics", string.Format("{0} invalid user property value length {1} > ", "GoogleAnalyticsUtils", value.Length) + $"{36}, value='{value}'");
			value = value.Substring(0, 36);
			iFit.Logger.Log.Info("Analytics", "GoogleAnalyticsUtils truncated user property value '" + value + "'");
			return value;
		}

		private static string NormalizePropertyValue(string key, string value, bool throwIfInvalid)
		{
			if (value == null)
			{
				return string.Empty;
			}
			if (value.Length <= 100)
			{
				return value;
			}
			string text = string.Format("{0} invalid parameter value length {1} > ", "GoogleAnalyticsUtils", value.Length) + $"{100}, key={key}, value={value}";
			if (throwIfInvalid)
			{
				throw new ArgumentOutOfRangeException(key, text);
			}
			iFit.Logger.Log.Error("Analytics", text);
			value = value.Substring(0, 100);
			iFit.Logger.Log.Info("Analytics", "Truncated param " + key + " to " + value);
			return value;
		}

		private static string NormalizePropertyValue(string key, object value, bool throwIfInvalid)
		{
			if (value == null)
			{
				return string.Empty;
			}
			string text = string.Format("{0} invalid parameter value type {1}, key={2}, value={3}", "GoogleAnalyticsUtils", value.GetType(), key, value);
			if (throwIfInvalid)
			{
				throw new ArgumentOutOfRangeException(key, text);
			}
			iFit.Logger.Log.Error("Analytics", text);
			string text2 = value.ToString();
			iFit.Logger.Log.Info("Analytics", "Converted param " + key + " value to " + text2);
			return NormalizePropertyValue(key, text2, throwIfInvalid: false);
		}

		public static IDictionary<string, object> NormalizeProperties(IDictionary<string, object> properties, bool throwIfInvalid)
		{
			if (properties == null)
			{
				iFit.Logger.Log.Warn("Analytics", "NormalizeProperties called with null, should instead pass null to LogEvent()");
				return new Dictionary<string, object>();
			}
			if (properties.Count > 25)
			{
				string text = string.Format("{0} properties count={1} greater than max {2}", "GoogleAnalyticsUtils", properties.Count, 25);
				if (throwIfInvalid)
				{
					throw new ArgumentOutOfRangeException(text);
				}
				iFit.Logger.Log.Error("Analytics", text + ". Excess properties will be lost.");
			}
			Dictionary<string, object> dictionary = new Dictionary<string, object>(properties.Count);
			foreach (KeyValuePair<string, object> property in properties)
			{
				property.Deconstruct(out var key, out var value);
				string key2 = key;
				object obj = value;
				string key3 = NormalizePropertyKey(key2, throwIfInvalid);
				object value2 = ((obj is string value3) ? NormalizePropertyValue(key2, value3, throwIfInvalid) : ((obj is bool) ? ((object)(long)(((bool)obj) ? 1 : 0)) : ((obj is int num) ? ((object)(long)num) : ((obj is uint num2) ? ((object)(long)num2) : ((obj is long num3) ? ((object)num3) : ((obj is double num4) ? ((object)num4) : ((obj is DateTime dateTime) ? dateTime.ToString(CultureInfo.InvariantCulture) : ((obj is Guid guid) ? guid.ToString() : ((!(obj is Enum obj2)) ? NormalizePropertyValue(key2, obj, throwIfInvalid) : obj2.ToString())))))))));
				dictionary.Add(key3, value2);
			}
			return dictionary;
		}

		private static string NormalizePropertyKey(string key, bool throwIfInvalid)
		{
			key = key.Replace('-', '_');
			if (key.All((char c2) => c2 == '_' || char.IsLetterOrDigit(c2)))
			{
				return key;
			}
			string text = "GoogleAnalyticsUtils invalid parameter key, must be letters, digits, or _: '" + key + "'";
			if (throwIfInvalid)
			{
				throw new ArgumentOutOfRangeException(key, text);
			}
			iFit.Logger.Log.Error("Analytics", text);
			StringBuilder stringBuilder = new StringBuilder();
			string text2 = key;
			foreach (char c in text2)
			{
				stringBuilder.Append((c == '_' || char.IsLetterOrDigit(c)) ? c : '_');
			}
			string text3 = stringBuilder.ToString();
			iFit.Logger.Log.Info("Analytics", "Converted key '" + key + "' to '" + text3 + "'");
			return text3;
		}
	}
