	public static class RaygunTag
	{
		public const string RenderProcessorError = "RenderProcessorError";

		public const string Manual = "Manual";

		public const string UnobservedTaskException = "UnobservedTaskException";
	}
	public static class RaygunAnalytics
	{
		private const string Prefix = "Raygun Report: ";

		private const string AndroidNotResponding = "Raygun Report: Android Not Responding";

		private const string RenderProcessorError = "Raygun Report: Render Processor Error";

		private const string ManualError = "Raygun Report: Manual Error";

		private const string TaskException = "Raygun Report: Task Exception";

		private const string RaygunFailed = "Raygun Report: Failed Raygun Report";

		public static Task ReportRaygunUpload(this ICoreAnalytics analytics, Exception exception, IList<string> tags)
		{
			Dictionary<string, object> dictionary = PropertiesForRaygunEvent(exception);
			if (exception is iFitAnrError && exception.Data.Count > 0)
			{
				foreach (DictionaryEntry datum in exception.Data)
				{
					dictionary.Add($"{datum.Key}", $"{datum.Value}");
				}
			}
			analytics.AddConsoleUuid(dictionary);
			string eventName;
			if (exception is iFitAnrError)
			{
				eventName = "Raygun Report: Android Not Responding";
			}
			else if (tags.Contains("RenderProcessorError"))
			{
				eventName = "Raygun Report: Render Processor Error";
			}
			else if (tags.Contains("Manual"))
			{
				eventName = "Raygun Report: Manual Error";
			}
			else
			{
				if (!tags.Contains("UnobservedTaskException"))
				{
					return analytics.RaygunReportAppCrashed(dictionary);
				}
				eventName = "Raygun Report: Task Exception";
			}
			return analytics.PostEvent(eventName, dictionary);
		}

		private static Dictionary<string, object> PropertiesForRaygunEvent(Exception exception)
		{
			return new Dictionary<string, object>
			{
				{ "message", exception.Message },
				{
					"exception",
					exception.GetType().ToString()
				}
			};
		}

		private static Dictionary<string, object> PropertiesForRaygunEvent(Exception exception, Exception failedException)
		{
			if (exception.InnerException != null)
			{
				if (failedException.InnerException != null)
				{
					return PropertiesForRaygunEvent(exception.InnerException, failedException.InnerException);
				}
				return PropertiesForRaygunEvent(exception.InnerException, failedException);
			}
			if (failedException.InnerException != null)
			{
				return PropertiesForRaygunEvent(exception, failedException.InnerException);
			}
			return new Dictionary<string, object>
			{
				{ "message", exception.Message },
				{
					"exception",
					exception.GetType().ToString()
				},
				{ "failedRaygunReportMessage", failedException.Message },
				{
					"failedRaygunReportException",
					failedException.GetType().ToString()
				}
			};
		}

		public static Task ReportFailedRaygunReport(this ICoreAnalytics analytics, Exception exception, IList<string> tags, Exception failedException)
		{
			Dictionary<string, object> properties = PropertiesForRaygunEvent(exception, failedException);
			analytics.AddConsoleUuid(properties);
			return analytics.PostEvent("Raygun Report: Failed Raygun Report", properties);
		}
	}
	public static class SystemAnalytics
	{
		private const string EventLowDiskSpace = "Low Disk Space";

		public static Task LowDiskSpace(this ICoreAnalytics analytics, DiskSpaceEvent diskSpaceEvent)
		{
			return analytics.PostEvent("Low Disk Space", diskSpaceEvent.AnalyticsProperties());
		}
	}
